	public static function activate() {
		self::ensure_capabilities();
		self::schedule_google_sync();
		self::schedule_google_pull_sync();
		self::schedule_daily_automation();
	}

	public static function deactivate() {
		$next = wp_next_scheduled(self::GOOGLE_SYNC_HOOK);
		if ($next) {
			wp_unschedule_event($next, self::GOOGLE_SYNC_HOOK);
		}
		$next_pull = wp_next_scheduled(self::GOOGLE_PULL_HOOK);
		if ($next_pull) {
			wp_unschedule_event($next_pull, self::GOOGLE_PULL_HOOK);
		}
		$next_auto = wp_next_scheduled(self::AUTOMATION_HOOK);
		if ($next_auto) {
			wp_unschedule_event($next_auto, self::AUTOMATION_HOOK);
		}
	}

	public static function schedule_google_sync() {
		if (wp_next_scheduled(self::GOOGLE_SYNC_HOOK)) {
			return;
		}
		$timestamp = TwoB_CRM_Dani_Automation_Module::next_daily_timestamp('23:00:00');
		wp_schedule_event($timestamp, 'daily', self::GOOGLE_SYNC_HOOK);
	}

	public static function schedule_google_pull_sync() {
		if (wp_next_scheduled(self::GOOGLE_PULL_HOOK)) {
			return;
		}
		wp_schedule_event(time() + HOUR_IN_SECONDS, 'hourly', self::GOOGLE_PULL_HOOK);
	}

	public static function schedule_daily_automation() {
		if (wp_next_scheduled(self::AUTOMATION_HOOK)) {
			return;
		}
		$timestamp = TwoB_CRM_Dani_Automation_Module::next_daily_timestamp('06:00:00');
		wp_schedule_event($timestamp, 'daily', self::AUTOMATION_HOOK);
	}

