	public static function ensure_capabilities() {
		$admin = get_role('administrator');
		if ($admin) {
			foreach (self::plugin_capabilities() as $cap) {
				$admin->add_cap($cap);
			}
		}

		$editor = get_role('editor');
		if ($editor) {
			$editor_caps = array_diff(self::plugin_capabilities(), array(self::SETTINGS_CAP, self::GOOGLE_CAP));
			foreach ($editor_caps as $cap) {
				$editor->add_cap($cap);
			}
		}

		self::ensure_named_crm_users();
	}

	private static function named_crm_user_profiles() {
		return array(
			'danitza' => array(
				'persona' => 'dani',
				'emails' => array('danitza@2bdigital.cl'),
			),
			'renata' => array(
				'persona' => 'renata',
				'emails' => array('renata@2bdigital.cl'),
			),
		);
	}

	private static function ensure_named_crm_users() {
		foreach (self::named_crm_user_profiles() as $login => $profile) {
			$user = get_user_by('login', $login);
			if (! $user && ! empty($profile['emails']) && is_array($profile['emails'])) {
				foreach ($profile['emails'] as $email) {
					$user = get_user_by('email', sanitize_email((string) $email));
					if ($user) {
						break;
					}
				}
			}

			if (! ($user instanceof WP_User) || ! $user->exists()) {
				continue;
			}

			$grant_all_caps = ! empty($user->allcaps['manage_options']) || in_array('administrator', (array) $user->roles, true);
			$caps = $grant_all_caps ? self::plugin_capabilities() : array_diff(self::plugin_capabilities(), array(self::SETTINGS_CAP, self::GOOGLE_CAP));
			foreach ($caps as $cap) {
				$user->add_cap($cap);
			}

			$persona = sanitize_key((string) ($profile['persona'] ?? ''));
			if ($persona && sanitize_key((string) get_user_meta($user->ID, 'twob_plan_usuario', true)) !== $persona) {
				update_user_meta($user->ID, 'twob_plan_usuario', $persona);
			}
		}
	}

