	public static function flush_metrics_cache_for_post($post_id) {
		$post = get_post((int) $post_id);
		if (! $post || ! in_array($post->post_type, array('crm_lead', 'crm_interaction', 'crm_task', 'crm_payment', 'crm_activity'), true)) {
			return;
		}
		self::flush_metrics_cache();
	}

	private static function user_can_access_crm() {
		return current_user_can(self::ACCESS_CAP);
	}

	private static function user_can_manage_settings() {
		return current_user_can(self::SETTINGS_CAP);
	}

	private static function user_can_access_prospect_finder() {
		if (! self::user_can_access_crm()) {
			return false;
		}

		if (current_user_can('manage_options')) {
			return true;
		}

		return 'renata' === self::current_crm_persona();
	}

	private static function user_can_manage_reports() {
