	}

	private static function crm_post_capability_family($post_type) {
		return match ((string) $post_type) {
			'crm_lead' => self::cpt_capabilities('crm_lead', 'crm_leads'),
			'crm_interaction' => self::cpt_capabilities('crm_interaction', 'crm_interactions'),
			'crm_task' => self::cpt_capabilities('crm_task', 'crm_tasks'),
			'crm_payment' => self::cpt_capabilities('crm_payment', 'crm_payments'),
			'crm_activity' => self::cpt_capabilities('crm_activity', 'crm_activities'),
			default => array(),
		};
	}

	private static function current_user_can_view_crm_post($post_id) {
		$post = $post_id ? get_post((int) $post_id) : null;
		if (! $post || ! self::user_can_access_crm()) {
			return false;
		}
		if (in_array((string) $post->post_type, array('crm_lead', 'crm_interaction', 'crm_task', 'crm_payment', 'crm_activity'), true)) {
			return true;
		}
		if (current_user_can('edit_post', (int) $post_id) || current_user_can('read_post', (int) $post_id)) {
			return true;
		}
		$caps = self::crm_post_capability_family($post->post_type);
		if (empty($caps)) {
			return false;
		}
		foreach (array('edit_posts', 'edit_others_posts', 'edit_published_posts', 'read_private_posts') as $cap_key) {
			if (! empty($caps[$cap_key]) && current_user_can((string) $caps[$cap_key])) {
				return true;
			}
		}
		return false;
	}

	private static function current_user_can_edit_crm_post($post_id) {
		$post = $post_id ? get_post((int) $post_id) : null;
		if (! $post || ! self::user_can_access_crm()) {
			return false;
		}
		if (current_user_can('edit_post', (int) $post_id)) {
			return true;
		}
		$caps = self::crm_post_capability_family($post->post_type);
		if (empty($caps)) {
			return false;
		}
		foreach (array('edit_posts', 'edit_others_posts', 'edit_published_posts', 'edit_private_posts') as $cap_key) {
			if (! empty($caps[$cap_key]) && current_user_can((string) $caps[$cap_key])) {
				return true;
			}
		}
		return false;
	}

	private static function current_user_can_delete_crm_post($post_id) {
		return $post_id > 0 && current_user_can('delete_post', (int) $post_id);
	}

	private static function validate_stage_choice($stage, $allow_empty = false, $field_label = 'Etapa') {
		$stage = trim((string) $stage);
		if ('' === $stage) {
			return $allow_empty ? '' : 'new';
		}
		$normalized = self::normalize_stage_key($stage);
		if (! isset(self::stage_labels()[$normalized])) {
			return new WP_Error('invalid_stage', $field_label . ' invalida.');
		}
		return $normalized;
	}

	private static function sanitize_stage_input($stage, $allow_empty = false) {
		$stage = self::validate_stage_choice($stage, $allow_empty);
		if (is_wp_error($stage)) {
			return $allow_empty ? '' : 'new';
		}
		return $stage;
	}

	private static function sanitize_budget_input($budget) {
		return TwoB_CRM_Dani_Leads_Module::sanitize_budget($budget, self::budget_options());
	}

	private static function sanitize_amount_input($amount) {
		$amount = is_numeric($amount) ? (float) $amount : 0.0;
		return max(0, $amount);
	}

	private static function sanitize_date_input($value, $allow_empty = true, $field_label = 'Fecha') {
		return TwoB_CRM_Dani_Leads_Module::sanitize_date($value, $allow_empty, $field_label);
	}

