	private static function set_lead_close_reason_code($lead_id, $reason = '') {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return;
		}
		$reason = self::normalize_close_reason_code($reason);
		if ($reason) {
			update_post_meta($lead_id, '_crm_close_reason_code', $reason);
			return;
		}
		delete_post_meta($lead_id, '_crm_close_reason_code');
	}

	private static function is_closed_detail_stage($stage) {
		$stage = self::normalize_stage_key((string) $stage);
		return in_array($stage, array('closed_no_response', 'won', 'lost'), true);
	}

	private static function determine_lifecycle_state($lead_id, $today = '') {
		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id) || 'trash' === get_post_status($lead_id)) {
			return 'closed';
		}

		$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		$close_reason = self::get_lead_close_reason_code($lead_id);
		if ($close_reason || self::is_closed_detail_stage($stage)) {
			return 'closed';
		}

		if (self::lead_has_response_signal($lead_id)) {
			$next_followup = trim((string) get_post_meta($lead_id, '_crm_next_followup', true));
			if ($next_followup && $next_followup > $today) {
				return 'pending';
			}
			if (in_array($stage, array('meeting_scheduled', 'meeting_done', 'proposal_sent'), true)) {
				return 'pending';
			}
			return 'interested';
		}

		if (! self::lead_has_logged_interaction($lead_id)) {
			return 'new';
		}

		$created_day = self::lead_sequence_anchor_day($lead_id);
		$warmup_limit = $created_day ? self::lead_sequence_due_day($lead_id, 3) : '';
		if ($created_day && $warmup_limit && $today < $warmup_limit) {
			return 'new';
		}

		return 'tracking';
	}

	private static function lead_lifecycle_state($lead_id, $today = '') {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return 'closed';
		}

		$stored_raw = sanitize_key((string) get_post_meta($lead_id, '_crm_lifecycle_state', true));
		if (isset(self::lifecycle_state_labels()[$stored_raw])) {
			return $stored_raw;
		}

		return self::sync_lead_lifecycle_state($lead_id, $today);
	}

	private static function sync_lead_lifecycle_state($lead_id, $today = '', $close_reason = null) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return 'closed';
		}

		if (null !== $close_reason) {
			self::set_lead_close_reason_code($lead_id, $close_reason);
		}

		$state = self::determine_lifecycle_state($lead_id, $today);
		update_post_meta($lead_id, '_crm_lifecycle_state', $state);
		if ('closed' !== $state && null === $close_reason) {
			self::set_lead_close_reason_code($lead_id, '');
		}
		return $state;
	}

