	private static function task_requires_guided_completion($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return false;
		}
		if (self::is_reactivation_task($task_id)) {
			return false;
		}

		$category = self::sanitize_task_category((string) get_post_meta($task_id, '_crm_task_category', true));
		$relation = self::sanitize_task_relation((string) get_post_meta($task_id, '_crm_task_relation', true));
		$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);

		return 'commercial' === $category && 'lead_client' === $relation && $lead_id > 0;
	}

