	private static function task_resolution_stage_suggestion($result, $current_stage = '') {
		$result = self::sanitize_interaction_result($result);
		$current_stage = self::normalize_stage_key((string) $current_stage);

		return match ($result) {
			'interested' => in_array($current_stage, array('meeting_scheduled', 'meeting_done', 'proposal_sent', 'won'), true) ? $current_stage : 'responded_interested',
			'meeting_booked' => 'meeting_scheduled',
			'rejected' => 'lost',
			default => '',
		};
	}

	private static function task_resolution_next_type($resolved_stage, $fallback_task_type = 'followup') {
		$resolved_stage = self::normalize_stage_key((string) $resolved_stage);
		if ('meeting_scheduled' === $resolved_stage) {
			return 'meeting';
		}
		if ('proposal_sent' === $resolved_stage) {
			return 'proposal';
		}

		$fallback_task_type = sanitize_key((string) $fallback_task_type);
		if (in_array($fallback_task_type, array('proposal', 'meeting'), true)) {
			return $fallback_task_type;
		}

		return 'followup';
	}

	private static function task_resolution_next_title($lead_id, $task_type) {
		$lead_id = (int) $lead_id;
		$lead_title = $lead_id ? wp_strip_all_tags(get_the_title($lead_id)) : 'Lead';

		return match (sanitize_key((string) $task_type)) {
			'meeting' => 'Reunion pendiente: ' . $lead_title,
			'proposal' => 'Seguimiento de propuesta: ' . $lead_title,
			'contact_lead' => 'Nuevo contacto: ' . $lead_title,
			default => 'Seguimiento programado: ' . $lead_title,
		};
	}

	private static function task_can_be_resolved_by_interaction($task_id, $kind = '', $channel = '', $interaction_action = '', $result = '') {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return false;
		}

		$task_type = sanitize_key((string) get_post_meta($task_id, '_crm_task_type', true));
		$kind = self::sanitize_interaction_kind($kind ?: 'followup');
		$channel = self::sanitize_interaction_channel($channel ?: 'linkedin');
		$interaction_action = self::sanitize_interaction_action($interaction_action);
		$result = self::sanitize_interaction_result($result ?: 'other');

		if ('meeting' === $task_type) {
			return in_array($channel, array('meeting', 'call'), true)
				|| in_array($interaction_action, array('meeting_scheduled', 'meeting_held'), true)
				|| 'meeting_booked' === $result;
		}

		if ('proposal' === $task_type) {
			return in_array($channel, array('email', 'whatsapp', 'linkedin', 'call'), true)
				|| in_array($interaction_action, array('email_sent', 'phone_call', 'linkedin_followup'), true)
				|| 'followup' === $kind;
		}

		if (self::interaction_result_is_positive($result) || 'rejected' === $result) {
			return true;
		}

		if (in_array($interaction_action, self::passive_interaction_actions(), true)) {
			return false;
		}

		if (in_array($interaction_action, self::social_touch_interaction_actions(), true)) {
			return in_array($result, array('warming_up', 'no_answer', 'other'), true);
		}

		if ('no_answer' === $result || 'warming_up' === $result) {
			return in_array($interaction_action, array(
				'linkedin_message',
				'linkedin_followup',
				'linkedin_final_attempt',
				'email_sent',
				'whatsapp_message',
				'phone_call',
				'meeting_scheduled',
				'meeting_held',
				'other',
			), true);
		}

		if ('other' === $result) {
			return in_array($interaction_action, array(
				'linkedin_message',
				'linkedin_followup',
				'linkedin_post_engagement',
				'linkedin_post_reaction',
				'linkedin_post_comment',
				'linkedin_connection_accept',
				'linkedin_content_share',
				'email_sent',
				'whatsapp_message',
				'phone_call',
				'other',
			), true);
		}

		return false;
	}

	private static function task_belongs_to_hidden_operational_lead($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return false;
		}
		if (self::is_reactivation_task($task_id)) {
			return false;
		}

		$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return false;
		}

		return self::is_operationally_archived_lead($lead_id) || self::is_closed_detail_stage((string) get_post_meta($lead_id, '_crm_stage', true));
	}

	private static function task_should_be_hidden_from_open_views($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return false;
		}
		if (self::is_alliance_task($task_id)) {
			return true;
		}
		if (self::task_requires_guided_completion($task_id) && self::is_task_open_status((string) get_post_meta($task_id, '_crm_task_status', true))) {
			self::reconcile_open_guided_task_from_history($task_id);
		}
		if (! self::is_task_open_status((string) get_post_meta($task_id, '_crm_task_status', true))) {
			return false;
		}
		if (! self::task_requires_guided_completion($task_id)) {
			return false;
		}
		return self::task_belongs_to_hidden_operational_lead($task_id);
	}

	private static function close_open_commercial_tasks_for_lead($lead_id, $resolved_stage = 'lost', $note = '', $context = 'lead_stage_closed') {
		$lead_id = (int) $lead_id;
		$resolved_stage = sanitize_key((string) $resolved_stage);
		if ('archive' !== $resolved_stage) {
			$resolved_stage = self::normalize_stage_key((string) $resolved_stage);
		}
		if (! $lead_id || ! in_array($resolved_stage, array('closed_no_response', 'lost', 'won', 'archive'), true)) {
			return 0;
		}

		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => -1,
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => '_crm_task_lead_id', 'value' => $lead_id, 'compare' => '='),
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
		));

		$completion_note = trim((string) $note);
		if ('' === $completion_note) {
			$completion_note = match ($resolved_stage) {
				'closed_no_response' => 'Lead cerrado automaticamente sin respuesta.',
				'lost' => 'Lead cerrado como perdido.',
				'archive' => 'Lead movido a archivo operativo.',
				default => 'Lead cerrado y tareas comerciales resueltas.',
			};
		}

		$closed_count = 0;
		foreach ($tasks as $task_id) {
			$task_id = (int) $task_id;
			if (! self::task_requires_guided_completion($task_id)) {
				continue;
			}
			if (! self::is_task_open_status((string) get_post_meta($task_id, '_crm_task_status', true))) {
				continue;
			}

			update_post_meta($task_id, '_crm_task_status', 'done');
			update_post_meta($task_id, '_crm_task_completed_at', current_time('mysql'));
			update_post_meta($task_id, '_crm_task_completion_interaction_id', 0);
			update_post_meta($task_id, '_crm_task_completion_action', 'other');
			update_post_meta($task_id, '_crm_task_completion_result', 'closed_no_response' === $resolved_stage ? 'no_answer' : ('lost' === $resolved_stage ? 'rejected' : ('archive' === $resolved_stage ? 'warming_up' : 'other')));
			update_post_meta($task_id, '_crm_task_completion_note', sanitize_textarea_field($completion_note));
			update_post_meta($task_id, '_crm_task_completion_next_followup', '');
			update_post_meta($task_id, '_crm_task_completion_stage', $resolved_stage);
			update_post_meta($task_id, '_crm_task_resolved_by', get_current_user_id());

			self::log_activity('task_completed', $task_id, array(
				'task_type' => (string) get_post_meta($task_id, '_crm_task_type', true),
				'result' => 'closed_no_response' === $resolved_stage ? 'no_answer' : ('lost' === $resolved_stage ? 'rejected' : ('archive' === $resolved_stage ? 'warming_up' : 'other')),
				'stage' => $resolved_stage,
				'lead_id' => $lead_id,
				'context' => sanitize_key((string) $context),
			));
			self::sync_google_task_status_prefix($task_id, 'done');
			$closed_count++;
		}

		return $closed_count;
	}

	private static function missing_lost_reason_task_auto_key($lead_id) {
		return 'lead_missing_lost_reason_' . (int) $lead_id;
	}

	private static function close_missing_lost_reason_tasks($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return 0;
		}

		$task_ids = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => -1,
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => '_crm_auto_key', 'value' => self::missing_lost_reason_task_auto_key($lead_id), 'compare' => '='),
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
		));

		$closed = 0;
		foreach ($task_ids as $task_id) {
			$task_id = (int) $task_id;
			update_post_meta($task_id, '_crm_task_status', 'done');
			update_post_meta($task_id, '_crm_task_completed_at', current_time('mysql'));
			self::sync_google_task_status_prefix($task_id, 'done');
			$closed++;
		}

		return $closed;
	}

	private static function ensure_missing_lost_reason_task($lead_id, $today = '', $context = '') {
		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
		if (! $lead) {
			return 0;
		}

		$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		$lost_reason = trim((string) get_post_meta($lead_id, '_crm_closed_lost_reason', true));
		if ('lost' !== $stage || '' !== $lost_reason) {
			self::close_missing_lost_reason_tasks($lead_id);
			return 0;
		}

		$description = 'Lead marcado como perdido sin motivo registrado.' . "\n\n" .
			'Accion obligatoria de hoy: completar el motivo de perdida en la ficha para medir la causa real.' . "\n\n" .
			'Lead: ' . wp_strip_all_tags(get_the_title($lead_id));
		if ($context) {
			$description .= "\nContexto: " . sanitize_text_field((string) $context);
		}

		return self::create_auto_task_once(
			$lead_id,
			'Completar motivo de perdida: ' . wp_strip_all_tags(get_the_title($lead_id)),
			'followup',
			'high',
			$today,
			self::missing_lost_reason_task_auto_key($lead_id),
			array(
				'description' => $description,
				'assignee' => 'dani',
				'category' => 'operational',
				'relation' => 'internal',
				'pipeline_stage' => 'lost',
				'allow_archived_lead' => true,
			)
		);
	}

	private static function reconcile_missing_lost_reason_for_lead($lead_id, $today = '') {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return 0;
		}

		return self::ensure_missing_lost_reason_task($lead_id, $today ?: current_time('Y-m-d'), 'reconciliacion diaria');
	}

	private static function close_sequence_tasks_for_lead($lead_id, $reason = '', $today = '') {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return 0;
		}

		$today = $today ?: current_time('Y-m-d');
		$prefix = 'lead_sequence_' . $lead_id . '_';
		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => -1,
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => '_crm_task_lead_id', 'value' => $lead_id, 'compare' => '='),
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
		));

		$reason = trim((string) $reason) ?: 'La secuencia automatica se cerro porque el lead ya respondio o salio del flujo inicial.';
		$closed = 0;
		foreach ($tasks as $task_id) {
			$task_id = (int) $task_id;
			$auto_key = (string) get_post_meta($task_id, '_crm_auto_key', true);
			if (! $auto_key || (0 !== strpos($auto_key, $prefix) && 0 !== strpos($auto_key, 'auto_contacted_followup_' . $lead_id . '_'))) {
				continue;
			}
			update_post_meta($task_id, '_crm_task_status', 'done');
			update_post_meta($task_id, '_crm_task_completed_at', current_time('mysql'));
			update_post_meta($task_id, '_crm_task_completion_interaction_id', 0);
			update_post_meta($task_id, '_crm_task_completion_action', 'other');
			update_post_meta($task_id, '_crm_task_completion_result', 'other');
			update_post_meta($task_id, '_crm_task_completion_note', sanitize_textarea_field($reason));
			update_post_meta($task_id, '_crm_task_completion_next_followup', '');
			update_post_meta($task_id, '_crm_task_completion_stage', sanitize_key((string) get_post_meta($lead_id, '_crm_stage', true)));
			update_post_meta($task_id, '_crm_task_resolved_by', get_current_user_id());
			self::log_activity('task_completed', $task_id, array(
				'task_type' => (string) get_post_meta($task_id, '_crm_task_type', true),
				'result' => 'other',
				'stage' => sanitize_key((string) get_post_meta($lead_id, '_crm_stage', true)),
				'lead_id' => $lead_id,
				'context' => 'sequence_closed',
				'closed_day' => $today,
			));
			self::sync_google_task_status_prefix($task_id, 'done');
			$closed++;
		}
		self::sync_lead_next_action($lead_id);
		return $closed;
	}

	private static function find_open_task_for_lead_on_day($lead_id, $day, $exclude_task_id = 0) {
		$lead_id = (int) $lead_id;
		$exclude_task_id = (int) $exclude_task_id;
		$day = trim((string) $day);
		if (! $lead_id || ! $day) {
			return 0;
		}

		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => 20,
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => '_crm_task_lead_id', 'value' => $lead_id, 'compare' => '='),
				array('key' => '_crm_task_due', 'value' => $day, 'compare' => '='),
			),
		));

		foreach ($tasks as $task_id) {
			$task_id = (int) $task_id;
			if ($exclude_task_id && $task_id === $exclude_task_id) {
				continue;
			}
			if (self::is_task_open_status((string) get_post_meta($task_id, '_crm_task_status', true))) {
				return $task_id;
			}
		}

		return 0;
	}

	private static function find_resolvable_open_task_for_lead($lead_id, $date = '', $preferred_task_id = 0, $payload = array()) {
		$lead_id = (int) $lead_id;
		$preferred_task_id = (int) $preferred_task_id;
		$date = trim((string) ($date ?: current_time('Y-m-d')));
		if (! $lead_id) {
			return 0;
		}

		$kind = isset($payload['kind']) ? (string) $payload['kind'] : '';
		$channel = isset($payload['channel']) ? (string) $payload['channel'] : '';
		$interaction_action = isset($payload['interaction_action']) ? (string) $payload['interaction_action'] : '';
		$result = isset($payload['result']) ? (string) $payload['result'] : '';

		if ($preferred_task_id && self::task_requires_guided_completion($preferred_task_id) && self::is_task_open_status((string) get_post_meta($preferred_task_id, '_crm_task_status', true))) {
			$preferred_due = (string) get_post_meta($preferred_task_id, '_crm_task_due', true);
			if ((! $preferred_due || $preferred_due <= $date) && self::task_can_be_resolved_by_interaction($preferred_task_id, $kind, $channel, $interaction_action, $result)) {
				return $preferred_task_id;
			}
		}

		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => 50,
			'meta_key' => '_crm_task_due',
			'orderby' => 'meta_value',
			'order' => 'ASC',
			'meta_query' => array(
				array('key' => '_crm_task_lead_id', 'value' => $lead_id, 'compare' => '='),
			),
		));

		foreach ($tasks as $task) {
			$task_id = (int) $task->ID;
			if (! self::task_requires_guided_completion($task_id)) {
				continue;
			}
			if (! self::is_task_open_status((string) get_post_meta($task_id, '_crm_task_status', true))) {
				continue;
			}
			$task_due = (string) get_post_meta($task_id, '_crm_task_due', true);
			if ($task_due && $task_due > $date) {
				continue;
			}
			if (! self::task_can_be_resolved_by_interaction($task_id, $kind, $channel, $interaction_action, $result)) {
				continue;
			}
			return $task_id;
		}

		return 0;
	}

	private static function task_recent_interactions_payload($lead_id, $limit = 4) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return array();
		}

		$items = get_posts(array(
			'post_type' => 'crm_interaction',
			'post_status' => 'publish',
			'posts_per_page' => max(1, (int) $limit),
			'meta_key' => '_crm_interaction_date',
			'orderby' => 'meta_value',
			'order' => 'DESC',
			'meta_query' => array(
				array('key' => '_crm_lead_id', 'value' => $lead_id, 'compare' => '='),
			),
		));

		if (empty($items)) {
			return array();
		}

		$history = array();
		foreach ($items as $item) {
			$item_id = (int) $item->ID;
			$date = trim((string) get_post_meta($item_id, '_crm_interaction_date', true));
			$kind = trim((string) get_post_meta($item_id, '_crm_interaction_kind', true));
			$channel = trim((string) get_post_meta($item_id, '_crm_interaction_channel', true));
			$action = trim((string) get_post_meta($item_id, '_crm_interaction_action', true));
			$result = trim((string) get_post_meta($item_id, '_crm_interaction_result', true));
			$note = trim((string) get_post_meta($item_id, '_crm_interaction_note', true));
			$action_label = self::interaction_action_label($action, $kind, $channel);
			$result_label = self::interaction_result_labels()[$result] ?? ucfirst(str_replace('_', ' ', $result));
			$summary = implode(' · ', array_filter(array($date, $action_label, $result_label)));
			if ($note) {
				$summary .= ' — ' . $note;
			}
			$history[] = array(
				'date' => $date,
				'action' => $action_label,
				'result' => $result_label,
				'note' => $note,
				'summary' => $summary,
			);
		}

		return $history;
	}

	private static function task_completion_context_payload($task_id) {
		$task_id = (int) $task_id;
		$task = self::get_valid_crm_post($task_id, 'crm_task');
		if (! $task) {
			return array();
		}

		$task_type = (string) get_post_meta($task_id, '_crm_task_type', true);
		$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
		$current_stage = $lead_id ? (string) get_post_meta($lead_id, '_crm_stage', true) : (string) get_post_meta($task_id, '_crm_task_pipeline_stage', true);
		$sequence_config = self::task_sequence_step_config($task_id);
		$default_kind = ! empty($sequence_config['default_kind']) ? (string) $sequence_config['default_kind'] : self::task_default_interaction_kind_for_type($task_type);
		$default_channel = ! empty($sequence_config['default_channel']) ? (string) $sequence_config['default_channel'] : self::task_default_interaction_channel_for_type($task_type);
		$next_followup = $lead_id ? (string) get_post_meta($lead_id, '_crm_next_followup', true) : '';
		$sequence_next = self::default_next_followup_for_sequence_task($task_id, current_time('Y-m-d'));
		$company = $lead_id ? trim((string) get_post_meta($lead_id, '_crm_company', true)) : '';
		$cycle_label = self::task_ai_cycle_label($task_id);
		$task_label = ! empty($sequence_config['next_action_label']) ? sanitize_text_field((string) $sequence_config['next_action_label']) : self::task_next_action_label($task_id);
		$recent_interactions = self::task_recent_interactions_payload($lead_id, 4);
		if (! empty($sequence_config) && $sequence_next) {
			$next_followup = $sequence_next;
		} elseif (! $next_followup) {
			$next_followup = current_time('Y-m-d');
		}

		return array(
			'task_id' => $task_id,
			'task_title' => (string) get_the_title($task_id),
			'lead_id' => $lead_id,
			'lead_title' => $lead_id ? (string) get_the_title($lead_id) : '',
			'current_stage' => self::normalize_stage_key($current_stage),
			'default_kind' => $default_kind,
			'default_channel' => $default_channel,
			'default_action' => ! empty($sequence_config['default_action']) ? (string) $sequence_config['default_action'] : self::normalize_interaction_action('', $default_kind, $default_channel),
			'next_followup' => $next_followup,
			'company' => $company,
			'cycle_label' => $cycle_label,
			'task_label' => $task_label,
			'recent_interactions' => $recent_interactions,
			'guided' => self::task_requires_guided_completion($task_id),
		);
	}

	private static function task_completion_button_data_attrs($task_id) {
		$context = self::task_completion_context_payload($task_id);
		if (empty($context['guided'])) {
			return '';
		}

		$attrs = array(
			'data-task-guided' => '1',
			'data-task-title' => (string) $context['task_title'],
			'data-lead-id' => (string) (int) $context['lead_id'],
			'data-lead-title' => (string) $context['lead_title'],
			'data-default-kind' => (string) $context['default_kind'],
			'data-default-channel' => (string) $context['default_channel'],
			'data-default-action' => (string) $context['default_action'],
			'data-current-stage' => (string) $context['current_stage'],
			'data-next-followup' => (string) $context['next_followup'],
		);

		$parts = array();
		foreach ($attrs as $key => $value) {
			$parts[] = $key . '="' . esc_attr($value) . '"';
		}

		return ' ' . implode(' ', $parts);
	}

	private static function normalize_interaction_action($action, $kind = '', $channel = '') {
		$action = self::sanitize_interaction_action($action);
		if ($action) {
			return $action;
		}

		$kind = self::sanitize_interaction_kind($kind);
		$channel = sanitize_key((string) $channel);
		if ('meeting' === $channel) {
			return 'meeting_held';
		}
		if ('call' === $channel) {
			return 'phone_call';
		}
		if ('email' === $channel) {
			return 'email_sent';
		}
		if ('whatsapp' === $channel) {
			return 'whatsapp_message';
		}
		if ('linkedin' === $channel) {
			return 'followup' === $kind ? 'linkedin_followup' : 'linkedin_message';
		}

		return 'other';
	}

	private static function interaction_action_label($action, $kind = '', $channel = '') {
		$action = self::normalize_interaction_action($action, $kind, $channel);
		$labels = self::interaction_action_labels();
		return isset($labels[$action]) ? $labels[$action] : ($labels['other'] ?? 'Otra accion');
	}

	private static function response_received_action_for_channel($channel) {
		return match (self::sanitize_interaction_channel($channel)) {
			'linkedin' => 'linkedin_reply_received',
			'email' => 'email_reply_received',
			'whatsapp' => 'whatsapp_reply_received',
			'call' => 'call_received',
			default => 'other',
		};
	}

	private static function interaction_action_is_response_received($action) {
		$action = sanitize_key((string) $action);
		return in_array($action, array(
			'linkedin_reply_received',
			'email_reply_received',
			'whatsapp_reply_received',
			'call_received',
		), true);
	}

	private static function task_personalization_meta($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return array(
				'label' => 'Rapido',
				'class' => 'twob-response-priority-baja',
				'hint' => 'Mensaje breve o accion simple.',
			);
		}

		$task_type = sanitize_key((string) get_post_meta($task_id, '_crm_task_type', true));
		$sequence_slug = self::task_sequence_step_slug($task_id);

		if (in_array($sequence_slug, array('day3_linkedin_followup', 'day10_last_linkedin'), true) || in_array($task_type, array('contact_lead', 'collection', 'linkedin_post'), true)) {
			return array(
				'label' => 'Rapido',
				'class' => 'twob-response-priority-baja',
				'hint' => 'Se puede resolver con mensaje corto o plantilla ajustada.',
			);
		}

		if ('day7_email' === $sequence_slug || in_array($task_type, array('followup', 'hosting_review', 'support', 'content_creation', 'web_optimization'), true)) {
			return array(
				'label' => 'Medio',
				'class' => 'twob-response-priority-media',
				'hint' => 'Conviene revisar contexto y personalizar antes de enviar.',
			);
		}

		return array(
			'label' => 'Alto',
			'class' => 'twob-response-priority-alta',
			'hint' => 'Requiere mas contexto, preparacion o mensaje muy personalizado.',
		);
	}

	private static function lead_first_name($lead_id) {
		$full_name = trim((string) self::lead_contact_name((int) $lead_id));
		if ('' === $full_name) {
			return '';
		}

		$parts = preg_split('/\s+/', $full_name);
		return trim((string) ($parts[0] ?? $full_name));
	}

	private static function lead_message_finding_excerpt($lead_id, $fallback = '') {
		$lead_id = (int) $lead_id;
		$fallback = trim((string) $fallback);
		$finding = trim((string) get_post_meta($lead_id, '_crm_technical_finding', true));
		if ('' === $finding) {
			return $fallback;
		}

		$lines = preg_split('/\R+/', $finding);
		$skip_prefixes = array(
			'empresa:',
			'url:',
			'fecha:',
			'pagespeed móvil:',
			'pagespeed movil:',
			'pagespeed escritorio:',
			'estado general:',
			'críticos',
			'criticos',
			'altos',
			'medios',
			'hallazgo técnico (renata):',
			'hallazgo tecnico (renata):',
		);

		foreach ((array) $lines as $line) {
			$line = trim((string) preg_replace('/^[•\-\x{2192}\x{1F534}\x{1F7E0}\x{1F535}\s]+/u', '', (string) $line));
			if ('' === $line) {
				continue;
			}
			$normalized = function_exists('mb_strtolower') ? mb_strtolower($line) : strtolower($line);
			$should_skip = false;
			foreach ($skip_prefixes as $prefix) {
				if (0 === strpos($normalized, $prefix)) {
					$should_skip = true;
					break;
				}
			}
			if ($should_skip) {
				continue;
			}
			return self::truncate_text($line, 180);
		}

		$flattened = self::truncate_text($finding, 180);
		return $flattened ?: $fallback;
	}

	private static function task_effective_outbound_channel($task_id, $lead_id = 0, $task_type = '') {
		$task_id = (int) $task_id;
		$lead_id = (int) $lead_id;
		$task_type = sanitize_key((string) $task_type);

		if (self::is_reactivation_task($task_id)) {
			$reactivation_channel = self::sanitize_interaction_channel((string) self::reactivation_task_channel($task_id));
			if ($reactivation_channel) {
				return $reactivation_channel;
			}
		}

		$sequence_config = self::task_sequence_step_config($task_id);
		if (! empty($sequence_config['default_channel'])) {
			return self::sanitize_interaction_channel((string) $sequence_config['default_channel']);
		}

		$first_contact_channel = self::lead_first_contact_channel($lead_id);
		return match ($first_contact_channel) {
			'whatsapp', 'red_calida' => 'whatsapp',
			'email', 'web', 'referral' => 'email',
			'call' => 'call',
			'meeting' => 'meeting',
			'linkedin' => 'linkedin',
			default => self::task_default_interaction_channel_for_type($task_type),
		};
	}

	private static function task_client_message_payload($task_id) {
		$task_id = (int) $task_id;
		$fallback = trim((string) get_post_field('post_content', $task_id));
		if (! $fallback) {
			$fallback = trim((string) get_the_title($task_id));
		}
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return array(
				'label' => 'Resumen interno de la tarea',
				'text' => $fallback,
				'is_client_copy' => false,
			);
		}

		$ai_message = trim((string) get_post_meta($task_id, 'twob_task_mensaje_ia', true));
		$ai_generated_at = (int) get_post_meta($task_id, 'twob_task_mensaje_ia_fecha', true);
		if (self::is_alliance_task($task_id)) {
			$alliance_message = $ai_message ?: self::alliance_task_message_text($task_id);
			return array(
				'label' => $ai_message ? 'Mensaje personalizado con IA' : 'Mensaje sugerido para alianza',
				'text' => $alliance_message ?: $fallback,
				'is_client_copy' => true,
				'is_ai' => '' !== $ai_message,
				'generated_at' => $ai_generated_at,
				'generated_at_label' => $ai_generated_at ? self::elapsed_label_from_unix($ai_generated_at) : '',
			);
		}

		$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return array(
				'label' => 'Resumen interno de la tarea',
				'text' => $fallback,
				'is_client_copy' => false,
			);
		}

		$task_type = sanitize_key((string) get_post_meta($task_id, '_crm_task_type', true));
		$sequence_slug = self::task_sequence_step_slug($task_id);
		$channel = self::task_effective_outbound_channel($task_id, $lead_id, $task_type);
		$contact_name = self::lead_first_name($lead_id) ?: self::lead_contact_name($lead_id);
		$company = trim((string) get_post_meta($lead_id, '_crm_company', true)) ?: get_the_title($lead_id);
		$url = trim((string) get_post_meta($lead_id, '_crm_website_url', true));
		$reference = $url ?: $company;
		$finding = self::lead_message_finding_excerpt($lead_id, 'un punto técnico que puede estar afectando resultados');
		$signature = "Danitza\n2B Consulting";
		$label = 'Mensaje sugerido para enviar';
		$text = $fallback;
		$is_client_copy = false;
		if ($ai_message) {
			return array(
				'label' => 'Mensaje personalizado con IA',
				'text' => $ai_message,
				'is_client_copy' => true,
				'is_ai' => true,
				'generated_at' => $ai_generated_at,
				'generated_at_label' => $ai_generated_at ? self::elapsed_label_from_unix($ai_generated_at) : '',
			);
		}

		if (self::is_reactivation_task($task_id)) {
			$is_client_copy = true;
			if ('email' === $channel) {
				$label = 'Email sugerido para enviar';
				$text = 'Asunto: ' . self::reactivation_email_subject($lead_id) . "\n\n" . self::reactivation_email_message($lead_id);
			} elseif ('formulario' === $channel) {
				$label = 'Texto sugerido para formulario';
				$text = self::reactivation_form_message($lead_id);
			} elseif (in_array($channel, array('instagram', 'facebook'), true)) {
				$label = 'Mensaje sugerido para DM';
				$text = self::reactivation_social_message($lead_id);
			} elseif ('telefono' === $channel) {
				$label = 'Guion sugerido para llamar';
				$text = self::reactivation_call_script($lead_id);
			} elseif ('meeting' === $channel) {
				$label = 'Mensaje sugerido para agendar';
				$text = self::reactivation_schedule_message($lead_id);
			}

			return array(
				'label' => $label,
				'text' => $text ?: $fallback,
				'is_client_copy' => $is_client_copy,
			);
		}

		if ('day3_linkedin_followup' === $sequence_slug) {
			$label = 'Mensaje sugerido para enviar por LinkedIn';
			$text = "Hola {$contact_name}, retomo mi mensaje por aquí.\n\nAl revisar {$reference} vi {$finding}.\n\nSi le hace sentido, le comparto en 2 minutos qué encontramos y cómo lo priorizaríamos.";
			$is_client_copy = true;
		} elseif ('day7_email' === $sequence_slug) {
			$label = 'Email sugerido para enviar';
			$text = "Asunto: Seguimiento breve sobre {$company}\n\nHola {$contact_name},\n\nLe escribo por aquí porque al revisar {$reference} vi {$finding}.\n\nSi le hace sentido, le comparto un diagnóstico breve con lo prioritario y el impacto que esto puede tener en resultados.\n\nQuedo atento.\n\n{$signature}";
			$is_client_copy = true;
		} elseif ('day7_email' === $sequence_slug) {
			$label = 'Segundo seguimiento sugerido para email';
			$text = "Asunto: Vi otro punto en {$company} que puede afectar resultados\n\nHola {$contact_name},\n\nAdemás de {$finding}, al revisar {$reference} vimos otras señales que pueden estar frenando conversiones o generando ruido operativo.\n\nSi le sirve, se lo resumo en 15 minutos y le muestro cómo lo priorizaríamos.\n\n{$signature}";
			$is_client_copy = true;
		} elseif ('day10_last_linkedin' === $sequence_slug) {
			$label = 'Último mensaje sugerido para LinkedIn';
			$text = "Hola {$contact_name}, cierro este hilo para no insistir de más.\n\nVi {$finding} en {$reference} y creo que puede afectar resultados, pero prefiero dejarle espacio.\n\nSi en otro momento quiere que se lo resuma, feliz se lo comparto.";
			$is_client_copy = true;
		} elseif ('day12_clean_close' === $sequence_slug) {
			$label = 'Mensaje de cierre sugerido';
			$text = "Hola {$contact_name}, cierro este seguimiento para no insistir más por ahora.\n\nSi más adelante quiere revisar {$reference} con foco en {$finding}, quedo disponible.\n\nUn abrazo,\n\n{$signature}";
			$is_client_copy = true;
		} elseif ('proposal' === $task_type) {
			$label = 'Mensaje sugerido para seguimiento de propuesta';
			$text = "Hola {$contact_name}, ¿alcanzó a revisar la propuesta para {$company}?\n\nSi quiere, le resumo los puntos clave o resolvemos dudas por aquí antes de decidir.\n\nQuedo atento.\n\n{$signature}";
			$is_client_copy = true;
		} elseif ('meeting' === $task_type) {
			$label = 'Mensaje sugerido para agendar o confirmar';
			$text = "Hola {$contact_name}, ¿le parece si vemos esto en una llamada corta de 20 minutos esta semana?\n\nPuedo mostrarle el contexto de {$company} y responder sus dudas.\n\nQuedo atento.\n\n{$signature}";
			$is_client_copy = true;
		} else {
			switch ($channel) {
				case 'email':
					$label = 'Email sugerido para enviar';
					$text = "Asunto: Seguimiento breve sobre {$company}\n\nHola {$contact_name},\n\nRetomo mi mensaje anterior porque al revisar {$reference} vi {$finding}.\n\nSi le hace sentido, le comparto un resumen corto con las prioridades y el posible impacto.\n\nQuedo atento.\n\n{$signature}";
					$is_client_copy = true;
					break;
				case 'whatsapp':
					$label = 'Mensaje sugerido para WhatsApp';
					$text = "Hola {$contact_name}, le escribo porque al revisar {$company} vi {$finding}.\n\nSi quiere, le dejo un resumen corto con lo más importante y cómo lo priorizaríamos.";
					$is_client_copy = true;
					break;
				case 'call':
					$label = 'Guion sugerido para llamada';
					$text = "Hola {$contact_name}, habla Danitza de 2B Consulting.\n\nLe llamo porque al revisar {$company} vi {$finding} y quería entender con quién conviene conversar esto dentro del equipo.";
					$is_client_copy = true;
					break;
				default:
					$label = 'Mensaje sugerido para enviar por LinkedIn';
					$text = "Hola {$contact_name}, retomo mi mensaje por aquí.\n\nRevisé {$reference} y vi {$finding}.\n\nSi le hace sentido, le comparto un resumen muy corto con lo que encontramos.";
					$is_client_copy = true;
					break;
			}
		}

		return array(
			'label' => $label,
			'text' => $text ?: $fallback,
			'is_client_copy' => $is_client_copy,
			'is_ai' => false,
			'generated_at' => 0,
			'generated_at_label' => '',
		);
	}

	private static function response_personalization_meta($lead_id, $result = '', $open_task_id = 0) {
		$lead_id = (int) $lead_id;
		$open_task_id = (int) $open_task_id;
		if ($open_task_id) {
			return self::task_personalization_meta($open_task_id);
		}

		$result = self::sanitize_interaction_result($result);
		if ('meeting_booked' === $result) {
			return array(
				'label' => 'Alto',
				'class' => 'twob-response-priority-alta',
				'hint' => 'Ya hay interes concreto. Prepara respuesta mas cuidada.',
			);
		}
		if ('need_time' === $result || 'interested' === $result) {
			return array(
				'label' => 'Medio',
				'class' => 'twob-response-priority-media',
				'hint' => 'Personaliza la respuesta para cuidar el ritmo de la conversacion.',
			);
		}

		return array(
			'label' => 'Rapido',
			'class' => 'twob-response-priority-baja',
			'hint' => 'Puedes responder en breve y dejar la siguiente fecha.',
		);
	}

	private static function lead_profile_links($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return array();
		}

		$website = trim((string) get_post_meta($lead_id, '_crm_website_url', true));
		$linkedin_person = trim((string) get_post_meta($lead_id, '_crm_linkedin_person', true));
		$linkedin_company = trim((string) get_post_meta($lead_id, '_crm_linkedin_company', true));
		$links = array();

		if ($linkedin_person) {
			$links[] = array('key' => 'linkedin_person', 'label' => 'LinkedIn persona', 'url' => $linkedin_person);
		}
		if ($linkedin_company) {
			$links[] = array('key' => 'linkedin_company', 'label' => 'LinkedIn empresa', 'url' => $linkedin_company);
		}
		if ($website) {
			$links[] = array('key' => 'website', 'label' => 'Sitio web', 'url' => $website);
		}

		return $links;
	}

