	private static function task_type_labels_for_category($category) {
		$all = self::task_type_labels();
		$map = self::task_types_by_category();
		$category = sanitize_key((string) $category);
		$keys = isset($map[$category]) ? $map[$category] : $map['commercial'];
		$labels = array();
		foreach ($keys as $key) {
			if (isset($all[$key])) {
				$labels[$key] = $all[$key];
			}
		}
		return $labels;
	}

	private static function default_task_type_for_category($category) {
		$labels = self::task_type_labels_for_category($category);
		if (! empty($labels)) {
			$keys = array_keys($labels);
			return (string) $keys[0];
		}
		return 'followup';
	}

	private static function task_category_for_type($task_type) {
		$task_type = sanitize_key((string) $task_type);
		foreach (self::task_types_by_category() as $category_key => $type_keys) {
			if (in_array($task_type, $type_keys, true)) {
				return $category_key;
			}
		}
		if (in_array($task_type, array('renewal', 'relationship'), true)) {
			return 'operational';
		}
		return 'commercial';
	}

