	private static function current_crm_user_scope() {
		$user_id = get_current_user_id();
		$plan = sanitize_key((string) get_user_meta($user_id, 'twob_plan_usuario', true));
		if ('renata' === $plan) {
			return 'renata';
		}
		if (in_array($plan, array('dani', 'danitza'), true)) {
			return 'dani';
		}

		$user = wp_get_current_user();
		$display_name = $user ? strtolower((string) $user->display_name) : '';
		$user_login = $user ? strtolower((string) $user->user_login) : '';
		if (false !== strpos($display_name, 'renata') || false !== strpos($user_login, 'renata')) {
			return 'renata';
		}
		if (
			false !== strpos($display_name, 'danitza')
			|| false !== strpos($user_login, 'danitza')
			|| false !== strpos($display_name, 'dani')
			|| false !== strpos($user_login, 'dani')
		) {
			return 'dani';
		}
		if ($user && (user_can($user, 'manage_options') || in_array('administrator', (array) $user->roles, true))) {
			return 'all';
		}

		return 'dani';
	}

	private static function task_matches_current_scope($task_id, $scope = '') {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return false;
		}

		$scope = $scope ?: self::current_crm_user_scope();
		if ('all' === $scope) {
			return true;
		}

		$assignee = self::sanitize_task_assignee((string) get_post_meta($task_id, '_crm_task_assignee', true));
		return 'renata' === $scope ? 'renata' === $assignee : 'renata' !== $assignee;
	}

