	private static function maybe_create_next_recurring_task($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return 0;
		}
		$next_existing = (int) get_post_meta($task_id, '_crm_task_next_recurring_id', true);
		if ($next_existing && 'crm_task' === get_post_type($next_existing)) {
			return $next_existing;
		}
		$recurrence = self::normalize_task_recurrence((string) get_post_meta($task_id, '_crm_task_recurrence', true));
		if ('none' === $recurrence) {
			return 0;
		}
		$due = (string) get_post_meta($task_id, '_crm_task_due', true);
		$next_due = self::next_due_by_recurrence($due, $recurrence);
		if (! $next_due) {
			return 0;
		}

		$title = (string) get_the_title($task_id);
		$content = (string) get_post_field('post_content', $task_id);
		$new_task_id = wp_insert_post(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'post_title' => $title,
			'post_content' => $content,
			'meta_input' => array(
				'_crm_task_due' => $next_due,
				'_crm_task_status' => 'pending',
				'_crm_task_lead_id' => (int) get_post_meta($task_id, '_crm_task_lead_id', true),
				'_crm_task_type' => (string) get_post_meta($task_id, '_crm_task_type', true),
				'_crm_task_priority' => (string) get_post_meta($task_id, '_crm_task_priority', true),
				'_crm_task_start_time' => (string) get_post_meta($task_id, '_crm_task_start_time', true),
				'_crm_task_duration' => (int) get_post_meta($task_id, '_crm_task_duration', true),
				'_crm_task_meeting_url' => (string) get_post_meta($task_id, '_crm_task_meeting_url', true),
				'_crm_task_meeting_location' => (string) get_post_meta($task_id, '_crm_task_meeting_location', true),
				'_crm_task_category' => (string) get_post_meta($task_id, '_crm_task_category', true),
				'_crm_task_relation' => (string) get_post_meta($task_id, '_crm_task_relation', true),
				'_crm_task_assignee' => (string) get_post_meta($task_id, '_crm_task_assignee', true),
				'_crm_task_pipeline_stage' => (string) get_post_meta($task_id, '_crm_task_pipeline_stage', true),
				'_crm_task_recurrence' => $recurrence,
				'_crm_task_recurring_parent' => $task_id,
			),
		));
		if ($new_task_id && ! is_wp_error($new_task_id)) {
			update_post_meta($task_id, '_crm_task_next_recurring_id', (int) $new_task_id);
			return (int) $new_task_id;
		}
		return 0;
	}

