	private static function validate_lead_payload($data, $mode = 'contacted') {
		$mode = self::normalize_lead_creation_mode($mode);
		if ('pre_contact' === $mode) {
			$name = trim((string) ($data['name'] ?? ''));
			$origin = trim((string) ($data['origin_channel'] ?? ''));
			$company = trim((string) ($data['company'] ?? ''));
			$website = trim((string) ($data['website_url'] ?? ''));
			$email = trim((string) ($data['email'] ?? ''));

			if (! $name) {
				return new WP_Error('lead_name_required', 'Nombre completo es obligatorio.');
			}
			if (! $company) {
				return new WP_Error('lead_company_required', 'Empresa es obligatoria para Pre-contacto.');
			}
			if (! $origin) {
				return new WP_Error('lead_origin_required', 'Canal de origen es obligatorio.');
			}
			if (! $website) {
				return new WP_Error('lead_website_required', 'Sitio web es obligatorio para Pre-contacto.');
			}
			if ($email && ! is_email($email)) {
				return new WP_Error('lead_email_invalid', 'Email invalido.');
			}
			return true;
		}

		return TwoB_CRM_Dani_Leads_Module::validate_payload($data);
	}

	private static function determine_temperature($lead_id) {
		$stage = (string) get_post_meta($lead_id, '_crm_stage', true);
		$origin_channel = sanitize_key((string) get_post_meta($lead_id, '_crm_origin_channel', true));
		$close_reason = self::get_lead_close_reason_code($lead_id);
		if (self::is_pre_contact_stage($stage)) {
			return 'warm';
		}
		if ('won' === $close_reason) {
			return 'hot';
		}
		if ('lost' === $close_reason || 'no_response' === $close_reason || self::is_closed_detail_stage($stage)) {
			return 'cold';
		}
		$latest = get_posts(array(
			'post_type' => 'crm_interaction',
			'post_status' => 'publish',
			'numberposts' => 1,
			'orderby' => 'date',
			'order' => 'DESC',
			'meta_query' => array(
				array('key' => '_crm_lead_id', 'value' => $lead_id, 'compare' => '='),
			),
		));
		$days = 999;
		$latest_result = '';
		if (! empty($latest[0])) {
			$interaction_date = (string) get_post_meta($latest[0]->ID, '_crm_interaction_date', true);
			if (! $interaction_date) {
				$interaction_date = substr((string) $latest[0]->post_date, 0, 10);
			}
			$days = (int) floor((strtotime(current_time('Y-m-d')) - strtotime($interaction_date)) / DAY_IN_SECONDS);
			$latest_result = (string) get_post_meta($latest[0]->ID, '_crm_interaction_result', true);
		} else {
			$created = get_post($lead_id);
			if ($created) {
				$days = (int) floor((strtotime(current_time('Y-m-d')) - strtotime(substr((string) $created->post_date, 0, 10))) / DAY_IN_SECONDS);
			}
		}
		if (in_array($latest_result, array('interested', 'meeting_booked', 'need_time'), true) || in_array($stage, array('responded_interested', 'meeting_scheduled', 'meeting_done', 'proposal_sent', 'won'), true)) {
			return 'hot';
		}
		if ($days >= 7) {
			return 'cold';
		}
		return self::temperature_seed_for_origin_channel($origin_channel, $stage);
	}

	private static function temperature_seed_for_origin_channel($origin_channel, $stage = '') {
		return TwoB_CRM_Dani_Sales_Policy_Module::temperature_seed_for_origin_channel($origin_channel, $stage);
	}

	private static function is_temperature_manual($lead_id) {
		return 'manual' === sanitize_key((string) get_post_meta((int) $lead_id, '_crm_temperature_mode', true));
	}

	private static function set_temperature_mode($lead_id, $is_manual) {
		update_post_meta((int) $lead_id, '_crm_temperature_mode', $is_manual ? 'manual' : 'auto');
	}

	private static function apply_temperature_selection($lead_id, $submitted_temperature = '', $origin_channel = '', $stage = '', $manual_requested = false, $previous_temperature = '') {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return 'warm';
		}

		$submitted_temperature = self::normalize_temperature($submitted_temperature, false);
		$previous_temperature = self::normalize_temperature($previous_temperature, false);
		$recommended = self::normalize_temperature(self::determine_temperature($lead_id), false);
		if (! $recommended) {
			$recommended = self::temperature_seed_for_origin_channel(
				$origin_channel ?: (string) get_post_meta($lead_id, '_crm_origin_channel', true),
				$stage ?: (string) get_post_meta($lead_id, '_crm_stage', true)
			);
		}

		$is_manual = false;
		if ($submitted_temperature && $submitted_temperature !== $recommended) {
			$is_manual = $manual_requested || ($previous_temperature && $submitted_temperature !== $previous_temperature);
		}

		if ($is_manual) {
			self::set_temperature_mode($lead_id, true);
			update_post_meta($lead_id, '_crm_temperature', $submitted_temperature);
			self::update_lead_score($lead_id);
			return $submitted_temperature;
		}

		self::set_temperature_mode($lead_id, false);
		update_post_meta($lead_id, '_crm_temperature', $recommended);
		self::update_lead_score($lead_id);
		return $recommended;
	}

	private static function update_temperature($lead_id, $force = false) {
		$lead_id = (int) $lead_id;
		$current = self::normalize_temperature((string) get_post_meta($lead_id, '_crm_temperature', true));
		if (self::is_temperature_manual($lead_id)) {
			$current = $current ?: 'warm';
			self::update_lead_score($lead_id);
			return $current;
		}

		$temp = self::normalize_temperature(self::determine_temperature($lead_id), false);
		if (! $temp) {
			$temp = self::temperature_seed_for_origin_channel(
				(string) get_post_meta($lead_id, '_crm_origin_channel', true),
				(string) get_post_meta($lead_id, '_crm_stage', true)
			);
		}
		if ($force || $temp !== $current) {
			self::set_temperature_mode($lead_id, false);
			update_post_meta($lead_id, '_crm_temperature', $temp);
		}
		self::update_lead_score($lead_id);
		return $temp;
	}

	private static function normalize_score_text($text) {
		$text = (string) $text;
		if (function_exists('remove_accents')) {
			$text = remove_accents($text);
		}
		$text = function_exists('mb_strtolower') ? mb_strtolower($text, 'UTF-8') : strtolower($text);
		return trim((string) preg_replace('/\s+/', ' ', $text));
	}

	private static function lead_score_has_response($lead_id) {
		foreach (self::get_lead_interactions((int) $lead_id, -1) as $interaction) {
			$result = self::sanitize_interaction_result((string) get_post_meta((int) $interaction->ID, '_crm_interaction_result', true));
			if ($result && 'no_answer' !== $result) {
				return true;
			}
		}
		return false;
	}

	private static function lead_score_sector_points($lead_id) {
		$lead_id = (int) $lead_id;
		$settings = self::settings_get();
		$sector_key = sanitize_key((string) get_post_meta($lead_id, '_crm_client_type', true));
		$sector_label = (string) ($settings['client_types'][$sector_key] ?? $sector_key);
		$sector_text = self::normalize_score_text($sector_key . ' ' . $sector_label);
		if (preg_match('/salud|clinic|medic|dental|hotel|turis|inmobil|constructor|corredor|educa|coleg|institut|academ/', $sector_text)) {
			return 20;
		}
		return 10;
	}

	private static function lead_score_hallazgo_points($lead_id) {
		$finding = trim((string) get_post_meta((int) $lead_id, '_crm_technical_finding', true));
		if ('' === $finding) {
			return 0;
		}
		$finding_text = self::normalize_score_text($finding);
		if (preg_match('/\b(ssl|formulario|vence|error|caido|spam|dkim)\b/', $finding_text)) {
			return 15;
		}
		return 8;
	}

	private static function lead_score_time_penalty($lead_id, $today = '') {
		$last_touch = self::lead_last_touch_day((int) $lead_id);
		if (! $last_touch) {
			return 0;
		}
		$days_since_touch = self::days_between_dates($last_touch, $today ?: current_time('Y-m-d'));
		if ($days_since_touch <= 3) {
			return 0;
		}
		return min(20, ($days_since_touch - 3) * 5);
	}

	public static function twob_calcular_score($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return 0;
		}

		$origin_channel = sanitize_key((string) get_post_meta($lead_id, '_crm_origin_channel', true));
		$channel_points = match ($origin_channel) {
			'red_calida' => 30,
			'referral' => 25,
			'whatsapp' => 20,
			'linkedin' => 15,
			'email' => 10,
			default => 0,
		};

		$temperature = self::normalize_temperature((string) get_post_meta($lead_id, '_crm_temperature', true), false);
		if (! $temperature) {
			$temperature = self::normalize_temperature(self::determine_temperature($lead_id), false);
		}
		if (! $temperature) {
			$temperature = self::temperature_seed_for_origin_channel(
				(string) get_post_meta($lead_id, '_crm_origin_channel', true),
				(string) get_post_meta($lead_id, '_crm_stage', true)
			);
		}
		$temperature_points = match ($temperature) {
			'hot' => 10,
			'warm' => 5,
			default => 0,
		};

		$score = 0;
		$score += $channel_points;
		$score += self::lead_score_has_response($lead_id) ? 25 : 0;
		$score += self::lead_score_sector_points($lead_id);
		$score += self::lead_score_hallazgo_points($lead_id);
		$score += $temperature_points;
		$score -= self::lead_score_time_penalty($lead_id);

		return max(0, min(100, (int) $score));
	}

	private static function update_lead_score($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return 0;
		}
		$score = self::twob_calcular_score($lead_id);
		update_post_meta($lead_id, 'twob_lead_score', $score);
		return $score;
	}

	private static function lead_score($lead_id, $force_sync = false) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return 0;
		}
		$stored = get_post_meta($lead_id, 'twob_lead_score', true);
		if ($force_sync || '' === $stored || null === $stored) {
			return self::update_lead_score($lead_id);
		}
		return max(0, min(100, (int) $stored));
	}

	private static function score_badge_meta($score) {
		$score = max(0, min(100, (int) $score));
		if ($score >= 80) {
			return array('label' => 'Score ' . $score, 'class' => 'is-high', 'indicator' => 'is-score-high');
		}
		if ($score >= 60) {
			return array('label' => 'Score ' . $score, 'class' => 'is-medium', 'indicator' => 'is-score-medium');
		}
		if ($score >= 40) {
			return array('label' => 'Score ' . $score, 'class' => 'is-watch', 'indicator' => 'is-score-watch');
		}
		return array('label' => 'Score ' . $score, 'class' => 'is-low', 'indicator' => 'is-score-low');
	}

