	private static function lead_sequence_policy($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return 'full';
		}

		$version = (string) get_post_meta($lead_id, '_crm_sequence_policy_version', true);
		if (self::SEQUENCE_POLICY_VERSION !== $version) {
			return 'full';
		}

		$policy = sanitize_key((string) get_post_meta($lead_id, '_crm_sequence_policy', true));
		return isset(self::lead_sequence_policy_labels()[$policy]) ? $policy : self::sequence_policy_for_origin_channel((string) get_post_meta($lead_id, '_crm_origin_channel', true));
	}

	private static function update_lead_sequence_policy($lead_id, $origin_channel, $force_new_version = false) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return 'full';
		}

		$policy = self::sequence_policy_for_origin_channel($origin_channel);
		$current_version = (string) get_post_meta($lead_id, '_crm_sequence_policy_version', true);
		if ($force_new_version || self::SEQUENCE_POLICY_VERSION === $current_version) {
			update_post_meta($lead_id, '_crm_sequence_policy', $policy);
			update_post_meta($lead_id, '_crm_sequence_policy_version', self::SEQUENCE_POLICY_VERSION);
			return $policy;
		}

		return 'full';
	}

	private static function lead_sequence_anchor_day($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return '';
		}

		$first_contacted_at = trim((string) get_post_meta($lead_id, '_crm_first_contacted_at', true));
		if ($first_contacted_at) {
			$anchor = self::normalize_iso_day(substr($first_contacted_at, 0, 10));
			if ($anchor) {
				return $anchor;
			}
		}

		return self::lead_created_day($lead_id);
	}

	private static function lead_sequence_due_day($lead_id, $offset) {
		$anchor_day = self::lead_sequence_anchor_day((int) $lead_id);
		if (! $anchor_day) {
			return '';
		}

		return self::add_chile_business_days($anchor_day, (int) $offset);
	}

	private static function has_recent_proposal_followup($lead_id, $date) {
		$latest = get_posts(array(
			'post_type' => 'crm_interaction',
			'post_status' => 'publish',
			'numberposts' => 1,
			'orderby' => 'date',
			'order' => 'DESC',
			'meta_query' => array(
				'relation' => 'AND',
				array('key' => '_crm_lead_id', 'value' => $lead_id, 'compare' => '='),
				array('key' => '_crm_interaction_kind', 'value' => 'followup', 'compare' => '='),
			),
		));
		if (empty($latest[0])) {
			return false;
		}
		$last_date = (string) get_post_meta($latest[0]->ID, '_crm_interaction_date', true);
		if (! $last_date) {
			$last_date = substr((string) $latest[0]->post_date, 0, 10);
		}
		return self::business_days_between_dates($last_date, $date) < 3;
	}

