	private static function lead_followup_sequence_steps_for_policy($policy) {
		$policy = sanitize_key((string) $policy);
		$steps = self::lead_followup_sequence_steps();
		if ('manual' === $policy) {
			return array();
		}
		if ('short' === $policy) {
			return array_values(array_filter($steps, function ($step) {
				return 'day3_linkedin_followup' === sanitize_key((string) ($step['slug'] ?? ''));
			}));
		}
		return $steps;
	}

	private static function lead_followup_step_by_slug($slug) {
		$slug = sanitize_key((string) $slug);
		foreach (self::lead_followup_sequence_steps() as $step) {
			if ($slug === sanitize_key((string) ($step['slug'] ?? ''))) {
				return $step;
			}
		}
		return array();
	}

	private static function task_sequence_step_slug($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return '';
		}

		$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
		$auto_key = (string) get_post_meta($task_id, '_crm_auto_key', true);
		$prefix = 'lead_sequence_' . $lead_id . '_';
		if ($lead_id && $auto_key && 0 === strpos($auto_key, $prefix)) {
			return sanitize_key(substr($auto_key, strlen($prefix)));
		}

		return '';
	}

	private static function task_sequence_step_config($task_id) {
		$slug = self::task_sequence_step_slug((int) $task_id);
		return $slug ? self::lead_followup_step_by_slug($slug) : array();
	}

	private static function default_next_followup_for_sequence_task($task_id, $base_day = '') {
		$config = self::task_sequence_step_config((int) $task_id);
		$gap = isset($config['next_followup_gap']) ? max(0, (int) $config['next_followup_gap']) : 0;
		$base_day = self::normalize_iso_day($base_day ?: current_time('Y-m-d'));
		if (! $gap || ! $base_day) {
			return '';
		}

		return self::add_chile_business_days($base_day, $gap);
	}

	private static function task_next_action_label($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return '';
		}

		$sequence_config = self::task_sequence_step_config($task_id);
		if (! empty($sequence_config['next_action_label'])) {
			return sanitize_text_field((string) $sequence_config['next_action_label']);
		}

		$task_type = sanitize_key((string) get_post_meta($task_id, '_crm_task_type', true));
		$title = trim((string) get_the_title($task_id));
		if ($title && ! in_array($task_type, array('followup', 'contact_lead'), true)) {
			return sanitize_text_field($title);
		}

		return match ($task_type) {
			'meeting' => 'Preparar reunion',
			'proposal' => 'Responder propuesta',
			'contact_lead' => 'Registrar primer mensaje',
			default => 'Seguimiento comercial',
		};
	}

	private static function primary_open_task_for_lead($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return 0;
		}

		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => 20,
			'meta_key' => '_crm_task_due',
			'orderby' => 'meta_value',
			'order' => 'ASC',
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => '_crm_task_lead_id', 'value' => $lead_id, 'compare' => '='),
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
		));

		foreach ($tasks as $task_id) {
			$task_id = (int) $task_id;
			if (! self::task_should_be_hidden_from_open_views($task_id)) {
				return $task_id;
			}
		}

		return 0;
	}

	private static function infer_lead_next_action($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return '';
		}

		$task_id = self::primary_open_task_for_lead($lead_id);
		if ($task_id) {
			return self::task_next_action_label($task_id);
		}
		if (self::lead_has_response_signal($lead_id)) {
			return 'Responder lead';
		}
		if (! self::lead_has_logged_interaction($lead_id)) {
			return 'Registrar primer mensaje';
		}
		return 'Seguimiento comercial';
	}

	private static function sync_lead_next_action($lead_id, $forced_label = null) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return;
		}

		$next_followup = trim((string) get_post_meta($lead_id, '_crm_next_followup', true));
		$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		$lifecycle_state = self::lead_lifecycle_state($lead_id);
		$manual_archive = (bool) get_post_meta($lead_id, '_crm_manual_archive', true);
		if (! $next_followup || 'closed' === $lifecycle_state || self::is_closed_detail_stage($stage) || $manual_archive || self::lead_should_archive_by_next_action_gap($lead_id) || self::lead_should_auto_close_on_day12($lead_id)) {
			update_post_meta($lead_id, '_crm_next_action', '');
			return;
		}

		$label = null;
		if (null !== $forced_label) {
			$label = trim((string) $forced_label);
		}
		if ('' === (string) $label) {
			$label = self::infer_lead_next_action($lead_id);
		}
		update_post_meta($lead_id, '_crm_next_action', sanitize_text_field((string) $label));
	}

	private static function set_lead_next_followup_meta($lead_id, $next_followup = '', $forced_label = null) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return;
		}

		$next_followup = trim((string) $next_followup);
		if ($next_followup) {
			$next_followup = self::normalize_business_due_day($next_followup);
		}

		update_post_meta($lead_id, '_crm_next_followup', $next_followup);
		self::sync_lead_next_action($lead_id, $forced_label);
	}

	private static function lead_stage_requires_next_action($stage) {
		$stage = self::normalize_stage_key((string) $stage);
		return ! in_array($stage, array('pre_contact', 'new', 'closed_no_response', 'lost', 'won'), true);
	}

	private static function lead_should_archive_by_next_action_gap($lead_id, $today = '') {
		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		$next_followup = trim((string) get_post_meta($lead_id, '_crm_next_followup', true));
		if (! $lead_id || ! $next_followup) {
			return false;
		}

		return $today > self::add_chile_business_days($next_followup, 3);
	}

	private static function lead_should_auto_close_on_day12($lead_id, $today = '') {
		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		if (! $lead_id || self::lead_has_response_signal($lead_id)) {
			return false;
		}
		$lead = get_post($lead_id);
		if (! $lead || 'crm_lead' !== $lead->post_type) {
			return false;
		}

		$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		if (self::is_pre_contact_stage($stage)) {
			return false;
		}
		if (self::is_closed_detail_stage($stage)) {
			return false;
		}
		$anchor_day = self::lead_sequence_anchor_day($lead_id);
		if (! $anchor_day) {
			return false;
		}
		$close_day = self::add_chile_business_days($anchor_day, 12);
		return $close_day <= $today;
	}

	private static function auto_close_lead_without_response($lead_id, $today = '') {
		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return false;
		}
		if (self::lead_has_response_signal($lead_id)) {
			return false;
		}

		$close_note = 'Cierre automatico D+12: el lead no respondio dentro del ciclo inicial.';
		$stage_result = self::set_lead_stage($lead_id, 'closed_no_response', 'day12_auto_close', $close_note);
		if (is_wp_error($stage_result)) {
			return false;
		}
		self::set_lead_close_reason_code($lead_id, 'no_response');
		self::sync_lead_lifecycle_state($lead_id, $today, 'no_response');
		self::set_lead_next_followup_meta($lead_id, '');
		self::close_sequence_tasks_for_lead($lead_id, $close_note, $today);
		self::close_open_commercial_tasks_for_lead($lead_id, 'closed_no_response', $close_note, 'day12_auto_close');
		self::update_temperature($lead_id);
		self::update_operational_status($lead_id, $today);
		self::sync_master_client_for_lead($lead_id);
		return true;
	}

	private static function ensure_today_positive_response_interaction($lead_id, $today = '', $note = '') {
		$lead_id = (int) $lead_id;
		$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
		if (! $lead) {
			return 0;
		}

		$today = $today ?: current_time('Y-m-d');
		$note = trim((string) $note) ?: 'Lead marcado como respondido desde el tablero.';
		$todays_interactions = get_posts(array(
			'post_type' => 'crm_interaction',
			'post_status' => 'publish',
			'numberposts' => 5,
			'orderby' => 'date',
			'order' => 'DESC',
			'meta_query' => array(
				array('key' => '_crm_lead_id', 'value' => $lead_id, 'compare' => '='),
				array('key' => '_crm_interaction_date', 'value' => $today, 'compare' => '='),
			),
		));

		$seed_interaction = null;
		foreach ($todays_interactions as $interaction) {
			$interaction = self::get_valid_crm_post((int) $interaction->ID, 'crm_interaction');
			if (! $interaction) {
				continue;
			}
			if (! $seed_interaction) {
				$seed_interaction = $interaction;
			}
			$result = self::sanitize_interaction_result((string) get_post_meta((int) $interaction->ID, '_crm_interaction_result', true));
			if (self::interaction_result_is_positive($result)) {
				return (int) $interaction->ID;
			}
		}

		$reference_interaction = $seed_interaction;
		if (! $reference_interaction) {
			$latest = self::lead_latest_interaction($lead_id);
			if ($latest instanceof WP_Post) {
				$reference_interaction = $latest;
			}
		}

		$channel = $reference_interaction instanceof WP_Post
			? self::sanitize_interaction_channel((string) get_post_meta((int) $reference_interaction->ID, '_crm_interaction_channel', true))
			: 'linkedin';
		if (! $channel) {
			$channel = 'linkedin';
		}
		$interaction_action = $reference_interaction instanceof WP_Post
			? self::sanitize_interaction_action((string) get_post_meta((int) $reference_interaction->ID, '_crm_interaction_action', true))
			: '';
		if (! $interaction_action) {
			$interaction_action = self::normalize_interaction_action('', 'followup', $channel);
		}

		if ($seed_interaction instanceof WP_Post) {
			$interaction_id = (int) $seed_interaction->ID;
			update_post_meta($interaction_id, '_crm_interaction_kind', self::sanitize_interaction_kind((string) get_post_meta($interaction_id, '_crm_interaction_kind', true) ?: 'followup'));
			update_post_meta($interaction_id, '_crm_lead_id', $lead_id);
			update_post_meta($interaction_id, '_crm_interaction_date', $today);
			update_post_meta($interaction_id, '_crm_interaction_channel', $channel);
			update_post_meta($interaction_id, '_crm_interaction_action', $interaction_action);
			update_post_meta($interaction_id, '_crm_interaction_result', 'interested');
			update_post_meta($interaction_id, '_crm_interaction_stage', 'responded_interested');
			update_post_meta($interaction_id, '_crm_interaction_next_followup', $today);
			update_post_meta($interaction_id, '_crm_interaction_note', $note);
			return $interaction_id;
		}

		$interaction_id = wp_insert_post(array(
			'post_type' => 'crm_interaction',
			'post_status' => 'publish',
			'post_title' => 'Respuesta: ' . wp_strip_all_tags(get_the_title($lead_id)),
			'meta_input' => array(
				'_crm_interaction_kind' => 'followup',
				'_crm_lead_id' => $lead_id,
				'_crm_interaction_date' => $today,
				'_crm_interaction_channel' => $channel,
				'_crm_interaction_action' => $interaction_action,
				'_crm_interaction_result' => 'interested',
				'_crm_interaction_stage' => 'responded_interested',
				'_crm_interaction_next_followup' => $today,
				'_crm_interaction_note' => $note,
			),
		));

		return is_wp_error($interaction_id) ? 0 : (int) $interaction_id;
	}

	private static function lead_created_day($lead_id) {
		$lead = get_post((int) $lead_id);
		if (! $lead || 'crm_lead' !== $lead->post_type) {
			return '';
		}
		$created_at = ! empty($lead->post_date) ? (string) $lead->post_date : current_time('mysql');
		return substr($created_at, 0, 10);
	}

	private static function lead_created_timestamp($lead_id) {
		$lead = get_post((int) $lead_id);
		if (! $lead || 'crm_lead' !== $lead->post_type) {
			return 0;
		}
		$created_at = ! empty($lead->post_date) ? (string) $lead->post_date : current_time('mysql');
		$timestamp = strtotime($created_at);
		return $timestamp ? (int) $timestamp : 0;
	}

	private static function elapsed_label_from_timestamp($timestamp) {
		$timestamp = (int) $timestamp;
		if ($timestamp <= 0) {
			return '';
		}

		$now = current_time('timestamp');
		$diff = max(60, $now - $timestamp);
		$minutes = (int) floor($diff / MINUTE_IN_SECONDS);
		$hours = (int) floor($diff / HOUR_IN_SECONDS);
		$days = (int) floor($diff / DAY_IN_SECONDS);

		if ($days >= 1) {
			return 'hace ' . $days . ' dia' . (1 === $days ? '' : 's');
		}
		if ($hours >= 1) {
			return 'hace ' . $hours . ' hora' . (1 === $hours ? '' : 's');
		}
		return 'hace ' . max(1, $minutes) . ' min';
	}

	private static function lead_wait_age_meta($lead_id) {
		$timestamp = self::lead_created_timestamp($lead_id);
		$now = current_time('timestamp');
		$diff = $timestamp ? max(0, $now - $timestamp) : 0;

		return array(
			'timestamp' => $timestamp,
			'hours' => (int) floor($diff / HOUR_IN_SECONDS),
			'label' => self::elapsed_label_from_timestamp($timestamp),
			'is_warning' => $diff >= (4 * HOUR_IN_SECONDS),
		);
	}

	private static function reactivation_lead_url($lead_id, $prepare = false) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return '';
		}

		$args = array(
			'page' => 'twob-crm-visual-leads',
			'lead_id' => $lead_id,
			'q' => rawurlencode((string) get_the_title($lead_id)),
		);
		if ($prepare) {
			$args['reactivation'] = '1';
		}

		return admin_url('admin.php?' . http_build_query($args)) . '#lead-' . $lead_id;
	}

	private static function lead_first_contact_channel($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return '';
		}

		$stored = sanitize_key((string) get_post_meta($lead_id, '_crm_first_contact_channel', true));
		if ($stored && isset(self::first_contact_channel_labels()[$stored])) {
			return $stored;
		}

		$first_contacts = get_posts(array(
			'post_type' => 'crm_interaction',
			'post_status' => 'publish',
			'numberposts' => 1,
			'orderby' => 'date',
			'order' => 'ASC',
			'meta_query' => array(
				'relation' => 'AND',
				array('key' => '_crm_lead_id', 'value' => $lead_id, 'compare' => '='),
				array('key' => '_crm_interaction_kind', 'value' => 'contact', 'compare' => '='),
			),
		));
		if (! empty($first_contacts[0])) {
			$channel = self::sanitize_interaction_channel((string) get_post_meta((int) $first_contacts[0]->ID, '_crm_interaction_channel', true));
			if ($channel && isset(self::first_contact_channel_labels()[$channel])) {
				return $channel;
			}
		}

		$origin = sanitize_key((string) get_post_meta($lead_id, '_crm_origin_channel', true));
		return isset(self::channel_labels()[$origin]) ? $origin : '';
	}

	private static function lead_completed_linkedin_outreach_cycle($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return false;
		}

		$sequence_map = self::get_lead_sequence_task_map($lead_id);
		$linkedin_steps = array('day0_linkedin', 'day3_linkedin_followup', 'day10_last_linkedin');
		$has_linkedin_step = false;
		foreach ($linkedin_steps as $step_key) {
			if (! empty($sequence_map[$step_key])) {
				$has_linkedin_step = true;
				break;
			}
		}

		return $has_linkedin_step;
	}

	private static function lead_used_linkedin_reactivation_path($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return false;
		}

		if ('linkedin' === sanitize_key((string) get_post_meta($lead_id, '_crm_origin_channel', true))) {
			return true;
		}

		if ('linkedin' === self::lead_first_contact_channel($lead_id)) {
			return true;
		}

		return self::lead_completed_linkedin_outreach_cycle($lead_id);
	}

	private static function reactivation_lead_is_eligible($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id) || 'trash' === get_post_status($lead_id)) {
			return false;
		}

		$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		if (! in_array($stage, array('lost', 'closed_no_response'), true)) {
			return false;
		}

		return self::lead_used_linkedin_reactivation_path($lead_id);
	}

	private static function get_reactivation_leads_for_automation($args = array()) {
		$defaults = array(
			'post_type' => 'crm_lead',
			'post_status' => 'publish',
			'numberposts' => -1,
			'orderby' => 'date',
			'order' => 'DESC',
		);

		return get_posts(wp_parse_args($args, $defaults));
	}

	private static function reactivation_task_result_is_exhausted($result_state) {
		$result_state = sanitize_key((string) $result_state);
		if (in_array($result_state, array('respondio_interes', 'reunion_agendada', 'rechazado', 'consegui_email', 'consegui_contacto', 'consegui_telefono'), true)) {
			return false;
		}

		return in_array($result_state, array('enviado_sin_respuesta', 'cerrada'), true);
	}

	private static function reactivation_is_paused($lead_id, $today = '') {
		$today = $today ?: current_time('Y-m-d');
		$pause_until = self::normalize_iso_day((string) get_post_meta((int) $lead_id, 'twob_react_pausa_hasta', true));
		return (bool) ($pause_until && $pause_until > $today);
	}

	private static function reactivation_closed_day($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return '';
		}

		$activities = get_posts(array(
			'post_type' => 'crm_activity',
			'post_status' => 'publish',
			'numberposts' => 20,
			'orderby' => 'date',
			'order' => 'DESC',
			'meta_query' => array(
				array('key' => '_crm_object_id', 'value' => $lead_id, 'compare' => '='),
				array('key' => '_crm_action', 'value' => 'stage_changed', 'compare' => '='),
			),
		));

		foreach ($activities as $activity) {
			$new_stage = self::normalize_stage_key((string) get_post_meta((int) $activity->ID, '_crm_stage', true));
			if (in_array($new_stage, array('lost', 'closed_no_response'), true)) {
				return substr((string) $activity->post_date, 0, 10);
			}
		}

		return self::lead_created_day($lead_id);
	}

	private static function reactivation_payload($lead_id) {
		$lead_id = (int) $lead_id;
		$payload = array(
			'telefono' => '',
			'email' => '',
			'formulario_url' => '',
			'instagram' => '',
			'facebook' => '',
			'sector' => '',
			'hallazgo' => '',
			'sequence_generated' => false,
			'sequence' => array(),
			'date_start' => '',
			'responded' => false,
			'agotada' => false,
			'pause_until' => '',
		);
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return $payload;
		}

		$sequence_raw = get_post_meta($lead_id, 'twob_react_secuencia_canales', true);
		$sequence = array();
		if (is_string($sequence_raw) && '' !== trim($sequence_raw)) {
			$decoded = json_decode($sequence_raw, true);
			if (is_array($decoded)) {
				$sequence = $decoded;
			}
		} elseif (is_array($sequence_raw)) {
			$sequence = $sequence_raw;
		}

		$payload['telefono'] = trim((string) get_post_meta($lead_id, 'twob_react_telefono', true));
		$payload['email'] = sanitize_email((string) get_post_meta($lead_id, 'twob_react_email', true));
		$payload['formulario_url'] = esc_url_raw((string) get_post_meta($lead_id, 'twob_react_formulario_url', true));
		$payload['instagram'] = esc_url_raw((string) get_post_meta($lead_id, 'twob_react_instagram', true));
		$payload['facebook'] = esc_url_raw((string) get_post_meta($lead_id, 'twob_react_facebook', true));
		$payload['sector'] = self::sanitize_reactivation_sector((string) get_post_meta($lead_id, 'twob_sector', true));
		$payload['hallazgo'] = trim((string) get_post_meta($lead_id, '_crm_technical_finding', true));
		$payload['sequence_generated'] = (bool) get_post_meta($lead_id, 'twob_react_secuencia_generada', true);
		$payload['sequence'] = array_values(array_filter((array) $sequence, function ($step) {
			return is_array($step) && ! empty($step['canal']);
		}));
		$payload['date_start'] = self::normalize_iso_day((string) get_post_meta($lead_id, 'twob_react_fecha_inicio', true));
		$payload['responded'] = (bool) get_post_meta($lead_id, 'twob_react_respondio', true);
		$payload['agotada'] = (bool) get_post_meta($lead_id, 'twob_react_agotada', true);
		$payload['pause_until'] = self::normalize_iso_day((string) get_post_meta($lead_id, 'twob_react_pausa_hasta', true));

		return $payload;
	}

	private static function reactivation_has_any_channel($payload) {
		$payload = is_array($payload) ? $payload : array();
		return '' !== trim((string) ($payload['telefono'] ?? ''))
			|| '' !== trim((string) ($payload['email'] ?? ''))
			|| '' !== trim((string) ($payload['formulario_url'] ?? ''))
			|| '' !== trim((string) ($payload['instagram'] ?? ''))
			|| '' !== trim((string) ($payload['facebook'] ?? ''));
	}

	private static function reactivation_task_auto_key($lead_id, $channel, $day, $suffix = '') {
		$key = 'reactivacion_' . (int) $lead_id . '_' . sanitize_key((string) $channel) . '_d' . (int) $day;
		if ('' !== $suffix) {
			$key .= '_' . sanitize_key((string) $suffix);
		}
		return $key;
	}

	private static function is_reactivation_task($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return false;
		}
		return 'reactivacion' === sanitize_key((string) get_post_meta($task_id, 'twob_task_tipo', true))
			|| (bool) get_post_meta($task_id, '_crm_task_reactivation', true);
	}

	private static function reactivation_task_channel($task_id) {
		$task_id = (int) $task_id;
		if (! self::is_reactivation_task($task_id)) {
			return '';
		}
		$channel = sanitize_key((string) get_post_meta($task_id, 'twob_task_canal', true));
		return isset(self::reactivation_channel_labels()[$channel]) ? $channel : '';
	}

	private static function reactivation_tasks_for_lead($lead_id, $open_only = false) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return array();
		}

		$meta_query = array(
			array('key' => '_crm_task_lead_id', 'value' => $lead_id, 'compare' => '='),
			array('key' => 'twob_task_tipo', 'value' => 'reactivacion', 'compare' => '='),
		);
		if ($open_only) {
			$meta_query[] = array(
				'relation' => 'OR',
				array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
				array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
				array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
			);
		}

		return get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => -1,
			'meta_key' => '_crm_task_due',
			'orderby' => 'meta_value',
			'order' => 'ASC',
			'meta_query' => $meta_query,
		));
	}

	private static function close_reactivation_tasks_for_lead($lead_id, $note = '', $result_state = 'cerrada') {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return 0;
		}

		$closed = 0;
		foreach (self::reactivation_tasks_for_lead($lead_id, true) as $task) {
			$task_id = (int) $task->ID;
			update_post_meta($task_id, '_crm_task_status', 'done');
			update_post_meta($task_id, '_crm_task_completed_at', current_time('mysql'));
			update_post_meta($task_id, 'twob_task_estado', sanitize_key((string) $result_state) ?: 'cerrada');
			update_post_meta($task_id, 'twob_react_result_state', sanitize_key((string) $result_state) ?: 'cerrada');
			if ('' !== trim((string) $note)) {
				update_post_meta($task_id, '_crm_task_completion_note', sanitize_textarea_field($note));
			}
			self::sync_google_task_status_prefix($task_id, 'done');
			$closed++;
		}

		return $closed;
	}

	private static function build_reactivation_sequence($lead_id) {
		$lead_id = (int) $lead_id;
		$payload = self::reactivation_payload($lead_id);
		if ('' === $payload['hallazgo']) {
			return new WP_Error('reactivation_hallazgo_required', 'Completa primero el hallazgo técnico antes de generar la secuencia.');
		}
		if (! self::reactivation_has_any_channel($payload)) {
			return new WP_Error('reactivation_channel_required', 'Llena al menos un canal antes de continuar.');
		}

		$sequence = array();
		$day = 0;
		$sector_allows_social = self::reactivation_sector_supports_social($payload['sector']);
		if ('' !== $payload['telefono']) {
			$sequence[] = array('canal' => 'telefono', 'dia' => $day);
			$day += 0;
		}
		if ('' !== $payload['email']) {
			$sequence[] = array('canal' => 'email', 'dia' => $day);
			$day += 7;
		}
		if ('' === $payload['email'] && '' !== $payload['formulario_url']) {
			$sequence[] = array('canal' => 'formulario', 'dia' => $day);
			$day += 7;
		}
		if ('' !== $payload['instagram'] && $sector_allows_social) {
			$sequence[] = array('canal' => 'instagram', 'dia' => $day);
		}
		if ('' !== $payload['facebook'] && $sector_allows_social && '' === $payload['instagram']) {
			$sequence[] = array('canal' => 'facebook', 'dia' => $day);
		}
		if (empty($sequence)) {
			return new WP_Error('reactivation_sequence_empty', 'No se pudo construir una secuencia válida con los datos encontrados.');
		}

		return $sequence;
	}

	private static function lead_has_logged_interaction($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return false;
		}
		$interaction_ids = get_posts(array(
			'post_type' => 'crm_interaction',
			'post_status' => 'publish',
			'numberposts' => 1,
			'fields' => 'ids',
			'orderby' => 'date',
			'order' => 'DESC',
			'meta_query' => array(
				array('key' => '_crm_lead_id', 'value' => $lead_id, 'compare' => '='),
			),
		));
		return ! empty($interaction_ids);
	}

	private static function lead_latest_interaction($lead_id) {
		$interactions = self::get_lead_interactions((int) $lead_id, 1);
		return ! empty($interactions[0]) ? $interactions[0] : null;
	}

	private static function lead_latest_response_result($lead_id) {
		$latest = self::lead_latest_interaction($lead_id);
		if (! ($latest instanceof WP_Post)) {
			return '';
		}
		return self::sanitize_interaction_result((string) get_post_meta((int) $latest->ID, '_crm_interaction_result', true));
	}

	private static function lead_responded_today($lead_id, $today = '') {
		$today = $today ?: current_time('Y-m-d');
		$latest = self::lead_latest_interaction($lead_id);
		if (! ($latest instanceof WP_Post)) {
			return false;
		}
		$result = (string) get_post_meta((int) $latest->ID, '_crm_interaction_result', true);
		if (! self::interaction_result_is_positive($result)) {
			return false;
		}
		$day = (string) get_post_meta((int) $latest->ID, '_crm_interaction_date', true);
		if (! $day) {
			$day = substr((string) $latest->post_date, 0, 10);
		}
		return $day === $today;
	}

	private static function lead_has_response_signal($lead_id) {
		$stage = self::normalize_stage_key((string) get_post_meta((int) $lead_id, '_crm_stage', true));
		if (in_array($stage, array('responded_interested', 'meeting_scheduled', 'meeting_done', 'proposal_sent', 'won'), true)) {
			return true;
		}
		return self::interaction_result_is_positive(self::lead_latest_response_result($lead_id));
	}

	private static function lead_days_since_created($lead_id, $today = '') {
		return self::days_between_dates(self::lead_created_day((int) $lead_id), $today ?: current_time('Y-m-d'));
	}

	private static function determine_operational_status($lead_id, $today = '') {
		static $cache = array();

		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		$cache_key = $lead_id . '|' . $today;
		if (isset($cache[$cache_key])) {
			return $cache[$cache_key];
		}
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id) || 'trash' === get_post_status($lead_id)) {
			$cache[$cache_key] = 'archive';
			return $cache[$cache_key];
		}

		$manual_archive = (bool) get_post_meta($lead_id, '_crm_manual_archive', true);
		if ($manual_archive) {
			$cache[$cache_key] = 'archive';
			return $cache[$cache_key];
		}
		if (self::lead_should_auto_close_on_day12($lead_id, $today)) {
			$cache[$cache_key] = 'archive';
			return $cache[$cache_key];
		}

		$lifecycle_state = self::lead_lifecycle_state($lead_id, $today);
		if ('closed' === $lifecycle_state) {
			$cache[$cache_key] = 'archive';
			return $cache[$cache_key];
		}
		$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		if (self::is_pre_contact_stage($stage)) {
			$cache[$cache_key] = 'pre_contact';
			return $cache[$cache_key];
		}
		if (self::lead_has_response_signal($lead_id)) {
			$cache[$cache_key] = 'interested';
			return $cache[$cache_key];
		}

		$has_interaction = self::lead_has_logged_interaction($lead_id);
		$next_followup = trim((string) get_post_meta($lead_id, '_crm_next_followup', true));
		$days_since_touch = self::business_days_between_dates(self::lead_last_touch_day($lead_id), $today);
		$stale_by_next_action = self::lead_should_archive_by_next_action_gap($lead_id, $today);

		if ('new' === $lifecycle_state) {
			$cache[$cache_key] = 'new';
			return $cache[$cache_key];
		}

		if (! $has_interaction) {
			if ($stale_by_next_action) {
				$cache[$cache_key] = 'archive';
				return $cache[$cache_key];
			}
			$cache[$cache_key] = 'new';
			return $cache[$cache_key];
		}

		if ($stale_by_next_action) {
			$cache[$cache_key] = 'archive';
			return $cache[$cache_key];
		}

		if ($days_since_touch <= 2 && 'pending' !== $lifecycle_state) {
			$cache[$cache_key] = 'contacted';
			return $cache[$cache_key];
		}

		$cache[$cache_key] = 'followup';
		return $cache[$cache_key];
	}

	private static function update_operational_status($lead_id, $today = '') {
		$status = self::determine_operational_status((int) $lead_id, $today ?: current_time('Y-m-d'));
		if ($lead_id) {
			update_post_meta((int) $lead_id, '_crm_operational_status', $status);
		}
		return $status;
	}

	private static function is_operationally_archived_lead($lead_id, $today = '') {
		return 'archive' === self::determine_operational_status((int) $lead_id, $today ?: current_time('Y-m-d'));
	}

	private static function lead_matches_operational_focus($lead_id, $focus, $today = '') {
		$lead_id = (int) $lead_id;
		$focus = self::sanitize_operational_focus($focus);
		$today = $today ?: current_time('Y-m-d');
		$status = self::determine_operational_status($lead_id, $today);
		$next_followup = (string) get_post_meta($lead_id, '_crm_next_followup', true);

		return match ($focus) {
			'pre_contact' => 'pre_contact' === $status,
			'new' => 'new' === $status,
			'contacted' => 'contacted' === $status,
			'followup' => 'followup' === $status,
			'interested' => 'interested' === $status,
			'archive' => 'archive' === $status,
			'all' => true,
			'today' => 'archive' !== $status && (
				('pre_contact' === $status && self::lead_created_day($lead_id) === $today)
				||
				('new' === $status && self::lead_created_day($lead_id) === $today)
				|| self::lead_responded_today($lead_id, $today)
				|| ($next_followup && $next_followup <= $today)
			),
			default => true,
		};
	}

	private static function filter_leads_by_operational_focus($leads, $focus, $today = '') {
		$focus = self::sanitize_operational_focus($focus);
		if (in_array($focus, array('today', 'pre_contact', 'new', 'contacted', 'followup', 'interested', 'archive', 'all'), true)) {
			$filtered = array();
			foreach ((array) $leads as $lead) {
				if ($lead instanceof WP_Post && self::lead_matches_operational_focus((int) $lead->ID, $focus, $today)) {
					$filtered[] = $lead;
				}
			}
			return $filtered;
		}
		return array_values((array) $leads);
	}

	private static function set_manual_archive_state($lead_id, $archived = true, $reason = '', $today = '') {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return;
		}
		$today = $today ?: current_time('Y-m-d');
		if ($archived) {
			update_post_meta($lead_id, '_crm_manual_archive', 1);
			update_post_meta($lead_id, '_crm_manual_archive_at', current_time('mysql'));
			update_post_meta($lead_id, '_crm_manual_archive_reason', sanitize_textarea_field((string) $reason));
			self::set_lead_next_followup_meta($lead_id, '');
			self::close_open_commercial_tasks_for_lead($lead_id, 'archive', $reason ?: 'Lead movido a archivo operativo.', 'manual_operational_archive');
		} else {
			delete_post_meta($lead_id, '_crm_manual_archive');
			delete_post_meta($lead_id, '_crm_manual_archive_at');
			delete_post_meta($lead_id, '_crm_manual_archive_reason');
			if (! get_post_meta($lead_id, '_crm_next_followup', true)) {
				self::set_lead_next_followup_meta($lead_id, $today);
			} else {
				self::sync_lead_next_action($lead_id);
			}
		}
		self::update_operational_status($lead_id, $today);
		self::maybe_google_sync_followup_for_current_user($lead_id);
	}

	private static function stage_requires_logged_interaction($stage) {
		$stage = self::normalize_stage_key((string) $stage);
		return in_array($stage, array('contacted', 'responded_interested', 'meeting_scheduled', 'meeting_done', 'proposal_sent', 'closed_no_response', 'won'), true);
	}

	private static function get_dashboard_new_leads_queue($today = '', $limit = 8) {
		$today = $today ?: current_time('Y-m-d');
		$limit = max(1, (int) $limit);
		$leads = self::get_active_leads(array(
			'numberposts' => -1,
			'orderby' => 'date',
			'order' => 'DESC',
			'date_query' => array(
				array(
					'after' => $today . ' 00:00:00',
					'before' => $today . ' 23:59:59',
					'inclusive' => true,
				),
			),
		));
		$leads = array_values(array_filter($leads, function ($lead) use ($today) {
			return 'new' === self::lead_lifecycle_state((int) $lead->ID, $today);
		}));
		return array_slice($leads, 0, $limit);
	}

	private static function get_dashboard_new_leads_count($today = '') {
		$today = $today ?: current_time('Y-m-d');
		$leads = self::get_active_leads(array(
			'numberposts' => -1,
			'fields' => 'ids',
			'orderby' => 'date',
			'order' => 'DESC',
			'date_query' => array(
				array(
					'after' => $today . ' 00:00:00',
					'before' => $today . ' 23:59:59',
					'inclusive' => true,
				),
			),
		));
		return count((array) $leads);
	}

	private static function get_dashboard_response_queue($today = '', $limit = 10) {
		$today = $today ?: current_time('Y-m-d');
		$limit = max(1, (int) $limit);
		$cutoff_day = date('Y-m-d', strtotime($today . ' -2 days'));
		$interactions = get_posts(array(
			'post_type' => 'crm_interaction',
			'post_status' => 'publish',
			'numberposts' => 140,
			'orderby' => 'date',
			'order' => 'DESC',
		));

		$items = array();
		$seen_leads = array();
		foreach ($interactions as $interaction) {
			$interaction_id = (int) $interaction->ID;
			$lead_id = (int) get_post_meta($interaction_id, '_crm_lead_id', true);
			if (! $lead_id || 'crm_lead' !== get_post_type($lead_id) || isset($seen_leads[$lead_id])) {
				continue;
			}
			$seen_leads[$lead_id] = true;
			$day = (string) get_post_meta($interaction_id, '_crm_interaction_date', true);
			if (! $day) {
				$day = substr((string) $interaction->post_date, 0, 10);
			}
			if (! $day || $day < $cutoff_day) {
				continue;
			}
			$kind = self::sanitize_interaction_kind((string) get_post_meta($interaction_id, '_crm_interaction_kind', true));
			$channel = self::sanitize_interaction_channel((string) get_post_meta($interaction_id, '_crm_interaction_channel', true));
			$action = self::normalize_interaction_action((string) get_post_meta($interaction_id, '_crm_interaction_action', true), $kind, $channel);
			$result = self::sanitize_interaction_result((string) get_post_meta($interaction_id, '_crm_interaction_result', true));
			if (! self::interaction_action_is_response_received($action) || ! self::interaction_result_is_positive($result)) {
				continue;
			}
			$items[$lead_id] = array(
				'lead' => get_post($lead_id),
				'interaction' => $interaction,
				'result' => $result,
				'action' => $action,
				'channel' => $channel,
				'day' => $day,
			);
			if (count($items) >= $limit) {
				break;
			}
		}

		return array_values($items);
	}

	private static function get_lead_sequence_task_map($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return array();
		}

		$prefix = 'lead_sequence_' . $lead_id . '_';
		$map = array();
		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => 40,
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => '_crm_task_lead_id', 'value' => $lead_id, 'compare' => '='),
			),
		));

		foreach ($tasks as $task_id) {
			$auto_key = (string) get_post_meta((int) $task_id, '_crm_auto_key', true);
			if ($auto_key && 0 === strpos($auto_key, $prefix)) {
				$map[substr($auto_key, strlen($prefix))] = (int) $task_id;
			}
			if ('auto1_' . $lead_id === $auto_key) {
				$map['day0_linkedin'] = (int) $task_id;
			}
		}

		return $map;
	}

	private static function sequence_task_description_for_lead($lead_id, $base_description) {
		$lead_id = (int) $lead_id;
		$base_description = trim((string) $base_description);
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return $base_description;
		}

		$technical_finding = trim((string) get_post_meta($lead_id, '_crm_technical_finding', true));
		if (! $technical_finding) {
			return $base_description;
		}

		return trim($base_description . "\n\nHallazgo técnico (Renata): " . $technical_finding);
	}

	private static function sync_open_sequence_task_descriptions_for_lead($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return;
		}

		foreach (self::get_lead_sequence_task_map($lead_id) as $slug => $task_id) {
			$task_id = (int) $task_id;
			if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
				continue;
			}
			if ('done' === self::normalize_task_status((string) get_post_meta($task_id, '_crm_task_status', true))) {
				continue;
			}
			$step = self::lead_followup_step_by_slug((string) $slug);
			if (empty($step['description'])) {
				continue;
			}
			wp_update_post(array(
				'ID' => $task_id,
				'post_content' => self::sequence_task_description_for_lead($lead_id, (string) $step['description']),
			));
		}
	}

	private static function ensure_lead_followup_sequence_task($lead_id, $today = '') {
		$lead_id = (int) $lead_id;
		$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
		if (! $lead) {
			return 0;
		}

		$today = $today ?: current_time('Y-m-d');
		$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		if (self::is_pre_contact_stage($stage) || in_array($stage, array('won', 'lost'), true)) {
			return 0;
		}
		if (! self::lead_has_logged_interaction($lead_id)) {
			return 0;
		}
		$operational_status = self::determine_operational_status($lead_id, $today);
		if (in_array($operational_status, array('interested', 'archive'), true)) {
			return 0;
		}
		if ((string) get_post_meta($lead_id, '_crm_last_sequence_auto_day', true) === $today) {
			return 0;
		}

		$anchor_day = self::lead_sequence_anchor_day($lead_id);
		if (! $anchor_day) {
			return 0;
		}

		$days_since_created = self::business_days_between_dates($anchor_day, $today);
		if ($days_since_created < 0) {
			return 0;
		}

		$steps = self::lead_followup_sequence_steps_for_policy(self::lead_sequence_policy($lead_id));
		if (empty($steps)) {
			return 0;
		}
		$existing_steps = self::get_lead_sequence_task_map($lead_id);
		$step_to_create = null;

		if (! empty($existing_steps)) {
			foreach ($steps as $step) {
				if ($days_since_created >= (int) $step['offset'] && empty($existing_steps[$step['slug']])) {
					$step_to_create = $step;
					break;
				}
			}
		} else {
			for ($i = count($steps) - 1; $i >= 0; $i--) {
				if ($days_since_created >= (int) $steps[$i]['offset']) {
					$step_to_create = $steps[$i];
					break;
				}
			}
		}

		if (! is_array($step_to_create)) {
			return 0;
		}

		$scheduled_day = self::lead_sequence_due_day($lead_id, (int) $step_to_create['offset']);
		$due = $scheduled_day <= $today ? $today : $scheduled_day;

		$task_id = self::create_auto_task_once(
			$lead_id,
			$step_to_create['title'] . wp_strip_all_tags(get_the_title($lead_id)),
			$step_to_create['type'],
			$step_to_create['priority'],
			$due,
			'lead_sequence_' . $lead_id . '_' . $step_to_create['slug'],
			array(
				'description' => self::sequence_task_description_for_lead($lead_id, (string) $step_to_create['description']),
			)
		);
		if ($task_id > 0) {
			update_post_meta($lead_id, '_crm_last_sequence_auto_day', $today);
		}
		return $task_id;
	}

	private static function reconcile_lead_business_day_schedule($lead_id, $today = '') {
		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id) || 'trash' === get_post_status($lead_id)) {
			return 0;
		}

		$open_tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => -1,
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => '_crm_task_lead_id', 'value' => $lead_id, 'compare' => '='),
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
		));

		$changes = 0;
		$earliest_commercial_due = '';
		foreach ($open_tasks as $task_id) {
			$task_id = (int) $task_id;
			if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
				continue;
			}

			$status = self::normalize_task_status((string) get_post_meta($task_id, '_crm_task_status', true));
			if (! self::is_task_open_status($status)) {
				continue;
			}

			$current_due = self::normalize_iso_day((string) get_post_meta($task_id, '_crm_task_due', true));
			if (! $current_due) {
				continue;
			}

			$new_due = $current_due;
			$sequence_slug = self::task_sequence_step_slug($task_id);
			if ($sequence_slug) {
				$step = self::lead_followup_step_by_slug($sequence_slug);
				if (isset($step['offset'])) {
					$new_due = self::lead_sequence_due_day($lead_id, (int) $step['offset']);
				}
			} else {
				$auto_key = (string) get_post_meta($task_id, '_crm_auto_key', true);
				if ($auto_key) {
					$new_due = self::normalize_business_due_day($current_due);
				}
			}

			if ($new_due && $new_due !== $current_due) {
				update_post_meta($task_id, '_crm_task_due', $new_due);
				$changes++;
			}

			$relation = self::sanitize_task_relation((string) get_post_meta($task_id, '_crm_task_relation', true));
			$category = self::sanitize_task_category((string) get_post_meta($task_id, '_crm_task_category', true));
			if ('lead_client' === $relation && 'commercial' === $category && ! self::task_should_be_hidden_from_open_views($task_id)) {
				$due_candidate = $new_due ?: $current_due;
				if ($due_candidate && ('' === $earliest_commercial_due || $due_candidate < $earliest_commercial_due)) {
					$earliest_commercial_due = $due_candidate;
				}
			}
		}

		$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		$current_next = self::normalize_iso_day((string) get_post_meta($lead_id, '_crm_next_followup', true));
		if (self::lead_stage_requires_next_action($stage)) {
			$target_next = $earliest_commercial_due ?: ($current_next ? self::normalize_business_due_day($current_next) : '');
			if ($target_next !== $current_next) {
				self::set_lead_next_followup_meta($lead_id, $target_next);
				$changes++;
			}
		} elseif ($current_next) {
			self::set_lead_next_followup_meta($lead_id, '');
			$changes++;
		}

		update_post_meta($lead_id, '_crm_business_day_policy_version', self::BUSINESS_DAY_POLICY_VERSION);
		return $changes;
	}

	private static function reconcile_business_day_schedules($today = '') {
		static $processed_days = array();

		$today = $today ?: current_time('Y-m-d');
		if (isset($processed_days[$today])) {
			return;
		}

		$leads = self::get_active_leads(array('numberposts' => -1, 'orderby' => 'date', 'order' => 'DESC'));
		foreach ($leads as $lead) {
			$lead_id = (int) $lead->ID;
			self::reconcile_missing_lost_reason_for_lead($lead_id, $today);
			self::reconcile_lead_business_day_schedule($lead_id, $today);
		}

		$processed_days[$today] = true;
	}

	private static function ensure_daily_routine_tasks($today = '') {
		$today = $today ?: current_time('Y-m-d');
		$lead_target = self::daily_new_leads_target();

		self::create_auto_task_once(
			0,
			'Ingresar ' . $lead_target . ' nuevos leads',
			'contact_lead',
			'high',
			$today,
			'daily_routine_new_leads_' . $today,
			array(
				'description' => 'Objetivo operativo del dia: ingresar ' . $lead_target . ' nuevos leads en el CRM.',
				'category' => 'commercial',
				'relation' => 'internal',
			)
		);

		self::create_auto_task_once(
			0,
			'Publicar en LinkedIn',
			'linkedin_post',
			'medium',
			$today,
			'daily_routine_linkedin_' . $today,
			array(
				'description' => 'Publicacion diaria de visibilidad y posicionamiento comercial en LinkedIn.',
				'category' => 'marketing',
				'relation' => 'internal',
			)
		);
	}

	private static function reconcile_stuck_guided_tasks_runtime($today = '') {
		static $processed = array();

		$today = $today ?: current_time('Y-m-d');
		if (isset($processed[$today])) {
			return;
		}

		$open_task_ids = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => 180,
			'fields' => 'ids',
			'meta_key' => '_crm_task_due',
			'orderby' => 'meta_value',
			'order' => 'ASC',
			'meta_query' => array(
				array('key' => '_crm_task_due', 'value' => $today, 'compare' => '<=', 'type' => 'DATE'),
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
		));

		foreach ($open_task_ids as $task_id) {
			$task_id = (int) $task_id;
			if (! self::task_requires_guided_completion($task_id)) {
				continue;
			}
			self::reconcile_open_guided_task_from_history($task_id);
		}

		$processed[$today] = true;
	}

	private static function refresh_operational_state_for_day($today = '') {
		$today = $today ?: current_time('Y-m-d');
		$leads = self::get_active_leads(array('numberposts' => -1, 'orderby' => 'date', 'order' => 'DESC'));
		foreach ($leads as $lead) {
			$lead_id = (int) $lead->ID;
			if (self::lead_should_auto_close_on_day12($lead_id, $today)) {
				self::auto_close_lead_without_response($lead_id, $today);
				continue;
			}
			$status = self::update_operational_status($lead_id, $today);
			if ('archive' === $status) {
				self::close_open_commercial_tasks_for_lead($lead_id, 'archive', 'Lead fuera del flujo diario por antiguedad o falta de respuesta.', 'operational_archive');
				continue;
			}
			if ('interested' === $status) {
				self::close_sequence_tasks_for_lead($lead_id, 'El lead respondio. La secuencia automatica se cerro para evitar duplicados.', $today);
			}
		}
	}

	private static function ensure_daily_operational_tasks($today = '') {
		static $processed_days = array();

		$today = $today ?: current_time('Y-m-d');
		if (isset($processed_days[$today])) {
			return;
		}

		self::reconcile_stuck_guided_tasks_runtime($today);
		self::reconcile_business_day_schedules($today);
		self::refresh_operational_state_for_day($today);
		self::ensure_daily_routine_tasks($today);

		$leads = self::get_active_leads(array('numberposts' => -1, 'orderby' => 'date', 'order' => 'DESC'));
		foreach ($leads as $lead) {
			$lead_id = (int) $lead->ID;
			if (self::is_operationally_archived_lead($lead_id, $today)) {
				continue;
			}
			self::ensure_lead_followup_sequence_task($lead_id, $today);
		}

		$processed_days[$today] = true;
	}

	private static function create_auto_task_once($lead_id, $title, $type, $priority, $due, $auto_key, $args = array()) {
		$lead_id = (int) $lead_id;
		$args = wp_parse_args($args, array(
			'description' => '',
			'assignee' => 'dani',
			'relation' => $lead_id ? 'lead_client' : 'internal',
			'category' => self::task_category_for_type($type),
			'pipeline_stage' => $lead_id ? (string) get_post_meta($lead_id, '_crm_stage', true) : '',
			'recurrence' => 'none',
			'allow_archived_lead' => false,
			'meta' => array(),
		));
		if ($lead_id && self::is_operationally_archived_lead($lead_id) && empty($args['allow_archived_lead'])) {
			return 0;
		}
		$due = self::normalize_business_due_day($due);
		if (! $due) {
			$due = self::normalize_business_due_day(current_time('Y-m-d'));
		}
		$exists = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => 1,
			'meta_query' => array(
				array('key' => '_crm_auto_key', 'value' => $auto_key, 'compare' => '='),
			),
		));
		if (! empty($exists)) {
			if ($lead_id) {
				self::sync_lead_next_action($lead_id);
			}
			return (int) $exists[0]->ID;
		}
		$meta_input = array(
			'_crm_task_due' => $due,
			'_crm_task_status' => 'pending',
			'_crm_task_lead_id' => $lead_id,
			'_crm_task_type' => $type,
			'_crm_task_priority' => $priority,
			'_crm_task_category' => (string) $args['category'],
			'_crm_task_relation' => (string) $args['relation'],
			'_crm_task_assignee' => (string) $args['assignee'],
			'_crm_task_pipeline_stage' => (string) $args['pipeline_stage'],
			'_crm_task_recurrence' => (string) $args['recurrence'],
			'_crm_auto_key' => $auto_key,
		);
		if (isset($args['meta']) && is_array($args['meta'])) {
			$meta_input = array_merge($meta_input, $args['meta']);
		}
		$task_id = wp_insert_post(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'post_title' => $title,
			'post_content' => (string) $args['description'],
			'meta_input' => $meta_input,
		));
		if (is_wp_error($task_id) || ! $task_id) {
			return 0;
		}
		if ($lead_id) {
			self::sync_lead_next_action($lead_id);
		}
		return (int) $task_id;
	}

	private static function precontact_review_task_auto_key($lead_id) {
		return 'lead_precontact_review_' . (int) $lead_id;
	}

	private static function ensure_precontact_review_task($lead_id, $today = '') {
		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return 0;
		}
		if (! self::is_pre_contact_stage((string) get_post_meta($lead_id, '_crm_stage', true))) {
			return 0;
		}

		$lead_title = wp_strip_all_tags(get_the_title($lead_id));
		$company = trim((string) get_post_meta($lead_id, '_crm_company', true));
		$website = trim((string) get_post_meta($lead_id, '_crm_website_url', true));
		$description = "Revisar el sitio y dejar el hallazgo técnico listo antes del primer contacto comercial.\n";
		if ($website) {
			$description .= 'Sitio: ' . $website . "\n";
		}
		$description .= "Objetivo: completar la revisión técnica y dejar el lead listo para que Danitza lo active.";
		$auto_key = self::precontact_review_task_auto_key($lead_id);
		$existing = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => 1,
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => '_crm_auto_key', 'value' => $auto_key, 'compare' => '='),
			),
		));
		if (! empty($existing[0])) {
			$task_id = (int) $existing[0];
			update_post_meta($task_id, '_crm_task_due', self::normalize_business_due_day($today) ?: $today);
			update_post_meta($task_id, '_crm_task_status', 'pending');
			update_post_meta($task_id, '_crm_task_assignee', 'renata');
			update_post_meta($task_id, '_crm_task_category', 'operational');
			update_post_meta($task_id, '_crm_task_pipeline_stage', 'pre_contact');
			update_post_meta($task_id, '_crm_task_precontact_review', 1);
			delete_post_meta($task_id, '_crm_task_completed_at');
			delete_post_meta($task_id, '_crm_task_completion_interaction_id');
			delete_post_meta($task_id, '_crm_task_completion_action');
			delete_post_meta($task_id, '_crm_task_completion_result');
			delete_post_meta($task_id, '_crm_task_completion_note');
			delete_post_meta($task_id, '_crm_task_completion_next_followup');
			delete_post_meta($task_id, '_crm_task_completion_stage');
			delete_post_meta($task_id, '_crm_task_resolved_by');
			wp_update_post(array(
				'ID' => $task_id,
				'post_title' => 'Revisión técnica previa — ' . $lead_title . ($company ? ' · ' . $company : ''),
				'post_content' => $description,
			));
			self::sync_lead_next_action($lead_id);
			return $task_id;
		}

		return self::create_auto_task_once(
			$lead_id,
			'Revisión técnica previa — ' . $lead_title . ($company ? ' · ' . $company : ''),
			'hosting_review',
			'high',
			$today,
			$auto_key,
			array(
				'description' => $description,
				'assignee' => 'renata',
				'category' => 'operational',
				'relation' => 'lead_client',
				'pipeline_stage' => 'pre_contact',
				'meta' => array(
					'_crm_task_precontact_review' => 1,
				),
			)
		);
	}

	private static function close_precontact_review_tasks_for_lead($lead_id, $reason = '', $today = '') {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return 0;
		}

		$today = $today ?: current_time('Y-m-d');
		$reason = trim((string) $reason) ?: 'El lead salió de Pre-contacto y la revisión técnica quedó cerrada.';
		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => -1,
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => '_crm_task_lead_id', 'value' => $lead_id, 'compare' => '='),
				array('key' => '_crm_task_precontact_review', 'value' => 1, 'compare' => '='),
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
		));

		$closed = 0;
		foreach ($tasks as $task_id) {
			$task_id = (int) $task_id;
			update_post_meta($task_id, '_crm_task_status', 'done');
			update_post_meta($task_id, '_crm_task_completed_at', current_time('mysql'));
			update_post_meta($task_id, '_crm_task_completion_interaction_id', 0);
			update_post_meta($task_id, '_crm_task_completion_action', 'other');
			update_post_meta($task_id, '_crm_task_completion_result', 'other');
			update_post_meta($task_id, '_crm_task_completion_note', sanitize_textarea_field($reason));
			update_post_meta($task_id, '_crm_task_completion_next_followup', '');
			update_post_meta($task_id, '_crm_task_completion_stage', sanitize_key((string) get_post_meta($lead_id, '_crm_stage', true)));
			update_post_meta($task_id, '_crm_task_resolved_by', get_current_user_id());
			self::log_activity('task_completed', $task_id, array(
				'task_type' => (string) get_post_meta($task_id, '_crm_task_type', true),
				'result' => 'other',
				'stage' => sanitize_key((string) get_post_meta($lead_id, '_crm_stage', true)),
				'lead_id' => $lead_id,
				'context' => 'precontact_review_closed',
				'closed_day' => $today,
			));
			self::sync_google_task_status_prefix($task_id, 'done');
			$closed++;
		}

		if ($closed) {
			self::sync_lead_next_action($lead_id);
		}

		return $closed;
	}

	private static function reactivation_task_label($channel) {
		$channel = sanitize_key((string) $channel);
		return self::reactivation_channel_labels()[$channel] ?? ucfirst(str_replace('_', ' ', $channel));
	}

	private static function create_reactivation_task($lead_id, $channel, $day = 0, $today = '', $args = array()) {
		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		$channel = sanitize_key((string) $channel);
		if (! $lead_id || ! isset(self::reactivation_channel_labels()[$channel])) {
			return 0;
		}

		$args = wp_parse_args($args, array(
			'auto_key' => '',
			'due' => '',
			'assignee' => 'dani',
			'priority' => 'high',
			'state' => 'pendiente',
			'title_prefix' => '↻ Reactivación',
			'description' => '',
		));

		$lead_title = wp_strip_all_tags(get_the_title($lead_id));
		$company = trim((string) get_post_meta($lead_id, '_crm_company', true));
		$title_tail = $lead_title . ($company ? ' · ' . $company : '');
		$due = ! empty($args['due']) ? self::normalize_iso_day((string) $args['due']) : self::shift_chile_business_days($today, (int) $day);
		$description = trim((string) $args['description']);
		if ('' === $description) {
			$description = 'Canal de reactivación: ' . self::reactivation_task_label($channel) . "\n" .
				'Lead: ' . $lead_title . ($company ? ' · ' . $company : '');
		}

		$auto_key = $args['auto_key'] ? sanitize_key((string) $args['auto_key']) : self::reactivation_task_auto_key($lead_id, $channel, (int) $day);

		return self::create_auto_task_once(
			$lead_id,
			trim((string) $args['title_prefix']) . ' ' . self::reactivation_task_label($channel) . ' — ' . $title_tail,
			'followup',
			self::sanitize_task_priority((string) $args['priority']),
			$due,
			$auto_key,
			array(
				'description' => $description,
				'assignee' => self::sanitize_task_assignee((string) $args['assignee']),
				'category' => 'commercial',
				'relation' => 'lead_client',
				'pipeline_stage' => (string) get_post_meta($lead_id, '_crm_stage', true),
				'allow_archived_lead' => true,
				'meta' => array(
					'_crm_task_reactivation' => 1,
					'twob_task_tipo' => 'reactivacion',
					'twob_task_canal' => $channel,
					'twob_task_dia' => (int) $day,
					'twob_task_estado' => sanitize_key((string) $args['state']) ?: 'pendiente',
					'twob_task_lead_id' => $lead_id,
					'twob_react_result_state' => '',
				),
			)
		);
	}

	private static function generate_reactivation_sequence_for_lead($lead_id, $today = '') {
		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
		if (! $lead || ! self::reactivation_lead_is_eligible($lead_id)) {
			return new WP_Error('reactivation_invalid_lead', 'Este lead no califica para la secuencia de reactivación.');
		}
		if (! self::current_user_can_edit_crm_post($lead_id)) {
			return new WP_Error('reactivation_forbidden', 'No tienes permisos para preparar este lead.');
		}
		if (! current_user_can('edit_crm_tasks')) {
			return new WP_Error('reactivation_task_forbidden', 'No tienes permisos para crear tareas de reactivación.');
		}
		if (self::reactivation_is_paused($lead_id, $today)) {
			return new WP_Error('reactivation_paused', 'Este lead está en pausa temporal y no aparece en la cola de reactivación por ahora.');
		}
		if (! empty(self::reactivation_tasks_for_lead($lead_id, true))) {
			return new WP_Error('reactivation_exists', 'Este lead ya tiene una secuencia de reactivación abierta.');
		}

		$sequence = self::build_reactivation_sequence($lead_id);
		if (is_wp_error($sequence)) {
			return $sequence;
		}

		$created = array();
		foreach ($sequence as $index => $step) {
			$channel = sanitize_key((string) ($step['canal'] ?? ''));
			$day = (int) ($step['dia'] ?? 0);
			$task_id = self::create_reactivation_task($lead_id, $channel, $day, $today, array(
				'auto_key' => self::reactivation_task_auto_key($lead_id, $channel, $day, 'seq' . ($index + 1)),
				'priority' => 0 === $index ? 'high' : 'medium',
				'description' => 'Secuencia de reactivación generada para Dani. Canal: ' . self::reactivation_task_label($channel) . '.',
			));
			if ($task_id > 0) {
				$created[] = $task_id;
			}
		}

		update_post_meta($lead_id, 'twob_react_secuencia_generada', 1);
		update_post_meta($lead_id, 'twob_react_fecha_inicio', $today);
		update_post_meta($lead_id, 'twob_react_secuencia_canales', wp_json_encode($sequence));
		delete_post_meta($lead_id, 'twob_react_agotada');
		delete_post_meta($lead_id, 'twob_react_pausa_hasta');
		delete_post_meta($lead_id, 'twob_react_respondio');
		self::flush_metrics_cache();

		return array(
			'sequence' => $sequence,
			'tasks' => $created,
		);
	}

	private static function reactivation_field_schema() {
		return array(
			'twob_react_telefono' => array('type' => 'text'),
			'twob_react_email' => array('type' => 'email'),
			'twob_react_formulario_url' => array('type' => 'url'),
			'twob_react_instagram' => array('type' => 'url'),
			'twob_react_facebook' => array('type' => 'url'),
			'twob_sector' => array('type' => 'sector'),
		);
	}

	private static function save_reactivation_field($lead_id, $field, $value) {
		$lead_id = (int) $lead_id;
		$field = sanitize_key((string) $field);
		$schema = self::reactivation_field_schema();
		$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
		if (! $lead || ! self::reactivation_lead_is_eligible($lead_id)) {
			return new WP_Error('reactivation_invalid_lead', 'Este lead no está disponible para reactivación.');
		}
		if (! self::current_user_can_edit_crm_post($lead_id)) {
			return new WP_Error('reactivation_forbidden', 'No tienes permisos para editar este lead.');
		}
		if (! isset($schema[$field])) {
			return new WP_Error('reactivation_invalid_field', 'Campo de investigación no permitido.');
		}

		$type = (string) ($schema[$field]['type'] ?? 'text');
		$clean = '';
		if ('email' === $type) {
			$clean = sanitize_email((string) $value);
		} elseif ('url' === $type) {
			$clean = esc_url_raw((string) $value);
		} elseif ('sector' === $type) {
			$clean = self::sanitize_reactivation_sector((string) $value);
		} else {
			$clean = sanitize_text_field((string) $value);
		}

		if ('' === trim((string) $clean)) {
			delete_post_meta($lead_id, $field);
		} else {
			update_post_meta($lead_id, $field, $clean);
		}

		return array(
			'lead_id' => $lead_id,
			'field' => $field,
			'value' => $clean,
			'payload' => self::reactivation_payload($lead_id),
		);
	}

	private static function update_reactivation_task_status($task_id, $status = 'done', $result_state = 'cerrada', $note = '', $extra_meta = array()) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return;
		}

		$status = self::normalize_task_status((string) $status);
		$result_state = sanitize_key((string) $result_state) ?: 'cerrada';
		update_post_meta($task_id, '_crm_task_status', $status);
		update_post_meta($task_id, '_crm_task_completed_at', current_time('mysql'));
		update_post_meta($task_id, 'twob_task_estado', $result_state);
		update_post_meta($task_id, 'twob_react_result_state', $result_state);
		if ('' !== trim((string) $note)) {
			update_post_meta($task_id, '_crm_task_completion_note', sanitize_textarea_field($note));
		}
		if (! empty($extra_meta) && is_array($extra_meta)) {
			foreach ($extra_meta as $meta_key => $meta_value) {
				if (! is_string($meta_key) || '' === $meta_key) {
					continue;
				}
				update_post_meta($task_id, $meta_key, $meta_value);
			}
		}
		self::sync_google_task_status_prefix($task_id, $status);
	}

	private static function create_reactivation_support_task($lead_id, $title, $type, $priority, $due, $auto_key, $args = array()) {
		$lead_id = (int) $lead_id;
		$args = wp_parse_args($args, array(
			'description' => '',
			'assignee' => 'dani',
			'channel' => '',
			'day' => 0,
			'state' => 'pendiente',
			'meta' => array(),
			'pipeline_stage' => (string) get_post_meta($lead_id, '_crm_stage', true),
		));

		$meta = array(
			'_crm_task_reactivation' => 1,
			'twob_task_tipo' => 'reactivacion',
			'twob_task_canal' => sanitize_key((string) $args['channel']),
			'twob_task_dia' => (int) $args['day'],
			'twob_task_estado' => sanitize_key((string) $args['state']) ?: 'pendiente',
			'twob_task_lead_id' => $lead_id,
			'twob_react_result_state' => '',
		);
		if (! empty($args['meta']) && is_array($args['meta'])) {
			$meta = array_merge($meta, $args['meta']);
		}

		return self::create_auto_task_once(
			$lead_id,
			$title,
			$type,
			$priority,
			$due,
			$auto_key,
			array(
				'description' => (string) $args['description'],
				'assignee' => self::sanitize_task_assignee((string) $args['assignee']),
				'category' => 'commercial',
				'relation' => 'lead_client',
				'pipeline_stage' => (string) $args['pipeline_stage'],
				'allow_archived_lead' => true,
				'meta' => $meta,
			)
		);
	}

	private static function reactivation_note_prefix($lead_id) {
		$lead_id = (int) $lead_id;
		$company = trim((string) get_post_meta($lead_id, '_crm_company', true));
		$lead_name = trim((string) get_the_title($lead_id));
		return trim($lead_name . ($company ? ' · ' . $company : ''));
	}

	private static function create_reactivation_email_task($lead_id, $due, $today = '', $suffix = '') {
		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		$due = self::normalize_business_due_day($due ?: $today);
		$title = '↻ Reactivación Email directo — ' . self::reactivation_note_prefix($lead_id);
		return self::create_reactivation_support_task(
			$lead_id,
			$title,
			'followup',
			'high',
			$due,
			self::reactivation_task_auto_key($lead_id, 'email', 0, $suffix ?: 'dynamic'),
			array(
				'assignee' => 'dani',
				'channel' => 'email',
				'day' => 0,
				'description' => 'Email directo al decisor desde la secuencia de reactivación.',
			)
		);
	}

	private static function create_reactivation_phone_task($lead_id, $due, $today = '', $suffix = '') {
		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		$due = self::normalize_business_due_day($due ?: $today);
		$title = '↻ Reactivación Llamada — ' . self::reactivation_note_prefix($lead_id);
		return self::create_reactivation_support_task(
			$lead_id,
			$title,
			'followup',
			'high',
			$due,
			self::reactivation_task_auto_key($lead_id, 'telefono', 0, $suffix ?: 'dynamic'),
			array(
				'assignee' => 'dani',
				'channel' => 'telefono',
				'day' => 0,
				'description' => 'Nueva llamada desde la secuencia de reactivación.',
			)
		);
	}

	private static function create_reactivation_meeting_workflow($lead_id, $meeting_day, $channel = 'email', $today = '') {
		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		$meeting_day = self::normalize_business_due_day($meeting_day);
		if (! $lead_id || ! $meeting_day) {
			return array();
		}

		$lead_label = self::reactivation_note_prefix($lead_id);
		$contact_name = self::lead_contact_name($lead_id);
		$url = trim((string) get_post_meta($lead_id, '_crm_website_url', true));
		$confirm_message = "Hola {$contact_name}, confirmando nuestra reunión\nel {$meeting_day}.\n\nDuración: 20 minutos.\nLe muestro en pantalla lo que encontramos\nen {$url} y cómo se ve el diagnóstico completo.\n\n¿Le parece bien o prefiere otro horario?";
		$proposal_followup_message = "Hola {$contact_name}, ¿pudo revisar la propuesta?\n\nSi tiene alguna duda antes de decidir,\ncon gusto la resolvemos.";

		$created = array();
		$evidence_due = self::shift_chile_business_days($meeting_day, -1);
		$created['renata_evidence'] = self::create_reactivation_support_task(
			$lead_id,
			'Preparar evidencia — Reunión con ' . ($contact_name ?: $lead_label),
			'meeting',
			'high',
			$evidence_due,
			'reactivation_prepare_evidence_' . $lead_id . '_' . $meeting_day,
			array(
				'assignee' => 'renata',
				'channel' => sanitize_key((string) $channel),
				'description' => "Preparar para la reunión con {$contact_name} de {$lead_label}:\n(1) Captura del hallazgo con impacto en negocio explicado en lenguaje de gerente, no técnico.\n(2) Demo del portal anonimizado listo para compartir pantalla.\n(3) Las 3 prioridades máximas del diagnóstico.",
				'pipeline_stage' => 'meeting_scheduled',
			)
		);
		$created['confirm_meeting'] = self::create_reactivation_support_task(
			$lead_id,
			'Confirmar reunión y enviar agenda — ' . $lead_label,
			'meeting',
			'high',
			$today,
			'reactivation_confirm_meeting_' . $lead_id . '_' . $meeting_day,
			array(
				'assignee' => 'dani',
				'channel' => sanitize_key((string) $channel),
				'description' => $confirm_message,
				'pipeline_stage' => 'meeting_scheduled',
			)
		);
		$created['send_proposal'] = self::create_reactivation_support_task(
			$lead_id,
			'Enviar propuesta post-reunión — ' . $lead_label,
			'proposal',
			'high',
			$meeting_day,
			'reactivation_send_proposal_' . $lead_id . '_' . $meeting_day,
			array(
				'assignee' => 'dani',
				'channel' => sanitize_key((string) $channel),
				'description' => 'Enviar la propuesta el mismo día de la reunión. No al día siguiente.',
				'pipeline_stage' => 'meeting_scheduled',
			)
		);
		$created['proposal_followup'] = self::create_reactivation_support_task(
			$lead_id,
			'Seguimiento propuesta — ' . $lead_label,
			'proposal',
			'medium',
			self::add_chile_business_days($meeting_day, 2),
			'reactivation_followup_proposal_' . $lead_id . '_' . $meeting_day,
			array(
				'assignee' => 'dani',
				'channel' => sanitize_key((string) $channel),
				'description' => $proposal_followup_message,
				'pipeline_stage' => 'proposal_sent',
			)
		);

		return $created;
	}

	private static function resolve_reactivation_task($task_id, $outcome, $extra = array(), $today = '') {
		$task_id = (int) $task_id;
		$today = $today ?: current_time('Y-m-d');
		$task = self::get_valid_crm_post($task_id, 'crm_task');
		if (! $task || ! self::is_reactivation_task($task_id)) {
			return new WP_Error('reactivation_invalid_task', 'Tarea de reactivación inválida.');
		}
		if (! self::current_user_can_edit_crm_post($task_id)) {
			return new WP_Error('reactivation_task_forbidden', 'No tienes permisos para resolver esta tarea.');
		}
		if (! current_user_can('edit_crm_tasks')) {
			return new WP_Error('reactivation_task_create_forbidden', 'No tienes permisos para crear el siguiente paso de la reactivación.');
		}

		$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
		$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
		if (! $lead) {
			return new WP_Error('reactivation_invalid_lead', 'El lead de esta reactivación ya no existe.');
		}

		$channel = self::reactivation_task_channel($task_id);
		$auto_key = (string) get_post_meta($task_id, '_crm_auto_key', true);
		$is_schedule_task = 0 === strpos($auto_key, 'reactivation_schedule_meeting_');
		$outcome = sanitize_key((string) $outcome);
		$extra = is_array($extra) ? $extra : array();
		$note = isset($extra['note']) ? sanitize_textarea_field((string) $extra['note']) : '';
		$response_channel = $channel ?: 'email';
		$result = array(
			'lead_id' => $lead_id,
			'task_id' => $task_id,
			'refresh' => true,
			'message' => 'Tarea de reactivación actualizada.',
		);

		if ($is_schedule_task) {
			if ('meeting_booked' === $outcome) {
				$meeting_day = self::sanitize_date_input((string) ($extra['meeting_date'] ?? ''), false, 'Fecha de la reunión');
				if (is_wp_error($meeting_day)) {
					return $meeting_day;
				}
				self::close_reactivation_tasks_for_lead($lead_id, 'El lead agendó reunión desde la secuencia de reactivación.', 'reunion_agendada');
				update_post_meta($lead_id, 'twob_react_respondio', 1);
				update_post_meta($lead_id, 'twob_react_fecha_reunion', $meeting_day);
				$stage_result = self::set_lead_stage($lead_id, 'meeting_scheduled', 'reactivation_auto_meeting_booked');
				if (is_wp_error($stage_result)) {
					return $stage_result;
				}
				self::set_lead_next_followup_meta($lead_id, $meeting_day, 'Confirmar reunión');
				$created = self::create_reactivation_meeting_workflow($lead_id, $meeting_day, $response_channel, $today);
				$result['created_tasks'] = array_values(array_filter(array_map('intval', $created)));
				$result['message'] = 'Reunión agendada. Se crearon las tareas de preparación, confirmación y propuesta.';
				return $result;
			}
			if ('rejected' === $outcome) {
				$reason = sanitize_textarea_field((string) ($extra['reason'] ?? ''));
				self::close_reactivation_tasks_for_lead($lead_id, 'Respuesta negativa durante la reactivación.', 'rechazado');
				if ($reason) {
					update_post_meta($lead_id, 'twob_react_motivo_rechazo', $reason);
				}
				$final_reason = $reason ?: 'Reactivación rechazada sin detalle adicional.';
				$stage_result = self::set_lead_stage($lead_id, 'lost', 'reactivation_auto_rejected', $final_reason);
				if (is_wp_error($stage_result)) {
					return $stage_result;
				}
				self::close_missing_lost_reason_tasks($lead_id);
				$result['message'] = 'La reactivación se cerró con respuesta negativa.';
				return $result;
			}
		}

		if ('telefono' === $channel) {
			if ('got_email' === $outcome) {
				$email = sanitize_email((string) ($extra['email'] ?? ''));
				if (! $email) {
					return new WP_Error('reactivation_email_required', 'Debes ingresar el email del decisor.');
				}
				update_post_meta($lead_id, 'twob_react_email', $email);
				self::update_reactivation_task_status($task_id, 'done', 'consegui_email', $note ?: 'Se consiguió el email del decisor por llamada.');
				$email_task_id = self::create_reactivation_email_task($lead_id, $today, $today, 'from_call');
				$result['next_task_id'] = (int) $email_task_id;
				$result['message'] = 'Llamada cerrada y tarea de email creada para hoy.';
				return $result;
			}
			if ('got_phone' === $outcome) {
				$phone = sanitize_text_field((string) ($extra['phone'] ?? ''));
				if (! $phone) {
					return new WP_Error('reactivation_phone_required', 'Debes ingresar el nuevo teléfono.');
				}
				update_post_meta($lead_id, 'twob_react_telefono', $phone);
				self::update_reactivation_task_status($task_id, 'done', 'consegui_telefono', $note ?: 'Se consiguió otro teléfono para seguir la reactivación.');
				$phone_task_id = self::create_reactivation_phone_task($lead_id, $today, $today, 'retry');
				$result['next_task_id'] = (int) $phone_task_id;
				$result['message'] = 'Llamada cerrada y se creó una nueva llamada con el teléfono actualizado.';
				return $result;
			}
			if ('no_response' === $outcome) {
				self::update_reactivation_task_status($task_id, 'done', 'cerrada', $note ?: 'No contestaron o no entregaron el contacto.');
				$next_due = self::add_chile_business_days($today, 3);
				foreach (self::reactivation_tasks_for_lead($lead_id, true) as $open_task) {
					$open_task_id = (int) $open_task->ID;
					if ($open_task_id === $task_id) {
						continue;
					}
					$open_channel = self::reactivation_task_channel($open_task_id);
					if (! in_array($open_channel, array('formulario', 'instagram', 'facebook'), true)) {
						continue;
					}
					$current_due = self::normalize_iso_day((string) get_post_meta($open_task_id, '_crm_task_due', true));
					if ($current_due && $current_due <= $today) {
						update_post_meta($open_task_id, '_crm_task_due', $next_due);
					}
				}
				$result['message'] = 'Llamada cerrada. El siguiente canal quedó movido a D+3 hábil.';
				return $result;
			}
		}

		if ('email' === $channel) {
			if ('sent_no_response' === $outcome) {
				self::update_reactivation_task_status($task_id, 'done', 'enviado_sin_respuesta', $note ?: 'Email enviado sin respuesta por ahora.');
				$result['message'] = 'Email marcado como enviado. Si no responden, quedará disponible el siguiente canal.';
				return $result;
			}
				if ('interested' === $outcome) {
					self::close_reactivation_tasks_for_lead($lead_id, 'El lead respondió con interés durante la reactivación.', 'respondio_interes');
					update_post_meta($lead_id, 'twob_react_respondio', 1);
					$stage_result = self::set_lead_stage($lead_id, 'responded_interested', 'reactivation_auto_interested');
					if (is_wp_error($stage_result)) {
						return $stage_result;
					}
					$meeting_due = self::add_chile_business_days($today, 1);
					$task = self::create_reactivation_support_task(
						$lead_id,
						'Agendar reunión — ' . self::reactivation_note_prefix($lead_id),
						'meeting',
					'high',
					$meeting_due,
						'reactivation_schedule_meeting_' . $lead_id . '_' . $today,
						array(
							'assignee' => 'dani',
							'channel' => 'email',
							'description' => self::reactivation_schedule_message($lead_id),
							'pipeline_stage' => 'responded_interested',
						)
					);
				self::set_lead_next_followup_meta($lead_id, $meeting_due, 'Agendar reunión');
				$result['next_task_id'] = (int) $task;
				$result['message'] = 'El lead respondió con interés. Se cerró la secuencia y se creó la tarea para agendar reunión.';
				return $result;
			}
			if ('meeting_booked' === $outcome) {
				$meeting_day = self::sanitize_date_input((string) ($extra['meeting_date'] ?? ''), false, 'Fecha de la reunión');
				if (is_wp_error($meeting_day)) {
					return $meeting_day;
				}
				self::close_reactivation_tasks_for_lead($lead_id, 'El lead agendó reunión desde la secuencia de reactivación.', 'reunion_agendada');
				update_post_meta($lead_id, 'twob_react_respondio', 1);
				update_post_meta($lead_id, 'twob_react_fecha_reunion', $meeting_day);
				$stage_result = self::set_lead_stage($lead_id, 'meeting_scheduled', 'reactivation_auto_meeting_booked');
				if (is_wp_error($stage_result)) {
					return $stage_result;
				}
				self::set_lead_next_followup_meta($lead_id, $meeting_day, 'Confirmar reunión');
				$created = self::create_reactivation_meeting_workflow($lead_id, $meeting_day, 'email', $today);
				$result['created_tasks'] = array_values(array_filter(array_map('intval', $created)));
				$result['message'] = 'Reunión agendada. Se crearon las tareas de preparación, confirmación y propuesta.';
				return $result;
			}
			if ('rejected' === $outcome) {
				$reason = sanitize_textarea_field((string) ($extra['reason'] ?? ''));
				self::close_reactivation_tasks_for_lead($lead_id, 'Respuesta negativa durante la reactivación.', 'rechazado');
				if ($reason) {
					update_post_meta($lead_id, 'twob_react_motivo_rechazo', $reason);
				}
				$final_reason = $reason ?: 'Reactivación rechazada sin detalle adicional.';
				$stage_result = self::set_lead_stage($lead_id, 'lost', 'reactivation_auto_rejected', $final_reason);
				if (is_wp_error($stage_result)) {
					return $stage_result;
				}
				self::close_missing_lost_reason_tasks($lead_id);
				$result['message'] = 'La reactivación se cerró con respuesta negativa.';
				return $result;
			}
		}

		if (in_array($channel, array('formulario', 'instagram', 'facebook'), true)) {
			if ('got_contact' === $outcome) {
				$email = sanitize_email((string) ($extra['email'] ?? ''));
				$phone = sanitize_text_field((string) ($extra['phone'] ?? ''));
				if (! $email && ! $phone) {
					return new WP_Error('reactivation_contact_required', 'Debes ingresar al menos un email o teléfono del decisor.');
				}
				if ($email) {
					update_post_meta($lead_id, 'twob_react_email', $email);
				}
				if ($phone) {
					update_post_meta($lead_id, 'twob_react_telefono', $phone);
				}
				self::update_reactivation_task_status($task_id, 'done', 'consegui_contacto', $note ?: 'Respondieron con el contacto del decisor.');
				$next_due = self::add_chile_business_days($today, 1);
				if ($email) {
					$next_task_id = self::create_reactivation_email_task($lead_id, $next_due, $today, 'from_contact');
					$result['next_task_id'] = (int) $next_task_id;
					$result['message'] = 'Contacto obtenido. Se creó tarea de email para el siguiente día hábil.';
				} else {
					$next_task_id = self::create_reactivation_phone_task($lead_id, $next_due, $today, 'from_contact');
					$result['next_task_id'] = (int) $next_task_id;
					$result['message'] = 'Contacto obtenido. Se creó tarea de llamada para el siguiente día hábil.';
				}
				return $result;
			}
				if ('direct_reply' === $outcome) {
					self::close_reactivation_tasks_for_lead($lead_id, 'El decisor respondió directamente durante la reactivación.', 'respondio_interes');
					update_post_meta($lead_id, 'twob_react_respondio', 1);
					$stage_result = self::set_lead_stage($lead_id, 'responded_interested', 'reactivation_auto_direct_reply');
				if (is_wp_error($stage_result)) {
					return $stage_result;
				}
					$meeting_due = self::add_chile_business_days($today, 1);
					$task = self::create_reactivation_support_task(
						$lead_id,
						'Agendar reunión — ' . self::reactivation_note_prefix($lead_id),
						'meeting',
					'high',
					$meeting_due,
					'reactivation_schedule_meeting_' . $lead_id . '_' . $today,
						array(
							'assignee' => 'dani',
							'channel' => $channel,
							'description' => self::reactivation_schedule_message($lead_id),
							'pipeline_stage' => 'responded_interested',
						)
					);
				self::set_lead_next_followup_meta($lead_id, $meeting_due, 'Agendar reunión');
				$result['next_task_id'] = (int) $task;
				$result['message'] = 'El decisor respondió directamente. Se creó la tarea para agendar reunión.';
				return $result;
			}
			if ('no_response' === $outcome) {
				self::update_reactivation_task_status($task_id, 'done', 'cerrada', $note ?: 'No hubo respuesta por este canal.');
				$result['message'] = 'Canal cerrado sin respuesta.';
				return $result;
			}
		}

		return new WP_Error('reactivation_invalid_outcome', 'Resultado de reactivación no reconocido para este canal.');
	}

	private static function run_reactivation_timeout_automation($today = '') {
		$today = $today ?: current_time('Y-m-d');
		$eligible_leads = self::get_reactivation_leads_for_automation();
		foreach ($eligible_leads as $lead) {
			$lead_id = (int) $lead->ID;
			if (! self::reactivation_lead_is_eligible($lead_id)) {
				continue;
			}
			$payload = self::reactivation_payload($lead_id);
			if (empty($payload['sequence_generated']) || empty($payload['date_start']) || ! empty($payload['responded'])) {
				continue;
			}
			if (self::reactivation_is_paused($lead_id, $today)) {
				continue;
			}
			if (self::days_between_dates($payload['date_start'], $today) < 30) {
				continue;
			}
			$open_tasks = self::reactivation_tasks_for_lead($lead_id, true);
			if (! empty($open_tasks)) {
				continue;
			}
			$all_tasks = self::reactivation_tasks_for_lead($lead_id, false);
			if (empty($all_tasks)) {
				continue;
			}
			$all_results_are_exhausted = true;
			foreach ($all_tasks as $task) {
				$task_result = sanitize_key((string) get_post_meta((int) $task->ID, 'twob_react_result_state', true));
				$task_status = sanitize_key((string) get_post_meta((int) $task->ID, '_crm_task_status', true));
				if ('done' !== $task_status && 'completed' !== $task_status) {
					$all_results_are_exhausted = false;
					break;
				}
				if (! self::reactivation_task_result_is_exhausted($task_result)) {
					$all_results_are_exhausted = false;
					break;
				}
			}
			if (! $all_results_are_exhausted) {
				continue;
			}
			update_post_meta($lead_id, 'twob_react_agotada', 1);
			update_post_meta($lead_id, 'twob_react_pausa_hasta', date('Y-m-d', strtotime($today . ' +60 days')));
		}
	}

	private static function task_source_label($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return 'Manual';
		}
		if (self::is_reactivation_task($task_id)) {
			return 'Reactivación';
		}

		$recurrence = self::normalize_task_recurrence((string) get_post_meta($task_id, '_crm_task_recurrence', true));
		if ('none' !== $recurrence) {
			return 'Recurrente';
		}

		if ('google_calendar' === (string) get_post_meta($task_id, '_crm_google_origin', true)) {
			return 'Google Calendar';
		}

		$auto_key = (string) get_post_meta($task_id, '_crm_auto_key', true);
		if ($auto_key) {
			return 0 === strpos($auto_key, 'daily_routine_') ? 'Rutina diaria' : 'Automatica';
		}

		return 'Manual';
	}

	private static function task_source_hint($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return '';
		}
		if (self::is_reactivation_task($task_id)) {
			return 'Esta tarea pertenece a una secuencia de reactivación para leads cerrados. LinkedIn ya no participa aquí.';
		}

		$recurrence = self::normalize_task_recurrence((string) get_post_meta($task_id, '_crm_task_recurrence', true));
		if ('none' !== $recurrence) {
			return 'Al completarla, el sistema crea la siguiente segun la recurrencia elegida.';
		}

		if ('google_calendar' === (string) get_post_meta($task_id, '_crm_google_origin', true)) {
			return 'Esta tarea viene de Google Calendar.';
		}

		$auto_key = (string) get_post_meta($task_id, '_crm_auto_key', true);
		if (! $auto_key) {
			return '';
		}
		if (0 === strpos($auto_key, 'daily_routine_')) {
			return 'Esta rutina nace una vez por dia. Si la completas hoy, manana aparece la rutina del nuevo dia.';
		}
		if (0 === strpos($auto_key, 'auto5_') || 0 === strpos($auto_key, 'auto6_')) {
			return 'Esta tarea viene de cobranza. Si el pago sigue pendiente, revisa tambien el estado del cobro.';
		}
		if (0 === strpos($auto_key, 'lead_sequence_') || 0 === strpos($auto_key, 'auto3_') || 0 === strpos($auto_key, 'auto4_') || 0 === strpos($auto_key, 'auto8_') || 0 === strpos($auto_key, 'lead_now_')) {
			return 'Esta tarea viene del seguimiento comercial automatico y no deberia duplicarse dia tras dia para el mismo contexto.';
		}

		return 'Esta tarea fue creada automaticamente por una regla del CRM.';
	}

	private static function task_should_show_in_dashboard_actions($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return false;
		}
		if (self::task_should_be_hidden_from_open_views($task_id)) {
			return false;
		}

		$auto_key = (string) get_post_meta($task_id, '_crm_auto_key', true);
		if ($auto_key && 0 === strpos($auto_key, 'daily_routine_')) {
			return false;
		}

		return true;
	}

	private static function tasks_page_number($param) {
		$param = sanitize_key((string) $param);
		if (! $param || ! isset($_GET[$param])) {
			return 1;
		}
		return max(1, absint(wp_unslash($_GET[$param])));
	}

	private static function tasks_page_url($overrides = array(), $anchor = '') {
		$args = array('page' => 'twob-crm-visual-tasks');
		foreach ((array) $_GET as $key => $value) {
			$key = sanitize_key((string) $key);
			if (! $key || 'page' === $key || ! preg_match('/^[a-z0-9_]+_page$/', $key)) {
				continue;
			}
			$page = max(1, absint(wp_unslash($value)));
			if ($page > 1) {
				$args[$key] = $page;
			}
		}

		foreach ((array) $overrides as $key => $value) {
			$key = sanitize_key((string) $key);
			if (! $key || ! preg_match('/^[a-z0-9_]+_page$/', $key)) {
				continue;
			}
			$page = max(1, absint($value));
			if ($page > 1) {
				$args[$key] = $page;
			} else {
				unset($args[$key]);
			}
		}

		$url = add_query_arg($args, admin_url('admin.php'));
		if ($anchor) {
			$url .= '#' . ltrim((string) $anchor, '#');
		}
		return $url;
	}

	private static function paginate_task_items($items, $page, $per_page = 10) {
		$items = array_values((array) $items);
		$total = count($items);
		$per_page = max(1, (int) $per_page);
		$pages = max(1, (int) ceil($total / $per_page));
		$page = min(max(1, (int) $page), $pages);
		$offset = ($page - 1) * $per_page;

		return array(
			'items' => array_slice($items, $offset, $per_page),
			'page' => $page,
			'pages' => $pages,
			'total' => $total,
			'from' => $total ? ($offset + 1) : 0,
			'to' => $total ? min($offset + $per_page, $total) : 0,
			'per_page' => $per_page,
		);
	}

	private static function tasks_archive_page_param($month_key) {
		$month_key = preg_replace('/[^0-9\-]/', '', (string) $month_key);
		return 'lost_' . str_replace('-', '_', $month_key) . '_page';
	}

	private static function tasks_month_label($month_key) {
		$timestamp = strtotime((string) $month_key . '-01');
		if (! $timestamp) {
			return (string) $month_key;
		}
		return date_i18n('F Y', $timestamp);
	}

	private static function render_tasks_pager($param, $pagination, $anchor) {
		$pagination = (array) $pagination;
		$total = (int) ($pagination['total'] ?? 0);
		$page = (int) ($pagination['page'] ?? 1);
		$pages = (int) ($pagination['pages'] ?? 1);
		$from = (int) ($pagination['from'] ?? 0);
		$to = (int) ($pagination['to'] ?? 0);
		if (! $total) {
			return;
		}
		?>
		<div class="twob-section-meta">
			<span class="twob-section-count"><?php echo esc_html('Mostrando ' . $from . '-' . $to . ' de ' . $total); ?></span>
			<?php if ($pages > 1) : ?>
				<div class="twob-section-pager">
					<?php if ($page > 1) : ?>
						<a class="button button-small" href="<?php echo esc_url(self::tasks_page_url(array($param => $page - 1), $anchor)); ?>">10 anteriores</a>
					<?php endif; ?>
					<span class="twob-section-page"><?php echo esc_html('Pagina ' . $page . ' de ' . $pages); ?></span>
					<?php if ($page < $pages) : ?>
						<a class="button button-small" href="<?php echo esc_url(self::tasks_page_url(array($param => $page + 1), $anchor)); ?>">Siguientes 10</a>
					<?php endif; ?>
				</div>
			<?php endif; ?>
		</div>
		<?php
	}

	private static function master_client_available() {
		return post_type_exists('2b_cliente');
	}

	private static function master_client_title_for_lead($lead_id) {
		$company = trim((string) get_post_meta($lead_id, '_crm_company', true));
		if ($company) {
			return $company;
		}
		return trim((string) get_the_title($lead_id));
	}

	private static function master_client_contact_label_for_lead($lead_id) {
		$company = trim((string) get_post_meta($lead_id, '_crm_company', true));
		$title = trim((string) get_the_title($lead_id));
		if ($company && $title && strtolower($company) !== strtolower($title)) {
			return $title;
		}
		return '';
	}

