	private static function master_client_is_real_for_lead($lead_id) {
		$stage = sanitize_key((string) get_post_meta($lead_id, '_crm_stage', true));
		return 'won' === $stage;
	}

	private static function master_client_find_existing_id($lead_id) {
		$linked_id = (int) get_post_meta($lead_id, '_crm_master_client_id', true);
		if ($linked_id > 0 && '2b_cliente' === get_post_type($linked_id)) {
			return $linked_id;
		}

		$by_relation = get_posts(array(
			'post_type' => '2b_cliente',
			'post_status' => array('publish', 'draft'),
			'numberposts' => 1,
			'meta_query' => array(
				array('key' => 'crm_dani_lead_relacionado', 'value' => (int) $lead_id, 'compare' => '='),
			),
			'fields' => 'ids',
		));
		if (! empty($by_relation[0])) {
			return (int) $by_relation[0];
		}

		$email = sanitize_email((string) get_post_meta($lead_id, '_crm_email', true));
		if ($email) {
			$by_email = get_posts(array(
				'post_type' => '2b_cliente',
				'post_status' => array('publish', 'draft'),
				'numberposts' => 1,
				'meta_query' => array(
					array('key' => 'email', 'value' => $email, 'compare' => '='),
				),
				'fields' => 'ids',
			));
			if (! empty($by_email[0])) {
				return (int) $by_email[0];
			}
		}

		$title = self::master_client_title_for_lead($lead_id);
		if ($title) {
			$existing = get_page_by_title($title, OBJECT, '2b_cliente');
			if ($existing instanceof WP_Post) {
				return (int) $existing->ID;
			}
		}

		return 0;
	}

	private static function master_client_relation_ids_for_lead($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return array();
		}

		$client_ids = array();
		$linked_id = (int) get_post_meta($lead_id, '_crm_master_client_id', true);
		if ($linked_id > 0 && '2b_cliente' === get_post_type($linked_id)) {
			$client_ids[] = $linked_id;
		}

		$related_ids = get_posts(array(
			'post_type' => 'any',
			'post_status' => 'any',
			'numberposts' => -1,
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => 'crm_dani_lead_relacionado', 'value' => $lead_id, 'compare' => '='),
			),
		));
		foreach ($related_ids as $related_id) {
			$related_id = (int) $related_id;
			if ($related_id > 0 && '2b_cliente' === get_post_type($related_id)) {
				$client_ids[] = $related_id;
			}
		}

		return array_values(array_unique(array_map('intval', $client_ids)));
	}

	private static function unlink_master_client_for_lead($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return;
		}

		foreach (self::master_client_relation_ids_for_lead($lead_id) as $client_id) {
			if ('2b_cliente' !== get_post_type($client_id)) {
				continue;
			}

			$related_lead_id = (int) get_post_meta($client_id, 'crm_dani_lead_relacionado', true);
			if ($related_lead_id !== $lead_id) {
				continue;
			}

			delete_post_meta($client_id, 'crm_dani_lead_relacionado');
			delete_post_meta($client_id, 'crm_dani_contact_name');
			delete_post_meta($client_id, 'crm_dani_company_name');
			delete_post_meta($client_id, 'crm_dani_last_sync_at');
			delete_post_meta($client_id, 'crm_dani_stage');
			delete_post_meta($client_id, 'crm_dani_client_type');
			delete_post_meta($client_id, 'crm_dani_service_interest');
			delete_post_meta($client_id, 'crm_dani_is_real_client');
		}

		delete_post_meta($lead_id, '_crm_master_client_id');
	}

	private static function sync_master_client_for_lead($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id) || ! self::master_client_available() || ! self::master_client_is_real_for_lead($lead_id)) {
			return 0;
		}

		$title = self::master_client_title_for_lead($lead_id);
		if (! $title) {
			return 0;
		}

		$service_interest = (string) get_post_meta($lead_id, '_crm_service_interest', true);
		$service_data = self::master_client_service_data($service_interest);
		$stage = (string) get_post_meta($lead_id, '_crm_stage', true);
		$next_followup = (string) get_post_meta($lead_id, '_crm_next_followup', true);
		$value = (float) get_post_meta($lead_id, '_crm_value', true);
		$notes = trim((string) get_post_meta($lead_id, '_crm_observations', true));
		$client_id = self::master_client_find_existing_id($lead_id);
		$is_existing_client = $client_id > 0;

		$postarr = array(
			'post_type' => '2b_cliente',
			'post_title' => $title,
		);

		if ($client_id > 0) {
			$postarr['ID'] = $client_id;
		} else {
			$postarr['post_status'] = 'publish';
		}

		$result = wp_insert_post($postarr, true);
		if (is_wp_error($result) || ! $result) {
			return 0;
		}

		$client_id = (int) $result;
		$contact_label = self::master_client_contact_label_for_lead($lead_id);
		$origin_channel = (string) get_post_meta($lead_id, '_crm_origin_channel', true);
		$custom_service_name = (string) $service_data['custom_service'];
		$phone = trim((string) get_post_meta($lead_id, '_crm_phone', true));
		$email = sanitize_email((string) get_post_meta($lead_id, '_crm_email', true));
		$website = trim((string) get_post_meta($lead_id, '_crm_website_url', true));
		$current_group = trim((string) get_post_meta($client_id, 'grupo', true));
		$current_operational_type = sanitize_key((string) get_post_meta($client_id, 'tipo_operacion_cliente', true));
		$current_service = sanitize_key((string) get_post_meta($client_id, 'servicio_principal', true));
		$current_owner = sanitize_key((string) get_post_meta($client_id, 'responsable', true));
		$current_problem = trim((string) get_post_meta($client_id, 'problema_principal', true));
		$should_seed_operational = ! $is_existing_client || '' === $current_operational_type || 'prospecto' === $current_operational_type;
		$should_seed_service = ! $is_existing_client || '' === $current_service || 'servicio_personalizado' === $current_service;

		update_post_meta($client_id, 'crm_dani_lead_relacionado', $lead_id);
		update_post_meta($lead_id, '_crm_master_client_id', $client_id);

		if ('' === $current_group) {
			update_post_meta($client_id, 'grupo', 'C');
		}
		if ($should_seed_operational) {
			update_post_meta($client_id, 'tipo_operacion_cliente', (string) $service_data['operational_type']);
		}
		if ($should_seed_service) {
			update_post_meta($client_id, 'servicio_principal', (string) $service_data['service']);
		}
		if ($custom_service_name && (! $is_existing_client || '' === trim((string) get_post_meta($client_id, 'servicio_personalizado_nombre', true)))) {
			update_post_meta($client_id, 'servicio_personalizado_nombre', $custom_service_name);
		}
		update_post_meta($client_id, 'estado_pipeline', self::master_client_pipeline_for_stage($stage));
		if ('' === $current_owner) {
			update_post_meta($client_id, 'responsable', 'dani');
		}
		if ('' !== $phone) {
			update_post_meta($client_id, 'telefono', $phone);
		}
		if ('' !== $email) {
			update_post_meta($client_id, 'email', $email);
		}
		if ('' !== $contact_label) {
			update_post_meta($client_id, 'cargo', $contact_label);
		}
		if ('' !== $website) {
			update_post_meta($client_id, 'url_sitio', $website);
		}
		if ('' !== $origin_channel) {
			update_post_meta($client_id, 'fuente_cliente', self::master_client_source_for_origin($origin_channel));
		}
		$preferred_channel = self::master_client_channel_for_origin($origin_channel);
		if ('' !== $preferred_channel) {
			update_post_meta($client_id, 'canal_preferido', $preferred_channel);
		}
		if ('' !== $notes && '' === $current_problem) {
			update_post_meta($client_id, 'problema_principal', $notes);
		}
		update_post_meta($client_id, 'fecha_proximo_contacto', $next_followup);
		if ('' !== $notes && (! $is_existing_client || '' === trim((string) get_post_meta($client_id, 'notas_internas', true)))) {
			update_post_meta($client_id, 'notas_internas', $notes);
		}
		update_post_meta($client_id, 'crm_dani_contact_name', (string) get_the_title($lead_id));
		update_post_meta($client_id, 'crm_dani_company_name', trim((string) get_post_meta($lead_id, '_crm_company', true)));
		update_post_meta($client_id, 'crm_dani_last_sync_at', current_time('mysql'));
		update_post_meta($client_id, 'crm_dani_stage', sanitize_key($stage));
		update_post_meta($client_id, 'crm_dani_client_type', sanitize_key((string) get_post_meta($lead_id, '_crm_client_type', true)));
		update_post_meta($client_id, 'crm_dani_service_interest', sanitize_key($service_interest));
		update_post_meta($client_id, 'crm_dani_is_real_client', 1);

		if ($should_seed_operational && 'diagnostico' === $service_data['operational_type']) {
			update_post_meta($client_id, 'valor_diagnostico', max(0, $value));
			update_post_meta($client_id, 'estado_diagnostico', (string) get_post_meta($client_id, 'estado_diagnostico', true) ?: (string) $service_data['diagnostico_status']);
		}

		if ($should_seed_operational && 'plan' === $service_data['operational_type']) {
			update_post_meta($client_id, 'estado_continuidad', (string) get_post_meta($client_id, 'estado_continuidad', true) ?: 'activa');
			if (! empty($service_data['continuity_services']) && ! get_post_meta($client_id, 'servicios_contratados', true)) {
				update_post_meta($client_id, 'servicios_contratados', array_values((array) $service_data['continuity_services']));
			}
			if ($custom_service_name && ! trim((string) get_post_meta($client_id, 'servicios_contratados_extra', true))) {
				update_post_meta($client_id, 'servicios_contratados_extra', $custom_service_name);
			}
		}

		if ($should_seed_operational && 'proyecto' === $service_data['operational_type']) {
			update_post_meta($client_id, 'estado_proyecto', (string) get_post_meta($client_id, 'estado_proyecto', true) ?: (string) $service_data['project_status']);
		}

		if (class_exists('Two_B_CRM_CPTs')) {
			Two_B_CRM_CPTs::sync_cliente_type($client_id);
			Two_B_CRM_CPTs::sync_ded_client_link($client_id);
		}

		return $client_id;
	}

	private static function set_lead_stage($lead_id, $new_stage, $context = 'manual', $lost_reason = '') {
		$new_stage = self::sanitize_stage_input($new_stage);
		$context_key = sanitize_key((string) $context);
		$current_stage_meta = (string) get_post_meta($lead_id, '_crm_stage', true);
		$old_stage = self::normalize_stage_key($current_stage_meta);
		if (! $old_stage) {
			$old_stage = 'new';
		}
		$current_lost_reason = (string) get_post_meta($lead_id, '_crm_closed_lost_reason', true);
		$resolved_lost_reason = trim((string) $lost_reason);
		$allow_missing_lost_reason = 'lost' === $new_stage && '' === $resolved_lost_reason && (false !== strpos($context_key, 'auto') || false !== strpos($context_key, 'legacy') || false !== strpos($context_key, 'runtime'));
		if ('lost' === $new_stage && '' === $resolved_lost_reason) {
			$resolved_lost_reason = trim($current_lost_reason);
		}
		if ('lost' === $new_stage && '' === $resolved_lost_reason && ! $allow_missing_lost_reason) {
			return new WP_Error('lost_reason_required', 'Debes registrar motivo para Cerrado perdido.');
		}
		if ($old_stage !== $new_stage && self::stage_requires_logged_interaction($new_stage) && ! self::lead_has_logged_interaction($lead_id)) {
			return new WP_Error('interaction_required', 'Debes registrar primero una interaccion antes de avanzar este lead.');
		}
		if ($old_stage === $new_stage) {
			if ($current_stage_meta !== $new_stage) {
				update_post_meta($lead_id, '_crm_stage', $new_stage);
			}
			if ('closed_no_response' === $new_stage) {
				self::set_lead_close_reason_code($lead_id, 'no_response');
				self::set_lead_next_followup_meta($lead_id, '');
				self::close_open_commercial_tasks_for_lead($lead_id, 'closed_no_response', 'Lead cerrado automaticamente sin respuesta.', 'lead_marked_no_response');
				self::close_sequence_tasks_for_lead($lead_id, 'El lead quedo cerrado sin respuesta dentro del ciclo inicial.', current_time('Y-m-d'));
			} elseif ('pre_contact' === $new_stage) {
				self::set_lead_next_followup_meta($lead_id, '');
				self::close_sequence_tasks_for_lead($lead_id, 'El lead volvio a revision tecnica previa y salio del ciclo automatico.', current_time('Y-m-d'));
				self::ensure_precontact_review_task($lead_id, current_time('Y-m-d'));
			} elseif ('lost' === $new_stage) {
				self::set_lead_close_reason_code($lead_id, 'lost');
				if ('' !== $resolved_lost_reason) {
					update_post_meta($lead_id, '_crm_closed_lost_reason', sanitize_textarea_field($resolved_lost_reason));
				} else {
					delete_post_meta($lead_id, '_crm_closed_lost_reason');
				}
				self::set_lead_next_followup_meta($lead_id, '');
				self::close_open_commercial_tasks_for_lead($lead_id, 'lost', $resolved_lost_reason ?: 'Lead cerrado como perdido sin motivo registrado al momento del cierre.', 'lead_marked_lost');
				self::close_sequence_tasks_for_lead($lead_id, 'El lead quedo cerrado como perdido.', current_time('Y-m-d'));
				if ('' !== $resolved_lost_reason) {
					self::close_missing_lost_reason_tasks($lead_id);
				} else {
					self::ensure_missing_lost_reason_task($lead_id, current_time('Y-m-d'), $context_key ?: 'cierre_perdido');
				}
			}
			if ('won' === $new_stage) {
				self::set_lead_close_reason_code($lead_id, 'won');
				update_post_meta($lead_id, '_crm_is_client', 1);
				self::close_sequence_tasks_for_lead($lead_id, 'El lead ya se convirtio en cliente y salio de la secuencia inicial.', current_time('Y-m-d'));
				self::close_missing_lost_reason_tasks($lead_id);
			} else {
				if (! in_array($new_stage, array('lost', 'closed_no_response'), true)) {
					self::set_lead_close_reason_code($lead_id, '');
				}
				if ('lost' !== $new_stage) {
					self::close_missing_lost_reason_tasks($lead_id);
				}
				delete_post_meta($lead_id, '_crm_is_client');
				self::unlink_master_client_for_lead($lead_id);
			}
			if (in_array($new_stage, array('responded_interested', 'meeting_scheduled', 'meeting_done', 'proposal_sent'), true) && ! get_post_meta($lead_id, '_crm_next_followup', true)) {
				self::set_lead_next_followup_meta($lead_id, current_time('Y-m-d'), 'Responder lead');
			}
			self::sync_lead_lifecycle_state($lead_id);
			self::sync_lead_next_action($lead_id);
			self::update_temperature($lead_id);
			self::update_operational_status($lead_id);
			self::flush_metrics_cache();
			return true;
		}

		update_post_meta($lead_id, '_crm_stage', $new_stage);
		if (self::is_pre_contact_stage($old_stage) && 'pre_contact' !== $new_stage) {
			self::close_precontact_review_tasks_for_lead($lead_id, 'El lead salió de Pre-contacto y el trabajo de Renata quedó cerrado.', current_time('Y-m-d'));
		}
		if (! self::is_closed_detail_stage($new_stage)) {
			delete_post_meta($lead_id, '_crm_manual_archive');
			delete_post_meta($lead_id, '_crm_manual_archive_at');
			delete_post_meta($lead_id, '_crm_manual_archive_reason');
		}
		if ('closed_no_response' === $new_stage) {
			self::set_lead_close_reason_code($lead_id, 'no_response');
			self::set_lead_next_followup_meta($lead_id, '');
			self::close_open_commercial_tasks_for_lead($lead_id, 'closed_no_response', 'Lead cerrado automaticamente sin respuesta.', 'lead_marked_no_response');
			self::close_sequence_tasks_for_lead($lead_id, 'El lead quedo cerrado sin respuesta dentro del ciclo inicial.', current_time('Y-m-d'));
			self::close_missing_lost_reason_tasks($lead_id);
		} elseif ('pre_contact' === $new_stage) {
			self::set_lead_next_followup_meta($lead_id, '');
			self::close_sequence_tasks_for_lead($lead_id, 'El lead volvio a revision tecnica previa y salio del ciclo automatico.', current_time('Y-m-d'));
			self::close_missing_lost_reason_tasks($lead_id);
			self::ensure_precontact_review_task($lead_id, current_time('Y-m-d'));
		} elseif ('lost' === $new_stage) {
			self::set_lead_close_reason_code($lead_id, 'lost');
			if ('' !== $resolved_lost_reason) {
				update_post_meta($lead_id, '_crm_closed_lost_reason', sanitize_textarea_field($resolved_lost_reason));
			} else {
				delete_post_meta($lead_id, '_crm_closed_lost_reason');
			}
			self::set_lead_next_followup_meta($lead_id, '');
			self::close_open_commercial_tasks_for_lead($lead_id, 'lost', $resolved_lost_reason ?: 'Lead cerrado como perdido sin motivo registrado al momento del cierre.', 'lead_marked_lost');
			self::close_sequence_tasks_for_lead($lead_id, 'El lead quedo cerrado como perdido.', current_time('Y-m-d'));
			if ('' !== $resolved_lost_reason) {
				self::close_missing_lost_reason_tasks($lead_id);
			} else {
				self::ensure_missing_lost_reason_task($lead_id, current_time('Y-m-d'), $context_key ?: 'cierre_perdido');
			}
		} elseif ('lost' === $old_stage) {
			delete_post_meta($lead_id, '_crm_closed_lost_reason');
			self::close_missing_lost_reason_tasks($lead_id);
		}
		if ('won' === $new_stage) {
			self::set_lead_close_reason_code($lead_id, 'won');
			update_post_meta($lead_id, '_crm_is_client', 1);
			$service_interest = (string) get_post_meta($lead_id, '_crm_service_interest', true);
			$funnel_stage = 'implementation';
			if (self::is_diagnostic_service($service_interest)) {
				$funnel_stage = 'diagnostic';
			} elseif (self::is_continuity_service($service_interest)) {
				$funnel_stage = 'continuity';
			}
			update_post_meta($lead_id, '_crm_funnel_stage', $funnel_stage);
			self::log_activity('deal_won', $lead_id, array('funnel_stage' => $funnel_stage));
			self::close_sequence_tasks_for_lead($lead_id, 'El lead ya se convirtio en cliente y salio de la secuencia inicial.', current_time('Y-m-d'));
		} else {
			if (! in_array($new_stage, array('lost', 'closed_no_response'), true)) {
				self::set_lead_close_reason_code($lead_id, '');
			}
			if ('lost' !== $new_stage) {
				self::close_missing_lost_reason_tasks($lead_id);
			}
			delete_post_meta($lead_id, '_crm_is_client');
			self::unlink_master_client_for_lead($lead_id);
		}
		if (in_array($new_stage, array('responded_interested', 'meeting_scheduled', 'meeting_done', 'proposal_sent'), true) && ! get_post_meta($lead_id, '_crm_next_followup', true)) {
			self::set_lead_next_followup_meta($lead_id, current_time('Y-m-d'), 'Responder lead');
		}
		if (in_array($new_stage, array('responded_interested', 'meeting_scheduled', 'meeting_done', 'proposal_sent'), true)) {
			self::close_sequence_tasks_for_lead($lead_id, 'El lead respondio o avanzo en el proceso. La secuencia inicial se detuvo.', current_time('Y-m-d'));
		}
		if (self::is_closed_detail_stage($old_stage) && ! self::is_closed_detail_stage($new_stage)) {
			self::log_activity('lead_reactivated', $lead_id, array('from_stage' => $old_stage, 'to_stage' => $new_stage));
		}
		$user_id = get_current_user_id();
		self::log_activity('stage_changed', $lead_id, array(
			'old_stage' => $old_stage,
			'stage' => $new_stage,
			'user_id' => $user_id,
			'context' => $context,
			'lost_reason' => ('lost' === $new_stage && '' !== $resolved_lost_reason) ? sanitize_textarea_field($resolved_lost_reason) : '',
		));
		self::sync_lead_lifecycle_state($lead_id);
		self::sync_lead_next_action($lead_id);
		self::update_temperature($lead_id);
		self::update_operational_status($lead_id);
		self::flush_metrics_cache();
		return true;
	}

	public static function block_lead_delete_capability($caps, $cap, $user_id, $args) {
		if (! in_array($cap, array('delete_post', 'delete_posts'), true) || empty($args[0])) {
			return $caps;
		}
		$post = get_post((int) $args[0]);
		if (! $post || 'crm_lead' !== $post->post_type) {
			return $caps;
		}
		return $caps;
	}

	public static function lead_row_actions($actions, $post) {
		if ('crm_lead' !== $post->post_type) {
			return $actions;
		}

		if ('trash' === $post->post_status) {
			$url = wp_nonce_url(admin_url('admin-post.php?action=twob_crm_restore_lead&lead_id=' . (int) $post->ID), 'twob_crm_restore_lead_' . (int) $post->ID);
			$actions['restore'] = '<a href="' . esc_url($url) . '">Restaurar</a>';
			$delete_url = get_delete_post_link($post->ID, '', true);
			if ($delete_url) {
				$actions['delete'] = '<a href="' . esc_url($delete_url) . '">Eliminar permanentemente</a>';
			}
			return $actions;
		}

		$trash_url = get_delete_post_link($post->ID);
		if ($trash_url) {
			$actions['trash'] = '<a href="' . esc_url($trash_url) . '">Enviar a la papelera</a>';
		}
		return $actions;
	}

	public static function archive_lead() {
		$lead_id = isset($_GET['lead_id']) ? absint($_GET['lead_id']) : 0;
		if (! $lead_id || ! self::get_valid_crm_post($lead_id, 'crm_lead')) {
			wp_safe_redirect(admin_url('edit.php?post_type=crm_lead'));
			exit;
		}
		if (! self::current_user_can_delete_crm_post($lead_id)) {
			wp_die('Sin permisos para archivar.');
		}
		check_admin_referer('twob_crm_archive_lead_' . $lead_id);
		delete_post_meta($lead_id, '_crm_archived');
		wp_trash_post($lead_id);
		wp_safe_redirect(admin_url('edit.php?post_type=crm_lead'));
		exit;
	}

	public static function restore_lead() {
		$lead_id = isset($_GET['lead_id']) ? absint($_GET['lead_id']) : 0;
		if (! $lead_id || ! self::get_valid_crm_post($lead_id, 'crm_lead', true)) {
			wp_safe_redirect(admin_url('edit.php?post_type=crm_lead&post_status=trash'));
			exit;
		}
		if (! self::current_user_can_edit_crm_post($lead_id)) {
			wp_die('Sin permisos para restaurar.');
		}
		check_admin_referer('twob_crm_restore_lead_' . $lead_id);
		self::restore_lead_record($lead_id);
		wp_safe_redirect(admin_url('edit.php?post_type=crm_lead'));
		exit;
	}

	private static function get_active_leads($args = array()) {
		$defaults = array(
			'post_type' => 'crm_lead',
			'post_status' => 'publish',
			'numberposts' => 120,
		);
		$args = wp_parse_args($args, $defaults);
		$meta_query = isset($args['meta_query']) ? (array) $args['meta_query'] : array();
		$meta_query[] = array('key' => '_crm_archived', 'compare' => 'NOT EXISTS');
		$args['meta_query'] = $meta_query;
		return get_posts($args);
	}

	private static function get_response_selectable_leads($args = array()) {
		$defaults = array(
			'post_type' => 'crm_lead',
			'post_status' => 'publish',
			'numberposts' => 300,
			'orderby' => 'date',
			'order' => 'DESC',
		);
		$args = wp_parse_args($args, $defaults);
		return get_posts($args);
	}

	private static function normalize_search_text($value) {
		$value = remove_accents(wp_strip_all_tags((string) $value));
		$value = strtolower($value);
		$value = preg_replace('/\s+/', ' ', $value);
		return trim((string) $value);
	}

	private static function lead_search_haystack($lead_id) {
		static $cache = array();

		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return '';
		}
		if (isset($cache[$lead_id])) {
			return $cache[$lead_id];
		}

		$settings = self::settings_get();
		$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		$client_type = (string) get_post_meta($lead_id, '_crm_client_type', true);
		$service_interest = (string) get_post_meta($lead_id, '_crm_service_interest', true);
		$origin_channel = (string) get_post_meta($lead_id, '_crm_origin_channel', true);
		$technical_finding = (string) get_post_meta($lead_id, '_crm_technical_finding', true);
		$alliance_source = (string) get_post_meta($lead_id, '_crm_alliance_source', true);

		$parts = array(
			get_the_title($lead_id),
			(string) get_post_meta($lead_id, '_crm_company', true),
			(string) get_post_meta($lead_id, '_crm_email', true),
			(string) get_post_meta($lead_id, '_crm_phone', true),
			(string) get_post_meta($lead_id, '_crm_website_url', true),
			(string) get_post_meta($lead_id, '_crm_observations', true),
			$technical_finding,
			$alliance_source,
			$settings['client_types'][$client_type] ?? $client_type,
			self::service_interest_label($service_interest),
			self::stage_labels()[$stage] ?? $stage,
			self::channel_labels()[$origin_channel] ?? $origin_channel,
		);

		$cache[$lead_id] = self::normalize_search_text(implode(' ', array_filter(array_map('strval', $parts))));
		return $cache[$lead_id];
	}

		private static function lead_matches_search($lead_id, $query) {
			$query = self::normalize_search_text($query);
			if ('' === $query) {
				return true;
			}
			return false !== strpos(self::lead_search_haystack($lead_id), $query);
		}

	private static function filter_leads_by_search($leads, $query) {
		$query = self::normalize_search_text($query);
		if ('' === $query) {
			return array_values((array) $leads);
		}

		$filtered = array();
		foreach ((array) $leads as $lead) {
			if ($lead instanceof WP_Post && self::lead_matches_search((int) $lead->ID, $query)) {
				$filtered[] = $lead;
			}
		}

		return $filtered;
	}

	private static function followup_filter_labels() {
		return array(
			'open' => 'Abiertos',
			'overdue' => 'Seguimiento vencido',
			'today' => 'Seguimiento hoy',
			'upcoming' => 'Seguimiento futuro',
			'no_date' => 'Sin fecha seguimiento',
			'closed' => 'Cerrados',
		);
	}

	private static function sanitize_followup_filter($filter) {
		$filter = sanitize_key((string) $filter);
		return isset(self::followup_filter_labels()[$filter]) ? $filter : '';
	}

	private static function lead_matches_followup_filter($lead_id, $filter, $today = '') {
		$filter = self::sanitize_followup_filter($filter);
		if ('' === $filter) {
			return true;
		}

		$today = $today ?: current_time('Y-m-d');
		$stage = self::normalize_stage_key((string) get_post_meta((int) $lead_id, '_crm_stage', true));
		$next = (string) get_post_meta((int) $lead_id, '_crm_next_followup', true);
		$is_closed = in_array($stage, array('won', 'lost'), true);

		if ('open' === $filter) {
			return ! $is_closed;
		}
		if ('closed' === $filter) {
			return $is_closed;
		}
		if ($is_closed) {
			return false;
		}
		if ('overdue' === $filter) {
			return '' !== $next && $next < $today;
		}
		if ('today' === $filter) {
			return $next === $today;
		}
		if ('upcoming' === $filter) {
			return '' !== $next && $next > $today;
		}
		if ('no_date' === $filter) {
			return '' === $next;
		}

		return true;
	}

	private static function filter_leads_by_followup($leads, $filter, $today = '') {
		$filter = self::sanitize_followup_filter($filter);
		if ('' === $filter) {
			return array_values((array) $leads);
		}

		$filtered = array();
		foreach ((array) $leads as $lead) {
			if ($lead instanceof WP_Post && self::lead_matches_followup_filter((int) $lead->ID, $filter, $today)) {
				$filtered[] = $lead;
			}
		}

		return $filtered;
	}

	private static function get_lead_interactions($lead_id, $limit = 10) {
		static $cache = array();

		$lead_id = (int) $lead_id;
		$limit = (int) $limit;
		$query_limit = -1 === $limit ? -1 : max(1, $limit);
		$cache_key = $lead_id . ':' . $limit;

		if (! $lead_id) {
			return array();
		}
		if (isset($cache[$cache_key])) {
			return $cache[$cache_key];
		}

		$cache[$cache_key] = get_posts(array(
			'post_type' => 'crm_interaction',
			'post_status' => 'publish',
			'numberposts' => $query_limit,
			'orderby' => 'date',
			'order' => 'DESC',
			'meta_query' => array(
				array('key' => '_crm_lead_id', 'value' => $lead_id, 'compare' => '='),
			),
		));

		return $cache[$cache_key];
	}

	private static function get_lead_tasks($lead_id, $limit = 10, $include_done = true) {
		static $cache = array();

		$lead_id = (int) $lead_id;
		$limit = max(1, (int) $limit);
		$cache_key = $lead_id . ':' . $limit . ':' . ($include_done ? 'all' : 'open');

		if (! $lead_id) {
			return array();
		}
		if (isset($cache[$cache_key])) {
			return $cache[$cache_key];
		}

		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => max($limit * 3, $limit),
			'meta_key' => '_crm_task_due',
			'orderby' => 'meta_value',
			'order' => 'ASC',
			'meta_query' => array(
				array('key' => '_crm_task_lead_id', 'value' => $lead_id, 'compare' => '='),
			),
		));

		if (! $include_done) {
			$tasks = array_values(array_filter($tasks, function ($task) {
				return 'done' !== self::normalize_task_status((string) get_post_meta((int) $task->ID, '_crm_task_status', true))
					&& ! self::task_should_be_hidden_from_open_views((int) $task->ID);
			}));
		}

		$cache[$cache_key] = array_slice($tasks, 0, $limit);
		return $cache[$cache_key];
	}

	private static function sync_google_task_status_prefix($task_id, $status) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return;
		}

		$calendar_id = rawurlencode((string) self::google_settings_get()['calendar_id']);
		$prefix = ('done' === self::normalize_task_status($status)) ? '[OK] ' : '';
		foreach (self::google_connected_user_ids() as $user_id) {
			$event_id = (string) get_post_meta($task_id, '_crm_google_event_id_user_' . (int) $user_id, true);
			if (! $event_id || ! self::google_is_connected((int) $user_id)) {
				continue;
			}
			self::google_api_request('PATCH', '/calendars/' . $calendar_id . '/events/' . rawurlencode($event_id), array(
				'summary' => $prefix . get_the_title($task_id),
			), (int) $user_id);
		}
	}

	private static function find_existing_interaction_for_resolution($lead_id, $date, $task_id = 0) {
		$lead_id = (int) $lead_id;
		$task_id = (int) $task_id;
		$date = trim((string) $date);
		if (! $lead_id || ! $date) {
			return 0;
		}

		$interactions = get_posts(array(
			'post_type' => 'crm_interaction',
			'post_status' => 'publish',
			'numberposts' => 10,
			'orderby' => 'date',
			'order' => 'DESC',
			'meta_query' => array(
				array('key' => '_crm_lead_id', 'value' => $lead_id, 'compare' => '='),
				array('key' => '_crm_interaction_date', 'value' => $date, 'compare' => '='),
			),
		));

		$fallback = 0;
		foreach ($interactions as $interaction) {
			$interaction_id = (int) $interaction->ID;
			$linked_task_id = (int) get_post_meta($interaction_id, '_crm_task_id', true);
			if ($task_id && $linked_task_id === $task_id) {
				return $interaction_id;
			}
			if (! $fallback && ! $linked_task_id) {
				$fallback = $interaction_id;
			}
		}

		return $fallback;
	}

	private static function upsert_resolution_interaction($lead_id, $task_id, $payload) {
		$lead_id = (int) $lead_id;
		$task_id = (int) $task_id;
		$date = (string) $payload['date'];
		$kind = (string) $payload['kind'];
		$channel = (string) $payload['channel'];
		$interaction_action = (string) $payload['interaction_action'];
		$result = (string) $payload['result'];
		$stage_update = (string) $payload['stage_update'];
		$next_followup = (string) $payload['next_followup'];
		$note = (string) $payload['note'];

		$existing_id = self::find_existing_interaction_for_resolution($lead_id, $date, $task_id);
		$post_args = array(
			'post_type' => 'crm_interaction',
			'post_status' => 'publish',
			'post_title' => ucfirst($kind) . ': ' . wp_strip_all_tags(get_the_title($lead_id)),
		);

		if ($existing_id) {
			$post_args['ID'] = (int) $existing_id;
			wp_update_post($post_args);
			$interaction_id = (int) $existing_id;
		} else {
			$post_args['meta_input'] = array(
				'_crm_interaction_kind' => $kind,
				'_crm_lead_id' => $lead_id,
				'_crm_interaction_date' => $date,
				'_crm_interaction_channel' => $channel,
				'_crm_interaction_action' => $interaction_action,
				'_crm_interaction_result' => $result,
				'_crm_interaction_stage' => $stage_update,
				'_crm_interaction_next_followup' => $next_followup,
				'_crm_interaction_note' => $note,
				'_crm_task_id' => $task_id,
			);
			$interaction_id = wp_insert_post($post_args);
			if (! $interaction_id || is_wp_error($interaction_id)) {
				return new WP_Error('interaction_insert_failed', 'No se pudo registrar la interaccion.');
			}
		}

		if ($existing_id) {
			update_post_meta($interaction_id, '_crm_interaction_kind', $kind);
			update_post_meta($interaction_id, '_crm_lead_id', $lead_id);
			update_post_meta($interaction_id, '_crm_interaction_date', $date);
			update_post_meta($interaction_id, '_crm_interaction_channel', $channel);
			update_post_meta($interaction_id, '_crm_interaction_action', $interaction_action);
			update_post_meta($interaction_id, '_crm_interaction_result', $result);
			update_post_meta($interaction_id, '_crm_interaction_stage', $stage_update);
			update_post_meta($interaction_id, '_crm_interaction_next_followup', $next_followup);
			update_post_meta($interaction_id, '_crm_interaction_note', $note);
			update_post_meta($interaction_id, '_crm_task_id', $task_id);
		}

		return (int) $interaction_id;
	}

	private static function interaction_effective_day($interaction_id) {
		$interaction_id = (int) $interaction_id;
		if (! $interaction_id || 'crm_interaction' !== get_post_type($interaction_id)) {
			return '';
		}

		$interaction_day = trim((string) get_post_meta($interaction_id, '_crm_interaction_date', true));
		if ($interaction_day) {
			return $interaction_day;
		}

		$interaction = get_post($interaction_id);
		if (! $interaction instanceof WP_Post) {
			return '';
		}

		return substr((string) $interaction->post_date, 0, 10);
	}

	private static function find_qualifying_interaction_for_open_task($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return 0;
		}

		$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
		$task_due = trim((string) get_post_meta($task_id, '_crm_task_due', true));
		if (! $lead_id) {
			return 0;
		}

		$interactions = get_posts(array(
			'post_type' => 'crm_interaction',
			'post_status' => 'publish',
			'numberposts' => 100,
			'orderby' => 'date',
			'order' => 'DESC',
			'meta_query' => array(
				array('key' => '_crm_lead_id', 'value' => $lead_id, 'compare' => '='),
			),
		));

		$fallback = 0;
		foreach ($interactions as $interaction) {
			$interaction_id = (int) $interaction->ID;
			$interaction_day = self::interaction_effective_day($interaction_id);
			if ($task_due && $interaction_day && $interaction_day < $task_due) {
				continue;
			}

			$kind = self::sanitize_interaction_kind((string) get_post_meta($interaction_id, '_crm_interaction_kind', true));
			$channel = self::sanitize_interaction_channel((string) get_post_meta($interaction_id, '_crm_interaction_channel', true));
			$interaction_action = self::normalize_interaction_action((string) get_post_meta($interaction_id, '_crm_interaction_action', true), $kind, $channel);
			$result = self::sanitize_interaction_result((string) get_post_meta($interaction_id, '_crm_interaction_result', true));
			if (! self::task_can_be_resolved_by_interaction($task_id, $kind, $channel, $interaction_action, $result)) {
				continue;
			}

			$linked_task_id = (int) get_post_meta($interaction_id, '_crm_task_id', true);
			if ($linked_task_id === $task_id) {
				return $interaction_id;
			}
			if (! $fallback) {
				$fallback = $interaction_id;
			}
		}

		return $fallback;
	}

	private static function reconcile_open_guided_task_from_history($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return 0;
		}
		if (! self::task_requires_guided_completion($task_id)) {
			return 0;
		}
		if (! self::is_task_open_status((string) get_post_meta($task_id, '_crm_task_status', true))) {
			return 0;
		}

		$interaction_id = self::find_qualifying_interaction_for_open_task($task_id);
		if (! $interaction_id) {
			return 0;
		}

		$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return 0;
		}

		$interaction_day = self::interaction_effective_day($interaction_id) ?: current_time('Y-m-d');
		$kind = self::sanitize_interaction_kind((string) get_post_meta($interaction_id, '_crm_interaction_kind', true));
		$channel = self::sanitize_interaction_channel((string) get_post_meta($interaction_id, '_crm_interaction_channel', true));
		$interaction_action = self::normalize_interaction_action((string) get_post_meta($interaction_id, '_crm_interaction_action', true), $kind, $channel);
		$result = self::sanitize_interaction_result((string) get_post_meta($interaction_id, '_crm_interaction_result', true));
		$note = (string) get_post_meta($interaction_id, '_crm_interaction_note', true);
		$next_followup = trim((string) get_post_meta($interaction_id, '_crm_interaction_next_followup', true));
		if ('' === $next_followup) {
			$next_followup = trim((string) get_post_meta($lead_id, '_crm_next_followup', true));
		}

		$interaction_stage = self::validate_stage_choice((string) get_post_meta($interaction_id, '_crm_interaction_stage', true), true, 'Etapa de lead');
		$resolved_stage = is_wp_error($interaction_stage) || ! $interaction_stage
			? self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true))
			: self::normalize_stage_key((string) $interaction_stage);

		update_post_meta($interaction_id, '_crm_task_id', $task_id);
		$next_task_id = self::mark_task_completed_from_interaction($task_id, $interaction_id, $interaction_action, $result, $note, $next_followup, $resolved_stage);
		if (self::interaction_result_is_positive($result)) {
			self::close_sequence_tasks_for_lead($lead_id, 'El lead ya habia respondido y se cerraron tareas abiertas que quedaron duplicadas.', $interaction_day);
		}
		self::update_temperature($lead_id);
		self::update_operational_status($lead_id, $interaction_day);
		self::maybe_google_sync_followup_for_current_user($lead_id);
		self::sync_master_client_for_lead($lead_id);
		self::log_activity('task_repaired_from_history', $task_id, array(
			'lead_id' => $lead_id,
			'interaction_id' => $interaction_id,
			'next_task_id' => (int) $next_task_id,
			'repaired_day' => $interaction_day,
		));

		return $interaction_id;
	}

	private static function maybe_schedule_next_task_after_resolution($task_id, $lead_id, $next_followup, $resolved_stage, $note = '', $result = '') {
		$task_id = (int) $task_id;
		$lead_id = (int) $lead_id;
		$next_followup = trim((string) $next_followup);
		$resolved_stage = self::normalize_stage_key((string) $resolved_stage);
		if (! $task_id || ! $lead_id || ! $next_followup || 'lost' === $resolved_stage) {
			return 0;
		}
		if (self::interaction_result_is_positive($result) || in_array($resolved_stage, array('responded_interested', 'meeting_scheduled', 'meeting_done', 'proposal_sent', 'won'), true)) {
			return 0;
		}
		if (self::find_open_task_for_lead_on_day($lead_id, $next_followup, $task_id)) {
			return 0;
		}

		$sequence_config = self::task_sequence_step_config($task_id);
		if (! empty($sequence_config)) {
			$next_step_slug = sanitize_key((string) ($sequence_config['next_step_slug'] ?? ''));
			if (! $next_step_slug) {
				return 0;
			}
			$allowed_step_slugs = array_map(function ($step) {
				return sanitize_key((string) ($step['slug'] ?? ''));
			}, self::lead_followup_sequence_steps_for_policy(self::lead_sequence_policy($lead_id)));
			if (! in_array($next_step_slug, $allowed_step_slugs, true)) {
				return 0;
			}
			$next_step = self::lead_followup_step_by_slug($next_step_slug);
			if (empty($next_step)) {
				return 0;
			}

			$new_task_id = self::create_auto_task_once(
				$lead_id,
				(string) $next_step['title'] . wp_strip_all_tags(get_the_title($lead_id)),
				(string) $next_step['type'],
				(string) $next_step['priority'],
				$next_followup,
				'lead_sequence_' . $lead_id . '_' . $next_step_slug,
				array(
					'description' => self::sequence_task_description_for_lead($lead_id, (string) $next_step['description']),
					'assignee' => self::sanitize_task_assignee((string) get_post_meta($task_id, '_crm_task_assignee', true)),
					'category' => 'commercial',
					'relation' => 'lead_client',
					'pipeline_stage' => $resolved_stage,
				)
			);
			if ($new_task_id > 0) {
				self::log_activity('task_followup_scheduled', $new_task_id, array(
					'lead_id' => $lead_id,
					'task_type' => (string) $next_step['type'],
					'next_followup' => $next_followup,
					'source_task_id' => $task_id,
				));
				self::maybe_google_sync_task_for_current_user($new_task_id);
			}
			return (int) $new_task_id;
		}

		$source_type = (string) get_post_meta($task_id, '_crm_task_type', true);
		$next_type = self::task_resolution_next_type($resolved_stage, $source_type);
		$assignee = self::sanitize_task_assignee((string) get_post_meta($task_id, '_crm_task_assignee', true));
		$priority = $next_followup <= current_time('Y-m-d') ? 'high' : 'medium';
		$description = 'Creada automaticamente despues de registrar la gestion de la tarea #' . $task_id . '.';
		if ($note) {
			$description .= "\n\nResumen: " . $note;
		}

		$new_task_id = self::create_auto_task_once(
			$lead_id,
			self::task_resolution_next_title($lead_id, $next_type),
			$next_type,
			$priority,
			$next_followup,
			'task_resolution_next_' . $task_id . '_' . $next_followup,
			array(
				'description' => $description,
				'assignee' => $assignee,
				'category' => 'commercial',
				'relation' => 'lead_client',
				'pipeline_stage' => $resolved_stage,
			)
		);

		if ($new_task_id > 0) {
			self::log_activity('task_followup_scheduled', $new_task_id, array(
				'lead_id' => $lead_id,
				'task_type' => $next_type,
				'next_followup' => $next_followup,
				'source_task_id' => $task_id,
			));
			self::maybe_google_sync_task_for_current_user($new_task_id);
		}

		return (int) $new_task_id;
	}

	private static function mark_task_completed_from_interaction($task_id, $interaction_id, $interaction_action, $result, $note, $next_followup, $resolved_stage) {
		$task_id = (int) $task_id;
		$interaction_id = (int) $interaction_id;
		$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
		$resolved_stage = self::normalize_stage_key((string) $resolved_stage);

		if (! $task_id || ! $lead_id || 'crm_task' !== get_post_type($task_id)) {
			return 0;
		}

		update_post_meta($task_id, '_crm_task_status', 'done');
		update_post_meta($task_id, '_crm_task_completed_at', current_time('mysql'));
		update_post_meta($task_id, '_crm_task_completion_interaction_id', $interaction_id);
		update_post_meta($task_id, '_crm_task_completion_action', self::sanitize_interaction_action($interaction_action));
		update_post_meta($task_id, '_crm_task_completion_result', self::sanitize_interaction_result($result));
		update_post_meta($task_id, '_crm_task_completion_note', sanitize_textarea_field((string) $note));
		update_post_meta($task_id, '_crm_task_completion_next_followup', (string) $next_followup);
		update_post_meta($task_id, '_crm_task_completion_stage', (string) $resolved_stage);
		update_post_meta($task_id, '_crm_task_resolved_by', get_current_user_id());

		$next_task_id = self::maybe_schedule_next_task_after_resolution($task_id, $lead_id, $next_followup, $resolved_stage, $note, $result);
		self::sync_lead_next_action($lead_id);
		self::log_activity('task_completed', $task_id, array(
			'task_type' => (string) get_post_meta($task_id, '_crm_task_type', true),
			'interaction_action' => self::sanitize_interaction_action($interaction_action),
			'result' => self::sanitize_interaction_result($result),
			'next_followup' => (string) $next_followup,
			'interaction_id' => $interaction_id,
			'stage' => (string) $resolved_stage,
		));
		self::maybe_create_next_recurring_task($task_id);
		self::sync_google_task_status_prefix($task_id, 'done');

		return (int) $next_task_id;
	}

	private static function complete_guided_task_resolution($task_id, $payload, $today = '') {
		$task_id = (int) $task_id;
		$task = self::get_valid_crm_post($task_id, 'crm_task');
		if (! $task) {
			return new WP_Error('invalid_task', 'Tarea invalida.');
		}
		if (! self::task_requires_guided_completion($task_id)) {
			return new WP_Error('task_not_guided', 'Esta tarea no requiere registro de interaccion.');
		}

		$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
		$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
		if (! $lead) {
			return new WP_Error('invalid_lead', 'El lead asociado ya no existe.');
		}

		$today = $today ?: current_time('Y-m-d');
		$task_type = (string) get_post_meta($task_id, '_crm_task_type', true);
		$current_stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		$kind = self::sanitize_interaction_kind($payload['interaction_kind'] ?? self::task_default_interaction_kind_for_type($task_type));
		$channel = self::sanitize_interaction_channel($payload['interaction_channel'] ?? self::task_default_interaction_channel_for_type($task_type));
		$interaction_action = self::normalize_interaction_action($payload['interaction_action'] ?? '', $kind, $channel);
		$result = self::sanitize_interaction_result($payload['interaction_result'] ?? 'other');
		$date = self::sanitize_date_input($payload['interaction_date'] ?? $today, false, 'Fecha de interaccion');
		if (is_wp_error($date)) {
			return $date;
		}
		$next_followup = self::sanitize_date_input($payload['next_followup'] ?? '', true, 'Proximo seguimiento');
		if (is_wp_error($next_followup)) {
			return $next_followup;
		}
		$note = isset($payload['interaction_note']) ? sanitize_textarea_field((string) $payload['interaction_note']) : '';
		if ('' === trim($note)) {
			return new WP_Error('task_note_required', 'Debes dejar una nota breve de lo que paso.');
		}

		$stage_update = self::validate_stage_choice($payload['interaction_stage'] ?? '', true, 'Etapa del lead');
		if (is_wp_error($stage_update)) {
			return $stage_update;
		}
		if (! $stage_update) {
			$stage_update = self::task_resolution_stage_suggestion($result, $current_stage);
		}
		$resolved_stage = $stage_update ? self::normalize_stage_key($stage_update) : $current_stage;
		$is_final_sequence_step = ('day10_last_linkedin' === self::task_sequence_step_slug($task_id));
		$archive_after_final_touch = $is_final_sequence_step && ! self::interaction_result_is_positive($result) && 'lost' !== $resolved_stage;

		if ('followup' === $kind && 'proposal_sent' === $current_stage && self::has_recent_proposal_followup($lead_id, $date)) {
			return new WP_Error('proposal_followup_spacing', 'Debes esperar minimo 3 dias entre seguimientos de propuesta.');
		}
		if (! $archive_after_final_touch && 'lost' !== $resolved_stage && '' === $next_followup) {
			return new WP_Error('next_followup_required', 'Debes dejar la proxima fecha de seguimiento antes de cerrar esta tarea.');
		}
		if ('lost' === $resolved_stage && '' === trim($note)) {
			return new WP_Error('lost_reason_required', 'Debes indicar el motivo para marcar este lead como perdido.');
		}
		if (! self::task_can_be_resolved_by_interaction($task_id, $kind, $channel, $interaction_action, $result)) {
			return new WP_Error('interaction_not_enough', 'Esta gestion no alcanza para cerrar la tarea de hoy. Usa una accion con contacto real o una interaccion social valida con resultado claro.');
		}

		$interaction_id = self::upsert_resolution_interaction($lead_id, $task_id, array(
			'kind' => $kind,
			'channel' => $channel,
			'interaction_action' => $interaction_action,
			'result' => $result,
			'stage_update' => $stage_update,
			'next_followup' => $next_followup,
			'note' => $note,
			'date' => $date,
		));
		if (is_wp_error($interaction_id)) {
			return $interaction_id;
		}

		if ($stage_update) {
			$stage_result = self::set_lead_stage($lead_id, $stage_update, 'guided_task_resolution', ('lost' === $resolved_stage) ? $note : '');
			if (is_wp_error($stage_result)) {
				return $stage_result;
			}
		}

		self::set_lead_next_followup_meta($lead_id, ('lost' === $resolved_stage || $archive_after_final_touch) ? '' : $next_followup);
		if (self::interaction_result_is_positive($result)) {
			self::close_sequence_tasks_for_lead($lead_id, 'El lead respondio. La secuencia automatica se cerro para evitar duplicados.', $today);
		}
		self::update_temperature($lead_id);
		self::update_operational_status($lead_id, $today);
		self::maybe_google_sync_followup_for_current_user($lead_id);
		self::sync_master_client_for_lead($lead_id);

		$next_task_id = self::mark_task_completed_from_interaction($task_id, (int) $interaction_id, $interaction_action, $result, $note, $next_followup, $resolved_stage);
		if ($archive_after_final_touch) {
			self::set_manual_archive_state($lead_id, true, 'Secuencia agotada despues del ultimo intento.', $today);
		}
		$message = $next_task_id ? 'Gestion registrada, tarea completada y proximo seguimiento programado.' : 'Gestion registrada y tarea completada.';
		if ($archive_after_final_touch) {
			$message = 'Gestion registrada, tarea completada y lead movido a archivo operativo.';
		}

		return array(
			'interaction_id' => (int) $interaction_id,
			'next_task_id' => (int) $next_task_id,
			'message' => $message,
		);
	}

	private static function maybe_complete_open_task_from_interaction($lead_id, $interaction_id, $payload = array()) {
		$lead_id = (int) $lead_id;
		$interaction_id = (int) $interaction_id;
		if (! $lead_id || ! $interaction_id) {
			return array('task_id' => 0, 'next_task_id' => 0);
		}

		$date = (string) ($payload['date'] ?? current_time('Y-m-d'));
		$task_id = self::find_resolvable_open_task_for_lead($lead_id, $date, isset($payload['task_id']) ? (int) $payload['task_id'] : 0, $payload);
		if (! $task_id) {
			return array('task_id' => 0, 'next_task_id' => 0);
		}

		$current_stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		$next_task_id = self::mark_task_completed_from_interaction(
			$task_id,
			$interaction_id,
			(string) ($payload['interaction_action'] ?? ''),
			(string) ($payload['result'] ?? 'other'),
			(string) ($payload['note'] ?? ''),
			(string) ($payload['next_followup'] ?? ''),
			(string) ($payload['resolved_stage'] ?? $current_stage)
		);

		return array(
			'task_id' => (int) $task_id,
			'next_task_id' => (int) $next_task_id,
		);
	}

	private static function lead_last_interaction_day($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return '';
		}

		$interactions = self::get_lead_interactions($lead_id, 1);
		if (empty($interactions[0])) {
			return '';
		}

		$interaction_id = (int) $interactions[0]->ID;
		$interaction_day = (string) get_post_meta($interaction_id, '_crm_interaction_date', true);
		if ($interaction_day) {
			return $interaction_day;
		}

		return substr((string) $interactions[0]->post_date, 0, 10);
	}

	private static function lead_last_touch_day($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return '';
		}

		$last_interaction_day = self::lead_last_interaction_day($lead_id);
		if ($last_interaction_day) {
			return $last_interaction_day;
		}

		$lead = get_post($lead_id);
		return ($lead && ! empty($lead->post_date)) ? substr((string) $lead->post_date, 0, 10) : '';
	}

	private static function days_between_dates($older_day, $newer_day = '') {
		$older_day = trim((string) $older_day);
		$newer_day = trim((string) ($newer_day ?: current_time('Y-m-d')));
		if (! $older_day || ! $newer_day) {
			return 0;
		}

		$older_ts = strtotime($older_day);
		$newer_ts = strtotime($newer_day);
		if (! $older_ts || ! $newer_ts || $newer_ts < $older_ts) {
			return 0;
		}

		return (int) floor(($newer_ts - $older_ts) / DAY_IN_SECONDS);
	}

	private static function lead_risk_snapshot($lead_id, $today = '') {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return array();
		}

		$today = $today ?: current_time('Y-m-d');
		$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		if (in_array($stage, array('lost', 'closed_no_response'), true)) {
			return array();
		}

		$next_followup = (string) get_post_meta($lead_id, '_crm_next_followup', true);
		$last_touch = self::lead_last_touch_day($lead_id);
		$days_since_touch = self::business_days_between_dates($last_touch, $today);
		$days_overdue = ($next_followup && $next_followup < $today) ? self::business_days_between_dates($next_followup, $today) : 0;
		$is_client = 'won' === $stage;
		$risk = 'stable';
		$reasons = array();

		if (! $next_followup) {
			$risk = 'critical';
			$reasons[] = 'Sin proxima fecha';
		}

		if ($is_client) {
			if ($days_since_touch >= 45 || $days_overdue >= 14) {
				$risk = 'critical';
			} elseif ($days_since_touch >= 30 || $days_overdue >= 7) {
				$risk = ('critical' === $risk) ? 'critical' : 'warning';
			}
		} else {
			if ($days_since_touch >= 14 || $days_overdue >= 7) {
				$risk = 'critical';
			} elseif ($days_since_touch >= 7 || $days_overdue >= 1) {
				$risk = ('critical' === $risk) ? 'critical' : 'warning';
			} elseif ($days_since_touch >= 3) {
				$risk = ('critical' === $risk) ? 'critical' : 'watch';
			}
		}

		if ($days_since_touch > 0) {
			$reasons[] = $days_since_touch . ' dias sin contacto';
		}
		if ($days_overdue > 0) {
			$reasons[] = $days_overdue . ' dias vencido';
		}

		return array(
			'lead_id' => $lead_id,
			'stage' => $stage,
			'is_client' => $is_client,
			'next_followup' => $next_followup,
			'last_touch' => $last_touch,
			'days_since_touch' => $days_since_touch,
			'days_overdue' => $days_overdue,
			'risk' => $risk,
			'reasons' => array_values(array_unique(array_filter($reasons))),
		);
	}

	private static function get_cooling_risk_board($today = '') {
		$today = $today ?: current_time('Y-m-d');
		$board = array(
			'lead_critical' => array(),
			'lead_warning' => array(),
			'lead_watch' => array(),
			'client_critical' => array(),
			'client_warning' => array(),
			'missing_next' => array(),
			'counts' => array(
				'lead_critical' => 0,
				'lead_warning' => 0,
				'lead_watch' => 0,
				'client_critical' => 0,
				'client_warning' => 0,
				'missing_next' => 0,
			),
		);

		$leads = self::get_active_leads(array('numberposts' => -1, 'orderby' => 'date', 'order' => 'DESC'));
		foreach ($leads as $lead) {
			if (self::is_operationally_archived_lead((int) $lead->ID, $today)) {
				continue;
			}
			$snapshot = self::lead_risk_snapshot((int) $lead->ID, $today);
			if (empty($snapshot)) {
				continue;
			}

			if (! $snapshot['next_followup']) {
				$board['missing_next'][] = $snapshot;
			}

			if (! empty($snapshot['is_client'])) {
				if ('critical' === $snapshot['risk']) {
					$board['client_critical'][] = $snapshot;
				} elseif ('warning' === $snapshot['risk']) {
					$board['client_warning'][] = $snapshot;
				}
				continue;
			}

			if ('critical' === $snapshot['risk']) {
				$board['lead_critical'][] = $snapshot;
			} elseif ('warning' === $snapshot['risk']) {
				$board['lead_warning'][] = $snapshot;
			} elseif ('watch' === $snapshot['risk']) {
				$board['lead_watch'][] = $snapshot;
			}
		}

		$sorter = function ($left, $right) {
			if (($left['days_since_touch'] ?? 0) !== ($right['days_since_touch'] ?? 0)) {
				return ($right['days_since_touch'] ?? 0) <=> ($left['days_since_touch'] ?? 0);
			}
			if (($left['days_overdue'] ?? 0) !== ($right['days_overdue'] ?? 0)) {
				return ($right['days_overdue'] ?? 0) <=> ($left['days_overdue'] ?? 0);
			}
			return strcmp((string) get_the_title((int) ($left['lead_id'] ?? 0)), (string) get_the_title((int) ($right['lead_id'] ?? 0)));
		};

		foreach (array('lead_critical', 'lead_warning', 'lead_watch', 'client_critical', 'client_warning', 'missing_next') as $bucket) {
			usort($board[$bucket], $sorter);
			$board['counts'][$bucket] = count($board[$bucket]);
		}

		return $board;
	}

	private static function render_interaction_history_item($interaction, $args = array()) {
		if (! ($interaction instanceof WP_Post) || 'crm_interaction' !== $interaction->post_type) {
			return;
		}

		$args = wp_parse_args($args, array(
			'open' => false,
			'show_lead' => true,
		));

		$lead_id = (int) get_post_meta($interaction->ID, '_crm_lead_id', true);
		$lead_title = $lead_id ? (string) get_the_title($lead_id) : 'Sin lead';
		$date = (string) get_post_meta($interaction->ID, '_crm_interaction_date', true);
		$channel = (string) get_post_meta($interaction->ID, '_crm_interaction_channel', true);
		$result = (string) get_post_meta($interaction->ID, '_crm_interaction_result', true);
		$stage = self::normalize_stage_key((string) get_post_meta($interaction->ID, '_crm_interaction_stage', true));
		$next = (string) get_post_meta($interaction->ID, '_crm_interaction_next_followup', true);
		$note = trim((string) get_post_meta($interaction->ID, '_crm_interaction_note', true));
		$kind = (string) get_post_meta($interaction->ID, '_crm_interaction_kind', true);
		$action = (string) get_post_meta($interaction->ID, '_crm_interaction_action', true);
		$lead_url = $lead_id ? (admin_url('admin.php?page=twob-crm-visual-leads&lead_id=' . $lead_id . '&q=' . rawurlencode($lead_title)) . '#lead-' . $lead_id) : '';
		$history_url = $lead_id ? admin_url('admin.php?page=twob-crm-visual-interactions&lead_id=' . $lead_id) : '';
		$action_label = self::interaction_action_label($action, $kind, $channel);
		$kind_labels = self::interaction_kind_labels();
		$summary_title = ! empty($args['show_lead']) ? $lead_title : $action_label;
		$summary_bits = array(
			$action_label,
			self::interaction_result_labels()[$result] ?? ucfirst(str_replace('_', ' ', $result)),
			self::stage_labels()[$stage] ?? ucfirst(str_replace('_', ' ', $stage)),
		);
		?>
		<details class="twob-timeline-item twob-interaction-detail" <?php echo ! empty($args['open']) ? 'open' : ''; ?>>
			<summary class="twob-detail-summary">
				<div>
					<strong><?php echo esc_html($summary_title); ?></strong>
					<div class="twob-line-2"><?php echo esc_html(implode(' | ', array_filter($summary_bits))); ?></div>
				</div>
				<div class="twob-line-2"><?php echo esc_html($date ?: substr((string) $interaction->post_date, 0, 10)); ?></div>
			</summary>
			<div class="twob-detail-body">
				<div class="twob-line-2">
					<?php
					echo esc_html(
						'Accion: ' . $action_label
						. ' | Tipo: ' . ($kind_labels[$kind] ?? ucfirst(str_replace('_', ' ', $kind)))
						. ' | Canal: ' . (self::channel_labels()[$channel] ?? ucfirst(str_replace('_', ' ', $channel)))
					);
					?>
				</div>
				<?php if ($note) : ?>
					<div class="twob-note-box"><?php echo nl2br(esc_html($note)); ?></div>
				<?php else : ?>
					<div class="twob-empty">Sin nota detallada en esta interaccion.</div>
				<?php endif; ?>
				<div class="twob-line-2">
					<?php echo esc_html('Registrada el ' . substr((string) $interaction->post_date, 0, 16)); ?>
					<?php if ($next) : ?>
						<?php echo esc_html(' | Proximo seguimiento: ' . $next); ?>
					<?php endif; ?>
				</div>
				<div class="twob-task-actions">
					<?php if ($lead_url && ! empty($args['show_lead'])) : ?><a class="button button-small" href="<?php echo esc_url($lead_url); ?>">Ver ficha del lead</a><?php endif; ?>
					<?php if ($history_url) : ?><a class="button button-small" href="<?php echo esc_url($history_url); ?>">Ver historial del cliente</a><?php endif; ?>
					<button class="button button-small twob-danger twob-delete-item" data-item-id="<?php echo esc_attr($interaction->ID); ?>" data-item-type="crm_interaction" data-item-label="<?php echo esc_attr($lead_title); ?>">Eliminar</button>
				</div>
			</div>
		</details>
		<?php
	}

