	private static function task_priority_weight($priority) {
		return match (sanitize_key((string) $priority)) {
			'high' => 3,
			'medium' => 2,
			'low' => 1,
			default => 0,
		};
	}

	private static function task_lead_score($task_id) {
		$lead_id = (int) get_post_meta((int) $task_id, '_crm_task_lead_id', true);
		return $lead_id ? self::lead_score($lead_id) : 0;
	}

	private static function compare_tasks_by_lead_score($left, $right) {
		$left_id = ($left instanceof WP_Post) ? (int) $left->ID : (int) $left;
		$right_id = ($right instanceof WP_Post) ? (int) $right->ID : (int) $right;
		$left_score = self::task_lead_score($left_id);
		$right_score = self::task_lead_score($right_id);
		if ($left_score !== $right_score) {
			return $right_score <=> $left_score;
		}

		$left_due = (string) get_post_meta($left_id, '_crm_task_due', true);
		$right_due = (string) get_post_meta($right_id, '_crm_task_due', true);
		if ($left_due !== $right_due) {
			return strcmp($left_due, $right_due);
		}

		$left_priority = self::task_priority_weight((string) get_post_meta($left_id, '_crm_task_priority', true));
		$right_priority = self::task_priority_weight((string) get_post_meta($right_id, '_crm_task_priority', true));
		if ($left_priority !== $right_priority) {
			return $right_priority <=> $left_priority;
		}

		$left_title = $left instanceof WP_Post ? (string) $left->post_title : (string) get_the_title($left_id);
		$right_title = $right instanceof WP_Post ? (string) $right->post_title : (string) get_the_title($right_id);
		return strcmp($left_title, $right_title);
	}

	private static function sort_tasks_by_lead_score(&$tasks) {
		if (count((array) $tasks) < 2) {
			return;
		}
		usort($tasks, array(__CLASS__, 'compare_tasks_by_lead_score'));
	}

	private static function get_dashboard_operational_tasks($today, $limit = 18) {
		$today = $today ?: current_time('Y-m-d');
		$limit = max(1, (int) $limit);
		$scope = self::current_crm_user_scope();

		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => max(60, $limit * 4),
			'meta_key' => '_crm_task_due',
			'orderby' => 'meta_value',
			'order' => 'ASC',
			'meta_query' => array(
				array('key' => '_crm_task_due', 'value' => $today, 'compare' => '<=', 'type' => 'DATE'),
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
		));
			$tasks = array_values(array_filter($tasks, function ($task) use ($scope) {
				return self::task_should_show_in_dashboard_actions((int) $task->ID)
					&& self::task_matches_current_scope((int) $task->ID, $scope);
			}));

		self::sort_tasks_by_lead_score($tasks);

		return array_slice($tasks, 0, $limit);
	}

