				<div class="twob-dashboard-task-pills">
					<span class="twob-pill <?php echo $is_overdue ? 'is-danger' : 'is-soft'; ?>"><?php echo esc_html($is_overdue ? 'Atrasada' : 'Hoy'); ?></span>
					<span class="twob-response-priority <?php echo esc_attr($priority_class); ?>"><?php echo esc_html(self::task_priority_labels()[$priority] ?? 'Media'); ?></span>
					<span class="twob-response-priority <?php echo esc_attr($effort_meta['class']); ?>">Personalizacion <?php echo esc_html($effort_meta['label']); ?></span>
				</div>
			</div>
			<div class="twob-dashboard-task-meta">
				<span class="twob-pill is-soft"><?php echo esc_html(self::task_type_labels()[$type] ?? 'Tarea'); ?></span>
				<span class="twob-pill is-soft"><?php echo esc_html($source_label); ?></span>
				<span class="twob-pill is-soft"><?php echo esc_html(self::task_status_labels()[$status] ?? 'Pendiente'); ?></span>
				<?php if ($due) : ?><span class="twob-pill is-soft">Vence: <?php echo esc_html($due); ?></span><?php endif; ?>
			</div>
			<?php if (! empty($task->post_content)) : ?><div class="twob-line-2"><?php echo esc_html($task->post_content); ?></div><?php endif; ?>
			<div class="twob-line-2">Nivel de personalizacion: <strong><?php echo esc_html($effort_meta['label']); ?></strong> | <?php echo esc_html($effort_meta['hint']); ?></div>
			<?php if (self::task_requires_guided_completion($task_id)) : ?><div class="twob-line-2">Esta tarea se cierra registrando la gestion que se hizo con el lead.</div><?php endif; ?>
			<?php if ($source_hint) : ?><div class="twob-line-2"><?php echo esc_html($source_hint); ?></div><?php endif; ?>
