				<button class="button button-small button-primary twob-task-status-btn" data-task-id="<?php echo esc_attr($task_id); ?>" data-task-status="done"<?php echo self::task_completion_button_data_attrs($task_id); ?>><?php echo esc_html(self::task_completion_button_label($task_id)); ?></button>
				<?php if (! empty($profile_link['url'])) : ?><a class="button button-small" href="<?php echo esc_url((string) $profile_link['url']); ?>" target="_blank" rel="noopener noreferrer">Abrir perfil</a><?php endif; ?>
