	private static function dashboard_initials($label) {
		$label = trim((string) $label);
		if ('' === $label) {
			return 'LD';
		}
		$words = preg_split('/\s+/', $label);
		$letters = '';
		foreach ((array) $words as $word) {
			$word = trim((string) $word);
			if ('' === $word) {
				continue;
			}
			$letters .= function_exists('mb_substr') ? mb_strtoupper(mb_substr($word, 0, 1)) : strtoupper(substr($word, 0, 1));
			if (strlen($letters) >= 2) {
				break;
			}
		}
		return $letters ?: 'LD';
	}

	private static function dashboard_lifecycle_summary($today = '') {
		$today = $today ?: current_time('Y-m-d');
		$leads = get_posts(array(
			'post_type' => 'crm_lead',
			'post_status' => 'publish',
			'numberposts' => -1,
			'orderby' => 'date',
			'order' => 'DESC',
		));

		$counts = array(
			'new' => 0,
			'tracking' => 0,
			'interested' => 0,
			'pending' => 0,
			'closed' => 0,
		);

		foreach ($leads as $lead) {
			$lead_id = (int) $lead->ID;
			$lifecycle_state = self::lead_lifecycle_state($lead_id, $today);
			if (! isset($counts[$lifecycle_state])) {
				continue;
			}
			$counts[$lifecycle_state]++;
		}

		return $counts;
	}

	private static function dashboard_week_meetings($today = '', $limit = 6) {
		$today = $today ?: current_time('Y-m-d');
		$week_end = date('Y-m-d', strtotime($today . ' +7 days'));
		return get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => max(1, (int) $limit),
			'meta_key' => '_crm_task_due',
			'orderby' => 'meta_value',
			'order' => 'ASC',
			'meta_query' => array(
				array('key' => '_crm_task_due', 'value' => array($today, $week_end), 'compare' => 'BETWEEN', 'type' => 'DATE'),
				array('key' => '_crm_task_type', 'value' => 'meeting', 'compare' => '='),
			),
		));
	}

