	private static function dashboard_today_meetings($today = '', $limit = 3) {
		$today = $today ?: current_time('Y-m-d');
		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => max(1, (int) $limit),
			'meta_key' => '_crm_task_start_time',
			'orderby' => 'meta_value',
			'order' => 'ASC',
			'meta_query' => array(
				array('key' => '_crm_task_due', 'value' => $today, 'compare' => '='),
				array('key' => '_crm_task_type', 'value' => 'meeting', 'compare' => '='),
			),
		));
		$scope = self::current_crm_user_scope();
		$tasks = array_values(array_filter($tasks, function ($task) use ($scope) {
			return self::task_matches_current_scope((int) $task->ID, $scope);
		}));
		return array_slice($tasks, 0, max(1, (int) $limit));
	}

	private static function dashboard_renata_queue_bucket($lead_id, $today = '', $cutoff_day = '') {
		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		$cutoff_day = $cutoff_day ?: date('Y-m-d', strtotime($today . ' -2 days'));
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return '';
		}

		$lifecycle_state = self::lead_lifecycle_state($lead_id, $today);
		if ('closed' === $lifecycle_state) {
			return '';
		}

		$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		$operational_status = self::determine_operational_status($lead_id, $today);
		$service_interest = (string) get_post_meta($lead_id, '_crm_service_interest', true);

		if (self::is_pre_contact_stage($stage)) {
			return 'review';
		}

		// Prioridad 1: el diagnostico en curso vive en su propia cola.
		if (self::is_diagnostic_service($service_interest) && 'proposal_sent' === $stage) {
			return 'diagnostic';
		}

		// Prioridad 2: si ya hay reunion, Renata debe preparar esa instancia.
		if (in_array($stage, array('meeting_scheduled', 'meeting_done'), true)) {
			return 'meeting';
		}

		// Prioridad 3: diagnosticos que ya respondieron o quedaron como interesados.
		if (self::is_diagnostic_service($service_interest) && ('responded_interested' === $stage || 'interested' === $operational_status)) {
			return 'diagnostic';
		}

		return '';
	}

	private static function dashboard_renata_queues($today = '', $limit = 10) {
		static $cache = array();

		$today = $today ?: current_time('Y-m-d');
		$limit = max(1, (int) $limit);
		$cache_key = $today . '|' . $limit;
		if (isset($cache[$cache_key])) {
			return $cache[$cache_key];
		}

		$cutoff_day = date('Y-m-d', strtotime($today . ' -2 days'));
		$queues = array(
			'review' => array(),
			'meeting' => array(),
			'diagnostic' => array(),
		);
		$leads = self::get_active_leads(array(
			'numberposts' => -1,
			'orderby' => 'date',
			'order' => 'DESC',
		));

		foreach ($leads as $lead) {
			if (
				count($queues['review']) >= $limit
				&& count($queues['meeting']) >= $limit
				&& count($queues['diagnostic']) >= $limit
			) {
				break;
			}
			if (! ($lead instanceof WP_Post)) {
				continue;
			}

			$bucket = self::dashboard_renata_queue_bucket((int) $lead->ID, $today, $cutoff_day);
			if (! $bucket || count($queues[$bucket]) >= $limit) {
				continue;
			}
			$queues[$bucket][] = $lead;
		}

		$cache[$cache_key] = $queues;
		return $cache[$cache_key];
	}

	private static function dashboard_renata_review_queue($today = '', $limit = 10) {
		$queues = self::dashboard_renata_queues($today, $limit);
		return $queues['review'] ?? array();
	}

	private static function dashboard_renata_meeting_prep_queue($today = '', $limit = 10) {
		$queues = self::dashboard_renata_queues($today, $limit);
		return $queues['meeting'] ?? array();
	}

	private static function dashboard_renata_diagnostic_queue($today = '', $limit = 10) {
		$queues = self::dashboard_renata_queues($today, $limit);
		return $queues['diagnostic'] ?? array();
	}

	public static function daily_plan_renata_live_data($today = '', $limit = 10) {
		$today = $today ?: current_time('Y-m-d');
		$queues = self::dashboard_renata_queues($today, $limit);
		$review_items = self::daily_plan_serialize_renata_review_queue($queues['review'] ?? array());
		$dani_ready = array();
		$dani_waiting = array();

		foreach ($review_items as $item) {
			if (! empty($item['hasFinding'])) {
				$dani_ready[] = $item;
			} else {
				$dani_waiting[] = $item;
			}
		}

		return array(
			'review' => $review_items,
			'meeting' => self::daily_plan_serialize_renata_meeting_queue($queues['meeting'] ?? array()),
			'diagnostic' => self::daily_plan_serialize_renata_diagnostic_queue($queues['diagnostic'] ?? array(), $today),
			'dani_ready' => array_values($dani_ready),
			'dani_waiting' => array_values($dani_waiting),
			'reactivation_prepare' => self::serialize_reactivation_prepare_queue(self::reactivation_prepare_queue($today, 5)),
			'reactivation_tasks' => self::serialize_reactivation_due_tasks(self::reactivation_due_tasks($today, 5)),
		);
	}

