	private static function task_supports_ai_generation($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return false;
		}

		if (self::is_reactivation_task($task_id)) {
			return true;
		}

		$sequence_slug = self::task_sequence_step_slug($task_id);
		if (in_array($sequence_slug, array('day3_linkedin_followup', 'day7_email', 'day10_last_linkedin', 'day12_clean_close'), true)) {
			return true;
		}

		$auto_key = strtolower((string) get_post_meta($task_id, '_crm_auto_key', true));
		$title = strtolower((string) get_the_title($task_id));
		foreach (array('d3', 'd7', 'd10', 'd12', 'day3', 'day7', 'day10', 'day12') as $needle) {
			if (false !== strpos($auto_key, $needle) || false !== strpos($title, $needle)) {
				return true;
			}
		}

		return false;
	}

	private static function task_ai_message_type($task_id, $explicit_type = '') {
		$explicit_type = sanitize_key((string) $explicit_type);
		if ($explicit_type) {
			return $explicit_type;
		}

		$task_id = (int) $task_id;
		if (self::is_reactivation_task($task_id)) {
			$channel = self::reactivation_task_channel($task_id);
			return match ($channel) {
				'email' => 'reactivacion_email',
				'formulario' => 'reactivacion_formulario',
				'telefono' => 'reactivacion_telefono',
				'instagram' => 'reactivacion_instagram',
				'facebook' => 'reactivacion_facebook',
				'meeting' => 'reactivacion_reunion',
				default => 'reactivacion',
			};
		}

		$sequence_slug = self::task_sequence_step_slug($task_id);
		return match ($sequence_slug) {
			'day3_linkedin_followup' => 'd3',
			'day7_email' => 'd7',
			'day10_last_linkedin' => 'd10',
			'day12_clean_close' => 'd12',
			default => 'seguimiento',
		};
	}

	private static function task_ai_cycle_label($task_id, $message_type = '') {
		$message_type = sanitize_key((string) ($message_type ?: self::task_ai_message_type((int) $task_id)));
		return match ($message_type) {
			'd3' => 'D3',
			'd7' => 'D7',
			'd10' => 'D10',
			'd12' => 'D12',
			default => strtoupper(str_replace('_', ' ', $message_type)),
		};
	}

	private static function task_ai_history_text($lead_id, $limit = 5) {
		$lead_id = (int) $lead_id;
		$items = get_posts(array(
			'post_type' => 'crm_interaction',
			'post_status' => 'publish',
			'posts_per_page' => max(1, (int) $limit),
			'orderby' => 'date',
			'order' => 'DESC',
			'meta_query' => array(
				array('key' => '_crm_lead_id', 'value' => $lead_id),
			),
		));

		if (empty($items)) {
			return 'Sin contacto previo registrado';
		}

		$lines = array();
		foreach ($items as $item) {
			$kind = trim((string) get_post_meta($item->ID, '_crm_interaction_kind', true));
			$action = trim((string) get_post_meta($item->ID, '_crm_interaction_action', true));
			$note = trim((string) get_post_meta($item->ID, '_crm_interaction_note', true));
			$date = trim((string) get_post_meta($item->ID, '_crm_interaction_date', true));
			$segments = array_filter(array(
				$date,
				$kind ? ucfirst(str_replace('_', ' ', $kind)) : '',
				$action ? str_replace('_', ' ', $action) : '',
				$note,
			));
			if (! empty($segments)) {
				$lines[] = implode(': ', array_slice($segments, 0, 2)) . (count($segments) > 2 ? ' — ' . implode(' · ', array_slice($segments, 2)) : '');
			}
		}

		return ! empty($lines) ? implode("\n", $lines) : 'Sin contacto previo registrado';
	}

	private static function lead_ai_role($lead_id) {
		$lead_id = (int) $lead_id;
		$candidates = array(
			(string) get_post_meta($lead_id, 'cargo', true),
			(string) get_post_meta($lead_id, '_crm_cargo', true),
			(string) get_post_meta($lead_id, '_crm_role', true),
			(string) get_post_meta($lead_id, '_crm_job_title', true),
		);
		foreach ($candidates as $candidate) {
			$candidate = trim((string) $candidate);
			if ('' !== $candidate) {
				return $candidate;
			}
		}
		return '';
	}

	private static function task_ai_prompt($lead_id, $task_id, $message_type = '') {
		$lead_id = (int) $lead_id;
		$task_id = (int) $task_id;
		$message_type = self::task_ai_message_type($task_id, $message_type);
		$nombre = self::lead_contact_name($lead_id);
		$empresa = get_the_title($lead_id);
		$cargo = self::lead_ai_role($lead_id);
		$url = trim((string) get_post_meta($lead_id, '_crm_website_url', true));
		$canal = self::channel_labels()[sanitize_key((string) get_post_meta($lead_id, '_crm_origin_channel', true))] ?? 'Sin canal';
		$hallazgo = trim((string) get_post_meta($lead_id, '_crm_technical_finding', true));
		$linkedin = trim((string) get_post_meta($lead_id, '_crm_linkedin_person', true));
		$sector_key = sanitize_key((string) get_post_meta($lead_id, '_crm_client_type', true));
		$sector = self::settings_get()['client_types'][$sector_key] ?? ($sector_key ?: 'No especificado');
		$servicio_key = sanitize_key((string) get_post_meta($lead_id, '_crm_service_interest', true));
		$servicio = self::service_interest_options_for_select($servicio_key)[$servicio_key] ?? ($servicio_key ?: 'No definido');
		$temperatura = self::temperature_labels()[self::lead_temperature($lead_id)] ?? 'Tibio';
		$dia_ciclo = self::task_ai_cycle_label($task_id, $message_type);
		$tipo_tarea = sanitize_key((string) get_post_meta($task_id, '_crm_task_type', true));
		$historial_txt = self::task_ai_history_text($lead_id, 5);
		$outbound_channel = self::task_effective_outbound_channel($task_id, $lead_id, $tipo_tarea);
		$outbound_channel_label = self::channel_labels()[$outbound_channel] ?? ucfirst((string) $outbound_channel);

		return TwoB_CRM_Dani_Message_Engine_Module::build_task_prompt(array(
			'nombre' => $nombre,
			'empresa' => $empresa,
			'cargo' => $cargo,
			'url' => $url,
			'sector' => $sector,
			'canal' => $canal,
			'outbound_channel' => $outbound_channel_label,
			'hallazgo' => $hallazgo,
			'linkedin' => $linkedin,
			'servicio' => $servicio,
			'temperatura' => $temperatura,
			'dia_ciclo' => $dia_ciclo,
			'historial' => $historial_txt,
			'message_type' => $message_type,
		));
	}

	private static function anthropic_request_message($prompt, $api_key = '', $max_tokens = 400) {
		$resolved_key = '' !== trim((string) $api_key) ? trim((string) $api_key) : self::anthropic_api_key_get();
		return TwoB_CRM_Dani_Message_Engine_Module::request_message($prompt, $resolved_key, $max_tokens);
	}

	private static function generate_ai_message_for_task($task_id, $lead_id = 0, $message_type = '') {
		$task_id = (int) $task_id;
		$lead_id = $lead_id ? (int) $lead_id : (int) get_post_meta($task_id, '_crm_task_lead_id', true);
		$task = self::get_valid_crm_post($task_id, 'crm_task');
		$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
		if (! $task || ! $lead) {
			return new WP_Error('invalid_task_or_lead', 'No se pudo identificar la tarea o el lead.');
		}
		if (! self::current_user_can_edit_crm_post($task_id) || ! self::current_user_can_edit_crm_post($lead_id)) {
			return new WP_Error('forbidden', 'No tienes permisos para generar este mensaje.');
		}
		if (! self::task_supports_ai_generation($task_id)) {
			return new WP_Error('unsupported_task', 'Esta tarea no usa generación personalizada con IA.');
		}

		$message_type = self::task_ai_message_type($task_id, $message_type);
		$prompt = self::task_ai_prompt($lead_id, $task_id, $message_type);
		$message = self::anthropic_request_message($prompt);
		if (is_wp_error($message)) {
			return $message;
		}

		update_post_meta($task_id, 'twob_task_mensaje_ia', $message);
		update_post_meta($task_id, 'twob_task_mensaje_ia_fecha', (int) current_time('timestamp'));
		update_post_meta($task_id, 'twob_task_mensaje_ia_tipo', $message_type);

		return array(
			'mensaje' => $message,
			'message_type' => $message_type,
			'task_id' => $task_id,
			'lead_id' => $lead_id,
			'generated_at' => (int) current_time('timestamp'),
		);
	}

	private static function lead_pending_ai_task_ids($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return array();
		}
		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => -1,
			'meta_query' => array(
				'relation' => 'AND',
				array('key' => '_crm_task_lead_id', 'value' => $lead_id),
				array('key' => '_crm_task_status', 'value' => array('pending', 'open', 'todo'), 'compare' => 'IN'),
			),
		));

		$eligible = array();
		foreach ($tasks as $task) {
			if (self::task_supports_ai_generation((int) $task->ID)) {
				$eligible[] = (int) $task->ID;
			}
		}

		return array_values(array_unique(array_filter($eligible)));
	}

	private static function user_can_run_site_scan() {
		return current_user_can('manage_options') || current_user_can('edit_others_posts') || self::user_can_manage_settings();
	}

	private static function lead_contact_name($lead_id) {
		$lead_id = (int) $lead_id;
		$candidates = array(
			(string) get_post_meta($lead_id, 'nombre_contacto', true),
			(string) get_post_meta($lead_id, '_crm_nombre_contacto', true),
			(string) get_post_meta($lead_id, '_crm_contact_name', true),
			(string) get_the_title($lead_id),
		);

		foreach ($candidates as $candidate) {
			$candidate = trim((string) $candidate);
			if ('' !== $candidate) {
				return $candidate;
			}
		}

		return '';
	}

	private static function elapsed_label_from_unix($timestamp) {
		$timestamp = (int) $timestamp;
		if ($timestamp <= 0) {
			return '';
		}

		$now = (int) current_time('timestamp');
		if ($timestamp >= $now) {
			return 'hace un momento';
		}

		return 'hace ' . human_time_diff($timestamp, $now);
	}

	private static function normalize_scan_url($raw_url) {
		$url = trim((string) $raw_url);
		if ('' === $url) {
			return new WP_Error('empty_url', 'Ingresa una URL para escanear.');
		}

		if (! preg_match('#^https?://#i', $url)) {
			$url = 'https://' . ltrim($url, '/');
		}

		$url = esc_url_raw($url);
		if (! $url) {
			return new WP_Error('invalid_url', 'La URL no es valida.');
		}

		$parts = wp_parse_url($url);
		$host = strtolower((string) ($parts['host'] ?? ''));
		if ('' === $host) {
			return new WP_Error('invalid_host', 'No se pudo detectar el dominio del sitio.');
		}

		return array(
			'url' => $url,
			'host' => $host,
			'dns_domain' => preg_replace('/^www\./', '', $host),
		);
	}

	private static function response_final_url($response) {
		if (is_array($response) && isset($response['http_response']) && is_object($response['http_response']) && method_exists($response['http_response'], 'get_response_object')) {
			$response_object = $response['http_response']->get_response_object();
			if (is_object($response_object) && ! empty($response_object->url)) {
				return (string) $response_object->url;
			}
		}

		$location = wp_remote_retrieve_header($response, 'location');
		return is_string($location) ? $location : '';
	}

	private static function pagespeed_request($url, $strategy, $api_key = '') {
		$query_args = array(
			'url' => $url,
			'strategy' => $strategy,
		);
		if ('' !== trim((string) $api_key)) {
			$query_args['key'] = trim((string) $api_key);
		}

		$endpoint = add_query_arg($query_args, 'https://www.googleapis.com/pagespeedonline/v5/runPagespeed');
		$response = wp_remote_get($endpoint, array(
			'timeout' => 30,
			'redirection' => 3,
		));
		if (is_wp_error($response)) {
			return new WP_Error('pagespeed_request_failed', $response->get_error_message());
		}

		$code = (int) wp_remote_retrieve_response_code($response);
		if ($code < 200 || $code >= 300) {
			$body = trim((string) wp_remote_retrieve_body($response));
			if (strlen($body) > 220) {
				$body = substr($body, 0, 220) . '...';
			}
			return new WP_Error('pagespeed_http_' . $code, $body ? $body : ('La API respondio con estado ' . $code . '.'));
		}

		$data = json_decode((string) wp_remote_retrieve_body($response), true);
		if (! is_array($data)) {
			return new WP_Error('pagespeed_invalid_json', 'La respuesta de PageSpeed no pudo leerse.');
		}

		return $data;
	}

	private static function pagespeed_score_from_response($data) {
		$score = $data['lighthouseResult']['categories']['performance']['score'] ?? null;
		if (! is_numeric($score)) {
			return 0;
		}

		return (int) round(((float) $score) * 100);
	}

	private static function pagespeed_audit_below_threshold($data, $audit_key, $threshold) {
		$score = $data['lighthouseResult']['audits'][$audit_key]['score'] ?? null;
		return is_numeric($score) ? ((float) $score) < (float) $threshold : false;
	}

	private static function scan_site_payload($raw_url, $api_key = '') {
		$normalized = self::normalize_scan_url($raw_url);
		if (is_wp_error($normalized)) {
			return $normalized;
		}

		$payload = array(
			'url' => $normalized['url'],
			'domain' => $normalized['dns_domain'],
			'speed_mobile' => 0,
			'speed_desktop' => 0,
			'ssl_ok' => false,
			'https_redirect' => false,
			'spf_ok' => false,
			'dkim_ok' => false,
			'dmarc_ok' => false,
			'auto_checks' => array(
				'speed_mobile_slow' => false,
				'speed_desktop_slow' => false,
				'images_heavy' => false,
				'no_cache' => false,
				'no_https' => false,
				'ssl_expired' => false,
				'dkim_missing' => false,
				'spf_missing' => false,
				'dmarc_missing' => false,
				'no_meta' => false,
				'no_h1' => false,
				'errors_404' => false,
			),
			'errors' => array(),
		);

		$api_key = '' !== trim((string) $api_key) ? trim((string) $api_key) : self::pagespeed_api_key_get();
		$mobile = self::pagespeed_request($normalized['url'], 'mobile', $api_key);
		if (is_wp_error($mobile)) {
			$payload['errors'][] = 'PageSpeed móvil: ' . $mobile->get_error_message();
		} else {
			$payload['speed_mobile'] = self::pagespeed_score_from_response($mobile);
			$payload['auto_checks']['speed_mobile_slow'] = $payload['speed_mobile'] > 0 && $payload['speed_mobile'] < 50;
			$payload['auto_checks']['images_heavy'] = self::pagespeed_audit_below_threshold($mobile, 'uses-optimized-images', 0.9);
			$payload['auto_checks']['no_cache'] = self::pagespeed_audit_below_threshold($mobile, 'uses-long-cache-ttl', 0.9);
			$payload['auto_checks']['no_https'] = self::pagespeed_audit_below_threshold($mobile, 'is-on-https', 1);
			$payload['auto_checks']['errors_404'] = self::pagespeed_audit_below_threshold($mobile, 'crawlable-anchors', 0.9);
			$payload['auto_checks']['no_meta'] = self::pagespeed_audit_below_threshold($mobile, 'meta-description', 1);
			$payload['auto_checks']['no_h1'] = self::pagespeed_audit_below_threshold($mobile, 'document-title', 1);
		}

		$desktop = self::pagespeed_request($normalized['url'], 'desktop', $api_key);
		if (is_wp_error($desktop)) {
			$payload['errors'][] = 'PageSpeed escritorio: ' . $desktop->get_error_message();
		} else {
			$payload['speed_desktop'] = self::pagespeed_score_from_response($desktop);
			$payload['auto_checks']['speed_desktop_slow'] = $payload['speed_desktop'] > 0 && $payload['speed_desktop'] < 60;
		}

		$ssl_response = wp_remote_get('https://' . $normalized['host'], array(
			'timeout' => 10,
			'sslverify' => true,
			'redirection' => 3,
		));
		$payload['ssl_ok'] = ! is_wp_error($ssl_response);
		$payload['auto_checks']['ssl_expired'] = ! $payload['ssl_ok'];
		if (is_wp_error($ssl_response)) {
			$payload['errors'][] = 'SSL/HTTPS: ' . $ssl_response->get_error_message();
		}

		$redirect_response = wp_remote_get('http://' . $normalized['host'], array(
			'timeout' => 10,
			'redirection' => 5,
			'sslverify' => false,
		));
		if (is_wp_error($redirect_response)) {
			$payload['errors'][] = 'Redirección HTTP→HTTPS: ' . $redirect_response->get_error_message();
		} else {
			$final_url = self::response_final_url($redirect_response);
			if ('' === $final_url) {
				$final_url = 'http://' . $normalized['host'];
			}
			$payload['https_redirect'] = 0 === stripos($final_url, 'https://');
		}
		$payload['auto_checks']['no_https'] = ! $payload['https_redirect'] || ! empty($payload['auto_checks']['no_https']);

		if (function_exists('dns_get_record')) {
			$txt_records = @dns_get_record($normalized['dns_domain'], DNS_TXT);
			if (is_array($txt_records)) {
				foreach ($txt_records as $record) {
					$txt_value = strtolower((string) ($record['txt'] ?? ($record['entries'][0] ?? '')));
					if (false !== strpos($txt_value, 'v=spf1')) {
						$payload['spf_ok'] = true;
						break;
					}
				}
			}

			$dkim_default = @dns_get_record('default._domainkey.' . $normalized['dns_domain'], DNS_TXT);
			$dkim_mail = @dns_get_record('mail._domainkey.' . $normalized['dns_domain'], DNS_TXT);
			$payload['dkim_ok'] = ! empty($dkim_default) || ! empty($dkim_mail);

			$dmarc = @dns_get_record('_dmarc.' . $normalized['dns_domain'], DNS_TXT);
			$payload['dmarc_ok'] = ! empty($dmarc);
		} else {
			$payload['errors'][] = 'dns_get_record no está disponible en este servidor.';
		}

		$payload['auto_checks']['spf_missing'] = ! $payload['spf_ok'];
		$payload['auto_checks']['dkim_missing'] = ! $payload['dkim_ok'];
		$payload['auto_checks']['dmarc_missing'] = ! $payload['dmarc_ok'];

		return $payload;
	}

	private static function lead_site_review_snapshot($lead_id) {
		$lead_id = (int) $lead_id;
		$technical_finding = trim((string) get_post_meta($lead_id, '_crm_technical_finding', true));
		$scan_timestamp = (int) get_post_meta($lead_id, 'twob_scan_fecha', true);
		$site_status = sanitize_key((string) get_post_meta($lead_id, 'twob_estado_sitio', true));
		$critical_count = max(0, (int) get_post_meta($lead_id, 'twob_scan_critical_count', true));
		$high_count = max(0, (int) get_post_meta($lead_id, 'twob_scan_high_count', true));
		$medium_count = max(0, (int) get_post_meta($lead_id, 'twob_scan_medium_count', true));
		$speed_mobile = (int) get_post_meta($lead_id, 'twob_speed_mobile', true);
		$speed_desktop = (int) get_post_meta($lead_id, 'twob_speed_desktop', true);
		$auto_checks = get_post_meta($lead_id, 'twob_scan_auto_checks', true);
		$auto_checks = is_array($auto_checks) ? $auto_checks : array();
		$scan_errors = get_post_meta($lead_id, 'twob_scan_errors', true);
		$scan_errors = is_array($scan_errors) ? $scan_errors : array();

		$snapshot = array(
			'mode' => 'unscanned',
			'label' => '⚪ Sin escanear',
			'description' => 'Todavía no hay revisión guardada para este lead.',
			'button_label' => 'Iniciar revisión técnica',
			'class' => 'is-unscanned',
			'scan_timestamp' => $scan_timestamp,
			'scan_label' => self::elapsed_label_from_unix($scan_timestamp),
			'site_status' => $site_status,
			'critical_count' => $critical_count,
			'high_count' => $high_count,
			'medium_count' => $medium_count,
			'speed_mobile' => $speed_mobile,
			'speed_desktop' => $speed_desktop,
			'auto_checks' => $auto_checks,
			'errors' => $scan_errors,
		);

		if ($scan_timestamp > 0) {
			$status_labels = array(
				'critico' => '🔴 Crítico',
				'moderado' => '🟠 Moderado',
				'leve' => '🔵 Leve',
				'ok' => '🟢 OK',
			);
			$snapshot['mode'] = 'scanned';
			$snapshot['label'] = $status_labels[$site_status] ?? '🟢 Revisado';
			$snapshot['class'] = 'is-' . ($site_status ?: 'ok');
			$snapshot['button_label'] = 'Abrir revisión técnica';

			$pieces = array();
			if ($critical_count > 0) {
				$pieces[] = $critical_count . ' críticos';
			}
			if ($high_count > 0) {
				$pieces[] = $high_count . ' altos';
			}
			if ($medium_count > 0) {
				$pieces[] = $medium_count . ' medios';
			}
			if (empty($pieces)) {
				$pieces[] = 'sin hallazgos críticos visibles';
			}
			if ($snapshot['scan_label']) {
				$pieces[] = 'Escaneado ' . $snapshot['scan_label'];
			}
			$snapshot['description'] = implode(' · ', $pieces);
			return $snapshot;
		}

		if ('' !== $technical_finding) {
			$snapshot['mode'] = 'manual';
			$snapshot['label'] = '✏️ Hallazgo manual registrado';
			$snapshot['description'] = 'Hay contexto técnico cargado, pero no se guardó desde el revisor embebido.';
			$snapshot['button_label'] = 'Abrir revisión técnica';
			$snapshot['class'] = 'is-manual';
		}

		return $snapshot;
	}

	public static function save_lead_technical_finding($lead_id, $technical_finding, $reviewed_at = '', $scan_meta = array()) {
		$lead_id = (int) $lead_id;
		$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
		if (! $lead) {
			return new WP_Error('invalid_lead', 'Lead invalido.');
		}

		if (! self::current_user_can_edit_crm_post($lead_id)) {
			return new WP_Error('forbidden', 'No tienes permisos para editar este lead.');
		}

		$technical_finding = sanitize_textarea_field((string) $technical_finding);
		if ('' === trim($technical_finding)) {
			return new WP_Error('finding_required', 'Escribe un hallazgo antes de guardar.');
		}

		update_post_meta($lead_id, '_crm_technical_finding', $technical_finding);
		update_post_meta($lead_id, '_crm_technical_reviewed_at', $reviewed_at ?: current_time('mysql'));
		if (! empty($scan_meta) && is_array($scan_meta)) {
			$scan_timestamp = isset($scan_meta['scan_timestamp']) ? max(0, (int) $scan_meta['scan_timestamp']) : (int) current_time('timestamp');
			$site_status = sanitize_key((string) ($scan_meta['site_status'] ?? ''));
			$allowed_statuses = array('critico', 'moderado', 'leve', 'ok');
			if (! in_array($site_status, $allowed_statuses, true)) {
				$site_status = 'ok';
			}
			$auto_checks = isset($scan_meta['auto_checks']) && is_array($scan_meta['auto_checks']) ? array_map('rest_sanitize_boolean', $scan_meta['auto_checks']) : array();
			$scan_errors = isset($scan_meta['errors']) && is_array($scan_meta['errors']) ? array_map('sanitize_text_field', $scan_meta['errors']) : array();

			update_post_meta($lead_id, 'twob_speed_mobile', max(0, (int) ($scan_meta['speed_mobile'] ?? 0)));
			update_post_meta($lead_id, 'twob_speed_desktop', max(0, (int) ($scan_meta['speed_desktop'] ?? 0)));
			update_post_meta($lead_id, 'twob_estado_sitio', $site_status);
			update_post_meta($lead_id, 'twob_scan_fecha', $scan_timestamp);
			update_post_meta($lead_id, 'twob_scan_critical_count', max(0, (int) ($scan_meta['critical_count'] ?? 0)));
			update_post_meta($lead_id, 'twob_scan_high_count', max(0, (int) ($scan_meta['high_count'] ?? 0)));
			update_post_meta($lead_id, 'twob_scan_medium_count', max(0, (int) ($scan_meta['medium_count'] ?? 0)));
			update_post_meta($lead_id, 'twob_scan_auto_checks', $auto_checks);
			update_post_meta($lead_id, 'twob_scan_errors', $scan_errors);
		}
		self::sync_lead_technical_finding_context($lead_id);
		self::update_lead_score($lead_id);

		return array(
			'lead_id' => $lead_id,
			'technical_finding' => $technical_finding,
			'scan_meta' => $scan_meta,
		);
	}

	public static function activate_precontact_lead($lead_id, $today = '', $first_contact_channel = '') {
		$lead_id = (int) $lead_id;
		$today = $today ?: current_time('Y-m-d');
		$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
		if (! $lead) {
			return new WP_Error('invalid_lead', 'Lead invalido.');
		}
		if (! self::current_user_can_edit_crm_post($lead_id)) {
			return new WP_Error('forbidden', 'No tienes permisos para activar este lead.');
		}

		$current_stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		if (! self::is_pre_contact_stage($current_stage)) {
			return new WP_Error('not_precontact', 'Este lead ya no esta en Pre-contacto.');
		}

		$origin_channel = sanitize_key((string) get_post_meta($lead_id, '_crm_origin_channel', true));
		$sequence_policy = self::sequence_policy_for_origin_channel($origin_channel);
		$first_contact_channel = self::sanitize_interaction_channel($first_contact_channel ?: $origin_channel ?: 'linkedin');
		if (! isset(self::first_contact_channel_labels()[$first_contact_channel])) {
			$first_contact_channel = 'linkedin';
		}

		$existing_interaction = self::lead_has_logged_interaction($lead_id);
		if (! $existing_interaction) {
			$interaction_id = wp_insert_post(array(
				'post_type' => 'crm_interaction',
				'post_status' => 'publish',
				'post_title' => 'Contacto: ' . wp_strip_all_tags(get_the_title($lead_id)),
				'meta_input' => array(
					'_crm_interaction_kind' => 'contact',
					'_crm_lead_id' => $lead_id,
					'_crm_interaction_date' => $today,
					'_crm_interaction_channel' => $first_contact_channel,
					'_crm_interaction_action' => self::normalize_interaction_action('', 'contact', $first_contact_channel),
					'_crm_interaction_result' => 'other',
					'_crm_interaction_stage' => 'contacted',
					'_crm_interaction_next_followup' => '',
					'_crm_interaction_note' => 'Primer contacto registrado al activar lead desde Pre-contacto.',
				),
			));
			if (! $interaction_id || is_wp_error($interaction_id)) {
				return new WP_Error('interaction_failed', 'No se pudo registrar el primer contacto del lead.');
			}
		}

		update_post_meta($lead_id, '_crm_sequence_policy', $sequence_policy);
		update_post_meta($lead_id, '_crm_sequence_policy_version', self::SEQUENCE_POLICY_VERSION);
		update_post_meta($lead_id, '_crm_first_contacted_at', current_time('mysql'));
		update_post_meta($lead_id, '_crm_first_contact_channel', $first_contact_channel);

		$stage_result = self::set_lead_stage($lead_id, 'contacted', 'precontact_activation');
		if (is_wp_error($stage_result)) {
			return $stage_result;
		}

		$first_followup = '';
		if ('manual' !== $sequence_policy) {
			$first_followup = self::add_chile_business_days($today, 3);
			self::set_lead_next_followup_meta($lead_id, $first_followup, 'Seguimiento primer contacto');
			$day3_step = self::lead_followup_step_by_slug('day3_linkedin_followup');
			if (! empty($day3_step)) {
				self::create_auto_task_once(
					$lead_id,
					(string) $day3_step['title'] . wp_strip_all_tags(get_the_title($lead_id)),
					(string) $day3_step['type'],
					(string) $day3_step['priority'],
					$first_followup,
					'lead_sequence_' . $lead_id . '_day3_linkedin_followup',
					array(
						'description' => self::sequence_task_description_for_lead($lead_id, (string) $day3_step['description']),
					)
				);
			}
		} else {
			self::set_lead_next_followup_meta($lead_id, '');
		}

		self::update_temperature($lead_id);
		self::update_operational_status($lead_id, $today);
		self::sync_master_client_for_lead($lead_id);
		self::maybe_google_sync_followup_for_current_user($lead_id);

		return array(
			'lead_id' => $lead_id,
			'sequence_policy' => $sequence_policy,
			'next_followup' => $first_followup,
		);
	}

