	private static function reactivation_call_script($lead_id) {
		$lead_id = (int) $lead_id;
		$company = trim((string) get_post_meta($lead_id, '_crm_company', true)) ?: get_the_title($lead_id);
		return "Buenos días, soy Dani de 2B Consulting.\nNecesito enviar información técnica sobre\nel sitio web de {$company} al gerente general\no al responsable de tecnología.\n¿Me puede dar su email directo o indicarme\ncómo contactarlo?";
	}

	private static function reactivation_email_subject($lead_id) {
		return 'Te escribí por LinkedIn — algo importante cambió';
	}

	private static function reactivation_email_message($lead_id) {
		$lead_id = (int) $lead_id;
		$nombre = self::lead_contact_name($lead_id);
		$url = trim((string) get_post_meta($lead_id, '_crm_website_url', true));
		$hallazgo = trim((string) get_post_meta($lead_id, '_crm_technical_finding', true));
		$company = trim((string) get_post_meta($lead_id, '_crm_company', true)) ?: get_the_title($lead_id);
		return "Hola {$nombre},\n\nTe contacté hace unas semanas por LinkedIn\nsobre un punto técnico que encontré en {$url}.\n\nQuería intentarlo por este medio porque desde\nentonces restructuramos completamente nuestra\noferta: el diagnóstico bajó de \$700.000\na \$350.000 + IVA.\n\nLo que encontramos en el sitio de {$company}:\n{$hallazgo}\n\nEsto puede estar afectando directamente\nlos resultados del negocio.\n\n¿Tiene 20 minutos esta semana para que le\nmuestre el diagnóstico completo?\n\nDani Guerrero\n2B Consulting · 2bconsulting.cl";
	}

	private static function reactivation_form_message($lead_id) {
		$config = self::reactivation_contact_config();
		$company = trim((string) get_post_meta((int) $lead_id, '_crm_company', true)) ?: get_the_title((int) $lead_id);
		return "Buenos días,\n\nMi nombre es Dani de 2B Consulting.\nRealizamos una revisión técnica del sitio\nweb de {$company} y encontramos puntos\nimportantes que necesitamos compartir\ndirectamente con el gerente general o\nresponsable de tecnología.\n\n¿Podrían indicarnos cómo contactarlo\no facilitarnos su email directo?\n\nMuchas gracias.\n" . trim((string) ($config['email'] ?? '')) . ' · ' . trim((string) ($config['whatsapp'] ?? ''));
	}

	private static function reactivation_social_message($lead_id) {
		$company = trim((string) get_post_meta((int) $lead_id, '_crm_company', true)) ?: get_the_title((int) $lead_id);
		return "Hola, soy Dani de 2B Consulting.\n\nRealizamos una revisión técnica del sitio\nweb de {$company} y encontramos algunos\npuntos importantes que queremos compartir\ncon el gerente general o responsable de\ntecnología.\n\n¿Podrían indicarnos cómo contactarlo\ndirectamente?\n\nMuchas gracias.";
	}

	private static function reactivation_schedule_message($lead_id) {
		$lead_id = (int) $lead_id;
		$contact_name = self::lead_contact_name($lead_id);
		$config = self::reactivation_contact_config();
		$message = "Hola {$contact_name}, me alegra que le parezca\nrelevante.\n\n¿Tiene disponibilidad esta semana para\nuna videollamada de 20 minutos?\n\nPuedo el [día] a las [hora] o el [día]\na las [hora]. ¿Cuál le acomoda mejor?";
		if (! empty($config['agenda'])) {
			$message .= "\n\nSi le acomoda más, también puede tomar un espacio aquí:\n" . trim((string) $config['agenda']);
		}
		return $message;
	}

	private static function render_reactivation_task_panel($task_id) {
		$task_id = (int) $task_id;
		if (! self::is_reactivation_task($task_id)) {
			return;
		}

		$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
		$channel = self::reactivation_task_channel($task_id);
		$payload = self::reactivation_payload($lead_id);
		$channel_label = self::reactivation_task_label($channel);
		$task_due = (string) get_post_meta($task_id, '_crm_task_due', true);
		$auto_key = (string) get_post_meta($task_id, '_crm_auto_key', true);
		$is_schedule_task = 0 === strpos($auto_key, 'reactivation_schedule_meeting_');
		$config = self::reactivation_contact_config();
		$email_subject = self::reactivation_email_subject($lead_id);
		$email_body = self::reactivation_email_message($lead_id);
		$form_message = self::reactivation_form_message($lead_id);
		$social_message = self::reactivation_social_message($lead_id);
		$schedule_message = self::reactivation_schedule_message($lead_id);
		$call_script = self::reactivation_call_script($lead_id);
		?>
		<div class="twob-react-task-card" data-react-task-id="<?php echo esc_attr($task_id); ?>" data-react-channel="<?php echo esc_attr($channel); ?>">
			<div class="twob-line-1">
				<strong><?php echo esc_html(get_the_title($task_id)); ?></strong>
				<span class="twob-pill twob-react-pill">↻ REACTIVACIÓN</span>
			</div>
			<div class="twob-line-2">Canal: <?php echo esc_html($channel_label); ?> | Vence: <?php echo esc_html($task_due ?: current_time('Y-m-d')); ?></div>
			<?php if ($is_schedule_task) : ?>
				<div class="twob-react-callout is-good">Este lead ya respondió con interés. Ahora el objetivo es cerrar fecha y hora de reunión sin enfriar la conversación.</div>
				<div class="twob-react-copy-group">
					<label>Mensaje listo para agendar</label>
					<pre class="twob-react-copy-block" data-copy-text><?php echo esc_html($schedule_message); ?></pre>
					<div class="twob-task-actions">
						<button class="button button-small twob-copy-inline" data-copy-value="<?php echo esc_attr($schedule_message); ?>">Copiar mensaje</button>
						<?php if (! empty($config['agenda'])) : ?><a class="button button-small" href="<?php echo esc_url((string) $config['agenda']); ?>" target="_blank" rel="noopener noreferrer">Abrir agenda</a><?php endif; ?>
					</div>
				</div>
				<div class="twob-task-actions">
					<button class="button button-small twob-react-result" data-react-outcome="meeting_booked">Agendó reunión</button>
					<button class="button button-small twob-react-result" data-react-outcome="rejected">Respondió negativamente</button>
				</div>
			<?php elseif ('telefono' === $channel) : ?>
