		$company = (string) get_post_meta($lead_id, '_crm_company', true);
		$website = esc_url_raw((string) get_post_meta($lead_id, '_crm_website_url', true));
		$open_tasks = self::reactivation_tasks_for_lead($lead_id, true);
		$closed_day = self::reactivation_closed_day($lead_id);
