	public static function ajax_scan_sitio() {
		check_ajax_referer(self::NONCE_ACTION, 'nonce');
		if (! self::user_can_run_site_scan()) {
			wp_send_json_error(array('message' => 'No tienes permisos para ejecutar este escaneo.'));
		}

		$url = isset($_POST['url']) ? wp_unslash($_POST['url']) : '';
		$payload = self::scan_site_payload($url);
		if (is_wp_error($payload)) {
			wp_send_json_error(array('message' => $payload->get_error_message()));
		}

		wp_send_json_success($payload);
	}

	public static function ajax_guardar_hallazgo() {
		check_ajax_referer(self::NONCE_ACTION, 'nonce');
		if (! self::user_can_access_crm()) {
			wp_send_json_error(array('message' => 'Sin permisos.'));
		}

		$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
		$technical_finding = isset($_POST['technical_finding']) ? wp_unslash($_POST['technical_finding']) : '';
		$auto_checks_raw = isset($_POST['auto_checks']) ? wp_unslash($_POST['auto_checks']) : '';
		$scan_errors_raw = isset($_POST['scan_errors']) ? wp_unslash($_POST['scan_errors']) : '';
		$auto_checks = json_decode((string) $auto_checks_raw, true);
		$scan_errors = json_decode((string) $scan_errors_raw, true);

		$scan_meta = array(
			'speed_mobile' => isset($_POST['speed_mobile']) ? max(0, (int) wp_unslash($_POST['speed_mobile'])) : 0,
			'speed_desktop' => isset($_POST['speed_desktop']) ? max(0, (int) wp_unslash($_POST['speed_desktop'])) : 0,
			'site_status' => isset($_POST['site_status']) ? sanitize_key((string) wp_unslash($_POST['site_status'])) : 'ok',
			'scan_timestamp' => isset($_POST['scan_timestamp']) ? max(0, (int) wp_unslash($_POST['scan_timestamp'])) : (int) current_time('timestamp'),
			'critical_count' => isset($_POST['critical_count']) ? max(0, (int) wp_unslash($_POST['critical_count'])) : 0,
			'high_count' => isset($_POST['high_count']) ? max(0, (int) wp_unslash($_POST['high_count'])) : 0,
			'medium_count' => isset($_POST['medium_count']) ? max(0, (int) wp_unslash($_POST['medium_count'])) : 0,
			'auto_checks' => is_array($auto_checks) ? $auto_checks : array(),
			'errors' => is_array($scan_errors) ? $scan_errors : array(),
		);

		$result = self::save_lead_technical_finding($lead_id, $technical_finding, '', $scan_meta);
		if (is_wp_error($result)) {
			wp_send_json_error(array('message' => $result->get_error_message()));
		}

		wp_send_json_success(array(
			'message' => 'Hallazgos guardados en el lead.',
			'technical_finding' => $result['technical_finding'] ?? '',
			'scan_timestamp' => (int) ($scan_meta['scan_timestamp'] ?? current_time('timestamp')),
		));
	}

	public static function ajax_verify_pagespeed_key() {
		check_ajax_referer(self::NONCE_ACTION, 'nonce');
		if (! self::user_can_manage_settings()) {
			wp_send_json_error(array('message' => 'No tienes permisos para verificar la API key.'));
		}

		$api_key = isset($_POST['api_key']) ? sanitize_text_field((string) wp_unslash($_POST['api_key'])) : '';
		if ('' === trim($api_key)) {
			wp_send_json_error(array('message' => 'Ingresa una API key para verificarla.'));
		}

		$response = self::pagespeed_request('https://example.com', 'mobile', $api_key);
		if (is_wp_error($response)) {
			wp_send_json_error(array('message' => $response->get_error_message()));
		}

		wp_send_json_success(array('message' => 'API key verificada correctamente.'));
	}

