	public static function ajax_generar_mensaje_ia() {
		check_ajax_referer(self::NONCE_ACTION, 'nonce');
		if (! self::user_can_access_crm()) {
			wp_send_json_error(array('message' => 'Sin permisos.'));
		}

		$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
		$task_id = isset($_POST['task_id']) ? absint($_POST['task_id']) : 0;
		$message_type = isset($_POST['tipo_mensaje']) ? wp_unslash($_POST['tipo_mensaje']) : '';

		$result = self::generate_ai_message_for_task($task_id, $lead_id, $message_type);
		if (is_wp_error($result)) {
			wp_send_json_error(array(
				'message' => $result->get_error_message(),
				'settings_url' => admin_url('admin.php?page=twob-crm-visual-settings'),
			));
		}

		wp_send_json_success(array(
			'mensaje' => (string) ($result['mensaje'] ?? ''),
			'message_type' => (string) ($result['message_type'] ?? ''),
			'task_id' => (int) ($result['task_id'] ?? 0),
			'lead_id' => (int) ($result['lead_id'] ?? 0),
			'generated_at' => (int) ($result['generated_at'] ?? current_time('timestamp')),
			'generated_at_label' => self::elapsed_label_from_unix((int) ($result['generated_at'] ?? current_time('timestamp'))),
		));
	}

	public static function ajax_buscar_prospectos() {
		check_ajax_referer(self::NONCE_ACTION, 'nonce');
		if (! self::user_can_access_prospect_finder()) {
			wp_send_json_error(array('message' => 'Sin permisos para usar el Buscador de Prospectos.'));
		}

		@set_time_limit(60);
		$sectors = isset($_POST['sectors']) ? (array) wp_unslash($_POST['sectors']) : array();
		if (isset($_POST['sectors']) && ! is_array($_POST['sectors'])) {
			$sectors = explode(',', (string) wp_unslash($_POST['sectors']));
		}
		$sectors = array_values(array_filter(array_map('sanitize_key', $sectors)));
		$zone_key = isset($_POST['zone']) ? sanitize_key((string) wp_unslash($_POST['zone'])) : 'santiago_chile';
		$quantity = isset($_POST['quantity']) ? max(5, min(15, (int) wp_unslash($_POST['quantity']))) : 10;
		$sector_options = self::prospect_sector_options();
		$zone_options = self::prospect_zone_options();
		$selected_sector_labels = array();
		foreach ($sectors as $sector_key) {
			if (isset($sector_options[$sector_key])) {
				$selected_sector_labels[] = (string) $sector_options[$sector_key];
			}
		}
		if (empty($selected_sector_labels)) {
			wp_send_json_error(array('message' => 'Selecciona al menos un sector antes de buscar.'));
		}
		$zone_label = $zone_options[$zone_key] ?? 'Santiago Chile';
		$started_at = microtime(true);
		$candidates = self::prospect_search_candidates($selected_sector_labels, $zone_label, $quantity, true);
		if (is_wp_error($candidates)) {
			wp_send_json_error(array('message' => $candidates->get_error_message()));
		}

		$payload = self::prospect_search_results_payload(
			(array) ($candidates['prospectos'] ?? array()),
			$selected_sector_labels,
			$zone_label,
			$quantity,
			$started_at,
			$sectors
		);
		$payload['message'] = ! empty($payload['prospects'])
			? 'Listo. Se encontraron ' . count((array) $payload['prospects']) . ' prospectos nuevos.'
			: 'No se encontraron empresas nuevas que cumplan los filtros o varias ya están en el CRM.';
		wp_send_json_success($payload);
	}

	public static function ajax_crear_prospecto_lead() {
		check_ajax_referer(self::NONCE_ACTION, 'nonce');
		if (! self::user_can_access_prospect_finder()) {
			wp_send_json_error(array('message' => 'Sin permisos para crear leads desde el Buscador.'));
		}

		$search_id = isset($_POST['search_id']) ? sanitize_key((string) wp_unslash($_POST['search_id'])) : '';
		$company = sanitize_text_field((string) wp_unslash($_POST['empresa'] ?? ''));
		$website_url = esc_url_raw((string) wp_unslash($_POST['url'] ?? ''));
		$domain = self::prospect_normalize_domain((string) wp_unslash($_POST['domain'] ?? $website_url));
		$sector_label = sanitize_text_field((string) wp_unslash($_POST['sector'] ?? ''));
		$sector_key = sanitize_key((string) wp_unslash($_POST['sector_key'] ?? ''));
		$sector_key = $sector_key ?: self::prospect_sector_key_guess($sector_label);
		$decisor_nombre = sanitize_text_field((string) wp_unslash($_POST['decisor_nombre'] ?? ''));
		$decisor_cargo = sanitize_text_field((string) wp_unslash($_POST['decisor_cargo'] ?? ''));
		$email = sanitize_email((string) wp_unslash($_POST['email'] ?? ''));
		$telefono = sanitize_text_field((string) wp_unslash($_POST['telefono'] ?? ''));
		$linkedin_empresa = esc_url_raw((string) wp_unslash($_POST['linkedin_empresa'] ?? ''));
		$hallazgo = sanitize_textarea_field((string) wp_unslash($_POST['hallazgo'] ?? ''));
		$impacto = sanitize_textarea_field((string) wp_unslash($_POST['impacto'] ?? ''));
		$hallazgo_completo = sanitize_textarea_field((string) wp_unslash($_POST['hallazgo_completo'] ?? ''));
		$mensaje_linkedin = sanitize_textarea_field((string) wp_unslash($_POST['mensaje_linkedin'] ?? ''));
		$capacidad_economica = sanitize_key((string) wp_unslash($_POST['capacidad_economica'] ?? 'media'));
		$senales_capacidad = json_decode((string) wp_unslash($_POST['senales_capacidad'] ?? '[]'), true);
		$senales_capacidad = is_array($senales_capacidad) ? array_values(array_filter(array_map('sanitize_text_field', $senales_capacidad))) : array();
		$decisor_busqueda = sanitize_text_field((string) wp_unslash($_POST['decisor_linkedin_busqueda'] ?? ''));

		if ('' === $company || '' === $website_url || '' === $domain) {
			wp_send_json_error(array('message' => 'Faltan datos mínimos del prospecto para crear el lead.'));
		}
		if (self::prospect_domain_exists($domain)) {
			wp_send_json_error(array('message' => 'Este dominio ya existe como lead en el CRM. No se puede duplicar.'));
		}

		$lead_name = '' !== $decisor_nombre ? $decisor_nombre : 'Por confirmar';
		$validation = self::validate_lead_payload(array(
			'name' => $lead_name,
			'company' => $company,
			'website_url' => $website_url,
			'origin_channel' => 'linkedin',
			'client_type' => $sector_key ?: $sector_label,
			'service_interest' => 'diagnostic',
			'email' => $email,
			'phone' => $telefono,
		), 'pre_contact');
		if (is_wp_error($validation)) {
			wp_send_json_error(array('message' => $validation->get_error_message()));
		}

		$lead_id = wp_insert_post(array(
			'post_type' => 'crm_lead',
			'post_status' => 'publish',
			'post_title' => $lead_name,
		));
		if (! $lead_id || is_wp_error($lead_id)) {
			wp_send_json_error(array('message' => 'No se pudo crear el lead del prospecto.'));
		}

		$signals_text = ! empty($senales_capacidad) ? implode(', ', $senales_capacidad) : 'Sin señales detalladas';
		$note = "Lead encontrado por búsqueda automática.\nDecisor por confirmar en LinkedIn: " . ($decisor_busqueda ?: 'No especificado') . "\nSeñales de capacidad: " . $signals_text;
		$hallazgo_text = trim($hallazgo_completo);
		if ('' === $hallazgo_text) {
			$hallazgo_text = trim(
				($hallazgo ? 'HALLAZGO: ' . $hallazgo : '') .
				(($hallazgo && $impacto) ? "\n" : '') .
				($impacto ? 'IMPACTO: ' . $impacto : '')
			);
		}

		update_post_meta($lead_id, '_crm_company', $company);
		update_post_meta($lead_id, '_crm_email', $email);
		update_post_meta($lead_id, '_crm_phone', $telefono);
		update_post_meta($lead_id, '_crm_website_url', $website_url);
		update_post_meta($lead_id, '_crm_linkedin_company', $linkedin_empresa);
		update_post_meta($lead_id, '_crm_origin_channel', 'linkedin');
		update_post_meta($lead_id, '_crm_first_contact_channel', '');
		update_post_meta($lead_id, '_crm_client_type', $sector_key ?: $sector_label);
		update_post_meta($lead_id, '_crm_service_interest', 'diagnostic');
		update_post_meta($lead_id, '_crm_stage', 'pre_contact');
		update_post_meta($lead_id, '_crm_next_followup', '');
		update_post_meta($lead_id, '_crm_next_action', 'Revisión técnica pendiente');
		update_post_meta($lead_id, '_crm_observations', $note);
		update_post_meta($lead_id, '_crm_qualification_notes', $note);
		update_post_meta($lead_id, '_crm_has_website', 'yes');
		update_post_meta($lead_id, '_crm_sequence_policy', self::sequence_policy_for_origin_channel('linkedin'));
		update_post_meta($lead_id, '_crm_sequence_policy_version', self::SEQUENCE_POLICY_VERSION);
		update_post_meta($lead_id, 'cargo', $decisor_cargo);
		update_post_meta($lead_id, '_crm_cargo', $decisor_cargo);
		update_post_meta($lead_id, 'nombre_contacto', $decisor_nombre);
		update_post_meta($lead_id, '_crm_nombre_contacto', $decisor_nombre);
		update_post_meta($lead_id, 'twob_origen', 'buscador_automatico');
		update_post_meta($lead_id, 'twob_prospect_linkedin_message', $mensaje_linkedin);
		update_post_meta($lead_id, 'twob_task_mensaje_ia', $mensaje_linkedin);
		update_post_meta($lead_id, 'twob_decisor_linkedin_busqueda', $decisor_busqueda);
		update_post_meta($lead_id, 'twob_prospect_capacity', $capacidad_economica);
		update_post_meta($lead_id, 'twob_prospect_capacity_signals', $senales_capacidad);
		update_post_meta($lead_id, 'twob_speed_mobile', max(0, (int) wp_unslash($_POST['speed_mobile'] ?? 0)));
		update_post_meta($lead_id, 'twob_speed_desktop', max(0, (int) wp_unslash($_POST['speed_desktop'] ?? 0)));
		update_post_meta($lead_id, 'twob_ssl', ! empty($_POST['ssl_ok']) ? '1' : '0');
		update_post_meta($lead_id, 'twob_dkim', ! empty($_POST['dkim_ok']) ? '1' : '0');
		update_post_meta($lead_id, 'twob_spf', ! empty($_POST['spf_ok']) ? '1' : '0');
		update_post_meta($lead_id, 'twob_dmarc', ! empty($_POST['dmarc_ok']) ? '1' : '0');
		update_post_meta($lead_id, 'twob_estado_sitio', sanitize_key((string) wp_unslash($_POST['site_status'] ?? 'ok')));
		update_post_meta($lead_id, 'twob_scan_fecha', (int) current_time('timestamp'));
		update_post_meta($lead_id, 'twob_scan_critical_count', max(0, (int) wp_unslash($_POST['critical_count'] ?? 0)));
		update_post_meta($lead_id, 'twob_scan_high_count', max(0, (int) wp_unslash($_POST['high_count'] ?? 0)));
		update_post_meta($lead_id, 'twob_scan_medium_count', max(0, (int) wp_unslash($_POST['medium_count'] ?? 0)));
		update_post_meta($lead_id, 'twob_scan_errors', json_decode((string) wp_unslash($_POST['scan_errors'] ?? '[]'), true));

		if ('' !== $hallazgo_text) {
			update_post_meta($lead_id, '_crm_technical_finding', $hallazgo_text);
			update_post_meta($lead_id, '_crm_technical_reviewed_at', current_time('mysql'));
			self::sync_lead_technical_finding_context($lead_id);
		}

		$stage_result = self::set_lead_stage($lead_id, 'pre_contact', 'prospect_finder_create');
		if (is_wp_error($stage_result)) {
			wp_delete_post($lead_id, true);
			wp_send_json_error(array('message' => $stage_result->get_error_message()));
		}

		update_post_meta($lead_id, '_crm_temperature', 'warm');
		self::ensure_precontact_review_task($lead_id, current_time('Y-m-d'));
		self::sync_lead_lifecycle_state($lead_id);
		self::sync_lead_next_action($lead_id, '' !== $hallazgo_text ? 'Listo para contactar' : 'Revisión técnica pendiente');
		self::update_temperature($lead_id);
		self::update_operational_status($lead_id);
		self::sync_master_client_for_lead($lead_id);
		self::prospect_search_history_increment_created($search_id, $company);

		wp_send_json_success(array(
			'message' => '✓ Lead creado — aparece en panel de Renata para revisión técnica',
			'lead_id' => (int) $lead_id,
			'lead_url' => admin_url('admin.php?page=twob-crm-visual-leads&lead_id=' . (int) $lead_id) . '#lead-' . (int) $lead_id,
			'history' => self::prospect_history_recent(5),
		));
	}

	public static function ajax_mensaje_alianza() {
		check_ajax_referer(self::NONCE_ACTION, 'nonce');
		if (! current_user_can('edit_crm_leads')) {
			wp_send_json_error(array('message' => 'Sin permisos para trabajar alianzas.'));
		}

		$alliance_id = isset($_POST['alliance_id']) ? sanitize_key((string) wp_unslash($_POST['alliance_id'])) : '';
		$alliance = self::alliance_find($alliance_id);
		if (empty($alliance)) {
			wp_send_json_error(array('message' => 'No se encontró la alianza.'));
		}
		if ('' === self::anthropic_api_key_get()) {
			wp_send_json_error(array(
				'message' => 'Configurar API key en Configuración →',
				'settings_url' => admin_url('admin.php?page=twob-crm-visual-settings'),
			));
		}

		$message = self::alliance_generate_text(
			self::alliance_contact_message_prompt($alliance),
			self::alliance_contact_message_fallback($alliance),
			200
		);
		$alliance = self::alliance_record_update($alliance_id, array(
			'twob_alianza_mensaje_ia' => $message,
			'twob_alianza_mensaje_ia_fecha' => (int) current_time('timestamp'),
		));
		wp_send_json_success(array(
			'mensaje' => $message,
			'generated_at' => (int) current_time('timestamp'),
			'generated_at_label' => self::elapsed_label_from_unix((int) current_time('timestamp')),
		));
	}

