	public static function ajax_registrar_referido_alianza() {
		check_ajax_referer(self::NONCE_ACTION, 'nonce');
		if (! current_user_can('edit_crm_leads')) {
			wp_send_json_error(array('message' => 'Sin permisos para crear leads.'));
		}

		$alliance_id = isset($_POST['alliance_id']) ? sanitize_key((string) wp_unslash($_POST['alliance_id'])) : '';
		$alliance = self::alliance_find($alliance_id);
		if (empty($alliance)) {
			wp_send_json_error(array('message' => 'No se encontró la alianza.'));
		}

		$contact_name = sanitize_text_field((string) wp_unslash($_POST['contact_name'] ?? ''));
		$company = sanitize_text_field((string) wp_unslash($_POST['company'] ?? ''));
		$website_url = esc_url_raw((string) wp_unslash($_POST['website_url'] ?? ''));
		$notes = sanitize_textarea_field((string) wp_unslash($_POST['notes'] ?? ''));
		if ('' === $contact_name || '' === $company || '' === $website_url) {
			wp_send_json_error(array('message' => 'Completa nombre, empresa y URL del sitio.'));
		}

		$lead_id = wp_insert_post(array(
			'post_type' => 'crm_lead',
			'post_status' => 'publish',
			'post_title' => $contact_name,
			'meta_input' => array(
				'_crm_company' => $company,
				'_crm_website_url' => $website_url,
				'_crm_origin_channel' => 'referral',
				'_crm_alliance_source' => (string) $alliance['name'],
				'_crm_referred_by' => (string) $alliance['name'],
				'_crm_observations' => $notes,
				'_crm_stage' => 'pre_contact',
				'_crm_next_followup' => '',
				'_crm_first_contact_channel' => '',
			),
		));
		if (is_wp_error($lead_id) || ! $lead_id) {
			wp_send_json_error(array('message' => 'No se pudo crear el lead referido.'));
		}

		self::ensure_precontact_review_task((int) $lead_id, current_time('Y-m-d'));
		self::sync_lead_lifecycle_state((int) $lead_id);
		self::sync_lead_next_action((int) $lead_id);
		self::update_temperature((int) $lead_id);
		self::update_operational_status((int) $lead_id);

		$existing_referred = self::alliance_referred_leads_count((string) $alliance['name']);
		self::alliance_record_update($alliance_id, array(
			'leads_referidos' => max($existing_referred, (int) ($alliance['leads_referidos'] ?? 0)) + 1,
			'last_referred_at' => current_time('Y-m-d'),
			'last_activity_at' => current_time('mysql'),
		));

		wp_send_json_success(array(
			'message' => '✓ Lead creado — aparece en panel de Renata para revisión técnica',
			'lead_id' => (int) $lead_id,
			'lead_url' => admin_url('admin.php?page=twob-crm-visual-leads&lead_id=' . (int) $lead_id) . '#lead-' . (int) $lead_id,
		));
	}

	public static function ajax_alianza_task_action() {
		check_ajax_referer(self::NONCE_ACTION, 'nonce');
		if (! current_user_can('edit_crm_tasks')) {
			wp_send_json_error(array('message' => 'Sin permisos para editar tareas de alianza.'));
		}

		$task_id = isset($_POST['task_id']) ? absint($_POST['task_id']) : 0;
		$task_action = sanitize_key((string) wp_unslash($_POST['task_action'] ?? ''));
		$result = null;
		if ('done' === $task_action) {
			$result = self::alliance_complete_task($task_id, sanitize_text_field((string) wp_unslash($_POST['note'] ?? '')));
		} elseif ('postpone' === $task_action) {
			$result = self::alliance_postpone_task($task_id, current_time('Y-m-d'));
		} else {
			wp_send_json_error(array('message' => 'Acción de alianza no válida.'));
		}

		if (is_wp_error($result)) {
			wp_send_json_error(array('message' => $result->get_error_message()));
		}

		wp_send_json_success($result);
	}

	private static function daily_plan_serialize_renata_review_queue($leads) {
		$items = array();

		foreach ((array) $leads as $lead) {
			if (! ($lead instanceof WP_Post)) {
				continue;
			}

			$lead_id = (int) $lead->ID;
			$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
			$technical_finding = trim((string) get_post_meta($lead_id, '_crm_technical_finding', true));
			$age_meta = self::lead_wait_age_meta($lead_id);
			$origin_channel = sanitize_key((string) get_post_meta($lead_id, '_crm_origin_channel', true));
			$items[] = array(
				'id' => $lead_id,
				'name' => (string) $lead->post_title,
				'company' => (string) get_post_meta($lead_id, '_crm_company', true),
				'websiteUrl' => esc_url_raw((string) get_post_meta($lead_id, '_crm_website_url', true)),
				'leadUrl' => esc_url_raw(admin_url('admin.php?page=twob-crm-visual-leads&lead_id=' . $lead_id . '&q=' . rawurlencode((string) $lead->post_title)) . '#lead-' . $lead_id),
				'stageLabel' => self::stage_labels()[$stage] ?? 'Sin etapa',
				'originChannel' => $origin_channel,
				'originLabel' => self::channel_labels()[$origin_channel] ?? 'Sin canal',
				'ageLabel' => (string) ($age_meta['label'] ?? ''),
				'ageHours' => (int) ($age_meta['hours'] ?? 0),
				'isWarning' => ! empty($age_meta['is_warning']) && '' === $technical_finding,
				'hasFinding' => '' !== $technical_finding,
				'technicalFinding' => $technical_finding,
				'technicalFindingShort' => $technical_finding ? self::truncate_text($technical_finding, 60) : '',
			);
		}

		return $items;
	}

	private static function daily_plan_serialize_renata_meeting_queue($leads) {
		$items = array();

		foreach ((array) $leads as $lead) {
			if (! ($lead instanceof WP_Post)) {
				continue;
			}

			$lead_id = (int) $lead->ID;
			$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
			$items[] = array(
				'id' => $lead_id,
				'name' => (string) $lead->post_title,
				'company' => (string) get_post_meta($lead_id, '_crm_company', true),
				'nextFollowup' => (string) get_post_meta($lead_id, '_crm_next_followup', true),
				'leadUrl' => esc_url_raw(admin_url('admin.php?page=twob-crm-visual-leads&lead_id=' . $lead_id . '&q=' . rawurlencode((string) $lead->post_title)) . '#lead-' . $lead_id),
				'stageLabel' => self::stage_labels()[$stage] ?? 'Sin etapa',
			);
		}

		return $items;
	}

	private static function daily_plan_serialize_renata_diagnostic_queue($leads, $today = '') {
		$today = $today ?: current_time('Y-m-d');
		$items = array();

		foreach ((array) $leads as $lead) {
			if (! ($lead instanceof WP_Post)) {
				continue;
			}

			$lead_id = (int) $lead->ID;
			$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
			$operational_status = self::determine_operational_status($lead_id, $today);
			$technical_finding = trim((string) get_post_meta($lead_id, '_crm_technical_finding', true));
			$items[] = array(
				'id' => $lead_id,
				'name' => (string) $lead->post_title,
				'company' => (string) get_post_meta($lead_id, '_crm_company', true),
				'leadUrl' => esc_url_raw(admin_url('admin.php?page=twob-crm-visual-leads&lead_id=' . $lead_id . '&q=' . rawurlencode((string) $lead->post_title)) . '#lead-' . $lead_id),
				'statusLabel' => 'proposal_sent' === $stage
					? (self::stage_labels()[$stage] ?? 'PROPUESTA ENVIADA')
					: (self::operational_status_labels()[$operational_status] ?? 'INTERESADO'),
				'technicalFinding' => $technical_finding,
				'technicalFindingShort' => $technical_finding ? self::truncate_text($technical_finding, 60) : 'Sin hallazgo tecnico aun',
			);
		}

		return $items;
	}

	private static function reactivation_prepare_queue($today = '', $limit = 5) {
		$today = $today ?: current_time('Y-m-d');
		$limit = max(1, (int) $limit);
		$leads = get_posts(array(
			'post_type' => 'crm_lead',
			'post_status' => 'publish',
			'numberposts' => -1,
			'orderby' => 'date',
			'order' => 'DESC',
		));

		$priority_one = array();
		$priority_two = array();
		foreach ($leads as $lead) {
			$lead_id = (int) $lead->ID;
			if (! self::reactivation_lead_is_eligible($lead_id) || self::reactivation_is_paused($lead_id, $today)) {
				continue;
			}
			$payload = self::reactivation_payload($lead_id);
			if (! empty($payload['sequence_generated'])) {
				continue;
			}
			if ('' === $payload['hallazgo']) {
				$priority_one[] = $lead;
				continue;
			}
			$priority_two[] = $lead;
		}

		return array_slice(array_merge($priority_one, $priority_two), 0, $limit);
	}

	private static function serialize_reactivation_prepare_queue($leads) {
		$items = array();
		foreach ((array) $leads as $lead) {
			if (! ($lead instanceof WP_Post)) {
				continue;
			}
			$lead_id = (int) $lead->ID;
			$payload = self::reactivation_payload($lead_id);
			$company = (string) get_post_meta($lead_id, '_crm_company', true);
			$website = esc_url_raw((string) get_post_meta($lead_id, '_crm_website_url', true));
			$closed_day = self::reactivation_closed_day($lead_id);
			$items[] = array(
				'id' => $lead_id,
				'name' => (string) $lead->post_title,
				'company' => $company,
				'websiteUrl' => $website,
				'leadUrl' => esc_url_raw(self::reactivation_lead_url($lead_id, true)),
				'closedDay' => $closed_day,
				'badge' => '' === $payload['hallazgo'] ? '⚠ Falta hallazgo + investigación' : '🔍 Falta investigación de canales',
				'badgeClass' => '' === $payload['hallazgo'] ? 'is-warning' : 'is-soft',
				'hasFinding' => '' !== $payload['hallazgo'],
			);
		}
		return $items;
	}

	private static function reactivation_due_tasks($today = '', $limit = 5) {
		$today = $today ?: current_time('Y-m-d');
		return get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => max(1, (int) $limit),
			'meta_key' => '_crm_task_due',
			'orderby' => 'meta_value',
			'order' => 'ASC',
			'meta_query' => array(
				array('key' => 'twob_task_tipo', 'value' => 'reactivacion', 'compare' => '='),
				array('key' => '_crm_task_due', 'value' => $today, 'compare' => '<=', 'type' => 'DATE'),
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
		));
	}

	private static function serialize_reactivation_due_tasks($tasks) {
		$items = array();
		foreach ((array) $tasks as $task) {
			if (! ($task instanceof WP_Post)) {
				continue;
			}
			$task_id = (int) $task->ID;
			$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
			if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
				continue;
			}
			$items[] = array(
				'taskId' => $task_id,
				'leadId' => $lead_id,
				'title' => (string) $task->post_title,
				'channel' => self::reactivation_task_channel($task_id),
				'channelLabel' => self::reactivation_task_label(self::reactivation_task_channel($task_id)),
				'due' => (string) get_post_meta($task_id, '_crm_task_due', true),
				'leadUrl' => esc_url_raw(self::reactivation_lead_url($lead_id, true)),
				'name' => (string) get_the_title($lead_id),
				'company' => (string) get_post_meta($lead_id, '_crm_company', true),
			);
		}
		return $items;
	}

	private static function dashboard_reactivation_banner_item($today = '') {
		$today = $today ?: current_time('Y-m-d');
		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => 1,
			'meta_key' => '_crm_task_due',
			'orderby' => 'meta_value',
			'order' => 'ASC',
			'meta_query' => array(
				array('key' => '_crm_auto_key', 'value' => 'reactivation_schedule_meeting_', 'compare' => 'LIKE'),
				array('key' => '_crm_task_due', 'value' => $today, 'compare' => '<=', 'type' => 'DATE'),
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
		));

		$task = ! empty($tasks[0]) ? $tasks[0] : null;
		if (! ($task instanceof WP_Post)) {
			return array();
		}

		$task_id = (int) $task->ID;
		$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
		if (! $lead_id) {
			return array();
		}

		return array(
			'lead_id' => $lead_id,
			'name' => (string) get_the_title($lead_id),
			'company' => (string) get_post_meta($lead_id, '_crm_company', true),
			'lead_url' => self::reactivation_lead_url($lead_id, true),
		);
	}

	private static function dashboard_sequence_counts($tasks) {
		$counts = array(
			'day3' => 0,
			'day7' => 0,
			'day10' => 0,
		);

		foreach ((array) $tasks as $task) {
			if (! ($task instanceof WP_Post)) {
				continue;
			}
			$slug = self::task_sequence_step_slug((int) $task->ID);
			if ('day3_linkedin_followup' === $slug) {
				$counts['day3']++;
			} elseif ('day7_email' === $slug) {
				$counts['day7']++;
			} elseif ('day10_last_linkedin' === $slug) {
				$counts['day10']++;
			}
		}

		return $counts;
	}

	private static function render_dashboard_response_row($item, $today) {
