			$priority_label = 'Media';
		}
		?>
		<div class="twob-response-row" data-lead-id="<?php echo esc_attr($lead_id); ?>">
			<div class="twob-response-avatar"><?php echo esc_html(self::dashboard_initials($lead->post_title)); ?></div>
			<div class="twob-response-copy">
				<div class="twob-response-head">
					<strong><?php echo esc_html($lead->post_title); ?></strong>
					<span class="twob-response-time"><?php echo esc_html($item['day'] === $today ? 'Hoy, ' . $time_label : $item['day']); ?></span>
				</div>
				<div class="twob-line-2"><?php echo esc_html($company ?: 'Sin empresa'); ?></div>
				<div class="twob-response-note"><?php echo esc_html($note ?: (self::interaction_result_labels()[$result] ?? 'Respuesta recibida')); ?></div>
				<div class="twob-response-meta-line">Siguiente mensaje: <strong><?php echo esc_html($effort_meta['label']); ?></strong> | <?php echo esc_html($effort_meta['hint']); ?></div>
			</div>
			<div class="twob-response-side">
				<span class="twob-response-priority twob-response-priority-<?php echo esc_attr(strtolower($priority_label)); ?>"><?php echo esc_html($priority_label); ?></span>
				<span class="twob-response-priority <?php echo esc_attr($effort_meta['class']); ?>">Personalizacion <?php echo esc_html($effort_meta['label']); ?></span>
				<div class="twob-response-actions">
					<button class="button button-primary button-small twob-btn" data-action="log_followup" data-task-id="<?php echo esc_attr((string) $open_task_id); ?>" data-lead-id="<?php echo esc_attr($lead_id); ?>" data-lead-title="<?php echo esc_attr($lead->post_title); ?>" data-default-channel="<?php echo esc_attr($channel ?: 'whatsapp'); ?>" data-default-action="<?php echo esc_attr(self::response_received_action_for_channel($channel)); ?>" data-default-result="<?php echo esc_attr($result ?: 'interested'); ?>">Responder</button>
					<?php if (! empty($profile_link['url'])) : ?><a class="button button-small" href="<?php echo esc_url((string) $profile_link['url']); ?>" target="_blank" rel="noopener noreferrer">Abrir perfil</a><?php endif; ?>
					<a class="button button-small" href="<?php echo esc_url($lead_url); ?>">Abrir</a>
				</div>
			</div>
		</div>
