	private static function activity_action_labels() {
		return array(
			'lead_created' => 'Lead creado',
			'interaction_logged' => 'Interaccion registrada',
			'response_sent' => 'Respuesta del lead',
			'task_completed' => 'Tarea completada',
			'task_followup_scheduled' => 'Proximo seguimiento programado',
			'collection_reviewed' => 'Cobro revisado',
			'payment_recorded' => 'Pago registrado',
			'stage_changed' => 'Cambio de etapa',
			'funnel_stage_changed' => 'Cambio de embudo',
			'deal_won' => 'Lead ganado',
			'lead_reactivated' => 'Lead reactivado',
		);
	}

	private static function activity_group_labels() {
		return array(
			'all' => 'Todo',
			'leads' => 'Leads',
			'interactions' => 'Interacciones',
			'stages' => 'Etapas',
			'tasks' => 'Tareas',
			'payments' => 'Cobros',
		);
	}

	private static function sanitize_activity_group($group) {
		$group = sanitize_key((string) $group);
		return isset(self::activity_group_labels()[$group]) ? $group : 'all';
	}

	private static function activity_group_actions($group) {
		return match (self::sanitize_activity_group($group)) {
			'leads' => array('lead_created', 'deal_won', 'lead_reactivated'),
			'interactions' => array('interaction_logged', 'response_sent'),
			'stages' => array('stage_changed', 'funnel_stage_changed'),
			'tasks' => array('task_completed'),
			'payments' => array('collection_reviewed', 'payment_recorded'),
			default => array(),
		};
	}

	private static function activity_category_for_action($action) {
		$action = sanitize_key((string) $action);
		return match ($action) {
			'lead_created', 'deal_won', 'lead_reactivated' => 'leads',
			'interaction_logged', 'response_sent' => 'interactions',
			'stage_changed', 'funnel_stage_changed' => 'stages',
			'task_completed' => 'tasks',
			'collection_reviewed', 'payment_recorded' => 'payments',
			default => 'all',
		};
	}

	private static function get_activity_items($args = array()) {
		$today = current_time('Y-m-d');
		$args = wp_parse_args($args, array(
			'date_from' => $today,
			'date_to' => $today,
			'group' => 'all',
			'search' => '',
			'numberposts' => 120,
		));

		$date_from = self::sanitize_date_input($args['date_from'], true, 'Fecha desde');
		$date_to = self::sanitize_date_input($args['date_to'], true, 'Fecha hasta');
		$date_from = is_wp_error($date_from) ? '' : $date_from;
		$date_to = is_wp_error($date_to) ? '' : $date_to;
		if ($date_from && $date_to && $date_from > $date_to) {
			$tmp = $date_from;
			$date_from = $date_to;
			$date_to = $tmp;
		}

		$meta_query = array();
		$group_actions = self::activity_group_actions($args['group']);
		if (! empty($group_actions)) {
			$meta_query[] = array(
				'key' => '_crm_action',
				'value' => $group_actions,
				'compare' => 'IN',
			);
		}

		$date_query = array();
		if ($date_from || $date_to) {
			$date_filter = array('inclusive' => true);
			if ($date_from) {
				$date_filter['after'] = $date_from;
			}
			if ($date_to) {
				$date_filter['before'] = $date_to;
			}
			$date_query[] = $date_filter;
		}

		$activity_ids = get_posts(array(
			'post_type' => 'crm_activity',
			'post_status' => 'publish',
			'numberposts' => (int) $args['numberposts'],
			'fields' => 'ids',
			'orderby' => 'date',
			'order' => 'DESC',
			'meta_query' => $meta_query,
			'date_query' => $date_query,
		));

		$search = self::normalize_search_text($args['search']);
		if ('' === $search) {
			return array_values(array_map('intval', $activity_ids));
		}

		$filtered = array();
		foreach ($activity_ids as $activity_id) {
			if (self::activity_matches_search((int) $activity_id, $search)) {
				$filtered[] = (int) $activity_id;
			}
		}

		return $filtered;
	}

	private static function activity_matches_search($activity_id, $query) {
		$query = self::normalize_search_text($query);
		if ('' === $query) {
			return true;
		}

		return false !== strpos(self::activity_search_haystack($activity_id), $query);
	}

	private static function activity_search_haystack($activity_id) {
		static $cache = array();

		$activity_id = (int) $activity_id;
		if (! $activity_id) {
			return '';
		}
		if (isset($cache[$activity_id])) {
			return $cache[$activity_id];
		}

		$parts = array(
			self::activity_summary_for_item($activity_id),
			self::activity_detail_for_item($activity_id),
			self::activity_actor_name($activity_id),
		);

		$lead_id = self::activity_related_lead_id($activity_id);
		if ($lead_id) {
			$parts[] = get_the_title($lead_id);
			$parts[] = (string) get_post_meta($lead_id, '_crm_company', true);
			$parts[] = (string) get_post_meta($lead_id, '_crm_email', true);
			$parts[] = (string) get_post_meta($lead_id, '_crm_phone', true);
		}

		$object_id = (int) get_post_meta($activity_id, '_crm_object_id', true);
		if ($object_id) {
			$parts[] = get_the_title($object_id);
		}

		$cache[$activity_id] = self::normalize_search_text(implode(' ', array_filter(array_map('strval', $parts))));
		return $cache[$activity_id];
	}

	private static function activity_related_lead_id($activity_id) {
		$activity_id = (int) $activity_id;
		if (! $activity_id) {
			return 0;
		}

		$object_id = (int) get_post_meta($activity_id, '_crm_object_id', true);
		if ($object_id && 'crm_lead' === get_post_type($object_id)) {
			return $object_id;
		}
		if ($object_id && 'crm_task' === get_post_type($object_id)) {
			return (int) get_post_meta($object_id, '_crm_task_lead_id', true);
		}
		if ($object_id && 'crm_payment' === get_post_type($object_id)) {
			return (int) get_post_meta($object_id, '_crm_lead_id', true);
		}
		if ($object_id && 'crm_interaction' === get_post_type($object_id)) {
			return (int) get_post_meta($object_id, '_crm_lead_id', true);
		}

		return 0;
	}

	private static function activity_actor_name($activity_id) {
		$activity_id = (int) $activity_id;
		$user_id = (int) get_post_meta($activity_id, '_crm_user_id', true);
		if (! $user_id) {
			$activity = get_post($activity_id);
			$user_id = $activity ? (int) $activity->post_author : 0;
		}
		$user = $user_id ? get_userdata($user_id) : null;
		return ($user && ! empty($user->display_name)) ? $user->display_name : 'Sistema';
	}

	private static function activity_summary_for_item($activity_id) {
		$action = sanitize_key((string) get_post_meta((int) $activity_id, '_crm_action', true));
		$labels = self::activity_action_labels();
		return $labels[$action] ?? ucfirst(str_replace('_', ' ', $action));
	}

	private static function activity_detail_for_item($activity_id) {
		$activity_id = (int) $activity_id;
		$action = sanitize_key((string) get_post_meta($activity_id, '_crm_action', true));
		$object_id = (int) get_post_meta($activity_id, '_crm_object_id', true);

		return match ($action) {
			'lead_created' => 'Ingreso de un nuevo lead al CRM.',
			'interaction_logged' => (
				((string) get_post_meta($activity_id, '_crm_interaction_action', true) || (string) get_post_meta($activity_id, '_crm_interaction_channel', true))
					? self::interaction_action_label(
						(string) get_post_meta($activity_id, '_crm_interaction_action', true),
						(string) get_post_meta($activity_id, '_crm_interaction_kind', true),
						(string) get_post_meta($activity_id, '_crm_interaction_channel', true)
					)
					: (self::interaction_kind_labels()[(string) get_post_meta($activity_id, '_crm_interaction_kind', true)] ?? 'Interaccion registrada')
			),
			'response_sent' => self::interaction_result_labels()[(string) get_post_meta($activity_id, '_crm_result', true)] ?? 'El lead respondio.',
			'task_completed' => trim(implode(' | ', array_filter(array(
				get_the_title($object_id) ?: (self::task_type_labels()[(string) get_post_meta($activity_id, '_crm_task_type', true)] ?? 'Tarea completada'),
				((string) get_post_meta($activity_id, '_crm_interaction_action', true)) ? self::interaction_action_label(
					(string) get_post_meta($activity_id, '_crm_interaction_action', true),
					'',
					''
				) : '',
				self::interaction_result_labels()[(string) get_post_meta($activity_id, '_crm_result', true)] ?? '',
				((string) get_post_meta($activity_id, '_crm_next_followup', true)) ? ('Proximo: ' . (string) get_post_meta($activity_id, '_crm_next_followup', true)) : '',
			)))),
			'task_followup_scheduled' => 'Nueva tarea para ' . ((string) get_post_meta($activity_id, '_crm_next_followup', true) ?: 'seguimiento futuro') . '.',
			'collection_reviewed' => 'Estado actualizado a ' . (self::payment_status_labels()[(string) get_post_meta($activity_id, '_crm_status', true)] ?? 'Pendiente') . '.',
			'payment_recorded' => 'Monto registrado: $' . number_format_i18n((float) get_post_meta($activity_id, '_crm_amount', true), 0),
			'stage_changed' => (self::stage_labels()[(string) get_post_meta($activity_id, '_crm_old_stage', true)] ?? 'Sin etapa') . ' -> ' . (self::stage_labels()[(string) get_post_meta($activity_id, '_crm_stage', true)] ?? 'Sin etapa'),
			'funnel_stage_changed' => self::funnel_stage_labels()[(string) get_post_meta($activity_id, '_crm_funnel_stage', true)] ?? 'Embudo actualizado.',
			'deal_won' => 'Cliente marcado como ganado.',
			'lead_reactivated' => 'Reactivado desde ' . (self::stage_labels()[(string) get_post_meta($activity_id, '_crm_from_stage', true)] ?? 'Perdido') . ' a ' . (self::stage_labels()[(string) get_post_meta($activity_id, '_crm_to_stage', true)] ?? 'Activo') . '.',
			default => '',
		};
	}

	private static function activity_context_label($activity_id) {
		$activity_id = (int) $activity_id;
		$lead_id = self::activity_related_lead_id($activity_id);
		if ($lead_id) {
			$company = (string) get_post_meta($lead_id, '_crm_company', true);
			$context = get_the_title($lead_id);
			if ($company) {
				$context .= ' | ' . $company;
			}
			return $context;
		}

		$object_id = (int) get_post_meta($activity_id, '_crm_object_id', true);
		return $object_id ? (string) get_the_title($object_id) : '';
	}

	private static function activity_note_for_item($activity_id) {
		$activity_id = (int) $activity_id;
		$action = sanitize_key((string) get_post_meta($activity_id, '_crm_action', true));
		if ('stage_changed' === $action) {
			return trim((string) get_post_meta($activity_id, '_crm_lost_reason', true));
		}
		return '';
	}

	private static function activity_target_url($activity_id) {
		$lead_id = self::activity_related_lead_id($activity_id);
		if ($lead_id) {
			return admin_url('admin.php?page=twob-crm-visual-leads&lead_id=' . $lead_id . '&q=' . rawurlencode((string) get_the_title($lead_id))) . '#lead-' . $lead_id;
		}

		$object_id = (int) get_post_meta((int) $activity_id, '_crm_object_id', true);
		return $object_id ? get_edit_post_link($object_id) : '';
	}

	private static function summarize_activity_items($activity_ids) {
		$summary = array(
			'total' => count((array) $activity_ids),
			'leads' => 0,
			'interactions' => 0,
			'stages' => 0,
			'tasks' => 0,
			'payments' => 0,
		);

		foreach ((array) $activity_ids as $activity_id) {
			$action = (string) get_post_meta((int) $activity_id, '_crm_action', true);
			$category = self::activity_category_for_action($action);
			if (isset($summary[$category])) {
				$summary[$category]++;
			}
		}

		return $summary;
	}

	private static function render_activity_timeline_item($activity_id, $args = array()) {
		$activity = get_post((int) $activity_id);
		if (! $activity || 'crm_activity' !== $activity->post_type) {
			return;
		}

		$args = wp_parse_args($args, array(
			'compact' => false,
		));

		$action = sanitize_key((string) get_post_meta($activity->ID, '_crm_action', true));
		$summary = self::activity_summary_for_item($activity->ID);
		$detail = self::activity_detail_for_item($activity->ID);
		$context = self::activity_context_label($activity->ID);
		$actor = self::activity_actor_name($activity->ID);
		$note = self::activity_note_for_item($activity->ID);
		$url = self::activity_target_url($activity->ID);
		$time_label = substr((string) $activity->post_date, 11, 5);
		$group_label = self::activity_group_labels()[self::activity_category_for_action($action)] ?? 'Todo';
		?>
		<div class="twob-timeline-item twob-activity-item">
			<div class="twob-line-1">
				<strong><?php echo esc_html($summary); ?></strong>
				<span class="twob-pill is-soft"><?php echo esc_html($time_label ?: '--:--'); ?></span>
			</div>
			<?php if ($detail) : ?><div class="twob-line-2"><?php echo esc_html($detail); ?></div><?php endif; ?>
			<?php if ($context) : ?><div class="twob-line-2"><?php echo esc_html($context); ?></div><?php endif; ?>
			<div class="twob-activity-meta">
				<span class="twob-pill is-soft"><?php echo esc_html($group_label); ?></span>
				<span class="twob-pill is-soft"><?php echo esc_html($actor); ?></span>
			</div>
			<?php if ($note && empty($args['compact'])) : ?><div class="twob-note-box"><?php echo nl2br(esc_html($note)); ?></div><?php endif; ?>
			<?php if ($url && empty($args['compact'])) : ?>
				<div class="twob-task-actions">
					<a class="button button-small" href="<?php echo esc_url($url); ?>">Abrir contexto</a>
				</div>
			<?php endif; ?>
		</div>
		<?php
	}

	private static function is_legacy_archived_lead($lead_id) {
		return 'crm_lead' === get_post_type($lead_id) && 'trash' !== get_post_status($lead_id) && (bool) get_post_meta($lead_id, '_crm_archived', true);
	}

	private static function get_trashed_leads($args = array()) {
		$defaults = array(
			'post_type' => 'crm_lead',
			'numberposts' => 120,
			'orderby' => 'date',
			'order' => 'DESC',
		);
		$args = wp_parse_args($args, $defaults);
		$limit = isset($args['numberposts']) ? (int) $args['numberposts'] : 120;

		$trash_args = $args;
		$trash_args['post_status'] = 'trash';
		unset($trash_args['meta_query']);

		$legacy_args = $args;
		$legacy_args['post_status'] = 'publish';
		$legacy_meta_query = isset($legacy_args['meta_query']) ? (array) $legacy_args['meta_query'] : array();
		$legacy_meta_query[] = array('key' => '_crm_archived', 'compare' => 'EXISTS');
		$legacy_args['meta_query'] = $legacy_meta_query;

		$leads = array();
		foreach (array_merge(get_posts($trash_args), get_posts($legacy_args)) as $lead) {
			$leads[(int) $lead->ID] = $lead;
		}
		$leads = array_values($leads);
		usort($leads, function ($a, $b) {
			$a_time = self::lead_trash_timestamp($a);
			$b_time = self::lead_trash_timestamp($b);
			if ($a_time === $b_time) {
				return (int) $b->ID <=> (int) $a->ID;
			}
			return $b_time <=> $a_time;
		});
		if ($limit > -1) {
			$leads = array_slice($leads, 0, $limit);
		}
		return $leads;
	}

	private static function lead_trash_timestamp($lead) {
		if (! $lead || empty($lead->ID)) {
			return 0;
		}
		$trash_time = (int) get_post_meta((int) $lead->ID, '_wp_trash_meta_time', true);
		if ($trash_time > 0) {
			return $trash_time;
		}
		$archived_at = (string) get_post_meta((int) $lead->ID, '_crm_archived', true);
		if ($archived_at) {
			$timestamp = strtotime($archived_at);
			if ($timestamp) {
				return (int) $timestamp;
			}
		}
		$modified = ! empty($lead->post_modified_gmt) && '0000-00-00 00:00:00' !== $lead->post_modified_gmt ? $lead->post_modified_gmt . ' UTC' : $lead->post_modified;
		$timestamp = strtotime((string) $modified);
		return $timestamp ? (int) $timestamp : 0;
	}

	private static function trashed_leads_count() {
		$counts = wp_count_posts('crm_lead');
		$native_trash = isset($counts->trash) ? (int) $counts->trash : 0;
		$legacy_archived = get_posts(array(
			'post_type' => 'crm_lead',
			'post_status' => 'publish',
			'numberposts' => -1,
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => '_crm_archived', 'compare' => 'EXISTS'),
			),
		));
		return $native_trash + count($legacy_archived);
	}

	private static function restore_lead_record($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return false;
		}
		delete_post_meta($lead_id, '_crm_archived');
		if ('trash' !== get_post_status($lead_id)) {
			return true;
		}
		return (bool) wp_untrash_post($lead_id);
	}

	private static function related_post_ids_for_lead($lead_id, $post_type, $meta_key) {
		return get_posts(array(
			'post_type' => $post_type,
			'post_status' => 'any',
			'numberposts' => -1,
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => $meta_key, 'value' => (int) $lead_id, 'compare' => '='),
			),
		));
	}

	private static function activity_ids_for_object_ids($object_ids) {
		$object_ids = array_values(array_unique(array_filter(array_map('intval', (array) $object_ids))));
		if (empty($object_ids)) {
			return array();
		}
		$meta_query = array('relation' => 'OR');
		foreach ($object_ids as $object_id) {
			$meta_query[] = array('key' => '_crm_object_id', 'value' => $object_id, 'compare' => '=');
		}

		return get_posts(array(
			'post_type' => 'crm_activity',
			'post_status' => 'any',
			'numberposts' => -1,
			'fields' => 'ids',
			'meta_query' => $meta_query,
		));
	}

	private static function permanently_delete_lead_dependencies($lead_id) {
		$lead_id = (int) $lead_id;
		if (! $lead_id) {
			return;
		}
		self::unlink_master_client_for_lead($lead_id);
		$interaction_ids = self::related_post_ids_for_lead($lead_id, 'crm_interaction', '_crm_lead_id');
		$task_ids = self::related_post_ids_for_lead($lead_id, 'crm_task', '_crm_task_lead_id');
		$payment_ids = self::related_post_ids_for_lead($lead_id, 'crm_payment', '_crm_lead_id');
		$activity_ids = self::activity_ids_for_object_ids(array_merge(array($lead_id), $interaction_ids, $task_ids, $payment_ids));

		foreach (array_merge($interaction_ids, $task_ids, $payment_ids) as $related_id) {
			wp_delete_post((int) $related_id, true);
		}
		foreach ($activity_ids as $activity_id) {
			wp_delete_post((int) $activity_id, true);
		}
	}

