	private static function settings_get() {
		$current = array_replace_recursive(self::settings_defaults(), (array) get_option(self::SETTINGS_OPTION, array()));
		$current['service_options'] = self::service_catalog();
		return $current;
	}

	private static function settings_save($raw) {
		$current = self::settings_get();
		if (isset($raw['client_types']) && is_array($raw['client_types'])) {
			$types = array();
			foreach ($raw['client_types'] as $key => $label) {
				$clean_key = sanitize_key((string) $key);
				$clean_label = sanitize_text_field((string) $label);
				if ($clean_key && $clean_label) {
					$types[$clean_key] = $clean_label;
				}
			}
			if (! empty($types)) {
				$current['client_types'] = $types;
			}
		}
		if (isset($raw['service_options']) && is_array($raw['service_options'])) {
			$services = array();
			foreach ($raw['service_options'] as $key => $label) {
				$clean_key = sanitize_key((string) $key);
				$clean_label = sanitize_text_field((string) $label);
				if ($clean_key && $clean_label) {
					$services[$clean_key] = $clean_label;
				}
			}
			if (! empty($services)) {
				$current['service_options'] = $services;
			}
		}
		if (isset($raw['contact']) && is_array($raw['contact'])) {
			$current['contact']['email'] = isset($raw['contact']['email']) ? sanitize_email((string) $raw['contact']['email']) : '';
			$current['contact']['whatsapp'] = isset($raw['contact']['whatsapp']) ? sanitize_text_field((string) $raw['contact']['whatsapp']) : '';
			$current['contact']['agenda'] = isset($raw['contact']['agenda']) ? esc_url_raw((string) $raw['contact']['agenda']) : '';
		}
		$current['service_options'] = self::service_catalog();
		update_option(self::SETTINGS_OPTION, $current);
		return $current;
	}

