	private static function prospect_sector_key_guess($sector_label, $fallback_keys = array()) {
		$sector_label = strtolower(trim((string) $sector_label));
		$fallback_keys = array_values(array_filter(array_map('sanitize_key', (array) $fallback_keys)));
		$options = self::prospect_sector_options();
		if (isset($options[$sector_label])) {
			return $sector_label;
		}

		$map = array(
			'salud_privada' => array('salud', 'clinica', 'clínica', 'medic', 'dental', 'centro médico', 'centro medico'),
			'hoteleria_turismo' => array('hotel', 'turismo', 'lodge', 'apart', 'hostal', 'resort'),
			'inmobiliaria' => array('inmobili', 'constructora', 'corredora', 'propiedad'),
			'educacion_privada' => array('educa', 'colegio', 'instituto', 'academia', 'school', 'universidad'),
			'servicios_juridicos_financieros' => array('juríd', 'jurid', 'abogado', 'legal', 'financ', 'contable', 'auditor'),
			'industria_manufactura_b2b' => array('industria', 'manufactura', 'fábrica', 'fabrica', 'b2b', 'logística', 'logistica'),
			'retail_especializado' => array('retail', 'tienda', 'ecommerce', 'e-commerce', 'comercio'),
			'gastronomia' => array('gastr', 'restaurant', 'restaurante', 'delivery', 'cocina', 'food'),
		);
		foreach ($map as $key => $needles) {
			foreach ($needles as $needle) {
				if ('' !== $sector_label && false !== strpos($sector_label, $needle)) {
					return $key;
				}
			}
		}

		return ! empty($fallback_keys) ? $fallback_keys[0] : sanitize_key($sector_label);
	}

