	private static function prospect_excluded_sector_terms() {
		$raw = self::prospect_excluded_sectors_raw();
		if ('' === $raw) {
			return array();
		}

		$terms = preg_split('/[\r\n,;]+/', strtolower($raw));
		$terms = array_values(array_unique(array_filter(array_map('trim', (array) $terms))));
		return $terms;
	}

