	private static function prospect_search_history_record($entry) {
		$history = self::prospect_search_history_get();
		array_unshift($history, $entry);
		return self::prospect_search_history_save(array_slice($history, 0, 20));
	}

	private static function prospect_search_history_increment_created($search_id, $company = '') {
		$search_id = sanitize_key((string) $search_id);
		if ('' === $search_id) {
			return;
		}

		$history = self::prospect_search_history_get();
		foreach ($history as &$entry) {
			if (($entry['search_id'] ?? '') !== $search_id) {
				continue;
			}
			$entry['created_count'] = max(0, (int) ($entry['created_count'] ?? 0)) + 1;
			if ($company) {
				$companies = isset($entry['created_companies']) && is_array($entry['created_companies']) ? $entry['created_companies'] : array();
				$companies[] = sanitize_text_field($company);
				$entry['created_companies'] = array_values(array_unique(array_filter($companies)));
			}
			break;
		}
		unset($entry);
		self::prospect_search_history_save($history);
	}

	private static function prospect_history_recent($limit = 5) {
		return array_slice(self::prospect_search_history_get(), 0, max(1, (int) $limit));
	}

	private static function prospect_normalize_domain($raw_url) {
		$url = trim((string) $raw_url);
		if ('' === $url) {
			return '';
		}
		if (! preg_match('#^https?://#i', $url)) {
			$url = 'https://' . ltrim($url, '/');
		}
		$parts = wp_parse_url($url);
		$host = strtolower((string) ($parts['host'] ?? ''));
		if ('' === $host) {
			return '';
		}
		return preg_replace('/^www\./', '', $host);
	}

	private static function prospect_existing_domains() {
		$lead_ids = get_posts(array(
			'post_type' => 'crm_lead',
			'post_status' => array('publish', 'draft', 'pending', 'future', 'private', 'trash'),
			'numberposts' => -1,
			'fields' => 'ids',
		));

		$domains = array();
		foreach ((array) $lead_ids as $lead_id) {
			$domain = self::prospect_normalize_domain((string) get_post_meta((int) $lead_id, '_crm_website_url', true));
			if ($domain) {
				$domains[$domain] = true;
			}
		}

		return $domains;
	}

	private static function prospect_domain_exists($domain) {
		$domain = strtolower(trim((string) $domain));
		if ('' === $domain) {
			return false;
		}
		$existing = self::prospect_existing_domains();
		return ! empty($existing[$domain]);
	}

	private static function anthropic_request_payload($payload, $api_key = '', $timeout = 20) {
		$resolved_key = '' !== trim((string) $api_key) ? trim((string) $api_key) : self::anthropic_api_key_get();
		return TwoB_CRM_Dani_Message_Engine_Module::request_payload($payload, $resolved_key, $timeout);
	}

	private static function anthropic_request_text_from_payload($payload, $api_key = '', $timeout = 20) {
		$data = self::anthropic_request_payload($payload, $api_key, $timeout);
		if (is_wp_error($data)) {
			return $data;
		}
		return TwoB_CRM_Dani_Message_Engine_Module::extract_text($data);
	}

	private static function prospect_json_from_text($text) {
		$text = trim((string) $text);
		if ('' === $text) {
			return new WP_Error('prospect_empty_response', 'Claude no devolvió contenido utilizable.');
		}

		$candidates = array($text);
		if (preg_match('/```(?:json)?\s*(\{.*\})\s*```/is', $text, $matches)) {
			$candidates[] = trim((string) $matches[1]);
		}
		if (preg_match('/(\{(?:[^{}]|(?1))*\})/s', $text, $matches)) {
			$candidates[] = trim((string) $matches[1]);
		}

		foreach ($candidates as $candidate) {
			$data = json_decode((string) $candidate, true);
			if (is_array($data) && isset($data['prospectos']) && is_array($data['prospectos'])) {
				return $data;
			}
		}

		return new WP_Error('prospect_invalid_json', 'Claude no devolvió un JSON válido para la búsqueda.');
	}

