    }
  ]
}
PROMPT;
	}

	private static function prospect_is_excluded_candidate($candidate, $excluded_terms) {
		$haystack = strtolower(
			implode(
				' ',
				array_filter(array(
					(string) ($candidate['empresa'] ?? ''),
					(string) ($candidate['sector'] ?? ''),
					(string) ($candidate['zona'] ?? ''),
				))
			)
		);
		foreach ((array) $excluded_terms as $term) {
			$term = strtolower(trim((string) $term));
			if ($term && false !== strpos($haystack, $term)) {
				return true;
			}
		}
		return false;
	}

	private static function prospect_candidate_prepare($candidate) {
		$candidate = is_array($candidate) ? $candidate : array();
		$url = esc_url_raw((string) ($candidate['url'] ?? ''));
		$domain = self::prospect_normalize_domain($url);
		$signals = isset($candidate['señales_capacidad']) && is_array($candidate['señales_capacidad']) ? array_values(array_filter(array_map('sanitize_text_field', $candidate['señales_capacidad']))) : array();
		$issues = isset($candidate['señales_problemas']) && is_array($candidate['señales_problemas']) ? array_values(array_filter(array_map('sanitize_text_field', $candidate['señales_problemas']))) : array();
		return array(
			'empresa' => sanitize_text_field((string) ($candidate['empresa'] ?? '')),
			'url' => $url,
			'domain' => $domain,
			'sector' => sanitize_text_field((string) ($candidate['sector'] ?? '')),
			'zona' => sanitize_text_field((string) ($candidate['zona'] ?? '')),
			'capacidad_economica' => in_array(strtolower((string) ($candidate['capacidad_economica'] ?? 'media')), array('alta', 'media'), true) ? strtolower((string) ($candidate['capacidad_economica'] ?? 'media')) : 'media',
			'señales_capacidad' => $signals,
			'decisor_nombre' => sanitize_text_field((string) ($candidate['decisor_nombre'] ?? '')),
			'decisor_cargo' => sanitize_text_field((string) ($candidate['decisor_cargo'] ?? '')),
			'decisor_linkedin_busqueda' => sanitize_text_field((string) ($candidate['decisor_linkedin_busqueda'] ?? '')),
			'email_sitio' => sanitize_email((string) ($candidate['email_sitio'] ?? '')),
			'telefono' => sanitize_text_field((string) ($candidate['telefono'] ?? '')),
			'linkedin_empresa' => esc_url_raw((string) ($candidate['linkedin_empresa'] ?? '')),
			'tiene_wordpress' => ! empty($candidate['tiene_wordpress']),
			'señales_problemas' => $issues,
		);
	}

	private static function prospect_search_candidates($sector_labels, $zone_label, $quantity, $retry = true) {
		if ('' === self::anthropic_api_key_get()) {
			return new WP_Error('anthropic_missing_key', 'Configura primero la API key de Anthropic en Configuración.');
		}

		$payload = array(
			'model' => TwoB_CRM_Dani_Message_Engine_Module::anthropic_model_name(),
			'max_tokens' => 4000,
			'tools' => array(
				array(
					'type' => 'web_search_20250305',
					'name' => 'web_search',
					'max_uses' => 5,
				),
			),
			'messages' => array(
				array(
					'role' => 'user',
					'content' => self::prospect_search_prompt($sector_labels, $zone_label, $quantity),
				),
			),
		);

		$text = self::anthropic_request_text_from_payload($payload, '', 35);
		if (is_wp_error($text)) {
			return $text;
		}

		$parsed = self::prospect_json_from_text($text);
		if (is_wp_error($parsed) && $retry) {
			return self::prospect_search_candidates($sector_labels, $zone_label, $quantity, false);
		}
		return $parsed;
	}

	private static function prospect_scan_counts($scan_payload) {
		$definitions = array(
			'speed_mobile_slow' => 'critical',
			'ssl_expired' => 'critical',
			'dkim_missing' => 'critical',
			'speed_desktop_slow' => 'high',
			'no_cache' => 'medium',
			'no_https' => 'high',
			'spf_missing' => 'high',
			'dmarc_missing' => 'medium',
			'images_heavy' => 'medium',
			'no_meta' => 'medium',
			'no_h1' => 'medium',
			'errors_404' => 'high',
		);
		$counts = array('critical' => 0, 'high' => 0, 'medium' => 0);
		foreach ($definitions as $key => $severity) {
			if (! empty($scan_payload['auto_checks'][$key])) {
				$counts[$severity]++;
			}
		}
		return $counts;
	}

	private static function prospect_hallazgo_prompt($prospect, $scan_payload) {
		$empresa = (string) ($prospect['empresa'] ?? '');
		$url = (string) ($prospect['url'] ?? '');
		$sector = (string) ($prospect['sector'] ?? 'No especificado');
		$signals = implode(', ', array_filter((array) ($prospect['señales_problemas'] ?? array())));
		$ssl = ! empty($scan_payload['ssl_ok']) ? 'sí' : 'no';
		$dkim = ! empty($scan_payload['dkim_ok']) ? 'sí' : 'no';
		$spf = ! empty($scan_payload['spf_ok']) ? 'sí' : 'no';
		$images = empty($scan_payload['auto_checks']['images_heavy']) ? 'sí' : 'no';
		$meta = empty($scan_payload['auto_checks']['no_meta']) ? 'sí' : 'no';

		return <<<PROMPT
Eres el asistente técnico de 2B Consulting Chile.

Datos del sitio auditado:
Empresa: {$empresa}
URL: {$url}
Sector: {$sector}
Velocidad móvil: {$scan_payload['speed_mobile']}/100
Velocidad escritorio: {$scan_payload['speed_desktop']}/100
SSL activo: {$ssl}
dKIM configurado: {$dkim}
SPF configurado: {$spf}
Imágenes optimizadas: {$images}
Meta description: {$meta}
Señales de problemas detectadas: {$signals}

Genera el hallazgo técnico en este formato exacto:

HALLAZGO: [el problema más crítico en 1 línea, en lenguaje de negocio, no técnico]
IMPACTO: [qué significa para el negocio de una empresa de {$sector} específicamente]

Solo estas dos líneas. Sin explicaciones.
PROMPT;
	}

	private static function prospect_linkedin_message_prompt($prospect, $hallazgo, $impacto) {
		$empresa = (string) ($prospect['empresa'] ?? '');
		$cargo = (string) ($prospect['decisor_cargo'] ?? 'no especificado');
		$sector = (string) ($prospect['sector'] ?? 'No especificado');
		$hallazgo = trim((string) $hallazgo);
		$impacto = trim((string) $impacto);

		return <<<PROMPT
Eres el asistente de Dani Guerrero, directora comercial de 2B Consulting Chile.

2B hace diagnósticos técnicos de sitios web. Precio: \$350.000 + IVA. No somos agencia web.

Datos del prospecto:
Empresa: {$empresa}
Cargo del decisor: {$cargo}
Sector: {$sector}
Hallazgo detectado: {$hallazgo}
Impacto: {$impacto}
Canal: LinkedIn

Genera el mensaje de primer contacto LinkedIn.
Máximo 280 caracteres.
Usar el hallazgo como gancho principal.
Hablar del impacto en el negocio, no del problema técnico.
Adaptar el tono al cargo: {$cargo}
Solo el mensaje, sin explicaciones.
PROMPT;
	}

	private static function prospect_parse_hallazgo($text) {
		$text = trim((string) $text);
		$hallazgo = '';
		$impacto = '';
		foreach (preg_split('/\r\n|\r|\n/', $text) as $line) {
			$line = trim((string) $line);
			if (0 === stripos($line, 'HALLAZGO:')) {
				$hallazgo = trim(substr($line, strlen('HALLAZGO:')));
			} elseif (0 === stripos($line, 'IMPACTO:')) {
				$impacto = trim(substr($line, strlen('IMPACTO:')));
			}
		}
		if ('' === $hallazgo && '' === $impacto) {
			$hallazgo = $text;
		}
		return array(
			'hallazgo' => $hallazgo,
			'impacto' => $impacto,
			'combined' => trim(
				($hallazgo ? 'HALLAZGO: ' . $hallazgo : '') .
				(($hallazgo && $impacto) ? "\n" : '') .
				($impacto ? 'IMPACTO: ' . $impacto : '')
			),
		);
	}

	private static function prospect_search_results_payload($candidates, $selected_sector_labels, $zone_label, $quantity, $started_at, $selected_sector_keys = array()) {
		$existing_domains = self::prospect_existing_domains();
		$excluded_terms = self::prospect_excluded_sector_terms();
		$time_limit = 55;
		$results = array();
		$audited = 0;
		$seen_domains = array();

		foreach ((array) $candidates as $candidate) {
			$prepared = self::prospect_candidate_prepare($candidate);
			if ('' === $prepared['empresa'] || '' === $prepared['url'] || '' === $prepared['domain']) {
				continue;
			}
			if (self::prospect_is_excluded_candidate($prepared, $excluded_terms)) {
				continue;
			}
			if (! empty($existing_domains[$prepared['domain']])) {
				continue;
			}
			if (isset($seen_domains[$prepared['domain']])) {
				continue;
			}
			if (isset($candidate['tiene_wordpress']) && empty($prepared['tiene_wordpress'])) {
				continue;
			}

			if ((microtime(true) - $started_at) >= $time_limit) {
				break;
			}

			$scan = self::scan_site_payload($prepared['url'], self::pagespeed_api_key_get());
			$manual_required = false;
			if (is_wp_error($scan)) {
				$manual_required = true;
				$scan = array(
					'speed_mobile' => 0,
					'speed_desktop' => 0,
					'ssl_ok' => false,
					'https_redirect' => false,
					'spf_ok' => false,
					'dkim_ok' => false,
					'dmarc_ok' => false,
					'auto_checks' => array(),
					'errors' => array($scan->get_error_message()),
				);
			} elseif (! empty($scan['errors'])) {
				$manual_required = true;
			}

			$counts = self::prospect_scan_counts($scan);
			$site_status = 'ok';
			if ($counts['critical'] > 0) {
				$site_status = 'critico';
			} elseif ($counts['high'] > 0) {
				$site_status = 'moderado';
			} elseif ($counts['medium'] > 0) {
				$site_status = 'leve';
			}

			$hallazgo_raw = self::anthropic_request_message(self::prospect_hallazgo_prompt($prepared, $scan), '', 300);
			$hallazgo_error = null;
			if (is_wp_error($hallazgo_raw)) {
				$hallazgo_error = $hallazgo_raw;
				$hallazgo_raw = "HALLAZGO: El sitio necesita una revisión técnica priorizada antes de seguir escalando inversión digital.\nIMPACTO: Puede estar perdiendo oportunidades comerciales sin visibilidad clara del problema.";
				$manual_required = true;
				$scan['errors'][] = $hallazgo_error instanceof WP_Error ? $hallazgo_error->get_error_message() : 'Hallazgo generado con fallback.';
			}
			$hallazgo = self::prospect_parse_hallazgo((string) $hallazgo_raw);
			$message = self::anthropic_request_message(self::prospect_linkedin_message_prompt($prepared, $hallazgo['hallazgo'], $hallazgo['impacto']), '', 200);
			if (is_wp_error($message)) {
				$message = 'Hola, revisé ' . $prepared['empresa'] . ' y detecté una señal técnica que podría estar filtrando oportunidades antes de que lleguen a contacto. Si te hace sentido, te muestro el hallazgo en 15 minutos.';
				$manual_required = true;
			}
			$sector_key = self::prospect_sector_key_guess((string) $prepared['sector'], $selected_sector_keys);

			$audited++;
			$results[] = array(
				'empresa' => $prepared['empresa'],
				'url' => $prepared['url'],
				'domain' => $prepared['domain'],
				'sector' => $prepared['sector'],
				'sectorKey' => $sector_key,
				'zona' => $prepared['zona'],
				'capacidadEconomica' => $prepared['capacidad_economica'],
				'senalesCapacidad' => array_values((array) $prepared['señales_capacidad']),
				'decisorNombre' => $prepared['decisor_nombre'],
				'decisorCargo' => $prepared['decisor_cargo'],
				'decisorBusquedaLinkedin' => $prepared['decisor_linkedin_busqueda'],
				'email' => $prepared['email_sitio'],
				'telefono' => $prepared['telefono'],
				'linkedinEmpresa' => $prepared['linkedin_empresa'],
				'tieneWordPress' => ! empty($prepared['tiene_wordpress']),
				'senalesProblemas' => array_values((array) $prepared['señales_problemas']),
				'hallazgo' => $hallazgo['hallazgo'],
				'impacto' => $hallazgo['impacto'],
				'hallazgoCompleto' => $hallazgo['combined'] ?: trim((string) $hallazgo_raw),
				'mensajeLinkedin' => trim((string) $message),
				'speedMobile' => (int) ($scan['speed_mobile'] ?? 0),
				'speedDesktop' => (int) ($scan['speed_desktop'] ?? 0),
				'sslOk' => ! empty($scan['ssl_ok']),
				'dkimOk' => ! empty($scan['dkim_ok']),
				'spfOk' => ! empty($scan['spf_ok']),
				'dmarcOk' => ! empty($scan['dmarc_ok']),
				'autoChecks' => (array) ($scan['auto_checks'] ?? array()),
				'scanErrors' => array_values(array_filter(array_map('sanitize_text_field', (array) ($scan['errors'] ?? array())))),
				'siteStatus' => $site_status,
				'criticalCount' => (int) $counts['critical'],
				'highCount' => (int) $counts['high'],
				'mediumCount' => (int) $counts['medium'],
				'manualAuditRequired' => $manual_required,
			);
			$seen_domains[$prepared['domain']] = true;
		}

		$search_id = sanitize_key('ps_' . wp_generate_password(12, false, false));
		$history_entry = array(
			'search_id' => $search_id,
			'created_at' => current_time('mysql'),
			'sector_labels' => array_values(array_filter(array_map('sanitize_text_field', (array) $selected_sector_labels))),
			'zone' => sanitize_text_field((string) $zone_label),
			'requested_count' => max(1, (int) $quantity),
			'found_count' => count($results),
			'created_count' => 0,
			'companies' => array_values(array_map(function ($item) {
				return (string) ($item['empresa'] ?? '');
			}, $results)),
		);
		self::prospect_search_history_record($history_entry);

		return array(
			'search_id' => $search_id,
			'prospects' => $results,
			'audited_count' => $audited,
			'history' => self::prospect_history_recent(5),
		);
	}

