	private static function normalize_temperature($temperature, $allow_legacy = true) {
		$temperature = sanitize_key((string) $temperature);
		$allowed = $allow_legacy ? array('hot', 'warm', 'cold', 'lost') : array('hot', 'warm', 'cold');
		return in_array($temperature, $allowed, true) ? $temperature : '';
	}

	private static function lead_temperature($lead_id, $force_sync = false) {
		$lead_id = (int) $lead_id;
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return 'warm';
		}

		$current = self::normalize_temperature((string) get_post_meta($lead_id, '_crm_temperature', true));
		if (self::is_temperature_manual($lead_id)) {
			return $current ?: 'warm';
		}
		if ($force_sync || ! $current) {
			return self::update_temperature($lead_id, true);
		}

		$recommended = self::normalize_temperature(self::determine_temperature($lead_id), false);
		if (! $recommended) {
			$recommended = self::temperature_seed_for_origin_channel(
				(string) get_post_meta($lead_id, '_crm_origin_channel', true),
				(string) get_post_meta($lead_id, '_crm_stage', true)
			);
		}
		if ($recommended !== $current) {
			return self::update_temperature($lead_id, true);
		}

		return $current;
	}

	private static function temperature_badge_meta($temperature) {
		$temperature = self::normalize_temperature($temperature);
		return match ($temperature) {
			'hot' => array('label' => self::temperature_labels()['hot'], 'class' => 'is-danger'),
			'cold' => array('label' => self::temperature_labels()['cold'], 'class' => 'is-cool'),
			'lost' => array('label' => self::temperature_labels()['lost'], 'class' => 'is-soft'),
			default => array('label' => self::temperature_labels()['warm'], 'class' => 'is-warning'),
		};
	}

	private static function truncate_text($text, $length = 60) {
		$text = trim(preg_replace('/\s+/', ' ', wp_strip_all_tags((string) $text)));
		$length = max(1, (int) $length);
		if ('' === $text) {
			return '';
		}
		if (function_exists('mb_strlen') && function_exists('mb_substr')) {
			if (mb_strlen($text) <= $length) {
				return $text;
			}
			return rtrim((string) mb_substr($text, 0, max(1, $length - 3))) . '...';
		}
		if (strlen($text) <= $length) {
			return $text;
		}
		return rtrim(substr($text, 0, max(1, $length - 3))) . '...';
	}

