	private static function is_alliance_task($task_id) {
		$task_id = (int) $task_id;
		if (! $task_id || 'crm_task' !== get_post_type($task_id)) {
			return false;
		}

		return isset(self::alliance_task_type_labels()[sanitize_key((string) get_post_meta($task_id, 'twob_task_tipo', true))]);
	}

	private static function alliance_record_defaults() {
		return array(
			'id' => '',
			'name' => '',
			'website_url' => '',
			'contact_name' => '',
			'contact_role' => '',
			'agency_type' => 'other',
			'status' => 'contacted',
			'first_contact_date' => '',
			'closed_diagnostics' => 0,
			'notes' => '',
			'leads_referidos' => 0,
			'last_referred_at' => '',
			'last_contact_at' => '',
			'last_activity_at' => '',
			'twob_alianza_mensaje_ia' => '',
			'twob_alianza_mensaje_ia_fecha' => 0,
			'twob_alianza_brief_short' => '',
			'twob_alianza_brief_email' => '',
			'twob_alianza_brief_fecha' => 0,
			'created_at' => '',
			'updated_at' => '',
		);
	}

	private static function sanitize_alliance_record($raw, $existing = array()) {
		$existing = wp_parse_args(is_array($existing) ? $existing : array(), self::alliance_record_defaults());
		$id = isset($raw['id']) ? sanitize_key((string) $raw['id']) : '';
		if (! $id) {
			$id = isset($existing['id']) ? sanitize_key((string) $existing['id']) : '';
		}
		if (! $id) {
			$id = 'alliance_' . strtolower(wp_generate_password(8, false, false));
		}

		$first_contact_date = self::sanitize_date_input(isset($raw['first_contact_date']) ? wp_unslash($raw['first_contact_date']) : ($existing['first_contact_date'] ?? ''), true, 'Fecha de primer contacto');
		if (is_wp_error($first_contact_date)) {
			$first_contact_date = '';
		}

		$last_referred_at = self::sanitize_date_input(isset($raw['last_referred_at']) ? wp_unslash($raw['last_referred_at']) : ($existing['last_referred_at'] ?? ''), true, 'Ultimo referido');
		if (is_wp_error($last_referred_at)) {
			$last_referred_at = '';
		}

		$last_contact_at = self::sanitize_date_input(isset($raw['last_contact_at']) ? wp_unslash($raw['last_contact_at']) : ($existing['last_contact_at'] ?? ''), true, 'Ultimo contacto');
		if (is_wp_error($last_contact_at)) {
			$last_contact_at = '';
		}

		$last_activity_at = isset($raw['last_activity_at']) ? sanitize_text_field((string) wp_unslash($raw['last_activity_at'])) : (string) ($existing['last_activity_at'] ?? '');
		if ('' === $last_activity_at) {
			$last_activity_at = current_time('mysql');
		}

		return array(
			'id' => $id,
			'name' => sanitize_text_field((string) ($raw['name'] ?? '')),
			'website_url' => esc_url_raw((string) ($raw['website_url'] ?? '')),
			'contact_name' => sanitize_text_field((string) ($raw['contact_name'] ?? '')),
			'contact_role' => sanitize_text_field((string) ($raw['contact_role'] ?? '')),
			'agency_type' => self::sanitize_alliance_type((string) ($raw['agency_type'] ?? ($existing['agency_type'] ?? 'other'))),
			'status' => self::sanitize_alliance_status((string) ($raw['status'] ?? ($existing['status'] ?? 'contacted'))),
			'first_contact_date' => $first_contact_date,
			'closed_diagnostics' => max(0, (int) ($raw['closed_diagnostics'] ?? ($existing['closed_diagnostics'] ?? 0))),
			'notes' => sanitize_textarea_field((string) ($raw['notes'] ?? '')),
			'leads_referidos' => max(0, (int) ($raw['leads_referidos'] ?? ($existing['leads_referidos'] ?? 0))),
			'last_referred_at' => $last_referred_at,
			'last_contact_at' => $last_contact_at,
			'last_activity_at' => $last_activity_at,
			'twob_alianza_mensaje_ia' => sanitize_textarea_field((string) ($raw['twob_alianza_mensaje_ia'] ?? ($existing['twob_alianza_mensaje_ia'] ?? ''))),
			'twob_alianza_mensaje_ia_fecha' => max(0, (int) ($raw['twob_alianza_mensaje_ia_fecha'] ?? ($existing['twob_alianza_mensaje_ia_fecha'] ?? 0))),
			'twob_alianza_brief_short' => sanitize_textarea_field((string) ($raw['twob_alianza_brief_short'] ?? ($existing['twob_alianza_brief_short'] ?? ''))),
			'twob_alianza_brief_email' => sanitize_textarea_field((string) ($raw['twob_alianza_brief_email'] ?? ($existing['twob_alianza_brief_email'] ?? ''))),
			'twob_alianza_brief_fecha' => max(0, (int) ($raw['twob_alianza_brief_fecha'] ?? ($existing['twob_alianza_brief_fecha'] ?? 0))),
			'created_at' => (string) ($existing['created_at'] ?: current_time('mysql')),
			'updated_at' => current_time('mysql'),
		);
	}

	private static function alliances_get() {
		$raw_items = (array) get_option(self::ALLIANCES_OPTION, array());
		$alliances = array();
		foreach ($raw_items as $raw_item) {
			if (! is_array($raw_item)) {
				continue;
			}
			$item = self::sanitize_alliance_record($raw_item, $raw_item);
			if (! $item['name']) {
				continue;
			}
			$alliances[] = $item;
		}
		usort($alliances, function ($left, $right) {
			return strcasecmp((string) ($left['name'] ?? ''), (string) ($right['name'] ?? ''));
		});
		return $alliances;
	}

	private static function alliances_save($alliances) {
		$clean = array();
		foreach ((array) $alliances as $alliance) {
			if (! is_array($alliance)) {
				continue;
			}
			$item = self::sanitize_alliance_record($alliance, $alliance);
			if (! $item['name']) {
				continue;
			}
			$clean[] = $item;
		}
		update_option(self::ALLIANCES_OPTION, array_values($clean), false);
		return $clean;
	}

	private static function alliance_find($alliance_id) {
		$alliance_id = sanitize_key((string) $alliance_id);
		if (! $alliance_id) {
			return array();
		}
		foreach (self::alliances_get() as $alliance) {
			if ($alliance_id === sanitize_key((string) ($alliance['id'] ?? ''))) {
				return $alliance;
			}
		}
		return array();
	}

	private static function alliance_referred_leads_count($alliance_name) {
		$alliance_name = self::normalize_search_text((string) $alliance_name);
		if ('' === $alliance_name) {
			return 0;
		}

		$lead_ids = get_posts(array(
			'post_type' => 'crm_lead',
			'post_status' => 'publish',
			'numberposts' => -1,
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => '_crm_alliance_source', 'compare' => 'EXISTS'),
			),
		));

		$count = 0;
		foreach ($lead_ids as $lead_id) {
			$current = self::normalize_search_text((string) get_post_meta((int) $lead_id, '_crm_alliance_source', true));
			if ($current && $current === $alliance_name) {
				$count++;
			}
		}

		return $count;
	}

	private static function alliance_commission_total($closed_diagnostics) {
		return max(0, (int) $closed_diagnostics) * self::ALLIANCE_COMMISSION_PER_DIAGNOSTIC;
	}

	private static function alliance_datetime_to_timestamp($value) {
		$value = trim((string) $value);
		if ('' === $value) {
			return 0;
		}

		$timestamp = strtotime($value);
		return $timestamp ? (int) $timestamp : 0;
	}

	private static function alliance_record_save($record) {
		$record = self::sanitize_alliance_record($record, $record);
		$alliances = self::alliances_get();
		$found = false;
		foreach ($alliances as $index => $alliance) {
			if (sanitize_key((string) ($alliance['id'] ?? '')) === sanitize_key((string) ($record['id'] ?? ''))) {
				$alliances[$index] = $record;
				$found = true;
				break;
			}
		}
		if (! $found) {
			$alliances[] = $record;
		}
		self::alliances_save($alliances);
		return self::alliance_find((string) ($record['id'] ?? ''));
	}

	private static function alliance_record_update($alliance_id, $changes = array()) {
		$current = self::alliance_find($alliance_id);
		if (empty($current)) {
			return array();
		}
		$merged = array_merge($current, (array) $changes);
		return self::alliance_record_save($merged);
	}

	private static function alliance_touch($alliance_id, $activity_when = '', $contact_when = null) {
		$current = self::alliance_find($alliance_id);
		if (empty($current)) {
			return array();
		}
		$activity_when = trim((string) $activity_when);
		if ('' === $activity_when) {
			$activity_when = current_time('mysql');
		}
		$changes = array(
			'last_activity_at' => $activity_when,
		);
		if (null !== $contact_when) {
			$contact_when = trim((string) $contact_when);
			$changes['last_contact_at'] = $contact_when;
		}
		return self::alliance_record_update($alliance_id, $changes);
	}

	private static function alliance_referred_leads($alliance_name, $args = array()) {
		$alliance_name = self::normalize_search_text((string) $alliance_name);
		if ('' === $alliance_name) {
			return array();
		}

		$args = wp_parse_args($args, array(
			'stage' => '',
			'unpaid_only' => false,
			'fields' => 'ids',
		));
		$lead_ids = get_posts(array(
			'post_type' => 'crm_lead',
			'post_status' => 'publish',
			'numberposts' => -1,
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => '_crm_alliance_source', 'compare' => 'EXISTS'),
			),
		));

		$matches = array();
		foreach ($lead_ids as $lead_id) {
			$lead_id = (int) $lead_id;
			$current = self::normalize_search_text((string) get_post_meta($lead_id, '_crm_alliance_source', true));
			if (! $current || $current !== $alliance_name) {
				continue;
			}
			if (! empty($args['stage']) && self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true)) !== sanitize_key((string) $args['stage'])) {
				continue;
			}
			if (! empty($args['unpaid_only']) && 'true' === (string) get_post_meta($lead_id, 'twob_comision_pagada', true)) {
				continue;
			}
			$matches[] = ('posts' === $args['fields']) ? get_post($lead_id) : $lead_id;
		}

		return array_values(array_filter($matches));
	}

	private static function alliance_latest_referred_day($alliance_name) {
		$latest = '';
		foreach (self::alliance_referred_leads($alliance_name, array('fields' => 'ids')) as $lead_id) {
			$lead = get_post((int) $lead_id);
			if (! $lead) {
				continue;
			}
			$day = substr((string) $lead->post_date, 0, 10);
			if ($day && ($latest === '' || $day > $latest)) {
				$latest = $day;
			}
		}
		return $latest;
	}

	private static function alliance_latest_referred_company($alliance_name) {
		$latest_post = null;
		foreach (self::alliance_referred_leads($alliance_name, array('fields' => 'ids')) as $lead_id) {
			$lead = get_post((int) $lead_id);
			if (! $lead) {
				continue;
			}
			if (! $latest_post || strtotime((string) $lead->post_date) > strtotime((string) $latest_post->post_date)) {
				$latest_post = $lead;
			}
		}
		if (! $latest_post) {
			return '';
		}
		return (string) get_post_meta((int) $latest_post->ID, '_crm_company', true) ?: (string) $latest_post->post_title;
	}

	private static function alliance_pending_commission_leads($alliance_name) {
		return self::alliance_referred_leads($alliance_name, array(
			'stage' => 'won',
			'unpaid_only' => true,
			'fields' => 'ids',
		));
	}

	private static function alliance_task_auto_key($alliance_id, $task_type, $suffix = '') {
		$key = 'alliance_' . sanitize_key((string) $alliance_id) . '_' . sanitize_key((string) $task_type);
		if ('' !== $suffix) {
			$key .= '_' . sanitize_key((string) $suffix);
		}
		return $key;
	}

	private static function create_alliance_task_once($alliance, $task_type, $title, $due, $auto_key, $args = array()) {
		$alliance = self::sanitize_alliance_record((array) $alliance, (array) $alliance);
		if (empty($alliance['id']) || empty($alliance['name'])) {
			return 0;
		}

		$args = wp_parse_args($args, array(
			'description' => '',
			'priority' => 'medium',
			'assignee' => 'dani',
			'lead_id' => 0,
			'message' => '',
			'day' => 0,
			'sequence_slot' => '',
			'postpone_count' => 0,
		));

		return self::create_auto_task_once(
			0,
			$title,
			$task_type,
			self::sanitize_task_priority((string) $args['priority']),
			$due,
			$auto_key,
			array(
				'description' => (string) $args['description'],
				'assignee' => self::sanitize_task_assignee((string) $args['assignee']),
				'category' => 'operational',
				'relation' => 'internal',
				'pipeline_stage' => 'alliance',
				'meta' => array(
					'twob_task_tipo' => sanitize_key((string) $task_type),
					'twob_task_alianza_id' => (string) $alliance['id'],
					'_crm_task_alliance_id' => (string) $alliance['id'],
					'_crm_task_alliance_name' => (string) $alliance['name'],
					'_crm_task_lead_id' => (int) $args['lead_id'],
					'twob_task_dia' => (int) $args['day'],
					'twob_task_estado' => 'pendiente',
					'twob_task_postergaciones' => max(0, (int) $args['postpone_count']),
					'twob_task_sequence_slot' => sanitize_key((string) $args['sequence_slot']),
				),
			)
		);
	}

	private static function alliance_tasks($alliance_id, $task_types = array(), $open_only = false) {
		$alliance_id = sanitize_key((string) $alliance_id);
		if ('' === $alliance_id) {
			return array();
		}
		$meta_query = array(
			array('key' => 'twob_task_alianza_id', 'value' => $alliance_id, 'compare' => '='),
		);
		if (! empty($task_types)) {
			$meta_query[] = array(
				'key' => 'twob_task_tipo',
				'value' => array_values(array_map('sanitize_key', (array) $task_types)),
				'compare' => 'IN',
			);
		}
		if ($open_only) {
			$meta_query[] = array(
				'relation' => 'OR',
				array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
				array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
				array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
			);
		}
		return get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => -1,
			'meta_key' => '_crm_task_due',
			'orderby' => 'meta_value',
			'order' => 'ASC',
			'meta_query' => $meta_query,
		));
	}

	private static function alliance_next_pending_task($alliance_id, $task_types = array()) {
		$tasks = self::alliance_tasks($alliance_id, $task_types, true);
		return ! empty($tasks[0]) ? $tasks[0] : null;
	}

	private static function cancel_alliance_pending_tasks($alliance_id, $task_types = array(), $note = '') {
		$alliance_id = sanitize_key((string) $alliance_id);
		if ('' === $alliance_id) {
			return 0;
		}
		$note = trim((string) $note) ?: 'La alianza cambió de estado y esta secuencia ya no corresponde.';
		$tasks = self::alliance_tasks($alliance_id, $task_types, true);
		$closed = 0;
		foreach ($tasks as $task) {
			$task_id = (int) $task->ID;
			update_post_meta($task_id, '_crm_task_status', 'done');
			update_post_meta($task_id, '_crm_task_completed_at', current_time('mysql'));
			update_post_meta($task_id, '_crm_task_completion_note', sanitize_textarea_field($note));
			update_post_meta($task_id, 'twob_task_estado', 'cancelada');
			$closed++;
		}
		return $closed;
	}

	private static function ensure_alliance_initial_tasks($alliance, $today = '') {
		$alliance = self::sanitize_alliance_record((array) $alliance, (array) $alliance);
		if (empty($alliance['id']) || empty($alliance['name'])) {
			return array();
		}
		$today = $today ?: current_time('Y-m-d');
		$tasks = array();
		$tasks[] = self::create_alliance_task_once(
			$alliance,
			'alianza_contacto',
			'Contactar agencia — ' . (string) $alliance['name'],
			$today,
			self::alliance_task_auto_key((string) $alliance['id'], 'alianza_contacto', 'd0'),
			array(
				'priority' => 'high',
				'day' => 0,
				'sequence_slot' => 'd0',
				'description' => 'Primer contacto para proponer la alianza y la comisión del 10%.',
			)
		);
		$tasks[] = self::create_alliance_task_once(
			$alliance,
			'alianza_seguimiento',
			'Seguimiento alianza — ' . (string) $alliance['name'],
			self::add_chile_business_days($today, 3),
			self::alliance_task_auto_key((string) $alliance['id'], 'alianza_seguimiento', 'd3'),
			array(
				'priority' => 'medium',
				'day' => 3,
				'sequence_slot' => 'd3',
				'description' => 'Segundo contacto para retomar la propuesta de alianza si aún no hay respuesta.',
			)
		);
		$tasks[] = self::create_alliance_task_once(
			$alliance,
			'alianza_seguimiento',
			'Último intento — ' . (string) $alliance['name'],
			self::add_chile_business_days($today, 7),
			self::alliance_task_auto_key((string) $alliance['id'], 'alianza_seguimiento', 'd7'),
			array(
				'priority' => 'medium',
				'day' => 7,
				'sequence_slot' => 'd7',
				'description' => 'Último intento antes de mover la alianza a Sin respuesta.',
			)
		);
		return array_values(array_filter(array_map('intval', $tasks)));
	}

	private static function alliance_last_contact_day($alliance) {
		$alliance = self::sanitize_alliance_record((array) $alliance, (array) $alliance);
		foreach (array('last_contact_at', 'first_contact_date', 'updated_at', 'created_at') as $field) {
			$value = trim((string) ($alliance[$field] ?? ''));
			if ('' === $value) {
				continue;
			}
			if (preg_match('/^\d{4}-\d{2}-\d{2}$/', $value)) {
				return $value;
			}
			$timestamp = self::alliance_datetime_to_timestamp($value);
			if ($timestamp > 0) {
				return wp_date('Y-m-d', $timestamp);
			}
		}
		return '';
	}

	private static function alliance_last_activity_label($alliance) {
		$alliance = self::sanitize_alliance_record((array) $alliance, (array) $alliance);
		$timestamp = self::alliance_datetime_to_timestamp((string) ($alliance['last_activity_at'] ?? ''));
		if ($timestamp <= 0) {
			$timestamp = self::alliance_datetime_to_timestamp((string) ($alliance['updated_at'] ?? ''));
		}
		return $timestamp > 0 ? self::elapsed_label_from_unix($timestamp) : 'sin actividad';
	}

