	private static function alliance_task_message_text($task_id) {
		$task_id = (int) $task_id;
		$task_type = sanitize_key((string) get_post_meta($task_id, 'twob_task_tipo', true));
		$alliance_id = sanitize_key((string) get_post_meta($task_id, 'twob_task_alianza_id', true));
		$alliance = self::alliance_find($alliance_id);
		if (empty($alliance)) {
			return trim((string) get_post_field('post_content', $task_id));
		}

		if (in_array($task_type, array('alianza_contacto', 'alianza_seguimiento'), true)) {
			$message = trim((string) ($alliance['twob_alianza_mensaje_ia'] ?? ''));
			if ($message) {
				return $message;
			}
			return self::alliance_contact_message_fallback($alliance);
		}

		$message = trim((string) get_post_meta($task_id, 'twob_task_mensaje_ia', true));
		if ($message) {
			return $message;
		}

		return trim((string) get_post_field('post_content', $task_id));
	}

