		return TwoB_CRM_Dani_Message_Engine_Module::generate_with_fallback($prompt, $fallback, self::anthropic_api_key_get(), $max_tokens);
	}

	private static function alliance_pdf_escape($text) {
		$text = str_replace(array('\\', '(', ')'), array('\\\\', '\\(', '\\)'), (string) $text);
		$text = preg_replace('/[^\x20-\x7E]/', ' ', $text);
		return (string) $text;
	}

	private static function alliance_pdf_wrap_lines($text, $max_chars = 74) {
		$text = trim((string) $text);
		if ('' === $text) {
			return array('');
		}
		$wrapped = wordwrap($text, max(24, (int) $max_chars), "\n", true);
		return array_values(array_filter(array_map('trim', explode("\n", $wrapped)), static function ($line) {
			return '' !== $line;
		}));
	}

	private static function alliance_brief_pdf_base64($alliance) {
		$alliance = self::sanitize_alliance_record((array) $alliance, (array) $alliance);
		$today = current_time('Ymd');
		$ops = array();
		$ops[] = '0.10 0.10 0.10 rg 0 0 595 842 re f';
		$ops[] = '1 1 1 rg';
		$ops[] = 'BT /F2 28 Tf 48 796 Td (2B.) Tj ET';
		$ops[] = '0.91 0.63 0.13 rg';
		$ops[] = 'BT /F2 18 Tf 108 798 Td (Brief de alianza) Tj ET';
		$ops[] = '1 1 1 rg';
		$ops[] = 'BT /F1 11 Tf 48 776 Td (' . self::alliance_pdf_escape('Agencia: ' . (string) $alliance['name']) . ') Tj ET';
		$ops[] = 'BT /F1 11 Tf 48 760 Td (' . self::alliance_pdf_escape('Fecha: ' . $today) . ') Tj ET';

		$y = 724;
		foreach (self::alliance_brief_sections() as $title => $body) {
			$ops[] = '0.91 0.63 0.13 rg';
			$ops[] = 'BT /F2 14 Tf 48 ' . $y . ' Td (' . self::alliance_pdf_escape($title) . ') Tj ET';
			$y -= 18;
			$ops[] = '1 1 1 rg';
			foreach (self::alliance_pdf_wrap_lines($body, 78) as $line) {
				$ops[] = 'BT /F1 11 Tf 48 ' . $y . ' Td (' . self::alliance_pdf_escape($line) . ') Tj ET';
				$y -= 14;
			}
			$y -= 10;
		}
		$ops[] = '0.72 0.72 0.72 rg';
		$ops[] = 'BT /F1 10 Tf 48 36 Td (2bconsulting.cl) Tj ET';
		$content = implode("\n", $ops);
		$len = strlen($content);

		$pdf = "%PDF-1.4\n";
		$offsets = array();
		$objects = array(
			"1 0 obj << /Type /Catalog /Pages 2 0 R >> endobj\n",
			"2 0 obj << /Type /Pages /Count 1 /Kids [3 0 R] >> endobj\n",
			"3 0 obj << /Type /Page /Parent 2 0 R /MediaBox [0 0 595 842] /Resources << /Font << /F1 4 0 R /F2 5 0 R >> >> /Contents 6 0 R >> endobj\n",
			"4 0 obj << /Type /Font /Subtype /Type1 /BaseFont /Helvetica >> endobj\n",
			"5 0 obj << /Type /Font /Subtype /Type1 /BaseFont /Helvetica-Bold >> endobj\n",
			"6 0 obj << /Length {$len} >> stream\n{$content}\nendstream endobj\n",
		);
		foreach ($objects as $object) {
			$offsets[] = strlen($pdf);
			$pdf .= $object;
		}
		$xref = strlen($pdf);
		$pdf .= "xref\n0 7\n0000000000 65535 f \n";
		foreach ($offsets as $offset) {
			$pdf .= sprintf("%010d 00000 n \n", $offset);
		}
		$pdf .= "trailer << /Size 7 /Root 1 0 R >>\nstartxref\n{$xref}\n%%EOF";
		return base64_encode($pdf);
	}

	private static function alliance_has_pending_task($alliance_id, $task_type) {
