	}

	private static function alliance_alert_meta($alliance, $today = '') {
		$alliance = self::sanitize_alliance_record((array) $alliance, (array) $alliance);
		$today = $today ?: current_time('Y-m-d');
		$status = sanitize_key((string) ($alliance['status'] ?? ''));
		$referred_count = self::alliance_referred_leads_count((string) ($alliance['name'] ?? ''));
		$last_referred_day = self::alliance_latest_referred_day((string) ($alliance['name'] ?? ''));
		$last_contact_day = self::alliance_last_contact_day($alliance);
		$pending_commissions = self::alliance_pending_commission_leads((string) ($alliance['name'] ?? ''));

		$orange = false;
		$red = false;
		if ('active' === $status) {
			if (empty($pending_commissions)) {
				if (! $last_referred_day || self::days_between_dates($last_referred_day, $today) >= 30) {
					$orange = true;
				}
			} else {
				$orange = true;
			}
			if ($last_contact_day && self::days_between_dates($last_contact_day, $today) >= 60) {
				$red = true;
			}
		}

		return array(
			'level' => $red ? 'red' : ($orange ? 'orange' : ''),
			'referred_count' => $referred_count,
			'last_referred_day' => $last_referred_day,
			'last_contact_day' => $last_contact_day,
			'pending_commissions' => $pending_commissions,
		);
	}

	private static function alliance_task_context_line($task_id) {
		$task_id = (int) $task_id;
		$task_type = sanitize_key((string) get_post_meta($task_id, 'twob_task_tipo', true));
		$alliance_id = sanitize_key((string) get_post_meta($task_id, 'twob_task_alianza_id', true));
		$alliance = self::alliance_find($alliance_id);
		if (empty($alliance)) {
			return 'Seguimiento de alianza pendiente.';
