			'alianza_comision' => 'Hay una comisión pendiente por un diagnóstico ganado vía referido.',
			'alianza_reactivacion' => 'La alianza sigue activa, pero no ha referido clientes en 30+ días.',
			'alianza_checkin' => 'No hay contacto reciente con esta alianza y conviene hacer check-in.',
			'alianza_contacto' => 'Primer contacto comercial para proponer la alianza y el 10% de comisión.',
			'alianza_seguimiento' => 'Seguimiento a la propuesta de alianza si aún no hubo respuesta.',
			default => 'Tarea operativa de alianza pendiente.',
		};
	}

	private static function alliance_dashboard_due_tasks($today = '', $limit = 5) {
		$today = $today ?: current_time('Y-m-d');
		$scope = self::current_crm_user_scope();
		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => 40,
			'meta_key' => '_crm_task_due',
			'orderby' => 'meta_value',
			'order' => 'ASC',
			'meta_query' => array(
				array(
					'key' => 'twob_task_tipo',
					'value' => array('alianza_contacto', 'alianza_seguimiento', 'alianza_reactivacion', 'alianza_comision', 'alianza_checkin'),
					'compare' => 'IN',
				),
				array('key' => '_crm_task_due', 'value' => $today, 'compare' => '<=', 'type' => 'DATE'),
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
		));
		$tasks = array_values(array_filter($tasks, function ($task) use ($scope) {
			return self::task_matches_current_scope((int) $task->ID, $scope);
		}));
		usort($tasks, function ($left, $right) {
			$left_type = sanitize_key((string) get_post_meta((int) $left->ID, 'twob_task_tipo', true));
			$right_type = sanitize_key((string) get_post_meta((int) $right->ID, 'twob_task_tipo', true));
			if ('alianza_comision' === $left_type && 'alianza_comision' !== $right_type) {
				return -1;
			}
			if ('alianza_comision' !== $left_type && 'alianza_comision' === $right_type) {
				return 1;
			}
			$left_due = (string) get_post_meta((int) $left->ID, '_crm_task_due', true);
			$right_due = (string) get_post_meta((int) $right->ID, '_crm_task_due', true);
			return strcmp($left_due, $right_due);
		});
		return array_slice($tasks, 0, max(1, (int) $limit));
	}

	private static function alliance_complete_task($task_id, $note = '') {
		$task_id = (int) $task_id;
		$task = self::get_valid_crm_post($task_id, 'crm_task');
		if (! $task || ! self::is_alliance_task($task_id)) {
			return new WP_Error('invalid_alliance_task', 'No se pudo identificar la tarea de alianza.');
		}
		if (! self::current_user_can_edit_crm_post($task_id)) {
			return new WP_Error('forbidden', 'No tienes permisos para completar esta tarea.');
		}

		$task_type = sanitize_key((string) get_post_meta($task_id, 'twob_task_tipo', true));
		$alliance_id = sanitize_key((string) get_post_meta($task_id, 'twob_task_alianza_id', true));
		$alliance = self::alliance_find($alliance_id);
		$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);

		update_post_meta($task_id, '_crm_task_status', 'done');
		update_post_meta($task_id, '_crm_task_completed_at', current_time('mysql'));
		update_post_meta($task_id, 'twob_task_estado', 'completada');
		update_post_meta($task_id, '_crm_task_completion_note', sanitize_textarea_field((string) $note));
		self::sync_google_task_status_prefix($task_id, 'done');

		if (! empty($alliance)) {
			self::alliance_touch($alliance_id, current_time('mysql'), current_time('mysql'));
		}
		if ('alianza_comision' === $task_type && $lead_id) {
			update_post_meta($lead_id, 'twob_comision_pagada', 'true');
		}

		return array(
			'task_id' => $task_id,
			'message' => 'Tarea de alianza completada.',
		);
	}

	private static function alliance_postpone_task($task_id, $today = '') {
		$task_id = (int) $task_id;
		$task = self::get_valid_crm_post($task_id, 'crm_task');
		if (! $task || ! self::is_alliance_task($task_id)) {
			return new WP_Error('invalid_alliance_task', 'No se pudo identificar la tarea de alianza.');
		}
		if (! self::current_user_can_edit_crm_post($task_id)) {
			return new WP_Error('forbidden', 'No tienes permisos para postergar esta tarea.');
		}

		$today = $today ?: current_time('Y-m-d');
		$postpones = max(0, (int) get_post_meta($task_id, 'twob_task_postergaciones', true));
		if ($postpones >= 2) {
			update_post_meta($task_id, '_crm_task_status', 'done');
			update_post_meta($task_id, 'twob_task_estado', 'ignorada');
			update_post_meta($task_id, '_crm_task_completion_note', 'Ignorada tras 3 intentos de postergación.');
			self::sync_google_task_status_prefix($task_id, 'done');
			return array(
				'task_id' => $task_id,
				'ignored' => true,
				'message' => 'La tarea quedó ignorada después del tercer intento de postergación.',
			);
		}

		$new_due = self::add_chile_business_days($today, 7);
		update_post_meta($task_id, '_crm_task_due', $new_due);
		update_post_meta($task_id, 'twob_task_postergaciones', $postpones + 1);
		update_post_meta($task_id, 'twob_task_estado', 'pendiente');
		return array(
			'task_id' => $task_id,
			'due' => $new_due,
			'message' => 'Tarea postergada 7 días hábiles.',
		);
	}

