			'client_id' => '',
			'client_secret' => '',
			'calendar_id' => 'primary',
			'workday_start_hour' => 9,
			'max_tasks_per_day' => 12,
			'sync_paused' => 0,
			'pause_days' => '',
		);
	}

	private static function google_settings_get() {
		return wp_parse_args((array) get_option(self::GOOGLE_SETTINGS_OPTION, array()), self::google_settings_defaults());
	}

	private static function google_settings_save($raw) {
		$current = self::google_settings_get();
		$current['client_id'] = isset($raw['client_id']) ? sanitize_text_field((string) $raw['client_id']) : $current['client_id'];
		$current['client_secret'] = isset($raw['client_secret']) ? sanitize_text_field((string) $raw['client_secret']) : $current['client_secret'];
		$current['calendar_id'] = isset($raw['calendar_id']) ? sanitize_text_field((string) $raw['calendar_id']) : $current['calendar_id'];
		$current['workday_start_hour'] = isset($raw['workday_start_hour']) ? max(6, min(20, (int) $raw['workday_start_hour'])) : $current['workday_start_hour'];
		$current['max_tasks_per_day'] = isset($raw['max_tasks_per_day']) ? max(1, min(40, (int) $raw['max_tasks_per_day'])) : $current['max_tasks_per_day'];
		$current['sync_paused'] = ! empty($raw['sync_paused']) ? 1 : 0;
		$current['pause_days'] = isset($raw['pause_days']) ? sanitize_text_field((string) $raw['pause_days']) : $current['pause_days'];
		update_option(self::GOOGLE_SETTINGS_OPTION, $current);
		return $current;
	}

	private static function google_token_get($user_id = 0) {
		$user_id = $user_id ? (int) $user_id : get_current_user_id();
		if (! $user_id) {
			return array();
		}
		return (array) get_user_meta($user_id, self::GOOGLE_TOKEN_OPTION, true);
	}

	private static function google_token_save($token, $user_id = 0) {
		$user_id = $user_id ? (int) $user_id : get_current_user_id();
		if (! $user_id) {
			return;
		}
		update_user_meta($user_id, self::GOOGLE_TOKEN_OPTION, (array) $token);
	}

	private static function google_token_clear($user_id = 0) {
		$user_id = $user_id ? (int) $user_id : get_current_user_id();
		if (! $user_id) {
			return;
		}
		delete_user_meta($user_id, self::GOOGLE_TOKEN_OPTION);
	}

