	public static function google_connect() {
		if (! self::user_can_manage_google()) {
			wp_die('Sin permisos.');
		}
		check_admin_referer('twob_crm_google_connect');
		$settings = self::google_settings_get();
		if (empty($settings['client_id']) || empty($settings['client_secret'])) {
			wp_safe_redirect(admin_url('admin.php?page=twob-crm-visual-calendar&google_msg=missing_credentials'));
			exit;
		}
		$state = wp_create_nonce('twob_crm_google_oauth');
		$params = array(
			'client_id' => $settings['client_id'],
			'redirect_uri' => self::google_redirect_uri(),
			'response_type' => 'code',
			'scope' => 'https://www.googleapis.com/auth/calendar.events',
			'access_type' => 'offline',
			'prompt' => 'consent',
			'state' => $state,
		);
		$url = 'https://accounts.google.com/o/oauth2/v2/auth?' . http_build_query($params, '', '&', PHP_QUERY_RFC3986);
		wp_safe_redirect($url);
		exit;
	}

	public static function google_callback() {
		if (! self::user_can_manage_google()) {
			wp_die('Sin permisos.');
		}
		$state = isset($_GET['state']) ? sanitize_text_field(wp_unslash($_GET['state'])) : '';
		if (! wp_verify_nonce($state, 'twob_crm_google_oauth')) {
			wp_safe_redirect(admin_url('admin.php?page=twob-crm-visual-calendar&google_msg=invalid_state'));
			exit;
		}
		if (isset($_GET['error'])) {
			self::google_set_last_error('Google OAuth error: ' . sanitize_text_field(wp_unslash($_GET['error'])));
			wp_safe_redirect(admin_url('admin.php?page=twob-crm-visual-calendar&google_msg=oauth_error'));
			exit;
		}
		$code = isset($_GET['code']) ? sanitize_text_field(wp_unslash($_GET['code'])) : '';
		if (! $code) {
			wp_safe_redirect(admin_url('admin.php?page=twob-crm-visual-calendar&google_msg=missing_code'));
			exit;
		}

		$settings = self::google_settings_get();
		$response = wp_remote_post('https://oauth2.googleapis.com/token', array(
			'timeout' => 20,
			'body' => array(
				'code' => $code,
				'client_id' => $settings['client_id'],
				'client_secret' => $settings['client_secret'],
				'redirect_uri' => self::google_redirect_uri(),
				'grant_type' => 'authorization_code',
			),
		));
		if (is_wp_error($response)) {
			self::google_set_last_error($response->get_error_message());
			wp_safe_redirect(admin_url('admin.php?page=twob-crm-visual-calendar&google_msg=token_error'));
			exit;
		}
		$data = json_decode((string) wp_remote_retrieve_body($response), true);
		if (empty($data['access_token'])) {
			self::google_set_last_error('No se recibio access_token.');
			wp_safe_redirect(admin_url('admin.php?page=twob-crm-visual-calendar&google_msg=token_error'));
			exit;
		}
		$token = array(
			'access_token' => sanitize_text_field((string) $data['access_token']),
			'refresh_token' => isset($data['refresh_token']) ? sanitize_text_field((string) $data['refresh_token']) : '',
			'expires_at' => time() + max(60, (int) ($data['expires_in'] ?? 3600)),
		);
		$old = self::google_token_get();
		if (empty($token['refresh_token']) && ! empty($old['refresh_token'])) {
			$token['refresh_token'] = $old['refresh_token'];
		}
		self::google_token_save($token);
		self::google_clear_last_error();
		wp_safe_redirect(admin_url('admin.php?page=twob-crm-visual-calendar&google_msg=connected'));
		exit;
	}

	public static function google_disconnect() {
		if (! self::user_can_manage_google()) {
			wp_die('Sin permisos.');
		}
		check_admin_referer('twob_crm_google_disconnect');
		self::google_token_clear();
		self::google_clear_last_error();
		wp_safe_redirect(admin_url('admin.php?page=twob-crm-visual-calendar&google_msg=disconnected'));
		exit;
	}

	public static function google_sync_now() {
		if (! self::user_can_manage_google()) {
			wp_die('Sin permisos.');
		}
		check_admin_referer('twob_crm_google_sync_now');
		$today = current_time('Y-m-d');
		$target_days = array_unique(array(
			$today,
			self::google_shift_day($today, '+1 day'),
		));
		if (! self::google_is_connected(get_current_user_id())) {
			$result = new WP_Error('twob_google_not_connected', 'Conecta tu cuenta Google para sincronizar.');
		} else {
			$push_result = 0;
			foreach ($target_days as $target_day) {
				$day_result = self::google_sync_user(get_current_user_id(), $target_day);
				if (is_wp_error($day_result)) {
					$push_result = $day_result;
					break;
				}
				$push_result += (int) $day_result;
			}
			$pull_result = self::google_sync_calendar_to_crm_user(get_current_user_id(), 14, 60);
			if (is_wp_error($push_result)) {
				$result = $push_result;
			} elseif (is_wp_error($pull_result)) {
				$result = $pull_result;
			} else {
				$result = array(
					'pushed' => (int) $push_result,
					'pulled' => (int) $pull_result,
				);
			}
		}
		$code = is_wp_error($result) ? 'sync_error' : 'sync_ok';
		$args = array('page' => 'twob-crm-visual-calendar', 'google_msg' => $code);
		if (! is_wp_error($result)) {
			$args['google_pushed'] = (int) $result['pushed'];
			$args['google_pulled'] = (int) $result['pulled'];
		}
		wp_safe_redirect(add_query_arg($args, admin_url('admin.php')));
		exit;
	}

	private static function google_get_access_token($user_id = 0) {
		$token = self::google_token_get($user_id);
		if (empty($token['access_token'])) {
			return '';
		}
		if (! empty($token['expires_at']) && time() < ((int) $token['expires_at'] - 60)) {
			return (string) $token['access_token'];
		}
		if (empty($token['refresh_token'])) {
			return '';
		}
		$settings = self::google_settings_get();
		$response = wp_remote_post('https://oauth2.googleapis.com/token', array(
			'timeout' => 20,
			'body' => array(
				'client_id' => $settings['client_id'],
				'client_secret' => $settings['client_secret'],
				'refresh_token' => $token['refresh_token'],
				'grant_type' => 'refresh_token',
			),
		));
		if (is_wp_error($response)) {
			self::google_set_last_error($response->get_error_message(), $user_id);
			return '';
		}
		$data = json_decode((string) wp_remote_retrieve_body($response), true);
		if (empty($data['access_token'])) {
			self::google_set_last_error('No se pudo refrescar el token.', $user_id);
			return '';
		}
		$token['access_token'] = sanitize_text_field((string) $data['access_token']);
		$token['expires_at'] = time() + max(60, (int) ($data['expires_in'] ?? 3600));
		self::google_token_save($token, $user_id);
		return $token['access_token'];
	}

	private static function google_api_request($method, $path, $body = null, $user_id = 0) {
		$access_token = self::google_get_access_token($user_id);
		if (! $access_token) {
			return new WP_Error('twob_google_no_token', 'No hay token Google activo.');
		}
		$url = 'https://www.googleapis.com/calendar/v3' . $path;
		$args = array(
			'method' => strtoupper($method),
			'timeout' => 20,
			'headers' => array(
				'Authorization' => 'Bearer ' . $access_token,
				'Content-Type' => 'application/json',
			),
		);
		if (null !== $body) {
			$args['body'] = wp_json_encode($body);
		}
		$response = wp_remote_request($url, $args);
		if (is_wp_error($response)) {
			self::google_set_last_error($response->get_error_message(), $user_id);
			return $response;
		}
		$code = (int) wp_remote_retrieve_response_code($response);
		$data = json_decode((string) wp_remote_retrieve_body($response), true);
		if ($code < 200 || $code >= 300) {
			$msg = ! empty($data['error']['message']) ? $data['error']['message'] : 'Error Google API.';
			self::google_set_last_error($msg, $user_id);
			return new WP_Error('twob_google_api_error', $msg, array('code' => $code, 'body' => $data));
		}
		self::google_clear_last_error($user_id);
		return $data;
	}

	private static function google_connected_user_ids() {
		$users = get_users(array(
			'meta_key' => self::GOOGLE_TOKEN_OPTION,
			'number' => -1,
			'fields' => 'ids',
		));
		$ids = array();
		foreach ((array) $users as $user_id) {
			if (self::google_is_connected((int) $user_id)) {
				$ids[] = (int) $user_id;
			}
		}
		return $ids;
	}

	private static function google_user_assignee($user_id) {
		$user = get_userdata((int) $user_id);
		if (! $user) {
			return 'dani';
		}
		$haystack = strtolower(trim(((string) $user->display_name) . ' ' . ((string) $user->user_login)));
		return false !== strpos($haystack, 'renata') ? 'renata' : 'dani';
	}

	private static function google_event_private_props($event) {
		if (empty($event['extendedProperties']['private']) || ! is_array($event['extendedProperties']['private'])) {
			return array();
		}
		return $event['extendedProperties']['private'];
	}

	private static function google_timezone() {
		if (function_exists('wp_timezone')) {
			return wp_timezone();
		}
		$timezone = wp_timezone_string();
		return new DateTimeZone($timezone ? $timezone : 'UTC');
	}

	private static function google_local_timestamp($date, $time = '00:00:00') {
		$date = trim((string) $date);
		$time = trim((string) $time);
		if (! $date) {
			return 0;
		}
		if (! preg_match('/^\d{2}:\d{2}(:\d{2})?$/', $time)) {
			$time = '00:00:00';
		}
		if (5 === strlen($time)) {
			$time .= ':00';
		}
		$datetime = date_create_immutable($date . ' ' . $time, self::google_timezone());
		return $datetime ? (int) $datetime->getTimestamp() : 0;
	}

	private static function google_rfc3339($timestamp) {
		$timestamp = (int) $timestamp;
		if (! $timestamp) {
			return '';
		}
		return wp_date('c', $timestamp, self::google_timezone());
	}

	private static function google_shift_day($date, $modifier) {
		$date = trim((string) $date);
		$modifier = trim((string) $modifier);
		if (! $date || ! $modifier) {
			return $date;
		}
		$datetime = date_create_immutable($date . ' 00:00:00', self::google_timezone());
		if (! $datetime) {
			return $date;
		}
		$shifted = $datetime->modify($modifier);
		return $shifted ? $shifted->format('Y-m-d') : $date;
	}

	private static function google_strip_crm_prefix($summary) {
		$summary = trim((string) $summary);
		$summary = preg_replace('/^\[OK\]\s*/', '', $summary);
		$summary = preg_replace('/^CRM\s*-\s*/i', '', $summary);
		return trim((string) $summary);
	}

	private static function google_event_meeting_url($event) {
		if (! empty($event['hangoutLink'])) {
			return esc_url_raw((string) $event['hangoutLink']);
		}
		if (! empty($event['conferenceData']['entryPoints']) && is_array($event['conferenceData']['entryPoints'])) {
			foreach ($event['conferenceData']['entryPoints'] as $entry) {
				if (! empty($entry['uri'])) {
					return esc_url_raw((string) $entry['uri']);
				}
			}
		}
		return '';
	}

	private static function google_event_slot($event) {
		$start_date_time = isset($event['start']['dateTime']) ? (string) $event['start']['dateTime'] : '';
		$end_date_time = isset($event['end']['dateTime']) ? (string) $event['end']['dateTime'] : '';
		$start_date = isset($event['start']['date']) ? (string) $event['start']['date'] : '';

		if ($start_date_time && $end_date_time) {
			$start_dt = date_create_immutable($start_date_time);
			$end_dt = date_create_immutable($end_date_time);
			if ($start_dt && $end_dt) {
				$start_local = $start_dt->setTimezone(self::google_timezone());
				$end_local = $end_dt->setTimezone(self::google_timezone());
				$start_ts = (int) $start_local->getTimestamp();
				$end_ts = (int) $end_local->getTimestamp();
				if ($end_ts > $start_ts) {
				return array(
						'due' => $start_local->format('Y-m-d'),
						'start_time' => $start_local->format('H:i'),
					'duration' => max(15, min(240, (int) round(($end_ts - $start_ts) / 60))),
					'has_time' => true,
				);
			}
			}
		}

		if ($start_date) {
			return array(
				'due' => $start_date,
				'start_time' => '',
				'duration' => 30,
				'has_time' => false,
			);
		}

		return array(
			'due' => '',
			'start_time' => '',
			'duration' => 30,
			'has_time' => false,
		);
	}

	private static function google_event_description_for_task($event) {
		$description = trim((string) ($event['description'] ?? ''));
		$link = ! empty($event['htmlLink']) ? esc_url_raw((string) $event['htmlLink']) : '';
		if ($link) {
			$description .= ($description ? "\n\n" : '') . 'Google Calendar: ' . $link;
		}
		return trim($description);
	}

	private static function google_detect_task_type_from_event($event) {
		$summary = strtolower((string) ($event['summary'] ?? ''));
		$description = strtolower((string) ($event['description'] ?? ''));
		$location = strtolower((string) ($event['location'] ?? ''));
		$meeting_url = strtolower((string) self::google_event_meeting_url($event));

		if (
			false !== strpos($summary, 'reunion') ||
			false !== strpos($summary, 'meeting') ||
			false !== strpos($summary, 'llamada') ||
			false !== strpos($summary, 'call') ||
			false !== strpos($description, 'meet.google.com') ||
			false !== strpos($meeting_url, 'meet.google.com') ||
			false !== strpos($location, 'zoom') ||
			false !== strpos($location, 'meet')
		) {
			return 'meeting';
		}

		if (false !== strpos($summary, 'hosting') || false !== strpos($summary, 'dominio') || false !== strpos($summary, 'vps')) {
			return 'hosting_review';
		}

		if (false !== strpos($summary, 'cobro') || false !== strpos($summary, 'pago') || false !== strpos($summary, 'factura')) {
			return 'collection';
		}

		if (false !== strpos($summary, 'linkedin') || false !== strpos($summary, 'contenido')) {
			return 'content_creation';
		}

		return 'other';
	}

	private static function google_detect_priority_from_event($event, $due) {
		$summary = strtolower((string) ($event['summary'] ?? ''));
		$today = current_time('Y-m-d');
		if (false !== strpos($summary, 'urgente') || false !== strpos($summary, 'critico') || false !== strpos($summary, 'crítico')) {
			return 'high';
		}
		if ($due && $due <= $today) {
			return 'high';
		}
		return 'medium';
	}

	private static function google_find_task_by_event($event_id, $user_id) {
		$event_id = trim((string) $event_id);
		$user_id = (int) $user_id;
		if (! $event_id || ! $user_id) {
			return 0;
		}
		$posts = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => 1,
			'meta_query' => array(
				array('key' => '_crm_google_event_id_user_' . $user_id, 'value' => $event_id, 'compare' => '='),
			),
			'fields' => 'ids',
		));
		return ! empty($posts[0]) ? (int) $posts[0] : 0;
	}

	private static function google_find_lead_by_followup_event($event_id, $user_id) {
		$event_id = trim((string) $event_id);
		$user_id = (int) $user_id;
		if (! $event_id || ! $user_id) {
			return 0;
		}
		$posts = get_posts(array(
			'post_type' => 'crm_lead',
			'post_status' => 'publish',
			'numberposts' => 1,
			'meta_query' => array(
				array('key' => '_crm_google_followup_event_id_user_' . $user_id, 'value' => $event_id, 'compare' => '='),
			),
			'fields' => 'ids',
		));
		return ! empty($posts[0]) ? (int) $posts[0] : 0;
	}

	private static function google_mark_event_meta($post_id, $user_id, $event_id, $event_day, $event_link, $event_updated, $followup = false) {
		$suffix = $followup ? '_crm_google_followup_' : '_crm_google_';
		update_post_meta($post_id, $suffix . 'event_id_user_' . (int) $user_id, sanitize_text_field((string) $event_id));
		update_post_meta($post_id, $suffix . 'event_day_user_' . (int) $user_id, sanitize_text_field((string) $event_day));
		update_post_meta($post_id, $suffix . 'event_link_user_' . (int) $user_id, esc_url_raw((string) $event_link));
		update_post_meta($post_id, $suffix . 'event_updated_user_' . (int) $user_id, sanitize_text_field((string) $event_updated));
	}

	private static function google_update_task_from_event($task_id, $event, $user_id, $external_source = false) {
		$slot = self::google_event_slot($event);
		$summary = self::google_strip_crm_prefix((string) ($event['summary'] ?? ''));
		$status = (string) ($event['status'] ?? 'confirmed');
		$meeting_url = self::google_event_meeting_url($event);
		$location = sanitize_text_field((string) ($event['location'] ?? ''));
		$event_updated = sanitize_text_field((string) ($event['updated'] ?? ''));
		$stored_updated = (string) get_post_meta($task_id, '_crm_google_event_updated_user_' . (int) $user_id, true);

		if ($event_updated && $stored_updated && $event_updated === $stored_updated) {
			return (int) $task_id;
		}

		if ('cancelled' === $status) {
			update_post_meta($task_id, '_crm_task_status', 'done');
			self::google_mark_event_meta(
				$task_id,
				$user_id,
				(string) ($event['id'] ?? ''),
				(string) ($slot['due'] ?? ''),
				(string) ($event['htmlLink'] ?? ''),
				$event_updated,
				false
			);
			return (int) $task_id;
		}

		self::$google_sync_context = true;
		wp_update_post(array(
			'ID' => (int) $task_id,
			'post_title' => $summary ?: 'Evento Google',
			'post_content' => $external_source ? self::google_event_description_for_task($event) : (string) get_post_field('post_content', $task_id),
		));
		self::$google_sync_context = false;

		update_post_meta($task_id, '_crm_task_due', (string) $slot['due']);
		update_post_meta($task_id, '_crm_task_start_time', (string) $slot['start_time']);
		update_post_meta($task_id, '_crm_task_duration', (int) $slot['duration']);
		update_post_meta($task_id, '_crm_task_meeting_url', $meeting_url);
		update_post_meta($task_id, '_crm_task_meeting_location', $location);
		if ('done' !== (string) get_post_meta($task_id, '_crm_task_status', true)) {
			update_post_meta($task_id, '_crm_task_status', 'pending');
		}
		if ($external_source) {
			update_post_meta($task_id, '_crm_task_type', self::google_detect_task_type_from_event($event));
			update_post_meta($task_id, '_crm_task_category', self::task_category_for_type((string) get_post_meta($task_id, '_crm_task_type', true)));
			update_post_meta($task_id, '_crm_task_priority', self::google_detect_priority_from_event($event, (string) $slot['due']));
		}

		self::google_mark_event_meta(
			$task_id,
			$user_id,
			(string) ($event['id'] ?? ''),
			(string) ($slot['due'] ?? ''),
			(string) ($event['htmlLink'] ?? ''),
			$event_updated,
			false
		);
		return (int) $task_id;
	}

	private static function google_create_task_from_event($event, $user_id) {
		$slot = self::google_event_slot($event);
		if (empty($slot['due'])) {
			return 0;
		}

		$task_type = self::google_detect_task_type_from_event($event);
		$task_id = wp_insert_post(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'post_title' => self::google_strip_crm_prefix((string) ($event['summary'] ?? '')) ?: 'Evento Google',
			'post_content' => self::google_event_description_for_task($event),
			'meta_input' => array(
				'_crm_task_due' => (string) $slot['due'],
				'_crm_task_status' => 'pending',
				'_crm_task_lead_id' => 0,
				'_crm_task_type' => $task_type,
				'_crm_task_priority' => self::google_detect_priority_from_event($event, (string) $slot['due']),
				'_crm_task_start_time' => (string) $slot['start_time'],
				'_crm_task_duration' => (int) $slot['duration'],
				'_crm_task_meeting_url' => self::google_event_meeting_url($event),
				'_crm_task_meeting_location' => sanitize_text_field((string) ($event['location'] ?? '')),
				'_crm_task_category' => self::task_category_for_type($task_type),
				'_crm_task_relation' => 'internal',
				'_crm_task_assignee' => self::google_user_assignee($user_id),
				'_crm_task_pipeline_stage' => '',
				'_crm_task_recurrence' => 'none',
				'_crm_google_origin' => 'google_calendar',
			),
		));

		if (! $task_id || is_wp_error($task_id)) {
			return 0;
		}

		self::google_mark_event_meta(
			(int) $task_id,
			$user_id,
			(string) ($event['id'] ?? ''),
			(string) ($slot['due'] ?? ''),
			(string) ($event['htmlLink'] ?? ''),
			(string) ($event['updated'] ?? ''),
			false
		);

		return (int) $task_id;
	}

	private static function google_fetch_events_range($calendar_id, $start_date, $end_date, $user_id) {
		$items = array();
		$page_token = '';
		$time_min = rawurlencode(self::google_rfc3339(self::google_local_timestamp($start_date, '00:00:00')));
		$time_max = rawurlencode(self::google_rfc3339(self::google_local_timestamp($end_date, '23:59:59')));
		$base = '/calendars/' . rawurlencode((string) $calendar_id) . '/events?singleEvents=true&orderBy=updated&showDeleted=true&maxResults=250&timeMin=' . $time_min . '&timeMax=' . $time_max;

		do {
			$path = $base;
			if ($page_token) {
				$path .= '&pageToken=' . rawurlencode($page_token);
			}
			$response = self::google_api_request('GET', $path, null, $user_id);
			if (is_wp_error($response)) {
				return $response;
			}
			if (! empty($response['items']) && is_array($response['items'])) {
				$items = array_merge($items, $response['items']);
			}
			$page_token = ! empty($response['nextPageToken']) ? (string) $response['nextPageToken'] : '';
		} while ($page_token);

		return $items;
	}

	private static function google_sync_event_to_crm($event, $user_id) {
		$event_id = (string) ($event['id'] ?? '');
		if (! $event_id) {
			return false;
		}

		$private = self::google_event_private_props($event);
		$event_source = (string) ($private['twob_crm_source'] ?? '');
		$task_id = 0;

		if ('crm_task' === $event_source && ! empty($private['twob_crm_task_id'])) {
			$task_id = (int) $private['twob_crm_task_id'];
		}
		if (! $task_id) {
			$task_id = self::google_find_task_by_event($event_id, $user_id);
		}

		if ($task_id && 'crm_task' === get_post_type($task_id)) {
			self::google_update_task_from_event($task_id, $event, $user_id, 'google_calendar' === (string) get_post_meta($task_id, '_crm_google_origin', true));
			return true;
		}

		$lead_id = 0;
		if ('crm_followup' === $event_source && ! empty($private['twob_crm_lead_id'])) {
			$lead_id = (int) $private['twob_crm_lead_id'];
		}
		if (! $lead_id) {
			$lead_id = self::google_find_lead_by_followup_event($event_id, $user_id);
		}

		if ($lead_id && 'crm_lead' === get_post_type($lead_id)) {
			$slot = self::google_event_slot($event);
			$event_updated = sanitize_text_field((string) ($event['updated'] ?? ''));
			$stored_updated = (string) get_post_meta($lead_id, '_crm_google_followup_event_updated_user_' . (int) $user_id, true);
			if ($event_updated && $stored_updated && $event_updated === $stored_updated) {
				return true;
			}
			if ('cancelled' === (string) ($event['status'] ?? 'confirmed')) {
				self::set_lead_next_followup_meta($lead_id, '');
			} elseif (! empty($slot['due'])) {
				self::set_lead_next_followup_meta($lead_id, (string) $slot['due']);
			}
			self::google_mark_event_meta(
				$lead_id,
				$user_id,
				$event_id,
				(string) ($slot['due'] ?? ''),
				(string) ($event['htmlLink'] ?? ''),
				$event_updated,
				true
			);
			return true;
		}

		if ('cancelled' === (string) ($event['status'] ?? 'confirmed')) {
			return false;
		}

		return (bool) self::google_create_task_from_event($event, $user_id);
	}

	private static function google_event_reminders($item) {
		$type = isset($item['task_type']) ? (string) $item['task_type'] : '';
		$summary = isset($item['title']) ? strtolower((string) $item['title']) : '';
		$overrides = array(array('method' => 'popup', 'minutes' => 15));
		if (false !== strpos($summary, 'reunion')) {
			$overrides = array(
				array('method' => 'popup', 'minutes' => 1440),
				array('method' => 'popup', 'minutes' => 30),
			);
		} elseif ('collection' === $type) {
			$overrides = array(
				array('method' => 'popup', 'minutes' => 540),
				array('method' => 'popup', 'minutes' => 15),
			);
		} elseif ('renewal' === $type) {
			$overrides = array(array('method' => 'popup', 'minutes' => 4320));
		}
		return array('useDefault' => false, 'overrides' => $overrides);
	}

	private static function google_fetch_busy_slots($calendar_id, $target_day, $user_id) {
		$start = self::google_rfc3339(self::google_local_timestamp($target_day, '00:00:00'));
		$end = self::google_rfc3339(self::google_local_timestamp($target_day, '23:59:59'));
		$path = '/calendars/' . rawurlencode((string) $calendar_id) . '/events?singleEvents=true&orderBy=startTime&timeMin=' . rawurlencode($start) . '&timeMax=' . rawurlencode($end) . '&maxResults=250';
		$resp = self::google_api_request('GET', $path, null, $user_id);
		if (is_wp_error($resp) || empty($resp['items']) || ! is_array($resp['items'])) {
			return array();
		}
		$busy = array();
		foreach ($resp['items'] as $event) {
			if (empty($event['start']['dateTime']) || empty($event['end']['dateTime'])) {
				continue;
			}
			$busy[] = array(
				'start' => strtotime((string) $event['start']['dateTime']),
				'end' => strtotime((string) $event['end']['dateTime']),
			);
		}
		return $busy;
	}

	private static function google_find_free_slot($busy, $target_day, $start_hour, $duration_minutes) {
		$cursor = self::google_local_timestamp($target_day, sprintf('%02d:00:00', $start_hour));
		$end_of_day = self::google_local_timestamp($target_day, '20:30:00');
		$duration = max(15, (int) $duration_minutes) * 60;
		while ($cursor <= $end_of_day) {
			$slot_end = $cursor + $duration;
			$overlap = false;
			foreach ($busy as $range) {
				if ($cursor < $range['end'] && $slot_end > $range['start']) {
					$overlap = true;
					break;
				}
			}
			if (! $overlap) {
				return array($cursor, $slot_end);
			}
			$cursor += 30 * 60;
		}
		return array(self::google_local_timestamp($target_day, '20:30:00'), self::google_local_timestamp($target_day, '20:45:00'));
	}

	private static function google_resolve_item_slot($busy, $target_day, $start_hour, $duration_minutes, $start_time = '') {
		$duration_minutes = max(15, min(240, (int) $duration_minutes));
		$start_time = trim((string) $start_time);
		if ($start_time && preg_match('/^\d{2}:\d{2}$/', $start_time)) {
			$requested_start = self::google_local_timestamp($target_day, $start_time . ':00');
			if ($requested_start) {
				$requested_end = $requested_start + ($duration_minutes * 60);
				$overlap = false;
				foreach ($busy as $range) {
					if ($requested_start < $range['end'] && $requested_end > $range['start']) {
						$overlap = true;
						break;
					}
				}
				if (! $overlap) {
					return array($requested_start, $requested_end, false);
				}
				$slot_hour = max((int) $start_hour, (int) substr($start_time, 0, 2));
				list($auto_start, $auto_end) = self::google_find_free_slot($busy, $target_day, $slot_hour, $duration_minutes);
				return array($auto_start, $auto_end, true);
			}
		}
		list($auto_start, $auto_end) = self::google_find_free_slot($busy, $target_day, $start_hour, $duration_minutes);
		return array($auto_start, $auto_end, false);
	}

	private static function google_task_item($task_id) {
		$task = get_post($task_id);
		if (! $task || 'crm_task' !== $task->post_type) {
			return new WP_Error('twob_task_invalid', 'Tarea invalida.');
		}
		$due = (string) get_post_meta($task_id, '_crm_task_due', true);
		if (! $due) {
			return new WP_Error('twob_task_due_missing', 'La tarea no tiene fecha programada.');
		}
		$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
		$priority = (string) get_post_meta($task_id, '_crm_task_priority', true);
		$type = (string) get_post_meta($task_id, '_crm_task_type', true);
		$duration = absint(get_post_meta($task_id, '_crm_task_duration', true));
		$start_time = (string) get_post_meta($task_id, '_crm_task_start_time', true);
		$meeting_url = ('meeting' === $type) ? esc_url_raw((string) get_post_meta($task_id, '_crm_task_meeting_url', true)) : '';
		$meeting_location = ('meeting' === $type) ? sanitize_text_field((string) get_post_meta($task_id, '_crm_task_meeting_location', true)) : '';
		if ($duration < 15) {
			$duration = ('proposal' === $type || 'meeting' === $type) ? 30 : 15;
		}
		$duration = max(15, min(240, $duration));

		$lead_title = $lead_id ? get_the_title($lead_id) : 'Sin lead';
		$color = '8';
		if ('high' === $priority) {
			$color = '11';
		} elseif ('proposal' === $type) {
			$color = '3';
		} elseif ('collection' === $type) {
			$color = '11';
		} elseif ('renewal' === $type) {
			$color = '9';
		} elseif ('meeting' === $type) {
			$color = '10';
		} elseif ('medium' === $priority) {
			$color = '6';
		}

		$crm_link = $lead_id ? (admin_url('admin.php?page=twob-crm-visual-leads') . '#lead-' . (int) $lead_id) : admin_url('admin.php?page=twob-crm-visual-tasks');
		$description = 'Lead: ' . $lead_title . "\nTipo: " . (self::task_type_labels()[$type] ?? 'Tarea') . "\nVer CRM: " . $crm_link;
		if ($meeting_url) {
			$description .= "\nEnlace reunion: " . $meeting_url;
		}
		if ($meeting_location) {
			$description .= "\nLugar: " . $meeting_location;
		}

		return array(
			'source_type' => 'task',
			'source_id' => (int) $task_id,
			'priority' => $priority,
			'title' => 'CRM - ' . $task->post_title,
			'description' => $description,
			'task_type' => $type,
			'color_id' => $color,
			'duration_minutes' => $duration,
			'target_day' => $due,
			'start_time' => $start_time,
			'location' => $meeting_location,
			'private_props' => array(
				'twob_crm_source' => 'crm_task',
				'twob_crm_task_id' => (string) (int) $task_id,
			),
		);
	}

	private static function google_followup_item($lead_id, $target_day) {
		$lead = get_post((int) $lead_id);
		if (! $lead || 'crm_lead' !== $lead->post_type) {
			return array();
		}

		return array(
			'source_type' => 'lead',
			'source_id' => (int) $lead_id,
			'priority' => 'medium',
			'title' => 'Seguimiento - ' . $lead->post_title,
			'description' => 'Estado: ' . (self::stage_labels()[get_post_meta($lead_id, '_crm_stage', true)] ?? 'Lead') . "\nVer CRM: " . admin_url('admin.php?page=twob-crm-visual-leads') . '#lead-' . (int) $lead_id,
			'task_type' => 'followup',
			'color_id' => '6',
			'duration_minutes' => 15,
			'target_day' => (string) $target_day,
			'start_time' => '',
			'private_props' => array(
				'twob_crm_source' => 'crm_followup',
				'twob_crm_lead_id' => (string) (int) $lead_id,
			),
		);
	}

	private static function google_upsert_task_for_user($task_id, $user_id) {
		$user_id = (int) $user_id;
		if (! self::google_is_connected($user_id)) {
			return new WP_Error('twob_google_not_connected', 'Conecta tu cuenta Google para sincronizar tareas.');
		}
		$item = self::google_task_item($task_id);
		if (is_wp_error($item)) {
			return $item;
		}
		$target_day = (string) $item['target_day'];
		$settings = self::google_settings_get();
		$calendar_id = (string) $settings['calendar_id'];
		$busy = self::google_fetch_busy_slots($calendar_id, $target_day, $user_id);
		$start_hour = (int) $settings['workday_start_hour'];
		list($start_ts, $end_ts, $moved) = self::google_resolve_item_slot($busy, $target_day, $start_hour, (int) $item['duration_minutes'], (string) $item['start_time']);
		$timezone = self::google_timezone()->getName();
		$event_body = array(
			'summary' => $item['title'],
			'description' => $item['description'],
			'start' => array('dateTime' => self::google_rfc3339($start_ts), 'timeZone' => $timezone),
			'end' => array('dateTime' => self::google_rfc3339($end_ts), 'timeZone' => $timezone),
			'colorId' => $item['color_id'],
			'reminders' => self::google_event_reminders($item),
			'extendedProperties' => array(
				'private' => ! empty($item['private_props']) && is_array($item['private_props']) ? $item['private_props'] : array(),
			),
		);
		if (! empty($item['location'])) {
			$event_body['location'] = $item['location'];
		}

		$calendar_path = '/calendars/' . rawurlencode($calendar_id) . '/events';
		$meta_event_id_key = '_crm_google_event_id_user_' . $user_id;
		$meta_event_day_key = '_crm_google_event_day_user_' . $user_id;
		$event_id = (string) get_post_meta($task_id, $meta_event_id_key, true);
		$resp = null;

		if ($event_id) {
			$resp = self::google_api_request('PATCH', $calendar_path . '/' . rawurlencode($event_id), $event_body, $user_id);
			if (is_wp_error($resp)) {
				$error_data = $resp->get_error_data();
				$code = (is_array($error_data) && isset($error_data['code'])) ? (int) $error_data['code'] : 0;
				if (404 !== $code) {
					return $resp;
				}
				delete_post_meta($task_id, $meta_event_id_key);
				$event_id = '';
			}
		}

		if (! $event_id) {
			$resp = self::google_api_request('POST', $calendar_path, $event_body, $user_id);
			if (is_wp_error($resp) || empty($resp['id'])) {
				return is_wp_error($resp) ? $resp : new WP_Error('twob_google_create_event_failed', 'No se pudo crear el evento en Google Calendar.');
			}
			$event_id = sanitize_text_field((string) $resp['id']);
			update_post_meta($task_id, $meta_event_id_key, $event_id);
		}

		update_post_meta($task_id, $meta_event_day_key, $target_day);
		update_post_meta($task_id, '_crm_google_event_link_user_' . $user_id, isset($resp['htmlLink']) ? esc_url_raw((string) $resp['htmlLink']) : '');
		update_post_meta($task_id, '_crm_google_event_updated_user_' . $user_id, isset($resp['updated']) ? sanitize_text_field((string) $resp['updated']) : '');
		return array(
			'event_id' => $event_id,
			'html_link' => isset($resp['htmlLink']) ? esc_url_raw((string) $resp['htmlLink']) : '',
			'target_day' => $target_day,
			'start_ts' => $start_ts,
			'end_ts' => $end_ts,
			'moved' => ! empty($moved),
		);
	}

	private static function google_upsert_followup_for_user($lead_id, $user_id) {
		$user_id = (int) $user_id;
		if (! self::google_is_connected($user_id)) {
			return new WP_Error('twob_google_not_connected', 'Conecta tu cuenta Google para sincronizar seguimientos.');
		}

		$target_day = (string) get_post_meta($lead_id, '_crm_next_followup', true);
		$meta_event_id_key = '_crm_google_followup_event_id_user_' . $user_id;
		$meta_event_day_key = '_crm_google_followup_event_day_user_' . $user_id;
		$meta_event_link_key = '_crm_google_followup_event_link_user_' . $user_id;
		$meta_event_updated_key = '_crm_google_followup_event_updated_user_' . $user_id;
		$event_id = (string) get_post_meta($lead_id, $meta_event_id_key, true);
		$calendar_id = (string) self::google_settings_get()['calendar_id'];
		$calendar_path = '/calendars/' . rawurlencode($calendar_id) . '/events';

		if (! $target_day) {
			if ($event_id) {
				self::google_api_request('DELETE', $calendar_path . '/' . rawurlencode($event_id), null, $user_id);
				delete_post_meta($lead_id, $meta_event_id_key);
				delete_post_meta($lead_id, $meta_event_day_key);
				delete_post_meta($lead_id, $meta_event_link_key);
				delete_post_meta($lead_id, $meta_event_updated_key);
			}
			return array('deleted' => true);
		}

		$item = self::google_followup_item($lead_id, $target_day);
		if (empty($item)) {
			return new WP_Error('twob_google_followup_invalid', 'No pude construir el seguimiento para Google Calendar.');
		}

		$settings = self::google_settings_get();
		$busy = self::google_fetch_busy_slots($calendar_id, $target_day, $user_id);
		$start_hour = (int) $settings['workday_start_hour'];
		$timezone = self::google_timezone()->getName();
		list($start_ts, $end_ts) = self::google_resolve_item_slot($busy, $target_day, $start_hour, (int) $item['duration_minutes'], '');
		$event_body = array(
			'summary' => $item['title'],
			'description' => $item['description'],
			'start' => array('dateTime' => self::google_rfc3339($start_ts), 'timeZone' => $timezone),
			'end' => array('dateTime' => self::google_rfc3339($end_ts), 'timeZone' => $timezone),
			'colorId' => $item['color_id'],
			'reminders' => self::google_event_reminders($item),
			'extendedProperties' => array(
				'private' => $item['private_props'],
			),
		);

		$resp = null;
		if ($event_id) {
			$resp = self::google_api_request('PATCH', $calendar_path . '/' . rawurlencode($event_id), $event_body, $user_id);
			if (is_wp_error($resp)) {
				$error_data = $resp->get_error_data();
				$code = (is_array($error_data) && isset($error_data['code'])) ? (int) $error_data['code'] : 0;
				if (404 !== $code) {
					return $resp;
				}
				delete_post_meta($lead_id, $meta_event_id_key);
				$event_id = '';
			}
		}

		if (! $event_id) {
			$resp = self::google_api_request('POST', $calendar_path, $event_body, $user_id);
			if (is_wp_error($resp) || empty($resp['id'])) {
				return is_wp_error($resp) ? $resp : new WP_Error('twob_google_create_followup_failed', 'No se pudo crear el seguimiento en Google Calendar.');
			}
			$event_id = sanitize_text_field((string) $resp['id']);
			update_post_meta($lead_id, $meta_event_id_key, $event_id);
		}

		update_post_meta($lead_id, $meta_event_day_key, $target_day);
		update_post_meta($lead_id, $meta_event_link_key, isset($resp['htmlLink']) ? esc_url_raw((string) $resp['htmlLink']) : '');
		update_post_meta($lead_id, $meta_event_updated_key, isset($resp['updated']) ? sanitize_text_field((string) $resp['updated']) : '');

		return array(
			'event_id' => $event_id,
			'target_day' => $target_day,
			'html_link' => isset($resp['htmlLink']) ? esc_url_raw((string) $resp['htmlLink']) : '',
		);
	}

	private static function google_sync_user($user_id, $target_day) {
		$settings = self::google_settings_get();
		if (! self::google_is_connected($user_id)) {
			return 0;
		}
		$pause_days = array_filter(array_map('trim', explode(',', (string) $settings['pause_days'])));
		if (in_array($target_day, $pause_days, true)) {
			return 0;
		}
		$items = self::google_collect_tomorrow_items($target_day, (int) $settings['max_tasks_per_day']);
		$calendar_id = (string) $settings['calendar_id'];
		$busy = self::google_fetch_busy_slots($calendar_id, $target_day, $user_id);
		$start_hour = (int) $settings['workday_start_hour'];
		$timezone = self::google_timezone()->getName();
		$synced = 0;

		foreach ($items as $item) {
			list($start_ts, $end_ts) = self::google_resolve_item_slot(
				$busy,
				$target_day,
				$start_hour,
				(int) $item['duration_minutes'],
				isset($item['start_time']) ? (string) $item['start_time'] : ''
			);
			$busy[] = array('start' => $start_ts, 'end' => $end_ts);
			$event_body = array(
				'summary' => $item['title'],
				'description' => $item['description'],
				'start' => array('dateTime' => self::google_rfc3339($start_ts), 'timeZone' => $timezone),
				'end' => array('dateTime' => self::google_rfc3339($end_ts), 'timeZone' => $timezone),
				'colorId' => $item['color_id'],
				'reminders' => self::google_event_reminders($item),
				'extendedProperties' => array(
					'private' => ! empty($item['private_props']) && is_array($item['private_props']) ? $item['private_props'] : array(),
				),
			);
			if (! empty($item['location'])) {
				$event_body['location'] = $item['location'];
			}

			$meta_event_id_key = ('task' === $item['source_type']) ? '_crm_google_event_id_user_' . (int) $user_id : '_crm_google_followup_event_id_user_' . (int) $user_id;
			$meta_event_day_key = ('task' === $item['source_type']) ? '_crm_google_event_day_user_' . (int) $user_id : '_crm_google_followup_event_day_user_' . (int) $user_id;
			$source_id = (int) $item['source_id'];
			$existing_id = (string) get_post_meta($source_id, $meta_event_id_key, true);
			$existing_day = (string) get_post_meta($source_id, $meta_event_day_key, true);
			$calendar_path = '/calendars/' . rawurlencode($calendar_id) . '/events';

			if ($existing_id && $existing_day === $target_day) {
				$resp = self::google_api_request('PATCH', $calendar_path . '/' . rawurlencode($existing_id), $event_body, $user_id);
				if (is_wp_error($resp)) {
					continue;
				}
					if ('task' === $item['source_type']) {
						update_post_meta($source_id, '_crm_google_event_link_user_' . (int) $user_id, isset($resp['htmlLink']) ? esc_url_raw((string) $resp['htmlLink']) : '');
						update_post_meta($source_id, '_crm_google_event_updated_user_' . (int) $user_id, isset($resp['updated']) ? sanitize_text_field((string) $resp['updated']) : '');
					} else {
						update_post_meta($source_id, '_crm_google_followup_event_updated_user_' . (int) $user_id, isset($resp['updated']) ? sanitize_text_field((string) $resp['updated']) : '');
					}
					$synced++;
					continue;
			}
			$resp = self::google_api_request('POST', $calendar_path, $event_body, $user_id);
			if (is_wp_error($resp) || empty($resp['id'])) {
				continue;
			}
				update_post_meta($source_id, $meta_event_id_key, sanitize_text_field((string) $resp['id']));
				update_post_meta($source_id, $meta_event_day_key, $target_day);
				if ('task' === $item['source_type']) {
					update_post_meta($source_id, '_crm_google_event_link_user_' . (int) $user_id, isset($resp['htmlLink']) ? esc_url_raw((string) $resp['htmlLink']) : '');
					update_post_meta($source_id, '_crm_google_event_updated_user_' . (int) $user_id, isset($resp['updated']) ? sanitize_text_field((string) $resp['updated']) : '');
				} else {
					update_post_meta($source_id, '_crm_google_followup_event_updated_user_' . (int) $user_id, isset($resp['updated']) ? sanitize_text_field((string) $resp['updated']) : '');
				}
				$synced++;
			}

		return $synced;
	}

	private static function google_sync_calendar_to_crm_user($user_id, $days_back = 14, $days_forward = 60) {
		$user_id = (int) $user_id;
		if (! self::google_is_connected($user_id)) {
			return 0;
		}

		$settings = self::google_settings_get();
		$calendar_id = (string) $settings['calendar_id'];
		$today = current_time('Y-m-d');
		$start_date = self::google_shift_day($today, '-' . max(0, (int) $days_back) . ' days');
		$end_date = self::google_shift_day($today, '+' . max(1, (int) $days_forward) . ' days');
		$events = self::google_fetch_events_range($calendar_id, $start_date, $end_date, $user_id);

		if (is_wp_error($events)) {
			return $events;
		}

		$imported = 0;
		foreach ((array) $events as $event) {
			if (self::google_sync_event_to_crm($event, $user_id)) {
				$imported++;
			}
		}

		return $imported;
	}

	private static function maybe_google_sync_task_for_current_user($task_id) {
		$user_id = get_current_user_id();
		if (self::$google_sync_context || ! $user_id || ! self::google_is_connected($user_id)) {
			return;
		}
		self::google_upsert_task_for_user((int) $task_id, (int) $user_id);
	}

	private static function maybe_google_sync_followup_for_current_user($lead_id) {
		$user_id = get_current_user_id();
		if (self::$google_sync_context || ! $user_id || ! self::google_is_connected($user_id)) {
			return;
		}
		self::google_upsert_followup_for_user((int) $lead_id, (int) $user_id);
	}

	public static function google_pull_hourly() {
		$settings = self::google_settings_get();
		if (! empty($settings['sync_paused'])) {
			return true;
		}
		$user_ids = self::google_connected_user_ids();
		if (empty($user_ids)) {
			return new WP_Error('twob_google_not_connected', 'Google Calendar no conectado por usuario.');
		}

		$total = 0;
		foreach ($user_ids as $user_id) {
			$result = self::google_sync_calendar_to_crm_user((int) $user_id, 14, 60);
			if (is_wp_error($result)) {
				continue;
			}
			$total += (int) $result;
		}

		return array('imported' => $total, 'users' => count($user_ids));
	}

	public static function google_sync_daily() {
		self::schedule_google_sync();
		$settings = self::google_settings_get();
		if (! empty($settings['sync_paused'])) {
			return true;
		}
		$target_day = self::google_shift_day(current_time('Y-m-d'), '+1 day');
		$user_ids = self::google_connected_user_ids();
		if (empty($user_ids)) {
			return new WP_Error('twob_google_not_connected', 'Google Calendar no conectado por usuario.');
		}
		$total = 0;
		foreach ($user_ids as $user_id) {
			$total += self::google_sync_user((int) $user_id, $target_day);
			$pull_result = self::google_sync_calendar_to_crm_user((int) $user_id, 14, 60);
			if (! is_wp_error($pull_result)) {
				$total += (int) $pull_result;
			}
		}
		return array('synced' => $total, 'target_day' => $target_day, 'users' => count($user_ids));
	}

	private static function google_collect_tomorrow_items($target_day, $limit) {
		$items = array();
		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => $limit,
			'meta_query' => array(
				'relation' => 'AND',
				array('key' => '_crm_task_due', 'value' => $target_day, 'compare' => '='),
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
			'orderby' => 'date',
			'order' => 'ASC',
		));

		foreach ($tasks as $task) {
			$task_id = (int) $task->ID;
			$item = self::google_task_item($task_id);
			if (! is_wp_error($item)) {
				$items[] = $item;
			}
		}

		$followups = self::get_active_leads(array(
			'numberposts' => max(1, $limit),
			'meta_key' => '_crm_next_followup',
			'meta_value' => $target_day,
			'meta_compare' => '=',
			'orderby' => 'date',
			'order' => 'ASC',
		));
		foreach ($followups as $lead) {
			$lead_item = self::google_followup_item((int) $lead->ID, $target_day);
			if (! empty($lead_item)) {
				$items[] = $lead_item;
			}
		}

		usort($items, function($a, $b) {
			$map = array('high' => 1, 'medium' => 2, 'low' => 3);
			return ($map[$a['priority']] ?? 2) <=> ($map[$b['priority']] ?? 2);
		});

		return array_slice($items, 0, max(1, $limit));
	}

