	public static function save_interaction_meta($post_id, $post) {
		if (! isset($_POST['crm_interaction_meta_nonce']) || ! wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['crm_interaction_meta_nonce'])), 'crm_interaction_meta_save')) {
			return;
		}
		if (defined('DOING_AUTOSAVE') && DOING_AUTOSAVE) {
			return;
		}

		$kind = self::sanitize_interaction_kind(isset($_POST['crm_interaction_kind']) ? wp_unslash($_POST['crm_interaction_kind']) : 'contact');
		$lead_id = isset($_POST['crm_interaction_lead_id']) ? absint($_POST['crm_interaction_lead_id']) : 0;
		if ($lead_id && ! self::get_valid_crm_post($lead_id, 'crm_lead')) {
			$lead_id = 0;
		}
		$date = self::sanitize_date_input(isset($_POST['crm_interaction_date']) ? wp_unslash($_POST['crm_interaction_date']) : '', true, 'Fecha de interaccion');
		$date = is_wp_error($date) ? '' : $date;
		$channel = self::sanitize_interaction_channel(isset($_POST['crm_interaction_channel']) ? wp_unslash($_POST['crm_interaction_channel']) : 'whatsapp');
		$action = self::normalize_interaction_action(isset($_POST['crm_interaction_action']) ? wp_unslash($_POST['crm_interaction_action']) : '', $kind, $channel);
		$result = self::sanitize_interaction_result(isset($_POST['crm_interaction_result']) ? wp_unslash($_POST['crm_interaction_result']) : 'other');
		$interaction_stage = self::sanitize_stage_input(isset($_POST['crm_interaction_stage']) ? wp_unslash($_POST['crm_interaction_stage']) : '', true);
		$next = self::sanitize_date_input(isset($_POST['crm_interaction_next_followup']) ? wp_unslash($_POST['crm_interaction_next_followup']) : '', true, 'Proximo seguimiento');
		$next = is_wp_error($next) ? '' : $next;
		$note = isset($_POST['crm_interaction_note']) ? sanitize_textarea_field(wp_unslash($_POST['crm_interaction_note'])) : '';

		update_post_meta($post_id, '_crm_interaction_kind', $kind);
		update_post_meta($post_id, '_crm_lead_id', $lead_id);
		update_post_meta($post_id, '_crm_interaction_date', $date);
		update_post_meta($post_id, '_crm_interaction_channel', $channel);
		update_post_meta($post_id, '_crm_interaction_action', $action);
		update_post_meta($post_id, '_crm_interaction_result', $result);
		update_post_meta($post_id, '_crm_interaction_stage', $interaction_stage);
		update_post_meta($post_id, '_crm_interaction_next_followup', $next);
		update_post_meta($post_id, '_crm_interaction_note', $note);
		if ($lead_id) {
			$current_stage = (string) get_post_meta($lead_id, '_crm_stage', true);
			if ('followup' === $kind && 'proposal_sent' === $current_stage && self::has_recent_proposal_followup($lead_id, $date ?: current_time('Y-m-d'))) {
				update_post_meta($post_id, '_crm_rule_violation', 'Debes esperar minimo 3 dias entre seguimientos de propuesta.');
			} else {
				delete_post_meta($post_id, '_crm_rule_violation');
			}
			if ($next) {
				self::set_lead_next_followup_meta($lead_id, $next);
			} else {
				self::sync_lead_next_action($lead_id);
			}
				if ($interaction_stage && isset(self::stage_labels()[$interaction_stage])) {
					self::set_lead_stage($lead_id, $interaction_stage, 'interaction_editor');
				}
				self::sync_lead_lifecycle_state($lead_id, $date ?: current_time('Y-m-d'));
				self::update_temperature($lead_id);
				self::maybe_google_sync_followup_for_current_user($lead_id);
				self::sync_master_client_for_lead($lead_id);
				self::update_lead_score($lead_id);
			}
	}

	public static function save_lead_meta($post_id, $post) {
		if (! isset($_POST['crm_lead_meta_nonce']) || ! wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['crm_lead_meta_nonce'])), 'crm_lead_meta_save')) {
			return;
		}
		if (defined('DOING_AUTOSAVE') && DOING_AUTOSAVE) {
			return;
		}
		$previous_next_followup = (string) get_post_meta($post_id, '_crm_next_followup', true);
		$previous_next_action = (string) get_post_meta($post_id, '_crm_next_action', true);
		$name = (string) get_the_title($post_id);
		$payload = array(
			'name' => $name,
			'email' => isset($_POST['crm_email']) ? sanitize_email(wp_unslash($_POST['crm_email'])) : '',
			'phone' => isset($_POST['crm_phone']) ? sanitize_text_field(wp_unslash($_POST['crm_phone'])) : '',
			'origin_channel' => isset($_POST['crm_origin_channel']) ? sanitize_text_field(wp_unslash($_POST['crm_origin_channel'])) : '',
			'client_type' => isset($_POST['crm_client_type']) ? sanitize_text_field(wp_unslash($_POST['crm_client_type'])) : '',
			'service_interest' => isset($_POST['crm_service_interest']) ? sanitize_text_field(wp_unslash($_POST['crm_service_interest'])) : '',
		);
		$editor_stage = isset($_POST['crm_stage']) ? self::sanitize_stage_input(wp_unslash($_POST['crm_stage'])) : 'new';
		$validation = self::validate_lead_payload($payload + array(
			'company' => isset($_POST['crm_company']) ? sanitize_text_field(wp_unslash($_POST['crm_company'])) : '',
			'website_url' => isset($_POST['crm_website_url']) ? esc_url_raw(wp_unslash($_POST['crm_website_url'])) : '',
		), self::is_pre_contact_stage($editor_stage) ? 'pre_contact' : 'contacted');
		if (is_wp_error($validation)) {
			update_post_meta($post_id, '_crm_validation_error', $validation->get_error_message());
		} else {
			delete_post_meta($post_id, '_crm_validation_error');
		}
		$budget = self::sanitize_budget_input(isset($_POST['crm_budget']) ? wp_unslash($_POST['crm_budget']) : '');
		$employee_count_raw = isset($_POST['crm_employee_count']) ? trim((string) wp_unslash($_POST['crm_employee_count'])) : '';
		$employee_count = '' !== $employee_count_raw ? max(0, (int) $employee_count_raw) : '';
		$value = isset($_POST['crm_value']) ? (float) wp_unslash($_POST['crm_value']) : 0;
		$previous_temperature = self::normalize_temperature((string) get_post_meta($post_id, '_crm_temperature', true), false);
		$temperature = self::normalize_temperature(isset($_POST['crm_temperature']) ? wp_unslash($_POST['crm_temperature']) : '', false);
		if (! $temperature) {
			$temperature = self::lead_temperature($post_id);
		}
		$alliance_source = isset($_POST['crm_alliance_source']) ? sanitize_text_field(wp_unslash($_POST['crm_alliance_source'])) : '';
		if ('referral' !== sanitize_key((string) $payload['origin_channel'])) {
			$alliance_source = '';
		}
		$technical_finding = isset($_POST['crm_technical_finding']) ? sanitize_textarea_field(wp_unslash($_POST['crm_technical_finding'])) : '';

		update_post_meta($post_id, '_crm_company', isset($_POST['crm_company']) ? sanitize_text_field(wp_unslash($_POST['crm_company'])) : '');
		update_post_meta($post_id, '_crm_email', $payload['email']);
		update_post_meta($post_id, '_crm_phone', $payload['phone']);
		update_post_meta($post_id, '_crm_employee_count', $employee_count);
		update_post_meta($post_id, '_crm_website_url', isset($_POST['crm_website_url']) ? esc_url_raw(wp_unslash($_POST['crm_website_url'])) : '');
		update_post_meta($post_id, '_crm_linkedin_person', isset($_POST['crm_linkedin_person']) ? esc_url_raw(wp_unslash($_POST['crm_linkedin_person'])) : '');
		update_post_meta($post_id, '_crm_linkedin_company', isset($_POST['crm_linkedin_company']) ? esc_url_raw(wp_unslash($_POST['crm_linkedin_company'])) : '');
		update_post_meta($post_id, '_crm_origin_channel', $payload['origin_channel']);
		update_post_meta($post_id, '_crm_client_type', $payload['client_type']);
		update_post_meta($post_id, '_crm_service_interest', $payload['service_interest']);
		update_post_meta($post_id, '_crm_budget', $budget);
		update_post_meta($post_id, '_crm_value', $value);
		update_post_meta($post_id, '_crm_alliance_source', $alliance_source);
		update_post_meta($post_id, '_crm_technical_finding', $technical_finding);
		update_post_meta($post_id, '_crm_observations', isset($_POST['crm_observations']) ? sanitize_textarea_field(wp_unslash($_POST['crm_observations'])) : '');
		update_post_meta($post_id, '_crm_qualification_notes', isset($_POST['crm_observations']) ? sanitize_textarea_field(wp_unslash($_POST['crm_observations'])) : '');
		update_post_meta($post_id, '_crm_has_website', isset($_POST['crm_website_url']) && '' !== trim((string) wp_unslash($_POST['crm_website_url'])) ? 'yes' : 'no');
		update_post_meta($post_id, '_crm_sells_online', '');
		update_post_meta($post_id, '_crm_urgency', '');
		update_post_meta($post_id, '_crm_trust_level', '');
		update_post_meta($post_id, '_crm_long_term_potential', '');
		update_post_meta($post_id, '_crm_referred_by', $alliance_source);
		$next_followup = self::sanitize_date_input(isset($_POST['crm_next_followup']) ? wp_unslash($_POST['crm_next_followup']) : '', true, 'Proximo seguimiento');
		self::set_lead_next_followup_meta($post_id, is_wp_error($next_followup) ? '' : $next_followup);
		$new_stage = $editor_stage;
		$lost_reason = isset($_POST['crm_closed_lost_reason']) ? sanitize_textarea_field(wp_unslash($_POST['crm_closed_lost_reason'])) : '';
		$stage_result = self::set_lead_stage($post_id, $new_stage, 'lead_editor', $lost_reason);
		if (is_wp_error($stage_result)) {
			update_post_meta($post_id, '_crm_validation_error', $stage_result->get_error_message());
		}
		$resolved_stage = self::normalize_stage_key((string) get_post_meta($post_id, '_crm_stage', true));
		$current_next_followup = (string) get_post_meta($post_id, '_crm_next_followup', true);
		if (self::lead_stage_requires_next_action($resolved_stage) && '' === $current_next_followup) {
			$fallback_next_followup = $previous_next_followup ?: current_time('Y-m-d');
			$fallback_next_action = $previous_next_action ?: 'Responder lead';
			self::set_lead_next_followup_meta($post_id, $fallback_next_followup, $fallback_next_action);
			update_post_meta($post_id, '_crm_validation_error', 'Este lead sigue activo. Debes dejar la proxima accion antes de guardar.');
			}
			self::sync_lead_lifecycle_state($post_id, current_time('Y-m-d'));
			self::apply_temperature_selection($post_id, $temperature, $payload['origin_channel'], $resolved_stage, false, $previous_temperature);
			self::update_lead_sequence_policy($post_id, $payload['origin_channel']);
			self::sync_open_sequence_task_descriptions_for_lead($post_id);
			self::maybe_google_sync_followup_for_current_user($post_id);
			self::sync_master_client_for_lead($post_id);
			self::update_lead_score($post_id);
		}

	public static function save_task_meta($post_id, $post) {
		if (! isset($_POST['crm_task_meta_nonce']) || ! wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['crm_task_meta_nonce'])), 'crm_task_meta_save')) {
			return;
		}
		if (defined('DOING_AUTOSAVE') && DOING_AUTOSAVE) {
			return;
		}
		$task_due = self::sanitize_date_input(isset($_POST['crm_task_due']) ? wp_unslash($_POST['crm_task_due']) : '', true, 'Fecha de tarea');
		update_post_meta($post_id, '_crm_task_due', is_wp_error($task_due) ? '' : $task_due);
		$status = self::validate_task_status_choice(isset($_POST['crm_task_status']) ? wp_unslash($_POST['crm_task_status']) : 'pending');
		$status = is_wp_error($status) ? 'pending' : $status;
		update_post_meta($post_id, '_crm_task_status', $status);
		$relation = self::sanitize_task_relation(isset($_POST['crm_task_relation']) ? wp_unslash($_POST['crm_task_relation']) : 'lead_client');
		$category = self::sanitize_task_category(isset($_POST['crm_task_category']) ? wp_unslash($_POST['crm_task_category']) : 'commercial');
		if ('commercial' === $category) {
			$relation = 'lead_client';
		}
		$lead_id = isset($_POST['crm_task_lead_id']) ? absint($_POST['crm_task_lead_id']) : 0;
		if ($lead_id && ! self::get_valid_crm_post($lead_id, 'crm_lead')) {
			$lead_id = 0;
		}
		if ('internal' === $relation) {
			$lead_id = 0;
		}
		if ('commercial' === $category && ! $lead_id) {
			$category = 'operational';
			$relation = 'internal';
		}
		$pipeline_stage = self::sanitize_stage_input(isset($_POST['crm_task_pipeline_stage']) ? wp_unslash($_POST['crm_task_pipeline_stage']) : '', true);
		if ('internal' === $relation) {
			$pipeline_stage = '';
		}
		if ('lead_client' === $relation && $lead_id && ! $pipeline_stage) {
			$lead_stage = (string) get_post_meta($lead_id, '_crm_stage', true);
			if ($lead_stage && isset(self::stage_labels()[$lead_stage])) {
				$pipeline_stage = $lead_stage;
			}
		}
		update_post_meta($post_id, '_crm_task_lead_id', $lead_id);
		$priority = self::sanitize_task_priority(isset($_POST['crm_task_priority']) ? wp_unslash($_POST['crm_task_priority']) : 'medium');
		update_post_meta($post_id, '_crm_task_priority', $priority);
		$task_type = self::sanitize_task_type(isset($_POST['crm_task_type']) ? wp_unslash($_POST['crm_task_type']) : '', $category);
		update_post_meta($post_id, '_crm_task_type', $task_type);
		update_post_meta($post_id, '_crm_task_category', $category);
		update_post_meta($post_id, '_crm_task_relation', $relation);
		$assignee = self::sanitize_task_assignee(isset($_POST['crm_task_assignee']) ? wp_unslash($_POST['crm_task_assignee']) : 'dani');
		update_post_meta($post_id, '_crm_task_assignee', $assignee);
		$recurrence = self::validate_task_recurrence_choice(isset($_POST['crm_task_recurrence']) ? wp_unslash($_POST['crm_task_recurrence']) : 'none');
		$recurrence = is_wp_error($recurrence) ? 'none' : $recurrence;
		update_post_meta($post_id, '_crm_task_recurrence', $recurrence);
		update_post_meta($post_id, '_crm_task_pipeline_stage', $pipeline_stage);
		$start_time = self::sanitize_time_input(isset($_POST['crm_task_start_time']) ? wp_unslash($_POST['crm_task_start_time']) : '', true);
		$clean_start_time = is_wp_error($start_time) ? '' : $start_time;
		$duration = isset($_POST['crm_task_duration']) ? absint($_POST['crm_task_duration']) : 0;
		if ('meeting' === $task_type) {
			$duration = max(15, min(240, $duration ? $duration : 30));
			update_post_meta($post_id, '_crm_task_start_time', $clean_start_time);
			update_post_meta($post_id, '_crm_task_duration', $duration);
			update_post_meta($post_id, '_crm_task_meeting_url', isset($_POST['crm_task_meeting_url']) ? esc_url_raw(wp_unslash($_POST['crm_task_meeting_url'])) : '');
			update_post_meta($post_id, '_crm_task_meeting_location', isset($_POST['crm_task_meeting_location']) ? sanitize_text_field(wp_unslash($_POST['crm_task_meeting_location'])) : '');
		} else {
			update_post_meta($post_id, '_crm_task_start_time', $clean_start_time);
			update_post_meta($post_id, '_crm_task_duration', ('proposal' === $task_type) ? 30 : 15);
			update_post_meta($post_id, '_crm_task_meeting_url', '');
			update_post_meta($post_id, '_crm_task_meeting_location', '');
		}
		$completion_stage = self::normalize_stage_key((string) get_post_meta($post_id, '_crm_task_completion_stage', true));
		if ('done' === $status && self::task_requires_guided_completion($post_id) && ! (int) get_post_meta($post_id, '_crm_task_completion_interaction_id', true) && ! in_array($completion_stage, array('lost', 'won'), true)) {
			$status = 'pending';
			update_post_meta($post_id, '_crm_task_status', 'pending');
		}
		if ('done' === $status) {
			self::log_activity('task_completed', $post_id, array('task_type' => (string) get_post_meta($post_id, '_crm_task_type', true)));
			self::maybe_create_next_recurring_task($post_id);
		}
		self::sync_google_task_status_prefix($post_id, $status);
		self::maybe_google_sync_task_for_current_user($post_id);
		if ($lead_id) {
			self::sync_lead_next_action($lead_id);
		}
	}

	public static function maybe_backfill_lead_scores() {
		if (get_option(self::LEAD_SCORE_BACKFILL_OPTION)) {
			return;
		}
		if (! self::user_can_access_crm()) {
			return;
		}

		$leads = get_posts(array(
			'post_type' => 'crm_lead',
			'post_status' => 'publish',
			'numberposts' => -1,
			'orderby' => 'date',
			'order' => 'DESC',
		));
		$updated = 0;
		foreach ($leads as $lead) {
			$lead_id = (int) $lead->ID;
			if (! $lead_id) {
				continue;
			}
			self::update_lead_score($lead_id);
			$updated++;
		}

		update_option(self::LEAD_SCORE_BACKFILL_OPTION, array(
			'updated' => $updated,
			'ran_at' => current_time('mysql'),
		), false);
	}

	public static function maybe_run_legacy_april_cleanup() {
		if (get_option(self::LEGACY_APRIL_CLEANUP_OPTION)) {
			return;
		}
		if (! self::user_can_access_crm()) {
			return;
		}

		$legacy_leads = get_posts(array(
			'post_type' => 'crm_lead',
			'post_status' => 'publish',
			'numberposts' => -1,
			'date_query' => array(
				array(
					'before' => '2026-04-30 23:59:59',
					'inclusive' => true,
				),
			),
		));

		$closed = 0;
		foreach ($legacy_leads as $lead) {
			$lead_id = (int) $lead->ID;
			$current_stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
			if (in_array($current_stage, array('won', 'lost'), true)) {
				continue;
			}
			$result = self::set_lead_stage($lead_id, 'lost', 'legacy_april_cleanup', 'Lead historico de abril o antes cerrado para limpiar backlog antiguo del CRM Dani.');
			if (is_wp_error($result)) {
				continue;
			}
			self::sync_master_client_for_lead($lead_id);
			$closed++;
		}

		update_option(self::LEGACY_APRIL_CLEANUP_OPTION, array(
			'closed' => $closed,
			'ran_at' => current_time('mysql'),
		), false);
	}

	public static function maybe_repair_stuck_guided_tasks() {
		if (get_option(self::STUCK_GUIDED_TASK_REPAIR_OPTION)) {
			return;
		}
		if (! self::user_can_access_crm()) {
			return;
		}

		$open_task_ids = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => -1,
			'fields' => 'ids',
			'meta_query' => array(
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
		));

		$repaired = 0;
		foreach ($open_task_ids as $task_id) {
			if (self::reconcile_open_guided_task_from_history((int) $task_id)) {
				$repaired++;
			}
		}

		update_option(self::STUCK_GUIDED_TASK_REPAIR_OPTION, array(
			'repaired' => $repaired,
			'ran_at' => current_time('mysql'),
		), false);
	}

	public static function save_payment_meta($post_id, $post) {
