		update_post_meta($post_id, '_crm_payment_amount', self::sanitize_amount_input(isset($_POST['crm_payment_amount']) ? wp_unslash($_POST['crm_payment_amount']) : 0));
		$status = self::validate_payment_status_choice(isset($_POST['crm_payment_status']) ? wp_unslash($_POST['crm_payment_status']) : 'pending');
		$status = is_wp_error($status) ? 'pending' : $status;
		update_post_meta($post_id, '_crm_payment_status', $status);
		$paid_date = self::sanitize_date_input(isset($_POST['crm_payment_paid_date']) ? wp_unslash($_POST['crm_payment_paid_date']) : '', true, 'Fecha de pago');
		$due_date = self::sanitize_date_input(isset($_POST['crm_payment_due_date']) ? wp_unslash($_POST['crm_payment_due_date']) : '', true, 'Fecha de vencimiento');
		update_post_meta($post_id, '_crm_payment_paid_date', is_wp_error($paid_date) ? '' : $paid_date);
		update_post_meta($post_id, '_crm_payment_due_date', is_wp_error($due_date) ? '' : $due_date);
		update_post_meta($post_id, '_crm_payment_service', isset($_POST['crm_payment_service']) ? sanitize_text_field(wp_unslash($_POST['crm_payment_service'])) : '');
	}

	public static function register_menu() {
		add_menu_page('CRM 2B', 'CRM 2B', self::ACCESS_CAP, 'twob-crm-visual-dashboard', array(__CLASS__, 'render_dashboard'), 'dashicons-chart-area', 27);
		add_submenu_page('twob-crm-visual-dashboard', 'Dashboard', 'Dashboard', self::ACCESS_CAP, 'twob-crm-visual-dashboard', array(__CLASS__, 'render_dashboard'));
		add_submenu_page('twob-crm-visual-dashboard', 'Actividad', 'Actividad', self::ACCESS_CAP, 'twob-crm-visual-activity', array(__CLASS__, 'render_activity_page'));
		add_submenu_page('twob-crm-visual-dashboard', 'Riesgo comercial', 'Riesgo comercial', 'edit_crm_leads', 'twob-crm-visual-risk', array(__CLASS__, 'render_risk_page'));
		add_submenu_page('twob-crm-visual-dashboard', 'Pipeline', 'Pipeline', 'edit_crm_leads', 'twob-crm-visual-pipeline', array(__CLASS__, 'render_pipeline_page'));
		add_submenu_page('twob-crm-visual-dashboard', 'Metas', 'Metas', self::SETTINGS_CAP, 'twob-crm-visual-goals', array(__CLASS__, 'render_goals_page'));
		add_submenu_page('twob-crm-visual-dashboard', 'Configuracion', 'Configuracion', self::SETTINGS_CAP, 'twob-crm-visual-settings', array(__CLASS__, 'render_settings_page'));
