	private static function period_bounds($period) {
		$today = current_time('Y-m-d');
		if ('day' === $period) {
			return array($today . ' 00:00:00', $today . ' 23:59:59');
		}
		if ('week' === $period) {
			$w = strtotime($today);
			$start = strtotime('monday this week', $w);
			$end = strtotime('sunday this week 23:59:59', $w);
			return array(date('Y-m-d H:i:s', $start), date('Y-m-d H:i:s', $end));
		}
		return array(date('Y-m-01 00:00:00', current_time('timestamp')), date('Y-m-t 23:59:59', current_time('timestamp')));
	}

	private static function activity_count($action, $period, $meta = array()) {
		$cache_meta = (array) $meta;
		ksort($cache_meta);
		return TwoB_CRM_Dani_Reports_Module::remember(
			'activity_count|' . sanitize_key((string) $action) . '|' . sanitize_key((string) $period) . '|' . wp_json_encode($cache_meta),
			self::METRICS_CACHE_TTL,
			function () use ($action, $period, $meta) {
				list($after, $before) = self::period_bounds($period);
				$mq = array(array('key' => '_crm_action', 'value' => $action));
				foreach ($meta as $k => $v) {
					$mq[] = array('key' => '_crm_' . $k, 'value' => $v);
				}
				$q = new WP_Query(array(
					'post_type' => 'crm_activity',
					'post_status' => 'publish',
					'posts_per_page' => -1,
					'fields' => 'ids',
					'date_query' => array(array('after' => $after, 'before' => $before, 'inclusive' => true)),
					'meta_query' => $mq,
				));
				return count($q->posts);
			}
		);
	}

	private static function activity_sum($action, $period, $sum_key) {
		return TwoB_CRM_Dani_Reports_Module::remember(
			'activity_sum|' . sanitize_key((string) $action) . '|' . sanitize_key((string) $period) . '|' . sanitize_key((string) $sum_key),
			self::METRICS_CACHE_TTL,
			function () use ($action, $period, $sum_key) {
				list($after, $before) = self::period_bounds($period);
				$q = new WP_Query(array(
					'post_type' => 'crm_activity',
					'post_status' => 'publish',
					'posts_per_page' => -1,
					'fields' => 'ids',
					'date_query' => array(array('after' => $after, 'before' => $before, 'inclusive' => true)),
					'meta_query' => array(array('key' => '_crm_action', 'value' => $action)),
				));
				$total = 0;
				foreach ($q->posts as $id) {
					$total += (float) get_post_meta($id, '_crm_' . $sum_key, true);
				}
				return $total;
			}
		);
	}

	private static function log_activity($action, $object_id, $extra, $when_mysql = null) {
		$post_date = current_time('mysql');
		if (! empty($when_mysql)) {
			$post_date = $when_mysql;
			// Si llega solo YYYY-MM-DD, normalizamos a un timestamp para que date_query funcione por dÃ­a/semana/mes.
			if (is_string($when_mysql) && preg_match('/^\d{4}-\d{2}-\d{2}$/', $when_mysql)) {
				$post_date = $when_mysql . ' 12:00:00';
			}
		}
		$actor_user_id = isset($extra['user_id']) ? absint($extra['user_id']) : get_current_user_id();
		$id = wp_insert_post(array(
			'post_type' => 'crm_activity',
			'post_status' => 'publish',
			'post_title' => $action . ' #' . (int) $object_id,
			'post_date' => $post_date,
			'post_author' => $actor_user_id,
		));
		if (! $id || is_wp_error($id)) {
			return;
		}
		update_post_meta($id, '_crm_action', $action);
		update_post_meta($id, '_crm_object_id', (int) $object_id);
		update_post_meta($id, '_crm_user_id', $actor_user_id);
		foreach ($extra as $k => $v) {
			update_post_meta($id, '_crm_' . sanitize_key($k), $v);
		}
	}

