	public static function track_lead_created($post_id, $post, $update) {
		if (defined('DOING_AUTOSAVE') && DOING_AUTOSAVE) {
			return;
		}
		if (! $post || ! is_object($post)) {
			$post = get_post($post_id);
		}
		if (! $post || 'crm_lead' !== $post->post_type) {
			return;
		}
		if ('publish' !== $post->post_status) {
			return;
		}
		if ($update) {
			return;
		}
		if ((int) get_post_meta($post_id, '_crm_lead_created_tracked', true) === 1) {
			return;
		}
		// Usamos la fecha de creacion del post para que el conteo por dia/semana/mes sea consistente.
		$when = ! empty($post->post_date) ? $post->post_date : current_time('mysql');
			self::log_activity('lead_created', $post_id, array(), $when);
			update_post_meta($post_id, '_crm_lead_created_tracked', 1);
				if (! get_post_meta($post_id, '_crm_funnel_stage', true)) {
					update_post_meta($post_id, '_crm_funnel_stage', 'contact');
				}
				self::sync_lead_lifecycle_state($post_id, current_time('Y-m-d'));
				self::update_temperature($post_id);
				self::update_operational_status($post_id, current_time('Y-m-d'));
				self::ensure_lead_followup_sequence_task($post_id, current_time('Y-m-d'));
		}

	public static function track_interaction_logged($post_id, $post, $update) {
		if (defined('DOING_AUTOSAVE') && DOING_AUTOSAVE) {
			return;
		}
		if (! $post || ! is_object($post)) {
			$post = get_post($post_id);
		}
		if (! $post || 'crm_interaction' !== $post->post_type) {
			return;
		}
		if ('publish' !== $post->post_status) {
			return;
		}
		if ((int) get_post_meta($post_id, '_crm_interaction_tracked', true) === 1) {
			return;
		}

		$kind   = get_post_meta($post_id, '_crm_interaction_kind', true);
		if (! $kind) {
			$kind = 'contact';
		}
		$channel = (string) get_post_meta($post_id, '_crm_interaction_channel', true);
		$interaction_action = (string) get_post_meta($post_id, '_crm_interaction_action', true);
		$lead_id = (int) get_post_meta($post_id, '_crm_lead_id', true);
		$when   = get_post_meta($post_id, '_crm_interaction_date', true);
		if (! $when) {
			$when = current_time('Y-m-d');
		}

		self::log_activity(
			'interaction_logged',
			$lead_id ? $lead_id : $post_id,
			array(
				'interaction_kind' => sanitize_text_field((string) $kind),
				'interaction_channel' => sanitize_key($channel),
				'interaction_action' => sanitize_key($interaction_action),
			),
			$when
		);
		$result = (string) get_post_meta($post_id, '_crm_interaction_result', true);
		if ($lead_id && ! in_array($result, array('', 'no_answer'), true)) {
			self::log_activity('response_sent', $lead_id, array('result' => $result, 'interaction_action' => sanitize_key($interaction_action)), $when);
		}
		if ($lead_id) {
			self::update_temperature($lead_id);
			self::update_operational_status($lead_id, $when);
		}
		update_post_meta($post_id, '_crm_interaction_tracked', 1);
	}

	public static function track_payment_recorded($post_id, $post, $update) {
		if (defined('DOING_AUTOSAVE') && DOING_AUTOSAVE) {
			return;
		}
		if (! $post || ! is_object($post)) {
			$post = get_post($post_id);
		}
		if (! $post || 'crm_payment' !== $post->post_type) {
			return;
		}
		if ('publish' !== $post->post_status) {
			return;
		}
		$status = get_post_meta($post_id, '_crm_payment_status', true);
		if ('paid' !== $status) {
			return;
		}
		if ((int) get_post_meta($post_id, '_crm_payment_tracked', true) === 1) {
			return;
		}

		$amount = (float) get_post_meta($post_id, '_crm_payment_amount', true);
		$when   = get_post_meta($post_id, '_crm_payment_paid_date', true);
		if (! $when) {
			$when = current_time('Y-m-d');
		}

		self::log_activity('payment_recorded', $post_id, array('amount' => $amount), $when);
		update_post_meta($post_id, '_crm_payment_tracked', 1);
	}

	private static function maybe_create_alliance_maintenance_task($alliance, $task_type, $today = '', $args = array()) {
		$alliance = self::sanitize_alliance_record((array) $alliance, (array) $alliance);
		if (empty($alliance['id']) || empty($alliance['name'])) {
			return 0;
		}
		$today = $today ?: current_time('Y-m-d');
		$args = wp_parse_args($args, array(
			'title' => '',
			'lead_id' => 0,
			'description' => '',
			'message' => '',
			'priority' => 'medium',
			'suffix' => $today,
		));
		$title = $args['title'] ?: ((self::alliance_task_type_labels()[$task_type] ?? 'Tarea alianza') . ' — ' . (string) $alliance['name']);
		$task_id = self::create_alliance_task_once(
			$alliance,
			$task_type,
			$title,
			$today,
			self::alliance_task_auto_key((string) $alliance['id'], $task_type, (string) $args['suffix']),
			array(
				'priority' => (string) $args['priority'],
				'description' => (string) $args['description'],
				'lead_id' => (int) $args['lead_id'],
			)
		);
		if ($task_id && ! get_post_meta($task_id, 'twob_task_mensaje_ia', true) && '' !== trim((string) $args['message'])) {
			update_post_meta($task_id, 'twob_task_mensaje_ia', trim((string) $args['message']));
			update_post_meta($task_id, 'twob_task_mensaje_ia_fecha', (int) current_time('timestamp'));
		}
		return (int) $task_id;
	}

	private static function run_alliance_automation($today = '') {
		$today = $today ?: current_time('Y-m-d');
		$alliances = self::alliances_get();
		if (empty($alliances)) {
			return;
		}

		foreach ($alliances as $alliance) {
			$alliance = self::sanitize_alliance_record((array) $alliance, (array) $alliance);
			$alliance_id = (string) ($alliance['id'] ?? '');
			$status = sanitize_key((string) ($alliance['status'] ?? 'contacted'));
			if ('' === $alliance_id || '' === trim((string) ($alliance['name'] ?? ''))) {
				continue;
			}

			if ('contacted' !== $status) {
				self::cancel_alliance_pending_tasks($alliance_id, array('alianza_contacto', 'alianza_seguimiento'), 'La alianza cambió de estado y se canceló la secuencia inicial.');
			} else {
				$d7_task = self::alliance_next_pending_task($alliance_id, array('alianza_seguimiento'));
				if ($d7_task instanceof WP_Post) {
					$slot = sanitize_key((string) get_post_meta((int) $d7_task->ID, 'twob_task_sequence_slot', true));
					$due = (string) get_post_meta((int) $d7_task->ID, '_crm_task_due', true);
					if ('d7' === $slot && $due && $due < $today) {
						self::alliance_record_update($alliance_id, array(
							'status' => 'no_response',
							'last_activity_at' => current_time('mysql'),
						));
						self::cancel_alliance_pending_tasks($alliance_id, array('alianza_contacto', 'alianza_seguimiento'), 'La alianza quedó como Sin respuesta después del último intento.');
						$status = 'no_response';
					}
				}
			}

			if ('active' !== $status) {
				continue;
			}

			$alert = self::alliance_alert_meta($alliance, $today);
			$last_referred_company = self::alliance_latest_referred_company((string) $alliance['name']);

			if (empty($alert['pending_commissions']) && ('orange' === $alert['level'] || '' === $alert['level'])) {
				$needs_reactivation = ! $alert['last_referred_day'] || self::days_between_dates((string) $alert['last_referred_day'], $today) >= 30;
				if ($needs_reactivation) {
					$prompt = 'Eres el asistente de Danitza de 2B Consulting. La agencia ' . (string) $alliance['name'] . ' es aliada activa pero no ha referido clientes en 30+ días. Genera mensaje WhatsApp (máx 3 líneas). Tono: cálido, de colega, no de vendedor. Si tiene referidos previos: mencionar el último. Si no tiene: recordar sutilmente la oportunidad. Contacto: ' . (string) ($alliance['contact_name'] ?: 'equipo') . '. Referidos previos: ' . (string) ($alert['referred_count'] ?? 0) . '. Último referido: ' . ($last_referred_company ?: 'sin referidos todavía') . '. Solo el mensaje.';
					$fallback = 'Hola ' . (trim((string) ($alliance['contact_name'] ?: 'equipo'))) . ', paso a saludar y a recordar que seguimos disponibles para apoyar con diagnósticos técnicos cuando te aparezca un cliente con sitio activo. Si quieres, te dejo un ejemplo concreto para moverlo rápido.';
					self::maybe_create_alliance_maintenance_task($alliance, 'alianza_reactivacion', $today, array(
						'title' => 'Reactivar alianza — ' . (string) $alliance['name'],
						'priority' => 'medium',
						'suffix' => substr($today, 0, 7),
						'message' => self::alliance_generate_text($prompt, $fallback, 160),
						'description' => 'La alianza activa no ha referido clientes en 30+ días.',
					));
				}
			}

			foreach ((array) $alert['pending_commissions'] as $pending_lead_id) {
				$pending_lead_id = (int) $pending_lead_id;
				if (! $pending_lead_id) {
					continue;
				}
				$company = (string) get_post_meta($pending_lead_id, '_crm_company', true) ?: get_the_title($pending_lead_id);
				$message = 'Hola ' . (trim((string) ($alliance['contact_name'] ?: 'equipo'))) . ', te confirmo la transferencia de $35.000 por el referido de ' . $company . '. ¡Gracias por la confianza! Seguimos disponibles para los próximos.';
				self::maybe_create_alliance_maintenance_task($alliance, 'alianza_comision', $today, array(
					'title' => 'Pagar comisión — ' . (string) $alliance['name'],
					'lead_id' => $pending_lead_id,
					'priority' => 'high',
					'suffix' => 'lead_' . $pending_lead_id,
					'message' => $message,
					'description' => 'Hay un diagnóstico ganado pendiente de comisión.',
				));
			}

			$last_contact_day = (string) ($alert['last_contact_day'] ?? '');
			if ($last_contact_day && self::days_between_dates($last_contact_day, $today) >= 60) {
				$prompt = 'Genera mensaje WhatsApp de check-in para ' . (string) ($alliance['contact_name'] ?: 'equipo') . ' de ' . (string) $alliance['name'] . '. Tono: ponerse al día, preguntar cómo va el negocio, recordar sutilmente que 2B sigue activo y disponible para referidos. Máximo 3 líneas. Solo el mensaje.';
				$fallback = 'Hola ' . (trim((string) ($alliance['contact_name'] ?: 'equipo'))) . ', ¿cómo han estado? Paso a saludar y a recordar que seguimos activos por si aparece un cliente al que le sirva un diagnóstico técnico del sitio.';
				self::maybe_create_alliance_maintenance_task($alliance, 'alianza_checkin', $today, array(
					'title' => 'Check-in alianza — ' . (string) $alliance['name'],
					'priority' => 'medium',
					'suffix' => substr($today, 0, 7),
					'message' => self::alliance_generate_text($prompt, $fallback, 160),
					'description' => 'No se registra contacto con esta alianza en 60+ días.',
				));
			}
		}
	}

	public static function run_daily_automation() {
		$today = current_time('Y-m-d');
		$in_3_days = self::add_chile_business_days($today, 3);
		$in_30_days = date('Y-m-d', strtotime($today . ' +30 days'));
		self::ensure_daily_operational_tasks($today);
		self::run_reactivation_timeout_automation($today);
		self::run_alliance_automation($today);

		$leads = self::get_active_leads(array('numberposts' => -1, 'orderby' => 'date', 'order' => 'DESC'));
		foreach ($leads as $lead) {
			$lead_id = (int) $lead->ID;
			$stage = (string) get_post_meta($lead_id, '_crm_stage', true);
			if (self::lead_should_auto_close_on_day12($lead_id, $today)) {
				self::auto_close_lead_without_response($lead_id, $today);
				continue;
			}
			self::update_temperature($lead_id); // AUTO-9
			self::update_operational_status($lead_id, $today);
			if (self::is_operationally_archived_lead($lead_id, $today)) {
				self::close_open_commercial_tasks_for_lead($lead_id, 'archive', 'Lead fuera del flujo diario por inactividad o fin de secuencia.', 'daily_operational_archive');
				continue;
			}

			$latest_interaction = get_posts(array(
				'post_type' => 'crm_interaction',
				'post_status' => 'publish',
				'numberposts' => 1,
				'orderby' => 'date',
				'order' => 'DESC',
				'meta_query' => array(array('key' => '_crm_lead_id', 'value' => $lead_id, 'compare' => '=')),
			));
			$last_date = '';
			if (! empty($latest_interaction[0])) {
				$last_date = (string) get_post_meta($latest_interaction[0]->ID, '_crm_interaction_date', true);
			}
			if (! $last_date) {
				$last_date = substr((string) $lead->post_date, 0, 10);
			}
			$days_without_activity = self::business_days_between_dates($last_date, $today);

			// AUTO-3 y AUTO-4: propuestas sin respuesta
			if ('proposal_sent' === $stage) {
				if ($days_without_activity >= 3) {
					self::create_auto_task_once($lead_id, 'Seguimiento suave de propuesta: ' . $lead->post_title, 'proposal', 'medium', $today, 'auto3_' . $lead_id . '_' . $last_date);
				}
				if ($days_without_activity >= 7) {
					self::create_auto_task_once($lead_id, 'Seguimiento directo de propuesta: ' . $lead->post_title, 'proposal', 'high', $today, 'auto4_' . $lead_id . '_' . $last_date);
				}
			}

			// AUTO-7: renovacion en 30 dias
			if ('won' === $stage) {
				$renewal = (string) get_post_meta($lead_id, '_crm_renewal_date', true);
				if ($renewal && $renewal <= $in_30_days && $renewal >= $today) {
					self::create_auto_task_once($lead_id, 'Aviso renovacion cliente: ' . $lead->post_title, 'renewal', 'medium', $today, 'auto7_' . $lead_id . '_' . $renewal);
				}
			}

			// AUTO-8: cerrado perdido hace 90 dias
			if ('lost' === $stage) {
				if (self::reactivation_lead_is_eligible($lead_id)) {
					continue;
				}
				$lost_changes = get_posts(array(
					'post_type' => 'crm_activity',
					'post_status' => 'publish',
					'numberposts' => 1,
					'orderby' => 'date',
					'order' => 'DESC',
					'meta_query' => array(
						'relation' => 'AND',
						array('key' => '_crm_action', 'value' => 'stage_changed', 'compare' => '='),
						array('key' => '_crm_object_id', 'value' => $lead_id, 'compare' => '='),
						array('key' => '_crm_stage', 'value' => 'lost', 'compare' => '='),
					),
				));
				if (! empty($lost_changes[0])) {
					$lost_date = substr((string) $lost_changes[0]->post_date, 0, 10);
					$days_lost = (int) floor((strtotime($today) - strtotime($lost_date)) / DAY_IN_SECONDS);
					if ($days_lost >= 90) {
						self::create_auto_task_once($lead_id, 'Reactivacion sugerida: ' . $lead->post_title, 'followup', 'low', $today, 'auto8_' . $lead_id . '_' . $lost_date);
					}
				}
			}
		}

		$payments = get_posts(array('post_type' => 'crm_payment', 'post_status' => 'publish', 'numberposts' => -1));
		foreach ($payments as $payment) {
			$payment_id = (int) $payment->ID;
			$status = (string) get_post_meta($payment_id, '_crm_payment_status', true);
			$due = (string) get_post_meta($payment_id, '_crm_payment_due_date', true);
			$lead_id = (int) get_post_meta($payment_id, '_crm_lead_id', true);
			if (! $lead_id || ! $due) {
				continue;
			}
			// AUTO-5
			if ('pending' === $status && $due <= $in_3_days && $due >= $today) {
				self::create_auto_task_once($lead_id, 'Cobro por vencer: ' . get_the_title($lead_id), 'collection', 'medium', $today, 'auto5_' . $payment_id . '_' . $due);
			}
			// AUTO-6
			if ('paid' !== $status && $due < $today) {
				update_post_meta($payment_id, '_crm_payment_status', 'overdue');
				self::create_auto_task_once($lead_id, 'Cobro vencido: ' . get_the_title($lead_id), 'collection', 'high', $today, 'auto6_' . $payment_id . '_' . $due);
			}
		}
	}

	public static function ajax_quick_action() {
		check_ajax_referer(self::NONCE_ACTION, 'nonce');
		if (! self::user_can_access_crm()) {
			wp_send_json_error(array('message' => 'Sin permisos.'));
		}
		$action = isset($_POST['quick_action']) ? sanitize_text_field(wp_unslash($_POST['quick_action'])) : '';
		$today  = current_time('Y-m-d');
		$item_labels = array(
			'crm_lead' => 'Lead',
			'crm_task' => 'Tarea',
			'crm_payment' => 'Cobro',
			'crm_interaction' => 'Interaccion',
		);

		if ('set_stage' === $action) {
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
			if (! $lead) {
				wp_send_json_error(array('message' => 'Lead invalido.'));
			}
			if (! self::current_user_can_edit_crm_post($lead_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para editar este lead.'));
			}
			$stage = self::validate_stage_choice(isset($_POST['stage']) ? wp_unslash($_POST['stage']) : 'new');
			if (is_wp_error($stage)) {
				wp_send_json_error(array('message' => $stage->get_error_message()));
			}
			$lost_reason = isset($_POST['lost_reason']) ? sanitize_textarea_field(wp_unslash($_POST['lost_reason'])) : '';
			$result = self::set_lead_stage($lead_id, $stage, 'ajax_set_stage', $lost_reason);
			if (is_wp_error($result)) {
				wp_send_json_error(array('message' => $result->get_error_message()));
			}
			self::maybe_google_sync_followup_for_current_user($lead_id);
			self::sync_master_client_for_lead($lead_id);
			wp_send_json_success(array('message' => 'Etapa actualizada.'));
		}

		if ('archive_lead' === $action || 'reactivate_lead' === $action) {
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
			if (! $lead) {
				wp_send_json_error(array('message' => 'Lead invalido.'));
			}
			if (! self::current_user_can_edit_crm_post($lead_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para editar este lead.'));
			}
			if ('archive_lead' === $action) {
				self::set_manual_archive_state($lead_id, true, 'Archivado manualmente para sacar backlog del flujo diario.', $today);
				wp_send_json_success(array('message' => 'Lead enviado a archivo operativo.'));
			}
			self::set_manual_archive_state($lead_id, false, '', $today);
			wp_send_json_success(array('message' => 'Lead reactivado para trabajar hoy.'));
		}

		if ('log_contact' === $action || 'log_followup' === $action) {
			if (! current_user_can('edit_crm_interactions')) {
				wp_send_json_error(array('message' => 'No tienes permisos para registrar interacciones.'));
			}
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
			if (! $lead) {
				wp_send_json_error(array('message' => 'Lead invalido.'));
			}
			if (! self::current_user_can_edit_crm_post($lead_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para registrar interacciones en este lead.'));
			}
			$kind = ('log_contact' === $action) ? 'contact' : 'followup';
			$stage = (string) get_post_meta($lead_id, '_crm_stage', true);
			if ('followup' === $kind && 'proposal_sent' === $stage && self::has_recent_proposal_followup($lead_id, $today)) {
				wp_send_json_error(array('message' => 'Debes esperar minimo 3 dias entre seguimientos de propuesta.'));
			}

			$interaction_id = wp_insert_post(array(
				'post_type'   => 'crm_interaction',
				'post_status' => 'publish',
				'post_title'  => ucfirst($kind) . ': ' . wp_strip_all_tags(get_the_title($lead_id)),
				'meta_input' => array(
					'_crm_interaction_kind' => $kind,
					'_crm_lead_id'          => $lead_id,
					'_crm_interaction_date' => $today,
					'_crm_interaction_channel' => 'whatsapp',
					'_crm_interaction_action' => self::normalize_interaction_action('', $kind, 'whatsapp'),
					'_crm_interaction_result' => 'other',
				),
			));
			if (! $interaction_id || is_wp_error($interaction_id)) {
				wp_send_json_error(array('message' => 'No se pudo registrar la interaccion.'));
			}
			self::update_temperature($lead_id);
			wp_send_json_success(array('message' => 'Interaccion registrada.'));
		}

		if ('new_task' === $action) {
			if (! current_user_can('edit_crm_tasks')) {
				wp_send_json_error(array('message' => 'No tienes permisos para crear tareas.'));
			}
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
			if (! $lead) {
				wp_send_json_error(array('message' => 'Lead invalido.'));
			}
			if (! self::current_user_can_edit_crm_post($lead_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para crear tareas en este lead.'));
			}
			$due = self::sanitize_date_input(isset($_POST['due']) ? wp_unslash($_POST['due']) : $today, false, 'Fecha de tarea');
			if (is_wp_error($due)) {
				wp_send_json_error(array('message' => $due->get_error_message()));
			}

			$task_id = wp_insert_post(array(
				'post_type'   => 'crm_task',
				'post_status' => 'publish',
				'post_title'  => 'Tarea: ' . wp_strip_all_tags(get_the_title($lead_id)),
			));
			if (! $task_id || is_wp_error($task_id)) {
				wp_send_json_error(array('message' => 'No se pudo crear la tarea.'));
			}
			$task_type = 'followup';
			update_post_meta($task_id, '_crm_task_due', $due);
			update_post_meta($task_id, '_crm_task_status', 'pending');
			update_post_meta($task_id, '_crm_task_lead_id', $lead_id);
			update_post_meta($task_id, '_crm_task_type', $task_type);
			update_post_meta($task_id, '_crm_task_category', self::task_category_for_type($task_type));
			update_post_meta($task_id, '_crm_task_relation', 'lead_client');
			update_post_meta($task_id, '_crm_task_assignee', 'dani');
			update_post_meta($task_id, '_crm_task_pipeline_stage', (string) get_post_meta($lead_id, '_crm_stage', true));
			update_post_meta($task_id, '_crm_task_recurrence', 'none');
			wp_send_json_success(array('message' => 'Tarea creada.'));
		}

		if ('mark_task_done' === $action) {
			$task_id = isset($_POST['task_id']) ? absint($_POST['task_id']) : 0;
			$task = self::get_valid_crm_post($task_id, 'crm_task');
			if (! $task) {
				wp_send_json_error(array('message' => 'Tarea invalida.'));
			}
			if (! self::current_user_can_edit_crm_post($task_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para editar esta tarea.'));
			}
			if (self::task_requires_guided_completion($task_id)) {
				wp_send_json_error(array(
					'message' => 'Esta tarea comercial se cierra registrando la interaccion asociada.',
					'require_task_completion' => true,
					'task' => self::task_completion_context_payload($task_id),
				));
			}
			update_post_meta($task_id, '_crm_task_status', 'done');
			self::log_activity('task_completed', $task_id, array('task_type' => (string) get_post_meta($task_id, '_crm_task_type', true)));
			self::maybe_create_next_recurring_task($task_id);
			self::sync_google_task_status_prefix($task_id, 'done');
			$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
			if ($lead_id) {
				self::sync_lead_next_action($lead_id);
			}
			wp_send_json_success(array('message' => 'Tarea marcada como completada.'));
		}

		if ('mark_responded' === $action) {
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
			if (! $lead) {
				wp_send_json_error(array('message' => 'Lead invalido.'));
			}
			if (! self::current_user_can_edit_crm_post($lead_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para editar este lead.'));
			}
			$result = self::set_lead_stage($lead_id, 'responded_interested', 'ajax_mark_responded');
			if (is_wp_error($result)) {
				wp_send_json_error(array('message' => $result->get_error_message()));
			}
			self::close_sequence_tasks_for_lead($lead_id, 'El lead respondio. La secuencia automatica se cerro para evitar duplicados.', $today);
			$interaction_id = self::ensure_today_positive_response_interaction($lead_id, $today, 'Respuesta confirmada desde el panel HOY.');
			if (! $interaction_id) {
				wp_send_json_error(array('message' => 'No se pudo registrar la respuesta del lead.'));
			}
			self::set_lead_next_followup_meta($lead_id, $today, 'Responder lead');
			self::update_temperature($lead_id);
			self::update_operational_status($lead_id, $today);
			self::maybe_google_sync_followup_for_current_user($lead_id);
			self::sync_master_client_for_lead($lead_id);
			wp_send_json_success(array('message' => 'Lead marcado como respondido y movido a interesados.'));
		}

		if ('mark_won' === $action) {
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
			if (! $lead) {
				wp_send_json_error(array('message' => 'Lead invalido.'));
			}
			if (! self::current_user_can_edit_crm_post($lead_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para editar este lead.'));
			}
			$result = self::set_lead_stage($lead_id, 'won', 'ajax_mark_won');
			if (is_wp_error($result)) {
				wp_send_json_error(array('message' => $result->get_error_message()));
			}
			self::sync_master_client_for_lead($lead_id);
			wp_send_json_success(array('message' => 'Lead marcado como ganado.'));
		}

		if ('mark_finding_reviewed' === $action) {
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
			if (! $lead) {
				wp_send_json_error(array('message' => 'Lead invalido.'));
			}
			if (! self::current_user_can_edit_crm_post($lead_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para editar este lead.'));
			}
			$technical_finding = trim((string) get_post_meta($lead_id, '_crm_technical_finding', true));
			if (! $technical_finding) {
				$technical_finding = self::renata_review_placeholder();
				update_post_meta($lead_id, '_crm_technical_finding', $technical_finding);
			}
			update_post_meta($lead_id, '_crm_technical_reviewed_at', current_time('mysql'));
			self::sync_open_sequence_task_descriptions_for_lead($lead_id);
			wp_send_json_success(array('message' => 'Hallazgo tecnico marcado como revisado.'));
		}

		if ('save_technical_finding' === $action) {
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$technical_finding = isset($_POST['technical_finding']) ? wp_unslash($_POST['technical_finding']) : '';
			$result = self::save_lead_technical_finding($lead_id, $technical_finding);
			if (is_wp_error($result)) {
				wp_send_json_error(array('message' => $result->get_error_message()));
			}
			wp_send_json_success(array(
				'message' => 'Hallazgo tecnico guardado.',
				'technical_finding' => $result['technical_finding'] ?? '',
			));
		}

		if ('activate_precontact' === $action) {
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$first_contact_channel = isset($_POST['first_contact_channel']) ? wp_unslash($_POST['first_contact_channel']) : '';
			$result = self::activate_precontact_lead($lead_id, $today, $first_contact_channel);
			if (is_wp_error($result)) {
				wp_send_json_error(array('message' => $result->get_error_message()));
			}
			$policy = sanitize_key((string) ($result['sequence_policy'] ?? 'full'));
			$message = 'Lead activado y primer contacto registrado.';
			if ('manual' === $policy) {
				$message .= ' Este canal queda sin secuencia automática.';
			} elseif ('short' === $policy) {
				$message .= ' Se generó solo D+3.';
			} else {
				$message .= ' Se generó el ciclo normal desde D+3.';
			}
			wp_send_json_success(array(
				'message' => $message,
				'next_followup' => (string) ($result['next_followup'] ?? ''),
			));
		}

		if ('save_reactivation_field' === $action) {
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$field = isset($_POST['field']) ? wp_unslash($_POST['field']) : '';
			$value = isset($_POST['value']) ? wp_unslash($_POST['value']) : '';
			$result = self::save_reactivation_field($lead_id, $field, $value);
			if (is_wp_error($result)) {
				wp_send_json_error(array('message' => $result->get_error_message()));
			}
			wp_send_json_success(array(
				'message' => 'Campo de investigación guardado.',
				'field' => (string) $result['field'],
				'value' => $result['value'],
				'payload' => $result['payload'],
			));
		}

		if ('generate_reactivation_sequence' === $action) {
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$result = self::generate_reactivation_sequence_for_lead($lead_id, $today);
			if (is_wp_error($result)) {
				wp_send_json_error(array('message' => $result->get_error_message()));
			}
			wp_send_json_success(array(
				'message' => 'Secuencia de reactivación creada para Dani.',
				'tasks' => array_values(array_map('intval', (array) ($result['tasks'] ?? array()))),
				'sequence' => array_values((array) ($result['sequence'] ?? array())),
			));
		}

		if ('resolve_reactivation_task' === $action) {
			$task_id = isset($_POST['task_id']) ? absint($_POST['task_id']) : 0;
			$outcome = isset($_POST['outcome']) ? wp_unslash($_POST['outcome']) : '';
			$extra = array(
				'email' => isset($_POST['email']) ? wp_unslash($_POST['email']) : '',
				'phone' => isset($_POST['phone']) ? wp_unslash($_POST['phone']) : '',
				'meeting_date' => isset($_POST['meeting_date']) ? wp_unslash($_POST['meeting_date']) : '',
				'reason' => isset($_POST['reason']) ? wp_unslash($_POST['reason']) : '',
				'note' => isset($_POST['note']) ? wp_unslash($_POST['note']) : '',
			);
			$result = self::resolve_reactivation_task($task_id, $outcome, $extra, $today);
			if (is_wp_error($result)) {
				wp_send_json_error(array('message' => $result->get_error_message()));
			}
			wp_send_json_success($result);
		}

		if ('update_lead_card' === $action) {
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
			if (! $lead) {
				wp_send_json_error(array('message' => 'Lead invalido.'));
			}
			if (! self::current_user_can_edit_crm_post($lead_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para editar este lead.'));
			}
			$stage = self::validate_stage_choice(isset($_POST['stage']) ? wp_unslash($_POST['stage']) : 'new');
			if (is_wp_error($stage)) {
				wp_send_json_error(array('message' => $stage->get_error_message()));
			}
			$lead_name = isset($_POST['lead_name']) ? sanitize_text_field(wp_unslash($_POST['lead_name'])) : '';
			$next = self::sanitize_date_input(isset($_POST['next_followup']) ? wp_unslash($_POST['next_followup']) : '', true, 'Proximo seguimiento');
			if (is_wp_error($next)) {
				wp_send_json_error(array('message' => $next->get_error_message()));
			}
			$email = isset($_POST['email']) ? sanitize_email(wp_unslash($_POST['email'])) : '';
			$phone = isset($_POST['phone']) ? sanitize_text_field(wp_unslash($_POST['phone'])) : '';
			$website_url = isset($_POST['website_url']) ? esc_url_raw(wp_unslash($_POST['website_url'])) : '';
			$linkedin_person = isset($_POST['linkedin_person']) ? esc_url_raw(wp_unslash($_POST['linkedin_person'])) : '';
			$linkedin_company = isset($_POST['linkedin_company']) ? esc_url_raw(wp_unslash($_POST['linkedin_company'])) : '';
			$origin_channel = isset($_POST['origin_channel']) ? sanitize_text_field(wp_unslash($_POST['origin_channel'])) : '';
			$client_type = isset($_POST['client_type']) ? sanitize_text_field(wp_unslash($_POST['client_type'])) : '';
			$service_interest = isset($_POST['service_interest']) ? sanitize_text_field(wp_unslash($_POST['service_interest'])) : '';
			$budget = self::sanitize_budget_input(isset($_POST['budget']) ? wp_unslash($_POST['budget']) : '');
			$employee_count_raw = isset($_POST['employee_count']) ? trim((string) wp_unslash($_POST['employee_count'])) : '';
			$employee_count = '' !== $employee_count_raw ? max(0, (int) $employee_count_raw) : '';
			$value = self::sanitize_amount_input(isset($_POST['value']) ? wp_unslash($_POST['value']) : 0);
			$company = isset($_POST['company']) ? sanitize_text_field(wp_unslash($_POST['company'])) : '';
			$observations = isset($_POST['observations']) ? sanitize_textarea_field(wp_unslash($_POST['observations'])) : '';
			$lost_reason = isset($_POST['lost_reason']) ? sanitize_textarea_field(wp_unslash($_POST['lost_reason'])) : '';
			$technical_finding = isset($_POST['technical_finding']) ? sanitize_textarea_field(wp_unslash($_POST['technical_finding'])) : '';
			$previous_temperature = self::normalize_temperature((string) get_post_meta($lead_id, '_crm_temperature', true), false);
			$temperature = self::normalize_temperature(isset($_POST['temperature']) ? wp_unslash($_POST['temperature']) : '', false);
			if (! $temperature) {
				$temperature = self::lead_temperature($lead_id);
			}
			$temperature_manual = ! empty($_POST['temperature_manual']);
			$alliance_source = isset($_POST['alliance_source']) ? sanitize_text_field(wp_unslash($_POST['alliance_source'])) : '';
			if ('referral' !== sanitize_key((string) $origin_channel)) {
				$alliance_source = '';
			}
			$current_title = get_the_title($lead_id);
			$lead_name_for_validation = '' !== $lead_name ? $lead_name : $current_title;
			$validation = self::validate_lead_payload(array(
				'name' => $lead_name_for_validation,
				'email' => $email,
				'phone' => $phone,
				'origin_channel' => $origin_channel,
				'client_type' => $client_type,
				'service_interest' => $service_interest,
				'company' => $company,
				'website_url' => $website_url,
			), self::is_pre_contact_stage($stage) ? 'pre_contact' : 'contacted');
			if (is_wp_error($validation)) {
				wp_send_json_error(array('message' => $validation->get_error_message()));
			}
			$result = self::set_lead_stage($lead_id, $stage, 'ajax_update_lead', $lost_reason);
			if (is_wp_error($result)) {
				wp_send_json_error(array('message' => $result->get_error_message()));
			}
			$resolved_stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
			if (self::lead_stage_requires_next_action($resolved_stage) && '' === $next) {
				wp_send_json_error(array('message' => 'Este lead sigue activo. Debes dejar la proxima accion antes de guardar.'));
			}
			if ('' !== $lead_name && $lead_name !== $current_title) {
				wp_update_post(array(
					'ID' => $lead_id,
					'post_title' => $lead_name,
				));
			}
			self::set_lead_next_followup_meta($lead_id, 'lost' === $resolved_stage ? '' : $next);
			update_post_meta($lead_id, '_crm_company', $company);
			update_post_meta($lead_id, '_crm_email', $email);
			update_post_meta($lead_id, '_crm_phone', $phone);
			update_post_meta($lead_id, '_crm_employee_count', $employee_count);
			update_post_meta($lead_id, '_crm_website_url', $website_url);
			update_post_meta($lead_id, '_crm_has_website', $website_url ? 'yes' : 'no');
			update_post_meta($lead_id, '_crm_linkedin_person', $linkedin_person);
			update_post_meta($lead_id, '_crm_linkedin_company', $linkedin_company);
			update_post_meta($lead_id, '_crm_origin_channel', $origin_channel);
			update_post_meta($lead_id, '_crm_client_type', $client_type);
			update_post_meta($lead_id, '_crm_service_interest', $service_interest);
			update_post_meta($lead_id, '_crm_budget', $budget);
			update_post_meta($lead_id, '_crm_value', $value);
			update_post_meta($lead_id, '_crm_alliance_source', $alliance_source);
			update_post_meta($lead_id, '_crm_technical_finding', $technical_finding);
			update_post_meta($lead_id, '_crm_observations', $observations);
			update_post_meta($lead_id, '_crm_qualification_notes', $observations);
			update_post_meta($lead_id, '_crm_referred_by', $alliance_source);
			self::update_lead_sequence_policy($lead_id, $origin_channel);
			self::sync_open_sequence_task_descriptions_for_lead($lead_id);
			self::maybe_google_sync_followup_for_current_user($lead_id);
			self::sync_master_client_for_lead($lead_id);
			self::apply_temperature_selection($lead_id, $temperature, $origin_channel, $resolved_stage, $temperature_manual, $previous_temperature);
			wp_send_json_success(array('message' => 'Lead actualizado.'));
		}

		if ('add_interaction_detailed' === $action) {
			if (! current_user_can('edit_crm_interactions')) {
				wp_send_json_error(array('message' => 'No tienes permisos para registrar interacciones.'));
			}
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$task_id = isset($_POST['task_id']) ? absint($_POST['task_id']) : 0;
			$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
			if (! $lead) {
				wp_send_json_error(array('message' => 'Selecciona un lead valido.'));
			}
			if (! self::current_user_can_edit_crm_post($lead_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para registrar interacciones en este lead.'));
			}
			$kind = self::sanitize_interaction_kind(isset($_POST['kind']) ? wp_unslash($_POST['kind']) : 'contact');
			$channel = self::sanitize_interaction_channel(isset($_POST['channel']) ? wp_unslash($_POST['channel']) : 'whatsapp');
			$action_label = self::normalize_interaction_action(isset($_POST['interaction_action']) ? wp_unslash($_POST['interaction_action']) : '', $kind, $channel);
			$result = self::sanitize_interaction_result(isset($_POST['result']) ? wp_unslash($_POST['result']) : 'other');
			$stage_update = self::validate_stage_choice(isset($_POST['stage']) ? wp_unslash($_POST['stage']) : '', true, 'Etapa de lead');
			if (is_wp_error($stage_update)) {
				wp_send_json_error(array('message' => $stage_update->get_error_message()));
			}
			$date = self::sanitize_date_input(isset($_POST['interaction_date']) ? wp_unslash($_POST['interaction_date']) : $today, false, 'Fecha de interaccion');
			if (is_wp_error($date)) {
				wp_send_json_error(array('message' => $date->get_error_message()));
			}
				$next = self::sanitize_date_input(isset($_POST['next_followup']) ? wp_unslash($_POST['next_followup']) : '', true, 'Proximo seguimiento');
			if (is_wp_error($next)) {
				wp_send_json_error(array('message' => $next->get_error_message()));
			}
				$note = isset($_POST['note']) ? sanitize_textarea_field(wp_unslash($_POST['note'])) : '';
				$stage = (string) get_post_meta($lead_id, '_crm_stage', true);
				$current_stage = self::normalize_stage_key($stage);
				$current_lifecycle = self::lead_lifecycle_state($lead_id, $date ?: $today);
				$current_next_followup = (string) get_post_meta($lead_id, '_crm_next_followup', true);
			if ('followup' === $kind && 'proposal_sent' === $stage && self::has_recent_proposal_followup($lead_id, $date)) {
				wp_send_json_error(array('message' => 'Debes esperar minimo 3 dias entre seguimientos de propuesta.'));
			}
			if (! $stage_update) {
				if (self::interaction_result_is_positive($result)) {
					$stage_update = self::task_resolution_stage_suggestion($result, $current_stage);
				} elseif ('closed' === $current_lifecycle || self::is_closed_detail_stage($current_stage)) {
					$stage_update = 'contacted';
				}
			}
			if ('lost' === $stage_update && '' === trim($note)) {
				wp_send_json_error(array('message' => 'Debes indicar el motivo en la nota para marcar el lead como perdido.'));
			}
			if ('lost' !== $stage_update && '' === $next && (! $current_next_followup || $current_next_followup <= $date)) {
				wp_send_json_error(array('message' => 'Debes dejar la proxima accion para que este lead siga activo en el sistema.'));
			}

			$interaction_id = wp_insert_post(array(
				'post_type'   => 'crm_interaction',
				'post_status' => 'publish',
				'post_title'  => ucfirst($kind) . ': ' . wp_strip_all_tags(get_the_title($lead_id)),
				'meta_input' => array(
					'_crm_interaction_kind' => $kind,
					'_crm_lead_id' => $lead_id,
					'_crm_task_id' => $task_id,
					'_crm_interaction_date' => $date,
					'_crm_interaction_channel' => $channel,
					'_crm_interaction_action' => $action_label,
					'_crm_interaction_result' => $result,
					'_crm_interaction_stage' => $stage_update,
					'_crm_interaction_next_followup' => $next,
					'_crm_interaction_note' => $note,
				),
			));

			if (! $interaction_id || is_wp_error($interaction_id)) {
				wp_send_json_error(array('message' => 'No se pudo registrar la interaccion.'));
			}

			if ('meeting_booked' === $result && 'meeting_scheduled' !== $stage) {
				self::set_lead_stage($lead_id, 'meeting_scheduled', 'ajax_interaction');
			}
				if ($stage_update) {
					$stage_result = self::set_lead_stage($lead_id, $stage_update, 'ajax_interaction_stage', ('lost' === $stage_update) ? $note : '');
					if (is_wp_error($stage_result)) {
						wp_send_json_error(array('message' => $stage_result->get_error_message()));
					}
				}
				if (('closed' === $current_lifecycle || (bool) get_post_meta($lead_id, '_crm_manual_archive', true)) && 'rejected' !== $result) {
					delete_post_meta($lead_id, '_crm_manual_archive');
					delete_post_meta($lead_id, '_crm_manual_archive_at');
					delete_post_meta($lead_id, '_crm_manual_archive_reason');
				}
				$resolved_stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
				if (self::is_closed_detail_stage($resolved_stage)) {
					self::set_lead_next_followup_meta($lead_id, '');
				} elseif ($next) {
					self::set_lead_next_followup_meta($lead_id, $next);
			} elseif ($current_next_followup && $current_next_followup <= $date) {
				self::set_lead_next_followup_meta($lead_id, '');
			} else {
				self::sync_lead_next_action($lead_id);
			}
				if (self::interaction_result_is_positive($result)) {
					delete_post_meta($lead_id, '_crm_manual_archive');
					delete_post_meta($lead_id, '_crm_manual_archive_at');
					delete_post_meta($lead_id, '_crm_manual_archive_reason');
					self::close_sequence_tasks_for_lead($lead_id, 'El lead respondio. La secuencia automatica se cerro para evitar duplicados.', $date);
					self::set_lead_next_followup_meta($lead_id, $next ?: $date, 'Responder lead');
				}
				self::sync_lead_lifecycle_state($lead_id, $date);
				self::update_temperature($lead_id);
				self::update_operational_status($lead_id, $date);
			self::maybe_google_sync_followup_for_current_user($lead_id);
			self::sync_master_client_for_lead($lead_id);
			$task_resolution = self::maybe_complete_open_task_from_interaction($lead_id, (int) $interaction_id, array(
				'task_id' => $task_id,
				'date' => $date,
				'kind' => $kind,
				'channel' => $channel,
				'interaction_action' => $action_label,
				'result' => $result,
				'note' => $note,
				'next_followup' => (string) get_post_meta($lead_id, '_crm_next_followup', true),
				'resolved_stage' => $resolved_stage,
			));
			$message = 'Interaccion registrada.';
			if (! empty($task_resolution['task_id'])) {
				$message = ! empty($task_resolution['next_task_id'])
					? 'Interaccion registrada, tarea relacionada completada y proximo seguimiento programado.'
					: 'Interaccion registrada y tarea relacionada completada.';
			} elseif ('lost' === $resolved_stage) {
				$message = 'Interaccion registrada y el lead quedo cerrado como perdido.';
			}
			wp_send_json_success(array(
				'message' => $message,
				'resolved_task_id' => (int) ($task_resolution['task_id'] ?? 0),
				'next_task_id' => (int) ($task_resolution['next_task_id'] ?? 0),
			));
		}

		if ('add_task_detailed' === $action) {
			if (! current_user_can('edit_crm_tasks')) {
				wp_send_json_error(array('message' => 'No tienes permisos para crear tareas.'));
			}
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$relation = self::sanitize_task_relation(isset($_POST['relation']) ? wp_unslash($_POST['relation']) : 'lead_client');
			$lead = $lead_id ? self::get_valid_crm_post($lead_id, 'crm_lead') : null;
			if ('lead_client' === $relation && ! $lead) {
				wp_send_json_error(array('message' => 'Selecciona un lead para tareas comerciales.'));
			}
			if ($lead_id && $lead && ! self::current_user_can_edit_crm_post($lead_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para crear tareas en este lead.'));
			}
			if ('internal' === $relation) {
				$lead_id = 0;
			}
			$title = isset($_POST['title']) ? sanitize_text_field(wp_unslash($_POST['title'])) : '';
			$description = isset($_POST['description']) ? sanitize_textarea_field(wp_unslash($_POST['description'])) : '';
			$category = self::sanitize_task_category(isset($_POST['category']) ? wp_unslash($_POST['category']) : 'commercial');
			$type = self::sanitize_task_type(isset($_POST['task_type']) ? wp_unslash($_POST['task_type']) : '', $category);
			if ('commercial' === $category && 'lead_client' !== $relation) {
				$relation = 'lead_client';
			}
			if ('commercial' === $category && ! $lead_id) {
				wp_send_json_error(array('message' => 'Las tareas comerciales deben vincularse a un lead.'));
			}
			$assignee = self::sanitize_task_assignee(isset($_POST['assignee']) ? wp_unslash($_POST['assignee']) : 'dani');
			$priority = self::sanitize_task_priority(isset($_POST['priority']) ? wp_unslash($_POST['priority']) : 'medium');
			$status = self::validate_task_status_choice(isset($_POST['task_status']) ? wp_unslash($_POST['task_status']) : 'pending');
			if (is_wp_error($status)) {
				wp_send_json_error(array('message' => $status->get_error_message()));
			}
			if ('done' === $status && 'commercial' === $category && 'lead_client' === $relation) {
				wp_send_json_error(array('message' => 'Las tareas comerciales no deben crearse ya completadas. Registra primero la gestion para cerrarlas.'));
			}
			$recurrence = self::validate_task_recurrence_choice(isset($_POST['recurrence']) ? wp_unslash($_POST['recurrence']) : 'none');
			if (is_wp_error($recurrence)) {
				wp_send_json_error(array('message' => $recurrence->get_error_message()));
			}
			$pipeline_stage = self::validate_stage_choice(isset($_POST['pipeline_stage']) ? wp_unslash($_POST['pipeline_stage']) : '', true, 'Etapa de pipeline');
			if (is_wp_error($pipeline_stage)) {
				wp_send_json_error(array('message' => $pipeline_stage->get_error_message()));
			}
			if ('internal' === $relation) {
				$pipeline_stage = '';
			}
			if ('lead_client' === $relation && $lead_id && ! $pipeline_stage) {
				$lead_stage = (string) get_post_meta($lead_id, '_crm_stage', true);
				if ($lead_stage && isset(self::stage_labels()[$lead_stage])) {
					$pipeline_stage = $lead_stage;
				}
			}
			$due = self::sanitize_date_input(isset($_POST['due']) ? wp_unslash($_POST['due']) : $today, false, 'Fecha de tarea');
			if (is_wp_error($due)) {
				wp_send_json_error(array('message' => $due->get_error_message()));
			}
			$start_time = self::sanitize_time_input(isset($_POST['start_time']) ? wp_unslash($_POST['start_time']) : '', true);
			if (is_wp_error($start_time)) {
				wp_send_json_error(array('message' => $start_time->get_error_message()));
			}
			$duration = isset($_POST['duration']) ? absint($_POST['duration']) : 0;
			$meeting_url = isset($_POST['meeting_url']) ? esc_url_raw(wp_unslash($_POST['meeting_url'])) : '';
			$meeting_location = isset($_POST['meeting_location']) ? sanitize_text_field(wp_unslash($_POST['meeting_location'])) : '';
			if (! $title) {
				$title = $lead_id ? ('Tarea: ' . wp_strip_all_tags(get_the_title($lead_id))) : 'Tarea interna';
			}
			if ($lead_id && 'proposal' === $type && self::has_recent_proposal_followup($lead_id, $due)) {
				wp_send_json_error(array('message' => 'Debes esperar minimo 3 dias entre seguimientos de propuesta.'));
			}
			if ('meeting' === $type) {
				$duration = max(15, min(240, $duration ? $duration : 30));
			} else {
				$duration = ('proposal' === $type) ? 30 : 15;
				$meeting_url = '';
				$meeting_location = '';
			}

			$task_id = wp_insert_post(array(
				'post_type' => 'crm_task',
				'post_status' => 'publish',
				'post_title' => $title,
				'post_content' => $description,
				'meta_input' => array(
					'_crm_task_due' => $due,
					'_crm_task_status' => $status,
					'_crm_task_lead_id' => $lead_id,
					'_crm_task_type' => $type,
					'_crm_task_priority' => $priority,
					'_crm_task_start_time' => $start_time,
					'_crm_task_duration' => $duration,
					'_crm_task_meeting_url' => $meeting_url,
					'_crm_task_meeting_location' => $meeting_location,
					'_crm_task_category' => $category,
					'_crm_task_relation' => $relation,
					'_crm_task_assignee' => $assignee,
					'_crm_task_pipeline_stage' => $pipeline_stage,
					'_crm_task_recurrence' => $recurrence,
				),
			));
			if (! $task_id || is_wp_error($task_id)) {
				wp_send_json_error(array('message' => 'No se pudo crear la tarea.'));
			}
			if ('done' === $status) {
				self::log_activity('task_completed', $task_id, array('task_type' => $type));
				self::maybe_create_next_recurring_task($task_id);
				self::sync_google_task_status_prefix($task_id, 'done');
			}
			self::maybe_google_sync_task_for_current_user($task_id);
			wp_send_json_success(array('message' => 'Tarea creada.'));
		}

		if ('set_task_status' === $action) {
			$task_id = isset($_POST['task_id']) ? absint($_POST['task_id']) : 0;
			$task = self::get_valid_crm_post($task_id, 'crm_task');
			if (! $task) {
				wp_send_json_error(array('message' => 'Tarea invalida.'));
			}
			if (! self::current_user_can_edit_crm_post($task_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para editar esta tarea.'));
			}
			$status = self::validate_task_status_choice(isset($_POST['task_status']) ? wp_unslash($_POST['task_status']) : 'pending');
			if (is_wp_error($status)) {
				wp_send_json_error(array('message' => $status->get_error_message()));
			}
			if ('done' === $status && self::task_requires_guided_completion($task_id)) {
				$resolution = self::complete_guided_task_resolution($task_id, $_POST, $today);
				if (is_wp_error($resolution)) {
					wp_send_json_error(array(
						'message' => $resolution->get_error_message(),
						'require_task_completion' => true,
						'task' => self::task_completion_context_payload($task_id),
					));
				}
				wp_send_json_success(array(
					'message' => $resolution['message'] ?? 'Gestion registrada y tarea completada.',
					'interaction_id' => (int) ($resolution['interaction_id'] ?? 0),
					'next_task_id' => (int) ($resolution['next_task_id'] ?? 0),
				));
			}
			update_post_meta($task_id, '_crm_task_status', $status);
			if ('done' === $status) {
				self::log_activity('task_completed', $task_id, array('task_type' => (string) get_post_meta($task_id, '_crm_task_type', true)));
				self::maybe_create_next_recurring_task($task_id);
			}
			self::sync_google_task_status_prefix($task_id, $status);
			$lead_id = (int) get_post_meta($task_id, '_crm_task_lead_id', true);
			if ($lead_id) {
				self::sync_lead_next_action($lead_id);
			}
			wp_send_json_success(array('message' => 'Tarea actualizada.'));
		}

		if ('sync_task_google' === $action) {
			if (! self::user_can_manage_google()) {
				wp_send_json_error(array('message' => 'No tienes permisos para sincronizar con Google Calendar.'));
			}
			$task_id = isset($_POST['task_id']) ? absint($_POST['task_id']) : 0;
			$task = self::get_valid_crm_post($task_id, 'crm_task');
			if (! $task) {
				wp_send_json_error(array('message' => 'Tarea invalida.'));
			}
			if (! self::current_user_can_edit_crm_post($task_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para sincronizar esta tarea.'));
			}
			$result = self::google_upsert_task_for_user($task_id, get_current_user_id());
			if (is_wp_error($result)) {
				wp_send_json_error(array('message' => $result->get_error_message()));
			}
			$slot = date_i18n('d-m-Y H:i', (int) $result['start_ts']);
			$message = 'Tarea sincronizada en Google Calendar (' . $slot . ').';
			if (! empty($result['moved'])) {
				$message .= ' El horario solicitado estaba ocupado y se movio al primer bloque libre.';
			}
			wp_send_json_success(array(
				'message' => $message,
				'event_link' => isset($result['html_link']) ? $result['html_link'] : '',
			));
		}

		if ('add_lead' === $action) {
			if (! current_user_can('edit_crm_leads')) {
				wp_send_json_error(array('message' => 'No tienes permisos para crear leads.'));
			}
			$name = isset($_POST['lead_name']) ? sanitize_text_field(wp_unslash($_POST['lead_name'])) : '';
			$next  = self::sanitize_date_input(isset($_POST['next_followup']) ? wp_unslash($_POST['next_followup']) : '', true, 'Proximo seguimiento');
			if (is_wp_error($next)) {
				wp_send_json_error(array('message' => $next->get_error_message()));
			}
			$company = isset($_POST['company']) ? sanitize_text_field(wp_unslash($_POST['company'])) : '';
			$email = isset($_POST['email']) ? sanitize_email(wp_unslash($_POST['email'])) : '';
			$phone = isset($_POST['phone']) ? sanitize_text_field(wp_unslash($_POST['phone'])) : '';
			$employee_count_raw = isset($_POST['employee_count']) ? trim((string) wp_unslash($_POST['employee_count'])) : '';
			$employee_count = '' !== $employee_count_raw ? max(0, (int) $employee_count_raw) : '';
			$website_url = isset($_POST['website_url']) ? esc_url_raw(wp_unslash($_POST['website_url'])) : '';
			$linkedin_person = isset($_POST['linkedin_person']) ? esc_url_raw(wp_unslash($_POST['linkedin_person'])) : '';
			$linkedin_company = isset($_POST['linkedin_company']) ? esc_url_raw(wp_unslash($_POST['linkedin_company'])) : '';
			$origin_channel = isset($_POST['origin_channel']) ? sanitize_text_field(wp_unslash($_POST['origin_channel'])) : '';
			$client_type = isset($_POST['client_type']) ? sanitize_text_field(wp_unslash($_POST['client_type'])) : '';
			$service_interest = isset($_POST['service_interest']) ? sanitize_text_field(wp_unslash($_POST['service_interest'])) : '';
			$budget = self::sanitize_budget_input(isset($_POST['budget']) ? wp_unslash($_POST['budget']) : '');
			$value = self::sanitize_amount_input(isset($_POST['value']) ? wp_unslash($_POST['value']) : 0);
			$notes = isset($_POST['observations']) ? sanitize_textarea_field(wp_unslash($_POST['observations'])) : '';
			$technical_finding = isset($_POST['technical_finding']) ? sanitize_textarea_field(wp_unslash($_POST['technical_finding'])) : '';
			$alliance_source = isset($_POST['alliance_source']) ? sanitize_text_field(wp_unslash($_POST['alliance_source'])) : '';
			if ('referral' !== sanitize_key((string) $origin_channel)) {
				$alliance_source = '';
			}
			$first_contact_channel = self::sanitize_interaction_channel(isset($_POST['first_contact_channel']) ? wp_unslash($_POST['first_contact_channel']) : 'linkedin');
			if (! isset(self::first_contact_channel_labels()[$first_contact_channel])) {
				$first_contact_channel = 'linkedin';
			}
			$create_task_now = ! empty($_POST['create_task_now']);
			$sequence_policy = self::sequence_policy_for_origin_channel($origin_channel);

			$validation = self::validate_lead_payload(array(
				'name' => $name,
				'email' => $email,
				'phone' => $phone,
				'origin_channel' => $origin_channel,
				'client_type' => $client_type,
				'service_interest' => $service_interest,
				'company' => $company,
				'website_url' => $website_url,
			), $creation_mode);
			if (is_wp_error($validation)) {
				wp_send_json_error(array('message' => $validation->get_error_message()));
			}

			$lead_id = wp_insert_post(array(
				'post_type'   => 'crm_lead',
				'post_status' => 'publish',
				'post_title'  => $name,
			));
			if (! $lead_id || is_wp_error($lead_id)) {
				wp_send_json_error(array('message' => 'No se pudo crear el lead.'));
			}
			$first_followup = $next;
			if (! $first_followup && 'manual' !== $sequence_policy) {
				$first_followup = self::add_chile_business_days($today, 3);
			} elseif ($first_followup) {
				$first_followup = self::normalize_business_due_day($first_followup);
			}
			self::set_lead_next_followup_meta($lead_id, $first_followup, $first_followup ? 'Seguimiento primer contacto' : '');
			update_post_meta($lead_id, '_crm_company', $company);
			update_post_meta($lead_id, '_crm_email', $email);
			update_post_meta($lead_id, '_crm_phone', $phone);
			update_post_meta($lead_id, '_crm_employee_count', $employee_count);
			update_post_meta($lead_id, '_crm_website_url', $website_url);
			update_post_meta($lead_id, '_crm_linkedin_person', $linkedin_person);
			update_post_meta($lead_id, '_crm_linkedin_company', $linkedin_company);
			update_post_meta($lead_id, '_crm_origin_channel', $origin_channel);
			update_post_meta($lead_id, '_crm_client_type', $client_type);
			update_post_meta($lead_id, '_crm_service_interest', $service_interest);
			update_post_meta($lead_id, '_crm_has_website', $website_url ? 'yes' : 'no');
			update_post_meta($lead_id, '_crm_sells_online', '');
			update_post_meta($lead_id, '_crm_budget', $budget);
			update_post_meta($lead_id, '_crm_value', $value);
			update_post_meta($lead_id, '_crm_alliance_source', $alliance_source);
			update_post_meta($lead_id, '_crm_technical_finding', $technical_finding);
			update_post_meta($lead_id, '_crm_urgency', '');
			update_post_meta($lead_id, '_crm_trust_level', '');
			update_post_meta($lead_id, '_crm_long_term_potential', '');
			update_post_meta($lead_id, '_crm_referred_by', $alliance_source);
			update_post_meta($lead_id, '_crm_sequence_policy', $sequence_policy);
			update_post_meta($lead_id, '_crm_sequence_policy_version', self::SEQUENCE_POLICY_VERSION);
			self::maybe_google_sync_followup_for_current_user($lead_id);
			update_post_meta($lead_id, '_crm_observations', $notes);
			update_post_meta($lead_id, '_crm_qualification_notes', $notes);
			update_post_meta($lead_id, '_crm_funnel_stage', 'contact');
			$interaction_id = 0;
			$stage_to_set = 'contacted';
			if ('pre_contact' === $creation_mode) {
				self::set_lead_next_followup_meta($lead_id, '');
				$stage_to_set = 'pre_contact';
			} else {
				$interaction_id = wp_insert_post(array(
					'post_type'   => 'crm_interaction',
					'post_status' => 'publish',
					'post_title'  => 'Contacto: ' . wp_strip_all_tags($name),
					'meta_input' => array(
						'_crm_interaction_kind' => 'contact',
						'_crm_lead_id' => $lead_id,
						'_crm_interaction_date' => $today,
						'_crm_interaction_channel' => $first_contact_channel,
						'_crm_interaction_action' => self::normalize_interaction_action('', 'contact', $first_contact_channel),
						'_crm_interaction_result' => 'other',
						'_crm_interaction_stage' => 'contacted',
						'_crm_interaction_next_followup' => $first_followup,
						'_crm_interaction_note' => $notes ? $notes : 'Primer contacto registrado al crear el lead.',
					),
				));
				if (! $interaction_id || is_wp_error($interaction_id)) {
					wp_delete_post($lead_id, true);
					wp_send_json_error(array('message' => 'No se pudo registrar la interaccion inicial del lead.'));
				}
				update_post_meta($lead_id, '_crm_first_contacted_at', current_time('mysql'));
				update_post_meta($lead_id, '_crm_first_contact_channel', $first_contact_channel);
			}

			$stage_result = self::set_lead_stage($lead_id, $stage_to_set, 'ajax_add_lead_day0');
			if (is_wp_error($stage_result)) {
				if ($interaction_id) {
					wp_delete_post((int) $interaction_id, true);
				}
				wp_delete_post($lead_id, true);
				wp_send_json_error(array('message' => $stage_result->get_error_message()));
			}
			if ('pre_contact' !== $creation_mode) {
				$day3_step = self::lead_followup_step_by_slug('day3_linkedin_followup');
				if (! empty($day3_step) && 'manual' !== $sequence_policy && $first_followup) {
					self::create_auto_task_once(
						$lead_id,
						(string) $day3_step['title'] . wp_strip_all_tags($name),
						(string) $day3_step['type'],
						(string) $day3_step['priority'],
						$first_followup,
						'lead_sequence_' . $lead_id . '_day3_linkedin_followup',
						array(
							'description' => self::sequence_task_description_for_lead($lead_id, (string) $day3_step['description']),
						)
					);
				}
			}
			self::apply_temperature_selection($lead_id, '', $origin_channel, $stage_to_set, false, '');
			self::sync_master_client_for_lead($lead_id);
			if ('pre_contact' !== $creation_mode && $create_task_now && current_user_can('edit_crm_tasks')) {
				self::create_auto_task_once($lead_id, 'Tarea inmediata: ' . $name, 'followup', 'high', $today, 'lead_now_' . $lead_id . '_' . $today);
			}
			self::update_temperature($lead_id);
			self::update_operational_status($lead_id, $today);
			if ('pre_contact' === $creation_mode) {
				$message = 'Lead creado en Pre-contacto. No se genero ninguna tarea y ya aparece para revision de Renata.';
			} else {
				$message = 'Lead creado y primer mensaje registrado.';
				if ('manual' === $sequence_policy) {
					$message .= ' Este canal queda sin secuencia automática.';
				} elseif ('short' === $sequence_policy) {
					$message .= ' Se programó el seguimiento corto de D+3.';
				} else {
					$message .= ' Se programó el follow-up del día 3.';
				}
			}
			wp_send_json_success(array('message' => $message));
		}

		if ('add_payment' === $action) {
			if (! current_user_can('edit_crm_payments')) {
				wp_send_json_error(array('message' => 'No tienes permisos para registrar cobros.'));
			}
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
			if (! $lead) {
				wp_send_json_error(array('message' => 'Lead invalido.'));
			}
			if (! self::current_user_can_edit_crm_post($lead_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para registrar cobros en este lead.'));
			}
			$amount = self::sanitize_amount_input(isset($_POST['amount']) ? wp_unslash($_POST['amount']) : 0);
			$status = self::validate_payment_status_choice(isset($_POST['payment_status']) ? wp_unslash($_POST['payment_status']) : 'paid');
			if (is_wp_error($status)) {
				wp_send_json_error(array('message' => $status->get_error_message()));
			}
			$paid_date = self::sanitize_date_input(isset($_POST['paid_date']) ? wp_unslash($_POST['paid_date']) : $today, 'paid' === $status ? false : true, 'Fecha de pago');
			if (is_wp_error($paid_date)) {
				wp_send_json_error(array('message' => $paid_date->get_error_message()));
			}
			if ('paid' !== $status) {
				$paid_date = '';
			}

			$payment_id = wp_insert_post(array(
				'post_type'   => 'crm_payment',
				'post_status' => 'publish',
				'post_title'  => 'Cobro: ' . wp_strip_all_tags(get_the_title($lead_id)),
				'meta_input'  => array(
					'_crm_payment_amount'    => $amount,
					'_crm_payment_status'    => $status,
					'_crm_payment_paid_date' => ('paid' === $status) ? $paid_date : '',
					'_crm_lead_id'           => $lead_id,
				),
			));
			if (! $payment_id || is_wp_error($payment_id)) {
				wp_send_json_error(array('message' => 'No se pudo crear el cobro.'));
			}
			wp_send_json_success(array('message' => 'Cobro creado.'));
		}

		if ('add_payment_detailed' === $action) {
			if (! current_user_can('edit_crm_payments')) {
				wp_send_json_error(array('message' => 'No tienes permisos para registrar cobros.'));
			}
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
			if (! $lead) {
				wp_send_json_error(array('message' => 'Lead invalido.'));
			}
			if (! self::current_user_can_edit_crm_post($lead_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para registrar cobros en este lead.'));
			}
			$amount = self::sanitize_amount_input(isset($_POST['amount']) ? wp_unslash($_POST['amount']) : 0);
			$status = self::validate_payment_status_choice(isset($_POST['payment_status']) ? wp_unslash($_POST['payment_status']) : 'pending');
			if (is_wp_error($status)) {
				wp_send_json_error(array('message' => $status->get_error_message()));
			}
			$paid_date = self::sanitize_date_input(isset($_POST['paid_date']) ? wp_unslash($_POST['paid_date']) : '', 'paid' === $status, 'Fecha de pago');
			if (is_wp_error($paid_date)) {
				wp_send_json_error(array('message' => $paid_date->get_error_message()));
			}
			$due_date = self::sanitize_date_input(isset($_POST['due_date']) ? wp_unslash($_POST['due_date']) : '', true, 'Fecha de vencimiento');
			if (is_wp_error($due_date)) {
				wp_send_json_error(array('message' => $due_date->get_error_message()));
			}
			$service = isset($_POST['service']) ? sanitize_text_field(wp_unslash($_POST['service'])) : '';
			if ('paid' !== $status) {
				$paid_date = '';
			}
			if ('overdue' === $status && '' === $due_date) {
				wp_send_json_error(array('message' => 'Fecha de vencimiento es obligatoria para cobros vencidos.'));
			}

			$payment_id = wp_insert_post(array(
				'post_type' => 'crm_payment',
				'post_status' => 'publish',
				'post_title' => 'Cobro: ' . wp_strip_all_tags(get_the_title($lead_id)),
				'meta_input' => array(
					'_crm_payment_amount' => $amount,
					'_crm_payment_status' => $status,
					'_crm_payment_paid_date' => ('paid' === $status) ? $paid_date : '',
					'_crm_payment_due_date' => $due_date,
					'_crm_payment_service' => $service,
					'_crm_lead_id' => $lead_id,
				),
			));

			if (! $payment_id || is_wp_error($payment_id)) {
				wp_send_json_error(array('message' => 'No se pudo registrar el cobro.'));
			}
			self::log_activity('collection_reviewed', $payment_id, array('status' => $status), $today);
			wp_send_json_success(array('message' => 'Cobro registrado.'));
		}

		if ('set_payment_status' === $action) {
			$payment_id = isset($_POST['payment_id']) ? absint($_POST['payment_id']) : 0;
			$payment = self::get_valid_crm_post($payment_id, 'crm_payment');
			if (! $payment) {
				wp_send_json_error(array('message' => 'Cobro invalido.'));
			}
			if (! self::current_user_can_edit_crm_post($payment_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para editar este cobro.'));
			}
			$status = self::validate_payment_status_choice(isset($_POST['payment_status']) ? wp_unslash($_POST['payment_status']) : 'pending');
			if (is_wp_error($status)) {
				wp_send_json_error(array('message' => $status->get_error_message()));
			}
			self::log_activity('collection_reviewed', $payment_id, array('status' => $status), $today);
			update_post_meta($payment_id, '_crm_payment_status', $status);
			if ('paid' === $status) {
				update_post_meta($payment_id, '_crm_payment_paid_date', $today);
				if ((int) get_post_meta($payment_id, '_crm_payment_tracked', true) !== 1) {
					$amount = (float) get_post_meta($payment_id, '_crm_payment_amount', true);
					self::log_activity('payment_recorded', $payment_id, array('amount' => $amount), $today);
					update_post_meta($payment_id, '_crm_payment_tracked', 1);
				}
			} else {
				update_post_meta($payment_id, '_crm_payment_paid_date', '');
				update_post_meta($payment_id, '_crm_payment_tracked', 0);
			}
			wp_send_json_success(array('message' => 'Estado de cobro actualizado.'));
		}

		if ('delete_item' === $action) {
			$item_id = isset($_POST['item_id']) ? absint($_POST['item_id']) : 0;
			$item = $item_id ? get_post($item_id) : null;
			if (! $item || ! isset($item_labels[$item->post_type])) {
				wp_send_json_error(array('message' => 'Registro invalido.'));
			}
			if (! self::current_user_can_delete_crm_post($item_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para eliminar este registro.'));
			}
			delete_post_meta($item_id, '_crm_archived');
			$trashed = wp_trash_post($item_id);
			if (! $trashed) {
				wp_send_json_error(array('message' => 'No se pudo enviar el registro a la papelera.'));
			}
			wp_send_json_success(array('message' => $item_labels[$item->post_type] . ' enviado a la papelera.'));
		}

		if ('restore_item' === $action) {
			$item_id = isset($_POST['item_id']) ? absint($_POST['item_id']) : 0;
			$item = $item_id ? get_post($item_id) : null;
			if (! $item || ! isset($item_labels[$item->post_type])) {
				wp_send_json_error(array('message' => 'Registro invalido.'));
			}
			if (! self::current_user_can_edit_crm_post($item_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para restaurar este registro.'));
			}
			if ('crm_lead' === $item->post_type && self::is_legacy_archived_lead($item_id)) {
				$restored = self::restore_lead_record($item_id);
			} else {
				if ('trash' !== get_post_status($item_id)) {
					wp_send_json_error(array('message' => 'El registro no esta en la papelera.'));
				}
				$restored = wp_untrash_post($item_id);
			}
			if (! $restored) {
				wp_send_json_error(array('message' => 'No se pudo restaurar el registro.'));
			}
			wp_send_json_success(array('message' => $item_labels[$item->post_type] . ' restaurado correctamente.'));
		}

		if ('delete_item_permanently' === $action) {
			$item_id = isset($_POST['item_id']) ? absint($_POST['item_id']) : 0;
			$item = $item_id ? get_post($item_id) : null;
			if (! $item || ! isset($item_labels[$item->post_type])) {
				wp_send_json_error(array('message' => 'Registro invalido.'));
			}
			if (! self::current_user_can_delete_crm_post($item_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para eliminar este registro.'));
			}
			if ('trash' !== get_post_status($item_id) && ! ('crm_lead' === $item->post_type && self::is_legacy_archived_lead($item_id))) {
				wp_send_json_error(array('message' => 'Primero envia el registro a la papelera.'));
			}
			delete_post_meta($item_id, '_crm_archived');
			if ('crm_lead' === $item->post_type) {
				self::permanently_delete_lead_dependencies($item_id);
			}
			$deleted = wp_delete_post($item_id, true);
			if (! $deleted) {
				wp_send_json_error(array('message' => 'No se pudo eliminar el registro de forma permanente.'));
			}
			wp_send_json_success(array('message' => $item_labels[$item->post_type] . ' eliminado permanentemente.'));
		}

		if ('set_funnel_stage' === $action) {
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
			if (! $lead) {
				wp_send_json_error(array('message' => 'Lead invalido.'));
			}
			if (! self::current_user_can_edit_crm_post($lead_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para editar este lead.'));
			}
			$funnel_stage = self::validate_funnel_stage_choice(isset($_POST['funnel_stage']) ? wp_unslash($_POST['funnel_stage']) : 'contact');
			if (is_wp_error($funnel_stage)) {
				wp_send_json_error(array('message' => $funnel_stage->get_error_message()));
			}
			update_post_meta($lead_id, '_crm_funnel_stage', $funnel_stage);
			self::log_activity('funnel_stage_changed', $lead_id, array('funnel_stage' => $funnel_stage));
			wp_send_json_success(array('message' => 'Embudo actualizado.'));
		}

		if ('dismiss_ui_onboarding' === $action) {
			$section = isset($_POST['section']) ? sanitize_key(wp_unslash($_POST['section'])) : '';
			if (! $section) {
				wp_send_json_error(array('message' => 'Sección inválida.'));
			}
			self::mark_ui_onboarding_seen($section);
			wp_send_json_success(array('section' => $section));
		}

		if ('load_lead_panel' === $action) {
			$lead_id = isset($_POST['lead_id']) ? absint($_POST['lead_id']) : 0;
			$lead = self::get_valid_crm_post($lead_id, 'crm_lead');
			if (! $lead) {
				wp_send_json_error(array('message' => 'Lead invalido.'));
			}
			if (! self::current_user_can_view_crm_post($lead_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para ver este lead.'));
			}
			$settings = self::settings_get();
			ob_start();
			self::render_lead_editor_panel($lead_id, $settings, $today);
			wp_send_json_success(array(
				'html' => ob_get_clean(),
				'lead_id' => $lead_id,
				'title' => get_the_title($lead_id),
				'company' => (string) get_post_meta($lead_id, '_crm_company', true),
			));
		}

		if ('load_task_panel' === $action) {
			$task_id = isset($_POST['task_id']) ? absint($_POST['task_id']) : 0;
			$task = self::get_valid_crm_post($task_id, 'crm_task');
			if (! $task) {
				wp_send_json_error(array('message' => 'Tarea invalida.'));
			}
			if (! self::current_user_can_view_crm_post($task_id)) {
				wp_send_json_error(array('message' => 'No tienes permisos para ver esta tarea.'));
			}
			ob_start();
			self::render_task_detail_panel_html($task, $today);
			wp_send_json_success(array(
				'html' => ob_get_clean(),
				'task_id' => $task_id,
			));
		}

		wp_send_json_error(array('message' => 'Accion no valida.'));
	}

	private static function ui_onboarding_meta_key($section) {
		return 'twob_ui_visto_' . sanitize_key((string) $section);
	}

	private static function user_has_seen_ui_onboarding($section) {
		$user_id = get_current_user_id();
		if (! $user_id) {
			return true;
		}
		return (bool) get_user_meta($user_id, self::ui_onboarding_meta_key($section), true);
	}

	private static function mark_ui_onboarding_seen($section) {
		$user_id = get_current_user_id();
		if (! $user_id) {
			return false;
		}
		return (bool) update_user_meta($user_id, self::ui_onboarding_meta_key($section), 1);
	}

	private static function current_crm_persona() {
		$user_id = get_current_user_id();
		$plan = sanitize_key((string) get_user_meta($user_id, 'twob_plan_usuario', true));
		if (in_array($plan, array('renata', 'dani', 'danitza'), true)) {
			return 'renata' === $plan ? 'renata' : 'dani';
		}
		$user = wp_get_current_user();
		$display_name = $user ? strtolower((string) $user->display_name) : '';
		$user_login = $user ? strtolower((string) $user->user_login) : '';
		if (false !== strpos($display_name, 'renata') || false !== strpos($user_login, 'renata')) {
			return 'renata';
		}
		return 'dani';
	}

	private static function render_ui_onboarding_block($section, $html) {
		if (self::user_has_seen_ui_onboarding($section) || '' === trim((string) $html)) {
			return;
		}
		?>
