	private static function lead_list_status_badge($lead_id) {
		$lead_id = (int) $lead_id;
		$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		$detail = strtoupper(trim((string) self::lead_detail_status_label($lead_id, $stage)));
		$skip = array('EN SEGUIMIENTO', 'SEGUIMIENTO', '');
		if ($detail && ! in_array($detail, $skip, true)) {
			return array('key' => $stage, 'label' => $detail);
		}
		$priority = array(
			'meeting_scheduled' => 'REUNIÓN AGENDADA',
			'responded_interested' => 'INTERESADO',
			'proposal_sent' => 'PROPUESTA ENVIADA',
			'contacted' => 'CONTACTADO',
			'new' => 'NUEVO',
			'pre_contact' => 'PRE-CONTACTO',
		);
		if (isset($priority[$stage])) {
			return array('key' => $stage, 'label' => $priority[$stage]);
		}
		$operational = self::determine_operational_status($lead_id);
		$op_label = self::operational_status_labels()[$operational] ?? strtoupper($operational);
		if (in_array(strtoupper($op_label), $skip, true)) {
			$op_label = $detail ?: 'ACTIVO';
		}
		return array('key' => $operational, 'label' => strtoupper($op_label));
	}

	private static function lead_list_channel_badge($lead_id) {
		$channel = sanitize_key((string) get_post_meta((int) $lead_id, '_crm_origin_channel', true));
		$labels = self::channel_labels();
		return isset($labels[$channel]) ? $labels[$channel] : ($channel ? ucfirst($channel) : 'Sin canal');
	}

	private static function lead_list_row_indicator($lead_id, $today = '') {
		$score_meta = self::score_badge_meta(self::lead_score((int) $lead_id));
		return (string) ($score_meta['indicator'] ?? 'is-score-low');
	}

	private static function lead_list_next_action_short($lead_id) {
		$lead_id = (int) $lead_id;
		$next_action = trim((string) get_post_meta($lead_id, '_crm_next_action', true));
		if ($next_action) {
			return self::truncate_text($next_action, 20);
		}
		$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		if (self::is_pre_contact_stage($stage)) {
			return 'Esperando Renata';
		}
		return 'Sin acción';
	}

	private static function relative_day_label($date, $today = '') {
		$date = self::normalize_iso_day((string) $date);
		$today = $today ?: current_time('Y-m-d');
		if (! $date) {
			return '—';
		}
		if ($date === $today) {
			return 'hoy';
		}
		$diff = self::days_between_dates($date, $today);
		if ($diff > 0) {
			return 'en ' . $diff . ' d';
		}
		return 'hace ' . abs($diff) . ' d';
	}

	private static function status_badge($status, $labels, $class_prefix = 'twob-badge') {
		$status_key = sanitize_key((string) $status);
		$normalized = self::normalize_stage_key($status_key);
		$key_for_label = isset($labels[$status_key]) ? $status_key : (isset($labels[$normalized]) ? $normalized : $status_key);
		$label = isset($labels[$key_for_label]) ? $labels[$key_for_label] : ucfirst(str_replace('_', ' ', (string) $status_key));
		return '<span class="' . esc_attr($class_prefix . ' ' . $class_prefix . '-' . sanitize_html_class((string) $key_for_label)) . '">' . esc_html($label) . '</span>';
	}

	private static function render_lead_compact_row($lead, $selected_lead_id, $today) {
		if (! ($lead instanceof WP_Post)) {
			return;
		}

		$lead_id = (int) $lead->ID;
		$company = (string) get_post_meta($lead_id, '_crm_company', true);
		$next = (string) get_post_meta($lead_id, '_crm_next_followup', true);
		$is_selected = (int) $selected_lead_id === $lead_id;
		$status_badge = self::lead_list_status_badge($lead_id);
		$channel_label = self::lead_list_channel_badge($lead_id);
		$indicator = self::lead_list_row_indicator($lead_id, $today);
		$score_meta = self::score_badge_meta(self::lead_score($lead_id));
		$next_action = self::lead_list_next_action_short($lead_id);
		$seg_label = self::relative_day_label($next ?: self::lead_last_touch_day($lead_id), $today);
		?>
		<div class="twob-lead-row-v2<?php echo $is_selected ? ' is-selected' : ''; ?>" id="lead-<?php echo esc_attr($lead_id); ?>" data-lead-id="<?php echo esc_attr($lead_id); ?>" data-lead-title="<?php echo esc_attr($lead->post_title); ?>" tabindex="0" role="button" aria-selected="<?php echo $is_selected ? 'true' : 'false'; ?>">
			<span class="twob-lead-indicator twob-lead-indicator-<?php echo esc_attr($indicator); ?>"></span>
			<div class="twob-lead-row-title">
				<strong><?php echo esc_html($lead->post_title); ?></strong>
				<span><?php echo esc_html($company ?: 'Sin empresa'); ?></span>
			</div>
			<span class="twob-badge twob-badge-status"><?php echo esc_html($status_badge['label']); ?></span>
			<span class="twob-badge twob-badge-channel"><?php echo esc_html($channel_label); ?></span>
			<span class="twob-badge twob-badge-score <?php echo esc_attr($score_meta['class']); ?>"><?php echo esc_html($score_meta['label']); ?></span>
			<span class="twob-lead-next-action"><?php echo esc_html($next_action); ?></span>
			<span class="twob-lead-seg">Seg.: <?php echo esc_html($seg_label); ?></span>
			<span class="twob-lead-open-arrow" aria-hidden="true">→</span>
			<div class="twob-lead-row-hover-actions">
				<button type="button" class="button button-small twob-btn" data-action="log_followup" data-lead-id="<?php echo esc_attr($lead_id); ?>" data-lead-title="<?php echo esc_attr($lead->post_title); ?>">Registrar interacción</button>
				<button type="button" class="button button-small twob-lead-open-btn" data-lead-open="<?php echo esc_attr($lead_id); ?>">Abrir →</button>
			</div>
		</div>
		<?php
	}

