	}

	public static function render_leads_page() {
		$view = isset($_GET['view']) ? sanitize_key(wp_unslash($_GET['view'])) : 'active';
		if (! in_array($view, array('active', 'trash'), true)) {
			$view = 'active';
		}
		$is_trash_view = 'trash' === $view;
		$focus = isset($_GET['focus']) ? self::sanitize_operational_focus(wp_unslash($_GET['focus'])) : 'all';
		if ($is_trash_view) {
			$focus = 'all';
		}
		$search_query = isset($_GET['q']) ? sanitize_text_field(wp_unslash($_GET['q'])) : '';
		$selected_lead_id = isset($_GET['lead_id']) ? absint($_GET['lead_id']) : 0;
		$stage_filter = isset($_GET['stage']) ? sanitize_text_field(wp_unslash($_GET['stage'])) : '';
		$stage_filter = self::normalize_stage_key($stage_filter);
		$type_filter = isset($_GET['type']) ? sanitize_text_field(wp_unslash($_GET['type'])) : '';
		$channel_filter = isset($_GET['channel']) ? sanitize_text_field(wp_unslash($_GET['channel'])) : '';
		$service_filter = isset($_GET['service']) ? sanitize_text_field(wp_unslash($_GET['service'])) : '';
		$temperature_filter = self::normalize_temperature(isset($_GET['temperature']) ? wp_unslash($_GET['temperature']) : '', false);
		$date_from = self::sanitize_date_input(isset($_GET['date_from']) ? wp_unslash($_GET['date_from']) : '', true, 'Fecha ingreso desde');
		$date_to = self::sanitize_date_input(isset($_GET['date_to']) ? wp_unslash($_GET['date_to']) : '', true, 'Fecha ingreso hasta');
		$date_from = is_wp_error($date_from) ? '' : $date_from;
		$date_to = is_wp_error($date_to) ? '' : $date_to;
		if ($date_from && $date_to && $date_from > $date_to) {
			$tmp = $date_from;
			$date_from = $date_to;
			$date_to = $tmp;
		}
		$today = current_time('Y-m-d');
		$settings = self::settings_get();
		$lead_fetch_limit = -1;
		$active_url = admin_url('admin.php?page=twob-crm-visual-leads');
		$trash_url = admin_url('admin.php?page=twob-crm-visual-leads&view=trash');
		$trash_count = self::trashed_leads_count();
		$operational_filter_options = array(
			'all' => 'TODOS',
			'pre_contact' => self::operational_status_labels()['pre_contact'] ?? 'PRE-CONTACTO',
			'new' => self::operational_status_labels()['new'] ?? 'NUEVO',
			'contacted' => self::operational_status_labels()['contacted'] ?? 'CONTACTADO',
			'followup' => self::operational_status_labels()['followup'] ?? 'SEGUIMIENTO',
			'interested' => self::operational_status_labels()['interested'] ?? 'INTERESADO',
			'archive' => self::operational_status_labels()['archive'] ?? 'ARCHIVO',
		);
		$shared_filter_args = array('page' => 'twob-crm-visual-leads');
		if (! $is_trash_view && $focus && 'all' !== $focus && 'today' !== $focus) {
			$shared_filter_args['focus'] = $focus;
		}
		if ('' !== $search_query) {
			$shared_filter_args['q'] = $search_query;
		}
		if ($type_filter && isset($settings['client_types'][$type_filter])) {
			$shared_filter_args['type'] = $type_filter;
		}
		if ($channel_filter && isset(self::channel_labels()[$channel_filter])) {
			$shared_filter_args['channel'] = $channel_filter;
		}
		if ($service_filter && isset($settings['service_options'][$service_filter])) {
			$shared_filter_args['service'] = $service_filter;
		}
		if ($temperature_filter) {
			$shared_filter_args['temperature'] = $temperature_filter;
		}
		if ($date_from) {
			$shared_filter_args['date_from'] = $date_from;
		}
		if ($date_to) {
			$shared_filter_args['date_to'] = $date_to;
		}
		$all_stages_url = add_query_arg($shared_filter_args, admin_url('admin.php'));
		$results_summary = array();
		$leads = array();
		if ($is_trash_view) {
			$leads = self::get_trashed_leads(array(
				'post_type' => 'crm_lead',
				'numberposts' => $lead_fetch_limit,
				'orderby' => 'date',
				'order' => 'DESC',
			));
		} else {
			$meta_query = array();
			if ($stage_filter && isset(self::stage_labels()[$stage_filter])) {
				$meta_query[] = array('key' => '_crm_stage', 'value' => $stage_filter);
			}
			if ($type_filter && isset($settings['client_types'][$type_filter])) {
				$meta_query[] = array('key' => '_crm_client_type', 'value' => $type_filter);
			}
			if ($channel_filter && isset(self::channel_labels()[$channel_filter])) {
				$meta_query[] = array('key' => '_crm_origin_channel', 'value' => $channel_filter);
			}
			if ($service_filter && isset($settings['service_options'][$service_filter])) {
				$meta_query[] = array('key' => '_crm_service_interest', 'value' => $service_filter);
			}
			$date_query = array();
			if ($date_from || $date_to) {
				$date_filter = array('inclusive' => true);
				if ($date_from) {
					$date_filter['after'] = $date_from;
				}
				if ($date_to) {
					$date_filter['before'] = $date_to;
				}
				$date_query[] = $date_filter;
			}
			$leads = self::get_active_leads(array(
				'post_type' => 'crm_lead',
				'post_status' => 'publish',
				'numberposts' => $lead_fetch_limit,
				'orderby' => 'date',
				'order' => 'DESC',
				'meta_query' => $meta_query,
				'date_query' => $date_query,
			));
		}
		if ($search_query) {
			$leads = self::filter_leads_by_search($leads, $search_query);
		}
		if (! $is_trash_view) {
			$leads = self::filter_leads_by_operational_focus($leads, $focus, $today);
			if ($temperature_filter) {
				$leads = array_values(array_filter($leads, function ($lead) use ($temperature_filter) {
					return ($lead instanceof WP_Post) && $temperature_filter === self::lead_temperature((int) $lead->ID);
				}));
			}
			usort($leads, function ($a, $b) {
				$a_id = ($a instanceof WP_Post) ? (int) $a->ID : 0;
				$b_id = ($b instanceof WP_Post) ? (int) $b->ID : 0;
				$a_pre = $a_id ? self::is_pre_contact_stage((string) get_post_meta($a_id, '_crm_stage', true)) : false;
				$b_pre = $b_id ? self::is_pre_contact_stage((string) get_post_meta($b_id, '_crm_stage', true)) : false;
				if ($a_pre !== $b_pre) {
					return $b_pre <=> $a_pre;
				}
				return strcmp((string) ($b->post_date ?? ''), (string) ($a->post_date ?? ''));
			});
		}
		$lead_count = count($leads);
		$results_summary[] = 'Mostrando ' . $lead_count . ' lead' . (1 === $lead_count ? '' : 's');
		if (! $is_trash_view && isset($operational_filter_options[$focus])) {
			$results_summary[] = 'Etapa operativa: ' . $operational_filter_options[$focus];
		}
		if ($search_query) {
			$results_summary[] = 'Busqueda: ' . $search_query;
		}
		if (! $is_trash_view && $stage_filter && isset(self::stage_labels()[$stage_filter])) {
			$results_summary[] = 'Detalle comercial: ' . self::stage_labels()[$stage_filter];
		}
		if (! $is_trash_view && $type_filter && isset($settings['client_types'][$type_filter])) {
			$results_summary[] = 'Tipo: ' . $settings['client_types'][$type_filter];
		}
		if (! $is_trash_view && $channel_filter && isset(self::channel_labels()[$channel_filter])) {
			$results_summary[] = 'Canal: ' . self::channel_labels()[$channel_filter];
		}
		if (! $is_trash_view && $service_filter && isset($settings['service_options'][$service_filter])) {
			$results_summary[] = 'Servicio: ' . self::service_interest_label($service_filter);
		}
		if (! $is_trash_view && $temperature_filter) {
			$results_summary[] = 'Temperatura: ' . (self::temperature_labels()[$temperature_filter] ?? $temperature_filter);
		}
		if (! $is_trash_view && ($date_from || $date_to)) {
			$results_summary[] = 'Ingreso: ' . ($date_from ?: 'inicio') . ' a ' . ($date_to ?: 'hoy');
		}
		$dashboard_metrics = self::get_dashboard_metrics();
		$lifecycle_counts = self::dashboard_lifecycle_summary($today);
		$visible_today_count = count(self::get_dashboard_operational_tasks($today, 60));
		$lead_target = self::daily_new_leads_target();
		$lead_done = (int) ($dashboard_metrics['daily_new_leads'] ?? 0);
		?>
