						<a class="button" href="<?php echo esc_url($active_url); ?>">Activos</a>
						<a class="button button-primary" href="<?php echo esc_url($trash_url); ?>">Papelera (<?php echo esc_html((string) $trash_count); ?>)</a>
					</div>
				<?php endif; ?>
