							</div>
							<div class="twob-lead-compact-meta">
								<?php echo wp_kses_post(self::status_badge($stage, self::stage_labels(), 'twob-badge-stage')); ?>
								<small class="twob-task-due"><?php echo esc_html($is_legacy_archived ? 'Archivado legado' : 'En papelera'); ?>: <?php echo esc_html($trash_time ? date_i18n('d-m-Y H:i', $trash_time) : '-'); ?></small>
							</div>
						</div>
						<div class="twob-line-2">Desde esta vista puedes recuperar el lead o eliminarlo definitivamente.</div>
						<div class="twob-actions twob-actions-3">
							<button class="button twob-restore-item" data-item-id="<?php echo esc_attr($lead_id); ?>" data-item-label="<?php echo esc_attr($lead->post_title); ?>">Restaurar</button>
							<button class="button twob-danger twob-permanent-delete-item" data-item-id="<?php echo esc_attr($lead_id); ?>" data-item-label="<?php echo esc_attr($lead->post_title); ?>">Eliminar permanentemente</button>
						</div>
					</div>
				<?php endforeach; ?>
			</div>
			<?php endif; ?>
		</div>
		<?php
	}

	public static function render_interactions_page() {
		$today = current_time('Y-m-d');
		$focus = isset($_GET['focus']) ? sanitize_key(wp_unslash($_GET['focus'])) : '';
		$is_response_focus = 'responses' === $focus;
		$lead_query = isset($_GET['lead_q']) ? sanitize_text_field(wp_unslash($_GET['lead_q'])) : '';
		$selected_lead_id = isset($_GET['lead_id']) ? absint($_GET['lead_id']) : 0;
		$active_leads = self::get_active_leads(array('numberposts' => ($is_response_focus || '' !== $lead_query) ? -1 : 300, 'orderby' => 'date', 'order' => 'DESC'));
		$response_selectable_leads = $is_response_focus
			? self::get_response_selectable_leads(array('numberposts' => -1, 'orderby' => 'date', 'order' => 'DESC'))
			: array();
		$response_queue = array();
		$response_leads_by_id = array();
		$response_defaults = array();
		if ($is_response_focus) {
			$response_queue = self::get_dashboard_response_queue($today, 50);
			foreach ($response_queue as $item) {
				$lead = isset($item['lead']) ? $item['lead'] : null;
				if (! ($lead instanceof WP_Post) || 'crm_lead' !== $lead->post_type) {
					continue;
				}
				$lead_id = (int) $lead->ID;
				$response_leads_by_id[$lead_id] = $lead;
				$response_defaults[$lead_id] = array(
					'channel' => self::sanitize_interaction_channel((string) ($item['channel'] ?? 'whatsapp')),
					'action' => self::response_received_action_for_channel((string) ($item['channel'] ?? 'whatsapp')),
					'result' => self::sanitize_interaction_result((string) ($item['result'] ?? 'interested')),
				);
			}
			$all_leads = ! empty($response_selectable_leads) ? $response_selectable_leads : $active_leads;
			if (! empty($response_leads_by_id)) {
				usort($all_leads, function ($a, $b) use ($response_leads_by_id) {
					$a_id = ($a instanceof WP_Post) ? (int) $a->ID : 0;
					$b_id = ($b instanceof WP_Post) ? (int) $b->ID : 0;
					$a_has_response = isset($response_leads_by_id[$a_id]) ? 1 : 0;
					$b_has_response = isset($response_leads_by_id[$b_id]) ? 1 : 0;
					if ($a_has_response !== $b_has_response) {
						return $b_has_response <=> $a_has_response;
					}
					return strcmp((string) ($a->post_title ?? ''), (string) ($b->post_title ?? ''));
				});
			}
		} else {
			$all_leads = $active_leads;
		}
		$filtered_leads = self::filter_leads_by_search($all_leads, $lead_query);
		if (! $selected_lead_id && '' !== $lead_query && 1 === count($filtered_leads)) {
			$selected_lead_id = (int) $filtered_leads[0]->ID;
		}
		if (! $selected_lead_id && $is_response_focus && ! empty($filtered_leads[0])) {
			if (! empty($response_leads_by_id)) {
				$selected_lead_id = (int) $filtered_leads[0]->ID;
			}
		}
		if ($selected_lead_id && 'crm_lead' !== get_post_type($selected_lead_id)) {
			$selected_lead_id = 0;
		}
		$form_leads = ! empty($filtered_leads) ? $filtered_leads : $all_leads;
		$interaction_args = array(
			'post_type' => 'crm_interaction',
			'post_status' => 'publish',
				'numberposts' => $selected_lead_id ? -1 : 250,
			'orderby' => 'date',
			'order' => 'DESC',
		);
		if ($selected_lead_id) {
			$interaction_args['meta_query'] = array(
				array('key' => '_crm_lead_id', 'value' => $selected_lead_id, 'compare' => '='),
			);
		}
		$interactions = get_posts($interaction_args);
		$interaction_groups = array();
			foreach ($interactions as $interaction) {
				$lead_id = (int) get_post_meta($interaction->ID, '_crm_lead_id', true);
				if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
					continue;
				}
				if ($is_response_focus && ! $selected_lead_id && ! isset($response_leads_by_id[$lead_id])) {
					continue;
				}
				if ($lead_query && ! self::lead_matches_search($lead_id, $lead_query)) {
					continue;
				}
			if (! isset($interaction_groups[$lead_id])) {
				$interaction_groups[$lead_id] = array(
					'lead' => get_post($lead_id),
					'items' => array(),
				);
			}
			$interaction_groups[$lead_id]['items'][] = $interaction;
		}
		$matching_count = count($filtered_leads);
		$response_detected_count = count($response_queue);
		$available_leads_count = count($form_leads);
		$history_group_count = count($interaction_groups);
		?>
			<div class="wrap twob-crm-visual twob-page twob-page-interactions">
				<h1><?php echo esc_html($is_response_focus ? 'Respuestas e interesados' : 'Interacciones'); ?></h1>
				<p class="twob-muted"><?php echo esc_html($is_response_focus ? 'Aqui Dani registra lo que sigue despues de una respuesta real. Elige el lead que respondio y deja el siguiente paso sin buscarlo en otra pantalla.' : 'Registro guiado de contacto, historial por cliente y acceso rapido a la ficha comercial.'); ?></p>
				<?php self::render_ui_onboarding_block('interacciones', self::interactions_education_html($is_response_focus)); ?>
				<div class="twob-onboarding-template" data-twob-onboarding-template="interacciones" hidden><?php echo self::interactions_education_html($is_response_focus); // phpcs:ignore ?></div>
				<div class="twob-grid twob-grid-2">
					<div class="twob-card">
						<h3><?php echo esc_html($is_response_focus ? 'Registrar siguiente paso' : 'Registrar interaccion'); ?></h3>
						<p class="twob-muted"><?php echo esc_html($is_response_focus ? 'Cuando un lead responde, Dani registra aqui la respuesta recibida y el paso siguiente. Si no aparece en la bandeja de la derecha, igual puedes buscarlo o elegirlo manualmente arriba.' : 'Aqui caben tanto contactos directos como gestiones suaves: reaccionar o comentar una publicacion, aceptar conexion o cualquier accion comercial real que deje el lead mas cerca.'); ?></p>
						<?php if ($is_response_focus) : ?>
							<div class="twob-helper-box">
								<strong>Si hoy no aparece en la bandeja, igual puedes registrarlo aqui.</strong>
								<span>Elige manualmente el lead, deja el canal real, registra la respuesta recibida y agenda el siguiente paso sin salir de esta pantalla.</span>
							</div>
						<?php endif; ?>
						<div class="twob-grid twob-grid-3">
							<?php if ($is_response_focus) : ?><div class="twob-form-row twob-col-span-2"><label>Buscar lead rapido</label><input type="text" id="twob_interaction_lead_search" value="<?php echo esc_attr($lead_query); ?>" placeholder="Nombre, empresa, correo o telefono"></div><?php endif; ?>
							<div class="twob-form-row"><label><?php echo esc_html($is_response_focus ? 'Lead que respondio' : 'Lead'); ?></label><select id="twob_interaction_lead"><?php if ($is_response_focus) : ?><option value="0" <?php selected($selected_lead_id, 0); ?>>Selecciona el lead que respondio</option><?php elseif (! $form_leads) : ?><option value="0">Sin leads disponibles</option><?php endif; ?><?php foreach ($form_leads as $lead) : $lead_id = (int) $lead->ID; $lead_defaults = $response_defaults[$lead_id] ?? array(); $lead_open_task_id = self::primary_open_task_for_lead($lead_id); ?><option value="<?php echo esc_attr($lead_id); ?>" data-search="<?php echo esc_attr(self::lead_search_haystack($lead_id)); ?>" data-stage="<?php echo esc_attr((string) get_post_meta($lead_id, '_crm_stage', true)); ?>" data-open-task-id="<?php echo esc_attr((string) $lead_open_task_id); ?>"<?php if (! empty($lead_defaults['channel'])) : ?> data-response-channel="<?php echo esc_attr($lead_defaults['channel']); ?>"<?php endif; ?><?php if (! empty($lead_defaults['action'])) : ?> data-response-action="<?php echo esc_attr($lead_defaults['action']); ?>"<?php endif; ?><?php if (! empty($lead_defaults['result'])) : ?> data-response-result="<?php echo esc_attr($lead_defaults['result']); ?>"<?php endif; ?> <?php selected($selected_lead_id, $lead_id); ?>><?php echo esc_html($lead->post_title); ?></option><?php endforeach; ?></select><input type="hidden" id="twob_interaction_task_id" value="<?php echo esc_attr((string) ($selected_lead_id ? self::primary_open_task_for_lead($selected_lead_id) : 0)); ?>"></div>
							<div class="twob-form-row"><label>Tipo</label><select id="twob_interaction_kind"><?php foreach (self::interaction_kind_labels() as $key => $label) : ?><option value="<?php echo esc_attr($key); ?>" <?php selected($is_response_focus ? 'followup' : 'contact', $key); ?>><?php echo esc_html($label); ?></option><?php endforeach; ?></select></div>
							<div class="twob-form-row"><label>Canal</label><select id="twob_interaction_channel"><?php foreach (self::channel_labels() as $key => $label) : ?><option value="<?php echo esc_attr($key); ?>" <?php selected($is_response_focus ? 'whatsapp' : '', $key); ?>><?php echo esc_html($label); ?></option><?php endforeach; ?></select></div>
							<div class="twob-form-row"><label>Accion o respuesta registrada</label><select id="twob_interaction_action"><?php foreach (self::interaction_action_labels() as $key => $label) : ?><option value="<?php echo esc_attr($key); ?>"><?php echo esc_html($label); ?></option><?php endforeach; ?></select></div>
						<div class="twob-form-row"><label>Resultado</label><select id="twob_interaction_result"><?php foreach (self::interaction_result_labels() as $key => $label) : ?><option value="<?php echo esc_attr($key); ?>" <?php selected($is_response_focus ? 'interested' : 'other', $key); ?>><?php echo esc_html($label); ?></option><?php endforeach; ?></select></div>
						<div class="twob-form-row"><label>Detalle comercial relacionado</label><select id="twob_interaction_stage"><?php foreach (self::stage_labels() as $key => $label) : ?><option value="<?php echo esc_attr($key); ?>" <?php selected($is_response_focus ? 'responded_interested' : '', $key); ?>><?php echo esc_html($label); ?></option><?php endforeach; ?></select></div>
						<div class="twob-form-row"><label>Fecha</label><input type="date" id="twob_interaction_date" value="<?php echo esc_attr($today); ?>"></div>
						<div class="twob-form-row"><label>Proximo seguimiento</label><input type="date" id="twob_interaction_next_followup"></div>
						<div class="twob-form-row twob-col-span-2"><label>Notas</label><div id="twob_interaction_notes_wrap"><textarea class="twob-interaction-note" rows="3" placeholder="Resumen corto de la conversacion"></textarea></div><button class="button button-small" type="button" id="twob_add_interaction_note">+ Agregar nota</button></div>
					</div>
					<p><button class="button button-primary" type="button" id="twob_add_interaction">Registrar interaccion</button></p>
					</div>
	
					<div class="twob-card">
						<?php if ($is_response_focus) : ?>
							<h3>Respuestas detectadas y busqueda manual</h3>
							<p class="twob-muted">Si aparece aqui, abrelo con un clic. Si no, buscala manualmente y registrala igual.</p>
							<form method="get">
								<input type="hidden" name="page" value="twob-crm-visual-interactions">
								<input type="hidden" name="focus" value="responses">
								<div class="twob-grid twob-grid-3 twob-compact-grid">
									<div class="twob-form-row twob-col-span-2"><label>Buscar lead manualmente</label><input type="text" name="lead_q" value="<?php echo esc_attr($lead_query); ?>" placeholder="Nombre, empresa, correo, telefono"></div>
									<div class="twob-form-row"><label>&nbsp;</label><button class="button button-primary" type="submit">Buscar</button></div>
								</div>
							</form>
							<?php if ($lead_query) : ?><div class="twob-line-2">Resultados para <strong><?php echo esc_html($lead_query); ?></strong>: <?php echo esc_html((string) $matching_count); ?></div><?php endif; ?>
							<?php if ($response_queue) : ?>
								<div class="twob-search-results">
									<?php foreach ($response_queue as $item) : ?>
										<?php $response_lead = isset($item['lead']) ? $item['lead'] : null; ?>
										<?php if (! ($response_lead instanceof WP_Post)) { continue; } ?>
										<?php $response_lead_id = (int) $response_lead->ID; ?>
										<a class="button button-small <?php echo $selected_lead_id === $response_lead_id ? 'button-primary' : ''; ?>" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-interactions&focus=responses&lead_id=' . $response_lead_id)); ?>"><?php echo esc_html($response_lead->post_title); ?></a>
									<?php endforeach; ?>
								</div>
							<?php endif; ?>
							<?php if ($lead_query && $matching_count > 0) : ?>
								<div class="twob-search-results">
									<?php foreach (array_slice($filtered_leads, 0, 8) as $lead) : ?>
										<a class="button button-small <?php echo $selected_lead_id === (int) $lead->ID ? 'button-primary' : ''; ?>" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-interactions&focus=responses&lead_id=' . (int) $lead->ID . ($lead_query ? '&lead_q=' . rawurlencode($lead_query) : ''))); ?>"><?php echo esc_html($lead->post_title); ?></a>
									<?php endforeach; ?>
								</div>
							<?php elseif (! $response_queue) : ?>
								<div class="twob-empty-card">No se detectaron respuestas recientes en la bandeja automatica. Si Dani ya vio una respuesta, puede elegir el lead manualmente aqui mismo y registrarla igual.</div>
								<div class="twob-search-results">
									<?php foreach (array_slice($form_leads, 0, 12) as $lead) : ?>
										<a class="button button-small <?php echo $selected_lead_id === (int) $lead->ID ? 'button-primary' : ''; ?>" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-interactions&focus=responses&lead_id=' . (int) $lead->ID)); ?>"><?php echo esc_html($lead->post_title); ?></a>
									<?php endforeach; ?>
								</div>
							<?php endif; ?>
							<?php if ($selected_lead_id) : ?>
								<?php self::render_lead_snapshot($selected_lead_id, array('title' => 'Ficha del lead que respondio', 'show_open_tasks' => false, 'show_history' => true, 'history_limit' => -1)); ?>
							<?php endif; ?>
						<?php else : ?>
							<h3>Buscador rapido y ficha</h3>
							<form method="get">
								<input type="hidden" name="page" value="twob-crm-visual-interactions">
								<div class="twob-grid twob-grid-3 twob-compact-grid">
									<div class="twob-form-row twob-col-span-2"><label>Buscar lead</label><input type="text" name="lead_q" value="<?php echo esc_attr($lead_query); ?>" placeholder="Nombre, empresa, correo, telefono"></div>
									<div class="twob-form-row"><label>&nbsp;</label><button class="button button-primary" type="submit">Buscar</button></div>
								</div>
							</form>
							<?php if ($lead_query) : ?><div class="twob-line-2">Resultados para <strong><?php echo esc_html($lead_query); ?></strong>: <?php echo esc_html((string) $matching_count); ?></div><?php endif; ?>
							<?php if ($selected_lead_id) : ?>
								<?php self::render_lead_snapshot($selected_lead_id, array('title' => 'Ficha del lead seleccionado', 'show_open_tasks' => false, 'show_history' => true, 'history_limit' => -1)); ?>
							<?php elseif ($lead_query && $matching_count > 0) : ?>
								<div class="twob-search-results">
									<?php foreach (array_slice($filtered_leads, 0, 8) as $lead) : ?>
										<a class="button button-small" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-interactions&lead_id=' . (int) $lead->ID . ($lead_query ? '&lead_q=' . rawurlencode($lead_query) : ''))); ?>"><?php echo esc_html($lead->post_title); ?></a>
									<?php endforeach; ?>
								</div>
							<?php else : ?>
								<div class="twob-empty">Busca un lead para abrir su ficha y revisar su historial sin salir de esta pantalla.</div>
							<?php endif; ?>
						<?php endif; ?>
					</div>
				</div>
	
				<div class="twob-card">
					<div class="twob-line-1">
						<strong><?php echo esc_html($selected_lead_id ? 'Historial completo del lead' : ($is_response_focus ? 'Historial de respuestas recientes' : 'Historial por lead')); ?></strong>
						<?php if ($selected_lead_id) : ?><a class="button button-small" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-interactions' . ($is_response_focus ? '&focus=responses' : '') . ($lead_query ? '&lead_q=' . rawurlencode($lead_query) : ''))); ?>">Ver todos</a><?php endif; ?>
					</div>
				<?php if ($selected_lead_id) : ?>
					<?php if (! empty($interaction_groups[$selected_lead_id]['items'])) : ?>
						<div class="twob-mini-list">
							<?php foreach ($interaction_groups[$selected_lead_id]['items'] as $idx => $interaction) : ?>
								<?php self::render_interaction_history_item($interaction, array('open' => 0 === $idx, 'show_lead' => false)); ?>
							<?php endforeach; ?>
						</div>
					<?php else : ?>
						<div class="twob-empty-card">Este lead aun no tiene interacciones registradas.</div>
					<?php endif; ?>
				<?php else : ?>
					<?php if (! $interaction_groups) : ?><div class="twob-empty-card">Aun no hay historial agrupado para mostrar.</div><?php endif; ?>
					<div class="twob-mini-list">
						<?php foreach ($interaction_groups as $lead_id => $group) : ?>
							<?php
							$lead = $group['lead'];
							if (! ($lead instanceof WP_Post)) {
								continue;
							}
							$company = (string) get_post_meta($lead_id, '_crm_company', true);
							$email = (string) get_post_meta($lead_id, '_crm_email', true);
							$phone = (string) get_post_meta($lead_id, '_crm_phone', true);
							$last_item = $group['items'][0] ?? null;
							$last_date = $last_item ? (string) get_post_meta($last_item->ID, '_crm_interaction_date', true) : '';
							$open_group = '' !== $lead_query && 1 === count($interaction_groups);
							?>
							<details class="twob-lead-history" <?php echo $open_group ? 'open' : ''; ?>>
								<summary class="twob-detail-summary">
									<div>
										<strong><?php echo esc_html($lead->post_title); ?></strong>
										<div class="twob-line-2"><?php echo esc_html($company ?: ($phone ?: $email ?: 'Sin contacto')); ?></div>
									</div>
									<div class="twob-line-2"><?php echo esc_html(count($group['items']) . ' interacciones'); ?><?php echo $last_date ? ' | ' . esc_html($last_date) : ''; ?></div>
								</summary>
								<div class="twob-detail-body">
									<div class="twob-task-actions">
										<a class="button button-small" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-leads&lead_id=' . $lead_id . '&q=' . rawurlencode((string) $lead->post_title)) . '#lead-' . $lead_id); ?>">Ver ficha</a>
											<a class="button button-small" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-interactions&lead_id=' . $lead_id . ($is_response_focus ? '&focus=responses' : '') . ($lead_query ? '&lead_q=' . rawurlencode($lead_query) : ''))); ?>">Abrir historial</a>
									</div>
									<div class="twob-mini-list">
										<?php foreach (array_slice($group['items'], 0, 12) as $interaction) : ?>
											<?php self::render_interaction_history_item($interaction, array('show_lead' => false)); ?>
										<?php endforeach; ?>
									</div>
								</div>
							</details>
						<?php endforeach; ?>
					</div>
				<?php endif; ?>
			</div>
			<?php self::render_ui_onboarding_reopen_link('interacciones'); ?>
		</div>
		<?php
	}

	public static function render_tasks_page() {
		$today = current_time('Y-m-d');
		$scope = self::current_crm_user_scope();
		$leads = self::get_active_leads(array('numberposts' => 300, 'orderby' => 'date', 'order' => 'DESC'));
		$open_tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => -1,
			'meta_key' => '_crm_task_due',
			'orderby' => 'meta_value',
			'order' => 'ASC',
			'meta_query' => array(
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
		));
		$done_tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => 120,
			'orderby' => 'date',
			'order' => 'DESC',
			'meta_query' => array(
				array('key' => '_crm_task_status', 'value' => 'done', 'compare' => '='),
			),
		));
			$open_tasks = array_values(array_filter($open_tasks, function ($task) use ($scope) {
				return self::task_matches_current_scope((int) $task->ID, $scope);
			}));
			$done_tasks = array_values(array_filter($done_tasks, function ($task) use ($scope) {
				return self::task_matches_current_scope((int) $task->ID, $scope);
			}));
			$today_tasks = array();
			$upcoming_tasks = array();
			$overdue_tasks = array();
			$historical_overdue_groups = array();
			$visible_today_tasks = array();
			$recurring_tasks = array();
			$current_month = substr($today, 0, 7);
		$task_type_map = array();
		foreach (self::task_types_by_category() as $cat_key => $type_keys) {
			$task_type_map[$cat_key] = array();
			foreach ($type_keys as $type_key) {
				$label = self::task_type_labels()[$type_key] ?? '';
				if ($label) {
					$task_type_map[$cat_key][$type_key] = $label;
				}
			}
		}
			foreach ($open_tasks as $task) {
				$task_id = (int) $task->ID;
				if (self::task_should_be_hidden_from_open_views($task_id)) {
					continue;
				}
				$due = (string) get_post_meta($task_id, '_crm_task_due', true);
				$recurrence = self::normalize_task_recurrence((string) get_post_meta($task_id, '_crm_task_recurrence', true));
				if ('none' !== $recurrence) {
					$recurring_tasks[] = $task;
				}
				if ((! $due || $due <= $today) && self::task_should_show_in_dashboard_actions($task_id)) {
					$visible_today_tasks[] = $task;
				}
				if (! $due || $due === $today) {
					$today_tasks[] = $task;
				} elseif ($due < $today) {
					$due_month = strlen($due) >= 7 ? substr($due, 0, 7) : '';
					if ($due_month && $due_month < $current_month) {
						if (! isset($historical_overdue_groups[$due_month])) {
							$historical_overdue_groups[$due_month] = array();
						}
						$historical_overdue_groups[$due_month][] = $task;
					} else {
						$overdue_tasks[] = $task;
					}
				} else {
					$upcoming_tasks[] = $task;
				}
			}
			krsort($historical_overdue_groups);
			self::sort_tasks_by_lead_score($visible_today_tasks);
			self::sort_tasks_by_lead_score($today_tasks);
			self::sort_tasks_by_lead_score($overdue_tasks);
			self::sort_tasks_by_lead_score($upcoming_tasks);
			self::sort_tasks_by_lead_score($recurring_tasks);
			foreach ($historical_overdue_groups as &$historical_group) {
				self::sort_tasks_by_lead_score($historical_group);
			}
			unset($historical_group);

			$visible_today_pagination = self::paginate_task_items($visible_today_tasks, self::tasks_page_number('visible_page'));
			$today_pagination = self::paginate_task_items($today_tasks, self::tasks_page_number('today_page'));
			$upcoming_pagination = self::paginate_task_items($upcoming_tasks, self::tasks_page_number('upcoming_page'));
			$overdue_pagination = self::paginate_task_items($overdue_tasks, self::tasks_page_number('overdue_page'));
			$recurring_pagination = self::paginate_task_items($recurring_tasks, self::tasks_page_number('recurring_page'));
			$done_pagination = self::paginate_task_items(array_slice($done_tasks, 0, 60), self::tasks_page_number('done_page'));
			?>
