	public static function render_payments_page() {
		$today = current_time('Y-m-d');
		$leads = self::get_active_leads(array('numberposts' => 300, 'orderby' => 'date', 'order' => 'DESC'));
		$payments = get_posts(array('post_type' => 'crm_payment', 'post_status' => 'publish', 'numberposts' => 120, 'orderby' => 'date', 'order' => 'DESC'));
		$due_soon = 0;
		$overdue = 0;
		$paid_month = 0;
		foreach ($payments as $p) {
			$status_i = (string) get_post_meta($p->ID, '_crm_payment_status', true);
			$due_i = (string) get_post_meta($p->ID, '_crm_payment_due_date', true);
			if ('paid' === $status_i) {
				$paid_month += (float) get_post_meta($p->ID, '_crm_payment_amount', true);
			}
			if ('pending' === $status_i && $due_i && $due_i >= $today && $due_i <= self::add_chile_business_days($today, 3)) {
				$due_soon++;
			}
			if ('paid' !== $status_i && $due_i && $due_i < $today) {
				$overdue++;
			}
		}
		?>
		<div class="wrap twob-crm-visual twob-page">
			<h1>Cobros</h1>
			<p class="twob-muted">Semaforo de cobros y registro asistido con estados claros.</p>
			<div class="twob-grid twob-grid-4">
				<div class="twob-card"><small>Por vencer (3 dias)</small><h2><?php echo esc_html($due_soon); ?></h2></div>
				<div class="twob-card"><small>Vencidos</small><h2><?php echo esc_html($overdue); ?></h2></div>
				<div class="twob-card"><small>Facturado cobrado</small><h2>$<?php echo esc_html(number_format((float) $paid_month, 0, ',', '.')); ?></h2></div>
				<div class="twob-card"><small>Revision diaria</small><h2><?php echo esc_html(self::activity_count('collection_reviewed', 'day')); ?></h2></div>
			</div>
			<div class="twob-card">
				<h3>Registrar cobro</h3>
				<div class="twob-grid twob-grid-6 twob-compact-grid">
					<div class="twob-form-row"><label>Lead</label><select id="twob_payment_lead_id"><?php foreach ($leads as $lead) : ?><option value="<?php echo esc_attr($lead->ID); ?>"><?php echo esc_html($lead->post_title); ?></option><?php endforeach; ?></select></div>
					<div class="twob-form-row"><label>Servicio</label><input type="text" id="twob_payment_service" placeholder="Diagnostico / Implementacion / Continuidad"></div>
					<div class="twob-form-row"><label>Monto</label><input type="number" step="0.01" id="twob_payment_amount" value="0"></div>
					<div class="twob-form-row"><label>Estado</label><select id="twob_payment_status"><?php foreach (self::payment_status_labels() as $key => $label) : ?><option value="<?php echo esc_attr($key); ?>" <?php selected($key, 'pending'); ?>><?php echo esc_html($label); ?></option><?php endforeach; ?></select></div>
					<div class="twob-form-row"><label>Fecha vencimiento</label><input type="date" id="twob_payment_due_date" value="<?php echo esc_attr($today); ?>"></div>
					<div class="twob-form-row"><label>Fecha pago</label><input type="date" id="twob_payment_paid_date" value="<?php echo esc_attr($today); ?>"></div>
				</div>
				<p><button class="button button-primary" id="twob_add_payment_full" type="button">Registrar cobro</button></p>
			</div>

			<div class="twob-grid twob-grid-1">
				<div class="twob-card">
					<h3>Listado de cobros</h3>
					<?php if (! $payments) : ?><div class="twob-empty">No hay cobros registrados.</div><?php endif; ?>
					<div class="twob-payments-list">
						<?php foreach ($payments as $payment) : ?>
							<?php
							$payment_id = (int) $payment->ID;
							$lead_id = (int) get_post_meta($payment_id, '_crm_lead_id', true);
							$amount = (float) get_post_meta($payment_id, '_crm_payment_amount', true);
							$status = get_post_meta($payment_id, '_crm_payment_status', true);
							$paid_date = get_post_meta($payment_id, '_crm_payment_paid_date', true);
							$due_date = get_post_meta($payment_id, '_crm_payment_due_date', true);
							$service = get_post_meta($payment_id, '_crm_payment_service', true);
							if ('paid' !== $status && $due_date && $due_date < $today) {
								$status = 'overdue';
							}
							$days_late = 0;
							if ('paid' !== $status && $due_date && $due_date < $today) {
								$days_late = (int) floor((strtotime($today) - strtotime($due_date)) / DAY_IN_SECONDS);
							}
							?>
							<div class="twob-payment-row">
								<div>
									<strong><?php echo esc_html($lead_id ? get_the_title($lead_id) : $payment->post_title); ?></strong>
									<small><?php echo esc_html($service ?: 'Sin servicio'); ?> | $<?php echo esc_html(number_format($amount, 0, ',', '.')); ?></small>
									<small>Vence: <?php echo esc_html($due_date ?: '-'); ?> | Pagado: <?php echo esc_html($paid_date ?: '-'); ?><?php echo $days_late > 0 ? ' | Mora: ' . esc_html((string) $days_late) . ' dias' : ''; ?></small>
								</div>
								<div class="twob-payment-actions">
									<?php echo wp_kses_post(self::status_badge($status, self::payment_status_labels(), 'twob-badge-payment')); ?>
									<button class="button button-small twob-payment-status" data-payment-id="<?php echo esc_attr($payment_id); ?>" data-status="paid">Pagado</button>
									<button class="button button-small twob-payment-status" data-payment-id="<?php echo esc_attr($payment_id); ?>" data-status="pending">Pendiente</button>
									<button class="button button-small twob-payment-status" data-payment-id="<?php echo esc_attr($payment_id); ?>" data-status="overdue">Vencido</button>
									<button class="button button-small twob-danger twob-delete-item" data-item-id="<?php echo esc_attr($payment_id); ?>" data-item-type="crm_payment" data-item-label="<?php echo esc_attr($lead_id ? get_the_title($lead_id) : $payment->post_title); ?>">Eliminar</button>
								</div>
							</div>
						<?php endforeach; ?>
					</div>
				</div>
			</div>
		</div>
		<?php
	}

	public static function render_pipeline_page() {
		$today = current_time('Y-m-d');
		$columns = array(
			'new' => array('label' => 'Nuevo', 'hint' => self::operational_status_hints()['new'] ?? '', 'limit' => 24),
			'contacted' => array('label' => 'Contactado', 'hint' => self::operational_status_hints()['contacted'] ?? '', 'limit' => 24),
			'followup' => array('label' => 'Seguimiento', 'hint' => self::operational_status_hints()['followup'] ?? '', 'limit' => 30),
			'interested' => array('label' => 'Interesado', 'hint' => self::operational_status_hints()['interested'] ?? '', 'limit' => 24),
			'archive' => array('label' => 'Archivo', 'hint' => self::operational_status_hints()['archive'] ?? '', 'limit' => 18),
		);
		$leads = self::get_active_leads(array('numberposts' => -1, 'orderby' => 'date', 'order' => 'DESC'));
		$buckets = array_fill_keys(array_keys($columns), array());
		foreach ($leads as $lead) {
			$lead_id = (int) $lead->ID;
			$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
			if ('won' === $stage) {
				continue;
			}
			$status = self::determine_operational_status($lead_id, $today);
			if (! isset($buckets[$status])) {
				$status = 'archive';
			}
			$buckets[$status][] = $lead;
		}
		?>
		<div class="wrap twob-crm-visual twob-page">
			<h1>Pipeline simple</h1>
			<p class="twob-muted">Vista operativa en 5 estados. No muestra clientes ganados ni backlog viejo en la jornada principal; aqui solo se ordena el trabajo real de Dani.</p>

			<div class="twob-grid twob-grid-2">
				<div class="twob-card twob-ops-rules">
					<h3>Reglas del flujo</h3>
					<div class="twob-mini-list">
						<div class="twob-ops-rule"><strong>Nuevo</strong><span>Lead creado y aun sin primer contacto registrado.</span></div>
						<div class="twob-ops-rule"><strong>Contactado</strong><span>Ya salio el mensaje inicial. Espera o prepara el siguiente toque.</span></div>
						<div class="twob-ops-rule"><strong>Seguimiento</strong><span>Lead vivo que hoy necesita accion directa o gestion blanda con criterio comercial.</span></div>
						<div class="twob-ops-rule"><strong>Interesado</strong><span>Respondio, pidio tiempo o ya avanza a reunion/propuesta.</span></div>
						<div class="twob-ops-rule"><strong>Archivo</strong><span>Fuera del flujo diario. Se conserva como historico y se puede reactivar.</span></div>
					</div>
				</div>
				<div class="twob-card twob-ops-rules">
					<h3>Reglas anti-colapso</h3>
					<div class="twob-mini-list">
						<div class="twob-ops-rule"><strong>Una accion por lead</strong><span>El dashboard de hoy solo muestra lo accionable ahora.</span></div>
						<div class="twob-ops-rule"><strong>Sin registro no avanza</strong><span>No se puede mover un lead vivo sin dejar interaccion.</span></div>
						<div class="twob-ops-rule"><strong>Mensaje final y cierre</strong><span>El lead recibe un ultimo mensaje en D+10. Si no responde, el sistema lo cierra automaticamente en D+12 como sin respuesta.</span></div>
						<div class="twob-ops-rule"><strong>Respuesta corta la secuencia</strong><span>Cuando el lead responde, se apagan tareas futuras para evitar duplicados.</span></div>
					</div>
				</div>
			</div>

			<div class="twob-card">
				<div class="twob-pipeline twob-ops-pipeline" style="--twob-pipeline-columns: <?php echo esc_attr((string) count($columns)); ?>;">
					<?php foreach ($columns as $status_key => $column) : ?>
						<?php
						$column_items = $buckets[$status_key] ?? array();
						$visible_items = array_slice($column_items, 0, (int) $column['limit']);
						?>
						<div class="twob-column twob-ops-column twob-ops-column-<?php echo esc_attr($status_key); ?>">
							<div class="twob-column-title twob-ops-column-title">
								<div>
									<strong><?php echo esc_html($column['label']); ?></strong>
									<div class="twob-line-2"><?php echo esc_html($column['hint']); ?></div>
								</div>
								<span class="twob-pill twob-pill-operational twob-pill-operational-<?php echo esc_attr($status_key); ?>"><?php echo esc_html((string) count($column_items)); ?></span>
							</div>
							<?php if (! $visible_items) : ?><div class="twob-empty">Sin leads en esta etapa operativa.</div><?php endif; ?>
							<?php foreach ($visible_items as $lead) : ?>
								<?php self::render_operational_pipeline_lead_card($lead, $status_key, $today); ?>
							<?php endforeach; ?>
							<?php if ('archive' === $status_key && count($column_items) > count($visible_items)) : ?>
								<div class="twob-line-2">Se muestran <?php echo esc_html((string) count($visible_items)); ?> de <?php echo esc_html((string) count($column_items)); ?> archivados. El resto vive en la vista Archivo.</div>
							<?php endif; ?>
						</div>
					<?php endforeach; ?>
				</div>
			</div>
		</div>
		<?php
	}

