	public static function render_activity_page() {
		if (! self::user_can_access_crm()) {
			wp_die('Sin permisos para acceder al CRM.');
		}

		$today = current_time('Y-m-d');
		$yesterday = date('Y-m-d', strtotime($today . ' -1 day'));
		$week_start = date('Y-m-d', strtotime($today . ' -6 days'));
		$search_query = isset($_GET['q']) ? sanitize_text_field(wp_unslash($_GET['q'])) : '';
		$group_filter = self::sanitize_activity_group(isset($_GET['group']) ? wp_unslash($_GET['group']) : 'all');
		$date_from = self::sanitize_date_input(isset($_GET['date_from']) ? wp_unslash($_GET['date_from']) : $today, true, 'Fecha desde');
		$date_to = self::sanitize_date_input(isset($_GET['date_to']) ? wp_unslash($_GET['date_to']) : $today, true, 'Fecha hasta');
		$date_from = is_wp_error($date_from) ? $today : $date_from;
		$date_to = is_wp_error($date_to) ? $today : $date_to;
		if ($date_from > $date_to) {
			$tmp = $date_from;
			$date_from = $date_to;
			$date_to = $tmp;
		}

		$activity_ids = self::get_activity_items(array(
			'date_from' => $date_from,
			'date_to' => $date_to,
			'group' => $group_filter,
			'search' => $search_query,
			'numberposts' => 240,
		));
		$summary = self::summarize_activity_items($activity_ids);
		$summary_text = array(
			'Mostrando ' . count($activity_ids) . ' registro' . (1 === count($activity_ids) ? '' : 's'),
			'Periodo: ' . $date_from . ($date_from !== $date_to ? ' a ' . $date_to : ''),
		);
		if ('all' !== $group_filter) {
			$summary_text[] = 'Tipo: ' . (self::activity_group_labels()[$group_filter] ?? 'Todo');
		}
		if ($search_query) {
			$summary_text[] = 'Busqueda: ' . $search_query;
		}
		?>
		<div class="wrap twob-crm-visual twob-page">
			<h1>Actividad diaria</h1>
			<p class="twob-muted">Bitacora automatica de lo que se hizo en el CRM: leads, interacciones, etapas, tareas y cobros.</p>

			<div class="twob-stage-filter">
				<a class="button <?php echo ($date_from === $today && $date_to === $today) ? 'button-primary' : ''; ?>" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-activity&date_from=' . $today . '&date_to=' . $today)); ?>">Hoy</a>
				<a class="button <?php echo ($date_from === $yesterday && $date_to === $yesterday) ? 'button-primary' : ''; ?>" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-activity&date_from=' . $yesterday . '&date_to=' . $yesterday)); ?>">Ayer</a>
				<a class="button <?php echo ($date_from === $week_start && $date_to === $today) ? 'button-primary' : ''; ?>" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-activity&date_from=' . $week_start . '&date_to=' . $today)); ?>">Ultimos 7 dias</a>
			</div>

			<div class="twob-card">
				<form method="get">
					<input type="hidden" name="page" value="twob-crm-visual-activity">
					<div class="twob-grid twob-grid-6 twob-compact-grid">
						<div class="twob-form-row twob-col-span-2"><label>Buscar</label><input type="text" name="q" value="<?php echo esc_attr($search_query); ?>" placeholder="Lead, empresa, etapa, tarea, cobro"></div>
						<div class="twob-form-row"><label>Tipo actividad</label><select name="group"><?php foreach (self::activity_group_labels() as $key => $label) : ?><option value="<?php echo esc_attr($key); ?>" <?php selected($group_filter, $key); ?>><?php echo esc_html($label); ?></option><?php endforeach; ?></select></div>
						<div class="twob-form-row"><label>Desde</label><input type="date" name="date_from" value="<?php echo esc_attr($date_from); ?>"></div>
						<div class="twob-form-row"><label>Hasta</label><input type="date" name="date_to" value="<?php echo esc_attr($date_to); ?>"></div>
						<div class="twob-form-row"><label>&nbsp;</label><button class="button button-primary" type="submit">Filtrar</button></div>
						<div class="twob-form-row"><label>&nbsp;</label><a class="button" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-activity&date_from=' . $today . '&date_to=' . $today)); ?>">Volver a hoy</a></div>
					</div>
				</form>
				<div class="twob-line-2"><?php echo esc_html(implode(' | ', $summary_text)); ?></div>
			</div>

			<div class="twob-dashboard-counters twob-activity-counters">
				<div class="twob-dashboard-counter"><small>Total</small><strong><?php echo esc_html((string) $summary['total']); ?></strong></div>
				<div class="twob-dashboard-counter"><small>Leads</small><strong><?php echo esc_html((string) $summary['leads']); ?></strong></div>
				<div class="twob-dashboard-counter"><small>Interacciones</small><strong><?php echo esc_html((string) $summary['interactions']); ?></strong></div>
				<div class="twob-dashboard-counter"><small>Etapas</small><strong><?php echo esc_html((string) $summary['stages']); ?></strong></div>
				<div class="twob-dashboard-counter"><small>Tareas</small><strong><?php echo esc_html((string) $summary['tasks']); ?></strong></div>
				<div class="twob-dashboard-counter"><small>Cobros</small><strong><?php echo esc_html((string) $summary['payments']); ?></strong></div>
			</div>

			<div class="twob-card">
				<div class="twob-line-1">
					<h3>Bitacora</h3>
					<span class="twob-pill is-soft"><?php echo esc_html((string) count($activity_ids)); ?> eventos</span>
				</div>
				<?php if (! $activity_ids) : ?>
					<div class="twob-empty-card">No hay actividad registrada para este filtro.</div>
				<?php else : ?>
					<div class="twob-activity-board">
						<?php $current_day = ''; ?>
						<?php foreach ($activity_ids as $activity_id) : ?>
							<?php $activity = get_post((int) $activity_id); ?>
							<?php if (! $activity) { continue; } ?>
							<?php $activity_day = substr((string) $activity->post_date, 0, 10); ?>
							<?php if ($activity_day !== $current_day) : ?>
								<?php $current_day = $activity_day; ?>
								<div class="twob-activity-day"><?php echo esc_html($current_day); ?></div>
							<?php endif; ?>
							<?php self::render_activity_timeline_item((int) $activity_id); ?>
						<?php endforeach; ?>
					</div>
				<?php endif; ?>
			</div>
		</div>
		<?php
	}

	private static function render_risk_snapshot_row($snapshot) {
		$lead_id = (int) ($snapshot['lead_id'] ?? 0);
		if (! $lead_id || 'crm_lead' !== get_post_type($lead_id)) {
			return;
		}

		$risk = (string) ($snapshot['risk'] ?? 'stable');
		$lead_url = admin_url('admin.php?page=twob-crm-visual-leads&lead_id=' . $lead_id . '&q=' . rawurlencode((string) get_the_title($lead_id))) . '#lead-' . $lead_id;
		$risk_label = match ($risk) {
			'critical' => 'Critico',
			'warning' => 'Atencion',
			'watch' => 'Vigilar',
			default => 'Estable',
		};
		$risk_class = match ($risk) {
			'critical' => 'is-danger',
			'warning' => 'is-warning',
			'watch' => 'is-watch',
			default => 'is-soft',
		};
		$company = (string) get_post_meta($lead_id, '_crm_company', true);
		$stage = self::normalize_stage_key((string) get_post_meta($lead_id, '_crm_stage', true));
		?>
		<div class="twob-task-item twob-risk-item">
			<div class="twob-line-1">
				<div>
					<strong><?php echo esc_html(get_the_title($lead_id)); ?></strong>
					<div class="twob-line-2"><?php echo esc_html($company ?: 'Sin empresa'); ?></div>
				</div>
				<div class="twob-dashboard-task-pills">
					<span class="twob-pill <?php echo esc_attr($risk_class); ?>"><?php echo esc_html($risk_label); ?></span>
					<span class="twob-pill is-soft"><?php echo esc_html(self::stage_labels()[$stage] ?? 'Sin etapa'); ?></span>
				</div>
			</div>
			<div class="twob-line-2">
				Ultimo contacto: <?php echo esc_html((string) ($snapshot['last_touch'] ?? '-')); ?> | Dias sin contacto: <?php echo esc_html((string) ($snapshot['days_since_touch'] ?? 0)); ?> | Proximo seguimiento: <?php echo esc_html((string) (($snapshot['next_followup'] ?? '') ?: '-')); ?>
			</div>
			<?php if (! empty($snapshot['reasons'])) : ?>
				<div class="twob-dashboard-task-meta">
					<?php foreach ((array) $snapshot['reasons'] as $reason) : ?>
						<span class="twob-pill is-soft"><?php echo esc_html((string) $reason); ?></span>
					<?php endforeach; ?>
				</div>
			<?php endif; ?>
			<?php self::render_lead_snapshot($lead_id, array('title' => '', 'show_open_tasks' => true, 'show_actions' => false, 'show_history' => false)); ?>
			<div class="twob-task-actions">
				<button class="button button-small twob-btn" data-action="log_followup" data-lead-id="<?php echo esc_attr($lead_id); ?>">Registrar gestion</button>
				<button class="button button-small twob-btn" data-action="new_task" data-lead-id="<?php echo esc_attr($lead_id); ?>">Crear tarea</button>
				<a class="button button-small" href="<?php echo esc_url($lead_url); ?>">Abrir lead</a>
			</div>
		</div>
		<?php
	}

