	public static function render_calendar_page() {
		if (! self::user_can_manage_google()) {
			wp_die('Sin permisos para acceder a Google Calendar.');
		}
		if (isset($_POST['twob_google_settings_nonce']) && wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['twob_google_settings_nonce'])), 'twob_google_settings_save')) {
			self::google_settings_save(array(
				'client_id' => isset($_POST['google_client_id']) ? wp_unslash($_POST['google_client_id']) : '',
				'client_secret' => isset($_POST['google_client_secret']) ? wp_unslash($_POST['google_client_secret']) : '',
				'calendar_id' => isset($_POST['google_calendar_id']) ? wp_unslash($_POST['google_calendar_id']) : 'primary',
				'workday_start_hour' => isset($_POST['google_workday_start_hour']) ? wp_unslash($_POST['google_workday_start_hour']) : 9,
				'max_tasks_per_day' => isset($_POST['google_max_tasks_per_day']) ? wp_unslash($_POST['google_max_tasks_per_day']) : 12,
				'sync_paused' => isset($_POST['google_sync_paused']) ? 1 : 0,
				'pause_days' => isset($_POST['google_pause_days']) ? wp_unslash($_POST['google_pause_days']) : '',
			));
			echo '<div class="notice notice-success is-dismissible"><p>Configuracion de Google Calendar guardada.</p></div>';
		}

		$settings = self::google_settings_get();
		$user_id = get_current_user_id();
		$connected = self::google_is_connected($user_id);
		$last_error = self::google_get_last_error($user_id);
		$msg = isset($_GET['google_msg']) ? sanitize_text_field(wp_unslash($_GET['google_msg'])) : '';
		$pushed_count = isset($_GET['google_pushed']) ? max(0, (int) $_GET['google_pushed']) : 0;
		$pulled_count = isset($_GET['google_pulled']) ? max(0, (int) $_GET['google_pulled']) : 0;
		if ('connected' === $msg) {
			echo '<div class="notice notice-success is-dismissible"><p>Google Calendar conectado correctamente.</p></div>';
		} elseif ('disconnected' === $msg) {
			echo '<div class="notice notice-warning is-dismissible"><p>Conexion de Google Calendar eliminada.</p></div>';
		} elseif ('sync_ok' === $msg) {
			echo '<div class="notice notice-success is-dismissible"><p>Sincronizacion ejecutada. CRM → Google: ' . esc_html((string) $pushed_count) . ' items. Google → CRM: ' . esc_html((string) $pulled_count) . ' items.</p></div>';
		} elseif ('sync_error' === $msg) {
			echo '<div class="notice notice-error is-dismissible"><p>No se pudo sincronizar. Revisa el error abajo.</p></div>';
		}

		$today = current_time('Y-m-d');
		$view = isset($_GET['view']) ? sanitize_text_field(wp_unslash($_GET['view'])) : 'month';
		$next_30 = date('Y-m-d', strtotime($today . ' +30 days'));
		$tasks = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => 300,
			'meta_query' => array(
				array('key' => '_crm_task_due', 'value' => array($today, $next_30), 'compare' => 'BETWEEN', 'type' => 'DATE'),
			),
			'orderby' => 'meta_value',
			'meta_key' => '_crm_task_due',
			'order' => 'ASC',
		));
		$leads = get_posts(array(
			'post_type' => 'crm_lead',
			'post_status' => 'publish',
			'numberposts' => 300,
			'meta_query' => array(
				array('key' => '_crm_next_followup', 'value' => array($today, $next_30), 'compare' => 'BETWEEN', 'type' => 'DATE'),
			),
			'orderby' => 'meta_value',
			'meta_key' => '_crm_next_followup',
			'order' => 'ASC',
		));
		$payments = get_posts(array(
			'post_type' => 'crm_payment',
			'post_status' => 'publish',
			'numberposts' => 300,
			'meta_query' => array(
				array('key' => '_crm_payment_due_date', 'value' => array($today, $next_30), 'compare' => 'BETWEEN', 'type' => 'DATE'),
			),
			'orderby' => 'meta_value',
			'meta_key' => '_crm_payment_due_date',
			'order' => 'ASC',
		));

		$month_start = date('Y-m-01', strtotime($today));
		$month_end = date('Y-m-t', strtotime($today));
