	private static function get_reports_metrics($range) {
		$range = in_array($range, array('month', 'quarter', 'all'), true) ? $range : 'month';
		return TwoB_CRM_Dani_Reports_Module::remember(
			'reports_page|' . $range,
			self::METRICS_CACHE_TTL,
			function () use ($range) {
				$today_ts = current_time('timestamp');
				$after = date('Y-m-01 00:00:00', $today_ts);
				if ('quarter' === $range) {
					$after = date('Y-m-d 00:00:00', strtotime('-90 days', $today_ts));
				} elseif ('all' === $range) {
					$after = '2000-01-01 00:00:00';
				}
				$before = date('Y-m-d 23:59:59', $today_ts);

				$activity_ids = get_posts(array(
					'post_type' => 'crm_activity',
					'post_status' => 'publish',
					'numberposts' => -1,
					'fields' => 'ids',
					'date_query' => array(array('after' => $after, 'before' => $before, 'inclusive' => true)),
				));
				$counts = array(
					'contacts' => 0,
					'followups' => 0,
					'sales' => 0,
					'lost' => 0,
					'billing' => 0,
				);
				foreach ($activity_ids as $activity_id) {
					$action = (string) get_post_meta($activity_id, '_crm_action', true);
					if ('interaction_logged' === $action) {
						$kind = (string) get_post_meta($activity_id, '_crm_interaction_kind', true);
						if ('contact' === $kind) {
							$counts['contacts']++;
						}
						if ('followup' === $kind) {
							$counts['followups']++;
						}
					}
					if ('stage_changed' === $action) {
						$stage = (string) get_post_meta($activity_id, '_crm_stage', true);
						if ('won' === $stage) {
							$counts['sales']++;
						}
						if ('lost' === $stage) {
							$counts['lost']++;
						}
					}
					if ('payment_recorded' === $action) {
						$counts['billing'] += (float) get_post_meta($activity_id, '_crm_amount', true);
					}
				}

				$channels = array();
				$interaction_ids = get_posts(array(
					'post_type' => 'crm_interaction',
					'post_status' => 'publish',
					'numberposts' => -1,
					'fields' => 'ids',
					'date_query' => array(array('after' => $after, 'before' => $before, 'inclusive' => true)),
				));
				foreach ($interaction_ids as $interaction_id) {
					$channel = (string) get_post_meta($interaction_id, '_crm_interaction_channel', true);
					if (! $channel) {
						continue;
					}
					$channels[$channel] = isset($channels[$channel]) ? $channels[$channel] + 1 : 1;
				}
				arsort($channels);
				$best_channel = ! empty($channels) ? key($channels) : '';
				$max_channel_count = ! empty($channels) ? max($channels) : 1;

				$close_days = array();
				$won_change_ids = get_posts(array(
					'post_type' => 'crm_activity',
					'post_status' => 'publish',
					'numberposts' => -1,
					'fields' => 'ids',
					'date_query' => array(array('after' => $after, 'before' => $before, 'inclusive' => true)),
					'meta_query' => array(
						array('key' => '_crm_action', 'value' => 'stage_changed', 'compare' => '='),
						array('key' => '_crm_stage', 'value' => 'won', 'compare' => '='),
					),
				));
				foreach ($won_change_ids as $change_id) {
					$lead_id = (int) get_post_meta($change_id, '_crm_object_id', true);
					$lead = $lead_id ? get_post($lead_id) : null;
					$change = get_post($change_id);
					if (! $lead || ! $change) {
						continue;
					}
					$diff = (int) floor((strtotime((string) $change->post_date) - strtotime((string) $lead->post_date)) / DAY_IN_SECONDS);
					if ($diff >= 0) {
						$close_days[] = $diff;
					}
				}
				$avg_close_days = ! empty($close_days) ? round(array_sum($close_days) / count($close_days), 1) : 0;

				$months = array();
				for ($i = 5; $i >= 0; $i--) {
					$key = date('Y-m', strtotime('-' . $i . ' months', $today_ts));
					$months[$key] = array('leads' => 0, 'billing' => 0);
				}
				$lead_creation_ids = get_posts(array(
					'post_type' => 'crm_activity',
					'post_status' => 'publish',
					'numberposts' => -1,
					'fields' => 'ids',
					'meta_query' => array(array('key' => '_crm_action', 'value' => 'lead_created', 'compare' => '=')),
				));
				foreach ($lead_creation_ids as $activity_id) {
					$activity = get_post($activity_id);
					if (! $activity) {
						continue;
					}
					$key = substr((string) $activity->post_date, 0, 7);
					if (isset($months[$key])) {
						$months[$key]['leads']++;
					}
				}
				$payment_activity_ids = get_posts(array(
					'post_type' => 'crm_activity',
					'post_status' => 'publish',
					'numberposts' => -1,
					'fields' => 'ids',
					'meta_query' => array(array('key' => '_crm_action', 'value' => 'payment_recorded', 'compare' => '=')),
				));
				foreach ($payment_activity_ids as $activity_id) {
					$activity = get_post($activity_id);
					if (! $activity) {
						continue;
					}
					$key = substr((string) $activity->post_date, 0, 7);
					if (isset($months[$key])) {
						$months[$key]['billing'] += (float) get_post_meta($activity_id, '_crm_amount', true);
					}
				}
				$max_leads = 1;
				$max_billing = 1;
				foreach ($months as $month) {
					$max_leads = max($max_leads, (int) $month['leads']);
					$max_billing = max($max_billing, (float) $month['billing']);
				}

				return array(
					'counts' => $counts,
					'channels' => $channels,
					'best_channel' => $best_channel,
					'max_channel_count' => $max_channel_count,
					'avg_close_days' => $avg_close_days,
					'months' => $months,
					'max_leads' => $max_leads,
					'max_billing' => $max_billing,
				);
			}
		);
	}

	private static function get_dashboard_metrics() {
		return TwoB_CRM_Dani_Reports_Module::remember(
			'dashboard_page',
			self::METRICS_CACHE_TTL,
				function () {
					$month_start = date('Y-m-01 00:00:00', current_time('timestamp'));
					$month_end = date('Y-m-t 23:59:59', current_time('timestamp'));

					$daily_new_leads = self::activity_count('lead_created', 'day');
					$daily_contacts = self::activity_count('interaction_logged', 'day', array('interaction_kind' => 'contact'));
					$daily_followups = self::activity_count('interaction_logged', 'day', array('interaction_kind' => 'followup'));
				$daily_meetings = self::activity_count('stage_changed', 'day', array('stage' => 'meeting_done'));
				$daily_responses = self::activity_count('response_sent', 'day');
				$daily_collections = self::activity_count('collection_reviewed', 'day');
				$daily_tasks_done = self::activity_count('task_completed', 'day');
				$weekly_meetings = self::activity_count('stage_changed', 'week', array('stage' => 'meeting_done'));
				$weekly_prop = self::activity_count('stage_changed', 'week', array('stage' => 'proposal_sent'));
				$weekly_close = self::activity_count('stage_changed', 'week', array('stage' => 'won'));
				$monthly_won = self::activity_count('stage_changed', 'month', array('stage' => 'won'));
				$monthly_lost = self::activity_count('stage_changed', 'month', array('stage' => 'lost'));
				$month_collected = self::activity_sum('payment_recorded', 'month', 'amount');

				$month_sold_amount = 0.0;
				$month_payment_ids = get_posts(array(
					'post_type' => 'crm_payment',
					'post_status' => 'publish',
					'numberposts' => -1,
					'fields' => 'ids',
					'date_query' => array(array('after' => $month_start, 'before' => $month_end, 'inclusive' => true)),
				));
				foreach ($month_payment_ids as $payment_id) {
					$month_sold_amount += (float) get_post_meta($payment_id, '_crm_payment_amount', true);
				}

				$month_diagnostics_sold = 0;
				$month_won_change_ids = get_posts(array(
					'post_type' => 'crm_activity',
					'post_status' => 'publish',
					'numberposts' => -1,
					'fields' => 'ids',
					'date_query' => array(array('after' => $month_start, 'before' => $month_end, 'inclusive' => true)),
					'meta_query' => array(
						array('key' => '_crm_action', 'value' => 'stage_changed', 'compare' => '='),
						array('key' => '_crm_stage', 'value' => 'won', 'compare' => '='),
					),
				));
				foreach ($month_won_change_ids as $activity_id) {
					$lead_id = (int) get_post_meta($activity_id, '_crm_object_id', true);
					if (self::is_diagnostic_service((string) get_post_meta($lead_id, '_crm_service_interest', true))) {
						$month_diagnostics_sold++;
					}
				}

				$registry_rejected = 0;
				$registry_no_response = 0;
				$month_interaction_ids = get_posts(array(
					'post_type' => 'crm_interaction',
					'post_status' => 'publish',
					'numberposts' => -1,
					'fields' => 'ids',
					'date_query' => array(array('after' => $month_start, 'before' => $month_end, 'inclusive' => true)),
				));
				foreach ($month_interaction_ids as $interaction_id) {
					$result = (string) get_post_meta($interaction_id, '_crm_interaction_result', true);
					if ('rejected' === $result) {
						$registry_rejected++;
					}
					if ('no_answer' === $result) {
						$registry_no_response++;
					}
				}

				$registry_canceled_meetings = 0;
				$month_stage_change_ids = get_posts(array(
					'post_type' => 'crm_activity',
					'post_status' => 'publish',
					'numberposts' => -1,
					'fields' => 'ids',
					'date_query' => array(array('after' => $month_start, 'before' => $month_end, 'inclusive' => true)),
					'meta_query' => array(array('key' => '_crm_action', 'value' => 'stage_changed', 'compare' => '=')),
				));
				foreach ($month_stage_change_ids as $activity_id) {
					$old_stage = (string) get_post_meta($activity_id, '_crm_old_stage', true);
					$new_stage = (string) get_post_meta($activity_id, '_crm_stage', true);
					if ('meeting_scheduled' === $old_stage && 'meeting_done' !== $new_stage) {
						$registry_canceled_meetings++;
					}
				}

				$month_contacts = self::activity_count('interaction_logged', 'month', array('interaction_kind' => 'contact'));
				$month_responses = self::activity_count('response_sent', 'month');
				$month_meeting_sched = self::activity_count('stage_changed', 'month', array('stage' => 'meeting_scheduled'));
				$kpi_close_rate = ($monthly_won + $monthly_lost) > 0 ? round(($monthly_won / ($monthly_won + $monthly_lost)) * 100, 1) : 0;
				$kpi_response_rate = $month_contacts > 0 ? round(($month_responses / $month_contacts) * 100, 1) : 0;
				$kpi_meeting_conversion = $month_responses > 0 ? round(($month_meeting_sched / $month_responses) * 100, 1) : 0;

				$contact_count = count(self::get_active_leads(array('numberposts' => -1, 'fields' => 'ids')));
				$diag_count = count(self::get_active_leads(array('numberposts' => -1, 'fields' => 'ids', 'meta_key' => '_crm_funnel_stage', 'meta_value' => 'diagnostic')));
				$impl_count = count(self::get_active_leads(array('numberposts' => -1, 'fields' => 'ids', 'meta_key' => '_crm_funnel_stage', 'meta_value' => 'implementation')));
				$cont_count = count(self::get_active_leads(array('numberposts' => -1, 'fields' => 'ids', 'meta_key' => '_crm_funnel_stage', 'meta_value' => 'continuity')));
				$conv_cd = $contact_count > 0 ? round(($diag_count / $contact_count) * 100, 1) : 0;
				$conv_di = $diag_count > 0 ? round(($impl_count / $diag_count) * 100, 1) : 0;
				$conv_ic = $impl_count > 0 ? round(($cont_count / $impl_count) * 100, 1) : 0;

					return array(
						'daily_new_leads' => $daily_new_leads,
						'daily_contacts' => $daily_contacts,
						'daily_followups' => $daily_followups,
					'daily_meetings' => $daily_meetings,
					'daily_responses' => $daily_responses,
					'daily_collections' => $daily_collections,
					'daily_tasks_done' => $daily_tasks_done,
					'weekly_meetings' => $weekly_meetings,
					'weekly_prop' => $weekly_prop,
					'weekly_close' => $weekly_close,
					'monthly_won' => $monthly_won,
					'monthly_lost' => $monthly_lost,
					'month_collected' => $month_collected,
					'month_sold_amount' => $month_sold_amount,
					'month_diagnostics_sold' => $month_diagnostics_sold,
					'registry_lost' => $monthly_lost,
					'registry_rejected' => $registry_rejected,
					'registry_no_response' => $registry_no_response,
					'registry_canceled_meetings' => $registry_canceled_meetings,
					'kpi_close_rate' => $kpi_close_rate,
					'kpi_response_rate' => $kpi_response_rate,
					'kpi_meeting_conversion' => $kpi_meeting_conversion,
					'contact_count' => $contact_count,
					'diag_count' => $diag_count,
					'impl_count' => $impl_count,
					'cont_count' => $cont_count,
					'conv_cd' => $conv_cd,
					'conv_di' => $conv_di,
					'conv_ic' => $conv_ic,
				);
			}
		);
	}

	public static function render_reports_page() {
		if (! self::user_can_manage_reports()) {
			wp_die('Sin permisos para acceder a reportes.');
		}
		$range = isset($_GET['range']) ? sanitize_text_field(wp_unslash($_GET['range'])) : 'month';
		$range = in_array($range, array('month', 'quarter', 'all'), true) ? $range : 'month';
		$report_metrics = self::get_reports_metrics($range);
		$counts = $report_metrics['counts'];
		$channels = $report_metrics['channels'];
		$best_channel = $report_metrics['best_channel'];
		$max_channel_count = $report_metrics['max_channel_count'];
		$avg_close_days = $report_metrics['avg_close_days'];
		$months = $report_metrics['months'];
		$max_leads = $report_metrics['max_leads'];
		$max_billing = $report_metrics['max_billing'];

		?>
		<div class="wrap twob-crm-visual twob-page">
			<h1>Reportes y conversion</h1>
			<p class="twob-muted">Graficos simples de barras/linea con filtro mensual, trimestral o historico.</p>
			<div class="twob-stage-filter">
				<a class="button <?php echo 'month' === $range ? 'button-primary' : ''; ?>" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-reports&range=month')); ?>">Mes</a>
				<a class="button <?php echo 'quarter' === $range ? 'button-primary' : ''; ?>" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-reports&range=quarter')); ?>">Trimestre</a>
				<a class="button <?php echo 'all' === $range ? 'button-primary' : ''; ?>" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-reports&range=all')); ?>">Historico</a>
			</div>
			<div class="twob-grid twob-grid-4">
				<div class="twob-card"><small>Contactos</small><h2><?php echo esc_html($counts['contacts']); ?></h2></div>
				<div class="twob-card"><small>Seguimientos</small><h2><?php echo esc_html($counts['followups']); ?></h2></div>
				<div class="twob-card"><small>Ventas cerradas</small><h2><?php echo esc_html($counts['sales']); ?></h2></div>
				<div class="twob-card"><small>Facturacion</small><h2>$<?php echo esc_html(number_format((float) $counts['billing'], 0, ',', '.')); ?></h2></div>
			</div>
			<div class="twob-grid twob-grid-2">
				<div class="twob-card">
					<h3>Leads captados por mes (barras)</h3>
					<div class="twob-chart">
						<?php foreach ($months as $key => $row) : $h = (int) max(6, round(($row['leads'] / $max_leads) * 150)); ?>
							<div class="twob-chart-bar" style="height:<?php echo esc_attr($h); ?>px;"><span><?php echo esc_html((int) $row['leads']); ?></span><i><?php echo esc_html(substr($key, 5)); ?></i></div>
						<?php endforeach; ?>
					</div>
				</div>
				<div class="twob-card">
					<h3>Facturacion mensual (linea simple)</h3>
					<div class="twob-chart">
						<?php foreach ($months as $key => $row) : $h = (int) max(6, round(($row['billing'] / $max_billing) * 150)); ?>
							<div class="twob-chart-bar" style="height:<?php echo esc_attr($h); ?>px;background:#10b981;"><span>$<?php echo esc_html(number_format((float) $row['billing'], 0, ',', '.')); ?></span><i><?php echo esc_html(substr($key, 5)); ?></i></div>
						<?php endforeach; ?>
					</div>
				</div>
			</div>
			<div class="twob-grid twob-grid-3">
				<div class="twob-card">
					<h3>Canal con mejor rendimiento</h3>
					<p><strong><?php echo esc_html($best_channel && isset(self::channel_labels()[$best_channel]) ? self::channel_labels()[$best_channel] : 'Sin datos'); ?></strong></p>
					<?php foreach ($channels as $ch => $count) : ?>
						<?php self::progress(self::channel_labels()[$ch] ?? $ch, $count, max(1, $max_channel_count)); ?>
					<?php endforeach; ?>
				</div>
				<div class="twob-card">
					<h3>Tiempo promedio de cierre</h3>
					<h2><?php echo esc_html($avg_close_days); ?> dias</h2>
					<p class="twob-muted">Promedio entre fecha de creacion de lead y cierre ganado.</p>
				</div>
				<div class="twob-card">
					<h3>Tasa de conversion</h3>
					<?php $total_close = max(1, $counts['sales'] + $counts['lost']); ?>
					<?php self::progress('Ganados', $counts['sales'], $total_close); ?>
					<?php self::progress('Perdidos', $counts['lost'], $total_close); ?>
				</div>
			</div>
		</div>
		<?php
	}

	public static function render_dashboard() {
		if (! self::user_can_access_crm()) {
			wp_die('Sin permisos para acceder al CRM.');
		}

		$today = current_time('Y-m-d');
		self::ensure_daily_operational_tasks($today);
		$dashboard_metrics = self::get_dashboard_metrics();
		$lead_target = self::daily_new_leads_target();
		$daily_new_leads = self::get_dashboard_new_leads_count($today);
		$new_leads_queue = self::get_dashboard_new_leads_queue($today, $lead_target);
		$today_tasks = self::get_dashboard_operational_tasks($today, 12);
		$response_queue = self::get_dashboard_response_queue($today, 18);
		$today_url = admin_url('admin.php?page=twob-crm-visual-leads&focus=today');
		$new_url = admin_url('admin.php?page=twob-crm-visual-leads&focus=new');
		$archive_url = admin_url('admin.php?page=twob-crm-visual-leads&focus=archive');
		$responses_url = admin_url('admin.php?page=twob-crm-visual-interactions&focus=responses');
		$tasks_url = admin_url('admin.php?page=twob-crm-visual-tasks') . '#twob-visible-actions';
		$meetings_today = self::dashboard_today_meetings($today, 3);
		$renata_live_data = self::daily_plan_renata_live_data($today, 10);
		$renata_review_queue = array_values((array) ($renata_live_data['review'] ?? array()));
		$renata_meeting_prep = array_values((array) ($renata_live_data['meeting'] ?? array()));
		$renata_diagnostic_queue = array_values((array) ($renata_live_data['diagnostic'] ?? array()));
		$renata_dani_ready = array_values((array) ($renata_live_data['dani_ready'] ?? array()));
		$renata_dani_waiting = array_values((array) ($renata_live_data['dani_waiting'] ?? array()));
		$reactivation_prepare = array_values((array) ($renata_live_data['reactivation_prepare'] ?? array()));
		$reactivation_due = array_values((array) ($renata_live_data['reactivation_tasks'] ?? array()));
		$reactivation_banner = self::dashboard_reactivation_banner_item($today);
		$alliance_due_tasks = self::alliance_dashboard_due_tasks($today, 5);
		$renata_total = count($renata_review_queue) + count($renata_meeting_prep) + count($renata_diagnostic_queue) + count($reactivation_prepare);
		$lifecycle = self::dashboard_lifecycle_summary($today);
		$sequence_counts = self::dashboard_sequence_counts($today_tasks);
		$risk_board = self::get_cooling_risk_board($today);
		$risk_preview = array();
		foreach (array_merge((array) $risk_board['lead_critical'], (array) $risk_board['lead_warning'], (array) $risk_board['missing_next']) as $snapshot) {
			$lead_id = (int) ($snapshot['lead_id'] ?? 0);
			if (! $lead_id || isset($risk_preview[$lead_id])) {
				continue;
			}
			$risk_preview[$lead_id] = $snapshot;
			if (count($risk_preview) >= 4) {
				break;
			}
		}
		$response_done = (int) ($dashboard_metrics['daily_responses'] ?? 0);
		$task_done = (int) ($dashboard_metrics['daily_tasks_done'] ?? 0);
		$lead_done = min($lead_target, $daily_new_leads);
		$response_total = $response_done + count($response_queue);
		$task_total = $task_done + count($today_tasks);
		$progress_total = max(1, $response_total + $task_total + $lead_target);
		$progress_done = min($progress_total, $response_done + $task_done + $lead_done);
		$progress_percent = (int) max(0, min(100, round(($progress_done / $progress_total) * 100)));
		$active_leads_count = $lifecycle['new'] + $lifecycle['tracking'] + $lifecycle['interested'] + $lifecycle['pending'];
		$dashboard_tip = count($response_queue) > 0
			? 'Tip del dia: responde una sola conversacion a la vez y agenda el proximo paso antes de pasar al siguiente lead.'
			: 'Tip del dia: si no hay respuestas recientes, resuelve las tareas visibles y solo despues crea leads nuevos.';
		$current_user = wp_get_current_user();
		$display_name = $current_user && ! empty($current_user->display_name) ? trim((string) $current_user->display_name) : 'Dani';
		$first_name = $display_name ? explode(' ', $display_name)[0] : 'Dani';
		$persona = self::current_crm_persona();
		$week_meetings = self::dashboard_week_meetings($today, 6);
		$at_risk_sidebar = array();
		foreach ($risk_preview as $risk_item) {
			if (count($at_risk_sidebar) >= 3) {
				break;
			}
			if ((int) ($risk_item['days_since_touch'] ?? 0) >= 5) {
				$at_risk_sidebar[] = $risk_item;
			}
		}
		$dashboard_tasks_preview = array_slice($today_tasks, 0, 5);
		$today_human = wp_date('l, j \\d\\e F', current_time('timestamp'));
		$default_dashboard_tab = count($response_queue) > 0 ? 'responses' : (! empty($today_tasks) ? 'tasks' : 'leads');
		$high_effort_visible = 0;
		$medium_effort_visible = 0;
		$quick_effort_visible = 0;
		foreach ($today_tasks as $task) {
			$task_id = ($task instanceof WP_Post) ? (int) $task->ID : 0;
			$effort_meta = self::task_personalization_meta($task_id);
			if ('Alto' === $effort_meta['label']) {
				$high_effort_visible++;
			} elseif ('Medio' === $effort_meta['label']) {
				$medium_effort_visible++;
			} else {
				$quick_effort_visible++;
			}
		}
		$lead_remaining = max(0, $lead_target - $lead_done);
		$time_blocks = array(
			array(
				'time' => '09:00 - 10:00',
				'title' => 'Respuestas primero',
				'count' => count($response_queue),
				'class' => 'is-high',
				'hint' => count($response_queue) > 0 ? 'Atiende una conversacion a la vez y deja la siguiente fecha cerrada.' : 'Si no hay respuestas, este bloque puede ser corto.',
			),
			array(
				'time' => '10:15 - 11:45',
				'title' => 'Seguimientos personalizados',
				'count' => $high_effort_visible + $medium_effort_visible,
				'class' => 'is-medium',
				'hint' => ($high_effort_visible + $medium_effort_visible) > 0 ? 'Aqui van los follow-ups que requieren mas contexto y personalizacion.' : 'No hay seguimientos medianos o altos visibles ahora.',
			),
			array(
				'time' => '12:00 - 12:45',
				'title' => 'Seguimientos rapidos',
				'count' => $quick_effort_visible,
				'class' => 'is-low',
				'hint' => $quick_effort_visible > 0 ? 'Ideal para mensajes cortos, cierres simples o recordatorios.' : 'Este bloque queda libre si no hay acciones rapidas visibles.',
			),
			array(
				'time' => '16:00 - 17:00',
				'title' => 'Nuevos leads',
				'count' => $lead_remaining,
				'class' => 'is-neutral',
				'hint' => $lead_remaining > 0 ? 'Prospecta solo cuando lo urgente ya quedo encaminado.' : 'Meta diaria de leads cumplida por hoy.',
			),
		);
		?>
			<div class="wrap twob-crm-visual twob-page twob-dashboard-v2 twob-dashboard-redesign" data-twob-persona="<?php echo esc_attr($persona); ?>">
				<div class="twob-status-bar">
					<span class="twob-status-greeting">Buenos días, <?php echo esc_html($first_name); ?></span>
					<span class="twob-status-sep">·</span>
					<span class="twob-status-date"><?php echo esc_html($today_human); ?></span>
					<span class="twob-status-sep">·</span>
					<div class="twob-status-progress">
						<div class="twob-status-progress-track"><i style="width:<?php echo esc_attr((string) max(4, $progress_percent)); ?>%"></i></div>
						<span><?php echo esc_html($progress_done . ' de ' . $progress_total . ' acciones completadas'); ?></span>
					</div>
				</div>

				<div class="twob-priority-strip">
					<a class="twob-priority-card<?php echo count($response_queue) > 0 ? ' has-pending' : ''; ?>" href="<?php echo esc_url($responses_url); ?>">
						<span class="twob-priority-num">1</span>
						<span class="twob-priority-label">Respuestas</span>
						<span class="twob-priority-meta"><?php echo esc_html((string) count($response_queue)); ?> pendientes</span>
						<span class="twob-priority-link">Abrir →</span>
					</a>
					<a class="twob-priority-card" href="<?php echo esc_url($tasks_url); ?>">
						<span class="twob-priority-num">2</span>
						<span class="twob-priority-label">Tareas del día</span>
						<span class="twob-priority-meta"><?php echo esc_html((string) count($today_tasks)); ?> visibles</span>
						<span class="twob-priority-link">Abrir →</span>
					</a>
					<a class="twob-priority-card" href="<?php echo esc_url($new_url); ?>">
						<span class="twob-priority-num">3</span>
						<span class="twob-priority-label">Leads nuevos</span>
						<span class="twob-priority-meta"><?php echo esc_html($lead_done . '/' . $lead_target); ?> creados</span>
						<span class="twob-priority-link">Abrir →</span>
					</a>
				</div>

				<div class="twob-dash-shell">
					<div class="twob-dash-main">
						<?php if (! empty($reactivation_banner['lead_id'])) : ?>
							<div class="twob-priority-banner twob-priority-banner-reactivation">
								<div class="twob-priority-copy">
									<span class="twob-priority-kicker">Reactivación</span>
									<h3 class="twob-priority-title">¡<?php echo esc_html((string) ($reactivation_banner['name'] ?? 'Este lead')); ?> de <?php echo esc_html((string) ($reactivation_banner['company'] ?? 'esta empresa')); ?> respondió!</h3>
									<p class="twob-priority-text">Agenda la reunión hoy y no dejes pasar el momento. Esta tarea viene de la secuencia de reactivación y ya quedó separada del ciclo normal.</p>
								</div>
								<div class="twob-ops-toolbar">
									<a class="button button-primary" href="<?php echo esc_url((string) ($reactivation_banner['lead_url'] ?? '#')); ?>">Abrir lead</a>
								</div>
							</div>
						<?php endif; ?>
						<?php self::render_ui_onboarding_block('dashboard', self::dashboard_flow_education_html()); ?>
						<div class="twob-onboarding-template" data-twob-onboarding-template="dashboard" hidden><?php echo self::dashboard_flow_education_html(); // phpcs:ignore ?></div>

						<?php if ($response_queue) : ?>
							<section class="twob-card twob-responded-today">
								<h3>Respondieron hoy</h3>
								<div class="twob-response-list twob-response-list-compact">
									<?php foreach (array_slice($response_queue, 0, 8) as $item) : ?>
										<?php self::render_dashboard_response_row($item, $today); ?>
									<?php endforeach; ?>
								</div>
							</section>
						<?php endif; ?>

						<section class="twob-card twob-dash-tasks-section">
							<div class="twob-line-1">
								<h3>Tareas que vencen hoy</h3>
								<?php if ($today_tasks) : ?><a class="twob-link-quiet" href="<?php echo esc_url($tasks_url); ?>">Ver todas →</a><?php endif; ?>
							</div>
							<?php if (! $dashboard_tasks_preview) : ?>
								<div class="twob-empty-card">No hay tareas visibles para hoy.</div>
							<?php else : ?>
								<div class="twob-dash-task-rows">
									<?php foreach ($dashboard_tasks_preview as $task) : ?>
										<?php self::render_task_list_row_compact($task, $today); ?>
									<?php endforeach; ?>
								</div>
							<?php endif; ?>
						</section>

						<section class="twob-card twob-dash-radar-card">
							<div class="twob-line-1">
								<h3>Radar comercial</h3>
								<a class="twob-link-quiet" href="<?php echo esc_url($new_url); ?>">Abrir leads →</a>
							</div>
							<div class="twob-dash-radar-grid">
								<div class="twob-dash-radar-item">
									<small>En ciclo</small>
									<strong><?php echo esc_html((string) $lifecycle['tracking']); ?></strong>
									<span>Leads que ya están siendo trabajados hoy.</span>
								</div>
								<div class="twob-dash-radar-item">
									<small>Interesados</small>
									<strong><?php echo esc_html((string) $lifecycle['interested']); ?></strong>
									<span>Conversaciones que piden seguimiento más fino.</span>
								</div>
								<div class="twob-dash-radar-item">
									<small>Pendientes</small>
									<strong><?php echo esc_html((string) $lifecycle['pending']); ?></strong>
