								</div>
								<div class="twob-dash-radar-item">
									<small>Cerrados</small>
									<strong><?php echo esc_html((string) $lifecycle['closed']); ?></strong>
									<span>Leads fuera del ciclo activo, listos para análisis o reactivación.</span>
								</div>
							</div>
						</section>

						<?php if ($week_meetings) : ?>
							<section class="twob-card twob-dash-meetings-section">
								<h3>Próximas citas</h3>
								<ul class="twob-meeting-compact-list">
									<?php foreach ($week_meetings as $meeting_task) : ?>
										<?php
										$meeting_id = (int) $meeting_task->ID;
