										</li>
									<?php endforeach; ?>
								</ul>
							</section>
						<?php endif; ?>

						<?php self::render_ui_onboarding_reopen_link('dashboard'); ?>

						<?php if ('renata' === $persona) : ?>
							<div class="twob-card twob-section-card twob-dashboard-panel is-active" id="twob-dashboard-renata">
