									<a class="button button-small" href="<?php echo esc_url(admin_url('admin.php?page=twob-crm-visual-leads')); ?>">Abrir leads</a>
								</div>
								<div class="twob-grid twob-grid-3">
									<div class="twob-card">
										<div class="twob-line-1">
