															<span class="twob-pill twob-review-finding-flag <?php echo esc_attr($has_finding ? 'is-ready' : ($is_warning ? 'is-warning' : 'is-soft')); ?>"><?php echo esc_html($has_finding ? 'Hallazgo listo' : 'Esperando hallazgo'); ?></span>
