		$daily_new_leads = $dashboard_metrics['daily_new_leads'];
		$daily_contacts = $dashboard_metrics['daily_contacts'];
		$daily_followups = $dashboard_metrics['daily_followups'];
		$daily_meetings = $dashboard_metrics['daily_meetings'];
		$daily_responses = $dashboard_metrics['daily_responses'];
		$daily_collections = $dashboard_metrics['daily_collections'];
		$daily_tasks_done = $dashboard_metrics['daily_tasks_done'];
		$weekly_meetings = $dashboard_metrics['weekly_meetings'];
		$weekly_prop = $dashboard_metrics['weekly_prop'];
		$weekly_close = $dashboard_metrics['weekly_close'];
		$monthly_won = $dashboard_metrics['monthly_won'];
		$monthly_lost = $dashboard_metrics['monthly_lost'];
		$month_collected = $dashboard_metrics['month_collected'];
		$month_sold_amount = $dashboard_metrics['month_sold_amount'];
		$month_diagnostics_sold = $dashboard_metrics['month_diagnostics_sold'];
		$registry_lost = $dashboard_metrics['registry_lost'];
		$registry_rejected = $dashboard_metrics['registry_rejected'];
		$registry_no_response = $dashboard_metrics['registry_no_response'];
		$registry_canceled_meetings = $dashboard_metrics['registry_canceled_meetings'];
		$kpi_close_rate = $dashboard_metrics['kpi_close_rate'];
		$kpi_response_rate = $dashboard_metrics['kpi_response_rate'];
		$kpi_meeting_conversion = $dashboard_metrics['kpi_meeting_conversion'];
		$contact_count = $dashboard_metrics['contact_count'];
		$diag_count = $dashboard_metrics['diag_count'];
		$impl_count = $dashboard_metrics['impl_count'];
		$cont_count = $dashboard_metrics['cont_count'];
		$conv_cd = $dashboard_metrics['conv_cd'];
		$conv_di = $dashboard_metrics['conv_di'];
		$conv_ic = $dashboard_metrics['conv_ic'];

		$funnel_goal = max(1, (int) $goals['funnel']['monthly_continuity_goal']);
		$r_ic = max(1, (float) $goals['funnel']['implementation_to_continuity']) / 100;
		$r_di = max(1, (float) $goals['funnel']['diagnostic_to_implementation']) / 100;
		$r_cd = max(1, (float) $goals['funnel']['contact_to_diagnostic']) / 100;
		$needed_impl = (int) ceil($funnel_goal / $r_ic);
		$needed_diag = (int) ceil($needed_impl / $r_di);
		$needed_contacts_month = (int) ceil($needed_diag / $r_cd);
		$needed_contacts = (int) ceil($needed_contacts_month / max(1, (int) $goals['funnel']['business_days']));

		$daily_lead_target = self::daily_new_leads_target();
		$agenda = self::get_active_leads(array(
			'numberposts' => 10,
			'meta_key' => '_crm_next_followup',
			'meta_value' => $today,
			'meta_compare' => '=',
		));
		$agenda = array_values(array_filter($agenda, function ($lead) {
			return 'lost' !== self::normalize_stage_key((string) get_post_meta((int) $lead->ID, '_crm_stage', true));
		}));
		$operational_tasks = self::get_dashboard_operational_tasks($today, 18);
		$primary_tasks = array_slice($operational_tasks, 0, 4);
		$secondary_tasks = array_slice($operational_tasks, 4);
		$operational_task_ids = get_posts(array(
			'post_type' => 'crm_task',
			'post_status' => 'publish',
			'numberposts' => -1,
			'fields' => 'ids',
			'meta_query' => array(
				array('key' => '_crm_task_due', 'value' => $today, 'compare' => '<=', 'type' => 'DATE'),
				array(
					'relation' => 'OR',
					array('key' => '_crm_task_status', 'value' => 'pending', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'in_progress', 'compare' => '='),
					array('key' => '_crm_task_status', 'value' => 'open', 'compare' => '='),
				),
			),
		));
		$operational_task_ids = array_values(array_filter(array_map('intval', $operational_task_ids), function ($task_id) {
			return ! self::task_should_be_hidden_from_open_views($task_id);
		}));

		$today_task_count = 0;
		$overdue_task_count = 0;
		$routine_task_count = 0;
		foreach ($operational_task_ids as $task_id) {
			$task_id = (int) $task_id;
			$due = (string) get_post_meta($task_id, '_crm_task_due', true);
			$auto_key = (string) get_post_meta($task_id, '_crm_auto_key', true);
			if ($due && $due < $today) {
				$overdue_task_count++;
			} else {
				$today_task_count++;
			}
			if ($auto_key && 0 === strpos($auto_key, 'daily_routine_')) {
				$routine_task_count++;
			}
		}

		$risk_board = self::get_cooling_risk_board($today);
		$risk_preview = array();
		foreach (array_merge((array) $risk_board['lead_critical'], (array) $risk_board['client_critical'], (array) $risk_board['missing_next']) as $snapshot) {
			$lead_id = (int) ($snapshot['lead_id'] ?? 0);
			if (! $lead_id || isset($risk_preview[$lead_id])) {
				continue;
			}
			$risk_preview[$lead_id] = $snapshot;
			if (count($risk_preview) >= 5) {
				break;
			}
		}
		$leads_for_select = self::get_active_leads(array('numberposts' => 40));
		?>
		<div class="wrap twob-crm-visual twob-page">
			<h1>CRM 2B - Jornada de Hoy</h1>
