				</div>

				<div class="twob-grid twob-grid-2">
					<div class="twob-card">
						<div class="twob-line-1">
							<h3>Ahora</h3>
							<span class="twob-pill is-soft"><?php echo esc_html((string) count($primary_tasks)); ?> visibles</span>
						</div>
						<p class="twob-muted">Estas son las primeras tareas que Dani debería resolver sin mirar nada más.</p>
						<?php if (! $primary_tasks) : ?>
							<div class="twob-empty-card">No hay tareas urgentes ni pendientes para hoy.</div>
						<?php else : ?>
