	private static function progress($label, $value, $goal) {
		$goal = max(1, (float) $goal);
		$percent = (int) min(100, round(((float) $value / $goal) * 100));
		$class = 'bad';
		if ($percent >= 100) {
			$class = 'good';
		} elseif ($percent >= 50) {
			$class = 'mid';
		}
		echo '<div class="twob-progress-item"><div><span>' . esc_html($label) . '</span><span>' . esc_html($value . ' / ' . $goal) . '</span></div><div class="twob-bar"><i class="' . esc_attr($class) . '" style="width:' . esc_attr($percent) . '%"></i></div></div>';
	}

	public static function render_alliances_page() {
		if (! current_user_can('edit_crm_leads')) {
			wp_die('Sin permisos para acceder a alianzas.');
		}

		$message = '';
		$message_class = 'notice notice-success';
		$base_url = admin_url('admin.php?page=twob-crm-visual-alliances');
		$alliances = self::alliances_get();

		if (isset($_POST['twob_alliance_nonce']) && wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['twob_alliance_nonce'])), 'twob_alliance_save')) {
			$action = sanitize_key((string) wp_unslash($_POST['twob_alliance_action'] ?? 'save'));
			$alliance_id = sanitize_key((string) wp_unslash($_POST['id'] ?? ''));
			if ('delete' === $action) {
				$before_count = count($alliances);
				$alliances = array_values(array_filter($alliances, function ($alliance) use ($alliance_id) {
					return $alliance_id !== sanitize_key((string) ($alliance['id'] ?? ''));
				}));
				self::alliances_save($alliances);
				self::cancel_alliance_pending_tasks($alliance_id, array_keys(self::alliance_task_type_labels()), 'La alianza fue eliminada.');
				$message = $before_count !== count($alliances) ? 'Alianza eliminada.' : 'No se encontró la alianza a eliminar.';
				if ($before_count === count($alliances)) {
					$message_class = 'notice notice-warning';
				}
			} else {
				$current = $alliance_id ? self::alliance_find($alliance_id) : array();
				$is_new = empty($current);
				$previous_status = sanitize_key((string) ($current['status'] ?? ''));
				$record = self::sanitize_alliance_record($_POST, $current);
				if (! $record['name']) {
					$message = 'El nombre de la agencia es obligatorio.';
					$message_class = 'notice notice-error';
				} else {
					$saved = self::alliance_record_save($record);
					$editing_id = (string) ($saved['id'] ?? $record['id']);
					if ('contacted' === sanitize_key((string) ($saved['status'] ?? ''))) {
						self::ensure_alliance_initial_tasks($saved, current_time('Y-m-d'));
					} else {
						self::cancel_alliance_pending_tasks((string) ($saved['id'] ?? ''), array('alianza_contacto', 'alianza_seguimiento'), 'La alianza cambió de estado y se canceló la secuencia inicial.');
					}
					if ('contacted' !== $previous_status && 'contacted' === sanitize_key((string) ($saved['status'] ?? ''))) {
						self::alliance_touch((string) ($saved['id'] ?? ''), current_time('mysql'), current_time('mysql'));
					}
					$alliances = self::alliances_get();
					$message = $is_new ? 'Alianza creada.' : 'Alianza actualizada.';
				}
			}
		}

		$editing_id = isset($editing_id) && $editing_id ? $editing_id : (isset($_GET['alliance']) ? sanitize_key(wp_unslash($_GET['alliance'])) : '');
		$editing = $editing_id ? self::alliance_find($editing_id) : array();
		$editing = wp_parse_args($editing, self::alliance_record_defaults());
		$anthropic_ready = '' !== self::anthropic_api_key_get();
		$editing_alert = ! empty($editing['id']) ? self::alliance_alert_meta($editing, current_time('Y-m-d')) : array();
		?>
		<div class="wrap twob-crm-visual twob-page twob-page-alliances">
			<h1>Alianzas</h1>
			<p class="twob-muted">Sistema de alianzas con seguimiento, referidos a Pre-contacto y tareas automáticas separadas del pipeline comercial.</p>

			<?php if ($message) : ?>
				<div class="<?php echo esc_attr($message_class); ?>"><p><?php echo esc_html($message); ?></p></div>
			<?php endif; ?>

			<div class="twob-grid twob-grid-2">
				<div class="twob-card">
					<div class="twob-line-1">
						<div>
							<h2><?php echo esc_html($editing['id'] ? 'Editar alianza' : 'Nueva alianza'); ?></h2>
							<p class="twob-muted">Desde aquí se guarda la ficha base, se generan los mensajes y se crean referidos como leads Pre-contacto.</p>
						</div>
						<?php if ($editing['id']) : ?><a class="button" href="<?php echo esc_url($base_url); ?>">+ Nueva alianza</a><?php endif; ?>
					</div>
					<form method="post">
						<?php wp_nonce_field('twob_alliance_save', 'twob_alliance_nonce'); ?>
						<input type="hidden" name="twob_alliance_action" value="save">
						<input type="hidden" name="id" value="<?php echo esc_attr((string) $editing['id']); ?>">
						<div class="twob-grid twob-grid-2">
							<div class="twob-form-row"><label>Nombre de la agencia</label><input type="text" name="name" value="<?php echo esc_attr((string) $editing['name']); ?>" required></div>
							<div class="twob-form-row"><label>URL del sitio</label><input type="url" name="website_url" value="<?php echo esc_attr((string) $editing['website_url']); ?>" placeholder="https://..."></div>
							<div class="twob-form-row"><label>Nombre del contacto</label><input type="text" name="contact_name" value="<?php echo esc_attr((string) $editing['contact_name']); ?>"></div>
							<div class="twob-form-row"><label>Cargo del contacto</label><input type="text" name="contact_role" value="<?php echo esc_attr((string) $editing['contact_role']); ?>"></div>
							<div class="twob-form-row"><label>Tipo de agencia</label><select name="agency_type"><?php foreach (self::alliance_type_labels() as $key => $label) : ?><option value="<?php echo esc_attr($key); ?>" <?php selected((string) $editing['agency_type'], $key); ?>><?php echo esc_html($label); ?></option><?php endforeach; ?></select></div>
							<div class="twob-form-row"><label>Estado</label><select name="status"><?php foreach (self::alliance_status_labels() as $key => $label) : ?><option value="<?php echo esc_attr($key); ?>" <?php selected((string) $editing['status'], $key); ?>><?php echo esc_html($label); ?></option><?php endforeach; ?></select></div>
