				</details>
			</div>
		</div>
		<script>
			(function(){
				var resultsNode = document.getElementById('twob_prospect_results');
				var statusNode = document.getElementById('twob_prospect_status');
				var searchButton = document.getElementById('twob_prospect_search_btn');
				var historyNode = document.getElementById('twob_prospect_history_table');
				var kpiFound = document.getElementById('twob_prospect_kpi_found');
				var kpiAudited = document.getElementById('twob_prospect_kpi_audited');
				var kpiCreated = document.getElementById('twob_prospect_kpi_created');
				var sectorInputs = Array.prototype.slice.call(document.querySelectorAll('input[name="twob_prospect_sector[]"]'));
				var zoneInput = document.getElementById('twob_prospect_zone');
				var quantityInput = document.getElementById('twob_prospect_quantity');
				var nonce = (window.twobCrm && window.twobCrm.nonce) ? window.twobCrm.nonce : '<?php echo esc_js(wp_create_nonce(self::NONCE_ACTION)); ?>';
				var state = {searchId:'', prospects:[], createdCount:0, progressTimer:null};

				function selectedSectors(){
					return sectorInputs.filter(function(input){ return input.checked; }).map(function(input){ return input.value; });
				}
				function setStatus(text, type){
					statusNode.textContent = text || '';
					statusNode.className = 'twob-prospect-status' + (type ? ' is-' + type : '');
				}
				function syncButton(){
					searchButton.disabled = selectedSectors().length === 0;
				}
				function escapeHtml(text){
					return String(text || '').replace(/[&<>"']/g, function(char){
						return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[char];
					});
				}
				function renderHistory(history){
					if (!history || !history.length) {
						historyNode.innerHTML = '<div class="twob-prospect-empty">Todavía no hay búsquedas registradas.</div>';
						return;
					}
					var html = '<table class="twob-prospect-history-table"><thead><tr><th>Fecha</th><th>Sectores</th><th>Encontrados</th><th>Convertidos</th><th>Empresas</th></tr></thead><tbody>';
					history.forEach(function(item){
						html += '<tr><td>' + escapeHtml(item.created_at || '') + '</td><td>' + escapeHtml((item.sector_labels || []).join(', ')) + '</td><td>' + escapeHtml(item.found_count || 0) + '</td><td>' + escapeHtml(item.created_count || 0) + '</td><td>' + escapeHtml((item.companies || []).slice(0,5).join(', ') || 'Sin registros') + '</td></tr>';
					});
					html += '</tbody></table>';
					historyNode.innerHTML = html;
				}
				function boolBadge(ok){ return ok ? '✓' : '✗'; }
				function capacityBadge(value){ return 'alta' === String(value || '').toLowerCase() ? 'Alta' : 'Media'; }
				function linkedInSearchUrl(query){ return 'https://www.linkedin.com/search/results/people/?keywords=' + encodeURIComponent(String(query || '')); }
				function beginProgress(quantity){
					var phases = ['Buscando empresas...','Auditando sitios (1/' + quantity + ')...','Auditando sitios (' + Math.max(2, Math.min(quantity, 3)) + '/' + quantity + ')...','Generando hallazgos...','Preparando mensajes de LinkedIn...'];
					var index = 0;
					setStatus(phases[index], 'loading');
					window.clearInterval(state.progressTimer);
					state.progressTimer = window.setInterval(function(){ index = (index + 1) % phases.length; setStatus(phases[index], 'loading'); }, 1600);
				}
				function stopProgress(){ window.clearInterval(state.progressTimer); state.progressTimer = null; }
				function renderEmpty(message){
					resultsNode.innerHTML = '<div class="twob-prospect-empty">' + escapeHtml(message || 'No se encontraron prospectos.') + '</div>';
				}
				function postAjax(params){
					return fetch(ajaxurl, {
						method:'POST',
						headers:{'Content-Type':'application/x-www-form-urlencoded; charset=UTF-8'},
						credentials:'same-origin',
						body:params.toString()
					}).then(function(response){ return response.json(); });
				}
				function updateCreatedKpi(){ kpiCreated.textContent = String(state.createdCount || 0); }
				function prospectData(index){ return state.prospects[index] || null; }
				function cardSignals(signals){ return (signals && signals.length) ? signals.map(escapeHtml).join(' · ') : 'Sin señales detectadas'; }
				function renderResults(prospects){
					if (!prospects || !prospects.length) {
						renderEmpty('No se encontraron empresas nuevas que cumplan los filtros o varias ya existen en el CRM.');
						return;
					}
					var html = '';
					prospects.forEach(function(item, index){
						var decisionLabel = (item.decisorNombre ? escapeHtml(item.decisorNombre) + ' · ' : '') + escapeHtml(item.decisorCargo || 'Decisor por confirmar');
						var scanErrors = (item.scanErrors || []).join(' · ');
						html += '<article class="twob-prospect-card" data-prospect-index="' + index + '">' +
							'<div class="twob-prospect-card-head"><div><div class="twob-prospect-badges"><span class="twob-badge">' + escapeHtml(item.sector || '') + '</span><span class="twob-badge">' + escapeHtml(capacityBadge(item.capacidadEconomica)) + '</span>' + (item.manualAuditRequired ? '<span class="twob-badge" style="background:#fff7ed;color:#9a3412">Auditoría manual requerida</span>' : '') + '</div><h3>' + escapeHtml(item.empresa || '') + '</h3></div><div class="twob-prospect-card-url"><code>' + escapeHtml(item.url || '') + '</code><a class="button" href="' + escapeHtml(item.url || '#') + '" target="_blank" rel="noopener">↗ Abrir</a></div></div>' +
							'<div class="twob-prospect-meta-grid">' +
								'<section><h4>Decisor identificado</h4><div class="twob-prospect-inline-box"><strong>' + decisionLabel + '</strong><span>Zona: ' + escapeHtml(item.zona || 'Chile') + '</span><span>Señales de capacidad: ' + cardSignals(item.senalesCapacidad || []) + '</span></div></section>' +
								'<section><h4>Buscar en LinkedIn</h4><div class="twob-prospect-linkedin-box"><div><strong>🔍 Texto de búsqueda</strong><div>' + escapeHtml(item.decisorBusquedaLinkedin || '') + '</div></div><a class="button" href="' + escapeHtml(linkedInSearchUrl(item.decisorBusquedaLinkedin || '')) + '" target="_blank" rel="noopener">Abrir búsqueda ↗</a></div></section>' +
								'<section><h4>Hallazgo técnico</h4><div class="twob-prospect-inline-box"><strong>' + escapeHtml(item.hallazgo || '') + '</strong><span>→ ' + escapeHtml(item.impacto || '') + '</span></div></section>' +
								'<section><h4>Scores técnicos</h4><div class="twob-prospect-inline-box"><strong>Móvil ' + escapeHtml(item.speedMobile || 0) + '/100 · Desktop ' + escapeHtml(item.speedDesktop || 0) + '/100</strong><span>SSL ' + boolBadge(item.sslOk) + ' · dKIM ' + boolBadge(item.dkimOk) + ' · SPF ' + boolBadge(item.spfOk) + ' · DMARC ' + boolBadge(item.dmarcOk) + '</span>' + (scanErrors ? '<span>' + escapeHtml(scanErrors) + '</span>' : '') + '</div></section>' +
							'</div>' +
							'<section><h4>Mensaje listo para LinkedIn</h4><div class="twob-prospect-message-box" data-message-box>' + escapeHtml(item.mensajeLinkedin || '') + '</div><div class="twob-prospect-card-actions"><button type="button" class="button" data-copy-message>⎘ Copiar</button><button type="button" class="button button-primary" data-open-create>✓ Crear lead en CRM</button><button type="button" class="button" data-discard>✗ Descartar</button></div></section>' +
							'<div class="twob-prospect-mini-form" data-create-form><div class="twob-grid twob-grid-2"><div class="twob-form-row"><label>Nombre del decisor</label><input type="text" data-field="decisor_nombre" value="' + escapeHtml(item.decisorNombre || '') + '" placeholder="Por confirmar"></div><div class="twob-form-row"><label>Cargo</label><input type="text" data-field="decisor_cargo" value="' + escapeHtml(item.decisorCargo || '') + '" placeholder="Gerente General"></div><div class="twob-form-row"><label>Email</label><input type="email" data-field="email" value="' + escapeHtml(item.email || '') + '" placeholder="contacto@empresa.cl"></div><div class="twob-form-row"><label>Teléfono</label><input type="text" data-field="telefono" value="' + escapeHtml(item.telefono || '') + '" placeholder="+56..."></div></div><div class="twob-prospect-card-actions"><button type="button" class="button button-primary" data-confirm-create>Confirmar y crear lead</button><button type="button" class="button" data-cancel-create>Cancelar</button></div><div class="twob-prospect-status" data-create-status></div></div>' +
						'</article>';
					});
					resultsNode.innerHTML = html;
					attachCardEvents();
				}
				function attachCardEvents(){
					resultsNode.querySelectorAll('[data-copy-message]').forEach(function(button){
						button.addEventListener('click', function(){
							var card = button.closest('[data-prospect-index]');
							var messageBox = card ? card.querySelector('[data-message-box]') : null;
							var text = messageBox ? messageBox.textContent.trim() : '';
							if (!text) { return; }
							navigator.clipboard.writeText(text).then(function(){
								button.textContent = '✓ Copiado';
								window.setTimeout(function(){ button.textContent = '⎘ Copiar'; }, 1800);
							});
						});
					});
					resultsNode.querySelectorAll('[data-discard]').forEach(function(button){
						button.addEventListener('click', function(){
							var card = button.closest('.twob-prospect-card');
							card.classList.add('is-faded');
							window.setTimeout(function(){ card.remove(); }, 220);
						});
					});
					resultsNode.querySelectorAll('[data-open-create]').forEach(function(button){
						button.addEventListener('click', function(){
							var form = button.closest('.twob-prospect-card').querySelector('[data-create-form]');
							if (form) { form.classList.add('is-open'); }
						});
					});
					resultsNode.querySelectorAll('[data-cancel-create]').forEach(function(button){
						button.addEventListener('click', function(){
							var form = button.closest('[data-create-form]');
							if (form) { form.classList.remove('is-open'); }
						});
					});
					resultsNode.querySelectorAll('[data-confirm-create]').forEach(function(button){
						button.addEventListener('click', function(){
							var card = button.closest('.twob-prospect-card');
							var index = parseInt(card.getAttribute('data-prospect-index') || '0', 10);
							var item = prospectData(index);
							if (!item) { return; }
							var form = card.querySelector('[data-create-form]');
							var status = form.querySelector('[data-create-status]');
							var params = new URLSearchParams();
							params.set('action', 'twob_crear_prospecto_lead');
							params.set('nonce', nonce);
							params.set('search_id', state.searchId || '');
							params.set('empresa', item.empresa || '');
							params.set('url', item.url || '');
							params.set('domain', item.domain || '');
							params.set('sector', item.sector || '');
							params.set('sector_key', item.sectorKey || '');
							params.set('capacidad_economica', item.capacidadEconomica || 'media');
							params.set('senales_capacidad', JSON.stringify(item.senalesCapacidad || []));
							params.set('decisor_nombre', form.querySelector('[data-field="decisor_nombre"]').value.trim());
							params.set('decisor_cargo', form.querySelector('[data-field="decisor_cargo"]').value.trim());
							params.set('decisor_linkedin_busqueda', item.decisorBusquedaLinkedin || '');
							params.set('email', form.querySelector('[data-field="email"]').value.trim());
							params.set('telefono', form.querySelector('[data-field="telefono"]').value.trim());
							params.set('linkedin_empresa', item.linkedinEmpresa || '');
							params.set('hallazgo', item.hallazgo || '');
							params.set('impacto', item.impacto || '');
							params.set('hallazgo_completo', item.hallazgoCompleto || '');
							params.set('mensaje_linkedin', item.mensajeLinkedin || '');
							params.set('speed_mobile', item.speedMobile || 0);
							params.set('speed_desktop', item.speedDesktop || 0);
							params.set('ssl_ok', item.sslOk ? '1' : '0');
							params.set('dkim_ok', item.dkimOk ? '1' : '0');
							params.set('spf_ok', item.spfOk ? '1' : '0');
							params.set('dmarc_ok', item.dmarcOk ? '1' : '0');
							params.set('site_status', item.siteStatus || 'ok');
							params.set('critical_count', item.criticalCount || 0);
							params.set('high_count', item.highCount || 0);
							params.set('medium_count', item.mediumCount || 0);
							params.set('scan_errors', JSON.stringify(item.scanErrors || []));
							params.set('manual_audit_required', item.manualAuditRequired ? '1' : '0');
							status.textContent = 'Creando lead en CRM...';
							status.className = 'twob-prospect-status is-loading';
							button.disabled = true;
							postAjax(params).then(function(payload){
								if (!payload || !payload.success) {
									throw new Error((payload && payload.data && payload.data.message) || 'No se pudo crear el lead.');
								}
								state.createdCount += 1;
								updateCreatedKpi();
								renderHistory(payload.data.history || []);
								card.querySelectorAll('button').forEach(function(btn){ btn.disabled = true; });
								status.textContent = payload.data.message || '✓ Lead creado';
								status.className = 'twob-prospect-status is-ok';
								var linkRow = document.createElement('div');
								linkRow.className = 'twob-prospect-status is-ok';
								linkRow.innerHTML = '✓ Lead creado → <a href="' + escapeHtml(payload.data.lead_url || '#') + '" target="_blank" rel="noopener">Abrir lead</a>';
								form.appendChild(linkRow);
							}).catch(function(error){
								button.disabled = false;
								status.textContent = error.message || 'No se pudo crear el lead.';
								status.className = 'twob-prospect-status is-error';
							});
						});
					});
				}
				function performSearch(){
					var sectors = selectedSectors();
					if (!sectors.length) {
						setStatus('Selecciona al menos un sector antes de buscar.', 'error');
						return;
					}
					var quantity = parseInt(quantityInput.value || '10', 10) || 10;
					var params = new URLSearchParams();
					params.set('action', 'twob_buscar_prospectos');
					params.set('nonce', nonce);
					params.set('zone', zoneInput.value || 'santiago_chile');
					params.set('quantity', String(quantity));
					sectors.forEach(function(sector){ params.append('sectors[]', sector); });
					searchButton.disabled = true;
					beginProgress(quantity);
					postAjax(params).then(function(payload){
						if (!payload || !payload.success) {
							throw new Error((payload && payload.data && payload.data.message) || 'No se pudo completar la búsqueda.');
						}
						stopProgress();
						state.searchId = payload.data.search_id || '';
						state.prospects = payload.data.prospects || [];
						state.createdCount = 0;
						kpiFound.textContent = String(state.prospects.length || 0);
						kpiAudited.textContent = String(payload.data.audited_count || 0);
						updateCreatedKpi();
						renderResults(state.prospects);
						renderHistory(payload.data.history || []);
						setStatus(payload.data.message || ('Listo. Se encontraron ' + state.prospects.length + ' prospectos nuevos.'), 'ok');
					}).catch(function(error){
						stopProgress();
						renderEmpty('La búsqueda no se pudo completar. Ajusta los filtros o reintenta en unos segundos.');
						setStatus(error.message || 'No se pudo completar la búsqueda.', 'error');
					}).finally(function(){
						searchButton.disabled = false;
						syncButton();
					});
				}
				sectorInputs.forEach(function(input){ input.addEventListener('change', syncButton); });
				searchButton.addEventListener('click', performSearch);
				syncButton();
				renderHistory(<?php echo wp_json_encode($history); ?>);
			})();
		</script>
		<?php
	}

	private static function render_prospect_history_table($history) {
		$history = array_values(array_filter((array) $history, 'is_array'));
		if (empty($history)) {
			echo '<div class="twob-prospect-empty">Todavía no hay búsquedas registradas.</div>';
			return;
		}
		echo '<table class="twob-prospect-history-table"><thead><tr><th>Fecha</th><th>Sectores</th><th>Encontrados</th><th>Convertidos</th><th>Empresas</th></tr></thead><tbody>';
		foreach ($history as $row) {
			echo '<tr>';
			echo '<td>' . esc_html((string) ($row['created_at'] ?? '')) . '</td>';
			echo '<td>' . esc_html(implode(', ', array_filter(array_map('strval', (array) ($row['sector_labels'] ?? array()))))) . '</td>';
			echo '<td>' . esc_html((string) ((int) ($row['found_count'] ?? 0))) . '</td>';
			echo '<td>' . esc_html((string) ((int) ($row['created_count'] ?? 0))) . '</td>';
			echo '<td>' . esc_html(implode(', ', array_slice(array_filter(array_map('strval', (array) ($row['companies'] ?? array()))), 0, 5))) . '</td>';
			echo '</tr>';
		}
		echo '</tbody></table>';
	}

	public static function render_settings_page() {
		if (! self::user_can_manage_settings()) {
			wp_die('Sin permisos para acceder a la configuracion.');
		}
		if (isset($_POST['twob_settings_nonce']) && wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['twob_settings_nonce'])), 'twob_settings_save')) {
			$client_types = array();
			$service_options = array();
			$types_raw = isset($_POST['client_types_lines']) ? (string) wp_unslash($_POST['client_types_lines']) : '';
			$services_raw = isset($_POST['service_options_lines']) ? (string) wp_unslash($_POST['service_options_lines']) : '';
			foreach (array_filter(array_map('trim', explode("\n", $types_raw))) as $line) {
				$key = sanitize_key($line);
				if ($key) {
					$client_types[$key] = sanitize_text_field($line);
				}
			}
			foreach (array_filter(array_map('trim', explode("\n", $services_raw))) as $line) {
				$key = sanitize_key($line);
				if ($key) {
					$service_options[$key] = sanitize_text_field($line);
				}
			}
			$contact = array(
				'email' => isset($_POST['contact_email']) ? wp_unslash($_POST['contact_email']) : '',
				'whatsapp' => isset($_POST['contact_whatsapp']) ? wp_unslash($_POST['contact_whatsapp']) : '',
				'agenda' => isset($_POST['contact_agenda']) ? wp_unslash($_POST['contact_agenda']) : '',
			);
			self::settings_save(array('client_types' => $client_types, 'service_options' => $service_options, 'contact' => $contact));
			$prospect_excluded = isset($_POST['prospect_excluded_sectors']) ? sanitize_textarea_field((string) wp_unslash($_POST['prospect_excluded_sectors'])) : '';
			update_option(self::PROSPECT_EXCLUDED_SECTORS_OPTION, $prospect_excluded);
			$pagespeed_api_key = isset($_POST['pagespeed_api_key']) ? wp_unslash($_POST['pagespeed_api_key']) : '';
			$anthropic_api_key = isset($_POST['anthropic_api_key']) ? wp_unslash($_POST['anthropic_api_key']) : '';
			self::pagespeed_api_key_save($pagespeed_api_key);
			self::anthropic_api_key_save($anthropic_api_key);
			echo '<div class="updated"><p>Configuracion CRM guardada.</p></div>';
		}
		$s = self::settings_get();
		$pagespeed_api_key = self::pagespeed_api_key_get();
		$anthropic_api_key = self::anthropic_api_key_get();
		$prospect_excluded = self::prospect_excluded_sectors_raw();
		$contacted_domains = implode("\n", array_keys(self::prospect_existing_domains()));
		$contact_settings = isset($s['contact']) && is_array($s['contact']) ? $s['contact'] : array();
		?>
		<div class="wrap twob-crm-visual">
			<h1>Configuracion CRM</h1>
			<p class="twob-muted">Edita tipos de cliente, servicios y APIs externas del CRM.</p>
			<form method="post" class="twob-grid twob-grid-2">
				<?php wp_nonce_field('twob_settings_save', 'twob_settings_nonce'); ?>
				<div class="twob-card">
					<h3>Tipos de cliente</h3>
					<textarea name="client_types_lines" rows="14"><?php echo esc_textarea(implode("\n", array_values((array) $s['client_types']))); ?></textarea>
				</div>
				<div class="twob-card">
					<h3>Servicios</h3>
					<textarea name="service_options_lines" rows="14"><?php echo esc_textarea(implode("\n", array_values((array) $s['service_options']))); ?></textarea>
				</div>
				<div class="twob-card twob-col-span-2">
					<h3>Datos de contacto de 2B Consulting</h3>
					<div class="twob-grid twob-grid-3">
						<div class="twob-form-row">
							<label>Email de contacto</label>
							<input type="email" name="contact_email" value="<?php echo esc_attr((string) ($contact_settings['email'] ?? '')); ?>" placeholder="contacto@2bconsulting.cl">
						</div>
						<div class="twob-form-row">
							<label>WhatsApp de contacto</label>
							<input type="text" name="contact_whatsapp" value="<?php echo esc_attr((string) ($contact_settings['whatsapp'] ?? '')); ?>" placeholder="+56 9 XXXX XXXX">
						</div>
						<div class="twob-form-row">
							<label>Link de agenda (opcional)</label>
							<input type="url" name="contact_agenda" value="<?php echo esc_attr((string) ($contact_settings['agenda'] ?? '')); ?>" placeholder="https://cal.com/...">
						</div>
					</div>
					<p class="twob-muted">Estos datos se insertan automáticamente en mensajes y formularios de reactivación.</p>
				</div>
				<div class="twob-card twob-col-span-2">
					<h3>APIs externas</h3>
					<div class="twob-form-row">
						<label>Google PageSpeed API Key</label>
						<input type="password" name="pagespeed_api_key" id="twob_pagespeed_api_key" value="<?php echo esc_attr($pagespeed_api_key); ?>" autocomplete="off" placeholder="AIza...">
