					<div class="twob-grid twob-grid-2">
						<div class="twob-form-row">
							<label>Sectores excluidos</label>
							<textarea name="prospect_excluded_sectors" rows="6" placeholder="Ej: inmobiliaria premium&#10;gastronomía boutique"><?php echo esc_textarea($prospect_excluded); ?></textarea>
							<small class="twob-form-help">Usa una línea por término o sector. El buscador omitirá resultados cuyo nombre, sector o zona coincidan con estas palabras.</small>
