	public static function render_goals_page() {
		if (! self::user_can_manage_settings()) {
			wp_die('Sin permisos para acceder a las metas.');
		}
		if (isset($_POST['twob_goals_nonce']) && wp_verify_nonce(sanitize_text_field(wp_unslash($_POST['twob_goals_nonce'])), 'twob_goals_save')) {
			self::goals_save($_POST);
			echo '<div class="updated"><p>Metas guardadas.</p></div>';
		}
		$g = self::goals_get();
		?>
		<div class="wrap twob-crm-visual">
			<h1>Configuracion de metas y KPI comercial</h1>
			<form method="post" class="twob-grid twob-grid-3">
				<?php wp_nonce_field('twob_goals_save', 'twob_goals_nonce'); ?>
				<div class="twob-card"><h3>Diarias</h3>
					<p><input type="number" name="daily_new_contacts" value="<?php echo esc_attr($g['daily']['new_contacts']); ?>"> Contactos nuevos</p>
