	private static function render_site_reviewer_scripts($nonce) {
		?>
		<script>
			(function(){
				var reviewerNonce = '<?php echo esc_js($nonce); ?>';
				var reviewerChecks = [
					{cat:'Rendimiento',items:[
						{id:'speed_mobile_slow',title:'Velocidad móvil lenta (< 50)',impact:'Más del 60% del tráfico en Chile es móvil. Un sitio lento pierde visitantes antes de que vean la propuesta.',sev:'critical',auto:true},
						{id:'speed_desktop_slow',title:'Velocidad escritorio lenta (< 60)',impact:'La primera impresión del sitio se ve afectada por la lentitud de carga.',sev:'high',auto:true},
						{id:'images_heavy',title:'Imágenes sin optimizar o muy pesadas',impact:'Recursos pesados aumentan el tiempo de carga y el abandono de usuarios.',sev:'medium',auto:true},
