					]},
					{cat:'Formularios y captación',items:[
						{id:'form_broken',title:'Formulario de contacto no envía',impact:'Las oportunidades comerciales que llegan al sitio no pueden contactar a la empresa.',sev:'critical',auto:false},
						{id:'form_no_confirm',title:'Formulario sin confirmación de envío',impact:'El usuario no sabe si su mensaje llegó, generando desconfianza y reenvíos duplicados.',sev:'high',auto:false},
						{id:'no_form',title:'Sin formulario de contacto visible',impact:'El sitio no captura leads de forma directa y el visitante interesado no tiene dónde dejar sus datos.',sev:'critical',auto:false},
						{id:'no_cta',title:'Sin CTA claro o poco visible',impact:'El visitante no sabe qué acción tomar, aumentando la tasa de rebote sin conversión.',sev:'high',auto:false},
						{id:'no_phone',title:'Sin teléfono ni WhatsApp visible',impact:'El prospecto que prefiere contacto directo no encuentra cómo hacerlo.',sev:'medium',auto:false}
					]},
					{cat:'Seguridad y correos',items:[
						{id:'ssl_expired',title:'SSL vencido o ausente',impact:'El navegador muestra advertencia de seguridad y frena la confianza antes de que el prospecto vea la propuesta.',sev:'critical',auto:true},
						{id:'no_https',title:'Sin redirección HTTPS',impact:'Parte del tráfico llega sin cifrado, con riesgo de seguridad y penalización en Google.',sev:'high',auto:true},
						{id:'dkim_missing',title:'DKIM no configurado',impact:'Los correos corporativos probablemente caen en spam, incluidos los de seguimiento comercial.',sev:'critical',auto:true},
						{id:'spf_missing',title:'SPF no configurado',impact:'Riesgo de que los correos sean rechazados o suplantados por terceros.',sev:'high',auto:true},
						{id:'dmarc_missing',title:'DMARC no configurado',impact:'Sin política de autenticación de correos, la reputación del dominio queda expuesta.',sev:'medium',auto:true}
					]},
					{cat:'Estado técnico WordPress',items:[
						{id:'wp_outdated',title:'WordPress desactualizado',impact:'Versión vulnerable a ataques conocidos y publicados públicamente.',sev:'critical',auto:false},
						{id:'plugins_outdated',title:'Plugins desactualizados',impact:'Riesgo de incompatibilidades, errores inesperados y brechas de seguridad activas.',sev:'high',auto:false},
						{id:'no_security_plugin',title:'Sin plugin de seguridad activo',impact:'Sin protección contra fuerza bruta, inyecciones y ataques comunes a WordPress.',sev:'high',auto:false},
						{id:'no_backup',title:'Sin sistema de respaldo activo',impact:'Un incidente puede resultar en pérdida total del sitio y los datos del negocio.',sev:'critical',auto:false},
						{id:'errors_404',title:'Errores 404 visibles en páginas clave',impact:'Páginas rotas dañan la credibilidad, la experiencia del usuario y el posicionamiento SEO.',sev:'high',auto:true}
					]},
					{cat:'Medición y campañas',items:[
						{id:'no_analytics',title:'Sin Google Analytics o GA4',impact:'No hay datos sobre el comportamiento de los visitantes y las decisiones se toman a ciegas.',sev:'critical',auto:false},
						{id:'no_gtm',title:'Sin Google Tag Manager',impact:'Las campañas pagadas no pueden medir conversiones correctamente.',sev:'high',auto:false},
						{id:'no_meta_pixel',title:'Sin pixel de Meta',impact:'Las campañas de redes sociales no pueden optimizarse ni crear audiencias personalizadas.',sev:'high',auto:false},
						{id:'no_search_console',title:'Sin Google Search Console vinculado',impact:'No hay visibilidad sobre errores de indexación ni rendimiento orgánico.',sev:'medium',auto:false},
						{id:'landing_no_convert',title:'Landing sin foco de conversión',impact:'El tráfico de campañas llega a páginas que no convierten y se desperdicia inversión.',sev:'high',auto:false}
					]},
					{cat:'Experiencia móvil',items:[
						{id:'not_responsive',title:'Sitio no adaptado a móvil',impact:'Un sitio que no se adapta pierde la mayoría de sus visitas móviles.',sev:'critical',auto:false},
						{id:'menu_mobile_broken',title:'Menú difícil de usar en móvil',impact:'La navegación en móvil genera frustración y abandono antes de llegar al contenido.',sev:'high',auto:false},
						{id:'text_unreadable_mobile',title:'Texto ilegible en pantallas pequeñas',impact:'El usuario no puede leer la propuesta de valor en móvil.',sev:'medium',auto:false},
						{id:'buttons_too_small',title:'Botones o CTAs muy pequeños en móvil',impact:'El usuario no puede hacer clic correctamente y se pierden conversiones.',sev:'medium',auto:false}
					]},
					{cat:'SEO básico',items:[
						{id:'no_meta',title:'Sin meta títulos o descripciones',impact:'El sitio no aparece correctamente en Google y pierde calidad en resultados orgánicos.',sev:'high',auto:true},
						{id:'no_sitemap',title:'Sin sitemap XML',impact:'Google no puede indexar el sitio correctamente, afectando la visibilidad orgánica.',sev:'medium',auto:false},
						{id:'no_h1',title:'Sin H1 claro en la home',impact:'Google y el visitante no entienden de qué trata el negocio en la primera lectura.',sev:'medium',auto:true},
						{id:'duplicate_content',title:'Contenido duplicado detectado',impact:'Puede generar señales confusas para SEO y diluir la página principal.',sev:'medium',auto:false}
					]}
				];

				function sendAjax(body){
					return fetch(ajaxurl, {
						method: 'POST',
						headers: {'Content-Type':'application/x-www-form-urlencoded; charset=UTF-8'},
						body: body.toString()
					}).then(function(response){
						return response.json();
					});
				}

				function escapeHtml(value){
					return String(value || '')
						.replace(/&/g, '&amp;')
						.replace(/</g, '&lt;')
						.replace(/>/g, '&gt;')
						.replace(/"/g, '&quot;')
						.replace(/'/g, '&#39;');
				}

				function readJson(rawValue){
					if (!rawValue) { return {}; }
					try {
						return JSON.parse(rawValue);
					} catch (error) {
						return {};
					}
				}

				function role(root, name){
					return root ? root.querySelector('[data-rev-role="' + name + '"]') : null;
				}

				function severityLabel(sev){
					if (sev === 'critical') { return 'Crítico'; }
					if (sev === 'high') { return 'Alto'; }
					return 'Medio';
				}

				function shortText(text, maxLength){
					var clean = String(text || '').trim();
					if (clean.length <= maxLength) { return clean; }
					return clean.slice(0, maxLength - 1) + '…';
				}

				function safeFileName(value){
					return String(value || 'empresa')
						.toLowerCase()
						.normalize('NFD')
						.replace(/[\u0300-\u036f]/g, '')
						.replace(/[^a-z0-9]+/g, '-')
						.replace(/^-+|-+$/g, '') || 'empresa';
				}

				function relativeTimeFromUnix(timestamp){
					var value = parseInt(timestamp, 10);
					if (!value) { return ''; }
					var diff = Math.max(0, Math.floor(Date.now() / 1000) - value);
					if (diff < 60) { return 'hace un momento'; }
					if (diff < 3600) { return 'hace ' + Math.max(1, Math.floor(diff / 60)) + ' min'; }
					if (diff < 86400) { return 'hace ' + Math.max(1, Math.floor(diff / 3600)) + ' horas'; }
					return 'hace ' + Math.max(1, Math.floor(diff / 86400)) + ' días';
				}

				function normalizeUrl(url){
					var clean = String(url || '').trim();
					if (!clean) { return ''; }
					if (!/^https?:\/\//i.test(clean)) {
						clean = 'https://' + clean.replace(/^\/+/, '');
					}
					return clean;
				}

				function getCheckedGroups(instance){
					var groups = {critical:[], high:[], medium:[]};
					reviewerChecks.forEach(function(category){
						category.items.forEach(function(item){
							if (instance.state[item.id]) {
								groups[item.sev].push(item);
							}
						});
					});
					return groups;
				}

				function topFinding(instance){
					var groups = getCheckedGroups(instance);
					return groups.critical[0] || groups.high[0] || groups.medium[0] || null;
				}

				function derivedStatusKey(instance){
					var groups = getCheckedGroups(instance);
					if (groups.critical.length > 0) { return 'critico'; }
					if (groups.high.length > 0) { return 'moderado'; }
					if (groups.medium.length > 0) { return 'leve'; }
					return 'ok';
				}

				function formatStatusBadge(statusKey, hasData){
					if (statusKey === 'critico') {
						return {label:'🔴 Estado crítico — requiere atención inmediata', className:'is-critico'};
					}
					if (statusKey === 'moderado') {
						return {label:'🟠 Estado moderado — varios puntos a mejorar', className:'is-moderado'};
					}
					if (statusKey === 'leve') {
						return {label:'🔵 Estado leve — mejoras recomendadas', className:'is-leve'};
					}
					if (hasData) {
						return {label:'🟢 Sin problemas detectados', className:'is-ok'};
					}
					return null;
				}

				function formatSpeedBadge(target, value){
					if (!target) { return; }
					var score = parseInt(value, 10);
					target.textContent = '';
					target.style.background = '';
					target.style.color = '';
					if (Number.isNaN(score)) { return; }
					if (score < 50) {
						target.textContent = 'Lento';
						target.style.background = '#fdf0ee';
						target.style.color = '#c0392b';
						return;
					}
					if (score < 70) {
						target.textContent = 'Regular';
						target.style.background = '#fef4ee';
						target.style.color = '#d35400';
						return;
					}
					target.textContent = 'OK';
					target.style.background = '#edfaf4';
					target.style.color = '#1d9e75';
				}

				function setChecked(instance, id, checked){
					instance.state[id] = !!checked;
					var row = instance.section.querySelector('[data-check-id="' + id + '"]');
					var input = row ? row.querySelector('input[type="checkbox"]') : null;
					if (input) { input.checked = !!checked; }
					if (row) { row.classList.toggle('is-checked', !!checked); }
				}

				function syncSpeedChecks(instance){
					var mobileValue = parseInt(role(instance.section, 'speed-mobile').value, 10);
					var desktopValue = parseInt(role(instance.section, 'speed-desktop').value, 10);
					if (!Number.isNaN(mobileValue)) {
						setChecked(instance, 'speed_mobile_slow', mobileValue < 50);
					}
					if (!Number.isNaN(desktopValue)) {
						setChecked(instance, 'speed_desktop_slow', desktopValue < 60);
					}
				}

				function setInlineMessage(node, message, tone){
					if (!node) { return; }
					node.classList.remove('is-loading', 'is-error', 'is-ok');
					if (tone) {
						node.classList.add('is-' + tone);
					}
					node.textContent = message || '';
				}

				function updateLeadCardIndicators(instance, findingText){
					var leadCard = instance.leadCard;
					if (!leadCard) { return; }
					var pill = leadCard.querySelector('.twob-precontact-finding-pill');
					var summary = leadCard.querySelector('.twob-precontact-finding-summary');
					var textarea = leadCard.querySelector('.twob-lead-technical-finding');
					var scanMeta = leadCard.querySelector('.twob-lead-scan-meta');
					var statusBlock = leadCard.querySelector('.twob-site-review-status');
					if (pill) {
						pill.classList.remove('is-soft', 'is-warning');
						pill.classList.add('is-ready');
						pill.textContent = 'Hallazgo listo';
					}
					if (summary) {
						summary.hidden = false;
						summary.textContent = 'Hallazgo: ' + shortText(findingText, 60);
					}
					if (textarea) {
						textarea.value = findingText;
					}
					if (scanMeta) {
						var critical = instance.latestCounts.critical;
						var high = instance.latestCounts.high;
						var medium = instance.latestCounts.medium;
						var parts = [];
						if (critical > 0) { parts.push(critical + ' críticos'); }
						if (high > 0) { parts.push(high + ' altos'); }
						if (medium > 0) { parts.push(medium + ' medios'); }
						if (!parts.length) { parts.push('sin hallazgos críticos visibles'); }
						scanMeta.textContent = 'Escaneo: ' + parts.join(' · ');
						scanMeta.classList.remove('is-warning');
						scanMeta.classList.add('is-ready');
						scanMeta.hidden = false;
					}
					if (statusBlock) {
						statusBlock.classList.remove('is-unscanned', 'is-manual', 'is-critico', 'is-moderado', 'is-leve', 'is-ok');
						statusBlock.classList.add('is-' + instance.currentStatusKey);
						var statusLabel = statusBlock.querySelector('.twob-site-review-status-label');
						var statusText = statusBlock.querySelector('.twob-site-review-status-text');
						var openButton = statusBlock.querySelector('.twob-site-review-open');
						if (statusLabel) {
							statusLabel.textContent = instance.currentStatusLabel;
						}
						if (statusText) {
							statusText.textContent = instance.currentStatusDescription;
						}
						if (openButton) {
							openButton.textContent = 'Abrir revisión técnica';
						}
					}
				}

				function updateReviewer(instance){
					var empresa = role(instance.section, 'empresa').value.trim();
					var contacto = role(instance.section, 'contacto').value.trim();
					var url = role(instance.section, 'url').value.trim();
					var speedMobileField = role(instance.section, 'speed-mobile');
					var speedDesktopField = role(instance.section, 'speed-desktop');
					syncSpeedChecks(instance);
					formatSpeedBadge(role(instance.section, 'badge-mobile'), speedMobileField.value);
					formatSpeedBadge(role(instance.section, 'badge-desktop'), speedDesktopField.value);

					var groups = getCheckedGroups(instance);
					var total = groups.critical.length + groups.high.length + groups.medium.length;
					var hasData = !!(empresa || contacto || url);
					var top = topFinding(instance);
					instance.latestCounts = {
						critical: groups.critical.length,
						high: groups.high.length,
						medium: groups.medium.length
					};
					instance.currentStatusKey = derivedStatusKey(instance);
					instance.currentStatusLabel = instance.currentStatusKey === 'critico' ? '🔴 Crítico' : (instance.currentStatusKey === 'moderado' ? '🟠 Moderado' : (instance.currentStatusKey === 'leve' ? '🔵 Leve' : '🟢 OK'));
					instance.currentStatusDescription = [
						groups.critical.length ? groups.critical.length + ' críticos' : '',
						groups.high.length ? groups.high.length + ' altos' : '',
						groups.medium.length ? groups.medium.length + ' medios' : '',
						instance.lastScanAt ? 'Escaneado ' + relativeTimeFromUnix(instance.lastScanAt) : ''
					].filter(Boolean).join(' · ') || 'Sin hallazgos guardados todavía.';

					['count-critical', 'count-critical-inline'].forEach(function(name){ var node = role(instance.section, name); if (node) { node.textContent = String(groups.critical.length); } });
					['count-high', 'count-high-inline'].forEach(function(name){ var node = role(instance.section, name); if (node) { node.textContent = String(groups.high.length); } });
					['count-medium', 'count-medium-inline'].forEach(function(name){ var node = role(instance.section, name); if (node) { node.textContent = String(groups.medium.length); } });

					var badgeWrap = role(instance.section, 'estado-badge-wrap');
					var badge = formatStatusBadge(instance.currentStatusKey, hasData);
					badgeWrap.innerHTML = badge ? '<div class="twob-rev-estado-badge ' + badge.className + '">' + escapeHtml(badge.label) + '</div>' : '';

					var daniEmpty = role(instance.section, 'dani-empty');
					var daniContent = role(instance.section, 'dani-content');
					if (!hasData && total === 0) {
						daniEmpty.hidden = false;
						daniContent.hidden = true;
					} else {
						daniEmpty.hidden = true;
						daniContent.hidden = false;
						var nowDate = new Date().toLocaleDateString('es-CL', {day:'2-digit', month:'2-digit', year:'numeric'});
						var daniText = 'EMPRESA: ' + (empresa || '[nombre empresa]') + '\n';
						daniText += 'URL: ' + (url || '[url]') + '\n';
						daniText += 'FECHA: ' + nowDate + '\n';
						if (speedMobileField.value) { daniText += 'PAGESPEED MÓVIL: ' + speedMobileField.value + '/100\n'; }
						if (speedDesktopField.value) { daniText += 'PAGESPEED ESCRITORIO: ' + speedDesktopField.value + '/100\n'; }
						daniText += '\n';
						if (groups.critical.length) {
							daniText += '🔴 CRÍTICOS (' + groups.critical.length + '):\n';
							groups.critical.forEach(function(item){ daniText += '• ' + item.title + '\n  → ' + item.impact + '\n'; });
							daniText += '\n';
						}
						if (groups.high.length) {
							daniText += '🟠 ALTOS (' + groups.high.length + '):\n';
							groups.high.forEach(function(item){ daniText += '• ' + item.title + '\n  → ' + item.impact + '\n'; });
							daniText += '\n';
						}
						if (groups.medium.length) {
							daniText += '🔵 MEDIOS (' + groups.medium.length + '):\n';
							groups.medium.forEach(function(item){ daniText += '• ' + item.title + '\n  → ' + item.impact + '\n'; });
						}
						if (groups.critical.length > 0) {
							daniText += '\nESTADO GENERAL: CRÍTICO — requiere intervención antes de escalar campañas o marketing';
						} else if (groups.high.length > 0) {
							daniText += '\nESTADO GENERAL: MODERADO — puntos importantes a corregir para mejorar resultados';
						} else if (groups.medium.length > 0) {
							daniText += '\nESTADO GENERAL: LEVE — mejoras recomendadas sin urgencia crítica';
						} else if (hasData) {
							daniText += '\nESTADO GENERAL: OK — no se detectaron problemas visibles en esta pasada.';
						}
						role(instance.section, 'out-dani').textContent = daniText;
						role(instance.section, 'char-dani').textContent = daniText.length + ' caracteres';
					}

					var liEmpty = role(instance.section, 'li-empty');
					var liContent = role(instance.section, 'li-content');
					if (!hasData || !top) {
						liEmpty.hidden = false;
						liContent.hidden = true;
					} else {
						liEmpty.hidden = true;
						liContent.hidden = false;
						var liImpact = top.impact.split('—')[0].trim();
						var li1 = 'Hola ' + (contacto || '[Nombre]') + ', revisé ' + (url || '[empresa].cl') + ' y noté que ' + top.title.toLowerCase() + ', lo que puede estar afectando ' + liImpact.toLowerCase() + '.\n\n¿Le envío los detalles? Son 2 minutos de lectura sin compromiso.';
						var li2 = 'Hola ' + (contacto || '[Nombre]') + ', vuelvo sobre mi mensaje anterior.\n\nEl punto que detecté en ' + (empresa || '[empresa]') + ' puede parecer técnico, pero tiene un impacto directo en resultados: ' + liImpact.toLowerCase() + '.\n\n¿Tiene 15 minutos esta semana para que le muestre exactamente lo que encontramos?';
						role(instance.section, 'out-linkedin').textContent = li1;
						role(instance.section, 'out-linkedin2').textContent = li2;
						role(instance.section, 'char-li').textContent = li1.length + ' car.';
						role(instance.section, 'char-li2').textContent = li2.length + ' car.';
					}

					var waEmpty = role(instance.section, 'wa-empty');
					var waContent = role(instance.section, 'wa-content');
					if (!hasData || !top) {
						waEmpty.hidden = false;
						waContent.hidden = true;
					} else {
						waEmpty.hidden = true;
						waContent.hidden = false;
						var waImpact = top.impact.split('—')[0].trim();
						var wa1 = 'Hola ' + (contacto || '[Nombre]') + ', revisé el sitio de ' + (empresa || '[empresa]') + ' y encontré algo que puede estar afectando ' + waImpact.toLowerCase().substring(0, 80) + '.\n\n¿Le cuento?';
						var wa2 = (empresa || '[Empresa]') + '.cl tiene ' + top.title.toLowerCase() + '.\n\nEsto puede significar que ' + waImpact.toLowerCase() + '.\n\nHacemos un diagnóstico ejecutivo completo con hallazgos priorizados y plan de acción. ¿Le interesa saber más?';
						role(instance.section, 'out-wa').textContent = wa1;
						role(instance.section, 'out-wa2').textContent = wa2;
						role(instance.section, 'char-wa').textContent = wa1.length + ' car.';
						role(instance.section, 'char-wa2').textContent = wa2.length + ' car.';
					}

					var repEmpty = role(instance.section, 'rep-empty');
					var repContent = role(instance.section, 'rep-content');
					if (!hasData || total === 0) {
						repEmpty.hidden = false;
						repContent.hidden = true;
						setInlineMessage(role(instance.section, 'report-status'), '', '');
					} else {
						repEmpty.hidden = true;
						repContent.hidden = false;
						var reportDate = new Date().toLocaleDateString('es-CL', {day:'2-digit', month:'long', year:'numeric'});
						var findingsHtml = '';
						var allFindings = groups.critical.concat(groups.high, groups.medium).slice(0, 6);
						allFindings.forEach(function(item){
							findingsHtml += '<div class="twob-rev-mr-finding ' + item.sev + '"><div class="twob-rev-mr-dot ' + item.sev + '"></div><div><div class="twob-rev-mr-title">' + escapeHtml(item.title) + '</div><div class="twob-rev-mr-impact">' + escapeHtml(item.impact) + '</div></div></div>';
						});
						role(instance.section, 'mini-report-render').innerHTML = '' +
							'<div class="twob-rev-mini-report">' +
								'<div class="twob-rev-mr-header">' +
									'<div><div class="twob-rev-mr-logo">2B. Consulting</div><div class="twob-rev-mr-company">' + escapeHtml(empresa || '[Empresa]') + '</div><div class="twob-rev-mr-url">' + escapeHtml(url || '[url]') + '</div></div>' +
									'<div class="twob-rev-mr-date">' + escapeHtml(reportDate) + '</div>' +
								'</div>' +
								'<div class="twob-rev-mr-divider"></div>' +
								'<div class="twob-rev-mr-findings">' + findingsHtml + '</div>' +
								'<div class="twob-rev-mr-footer"><div class="twob-rev-mr-cta">→ Diagnóstico ejecutivo completo disponible en 5–7 días hábiles</div><div class="twob-rev-mr-brand">2bconsulting.cl</div></div>' +
							'</div>';
						var repText = 'DIAGNÓSTICO PREVIO — 2B Consulting\n' + (empresa || '[Empresa]') + ' · ' + (url || '') + ' · ' + reportDate + '\n\n';
						repText += 'RESUMEN: ' + groups.critical.length + ' críticos · ' + groups.high.length + ' altos · ' + groups.medium.length + ' medios.\n\n';
						allFindings.forEach(function(item){
							var icon = item.sev === 'critical' ? '🔴' : (item.sev === 'high' ? '🟠' : '🔵');
							repText += icon + ' ' + item.title + '\n   ' + item.impact + '\n\n';
						});
						repText += '→ Diagnóstico ejecutivo completo en 5–7 días hábiles · 2bconsulting.cl';
						role(instance.section, 'rep-text-hidden').textContent = repText;
					}

					if (instance.saveButton) {
						instance.saveButton.hidden = !(instance.leadId && total > 0);
					}
				}

				function copyOutput(instance, roleName, button){
					var node = role(instance.section, roleName);
					if (!node) { return; }
					var text = node.textContent || node.innerText || '';
					if (!navigator.clipboard || !text) { return; }
					var originalLabel = button.getAttribute('data-label') || button.textContent;
					button.setAttribute('data-label', originalLabel);
					navigator.clipboard.writeText(text).then(function(){
						button.textContent = '✓ Copiado';
						button.classList.add('is-ok');
						window.setTimeout(function(){
							button.textContent = originalLabel;
							button.classList.remove('is-ok');
						}, 1800);
					});
				}

				function downloadReportImage(instance, button){
					var target = role(instance.section, 'mini-report-render');
					var reportStatus = role(instance.section, 'report-status');
					var empresa = role(instance.section, 'empresa').value.trim() || 'empresa';
					var fecha = new Date().toISOString().slice(0, 10).replace(/-/g, '');
					if (!target || !target.children.length) {
						setInlineMessage(reportStatus, 'No hay mini reporte para descargar todavía.', 'error');
						return;
					}
					if (typeof html2canvas !== 'function') {
						setInlineMessage(reportStatus, 'No se pudo cargar html2canvas.', 'error');
						return;
					}
					var originalLabel = button.getAttribute('data-label') || button.textContent;
					button.setAttribute('data-label', originalLabel);
					button.disabled = true;
					button.textContent = 'Generando imagen...';
					button.classList.add('is-loading');
					setInlineMessage(reportStatus, 'Generando imagen...', '');
					html2canvas(target, {
						backgroundColor: null,
						scale: 2,
						useCORS: true,
						logging: false
					}).then(function(canvas){
						var link = document.createElement('a');
						link.download = '2B-diagnostico-' + safeFileName(empresa) + '-' + fecha + '.png';
						link.href = canvas.toDataURL('image/png');
						link.click();
						button.disabled = false;
						button.textContent = '✓ Descargada';
						button.classList.remove('is-loading');
						button.classList.add('is-ok');
						setInlineMessage(reportStatus, '✓ Imagen descargada — lista para adjuntar en WhatsApp', 'ok');
						window.setTimeout(function(){
							button.textContent = originalLabel;
							button.classList.remove('is-ok');
						}, 2500);
					}).catch(function(){
						button.disabled = false;
						button.textContent = originalLabel;
						button.classList.remove('is-loading');
						setInlineMessage(reportStatus, 'No se pudo generar la imagen. Intenta otra vez.', 'error');
					});
				}

				function applyAutoChecks(instance, autoChecks){
					reviewerChecks.forEach(function(category){
						category.items.forEach(function(item){
							if (Object.prototype.hasOwnProperty.call(autoChecks, item.id)) {
								setChecked(instance, item.id, !!autoChecks[item.id]);
							}
						});
					});
				}

				function openSite(instance){
					var urlField = role(instance.section, 'url');
					var cleanUrl = normalizeUrl(urlField.value);
					if (!cleanUrl) {
						window.alert('Ingresa la URL primero.');
						return;
					}
					urlField.value = cleanUrl;
					window.open(cleanUrl, '_blank');
					window.open('https://pagespeed.web.dev/analysis?url=' + encodeURIComponent(cleanUrl), '_blank');
				}

				function runScan(instance){
					var urlField = role(instance.section, 'url');
					var cleanUrl = normalizeUrl(urlField.value);
					if (!cleanUrl) {
						setInlineMessage(instance.scanStatus, 'Ingresa una URL válida antes de escanear.', 'error');
						return;
					}
					urlField.value = cleanUrl;
					setInlineMessage(instance.scanStatus, 'Escaneando... esto puede tomar 15–20 segundos.', 'loading');
					instance.scanButton.disabled = true;
					var body = new URLSearchParams();
					body.append('action', 'twob_scan_sitio');
					body.append('nonce', reviewerNonce);
					body.append('url', cleanUrl);
					sendAjax(body)
						.then(function(json){
							if (!json || !json.success) {
								setInlineMessage(instance.scanStatus, (json && json.data && json.data.message) ? json.data.message : 'No se pudo completar el escaneo automático. Verifica la URL e ingresa los datos manualmente.', 'error');
								instance.scanButton.disabled = false;
								return;
							}
							var data = json.data || {};
							role(instance.section, 'speed-mobile').value = data.speed_mobile ? String(data.speed_mobile) : '';
							role(instance.section, 'speed-desktop').value = data.speed_desktop ? String(data.speed_desktop) : '';
							instance.scanErrors = Array.isArray(data.errors) ? data.errors : [];
							instance.lastScanAt = Math.floor(Date.now() / 1000);
							applyAutoChecks(instance, data.auto_checks || {});
							updateReviewer(instance);
							var autoCount = 0;
							Object.keys(data.auto_checks || {}).forEach(function(key){
								if (data.auto_checks[key]) { autoCount += 1; }
							});
							var message = '✓ Escaneo completado. Se detectaron ' + autoCount + ' problemas automáticamente. Revisa visualmente los ítems manuales para completar.';
							if (instance.scanErrors.length) {
								message += ' Avisos: ' + instance.scanErrors.join(' | ');
							}
							setInlineMessage(instance.scanStatus, message, 'ok');
							var checklist = role(instance.section, 'checklist');
							if (checklist && checklist.scrollIntoView) {
								checklist.scrollIntoView({behavior:'smooth', block:'start'});
							}
							instance.scanButton.disabled = false;
						})
						.catch(function(){
							setInlineMessage(instance.scanStatus, 'No se pudo completar el escaneo automático. Verifica la URL e ingresa los datos manualmente.', 'error');
							instance.scanButton.disabled = false;
						});
				}

				function saveFinding(instance){
					var findingText = role(instance.section, 'out-dani').textContent || '';
					if (!findingText.trim()) {
						setInlineMessage(instance.saveStatus, 'Marca al menos un hallazgo antes de guardar.', 'error');
						return;
					}
					if (!instance.leadId) {
						setInlineMessage(instance.saveStatus, 'Este revisor solo puede guardar cuando está embebido en una ficha de lead.', 'error');
						return;
					}
					instance.saveButton.disabled = true;
					setInlineMessage(instance.saveStatus, 'Guardando hallazgos en el lead...', 'loading');
					var body = new URLSearchParams();
					body.append('action', 'twob_guardar_hallazgo');
					body.append('nonce', reviewerNonce);
					body.append('lead_id', String(instance.leadId));
					body.append('technical_finding', findingText);
					body.append('speed_mobile', role(instance.section, 'speed-mobile').value || '0');
					body.append('speed_desktop', role(instance.section, 'speed-desktop').value || '0');
					body.append('site_status', instance.currentStatusKey || 'ok');
					body.append('scan_timestamp', String(instance.lastScanAt || Math.floor(Date.now() / 1000)));
					body.append('critical_count', String(instance.latestCounts.critical || 0));
					body.append('high_count', String(instance.latestCounts.high || 0));
					body.append('medium_count', String(instance.latestCounts.medium || 0));
					body.append('auto_checks', JSON.stringify(instance.state));
					body.append('scan_errors', JSON.stringify(instance.scanErrors || []));
					sendAjax(body)
						.then(function(json){
							if (!json || !json.success) {
								setInlineMessage(instance.saveStatus, (json && json.data && json.data.message) ? json.data.message : 'No se pudo guardar el hallazgo en el lead.', 'error');
								instance.saveButton.disabled = false;
								return;
							}
							instance.lastScanAt = (json.data && json.data.scan_timestamp) ? parseInt(json.data.scan_timestamp, 10) : Math.floor(Date.now() / 1000);
							updateReviewer(instance);
							setInlineMessage(instance.saveStatus, '✓ Hallazgos guardados en el lead.', 'ok');
							updateLeadCardIndicators(instance, json.data && json.data.technical_finding ? json.data.technical_finding : findingText);
							instance.section.dispatchEvent(new CustomEvent('twob:finding-saved', {
								bubbles: true,
								detail: {
									leadId: instance.leadId,
									technicalFinding: json.data && json.data.technical_finding ? json.data.technical_finding : findingText
								}
							}));
							instance.saveButton.disabled = false;
						})
						.catch(function(){
							setInlineMessage(instance.saveStatus, 'No se pudo guardar el hallazgo en el lead.', 'error');
							instance.saveButton.disabled = false;
						});
				}

				function buildChecklist(instance){
					var html = '';
					reviewerChecks.forEach(function(category){
						html += '<div class="twob-rev-cat-label">' + escapeHtml(category.cat) + '</div>';
						category.items.forEach(function(item){
							html += '' +
								'<label class="twob-rev-check-item sev-' + item.sev + '" data-check-id="' + item.id + '">' +
									'<input type="checkbox" data-check-toggle="' + item.id + '">' +
									'<div class="twob-rev-check-content">' +
										'<div class="twob-rev-check-title">' + escapeHtml(item.title) + '</div>' +
										'<div class="twob-rev-check-impact">' + escapeHtml(item.impact) + '</div>' +
									'</div>' +
									'<div class="twob-rev-badges">' +
										'<span class="twob-rev-sev-tag is-' + item.sev + '">' + severityLabel(item.sev) + '</span>' +
										'<span class="twob-rev-mode-tag ' + (item.auto ? 'is-auto' : 'is-manual') + '">' + (item.auto ? 'Auto' : 'Manual') + '</span>' +
									'</div>' +
								'</label>';
							instance.state[item.id] = false;
						});
					});
					role(instance.section, 'checklist').innerHTML = html;
					instance.section.querySelectorAll('[data-check-id]').forEach(function(node){
						var id = node.getAttribute('data-check-id');
						var input = node.querySelector('input[type="checkbox"]');
						if (input) {
							input.addEventListener('click', function(event){ event.stopPropagation(); });
							input.addEventListener('change', function(){
								setChecked(instance, id, input.checked);
								updateReviewer(instance);
							});
						}
						node.addEventListener('click', function(event){
							if (event.target && event.target.tagName === 'INPUT') { return; }
							setChecked(instance, id, !instance.state[id]);
							updateReviewer(instance);
						});
					});
				}

				function activateTab(section, tabName){
					section.querySelectorAll('[data-rev-tab]').forEach(function(button){
						button.classList.toggle('is-active', button.getAttribute('data-rev-tab') === tabName);
					});
					section.querySelectorAll('[data-rev-panel]').forEach(function(panel){
						panel.classList.toggle('is-active', panel.getAttribute('data-rev-panel') === tabName);
					});
				}

				function initReviewer(section){
					if (!section || section.getAttribute('data-review-ready') === '1') { return; }
					section.setAttribute('data-review-ready', '1');
					var instance = {
						section: section,
						block: section.closest('.twob-site-review-block'),
						leadCard: section.closest('.twob-lead-accordion'),
						leadId: parseInt(section.getAttribute('data-lead-id') || '0', 10) || 0,
						state: {},
						latestCounts: {critical:0, high:0, medium:0},
						currentStatusKey: section.getAttribute('data-status') || 'ok',
						currentStatusLabel: '🟢 OK',
						currentStatusDescription: '',
						lastScanAt: parseInt(section.getAttribute('data-scan-timestamp') || '0', 10) || 0,
						scanErrors: readJson(section.getAttribute('data-scan-errors'))
					};
					instance.scanStatus = role(section, 'scan-status');
					instance.saveStatus = role(section, 'save-status');
					instance.reportStatus = role(section, 'report-status');
					instance.scanButton = section.querySelector('[data-rev-action="scan"]');
					instance.saveButton = section.querySelector('[data-rev-action="save"]');

					buildChecklist(instance);
					role(section, 'empresa').value = section.getAttribute('data-company') || '';
					role(section, 'contacto').value = section.getAttribute('data-contact') || '';
					role(section, 'url').value = section.getAttribute('data-url') || '';
					role(section, 'speed-mobile').value = section.getAttribute('data-speed-mobile') || '';
					role(section, 'speed-desktop').value = section.getAttribute('data-speed-desktop') || '';
					applyAutoChecks(instance, readJson(section.getAttribute('data-saved-checks')));

					['empresa', 'contacto', 'url'].forEach(function(name){
						var field = role(section, name);
						if (field) {
							field.addEventListener('input', function(){ updateReviewer(instance); });
						}
					});
					['speed-mobile', 'speed-desktop'].forEach(function(name){
						var field = role(section, name);
						if (field) {
							field.addEventListener('input', function(){ updateReviewer(instance); });
						}
					});
					section.querySelectorAll('[data-rev-copy]').forEach(function(button){
						button.addEventListener('click', function(){
							copyOutput(instance, button.getAttribute('data-rev-copy'), button);
						});
					});
					section.querySelectorAll('[data-rev-tab]').forEach(function(button){
						button.addEventListener('click', function(){
							activateTab(section, button.getAttribute('data-rev-tab'));
						});
					});
					var openButton = section.querySelector('[data-rev-action="open-site"]');
					if (openButton) {
						openButton.addEventListener('click', function(){ openSite(instance); });
					}
					if (instance.scanButton) {
						instance.scanButton.addEventListener('click', function(){ runScan(instance); });
					}
					if (instance.saveButton) {
						instance.saveButton.addEventListener('click', function(){ saveFinding(instance); });
					}
					var imageButton = section.querySelector('[data-rev-action="download-image"]');
					if (imageButton) {
						imageButton.addEventListener('click', function(){ downloadReportImage(instance, imageButton); });
					}
					var resetButton = section.querySelector('.twob-rev-reset');
					if (resetButton) {
						resetButton.addEventListener('click', function(){
							role(section, 'empresa').value = section.getAttribute('data-company') || '';
							role(section, 'contacto').value = section.getAttribute('data-contact') || '';
							role(section, 'url').value = section.getAttribute('data-url') || '';
							role(section, 'speed-mobile').value = '';
							role(section, 'speed-desktop').value = '';
							Object.keys(instance.state).forEach(function(key){ setChecked(instance, key, false); });
							instance.scanErrors = [];
							setInlineMessage(instance.scanStatus, '', '');
							setInlineMessage(instance.saveStatus, '', '');
							setInlineMessage(instance.reportStatus, '', '');
							updateReviewer(instance);
						});
					}
					updateReviewer(instance);
					if (Array.isArray(instance.scanErrors) && instance.scanErrors.length) {
						setInlineMessage(instance.scanStatus, 'Último escaneo con avisos: ' + instance.scanErrors.join(' | '), 'error');
					}
				}

				document.querySelectorAll('.twob-site-review-open').forEach(function(button){
					button.addEventListener('click', function(){
						var targetId = button.getAttribute('data-review-target');
						if (!targetId) { return; }
						var details = document.getElementById(targetId);
						if (!details) { return; }
						details.open = true;
						if (details.scrollIntoView) {
							details.scrollIntoView({behavior:'smooth', block:'start'});
						}
					});
				});

				document.querySelectorAll('.twob-site-review').forEach(function(section){
					initReviewer(section);
				});

				var verifyButton = document.getElementById('twob_verify_pagespeed_key');
				var verifyStatus = document.getElementById('twob_pagespeed_key_status');
				var verifyInput = document.getElementById('twob_pagespeed_api_key');
				if (verifyButton && verifyInput && verifyStatus) {
					verifyButton.addEventListener('click', function(){
						var body = new URLSearchParams();
						body.append('action', 'twob_verify_pagespeed_key');
						body.append('nonce', reviewerNonce);
						body.append('api_key', verifyInput.value || '');
						verifyButton.disabled = true;
						verifyStatus.textContent = 'Verificando API key con PageSpeed...';
						sendAjax(body)
							.then(function(json){
								if (!json || !json.success) {
									verifyStatus.textContent = (json && json.data && json.data.message) ? json.data.message : 'No se pudo verificar la API key.';
									verifyButton.disabled = false;
									return;
								}
								verifyStatus.textContent = (json.data && json.data.message) ? json.data.message : 'API key verificada correctamente.';
								verifyButton.disabled = false;
							})
							.catch(function(){
								verifyStatus.textContent = 'No se pudo verificar la API key.';
								verifyButton.disabled = false;
							});
					});
				}
			})();
		</script>
		<?php
	}

	public static function admin_styles() {
		$screen = function_exists('get_current_screen') ? get_current_screen() : null;
		$screen_id = $screen ? (string) $screen->id : '';
		if (! $screen || (false === strpos($screen_id, 'twob-crm-visual') && false === strpos($screen_id, 'twob-crm-buscador'))) {
			return;
		}
		?>
			<style>
				:root{
					--twob-bg:#f4f6fb;
					--twob-ink:#0f172a;
				--twob-muted:#64748b;
				--twob-card:#ffffff;
				--twob-border:#d9e0ea;
				--twob-side:#16172f;
					--twob-side-soft:#212347;
					--twob-accent:#f6b425;
					--twob-accent-strong:#f59e0b;
					--twob-shadow:0 10px 30px rgba(15,23,42,.08);
				}
				body.wp-admin.twob-crm-focus #adminmenumain{display:none}
				body.wp-admin.twob-crm-focus #wpcontent,body.wp-admin.twob-crm-focus #wpfooter{margin-left:0}
				body.wp-admin.twob-crm-focus #wpbody-content{padding-bottom:24px}
				body.wp-admin{background:var(--twob-bg)}
				.twob-crm-visual{max-width:1600px}
				.twob-crm-visual.twob-shell-ready{display:grid;grid-template-columns:240px 1fr;gap:18px;align-items:start}
				.twob-main{min-width:0}
			.twob-page h1,.twob-main h1{margin:0 0 4px;font-size:28px;line-height:1.2;color:var(--twob-ink);letter-spacing:-.02em}
			.twob-page h2,.twob-main h2,.twob-main h3,.twob-main h4{color:var(--twob-ink);letter-spacing:-.01em}
			.twob-muted{color:var(--twob-muted);margin:0 0 14px}
			.twob-sidebar{position:sticky;top:56px;background:linear-gradient(180deg,var(--twob-side) 0%,#1a1c3a 100%);border-radius:16px;padding:14px;box-shadow:var(--twob-shadow)}
				.twob-brand{color:#fff;font-size:14px;font-weight:700;padding:4px 6px 10px}
				.twob-brand small{display:block;font-size:11px;color:#a5b4fc;font-weight:500;opacity:.95}
				.twob-exit-link{display:inline-flex;align-items:center;gap:6px;margin-top:14px;color:#c7d2fe;text-decoration:none;font-size:11px;font-weight:700;opacity:.92}
				.twob-exit-link:hover{color:#fff;opacity:1}
				.twob-nav{display:grid;gap:6px}
				.twob-nav a{color:#dbe4ff;text-decoration:none;padding:9px 11px;border-radius:10px;font-size:12px;font-weight:600;border:1px solid transparent;background:transparent;transition:.2s}
			.twob-nav a:hover{background:var(--twob-side-soft);border-color:#3c3f73;color:#fff}
			.twob-nav a.is-active{background:var(--twob-accent);color:#221802;border-color:#f1b233;box-shadow:inset 0 0 0 1px rgba(255,255,255,.18)}
			.twob-grid{display:grid;gap:14px;margin:14px 0}
			.twob-grid-1{grid-template-columns:1fr}
			.twob-grid-2{grid-template-columns:minmax(0,2fr) minmax(0,1fr)}
			.twob-grid-3{grid-template-columns:repeat(3,minmax(0,1fr))}
			.twob-grid-4{grid-template-columns:repeat(4,minmax(0,1fr))}
			.twob-grid-5{grid-template-columns:repeat(5,minmax(0,1fr))}
			.twob-grid-6{grid-template-columns:repeat(6,minmax(0,1fr))}
			.twob-col-span-2{grid-column:span 2}
			.twob-card{background:var(--twob-card);border:1px solid var(--twob-border);border-radius:14px;padding:14px 15px;box-shadow:0 2px 0 rgba(255,255,255,.5),0 8px 24px rgba(15,23,42,.04);transition:border-color .2s,box-shadow .2s}
			.twob-card:hover{border-color:#bfd0e6;box-shadow:0 8px 22px rgba(15,23,42,.08)}
			.twob-card h2,.twob-card h3,.twob-card h4{margin:0 0 8px}
			.twob-alert{padding:11px 12px;border-radius:12px;margin:12px 0;font-weight:600}
			.twob-alert.ok{background:#edfdf4;border:1px solid #b9f0cf;color:#155e34}
			.twob-progress-item{margin:10px 0}
			.twob-progress-item>div:first-child{display:flex;justify-content:space-between;font-size:12px;color:var(--twob-ink)}
			.twob-bar{height:10px;background:#e9edf4;border-radius:20px;overflow:hidden}
			.twob-bar i{display:block;height:100%}
			.twob-bar .good{background:#16a34a}
			.twob-bar .mid{background:#f59e0b}
			.twob-bar .bad{background:#ef4444}
				.twob-pipeline{display:grid;grid-template-columns:repeat(var(--twob-pipeline-columns,8),minmax(280px,1fr));gap:14px;overflow-x:auto;overflow-y:hidden;align-items:start;padding-bottom:4px}
				.twob-column{background:#eef2f8;border:1px solid #d5deea;border-radius:12px;padding:10px;min-width:0;display:flex;flex-direction:column;gap:10px}
				.twob-column>*{min-width:0}
				.twob-column-title{font-weight:700;font-size:12px;line-height:1.3;margin-bottom:0;color:#1e293b}
				.twob-lead{background:#fff;border:1px solid #dbe3ef;border-radius:10px;padding:10px;margin:0;display:flex;flex-direction:column;gap:7px;min-width:0;overflow:hidden}
				.twob-pipeline-lead-title,.twob-pipeline-lead-meta{display:block;overflow-wrap:anywhere;word-break:break-word}
				.twob-pipeline-actions{grid-template-columns:repeat(2,minmax(0,1fr));align-items:stretch}
				.twob-pipeline-actions>*{min-width:0}
				.twob-pipeline-actions .button,.twob-pipeline-actions button,.twob-pipeline-actions select{width:100%;max-width:100%;min-width:0;box-sizing:border-box}
				.twob-pipeline-actions .button,.twob-pipeline-actions button{display:flex;align-items:center;justify-content:center;min-height:40px;padding:8px 10px;line-height:1.2;text-align:center;white-space:normal}
				.twob-pipeline-actions select{grid-column:1/-1;padding-right:34px;background:#fff;white-space:normal}
				.twob-draggable{cursor:grab}
				.twob-draggable.is-dragging{opacity:.6}
				.twob-dropzone.drag-over{outline:2px dashed #3b82f6;outline-offset:-2px;background:#dbeafe}
				.twob-actions{display:grid;grid-template-columns:1fr 1fr;gap:6px}
			.twob-actions-3{grid-template-columns:repeat(3,minmax(120px,1fr))}
			.twob-actions select{grid-column:1/-1}
			.twob-empty{opacity:.72;font-size:12px;color:var(--twob-muted)}
			.twob-empty-card{padding:26px;border:1px dashed #c8d3e4;border-radius:12px;background:#f8fafe;color:#64748b}
			.twob-error-box{background:#fff2f2;border:1px solid #ffc9cf;padding:8px 10px;border-radius:9px;color:#9f1239}
			.twob-form-row{margin:8px 0}
			.twob-form-row label{display:block;font-size:12px;color:#475569;margin-bottom:4px;font-weight:600}
			.twob-form-row input:not([type="checkbox"]):not([type="radio"]),.twob-form-row select,.twob-form-row textarea,textarea,input[type="number"],input[type="text"],input[type="url"],input[type="email"],input[type="date"],input[type="time"]{width:100%;padding:9px 10px;border:1px solid #d5ddeb;border-radius:10px;box-sizing:border-box;background:#fff;color:#0f172a}
			.twob-form-row input:not([type="checkbox"]):not([type="radio"]):focus,.twob-form-row select:focus,.twob-form-row textarea:focus,textarea:focus,input[type="number"]:focus,input[type="text"]:focus,input[type="url"]:focus,input[type="email"]:focus,input[type="date"]:focus,input[type="time"]:focus{border-color:#60a5fa;box-shadow:0 0 0 3px rgba(59,130,246,.14);outline:none}
			.twob-form-row textarea{min-height:76px;resize:vertical}
			.twob-form-help{display:block;margin-top:6px;font-size:11px;color:#64748b}
			.twob-lost-reason-summary{padding:12px 14px;border:1px solid #fde68a;border-radius:14px;background:linear-gradient(180deg,#fffdf5 0%,#ffffff 100%)}
			.twob-lost-reason-display{padding:10px 12px;border-radius:12px;border:1px dashed #f59e0b;background:#fffbeb;color:#92400e;font-size:13px;line-height:1.6;white-space:pre-wrap}
			.twob-lost-reason-actions{display:flex;align-items:center;gap:10px;flex-wrap:wrap;margin-top:10px}
			.twob-inline-lock{display:flex;align-items:center;min-height:44px;padding:0 12px;border:1px solid #d5ddeb;border-radius:10px;background:#f8fafc;color:#0f172a;font-weight:700;letter-spacing:.02em}
			.twob-helper-box{margin:0 0 12px;padding:12px 14px;border:1px solid #dbe4f0;border-radius:12px;background:#f8fbff;display:grid;gap:4px}
			.twob-helper-box strong{font-size:13px;color:#0f172a}
			.twob-helper-box span{font-size:12px;color:#475569}
			.twob-screen-hero{display:grid;grid-template-columns:minmax(0,1.45fr) minmax(280px,.95fr);gap:18px;padding:22px 24px;border:1px solid #ece7ff;border-radius:24px;background:linear-gradient(135deg,#fffdf7 0%,#ffffff 58%,#faf7ff 100%);box-shadow:0 18px 40px rgba(15,23,42,.05);margin:14px 0 18px}
			.twob-screen-hero-copy{display:grid;gap:10px;align-content:start}
			.twob-screen-kicker{display:inline-flex;width:max-content;padding:6px 10px;border-radius:999px;background:#fff7ed;border:1px solid #fed7aa;color:#9a3412;font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.05em}
			.twob-screen-hero-copy h2{margin:0;font-size:34px;line-height:1.06;letter-spacing:-.04em;color:#111827}
			.twob-screen-hero-copy p{margin:0;font-size:15px;line-height:1.65;color:#475569;max-width:70ch}
			.twob-screen-hero-side{display:grid;gap:14px;align-content:start}
			.twob-hero-metrics{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}
			.twob-hero-metric{padding:14px 14px 12px;border-radius:18px;background:rgba(255,255,255,.94);border:1px solid #ece9ff;box-shadow:0 10px 22px rgba(15,23,42,.04)}
			.twob-hero-metric small{display:block;margin-bottom:5px;font-size:11px;color:#7c3aed;font-weight:800;text-transform:uppercase;letter-spacing:.04em}
			.twob-hero-metric strong{display:block;font-size:22px;line-height:1.1;color:#111827;word-break:break-word}
			.twob-screen-steps{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:12px;margin-top:2px}
			.twob-screen-step{display:grid;grid-template-columns:38px 1fr;gap:10px;align-items:start;padding:12px;border-radius:16px;background:#fff;border:1px solid #edf0f7}
			.twob-screen-step strong{display:flex;align-items:center;justify-content:center;width:38px;height:38px;border-radius:999px;background:linear-gradient(135deg,#7c3aed 0%,#4f46e5 100%);color:#fff;font-size:16px}
			.twob-screen-step span{font-size:13px;line-height:1.45;color:#334155}
			.twob-tip-box{display:grid;gap:6px;padding:14px;border-radius:18px;background:linear-gradient(135deg,#f7f2ff 0%,#eef4ff 100%);border:1px solid #e4dcff}
			.twob-tip-box strong{font-size:14px;color:#111827}
			.twob-tip-box span{font-size:12px;line-height:1.55;color:#5b6476}
			.twob-flow-strip{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:10px}
			.twob-flow-strip-compact .twob-flow-mini{min-height:96px}
			.twob-flow-mini{display:grid;gap:6px;padding:12px;border-radius:18px;background:#fff;border:1px solid #e8edf7;box-shadow:0 8px 18px rgba(15,23,42,.03)}
			.twob-flow-mini span{font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.04em;color:#3156d3}
			.twob-flow-mini strong{font-size:14px;line-height:1.35;color:#111827}
			.twob-danger-soft{background:linear-gradient(180deg,#fff7f7 0%,#ffffff 100%);border-color:#fecaca}
			.twob-danger-soft span{color:#b91c1c}
			.twob-checkbox-row label{display:flex;align-items:flex-start;gap:10px;margin-bottom:0;font-size:13px;color:#0f172a;cursor:pointer}
			.twob-checkbox-row input[type="checkbox"]{width:18px;height:18px;margin:2px 0 0;flex:0 0 auto;accent-color:#1d4ed8}
			.twob-checkbox-copy{display:grid;gap:2px}
				.twob-checkbox-copy strong{font-size:13px;color:#0f172a}
				.twob-checkbox-copy small{font-size:12px;color:#64748b;font-weight:500}
				.twob-focus-card{background:linear-gradient(180deg,#fffef6 0%,#ffffff 100%);border-color:#f8df95}
				.twob-focus-steps{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:10px}
				.twob-focus-step{display:grid;grid-template-columns:36px 1fr;gap:10px;align-items:start;padding:12px;border:1px solid #e7ecf4;border-radius:12px;background:#fff}
				.twob-focus-step strong{display:flex;align-items:center;justify-content:center;width:36px;height:36px;border-radius:999px;background:#1d4ed8;color:#fff;font-size:16px}
				.twob-focus-step span{font-size:13px;color:#334155;line-height:1.45}
				.twob-section-meta{display:flex;justify-content:space-between;gap:10px;align-items:center;flex-wrap:wrap;margin:10px 0 12px}
				.twob-section-count{font-size:12px;font-weight:700;color:#475569}
				.twob-section-pager{display:flex;align-items:center;gap:8px;flex-wrap:wrap}
				.twob-section-page{font-size:12px;color:#64748b;font-weight:700}
				.twob-stage-guide{margin:10px 0}
				.twob-stage-guide summary{cursor:pointer;list-style:none;padding:8px 10px;border:1px solid #cdd8ea;border-radius:10px;background:#f2f6ff;font-size:12px;font-weight:700;color:#1e3a8a;user-select:none}
			.twob-stage-guide summary::-webkit-details-marker{display:none}
			.twob-stage-guide[open] summary{border-bottom-left-radius:0;border-bottom-right-radius:0}
			.twob-stage-legend{margin:0;padding:8px 10px;border:1px solid #d9e2ef;border-top:none;border-bottom-left-radius:10px;border-bottom-right-radius:10px;background:#f8fafe;font-size:12px;color:#475569;display:grid;gap:4px}
			.twob-compact-grid .twob-form-row{margin:4px 0}
			.twob-stage-filter{display:flex;flex-wrap:wrap;gap:6px;margin:10px 0 4px}
			.twob-leads-grid{display:grid;grid-template-columns:repeat(2,minmax(320px,1fr));gap:12px}
			.twob-leads-list{display:flex;flex-direction:column;gap:12px;margin-top:12px}
			.twob-leads-toolbar{background:#fff;border:1px solid #dbe4f0;border-radius:16px;padding:14px 16px;margin:12px 0;box-shadow:0 8px 24px rgba(15,23,42,.04)}
			.twob-leads-toolbar-row{display:grid;grid-template-columns:minmax(180px,1.4fr) repeat(8,minmax(110px,1fr)) auto;gap:10px;align-items:end}
			.twob-leads-toolbar-summary{margin-top:10px;font-size:12px;color:#64748b}
			.twob-leads-workspace{position:relative;display:grid;grid-template-columns:minmax(0,1fr);gap:0;margin-top:12px;min-height:420px}
			.twob-leads-workspace.has-drawer-open{grid-template-columns:minmax(0,1fr)}
			.twob-leads-main{min-width:0;background:#fff;border:1px solid #dbe4f0;border-radius:16px;overflow:auto;max-height:calc(100vh - 220px)}
			.twob-leads-table{width:100%;border-collapse:collapse;font-size:13px}
			.twob-leads-table thead th{position:sticky;top:0;background:#f8fafc;border-bottom:1px solid #e2e8f0;padding:10px 12px;text-align:left;font-size:11px;text-transform:uppercase;letter-spacing:.04em;color:#64748b;z-index:1}
			.twob-lead-row{cursor:pointer;transition:background .15s ease}
			.twob-lead-row:hover,.twob-lead-row.is-selected{background:#eef4ff}
			.twob-lead-row td{padding:10px 12px;border-bottom:1px solid #f1f5f9;vertical-align:middle}
			.twob-lead-row-name strong{display:block;color:#0f172a}
			.twob-lead-row-sub{display:block;font-size:12px;color:#64748b;margin-top:2px}
			.twob-lead-drawer{position:fixed;left:50%;top:50%;right:auto;bottom:auto;transform:translate(-50%,-50%);width:min(1140px,calc(100vw - 96px));height:min(82vh,860px);max-height:min(82vh,860px);align-self:start;background:#fff;border:1px solid #dbe4f0;border-radius:28px;box-shadow:0 28px 90px rgba(15,23,42,.16);display:flex;flex-direction:column;overflow:hidden;z-index:9999}
			.twob-lead-drawer[aria-hidden="true"]{display:none}
			.twob-leads-workspace.has-drawer-open .twob-lead-drawer{display:flex}
			.twob-lead-drawer-head{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:18px 24px;border-bottom:1px solid #e2e8f0;background:linear-gradient(180deg,#f8fafc 0%,#fff 100%)}
			.twob-lead-drawer-title{font-size:28px;font-weight:800;color:#0f172a;letter-spacing:-.035em;line-height:1.05}
			.twob-lead-drawer-body{overflow-y:auto;overflow-x:hidden;padding:18px 24px 24px;flex:1 1 auto;min-height:0;overscroll-behavior:contain;-webkit-overflow-scrolling:touch}
			.twob-lead-drawer-backdrop{position:fixed;inset:0;background:rgba(15,23,42,.16);backdrop-filter:blur(2px);z-index:9998}
			.twob-lead-drawer-backdrop[hidden]{display:none}
			.twob-lead-panel-tabs{position:sticky;top:-18px;z-index:5;display:flex;gap:8px;flex-wrap:wrap;margin:0 -4px 16px;padding:8px 4px 12px;border-bottom:1px solid #e2e8f0;background:linear-gradient(180deg,#ffffff 0%,rgba(255,255,255,.98) 100%)}
			.twob-lead-panel-tab{border:1px solid transparent;background:transparent;border-radius:999px;padding:9px 16px;font-size:13px;font-weight:800;color:#64748b;cursor:pointer}
			.twob-lead-panel-tab.is-active{background:#eef4ff;border-color:#c6dafc;color:#1d4ed8}
			.twob-lead-panel-section{display:none}
			.twob-lead-panel-section.is-active{display:block}
			.twob-lead-panel .twob-grid.twob-grid-3{gap:14px}
			.twob-lead-panel .twob-form-row label{font-size:12px;font-weight:700;color:#334155;margin-bottom:6px}
			.twob-lead-panel .twob-form-row input:not([type="checkbox"]):not([type="radio"]),.twob-lead-panel .twob-form-row select,.twob-lead-panel .twob-form-row textarea{min-height:48px;font-size:15px;border-radius:14px}
			.twob-lead-panel .twob-form-row textarea{min-height:110px}
			.twob-lead-panel .twob-actions{display:flex;flex-wrap:wrap;gap:10px;margin-top:18px}
			.twob-lead-panel .twob-actions .button{display:inline-flex;align-items:center;justify-content:center;min-height:40px;padding:0 16px;font-size:13px;font-weight:700;border-radius:12px;line-height:1.2;flex:0 1 auto;min-width:148px;max-width:220px}
			.twob-lead-panel .twob-actions .twob-danger{min-width:200px}
			@media (max-width:1280px){
				.twob-leads-toolbar-row{grid-template-columns:repeat(3,minmax(0,1fr))}
				.twob-leads-workspace.has-drawer-open{grid-template-columns:1fr}
				.twob-lead-drawer{width:min(1040px,calc(100vw - 48px));height:min(84vh,820px);max-height:min(84vh,820px);border-radius:24px}
			}
			.twob-lead-editor{border-left:4px solid #3b82f6;background:linear-gradient(180deg,#ffffff 0%,#f6faff 100%)}
			.twob-lead-editor .twob-lead-header{display:flex;justify-content:space-between;gap:8px;align-items:center;margin-bottom:6px}
			.twob-lead-accordion{padding:10px 12px}
			.twob-lead-compact-header{margin:0}
			.twob-lead-compact-main strong{display:block;font-size:14px;color:#0f172a}
			.twob-lead-compact-meta{display:flex;align-items:center;gap:8px;flex-wrap:wrap;justify-content:flex-end}
			.twob-lead-details{display:none;margin-top:10px;padding-top:10px;border-top:1px solid #dbe4ef}
			.twob-lead-accordion.is-open .twob-lead-details{display:block}
			.twob-badge,.twob-badge-stage,.twob-badge-payment{display:inline-block;padding:3px 9px;border-radius:999px;font-size:11px;font-weight:700;background:#eef2ff;color:#3730a3}
			.twob-badge-stage-pre_contact{background:#e5e7eb;color:#374151}
			.twob-badge-stage-new{background:#e2e8f0;color:#334155}
			.twob-badge-stage-contacted{background:#dbeafe;color:#1d4ed8}
			.twob-badge-stage-responded_interested{background:#fef3c7;color:#92400e}
			.twob-badge-stage-meeting_scheduled{background:#ffedd5;color:#9a3412}
			.twob-badge-stage-meeting_done{background:#fce7f3;color:#9d174d}
			.twob-badge-stage-proposal_sent{background:#ede9fe;color:#5b21b6}
			.twob-badge-stage-won{background:#dcfce7;color:#166534}
			.twob-badge-stage-lost{background:#fee2e2;color:#b91c1c}
			.twob-badge-payment-pending{background:#fef3c7;color:#92400e}
			.twob-badge-payment-paid{background:#dcfce7;color:#166534}
			.twob-badge-payment-overdue{background:#fee2e2;color:#b91c1c}
			.twob-timeline{display:flex;flex-direction:column;gap:8px;max-height:620px;overflow:auto;padding-right:4px}
			.twob-timeline-item{border:1px solid #dde5f0;border-radius:10px;padding:10px;background:#f8fafc}
			.twob-line-1{display:flex;justify-content:space-between;gap:8px}
			.twob-line-2{font-size:12px;color:var(--twob-muted)}
			.twob-task-item{background:#fff;border:1px solid #dbe4f0;border-radius:10px;padding:11px;margin:0 0 10px}
			.twob-task-item small{display:block;color:var(--twob-muted)}
			.twob-task-label{display:flex;gap:10px;align-items:flex-start;cursor:pointer}
			.twob-task-label input{margin-top:3px}
			.twob-task-actions{display:flex;gap:8px;align-items:center;flex-wrap:wrap;margin-top:8px;margin-left:0}
			.twob-dashboard-focus{display:grid;gap:14px;margin:14px 0}
			.twob-dashboard-hero{background:linear-gradient(135deg,#f6fbff 0%,#eef4ff 100%);border-color:#cfe0ff}
			.twob-dashboard-hero-top{display:flex;justify-content:space-between;gap:14px;align-items:flex-start}
			.twob-dashboard-hero-top h2{margin:0 0 6px;font-size:26px;line-height:1.1}
			.twob-dashboard-counters{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px;margin-top:12px}
			.twob-dashboard-counter{background:#fff;border:1px solid #dbe4f0;border-radius:14px;padding:12px}
			.twob-dashboard-counter small{display:block;color:var(--twob-muted);font-size:12px;margin-bottom:4px}
			.twob-dashboard-counter strong{display:block;color:#0f172a;font-size:24px;line-height:1.1}
			.twob-dashboard-counter.is-danger{background:#fff4f4;border-color:#fecaca}
			.twob-dashboard-counter.is-warning{background:#fff8eb;border-color:#fcd34d}
				.twob-dashboard-board{display:grid;gap:10px}
				.twob-priority-banner{background:linear-gradient(135deg,#fff8ea 0%,#fffdf8 55%,#f6f9ff 100%);border:1px solid #f3d28b;border-radius:20px;padding:18px 20px;display:grid;gap:14px;align-items:start;box-shadow:0 10px 28px rgba(15,23,42,.05)}
				.twob-priority-copy{display:grid;gap:8px;max-width:70ch}
				.twob-priority-kicker{display:inline-flex;align-items:center;justify-content:center;width:max-content;padding:5px 9px;border-radius:999px;background:#fff;color:#9a3412;font-size:10px;font-weight:800;letter-spacing:.05em;text-transform:uppercase;border:1px solid #fed7aa}
				.twob-priority-title{margin:0;font-size:18px;line-height:1.15;color:#0f172a;letter-spacing:-.025em}
				.twob-priority-text{margin:0;color:#475569;font-size:13px;line-height:1.55;max-width:62ch}
				.twob-priority-steps{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:10px}
