				.twob-priority-step-number{display:flex;align-items:center;justify-content:center;width:34px;height:34px;border-radius:999px;background:#3156d3;color:#fff;font-size:14px;font-weight:800}
				.twob-priority-step-copy{display:grid;gap:2px}
