			.twob-dashboard-task-pills,.twob-dashboard-task-meta{display:flex;flex-wrap:wrap;gap:6px}
			.twob-pill{display:inline-flex;align-items:center;justify-content:center;padding:4px 8px;border-radius:999px;font-size:11px;font-weight:700}
			.twob-pill.is-soft{background:#eef2ff;color:#334155}
			.twob-pill.is-danger{background:#fee2e2;color:#b91c1c}
			.twob-pill.is-warning{background:#fff3cd;color:#9a3412}
			.twob-pill.is-cool{background:#eef4ff;color:#3156d3}
			.twob-pill.is-watch{background:#fef9c3;color:#854d0e}
			.twob-pill.is-ready{background:#dcfce7;color:#166534}
			.twob-pill-operational{border:1px solid transparent}
			.twob-pill-operational-pre_contact{background:#e2e8f0;color:#334155;border-color:#cbd5e1}
			.twob-pill-operational-new{background:#dcfce7;color:#166534;border-color:#86efac}
			.twob-pill-operational-contacted{background:#fef3c7;color:#92400e;border-color:#fcd34d}
			.twob-pill-operational-followup{background:#fff3cd;color:#9a3412;border-color:#facc15}
			.twob-pill-operational-interested{background:#dbeafe;color:#1d4ed8;border-color:#93c5fd}
			.twob-pill-operational-archive{background:#e5e7eb;color:#475569;border-color:#cbd5e1}
			.twob-ops-toolbar{display:flex;gap:8px;flex-wrap:wrap;margin:12px 0 14px}
				.twob-ops-grid{grid-template-columns:1fr;align-items:start}
				.twob-ops-block{display:grid;gap:12px}
				.twob-ops-block.is-new{background:linear-gradient(180deg,#f3fff6 0%,#ffffff 100%);border-color:#bde7c8}
				.twob-ops-block.is-today{background:linear-gradient(180deg,#fffdf3 0%,#ffffff 100%);border-color:#f8df95}
				.twob-ops-block.is-interested{background:linear-gradient(180deg,#f3f8ff 0%,#ffffff 100%);border-color:#c6dafc}
				.twob-ops-dashboard .twob-dashboard-board{display:grid;grid-template-columns:repeat(auto-fit,minmax(320px,1fr));gap:12px}
				.twob-ops-item{margin:0}
				.twob-ops-item-new{border-color:#86efac;background:#f7fff9}
				.twob-ops-item-interested{border-color:#93c5fd;background:#f8fbff}
			.twob-ops-footer{padding-top:2px}
			.twob-ops-footer a{font-size:12px;font-weight:700;color:#1d4ed8;text-decoration:none}
			.twob-ops-footer a:hover{text-decoration:underline}
			.twob-operational-new{border-left-color:#16a34a}
			.twob-operational-pre_contact{border-left-color:#64748b;background:linear-gradient(180deg,#fafafa 0%,#f4f4f5 100%)}
			.twob-operational-contacted{border-left-color:#f59e0b}
			.twob-operational-followup{border-left-color:#f97316}
			.twob-operational-interested{border-left-color:#2563eb}
			.twob-operational-archive{border-left-color:#94a3b8;background:linear-gradient(180deg,#fbfcfe 0%,#f6f8fb 100%)}
			.twob-archive-banner{background:linear-gradient(180deg,#f8fafc 0%,#eef2f7 100%);border-style:dashed}
			.twob-ops-rules{display:grid;gap:10px}
			.twob-ops-rule{display:grid;gap:3px;padding:10px 12px;border:1px solid #dbe4f0;border-radius:12px;background:#f8fafc}
			.twob-ops-rule strong{font-size:13px;color:#0f172a}
			.twob-ops-rule span{font-size:12px;color:#64748b}
			.twob-ops-pipeline{align-items:start}
			.twob-ops-column{background:#f8fafc}
			.twob-ops-column-title{display:flex;justify-content:space-between;gap:12px;align-items:flex-start}
			.twob-ops-column-new{background:linear-gradient(180deg,#f3fff6 0%,#eefcf3 100%);border-color:#bde7c8}
			.twob-ops-column-contacted{background:linear-gradient(180deg,#fff8e9 0%,#fffdf6 100%);border-color:#f8df95}
			.twob-ops-column-followup{background:linear-gradient(180deg,#fff7ed 0%,#fffdfa 100%);border-color:#f3c38d}
				.twob-ops-column-interested{background:linear-gradient(180deg,#f3f8ff 0%,#f8fbff 100%);border-color:#c6dafc}
				.twob-ops-column-archive{background:linear-gradient(180deg,#f1f5f9 0%,#f8fafc 100%);border-color:#cbd5e1}
				.twob-page-leads .twob-card,.twob-page-interactions .twob-card,.twob-page-tasks .twob-card{border-radius:22px;border-color:#e6ebfb;box-shadow:0 18px 42px rgba(40,53,120,.08)}
				.twob-page-leads .twob-card,.twob-page-interactions .twob-card,.twob-page-tasks .twob-card,.twob-page-leads .twob-screen-hero,.twob-page-interactions .twob-screen-hero,.twob-page-tasks .twob-screen-hero{background:linear-gradient(180deg,rgba(255,255,255,.98) 0%,rgba(248,250,255,.98) 100%)}
				.twob-page-leads .twob-main,.twob-page-interactions .twob-main,.twob-page-tasks .twob-main{display:grid;gap:20px}
				.twob-page-interactions .twob-grid.twob-grid-2{grid-template-columns:minmax(0,1.35fr) minmax(320px,.75fr);align-items:start}
			.twob-page-tasks .twob-focus-card,.twob-page-interactions .twob-helper-box,.twob-page-leads .twob-helper-box{background:linear-gradient(180deg,#fffdf6 0%,#ffffff 100%);border:1px solid #f5dfad}
			.twob-page-leads .twob-inline-lock{display:flex;align-items:center;min-height:44px;padding:0 14px;border-radius:14px;background:#eef5ff;border:1px solid #d6e3ff;color:#1e3a8a;font-weight:700}
			.twob-lead-mode-picker{display:grid;gap:10px;margin:0 0 14px}
			.twob-mode-toggle{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}
			.twob-mode-option{display:flex;align-items:flex-start;gap:10px;padding:12px 14px;border:1px solid #dbe4f0;border-radius:16px;background:#fff;cursor:pointer;transition:.2s}
			.twob-mode-option input{margin-top:3px}
