			.twob-mode-option strong{font-size:13px;color:#0f172a}
			.twob-mode-option small{font-size:12px;color:#64748b;line-height:1.45}
			.twob-mode-option.is-active{border-color:#c7d7ff;background:linear-gradient(180deg,#f7fbff 0%,#eef4ff 100%);box-shadow:0 10px 24px rgba(49,86,211,.08)}
			.twob-review-inline-row textarea{margin-top:6px}
			.twob-review-finding-flag{border:1px solid transparent}
			.twob-review-finding-flag.is-ready{background:#dcfce7;color:#166534;border-color:#86efac}
			.twob-review-finding-flag.is-warning{background:#fff7ed;color:#9a3412;border-color:#fdba74}
			.twob-review-finding-flag.is-soft{background:#eef2ff;color:#334155;border-color:#dbe4f0}
			.twob-dashboard-details{margin:14px 0;border:1px solid #d7e3f4;border-radius:14px;background:#f8fbff;overflow:hidden}
			.twob-dashboard-details summary{cursor:pointer;list-style:none;padding:14px 16px;font-weight:700;color:#0f172a;background:#eef4ff}
			.twob-dashboard-details summary::-webkit-details-marker{display:none}
			.twob-dashboard-details[open] summary{border-bottom:1px solid #d7e3f4}
			.twob-task-meeting-only{display:none}
			.twob-task-meeting-only.is-visible{display:block}
			.twob-task-done-row{display:flex;justify-content:space-between;align-items:center}
			.twob-inline-section{margin-top:14px;padding-top:12px;border-top:1px solid #dbe4ef;display:grid;gap:8px}
			.twob-mini-list{display:grid;gap:8px}
			.twob-activity-board{display:grid;gap:10px}
			.twob-activity-day{font-size:13px;font-weight:700;color:#0f172a;margin-top:4px}
			.twob-activity-meta{display:flex;flex-wrap:wrap;gap:6px;margin-top:8px}
			.twob-activity-counters{grid-template-columns:repeat(5,minmax(0,1fr))}
			.twob-search-results{display:flex;flex-wrap:wrap;gap:8px;margin-top:10px}
			.twob-detail-summary{cursor:pointer;list-style:none;display:flex;justify-content:space-between;gap:10px;align-items:flex-start}
			.twob-detail-summary::-webkit-details-marker{display:none}
			.twob-detail-body{margin-top:10px;padding-top:10px;border-top:1px solid #dde5f0;display:grid;gap:10px}
			.twob-interaction-detail[open],.twob-lead-history[open],.twob-related-detail[open]{background:#fff;border-color:#c9d6e8}
			.twob-note-box{background:#f8fafc;border:1px solid #dbe4f0;border-radius:10px;padding:10px;color:#334155;white-space:pre-wrap}
			.twob-context-card{display:grid;gap:10px}
			.twob-context-pill-row{display:flex;gap:6px;align-items:center;flex-wrap:wrap;justify-content:flex-end}
			.twob-context-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:8px}
			.twob-context-block{background:#f8fafc;border:1px solid #dbe4f0;border-radius:10px;padding:10px}
			.twob-context-block small{display:block;color:#64748b;font-size:11px;margin-bottom:3px}
			.twob-context-block strong{display:block;color:#0f172a;font-size:13px;line-height:1.35}
			.twob-profile-links{display:flex;gap:8px;flex-wrap:wrap;margin-top:10px}
			.twob-profile-link-button{display:inline-flex;align-items:center;justify-content:center;min-height:36px;padding:8px 14px;border-radius:12px;font-size:12px;font-weight:700;line-height:1.2}
			.twob-context-history .twob-detail-body{padding-top:0;border-top:none}
			.twob-related-detail{margin-top:10px;border:1px solid #dde5f0;border-radius:10px;padding:10px;background:#f8fafc}
			.twob-payments-list{display:flex;flex-direction:column;gap:8px}
			.twob-payment-row{border:1px solid #dbe3ef;border-radius:10px;padding:10px;display:flex;justify-content:space-between;gap:10px;align-items:center;background:#fff}
			.twob-payment-row small{display:block;color:var(--twob-muted)}
			.twob-payment-actions{display:flex;gap:6px;align-items:center;flex-wrap:wrap;justify-content:flex-end}
			.twob-calendar-grid{display:grid;grid-template-columns:repeat(7,minmax(120px,1fr));gap:8px}
			.twob-day{border:1px solid #dbe3ef;background:#fff;border-radius:10px;min-height:88px;padding:8px}
			.twob-day-num{font-weight:700;font-size:12px}
			.twob-dot{display:inline-block;width:8px;height:8px;border-radius:999px;margin-right:4px}
			.twob-dot-followup{background:#f59e0b}
			.twob-dot-task{background:#2563eb}
			.twob-dot-payment{background:#ef4444}
			.twob-dot-renewal{background:#06b6d4}
			.twob-chart{display:flex;align-items:flex-end;gap:6px;height:180px;padding:10px;border:1px solid #dbe3ef;border-radius:10px;background:#fff}
			.twob-chart-bar{flex:1;min-width:20px;background:#3b82f6;border-radius:6px 6px 0 0;position:relative}
			.twob-chart-bar span{position:absolute;bottom:100%;left:50%;transform:translateX(-50%);font-size:10px;color:#64748b;white-space:nowrap}
			.twob-chart-bar i{position:absolute;bottom:-18px;left:50%;transform:translateX(-50%);font-size:10px;color:#6b7280;font-style:normal}
			.twob-task-due{color:#64748b;font-size:12px;display:block;margin-top:6px}
			.twob-task-link{color:#1d4ed8;text-decoration:none;font-size:12px;font-weight:600}
			.twob-task-link:hover{text-decoration:underline}
			.twob-risk-counters{grid-template-columns:repeat(4,minmax(0,1fr))}
			.twob-risk-item,.twob-risk-preview{background:linear-gradient(180deg,#ffffff 0%,#f8fbff 100%)}
			.twob-modal-backdrop{position:fixed;inset:0;background:rgba(15,23,42,.45);display:none;align-items:center;justify-content:center;padding:18px;z-index:100000}
			.twob-modal-backdrop.is-open{display:flex}
			.twob-modal{width:min(760px,100%);max-height:calc(100vh - 40px);overflow:auto;background:#fff;border-radius:18px;border:1px solid #dbe4f0;box-shadow:0 30px 80px rgba(15,23,42,.28);padding:18px}
			.twob-modal-head{display:flex;justify-content:space-between;gap:12px;align-items:flex-start;margin-bottom:12px}
			.twob-modal-head h3{margin:0 0 4px}
			.twob-modal-close{border:none;background:#e2e8f0;color:#0f172a;border-radius:999px;width:34px;height:34px;font-size:18px;cursor:pointer}
			.twob-modal-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px}
			.twob-modal-grid .twob-col-span-2{grid-column:1 / -1}
			.twob-modal-footer{display:flex;justify-content:flex-end;gap:8px;flex-wrap:wrap;margin-top:14px}
			.twob-modal-hint{background:#f8fafc;border:1px solid #dbe4f0;border-radius:12px;padding:10px;color:#334155;font-size:12px}
			.twob-modal-context{display:grid;gap:10px;margin-top:10px;padding:12px 14px;border-radius:14px;background:#f8fbff;border:1px solid #dbe7fb}
			.twob-modal-context-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}
			.twob-modal-context-item{display:grid;gap:4px;padding:10px 12px;border-radius:12px;background:#fff;border:1px solid #e2e8f0}
			.twob-modal-context-item small,.twob-modal-context-history > small{font-size:11px;font-weight:800;letter-spacing:.04em;text-transform:uppercase;color:#64748b}
			.twob-modal-context-item strong{font-size:14px;line-height:1.45;color:#0f172a}
			.twob-modal-context-history{display:grid;gap:8px}
			.twob-modal-history-list{display:grid;gap:8px}
			.twob-modal-history-item{padding:10px 12px;border-radius:12px;background:#fff;border:1px solid #e2e8f0;color:#334155;font-size:12px;line-height:1.55}
			.twob-modal-history-item.is-empty{color:#64748b;font-style:italic}
			.twob-modal-status{display:none;margin:10px 0;padding:10px 12px;border-radius:12px;font-size:13px;font-weight:600}
			.twob-modal-status.is-error{display:block;background:#fff1f2;border:1px solid #fecdd3;color:#be123c}
			.twob-modal-status.is-ok{display:block;background:#edfdf4;border:1px solid #bbf7d0;color:#166534}
			.twob-crm-visual .button,.twob-crm-visual button{border-radius:9px!important;font-weight:600!important;transition:.2s}
			.twob-crm-visual .button-primary{background:#1d4ed8!important;border-color:#1e40af!important}
			.twob-crm-visual .button-primary:hover{background:#1e40af!important}
			.twob-success{background:#15803d!important;color:#fff!important;border-color:#166534!important}
			.twob-danger{background:#b91c1c!important;color:#fff!important;border-color:#991b1b!important}
			.twob-main .notice{border-radius:10px}
				.twob-modern-shell.twob-crm-visual.twob-shell-ready{grid-template-columns:280px minmax(0,1fr);gap:24px}
				.twob-modern-shell .twob-sidebar{position:sticky;top:48px;background:linear-gradient(180deg,#ffffff 0%,#fbf9ff 100%);border:1px solid #ebe5ff;border-radius:24px;padding:22px 18px;box-shadow:0 16px 46px rgba(109,52,255,.08)}
				.twob-modern-shell .twob-brand{color:#111827;font-size:28px;font-weight:800;letter-spacing:-.03em;padding:0 6px 16px}
				.twob-modern-shell .twob-brand small{display:block;margin-top:6px;font-size:12px;color:#7c3aed;font-weight:700;letter-spacing:0}
				.twob-modern-shell .twob-nav{gap:8px}
				.twob-modern-shell .twob-nav a{display:flex;align-items:center;min-height:44px;padding:11px 14px;border-radius:14px;font-size:14px;font-weight:700;color:#334155;background:transparent;border:1px solid transparent}
				.twob-modern-shell .twob-nav a:hover{background:#f5f3ff;border-color:#e9ddff;color:#111827}
				.twob-modern-shell .twob-nav a.is-active{background:linear-gradient(135deg,#7c3aed 0%,#4f46e5 100%);color:#fff;border-color:transparent;box-shadow:0 14px 28px rgba(79,70,229,.25)}
				.twob-modern-shell .twob-sidebar-section{display:grid;gap:10px;margin-top:18px;padding-top:18px;border-top:1px solid #efe9ff}
				.twob-modern-shell .twob-sidebar-kicker{font-size:11px;color:#7c3aed;font-weight:800;text-transform:uppercase;letter-spacing:.05em}
				.twob-modern-shell .twob-shortcut-btn{display:flex;align-items:center;min-height:42px;padding:10px 12px;border-radius:14px;background:#fff;border:1px solid #ece9ff;color:#111827;text-decoration:none;font-size:13px;font-weight:700;box-shadow:0 8px 18px rgba(15,23,42,.04)}
				.twob-modern-shell .twob-shortcut-btn:hover{border-color:#d8c9ff;background:#faf7ff;color:#4338ca}
				.twob-modern-shell .twob-sidebar-focus{display:grid;gap:6px;margin-top:18px;padding:14px;border-radius:18px;background:linear-gradient(135deg,#f7f2ff 0%,#eef4ff 100%);border:1px solid #e4dcff}
				.twob-modern-shell .twob-sidebar-focus strong{font-size:15px;color:#111827}
				.twob-modern-shell .twob-sidebar-focus span{font-size:12px;line-height:1.5;color:#5b6476}
				.twob-dashboard-v2{max-width:none}
				.twob-dashboard-v2 h1{margin:0;font-size:42px;line-height:1.02;letter-spacing:-.04em}
				.twob-dash-header{display:flex;justify-content:space-between;gap:18px;align-items:flex-start;margin:2px 0 18px}
				.twob-dash-chip-row{display:flex;gap:12px;flex-wrap:wrap;justify-content:flex-end}
				.twob-dash-chip{min-width:150px;padding:12px 14px;border-radius:18px;border:1px solid #ece9ff;background:rgba(255,255,255,.9);box-shadow:0 8px 22px rgba(15,23,42,.04)}
				.twob-dash-chip small{display:block;margin-bottom:4px;font-size:11px;color:#7c3aed;font-weight:800;text-transform:uppercase;letter-spacing:.04em}
				.twob-dash-chip strong{font-size:18px;color:#111827;line-height:1.2}
				.twob-dash-shell{display:grid;grid-template-columns:minmax(0,1.85fr) minmax(320px,.9fr);gap:20px;align-items:start}
				.twob-dash-main,.twob-dash-aside{display:grid;gap:18px}
				.twob-plan-card{background:linear-gradient(135deg,#fffdf7 0%,#ffffff 55%,#faf7ff 100%);border-color:#efe2c5;padding:22px 24px;border-radius:28px;box-shadow:0 18px 46px rgba(15,23,42,.06)}
				.twob-plan-card h2,.twob-flow-card h3,.twob-section-card h3,.twob-progress-card h3,.twob-focus-now-card h3,.twob-lifecycle-card h3{margin:0 0 6px}
				.twob-plan-steps{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:14px;margin-top:12px}
				.twob-plan-step{display:grid;grid-template-columns:56px 1fr;gap:14px;align-items:center;padding:16px;border-radius:20px;background:#fff;border:1px solid #edf0f7;box-shadow:0 10px 24px rgba(15,23,42,.04)}
				.twob-plan-step-number{display:flex;align-items:center;justify-content:center;width:56px;height:56px;border-radius:999px;color:#fff;font-size:22px;font-weight:800}
				.twob-plan-step.is-high .twob-plan-step-number{background:linear-gradient(135deg,#33b45c 0%,#22c55e 100%)}
				.twob-plan-step.is-medium .twob-plan-step-number{background:linear-gradient(135deg,#ff9b28 0%,#f59e0b 100%)}
				.twob-plan-step.is-low .twob-plan-step-number{background:linear-gradient(135deg,#4f7cf8 0%,#3156d3 100%)}
				.twob-plan-step-copy{display:grid;gap:2px}
				.twob-plan-step-copy strong{font-size:22px;line-height:1.12;color:#111827;letter-spacing:-.02em}
				.twob-plan-step-copy span{display:inline-flex;width:max-content;padding:4px 8px;border-radius:999px;font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:.04em;background:#f8fafc;color:#64748b}
				.twob-plan-step.is-high .twob-plan-step-copy span{background:#ecfdf3;color:#15803d}
				.twob-plan-step.is-medium .twob-plan-step-copy span{background:#fff7ed;color:#c2410c}
				.twob-plan-step.is-low .twob-plan-step-copy span{background:#eef4ff;color:#3156d3}
				.twob-plan-step-copy small{font-size:20px;font-weight:800;color:#111827}
				.twob-plan-footer{display:flex;justify-content:space-between;gap:14px;align-items:center;flex-wrap:wrap;margin-top:16px;padding-top:14px;border-top:1px solid #ede7ff}
				.twob-plan-tip{display:flex;align-items:center;gap:10px;min-height:48px;padding:12px 14px;border-radius:16px;background:#fff;border:1px solid #ece9ff;color:#475569;font-size:13px;line-height:1.5;flex:1 1 340px}
				.twob-dashboard-tabs{display:flex;gap:10px;flex-wrap:wrap;margin-top:18px}
				.twob-dashboard-tab{display:flex;align-items:center;gap:10px;padding:12px 14px;border-radius:16px;border:1px solid #ece9ff;background:#fff;color:#334155;font-size:14px;font-weight:800;cursor:pointer;transition:.18s}
				.twob-dashboard-tab:hover{border-color:#d8c9ff;color:#111827}
				.twob-dashboard-tab.is-active{background:linear-gradient(135deg,#f5f0ff 0%,#eef4ff 100%);border-color:#d8c9ff;color:#111827;box-shadow:0 12px 24px rgba(79,70,229,.08)}
				.twob-dashboard-tab span{display:inline-flex;align-items:center;justify-content:center;min-width:28px;height:28px;padding:0 8px;border-radius:999px;background:#eef2ff;color:#4338ca;font-size:12px;font-weight:800}
				.twob-dashboard-panel{display:none}
				.twob-dashboard-panel.is-active{display:block}
				.twob-flow-card{border-radius:26px;padding:22px 24px;background:linear-gradient(180deg,#ffffff 0%,#fcfcff 100%);border-color:#e6ebf6}
				.twob-flow-steps{display:grid;grid-template-columns:minmax(0,1fr) 24px minmax(0,1fr) 24px minmax(0,1fr) 24px minmax(0,1fr) 24px minmax(0,1fr);gap:8px;align-items:center;margin-top:14px}
				.twob-flow-step{display:grid;gap:6px;padding:16px 14px;border-radius:20px;background:#fff;border:1px solid #e8edf7;min-height:156px}
				.twob-flow-step span{font-size:12px;font-weight:800;text-transform:uppercase;letter-spacing:.04em}
				.twob-flow-step strong{font-size:18px;line-height:1.15;color:#111827}
				.twob-flow-step small{font-size:13px;color:#64748b;line-height:1.45}
				.twob-flow-step.is-start span,.twob-lifecycle-item:nth-child(1) small{color:#15803d}
				.twob-flow-step.is-day3 span,.twob-flow-step.is-day7 span{color:#3156d3}
				.twob-flow-step.is-day10 span,.twob-lifecycle-item:nth-child(4) small{color:#c2410c}
				.twob-flow-step.is-close span,.twob-lifecycle-item.is-closed small{color:#b91c1c}
				.twob-flow-arrow{position:relative;height:2px;background:linear-gradient(90deg,#d7deef 0%,#c9d3ea 100%);border-radius:999px}
				.twob-flow-arrow:after{content:'';position:absolute;right:-1px;top:50%;width:10px;height:10px;border-top:2px solid #94a3b8;border-right:2px solid #94a3b8;transform:translateY(-50%) rotate(45deg)}
				.twob-flow-note{margin-top:14px;padding:12px 14px;border-radius:16px;background:#f4fff6;border:1px solid #cfead4;color:#166534;font-size:13px;line-height:1.5}
				.twob-section-card{border-radius:26px;padding:20px 20px 18px}
				.twob-response-list{display:grid;gap:12px}
				.twob-response-row{display:grid;grid-template-columns:52px minmax(0,1fr) auto;gap:14px;align-items:center;padding:14px 16px;border-radius:20px;background:#fff;border:1px solid #edf2fb;box-shadow:0 10px 22px rgba(15,23,42,.04)}
				.twob-response-avatar{display:flex;align-items:center;justify-content:center;width:52px;height:52px;border-radius:999px;background:linear-gradient(135deg,#f0fff5 0%,#d8f5e4 100%);color:#15803d;font-weight:800;font-size:18px}
				.twob-response-copy{min-width:0;display:grid;gap:4px}
				.twob-response-head{display:flex;justify-content:space-between;gap:10px;align-items:center}
			.twob-response-head strong{font-size:18px;line-height:1.15;color:#111827}
			.twob-response-time{font-size:12px;color:#64748b;font-weight:700}
			.twob-response-note{font-size:13px;color:#475569;line-height:1.45;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
			.twob-response-meta-line{font-size:12px;color:#64748b;line-height:1.5}
			.twob-response-side{display:grid;gap:10px;justify-items:end}
			.twob-response-priority{display:inline-flex;align-items:center;justify-content:center;min-width:64px;padding:6px 10px;border-radius:999px;font-size:11px;font-weight:800}
				.twob-response-priority-alta{background:#fee2e2;color:#b91c1c}
				.twob-response-priority-media{background:#fef3c7;color:#92400e}
				.twob-response-priority-baja{background:#dbeafe;color:#1d4ed8}
				.twob-response-actions{display:flex;gap:8px;flex-wrap:wrap;justify-content:flex-end}
				.twob-dash-task-grid,.twob-dash-new-grid{grid-template-columns:repeat(auto-fit,minmax(300px,1fr))}
				.twob-goal-strip{display:flex;justify-content:space-between;gap:14px;align-items:center;flex-wrap:wrap;margin-bottom:14px}
				.twob-goal-meter{display:grid;gap:8px;min-width:250px}
				.twob-goal-meter span{font-size:13px;color:#475569;font-weight:700}
				.twob-goal-meter-bar{height:14px;border-radius:999px;background:#eef2ff;overflow:hidden}
				.twob-goal-meter-bar i{display:block;height:100%;border-radius:999px;background:linear-gradient(90deg,#33b45c 0%,#4f46e5 100%)}
				.twob-focus-now-card{padding:22px;background:linear-gradient(135deg,#6f41f4 0%,#4f46e5 100%);border-color:transparent;color:#fff;box-shadow:0 24px 50px rgba(79,70,229,.24)}
				.twob-focus-now-card small{display:block;margin-bottom:8px;color:#ddd6fe;font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.04em}
				.twob-focus-now-card h3{font-size:32px;line-height:1.1;color:#fff}
				.twob-focus-now-card p{margin:0;color:#f5f3ff;font-size:15px;line-height:1.6}
				.twob-progress-card{padding:20px;border-radius:24px}
				.twob-progress-ring{--twob-progress:0%;width:170px;height:170px;margin:16px auto;border-radius:50%;background:conic-gradient(#4db86f 0 var(--twob-progress),#e8f5ed var(--twob-progress) 100%);display:flex;align-items:center;justify-content:center}
				.twob-progress-ring>div{width:128px;height:128px;border-radius:50%;background:#fff;display:grid;place-items:center;text-align:center;box-shadow:inset 0 0 0 1px #eef2f7}
			.twob-progress-ring strong{font-size:30px;line-height:1;color:#15803d}
			.twob-progress-ring span{font-size:12px;color:#64748b;font-weight:700}
			.twob-check-list{margin:0;padding-left:18px;display:grid;gap:8px;color:#475569;font-size:13px;line-height:1.5}
			.twob-timeblock-card{background:linear-gradient(180deg,#fffdf7 0%,#ffffff 100%);border-color:#f1dfba}
			.twob-timeblock-list{display:grid;gap:10px}
			.twob-timeblock-item{display:grid;grid-template-columns:92px 1fr;gap:12px;align-items:start;padding:12px 14px;border-radius:18px;background:#fff;border:1px solid #edf2fb}
			.twob-timeblock-time{font-size:12px;font-weight:800;color:#7c3aed;text-transform:uppercase;letter-spacing:.04em}
			.twob-timeblock-copy{display:grid;gap:4px}
			.twob-timeblock-copy strong{font-size:15px;color:#111827}
			.twob-timeblock-copy span{font-size:13px;font-weight:700;color:#111827}
			.twob-timeblock-copy small{font-size:12px;line-height:1.5;color:#64748b}
			.twob-timeblock-item.is-high{border-left:4px solid #22c55e}
			.twob-timeblock-item.is-medium{border-left:4px solid #f59e0b}
			.twob-timeblock-item.is-low{border-left:4px solid #4f46e5}
			.twob-timeblock-item.is-neutral{border-left:4px solid #94a3b8}
			.twob-upcoming-list,.twob-meeting-list{display:grid;gap:10px}
				.twob-upcoming-item,.twob-meeting-item{display:flex;gap:12px;justify-content:space-between;align-items:center;padding:12px 14px;border-radius:16px;background:#fff;border:1px solid #edf2fb}
				.twob-upcoming-item strong,.twob-meeting-item strong{display:block;font-size:15px;color:#111827}
				.twob-upcoming-item small,.twob-meeting-item small{display:block;font-size:12px;color:#64748b}
				.twob-upcoming-item.is-day3{border-left:4px solid #4f7cf8}
				.twob-upcoming-item.is-day7{border-left:4px solid #f59e0b}
			.twob-upcoming-item.is-day10{border-left:4px solid #8b5cf6}
			.twob-reminders-card{background:linear-gradient(180deg,#fffdf7 0%,#ffffff 100%);border-color:#f1dfba}
			.twob-health-card{background:linear-gradient(180deg,#ffffff 0%,#fbfaff 100%)}
			.twob-risk-alert-card{background:linear-gradient(180deg,#fffafb 0%,#ffffff 100%);border-color:#ffd7df}
			.twob-health-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px}
			.twob-health-grid div{padding:12px 14px;border-radius:16px;background:#fff;border:1px solid #edf2fb}
			.twob-health-grid small{display:block;font-size:11px;color:#7c3aed;font-weight:800;text-transform:uppercase;letter-spacing:.04em}
			.twob-health-grid strong{display:block;margin-top:4px;font-size:22px;color:#111827}
			.twob-risk-mini-list{display:grid;gap:10px;margin-top:12px}
			.twob-risk-mini-item{display:flex;justify-content:space-between;gap:12px;align-items:flex-start;padding:12px 14px;border-radius:16px;background:#fff;border:1px solid #edf2fb}
			.twob-risk-mini-item strong{display:block;font-size:14px;color:#111827}
			.twob-risk-mini-item small{display:block;margin-top:4px;font-size:12px;line-height:1.45;color:#64748b}
			.twob-risk-mini-side{display:grid;gap:8px;justify-items:end}
			.twob-lifecycle-card{padding:20px 22px;border-radius:26px}
				.twob-lifecycle-grid{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:12px;margin-top:10px}
				.twob-lifecycle-item{padding:16px 14px;border-radius:18px;background:#fff;border:1px solid #edf2fb;text-align:center}
				.twob-lifecycle-item small{display:block;font-size:12px;font-weight:800;text-transform:uppercase;letter-spacing:.04em}
				.twob-lifecycle-item strong{display:block;margin-top:8px;font-size:30px;line-height:1;color:#111827}
				.twob-lifecycle-item.is-closed{background:#fff8f8;border-color:#ffd7d7}
				/* UI redesign v1.5.15 */
				.twob-crm-visual,.twob-crm-visual .twob-main{font-size:13px;font-weight:400}
				.twob-crm-visual .twob-muted,.twob-crm-visual small{font-size:12px}
				.twob-crm-visual label,.twob-crm-visual .twob-form-row label{font-size:11px;font-weight:600}
				.twob-crm-visual .twob-card{padding:16px}
				.twob-crm-visual .twob-grid{gap:12px}
				.twob-crm-visual .button,.twob-crm-visual .button-primary{border-radius:8px;padding:8px 14px;font-weight:600;box-shadow:none}
				.twob-crm-visual .button-primary{background:#1a1a1a;border-color:#1a1a1a;color:#fff}
				.twob-crm-visual .button-primary:hover,.twob-crm-visual .button-primary:focus{background:#E8A020;border-color:#E8A020;color:#1a1a1a}
				.twob-crm-visual .button:not(.button-primary){background:transparent;border:1px solid #e2dfd6;color:#1a1a1a}
				.twob-crm-visual .button:not(.button-primary):hover{background:#f5f4f0}
				.twob-link-quiet{background:none;border:0;padding:0;color:#64748b;font-size:12px;cursor:pointer}
				.twob-onboarding-block.is-dismissing{opacity:0;max-height:0;overflow:hidden;margin:0;transition:opacity .25s ease}
				.twob-onboarding-modal{position:fixed;inset:0;z-index:100001;display:flex;align-items:center;justify-content:center;padding:24px;background:rgba(15,23,42,.45)}
				.twob-onboarding-modal[hidden]{display:none}
				.twob-onboarding-modal-card{max-width:720px;width:100%;max-height:85vh;overflow:auto;background:#fff;border-radius:12px;padding:20px}
				.twob-sidebar-quick-actions{display:grid;gap:8px;margin:0 0 12px;padding:0 6px}
				.twob-shortcut-btn-compact{display:flex;align-items:center;justify-content:center;min-height:32px;border-radius:8px;border:1px solid #E8A020;background:rgba(232,160,32,.12);color:#fff;font-size:12px;font-weight:600;text-decoration:none}
				.twob-sidebar-user{display:flex;align-items:center;gap:10px;padding:6px 6px 12px}
				.twob-user-avatar{width:36px;height:36px;border-radius:999px;display:flex;align-items:center;justify-content:center;font-weight:600}
				.twob-user-avatar.is-dani{background:#185FA5;color:#fff}
				.twob-user-avatar.is-renata{background:#E8A020;color:#1a1a1a}
				.twob-user-role{font-size:12px;color:#c7d2fe}
				.twob-user-role strong{display:block;color:#fff;font-size:13px}
				.twob-sidebar-focus{display:none!important}
				.twob-status-bar{display:flex;align-items:center;flex-wrap:wrap;gap:10px;min-height:40px;margin:0 0 12px;padding:8px 14px;background:#fff;border:1px solid var(--twob-border);border-radius:10px}
				.twob-status-progress{display:flex;align-items:center;gap:10px;margin-left:auto}
				.twob-status-progress-track{width:120px;height:4px;background:#e8edf4;border-radius:999px;overflow:hidden}
				.twob-status-progress-track i{display:block;height:100%;background:#E8A020}
				.twob-priority-strip{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:12px;margin:0 0 14px}
				.twob-priority-card{display:grid;grid-template-columns:auto 1fr auto auto;align-items:center;gap:8px;min-height:60px;padding:10px 14px;border-radius:10px;border:1px solid var(--twob-border);background:#fff;text-decoration:none;color:inherit}
				.twob-priority-card.has-pending{background:#fff8ec;border-color:#f5d9a8}
				.twob-responded-today{border-left:3px solid #E8A020;background:#fff8ec}
				.twob-metrics-inline{display:flex;gap:14px;flex-wrap:wrap;font-size:12px;font-weight:600}
				.twob-timeblock-item{padding:12px}
				.twob-filter-pills{display:flex;flex-wrap:wrap;gap:8px;align-items:center;margin:0 0 12px}
				.twob-filter-pill{padding:6px 12px;border-radius:999px;border:1px solid #e2dfd6;font-size:12px;font-weight:600;text-decoration:none;color:#1a1a1a}
				.twob-filter-pill.is-active{background:#1a1a1a;color:#fff;border-color:#1a1a1a}
				.twob-filter-pills-right{margin-left:auto;display:flex;gap:8px}
				.twob-leads-compact-list{border:1px solid var(--twob-border);border-radius:10px;overflow:hidden;background:#fff}
				.twob-lead-row-v2{display:grid;grid-template-columns:4px minmax(0,1.4fr) auto auto minmax(0,.7fr) auto auto;align-items:center;gap:10px;min-height:52px;padding:8px 12px;border-bottom:1px solid #eef2f7;position:relative;cursor:pointer}
				.twob-lead-indicator{width:4px;min-height:36px;border-radius:4px}
				.twob-lead-indicator-is-danger{background:#dc2626}
				.twob-lead-indicator-is-ok{background:#16a34a}
				.twob-lead-indicator-is-warn{background:#E8A020}
				.twob-lead-indicator-is-muted{background:#94a3b8}
				.twob-lead-row-hover-actions{display:none;position:absolute;right:12px;top:50%;transform:translateY(-50%);gap:6px;background:#fff;padding:4px;box-shadow:0 4px 12px rgba(15,23,42,.08)}
				.twob-lead-row-v2:hover .twob-lead-row-hover-actions{display:flex}
				.twob-tasks-workspace{display:grid;grid-template-columns:58% 42%;gap:14px}
				.twob-task-scroll-list{max-height:calc(100vh - 200px);overflow-y:auto}
				.twob-task-row-compact{display:grid;grid-template-columns:28px 1fr auto auto auto;align-items:center;gap:10px;min-height:48px;padding:8px 12px;border-bottom:1px solid #eef2f7;cursor:pointer}
				.twob-task-row-compact.is-completing{opacity:0;max-height:0;overflow:hidden;transition:opacity .25s ease,max-height .25s ease}
				.twob-task-complete-circle{display:inline-flex;align-items:center;justify-content:center;width:22px;height:22px;border-radius:999px;border:2px solid #cbd5e1;background:#fff;appearance:none;-webkit-appearance:none;cursor:pointer;position:relative;z-index:2}
				.twob-tasks-workspace ~ .twob-grid{display:none}
				.twob-copy-message-btn.is-copied{background:#16a34a!important;border-color:#16a34a!important}
				/* Readability pass */
				.twob-crm-visual,.twob-crm-visual .twob-main{color:#0f172a}
				.twob-crm-visual .twob-muted,.twob-crm-visual small{color:#5b6476}
				.twob-crm-visual label,.twob-crm-visual .twob-form-row label{font-weight:700;color:#334155}
				.twob-crm-visual .button,.twob-crm-visual .button-primary{border-radius:10px;padding:9px 14px;font-weight:700}
				.twob-crm-visual .button-primary{background:#1f3fae;border-color:#1f3fae;color:#fff}
				.twob-crm-visual .button:not(.button-primary){background:#fff;border-color:#d6dde8;color:#0f172a}
				.twob-crm-visual .button:not(.button-primary):hover{background:#f8fafc;border-color:#c3cfdd}
				.twob-link-quiet{color:#475569}
				.twob-page-leads .twob-card,.twob-page-interactions .twob-card,.twob-page-tasks .twob-card{border-color:#dde5f0;box-shadow:0 14px 32px rgba(15,23,42,.06)}
				.twob-page-leads .twob-card,.twob-page-interactions .twob-card,.twob-page-tasks .twob-card,.twob-page-leads .twob-screen-hero,.twob-page-interactions .twob-screen-hero,.twob-page-tasks .twob-screen-hero{background:#fff}
				.twob-page-tasks .twob-focus-card,.twob-page-interactions .twob-helper-box,.twob-page-leads .twob-helper-box{background:#fffaf2;border-color:#ebd6a8}
				.twob-modern-shell .twob-sidebar{background:#fff;border-color:#dde5f0;box-shadow:0 18px 36px rgba(15,23,42,.06)}
				.twob-modern-shell .twob-brand small,.twob-modern-shell .twob-sidebar-kicker,.twob-dash-chip small,.twob-timeblock-time{color:#4338ca}
				.twob-modern-shell .twob-nav a:hover{background:#f8fafc;border-color:#dde5f0;color:#111827}
				.twob-modern-shell .twob-nav a.is-active{background:linear-gradient(135deg,#5b4df0 0%,#3156d3 100%);box-shadow:0 12px 24px rgba(49,86,211,.24)}
				.twob-sidebar-user{padding:8px 8px 14px;margin-bottom:10px;border-bottom:1px solid #edf2f7}
				.twob-user-role{color:#475569}
				.twob-user-role strong{color:#0f172a;font-size:14px}
				.twob-sidebar-quick-actions{gap:10px;margin-bottom:14px;padding:0 4px 6px}
				.twob-shortcut-btn-compact{min-height:40px;padding:10px 12px;border-radius:12px;border-color:#d9e0ea;background:#fff;color:#0f172a;font-weight:700;box-shadow:0 4px 14px rgba(15,23,42,.04)}
				.twob-shortcut-btn-compact:hover{background:#f8fafc;border-color:#c7d2df;color:#111827}
				.twob-status-bar{border-color:#dde5f0;border-radius:12px;box-shadow:0 8px 20px rgba(15,23,42,.04)}
				.twob-status-progress-track{background:#e2e8f0}
				.twob-priority-card{border-color:#dde5f0;border-radius:12px;box-shadow:0 8px 20px rgba(15,23,42,.04)}
				.twob-priority-card.has-pending{background:#fff8f1;border-color:#f0d3a2}
				.twob-responded-today{border-left-width:4px;background:#fff8f1}
				.twob-metrics-inline{color:#334155}
				.twob-dash-chip{border-color:#dde5f0;box-shadow:0 8px 18px rgba(15,23,42,.04)}
				.twob-plan-card,.twob-flow-card,.twob-timeblock-card,.twob-reminders-card,.twob-health-card,.twob-risk-alert-card{background:#fff;border-color:#dde5f0;box-shadow:0 14px 30px rgba(15,23,42,.06)}
				.twob-dashboard-tab{border-color:#dde5f0;background:#fff;color:#334155}
				.twob-dashboard-tab:hover{border-color:#c8d5ea;background:#f8fafc;color:#111827}
