	public static function admin_scripts() {
		$screen = function_exists('get_current_screen') ? get_current_screen() : null;
		$screen_id = $screen ? (string) $screen->id : '';
		if (! $screen || (false === strpos($screen_id, 'twob-crm-visual') && false === strpos($screen_id, 'twob-crm-buscador'))) {
			return;
		}
		$nonce = wp_create_nonce(self::NONCE_ACTION);
		?>
		<script>
			(function(){
				var todayValue = '<?php echo esc_js(current_time('Y-m-d')); ?>';
				var chileHolidayDays = <?php echo wp_json_encode(self::chile_holiday_days_window(((int) current_time('Y')) - 1, ((int) current_time('Y')) + 4)); ?>;
				var chileHolidayMap = {};
				(chileHolidayDays || []).forEach(function(day){
					chileHolidayMap[String(day)] = true;
				});
				var isResponseFocusScreen = window.location.search.indexOf('focus=responses') !== -1;
				var stageLabels = <?php echo wp_json_encode(self::stage_labels()); ?>;
				var channelLabels = <?php echo wp_json_encode(self::channel_labels()); ?>;
				var serviceValueMap = <?php echo wp_json_encode(self::service_value_map()); ?>;
				var interactionActionLabels = <?php echo wp_json_encode(self::interaction_action_labels()); ?>;
				var interactionResultLabels = <?php echo wp_json_encode(self::interaction_result_labels()); ?>;

			function sendQuick(body){
				return fetch(ajaxurl, {
					method: 'POST',
					headers: {'Content-Type':'application/x-www-form-urlencoded; charset=UTF-8'},
					body: body.toString(),
					credentials: 'same-origin'
				}).then(function(r){ return r.json(); });
			}

			function toIsoDate(dateObj){
				return dateObj.getFullYear() + '-' + String(dateObj.getMonth() + 1).padStart(2, '0') + '-' + String(dateObj.getDate()).padStart(2, '0');
			}

			function isChileBusinessDay(dateObj){
				if (!(dateObj instanceof Date) || Number.isNaN(dateObj.getTime())) { return false; }
				var weekday = dateObj.getDay();
				if (weekday === 0 || weekday === 6) { return false; }
				return !Object.prototype.hasOwnProperty.call(chileHolidayMap, toIsoDate(dateObj));
			}

			function addChileBusinessDays(baseIsoDay, days){
				var base = new Date(String(baseIsoDay || todayValue) + 'T12:00:00');
				if (Number.isNaN(base.getTime())) { return String(baseIsoDay || todayValue); }
				var remaining = Math.max(0, parseInt(days || 0, 10) || 0);
				if (remaining === 0) {
					while (!isChileBusinessDay(base)) {
						base.setDate(base.getDate() + 1);
					}
					return toIsoDate(base);
				}
				while (remaining > 0) {
					base.setDate(base.getDate() + 1);
					if (isChileBusinessDay(base)) {
						remaining -= 1;
					}
				}
				return toIsoDate(base);
			}

			function defaultDay3Value(){
				return addChileBusinessDays(todayValue, 3);
			}

			function sequencePolicyForOrigin(channel){
				switch ((channel || '').toLowerCase()) {
					case 'red_calida':
					case 'whatsapp':
						return 'short';
					case 'referral':
						return 'manual';
					case 'linkedin':
					case 'email':
					default:
						return 'full';
				}
			}

			function defaultValueForService(serviceKey){
				if (!Object.prototype.hasOwnProperty.call(serviceValueMap || {}, serviceKey || '')) {
					return '';
				}
				return String(serviceValueMap[serviceKey]);
			}

			function syncServiceValue(select, input, force){
				if (!select || !input) { return; }
				var mappedValue = defaultValueForService(select.value || '');
				if (mappedValue === '') { return; }
				if (force || !input.value) {
					input.value = mappedValue;
				}
			}

			function toggleAllianceSourceWrap(originInput, wrap){
				if (!originInput || !wrap) { return; }
				var isReferral = (originInput.value || '') === 'referral';
				wrap.hidden = !isReferral;
			}

			function recommendedTemperatureForLead(originChannel, stage){
				var normalizedStage = String(stage || '').toLowerCase();
				if (normalizedStage === 'lost') {
					return 'cold';
				}
				if (['responded_interested', 'meeting_scheduled', 'meeting_done', 'proposal_sent', 'won'].indexOf(normalizedStage) >= 0) {
					return 'hot';
				}
				switch (String(originChannel || '').toLowerCase()) {
					case 'linkedin':
					case 'email':
					case 'whatsapp':
					case 'red_calida':
					case 'referral':
					default:
						return 'warm';
				}
			}

			function syncLeadTemperatureSelect(originInput, temperatureInput, stageInput){
				if (!temperatureInput) { return; }
				var autoValue = recommendedTemperatureForLead(originInput ? originInput.value : '', stageInput ? stageInput.value : '');
				var lastAuto = temperatureInput.dataset.lastAutoValue || '';
				var userChanged = temperatureInput.dataset.userChanged === '1';
				if (!userChanged || !temperatureInput.value || temperatureInput.value === lastAuto) {
					temperatureInput.value = autoValue;
				}
				temperatureInput.dataset.lastAutoValue = autoValue;
			}

				function syncLeadSequenceHelp(originInput, nextInput, helpNode){
					if (!originInput || !nextInput || !helpNode) { return; }
					var policy = sequencePolicyForOrigin(originInput.value || '');
				var defaultDay3 = defaultDay3Value();
				if (policy === 'manual') {
					if (!nextInput.dataset.userChanged && nextInput.value === defaultDay3) {
						nextInput.value = '';
					}
					helpNode.textContent = 'Este canal no crea seguimiento automatico. Deja fecha solo si quieres programar gestion manual.';
					return;
				}
				if (!nextInput.value && !nextInput.dataset.userChanged) {
					nextInput.value = defaultDay3;
				}
				if (policy === 'short') {
					helpNode.textContent = 'Si no la cambias, queda en D+3 habil. Este canal no crea D+7 ni D+10.';
					return;
				}
					helpNode.textContent = 'Si no la cambias, queda automaticamente en D+3 habil y luego sigue el ciclo completo.';
				}

				function currentLeadCreationMode(){
					var checked = document.querySelector('input[name="twob_lead_creation_mode"]:checked');
					return checked ? checked.value : 'contacted';
				}

				function syncLeadCreationModeUI(originInput, nextInput, helpNode){
					var mode = currentLeadCreationMode();
					var isPreContact = mode === 'pre_contact';
					var stateLock = document.getElementById('twob_lead_state_lock');
					var modeHint = document.getElementById('twob_lead_creation_mode_hint');
					var createLeadBtn = document.getElementById('twob_create_lead');
					document.querySelectorAll('[data-lead-normal-only]').forEach(function(node){
						node.hidden = isPreContact;
					});
					document.querySelectorAll('.twob-mode-option').forEach(function(option){
						var input = option.querySelector('input[type="radio"]');
						option.classList.toggle('is-active', !!(input && input.checked));
					});
					if (isPreContact) {
						if (stateLock) {
							stateLock.textContent = 'Se guarda como PRE-CONTACTO y espera revision tecnica antes del primer mensaje.';
						}
						if (modeHint) {
							modeHint.textContent = 'Modo actual: revision tecnica primero. Solo son obligatorios Nombre, Empresa, Sitio web y Canal origen.';
						}
						if (createLeadBtn) {
							createLeadBtn.textContent = 'Crear lead en Pre-contacto';
						}
						if (nextInput) {
							nextInput.value = '';
							delete nextInput.dataset.userChanged;
						}
						return;
					}
					if (stateLock) {
						stateLock.textContent = 'Se guarda como CONTACTADO y arranca el flujo comercial.';
					}
					if (modeHint) {
						modeHint.textContent = 'Modo actual: primer contacto ya enviado. El CRM creara el lead activo y programara la siguiente accion.';
					}
					if (createLeadBtn) {
						createLeadBtn.textContent = 'Crear lead y registrar primer contacto';
					}
					if (originInput && nextInput && helpNode) {
						syncLeadSequenceHelp(originInput, nextInput, helpNode);
					}
				}

