				function initDashboardFocusTabs(){
					var tabsRoot = document.querySelector('[data-twob-dashboard-tabs]');
					if (!tabsRoot) { return; }
					var buttons = Array.prototype.slice.call(tabsRoot.querySelectorAll('[data-twob-tab]'));
					var panels = Array.prototype.slice.call(document.querySelectorAll('[data-twob-tab-panel]'));
					if (!buttons.length || !panels.length) { return; }
					var defaultTab = tabsRoot.getAttribute('data-default-tab') || buttons[0].getAttribute('data-twob-tab');

					function activateTab(tabName){
						buttons.forEach(function(btn){
							var active = btn.getAttribute('data-twob-tab') === tabName;
							btn.classList.toggle('is-active', active);
							btn.setAttribute('aria-pressed', active ? 'true' : 'false');
						});
						panels.forEach(function(panel){
							var active = panel.getAttribute('data-twob-tab-panel') === tabName;
							panel.classList.toggle('is-active', active);
						});
					}

					buttons.forEach(function(btn){
						btn.addEventListener('click', function(){
							activateTab(btn.getAttribute('data-twob-tab'));
						});
					});

					activateTab(defaultTab);
				}

				initDashboardFocusTabs();
	
				function initLeadAccordion(){
				document.querySelectorAll('.twob-lead-accordion').forEach(function(card){
					var toggle = card.querySelector('.twob-toggle-lead');
					if (!toggle) { return; }
					toggle.addEventListener('click', function(){
						var open = card.classList.toggle('is-open');
						toggle.textContent = open ? 'Ocultar detalle' : 'Ver detalle';
					});
				});
				if (window.location.hash && window.location.hash.indexOf('#lead-') === 0) {
					var target = document.querySelector(window.location.hash);
					if (target && target.classList.contains('twob-lead-accordion') && !document.querySelector('[data-twob-leads-workspace]')) {
						target.classList.add('is-open');
						var targetBtn = target.querySelector('.twob-toggle-lead');
						if (targetBtn) { targetBtn.textContent = 'Ocultar detalle'; }
					}
				}
			}

			function initLeadPanelTabs(scope) {
				var root = scope || document;
				root.querySelectorAll('[data-twob-lead-tabs]').forEach(function(tabWrap) {
					var buttons = tabWrap.querySelectorAll('.twob-lead-panel-tab');
					var panelRoot = tabWrap.closest('.twob-lead-panel');
					if (!panelRoot) { return; }
					var panels = panelRoot.querySelectorAll('[data-twob-tab-panel]');
					function activate(tabName) {
						buttons.forEach(function(btn) {
							btn.classList.toggle('is-active', btn.getAttribute('data-twob-tab') === tabName);
						});
						panels.forEach(function(panel) {
							panel.classList.toggle('is-active', panel.getAttribute('data-twob-tab-panel') === tabName);
						});
					}
					var defaultPanel = panelRoot.querySelector('[data-twob-tab-panel][data-default-tab="1"]');
					activate(defaultPanel ? defaultPanel.getAttribute('data-twob-tab-panel') : (buttons[0] ? buttons[0].getAttribute('data-twob-tab') : 'datos'));
					buttons.forEach(function(btn) {
						btn.addEventListener('click', function() {
							activate(btn.getAttribute('data-twob-tab'));
						});
					});
				});
			}

			function initLeadsMondayWorkspace() {
				var workspace = document.querySelector('[data-twob-leads-workspace]');
				if (!workspace) { return; }

				var drawer = workspace.querySelector('[data-twob-lead-drawer]');
				var drawerBody = workspace.querySelector('[data-twob-drawer-body]');
				var drawerTitle = workspace.querySelector('[data-twob-drawer-title]');
				var backdrop = workspace.querySelector('[data-twob-drawer-backdrop]');
				var panelCache = {};
				var loadingLeadId = 0;

				function setDrawerOpen(open) {
					workspace.classList.toggle('has-drawer-open', !!open);
					if (drawer) {
						drawer.setAttribute('aria-hidden', open ? 'false' : 'true');
					}
					if (backdrop) {
						backdrop.hidden = !open;
					}
				}

				function updateUrlLeadId(leadId, reactivation) {
					var url = new URL(window.location.href);
					if (leadId) {
						url.searchParams.set('lead_id', String(leadId));
						if (reactivation) {
							url.searchParams.set('reactivation', '1');
						} else {
							url.searchParams.delete('reactivation');
						}
					} else {
						url.searchParams.delete('lead_id');
						url.searchParams.delete('reactivation');
					}
					url.hash = leadId ? ('#lead-' + leadId) : '';
					window.history.pushState({ leadId: leadId || 0 }, '', url.toString());
				}

				function directLeadUrl(leadId, reactivation) {
					var url = new URL(window.location.href);
					if (leadId) {
						url.searchParams.set('lead_id', String(leadId));
						if (reactivation) {
							url.searchParams.set('reactivation', '1');
						} else {
							url.searchParams.delete('reactivation');
						}
						url.hash = '#lead-' + leadId;
					} else {
						url.searchParams.delete('lead_id');
						url.searchParams.delete('reactivation');
						url.hash = '';
					}
					return url.toString();
				}

				function markSelectedRow(leadId) {
					workspace.querySelectorAll('.twob-lead-row, .twob-lead-row-v2').forEach(function(row) {
						var active = String(row.getAttribute('data-lead-id')) === String(leadId);
						row.classList.toggle('is-selected', active);
						row.setAttribute('aria-selected', active ? 'true' : 'false');
					});
				}

				function bindPanelBehaviors() {
					initLeadPanelTabs(drawerBody);
					initLeadCardHelpers();
					document.dispatchEvent(new CustomEvent('twob:reactivation-mount', { detail: { scope: drawerBody } }));
				}

				function renderPanelHtml(html) {
					if (!drawerBody) { return; }
					drawerBody.innerHTML = html || '<div class="twob-empty">No se pudo cargar la ficha.</div>';
					bindPanelBehaviors();
				}

				function renderLeadPanelError(message, leadId, reactivation) {
					if (!drawerBody) { return; }
					var safeMessage = message || 'No se pudo cargar la ficha del lead.';
					var fallbackUrl = directLeadUrl(leadId, reactivation);
					drawerBody.innerHTML = '<div class="twob-empty">' + safeMessage + '<br><br><a class="button button-small" href="' + fallbackUrl + '">Abrir en pantalla completa</a></div>';
				}

				function openLeadPanel(leadId, options) {
					options = options || {};
					leadId = parseInt(leadId, 10) || 0;
					if (!leadId) {
						setDrawerOpen(false);
						markSelectedRow(0);
						updateUrlLeadId(0);
						if (drawerTitle) { drawerTitle.textContent = 'Selecciona un lead'; }
						if (drawerBody) {
							drawerBody.innerHTML = '<div class="twob-empty">Haz clic en una fila para abrir la ficha sin salir de esta pantalla.</div>';
						}
						return;
					}

					var row = workspace.querySelector('.twob-lead-row-v2[data-lead-id="' + leadId + '"], .twob-lead-row[data-lead-id="' + leadId + '"]');
					if (drawerTitle) {
						drawerTitle.textContent = row ? (row.getAttribute('data-lead-title') || 'Lead') : 'Lead';
					}
					markSelectedRow(leadId);
					setDrawerOpen(true);
					updateUrlLeadId(leadId, !!options.reactivation);

					if (panelCache[leadId] && !options.forceReload) {
						renderPanelHtml(panelCache[leadId]);
						if (options.reactivation) {
							var reactTabCached = drawerBody.querySelector('.twob-lead-panel-tab[data-twob-tab="reactivacion"]');
							if (reactTabCached) { reactTabCached.click(); }
						}
						return;
					}

					if (loadingLeadId === leadId) { return; }
					loadingLeadId = leadId;
					drawerBody.innerHTML = '<div class="twob-line-2">Cargando ficha...</div>';
					if (!twobCrm || !twobCrm.nonce) {
						window.location.assign(directLeadUrl(leadId, !!options.reactivation));
						return;
					}

					var body = new URLSearchParams();
					body.append('action', 'twob_crm_quick_action');
					body.append('nonce', twobCrm.nonce);
					body.append('quick_action', 'load_lead_panel');
					body.append('lead_id', String(leadId));

					fetch(ajaxurl, { method: 'POST', credentials: 'same-origin', headers: { 'Content-Type': 'application/x-www-form-urlencoded' }, body: body.toString() })
						.then(function(res) { return res.json(); })
						.then(function(payload) {
							loadingLeadId = 0;
							if (!payload || !payload.success || !payload.data || !payload.data.html) {
								renderLeadPanelError((payload && payload.data && payload.data.message) ? payload.data.message : 'No se pudo cargar la ficha del lead.', leadId, !!options.reactivation);
								return;
							}
							panelCache[leadId] = payload.data.html || '';
							if (drawerTitle && payload.data.title) {
								drawerTitle.textContent = payload.data.title;
							}
							renderPanelHtml(panelCache[leadId]);
							if (options.reactivation) {
								var reactTabLoaded = drawerBody.querySelector('.twob-lead-panel-tab[data-twob-tab="reactivacion"]');
								if (reactTabLoaded) { reactTabLoaded.click(); }
							}
						})
						.catch(function() {
							loadingLeadId = 0;
							renderLeadPanelError('No se pudo cargar la ficha del lead.', leadId, !!options.reactivation);
						});
				}

				workspace.querySelectorAll('.twob-lead-row, .twob-lead-row-v2').forEach(function(row) {
					row.addEventListener('click', function(event) {
						if (event.target.closest('a,button,input,select,textarea,label') && !event.target.closest('.twob-lead-open-btn')) { return; }
						openLeadPanel(row.getAttribute('data-lead-id'));
					});
					row.addEventListener('keydown', function(event) {
						if (event.key === 'Enter' || event.key === ' ') {
							event.preventDefault();
							openLeadPanel(row.getAttribute('data-lead-id'));
						}
					});
				});
				workspace.querySelectorAll('.twob-lead-open-btn').forEach(function(btn) {
					btn.addEventListener('click', function(event) {
						event.preventDefault();
						event.stopPropagation();
						openLeadPanel(btn.getAttribute('data-lead-open') || btn.closest('[data-lead-id]').getAttribute('data-lead-id'));
					});
				});

				if (backdrop) {
					backdrop.addEventListener('click', function() { openLeadPanel(0); });
				}
				var closeBtn = workspace.querySelector('[data-twob-drawer-close]');
				if (closeBtn) {
					closeBtn.addEventListener('click', function() { openLeadPanel(0); });
				}

				document.addEventListener('keydown', function(event) {
					if (event.key === 'Escape' && workspace.classList.contains('has-drawer-open')) {
						openLeadPanel(0);
					}
				});

				var initialLeadId = parseInt(workspace.getAttribute('data-selected-lead'), 10) || 0;
				if (!initialLeadId && window.location.hash && window.location.hash.indexOf('#lead-') === 0) {
					initialLeadId = parseInt(window.location.hash.replace('#lead-', ''), 10) || 0;
				}
				if (initialLeadId) {
					var openReactivation = (new URL(window.location.href)).searchParams.get('reactivation') === '1';
					if (drawerBody && drawerBody.querySelector('.twob-lead-panel')) {
						markSelectedRow(initialLeadId);
						setDrawerOpen(true);
						initLeadPanelTabs(drawerBody);
						if (openReactivation) {
							var reactTabInitial = drawerBody.querySelector('.twob-lead-panel-tab[data-twob-tab="reactivacion"]');
							if (reactTabInitial) { reactTabInitial.click(); }
						}
					} else {
						openLeadPanel(initialLeadId, { reactivation: openReactivation });
					}
				}

				window.addEventListener('popstate', function() {
					var url = new URL(window.location.href);
					var leadId = parseInt(url.searchParams.get('lead_id'), 10) || 0;
					if (!leadId && url.hash.indexOf('#lead-') === 0) {
						leadId = parseInt(url.hash.replace('#lead-', ''), 10) || 0;
					}
					if (leadId) {
						openLeadPanel(leadId, { reactivation: url.searchParams.get('reactivation') === '1', forceReload: true });
					} else {
						openLeadPanel(0);
					}
				});
			}

			function initUiOnboarding() {
				var modal = document.getElementById('twob-onboarding-modal');
				if (!modal) {
					modal = document.createElement('div');
					modal.id = 'twob-onboarding-modal';
					modal.className = 'twob-onboarding-modal';
					modal.hidden = true;
					modal.innerHTML = '<div class="twob-onboarding-modal-card" role="dialog" aria-modal="true"><button type="button" class="button" data-twob-modal-close style="float:right">Cerrar</button><div data-twob-modal-body></div></div>';
					document.body.appendChild(modal);
					modal.addEventListener('click', function(e) {
						if (e.target === modal || e.target.closest('[data-twob-modal-close]')) { modal.hidden = true; }
					});
				}
				var modalBody = modal.querySelector('[data-twob-modal-body]');
				document.querySelectorAll('[data-twob-onboarding-dismiss]').forEach(function(btn) {
					btn.addEventListener('click', function() {
						var section = btn.getAttribute('data-twob-onboarding-dismiss');
						var block = btn.closest('[data-twob-onboarding-block]');
						if (block) { block.classList.add('is-dismissing'); }
						var fd = new FormData();
						fd.append('action', 'twob_crm_quick_action');
						fd.append('nonce', '<?php echo esc_js($nonce); ?>');
						fd.append('quick_action', 'dismiss_ui_onboarding');
						fd.append('section', section);
						fetch(ajaxurl, { method: 'POST', body: fd, credentials: 'same-origin' })
							.finally(function() {
								setTimeout(function() { if (block && block.parentNode) { block.parentNode.removeChild(block); } }, 260);
							});
					});
				});
				document.querySelectorAll('[data-twob-onboarding-reopen]').forEach(function(btn) {
					btn.addEventListener('click', function() {
						var section = btn.getAttribute('data-twob-onboarding-reopen');
						var tpl = document.querySelector('[data-twob-onboarding-template="' + section + '"]');
						if (modalBody && tpl) {
							modalBody.innerHTML = tpl.innerHTML;
							modal.hidden = false;
						}
					});
				});
			}

			function initTasksWorkspace() {
				var workspace = document.querySelector('[data-twob-tasks-workspace]');
				var detail = document.querySelector('[data-twob-task-detail]');
				var globalRoot = document.documentElement;
				var shouldBindGlobals = globalRoot.dataset.twobTaskGlobalsBound !== '1';
				if (workspace && workspace.dataset.twobTasksBound === '1' && !shouldBindGlobals) { return; }
				if (workspace) {
					workspace.dataset.twobTasksBound = '1';
				}
				if (shouldBindGlobals) {
					globalRoot.dataset.twobTaskGlobalsBound = '1';
				}
				var leadDrawer = document.querySelector('[data-twob-task-lead-drawer]');
				var leadDrawerBody = document.querySelector('[data-twob-task-drawer-body]');
				var leadDrawerTitle = document.querySelector('[data-twob-task-drawer-title]');
				var leadBackdrop = document.querySelector('[data-twob-task-lead-backdrop]');

				function flashCopyButton(button) {
					if (!button) { return; }
					var original = button.dataset.originalLabel || button.textContent;
					button.dataset.originalLabel = original;
					button.textContent = '✓ Copiado';
					button.classList.add('is-copied');
					setTimeout(function() {
						button.textContent = original;
						button.classList.remove('is-copied');
					}, 1800);
				}

				function readCopyText(button) {
					if (!button) { return ''; }
					var explicit = button.getAttribute('data-twob-copy-text') || '';
					if (explicit) { return explicit; }
					var targetSelector = button.getAttribute('data-twob-copy-target') || '';
					if (!targetSelector) { return ''; }
					var scope = button.closest('[data-twob-task-detail-panel], .twob-card, .twob-task-item, .twob-lead-panel-section, .twob-lead-panel, form') || document;
					var target = scope.querySelector(targetSelector) || document.querySelector(targetSelector);
					if (!target) { return ''; }
					if (typeof target.value === 'string') {
						return target.value;
					}
					return target.textContent || '';
				}

				function copyButtonPayload(button) {
					var text = readCopyText(button);
					if (!text) { return Promise.resolve(false); }
					if (!navigator.clipboard || typeof navigator.clipboard.writeText !== 'function') {
						var helper = document.createElement('textarea');
						helper.value = text;
						helper.setAttribute('readonly', 'readonly');
						helper.style.position = 'absolute';
						helper.style.left = '-9999px';
						document.body.appendChild(helper);
						helper.select();
						try {
							document.execCommand('copy');
							flashCopyButton(button);
							document.body.removeChild(helper);
							return Promise.resolve(true);
						} catch (error) {
							document.body.removeChild(helper);
							return Promise.reject(error);
						}
					}
					return navigator.clipboard.writeText(text).then(function() {
						flashCopyButton(button);
						return true;
					});
				}

				function bindTaskLeadPanelBehaviors() {
					if (!leadDrawerBody) { return; }
					initLeadPanelTabs(leadDrawerBody);
					initLeadCardHelpers();
					document.dispatchEvent(new CustomEvent('twob:reactivation-mount', { detail: { scope: leadDrawerBody } }));
				}

				function renderTaskLeadPanelError(message, leadId) {
					if (!leadDrawerBody) { return; }
					var safeMessage = message || 'No se pudo cargar la ficha del lead.';
					var fallbackUrl = String(leadId || '').trim() ? ('<?php echo esc_js(admin_url('admin.php?page=twob-crm-visual-leads&lead_id=')); ?>' + String(leadId) + '#lead-' + String(leadId)) : '<?php echo esc_js(admin_url('admin.php?page=twob-crm-visual-leads')); ?>';
					leadDrawerBody.innerHTML = '<div class="twob-empty">' + safeMessage + '<br><br><a class="button button-small" href="' + fallbackUrl + '">Abrir en pantalla completa</a></div>';
				}

				function setTaskLeadDrawerOpen(open) {
					if (leadDrawer) {
						leadDrawer.setAttribute('aria-hidden', open ? 'false' : 'true');
					}
					if (leadBackdrop) {
						leadBackdrop.hidden = !open;
					}
				}

				function openTaskLeadDrawer(leadId, leadLabel) {
					leadId = parseInt(leadId, 10) || 0;
					if (!leadId) {
						setTaskLeadDrawerOpen(false);
						return;
					}
					if (leadDrawerTitle) {
						leadDrawerTitle.textContent = leadLabel || 'Lead';
					}
					if (leadDrawerBody) {
						leadDrawerBody.innerHTML = '<div class="twob-empty">Cargando ficha del lead...</div>';
					}
					setTaskLeadDrawerOpen(true);
					var body = new URLSearchParams();
					body.append('action', 'twob_crm_quick_action');
					body.append('nonce', '<?php echo esc_js($nonce); ?>');
					body.append('quick_action', 'load_lead_panel');
					body.append('lead_id', String(leadId));
					sendQuick(body)
						.then(function(json) {
							if (!json || !json.success || !json.data || !json.data.html) {
								renderTaskLeadPanelError((json && json.data && json.data.message) ? json.data.message : 'No se pudo cargar la ficha del lead.', leadId);
								return;
							}
							if (leadDrawerTitle && json.data.title) {
								leadDrawerTitle.textContent = json.data.title;
							}
							if (leadDrawerBody) {
								leadDrawerBody.innerHTML = json.data.html;
							}
							bindTaskLeadPanelBehaviors();
						})
						.catch(function(error) {
							renderTaskLeadPanelError(error && error.message ? error.message : 'No se pudo cargar la ficha del lead.', leadId);
						});
				}

				function setTaskAiStatus(panel, message, type) {
					if (!panel) { return; }
					var statusNode = panel.querySelector('[data-twob-ai-status]');
					if (!statusNode) { return; }
					statusNode.textContent = message || '';
					statusNode.className = 'twob-task-ai-status' + (message ? (' is-' + (type || 'ok')) : '');
				}

				function renderTaskAiMessage(panel, data) {
					if (!panel || !data) { return; }
					var message = String(data.mensaje || '');
					var generatedLabel = String(data.generated_at_label || '');
					var messageBody = panel.querySelector('.twob-task-message-body');
					if (messageBody) {
						messageBody.textContent = message;
					}
					var copyBtn = panel.querySelector('.twob-copy-message-btn');
					if (copyBtn) {
						copyBtn.setAttribute('data-twob-copy-text', message);
					}
					var banner = panel.querySelector('.twob-task-ai-banner');
					if (!banner) {
						banner = document.createElement('div');
						banner.className = 'twob-task-ai-banner';
						var messageBox = panel.querySelector('.twob-task-message-box');
						if (messageBox && messageBody) {
							messageBox.insertBefore(banner, messageBody);
						}
					}
					if (banner) {
						banner.textContent = '✨ Personalizado con IA' + (generatedLabel ? ' · ' + generatedLabel : '');
						banner.setAttribute('title', generatedLabel ? ('Generado ' + generatedLabel) : 'Mensaje personalizado con IA');
					}
					var actionBtn = panel.querySelector('.twob-ai-generate-btn');
					if (actionBtn) {
						actionBtn.textContent = '↺ Regenerar versión IA';
					}
					var taskId = parseInt(panel.getAttribute('data-row-task-id') || panel.getAttribute('data-twob-task-detail-panel') || '0', 10) || 0;
					var row = taskId ? document.querySelector('[data-twob-task-row="' + taskId + '"]') : null;
					if (row) {
						row.setAttribute('data-task-message', message);
						var dueNode = row.querySelector('.twob-task-row-due');
						if (dueNode && !row.querySelector('.twob-badge-ai')) {
							var aiBadge = document.createElement('span');
							aiBadge.className = 'twob-badge twob-badge-ai';
							aiBadge.textContent = '✨ IA';
							row.insertBefore(aiBadge, dueNode);
						}
						var rowAiBadge = row.querySelector('.twob-badge-ai');
						if (rowAiBadge) {
							rowAiBadge.setAttribute('title', generatedLabel ? ('Generado ' + generatedLabel) : 'Mensaje personalizado con IA');
						}
					}
				}

				function requestTaskAiMessage(taskId, leadId, messageType) {
					var body = new URLSearchParams();
					body.append('action', 'twob_generar_mensaje_ia');
					body.append('nonce', '<?php echo esc_js($nonce); ?>');
					body.append('task_id', String(parseInt(taskId, 10) || 0));
					body.append('lead_id', String(parseInt(leadId, 10) || 0));
					body.append('tipo_mensaje', String(messageType || ''));
					return sendQuick(body).then(function(json) {
						if (!json || !json.success || !json.data) {
							var message = (json && json.data && json.data.message) ? json.data.message : 'No se pudo generar el mensaje.';
							throw new Error(message);
						}
						return json.data;
					});
				}

				function bindTaskDetailPanel(detailRoot) {
					if (!detailRoot) { return; }
					var aiBtn = detailRoot.querySelector('.twob-ai-generate-btn');
					if (aiBtn && aiBtn.dataset.twobAiBound !== '1') {
						aiBtn.dataset.twobAiBound = '1';
						aiBtn.addEventListener('click', function() {
							var panel = aiBtn.closest('[data-twob-task-detail-panel]');
							if (!panel) { return; }
							var taskId = aiBtn.getAttribute('data-twob-ai-generate-task');
							var leadId = aiBtn.getAttribute('data-lead-id');
							var messageType = aiBtn.getAttribute('data-message-type');
							setTaskAiStatus(panel, 'Generando mensaje personalizado...', 'loading');
							aiBtn.disabled = true;
							requestTaskAiMessage(taskId, leadId, messageType)
								.then(function(data) {
									renderTaskAiMessage(panel, data);
									setTaskAiStatus(panel, '✓ Mensaje personalizado generado.', 'ok');
								})
								.catch(function(error) {
									setTaskAiStatus(panel, error && error.message ? error.message : 'No se pudo generar el mensaje.', 'error');
								})
								.finally(function() {
									aiBtn.disabled = false;
								});
						});
					}
				}

				function loadTaskDetail(taskId, row) {
					taskId = parseInt(taskId, 10) || 0;
					if (!detail) { return; }
					if (!taskId) {
						detail.innerHTML = '<div class="twob-task-detail-empty">Selecciona una tarea para ver el mensaje listo</div>';
						return;
					}
					detail.innerHTML = '<div class="twob-task-detail-empty">Cargando detalle de la tarea...</div>';
					var body = new URLSearchParams();
					body.append('action', 'twob_crm_quick_action');
					body.append('nonce', '<?php echo esc_js($nonce); ?>');
					body.append('quick_action', 'load_task_panel');
					body.append('task_id', String(taskId));
					sendQuick(body)
						.then(function(json){
							if (!json || !json.success || !json.data || !json.data.html) {
								throw new Error((json && json.data && json.data.message) ? json.data.message : 'No se pudo cargar la tarea.');
							}
							detail.innerHTML = json.data.html;
							bindTaskDetailPanel(detail);
							if (row) {
								var panel = detail.querySelector('[data-twob-task-detail-panel]');
								if (panel) {
									panel.setAttribute('data-row-task-id', String(taskId));
									panel.setAttribute('data-row-lead-label', row.getAttribute('data-task-lead') || 'Lead');
								}
							}
						})
						.catch(function(error){
							detail.innerHTML = '<div class="twob-task-detail-empty">' + (error && error.message ? error.message : 'No se pudo cargar el detalle de la tarea.') + '</div>';
						});
				}

				function selectRow(row) {
					if (!workspace) { return; }
					workspace.querySelectorAll('[data-twob-task-row]').forEach(function(r) {
						r.classList.toggle('is-selected', r === row);
					});
					if (detail) {
						loadTaskDetail(row ? row.getAttribute('data-twob-task-row') : 0, row);
					}
				}

				function removeCompletedTaskRow(row) {
					if (!row) { return; }
					row.classList.add('is-completing');
					var metrics = document.querySelector('[data-twob-visible-count]');
					if (metrics) {
						var n = parseInt(metrics.getAttribute('data-twob-visible-count'), 10) || 0;
						n = Math.max(0, n - 1);
						metrics.setAttribute('data-twob-visible-count', String(n));
						var firstSpan = metrics.querySelector('span');
						if (firstSpan) { firstSpan.textContent = n + ' visibles'; }
					}
					setTimeout(function() {
						var next = row.nextElementSibling;
						row.remove();
						if (detail && workspace && workspace.contains(row)) {
							if (next && next.matches('[data-twob-task-row]')) { selectRow(next); }
							else {
								var first = workspace.querySelector('[data-twob-task-row]');
								selectRow(first || null);
							}
						}
					}, 280);
				}

				function completeTaskRow(row) {
					if (!row) { return; }
					var body = new URLSearchParams();
					body.append('action', 'twob_crm_quick_action');
					body.append('nonce', '<?php echo esc_js($nonce); ?>');
					body.append('quick_action', 'set_task_status');
					body.append('task_id', row.getAttribute('data-twob-task-row') || row.getAttribute('data-task-id') || '');
					body.append('task_status', 'done');
					row.classList.add('is-loading');
					sendQuick(body)
						.then(function(json) {
							if (!json || !json.success) {
								if (json && json.data && json.data.require_task_completion) {
									openInteractionModal(json.data.task || interactionContextFromTaskButton(row));
									return;
								}
								throw new Error((json && json.data && json.data.message) ? json.data.message : 'No se pudo marcar la tarea.');
							}
							removeCompletedTaskRow(row);
						})
						.catch(function(error) {
							alert(error && error.message ? error.message : 'No se pudo marcar la tarea.');
						})
						.finally(function() {
							row.classList.remove('is-loading');
						});
				}

				function showTaskCompleteConfirm(row) {
					if (!row || row.querySelector('.twob-task-complete-confirm')) { return; }
					var confirm = document.createElement('div');
					confirm.className = 'twob-task-complete-confirm';
					confirm.innerHTML = '¿Marcar como completada? <button type="button" class="button button-small" data-yes>Sí</button> <button type="button" class="button button-small" data-no>No</button>';
					row.appendChild(confirm);
					confirm.querySelector('[data-no]').addEventListener('click', function(ev) { ev.preventDefault(); ev.stopPropagation(); confirm.remove(); });
					confirm.querySelector('[data-yes]').addEventListener('click', function(ev) {
						ev.preventDefault();
						ev.stopPropagation();
						confirm.remove();
						completeTaskRow(row);
					});
				}

				function handleCompactTaskCompletion(row) {
					if (!row) { return; }
					if (row.getAttribute('data-task-guided') === '1') {
						completeTaskRow(row);
						return;
					}
					showTaskCompleteConfirm(row);
				}

				if (workspace) {
					workspace.addEventListener('click', function(e) {
						var confirmAction = e.target.closest('.twob-task-complete-confirm');
						if (confirmAction) { return; }
						var circle = e.target.closest('[data-twob-task-complete]');
						if (circle && workspace.contains(circle)) {
							e.preventDefault();
							e.stopPropagation();
							handleCompactTaskCompletion(circle.closest('[data-twob-task-row]'));
							return;
						}
						var row = e.target.closest('[data-twob-task-row]');
						if (row && workspace.contains(row)) {
							selectRow(row);
						}
					});
				}

				if (shouldBindGlobals) {
					document.addEventListener('click', function(e) {
					var copyBtn = e.target.closest('.twob-copy-message-btn');
					if (copyBtn) {
						e.preventDefault();
						copyButtonPayload(copyBtn).catch(function(){});
						return;
					}

					var compactCircle = e.target.closest('[data-twob-task-complete]');
					if (compactCircle) {
						var compactRow = compactCircle.closest('[data-twob-task-row]');
						if (compactRow) {
							e.preventDefault();
							e.stopPropagation();
							handleCompactTaskCompletion(compactRow);
							return;
						}
					}

					var dashboardRow = e.target.closest('.twob-dash-task-rows [data-twob-task-row]');
					if (dashboardRow && !e.target.closest('a,button,input,select,textarea,label')) {
						e.preventDefault();
						e.stopPropagation();
						handleCompactTaskCompletion(dashboardRow);
						return;
					}

					var openLeadBtn = e.target.closest('[data-open-lead-from-task]');
					if (openLeadBtn) {
						e.preventDefault();
						e.stopPropagation();
						var panelTitle = detail && detail.querySelector('.twob-task-detail-head strong') ? detail.querySelector('.twob-task-detail-head strong').textContent : 'Lead';
						openTaskLeadDrawer(openLeadBtn.getAttribute('data-open-lead-from-task'), panelTitle);
						return;
					}

					var bulkAiBtn = e.target.closest('.twob-ai-lead-regenerate-btn');
					if (bulkAiBtn) {
						e.preventDefault();
						var leadId = parseInt(bulkAiBtn.getAttribute('data-twob-ai-lead-regenerate') || '0', 10) || 0;
						var taskIds = String(bulkAiBtn.getAttribute('data-task-ids') || '').split(',').map(function(item){
							return parseInt(item, 10) || 0;
						}).filter(Boolean);
						var statusNode = bulkAiBtn.parentNode ? bulkAiBtn.parentNode.querySelector('[data-twob-ai-lead-status]') : null;
						if (!leadId || !taskIds.length) {
							if (statusNode) {
								statusNode.textContent = 'No hay tareas pendientes para actualizar.';
								statusNode.className = 'twob-task-ai-status is-error';
							}
							return;
						}
						bulkAiBtn.disabled = true;
						var done = 0;
						var failed = 0;
						function runNext(index) {
							if (index >= taskIds.length) {
								if (statusNode) {
									var summary = '✓ ' + done + ' mensajes actualizados';
									if (failed) {
										summary += ' · ' + failed + ' con error';
									}
									statusNode.textContent = summary;
									statusNode.className = 'twob-task-ai-status ' + (failed ? 'is-error' : 'is-ok');
								}
								bulkAiBtn.disabled = false;
								return;
							}
							if (statusNode) {
								statusNode.textContent = 'Actualizando tarea ' + (index + 1) + ' de ' + taskIds.length + '...';
								statusNode.className = 'twob-task-ai-status is-loading';
							}
							requestTaskAiMessage(taskIds[index], leadId, '')
								.then(function(data) {
									done += 1;
									var visiblePanel = document.querySelector('[data-twob-task-detail-panel][data-row-task-id="' + String(taskIds[index]) + '"]');
									if (visiblePanel) {
										renderTaskAiMessage(visiblePanel, data);
									}
								})
								.catch(function() {
									failed += 1;
								})
								.finally(function() {
									runNext(index + 1);
								});
						}
						runNext(0);
						return;
					}

					var allianceMsgBtn = e.target.closest('.twob-alianza-msg-generate');
					if (allianceMsgBtn) {
						e.preventDefault();
						var allianceCard = allianceMsgBtn.closest('.twob-card');
						var allianceId = allianceMsgBtn.getAttribute('data-alliance-id') || '';
						var msgStatus = allianceCard ? allianceCard.querySelector('[data-alianza-message-status]') : null;
						var msgBox = allianceCard ? allianceCard.querySelector('[data-alianza-message-box]') : null;
						var bodyMsg = new URLSearchParams();
						bodyMsg.append('action', 'twob_mensaje_alianza');
						bodyMsg.append('nonce', '<?php echo esc_js($nonce); ?>');
						bodyMsg.append('alliance_id', allianceId);
						allianceMsgBtn.disabled = true;
						if (msgStatus) {
							msgStatus.textContent = 'Generando mensaje de contacto...';
							msgStatus.className = 'twob-task-ai-status is-loading';
						}
						sendQuick(bodyMsg).then(function(json){
							if (!json || !json.success || !json.data) {
								throw new Error((json && json.data && json.data.message) ? json.data.message : 'No se pudo generar el mensaje.');
							}
							if (msgBox) {
								msgBox.value = json.data.mensaje || '';
							}
							if (msgStatus) {
								msgStatus.textContent = '✓ Mensaje generado' + (json.data.generated_at_label ? ' · ' + json.data.generated_at_label : '');
								msgStatus.className = 'twob-task-ai-status is-ok';
							}
						}).catch(function(error){
							if (msgStatus) {
								msgStatus.textContent = error && error.message ? error.message : 'No se pudo generar el mensaje.';
								msgStatus.className = 'twob-task-ai-status is-error';
							}
						}).finally(function(){
							allianceMsgBtn.disabled = false;
						});
						return;
					}

					var allianceBriefBtn = e.target.closest('.twob-alianza-brief-generate');
					if (allianceBriefBtn) {
						e.preventDefault();
						var briefCard = allianceBriefBtn.closest('.twob-card');
						var briefAllianceId = allianceBriefBtn.getAttribute('data-alliance-id') || '';
						var briefStatus = briefCard ? briefCard.querySelector('[data-alianza-brief-status]') : null;
						var shortBox = briefCard ? briefCard.querySelector('[data-alianza-brief-short]') : null;
						var emailBox = briefCard ? briefCard.querySelector('[data-alianza-brief-email]') : null;
						var pdfButton = briefCard ? briefCard.querySelector('.twob-alianza-brief-download') : null;
						var bodyBrief = new URLSearchParams();
						bodyBrief.append('action', 'twob_brief_alianza');
						bodyBrief.append('nonce', '<?php echo esc_js($nonce); ?>');
						bodyBrief.append('alliance_id', briefAllianceId);
						allianceBriefBtn.disabled = true;
						if (briefStatus) {
							briefStatus.textContent = 'Generando brief de alianza...';
							briefStatus.className = 'twob-task-ai-status is-loading';
						}
						sendQuick(bodyBrief).then(function(json){
							if (!json || !json.success || !json.data) {
								throw new Error((json && json.data && json.data.message) ? json.data.message : 'No se pudo generar el brief.');
							}
							if (shortBox) { shortBox.value = json.data.short || ''; }
							if (emailBox) { emailBox.value = json.data.email || ''; }
							if (pdfButton) {
								pdfButton.dataset.pdfBase64 = json.data.pdf_base64 || '';
								pdfButton.dataset.briefFilename = json.data.filename || pdfButton.getAttribute('data-brief-filename') || 'brief-alianza-2b.pdf';
							}
							if (briefStatus) {
								briefStatus.textContent = '✓ Brief generado en sus 3 formatos';
								briefStatus.className = 'twob-task-ai-status is-ok';
							}
						}).catch(function(error){
							if (briefStatus) {
								briefStatus.textContent = error && error.message ? error.message : 'No se pudo generar el brief.';
								briefStatus.className = 'twob-task-ai-status is-error';
							}
						}).finally(function(){
							allianceBriefBtn.disabled = false;
						});
						return;
					}

					var briefTab = e.target.closest('[data-brief-tab]');
					if (briefTab) {
						e.preventDefault();
						var tabsWrap = briefTab.closest('[data-twob-alianza-brief-tabs]');
						var panelsWrap = tabsWrap ? tabsWrap.nextElementSibling : null;
						var briefTabName = briefTab.getAttribute('data-brief-tab');
						if (!tabsWrap || !panelsWrap || !briefTabName) { return; }
						tabsWrap.querySelectorAll('[data-brief-tab]').forEach(function(button){
							button.classList.toggle('is-active', button === briefTab);
						});
						panelsWrap.querySelectorAll('[data-brief-panel]').forEach(function(panel){
							panel.classList.toggle('is-active', panel.getAttribute('data-brief-panel') === briefTabName);
						});
						return;
					}

					var briefDownloadBtn = e.target.closest('.twob-alianza-brief-download');
					if (briefDownloadBtn) {
						e.preventDefault();
						var pdfBase64 = briefDownloadBtn.dataset.pdfBase64 || '';
						if (!pdfBase64) {
							var briefStatusNode = briefDownloadBtn.closest('.twob-card') ? briefDownloadBtn.closest('.twob-card').querySelector('[data-alianza-brief-status]') : null;
							if (briefStatusNode) {
								briefStatusNode.textContent = 'Genera primero el brief para descargar el PDF.';
								briefStatusNode.className = 'twob-task-ai-status is-error';
							}
							return;
						}
						var link = document.createElement('a');
						link.href = 'data:application/pdf;base64,' + pdfBase64;
						link.download = briefDownloadBtn.dataset.briefFilename || 'brief-alianza-2b.pdf';
						document.body.appendChild(link);
						link.click();
						document.body.removeChild(link);
						return;
					}

					var referredBtn = e.target.closest('.twob-alianza-ref-create');
					if (referredBtn) {
						e.preventDefault();
						var refCard = referredBtn.closest('.twob-card');
						var refStatus = refCard ? refCard.querySelector('[data-alianza-ref-status]') : null;
						var refBody = new URLSearchParams();
						refBody.append('action', 'twob_registrar_referido_alianza');
						refBody.append('nonce', '<?php echo esc_js($nonce); ?>');
						refBody.append('alliance_id', referredBtn.getAttribute('data-alliance-id') || '');
						refBody.append('contact_name', refCard && refCard.querySelector('[data-alianza-ref-contact]') ? refCard.querySelector('[data-alianza-ref-contact]').value : '');
						refBody.append('company', refCard && refCard.querySelector('[data-alianza-ref-company]') ? refCard.querySelector('[data-alianza-ref-company]').value : '');
						refBody.append('website_url', refCard && refCard.querySelector('[data-alianza-ref-url]') ? refCard.querySelector('[data-alianza-ref-url]').value : '');
						refBody.append('notes', refCard && refCard.querySelector('[data-alianza-ref-notes]') ? refCard.querySelector('[data-alianza-ref-notes]').value : '');
						referredBtn.disabled = true;
						if (refStatus) {
							refStatus.textContent = 'Creando lead Pre-contacto...';
							refStatus.className = 'twob-task-ai-status is-loading';
						}
						sendQuick(refBody).then(function(json){
							if (!json || !json.success || !json.data) {
								throw new Error((json && json.data && json.data.message) ? json.data.message : 'No se pudo crear el referido.');
							}
							if (refStatus) {
								var linkHtml = json.data.lead_url ? ' <a href="' + json.data.lead_url + '">Abrir lead</a>' : '';
								refStatus.innerHTML = '✓ Lead creado — aparece en panel de Renata para revisión técnica.' + linkHtml;
								refStatus.className = 'twob-task-ai-status is-ok';
							}
							['[data-alianza-ref-contact]','[data-alianza-ref-company]','[data-alianza-ref-url]','[data-alianza-ref-notes]'].forEach(function(selector){
								var field = refCard ? refCard.querySelector(selector) : null;
								if (field) { field.value = ''; }
							});
						}).catch(function(error){
							if (refStatus) {
								refStatus.textContent = error && error.message ? error.message : 'No se pudo crear el referido.';
								refStatus.className = 'twob-task-ai-status is-error';
							}
						}).finally(function(){
							referredBtn.disabled = false;
						});
						return;
					}

					var allianceTaskBtn = e.target.closest('.twob-alliance-task-action');
					if (allianceTaskBtn) {
						e.preventDefault();
						var taskCard = allianceTaskBtn.closest('[data-alliance-task-id]');
						var taskStatusNode = taskCard ? taskCard.querySelector('[data-twob-alliance-status]') : null;
						var taskBody = new URLSearchParams();
						taskBody.append('action', 'twob_alianza_task_action');
						taskBody.append('nonce', '<?php echo esc_js($nonce); ?>');
						taskBody.append('task_id', allianceTaskBtn.getAttribute('data-task-id') || '');
						taskBody.append('task_action', allianceTaskBtn.getAttribute('data-task-action') || '');
						allianceTaskBtn.disabled = true;
						if (taskStatusNode) {
							taskStatusNode.textContent = 'Actualizando tarea...';
							taskStatusNode.className = 'twob-task-ai-status is-loading';
						}
						sendQuick(taskBody).then(function(json){
							if (!json || !json.success || !json.data) {
								throw new Error((json && json.data && json.data.message) ? json.data.message : 'No se pudo actualizar la tarea.');
							}
							if (taskStatusNode) {
								taskStatusNode.textContent = json.data.message || 'Tarea actualizada.';
								taskStatusNode.className = 'twob-task-ai-status is-ok';
							}
							if (taskCard) {
								taskCard.classList.add('is-completing');
								setTimeout(function(){
									taskCard.remove();
								}, 320);
							}
						}).catch(function(error){
							if (taskStatusNode) {
								taskStatusNode.textContent = error && error.message ? error.message : 'No se pudo actualizar la tarea.';
								taskStatusNode.className = 'twob-task-ai-status is-error';
							}
						}).finally(function(){
							allianceTaskBtn.disabled = false;
						});
					}
					});

					document.addEventListener('keydown', function(e) {
						var dashboardRow = e.target.closest ? e.target.closest('.twob-dash-task-rows [data-twob-task-row]') : null;
						if (!dashboardRow) {
							return;
						}
						if (e.key === 'Enter' || e.key === ' ') {
							e.preventDefault();
							handleCompactTaskCompletion(dashboardRow);
						}
					});
				}

				if (leadBackdrop) {
					leadBackdrop.addEventListener('click', function() { setTaskLeadDrawerOpen(false); });
				}
				var leadDrawerClose = document.querySelector('[data-twob-task-drawer-close]');
				if (leadDrawerClose) {
					leadDrawerClose.addEventListener('click', function() { setTaskLeadDrawerOpen(false); });
				}

				if (workspace) {
					workspace.querySelectorAll('[data-twob-task-row]').forEach(function(row) {
						row.addEventListener('keydown', function(e) {
							if (e.key === 'Enter' || e.key === ' ') {
