			function initAnthropicVerifier() {
				var verifyButton = document.getElementById('twob_verify_anthropic_key');
				var verifyInput = document.getElementById('twob_anthropic_api_key');
				var verifyStatus = document.getElementById('twob_anthropic_key_status');
				if (!verifyButton || !verifyInput || !verifyStatus || verifyButton.dataset.twobBound === '1') {
					return;
				}
				verifyButton.dataset.twobBound = '1';
				verifyButton.addEventListener('click', function() {
					var body = new URLSearchParams();
					body.append('action', 'twob_verify_anthropic_key');
					body.append('nonce', '<?php echo esc_js($nonce); ?>');
					body.append('api_key', verifyInput.value || '');
					verifyButton.disabled = true;
					verifyStatus.textContent = 'Verificando API key con Anthropic...';
					sendQuick(body)
						.then(function(json){
							if (!json || !json.success) {
								throw new Error((json && json.data && json.data.message) ? json.data.message : 'No se pudo verificar la API key.');
							}
							verifyStatus.textContent = (json.data && json.data.message) ? json.data.message : 'API key verificada correctamente.';
						})
						.catch(function(error){
							verifyStatus.textContent = error && error.message ? error.message : 'No se pudo verificar la API key.';
						})
						.finally(function(){
							verifyButton.disabled = false;
						});
				});
			}

