			function initLeadCardHelpers(){
				document.querySelectorAll('.twob-lead-accordion').forEach(function(card){
					var serviceSelect = card.querySelector('.twob-lead-service-interest');
					var valueInput = card.querySelector('.twob-lead-value');
					var originInput = card.querySelector('.twob-lead-origin-channel');
					var stageInput = card.querySelector('.twob-lead-stage');
					var temperatureInput = card.querySelector('.twob-lead-temperature');
					var allianceWrap = card.querySelector('[data-alliance-source-wrap]');
					if (serviceSelect && valueInput) {
						serviceSelect.addEventListener('change', function(){
							syncServiceValue(serviceSelect, valueInput, true);
						});
					}
					if (temperatureInput) {
						temperatureInput.addEventListener('change', function(){
							temperatureInput.dataset.userChanged = '1';
						});
					}
					if (originInput) {
						originInput.addEventListener('change', function(){
							toggleAllianceSourceWrap(originInput, allianceWrap);
							syncLeadTemperatureSelect(originInput, temperatureInput, stageInput);
						});
						toggleAllianceSourceWrap(originInput, allianceWrap);
					}
					if (stageInput) {
						stageInput.dataset.previousValue = stageInput.value || '';
						stageInput.addEventListener('change', function(){
							syncLeadTemperatureSelect(originInput, temperatureInput, stageInput);
							refreshLostReasonUI(card);
							if (stageInput.value === 'lost') {
								var lostInput = card.querySelector('.twob-lead-lost-reason');
								if (!lostInput || !(lostInput.value || '').trim()) {
									openLostReasonModal({
										leadCard: card,
										leadTitle: card.querySelector('.twob-lead-name') ? card.querySelector('.twob-lead-name').value : '',
										leadCompany: card.querySelector('.twob-lead-company') ? card.querySelector('.twob-lead-company').value : '',
										initialReason: '',
										onCancel: function(){
											stageInput.value = stageInput.dataset.previousValue || 'contacted';
											refreshLostReasonUI(card);
										},
										onConfirm: function(){
											stageInput.dataset.previousValue = 'lost';
										}
									});
									return;
								}
							}
							stageInput.dataset.previousValue = stageInput.value || '';
						});
					}
					var lostReasonButton = card.querySelector('.twob-open-lost-reason');
					if (lostReasonButton) {
						lostReasonButton.addEventListener('click', function(){
							openLostReasonModal({
								leadCard: card,
								leadTitle: card.querySelector('.twob-lead-name') ? card.querySelector('.twob-lead-name').value : '',
								leadCompany: card.querySelector('.twob-lead-company') ? card.querySelector('.twob-lead-company').value : '',
								initialReason: card.querySelector('.twob-lead-lost-reason') ? card.querySelector('.twob-lead-lost-reason').value : ''
							});
						});
					}
					syncLeadTemperatureSelect(originInput, temperatureInput, stageInput);
					refreshLostReasonUI(card);
				});
			}

			initLeadCardHelpers();

			var lostReasonModal = null;
			var lostReasonModalState = {};

			function refreshLostReasonUI(leadCard){
				if (!leadCard) { return; }
				var summary = leadCard.querySelector('[data-lost-reason-summary]');
				var reasonInput = leadCard.querySelector('.twob-lead-lost-reason');
				var display = summary ? summary.querySelector('.twob-lost-reason-display') : null;
				var button = summary ? summary.querySelector('.twob-open-lost-reason') : null;
				var stageInput = leadCard.querySelector('.twob-lead-stage');
				var isLost = !!(stageInput && stageInput.value === 'lost');
				var reason = reasonInput ? String(reasonInput.value || '').trim() : '';
				if (summary) {
					summary.hidden = !isLost && !reason;
				}
				if (display) {
					display.textContent = reason || 'Pendiente por registrar.';
				}
				if (button) {
					button.textContent = reason ? 'Editar motivo' : 'Registrar motivo';
				}
			}

			function ensureLostReasonModal(){
				if (lostReasonModal) { return lostReasonModal; }
				var backdrop = document.createElement('div');
				backdrop.className = 'twob-modal-backdrop';
				backdrop.innerHTML = '' +
					'<div class="twob-modal" role="dialog" aria-modal="true" aria-labelledby="twobLostReasonModalTitle">' +
						'<div class="twob-modal-head">' +
							'<div>' +
								'<h3 id="twobLostReasonModalTitle">Registrar motivo de perdida</h3>' +
								'<div class="twob-line-2" id="twobLostReasonModalSubtitle"></div>' +
							'</div>' +
							'<button type="button" class="twob-modal-close" aria-label="Cerrar">×</button>' +
						'</div>' +
						'<div class="twob-modal-status" id="twobLostReasonModalStatus"></div>' +
						'<div class="twob-form-row">' +
							'<label>Motivo de perdida</label>' +
							'<textarea id="twob_lost_reason_value" rows="5" placeholder="Ej: no tenia presupuesto / ya trabaja con agencia / urgencia baja / no respondio despues de reunion"></textarea>' +
							'<small class="twob-form-help">Este motivo queda guardado para medir despues por que se perdieron los leads.</small>' +
						'</div>' +
						'<div class="twob-modal-footer">' +
							'<button type="button" class="button" id="twob_lost_reason_cancel">Cancelar</button>' +
							'<button type="button" class="button button-primary" id="twob_lost_reason_submit">Guardar motivo</button>' +
						'</div>' +
					'</div>';
				document.body.appendChild(backdrop);

				lostReasonModal = {
					backdrop: backdrop,
					subtitle: backdrop.querySelector('#twobLostReasonModalSubtitle'),
					status: backdrop.querySelector('#twobLostReasonModalStatus'),
					textarea: backdrop.querySelector('#twob_lost_reason_value'),
					cancel: backdrop.querySelector('#twob_lost_reason_cancel'),
					submit: backdrop.querySelector('#twob_lost_reason_submit'),
					close: backdrop.querySelector('.twob-modal-close')
				};

				function setStatus(message, type){
					lostReasonModal.status.textContent = message || '';
					lostReasonModal.status.className = 'twob-modal-status' + (message ? (' is-' + (type || 'error')) : '');
				}

				function closeModal(runCancel){
					if (!lostReasonModal) { return; }
					lostReasonModal.backdrop.classList.remove('is-open');
					lostReasonModal.submit.disabled = false;
					setStatus('', '');
					if (runCancel && typeof lostReasonModalState.onCancel === 'function') {
						lostReasonModalState.onCancel();
					}
					lostReasonModalState = {};
				}

				lostReasonModal.close.addEventListener('click', function(){ closeModal(true); });
				lostReasonModal.cancel.addEventListener('click', function(){ closeModal(true); });
				lostReasonModal.backdrop.addEventListener('click', function(event){
					if (event.target === lostReasonModal.backdrop) {
						closeModal(true);
					}
				});
				lostReasonModal.submit.addEventListener('click', function(){
					var reason = String(lostReasonModal.textarea.value || '').trim();
					if (!reason) {
						setStatus('Debes escribir el motivo para medir la perdida despues.', 'error');
						return;
					}
					if (lostReasonModalState.leadCard) {
						var hiddenInput = lostReasonModalState.leadCard.querySelector('.twob-lead-lost-reason');
						if (hiddenInput) {
							hiddenInput.value = reason;
						}
						refreshLostReasonUI(lostReasonModalState.leadCard);
					}
					var onConfirm = lostReasonModalState.onConfirm;
					closeModal(false);
					if (typeof onConfirm === 'function') {
						onConfirm(reason);
					}
				});

				lostReasonModal.setStatus = setStatus;
				lostReasonModal.closeModal = closeModal;
				return lostReasonModal;
			}

			function openLostReasonModal(context){
				var modal = ensureLostReasonModal();
				lostReasonModalState = context || {};
				var leadTitle = context && context.leadTitle ? context.leadTitle : 'este lead';
				var leadCompany = context && context.leadCompany ? context.leadCompany : '';
				modal.subtitle.textContent = leadCompany ? (leadTitle + ' | ' + leadCompany) : leadTitle;
				modal.textarea.value = context && context.initialReason ? context.initialReason : '';
				modal.setStatus('', '');
				modal.submit.disabled = false;
				modal.backdrop.classList.add('is-open');
				window.setTimeout(function(){ modal.textarea.focus(); }, 30);
			}

			function suggestedInteractionAction(kind, channel){
				if (channel === 'meeting') { return 'meeting_held'; }
				if (channel === 'call') { return 'phone_call'; }
				if (channel === 'email') { return 'email_sent'; }
				if (channel === 'whatsapp') { return 'whatsapp_message'; }
				if (channel === 'linkedin') { return kind === 'followup' ? 'linkedin_followup' : 'linkedin_message'; }
				return 'other';
			}

			function responseReceivedAction(channel){
				if (channel === 'email') { return 'email_reply_received'; }
				if (channel === 'whatsapp') { return 'whatsapp_reply_received'; }
				if (channel === 'call' || channel === 'meeting') { return 'call_received'; }
				return 'linkedin_reply_received';
			}

			function suggestedStageFromResult(result, currentStage){
				if (result === 'meeting_booked') { return 'meeting_scheduled'; }
				if (result === 'interested') {
					if (['meeting_scheduled', 'meeting_done', 'proposal_sent', 'won'].indexOf(currentStage) >= 0) {
						return currentStage;
					}
					return 'responded_interested';
				}
				if (result === 'rejected') { return 'lost'; }
				return '';
			}

			var interactionModal = null;
			var interactionModalState = {};

			function populateSelect(select, options, allowEmptyLabel){
				if (!select) { return; }
				select.innerHTML = '';
				if (allowEmptyLabel) {
					var emptyOption = document.createElement('option');
					emptyOption.value = '';
					emptyOption.textContent = allowEmptyLabel;
					select.appendChild(emptyOption);
				}
				Object.keys(options || {}).forEach(function(key){
					var option = document.createElement('option');
					option.value = key;
					option.textContent = options[key];
					select.appendChild(option);
				});
			}

