					note: backdrop.querySelector('#twob_modal_note'),
					submit: backdrop.querySelector('#twob_modal_submit'),
					cancel: backdrop.querySelector('#twob_modal_cancel'),
					close: backdrop.querySelector('.twob-modal-close')
				};

				populateSelect(interactionModal.kind, {contact: 'Contacto', followup: 'Seguimiento'});
				populateSelect(interactionModal.channel, channelLabels);
				populateSelect(interactionModal.action, interactionActionLabels);
				populateSelect(interactionModal.result, interactionResultLabels);
				populateSelect(interactionModal.stage, stageLabels, 'Sin cambio');

				function syncModalAction(force, explicitAction){
					if (!interactionModal) { return; }
					var suggested = suggestedInteractionAction(interactionModal.kind.value, interactionModal.channel.value);
					var lastAuto = interactionModal.action.getAttribute('data-auto-value') || '';
					if (explicitAction) {
						interactionModal.action.value = explicitAction;
					} else if (force || !interactionModal.action.value || interactionModal.action.value === lastAuto) {
						interactionModal.action.value = suggested;
					}
					interactionModal.action.setAttribute('data-auto-value', explicitAction || suggested);
				}

				function syncModalStageSuggestion(force){
					if (!interactionModal) { return; }
					var currentStage = interactionModalState.currentStage || '';
					var suggestion = suggestedStageFromResult(interactionModal.result.value, currentStage);
					var lastAuto = interactionModal.stage.getAttribute('data-auto-stage') || '';
					if (force || !interactionModal.stage.value || interactionModal.stage.value === lastAuto) {
						interactionModal.stage.value = suggestion;
					}
					interactionModal.stage.setAttribute('data-auto-stage', suggestion);
				}

				function setModalStatus(message, type){
					if (!interactionModal) { return; }
					interactionModal.status.textContent = message || '';
					interactionModal.status.className = 'twob-modal-status' + (message ? (' is-' + (type || 'error')) : '');
				}

				function closeInteractionModal(){
					if (!interactionModal) { return; }
					interactionModal.backdrop.classList.remove('is-open');
					interactionModal.submit.disabled = false;
					setModalStatus('', '');
					if (interactionModal.history) {
						interactionModal.history.innerHTML = '';
					}
				}

				function submitInteractionModal(){
					if (!interactionModal) { return; }
					var note = (interactionModal.note.value || '').trim();
					var stageAfter = interactionModal.stage.value || suggestedStageFromResult(interactionModal.result.value, interactionModalState.currentStage || '') || (interactionModalState.currentStage || '');
					var requiresNext = stageAfter !== 'lost';
					if (interactionModalState.mode === 'task' && !note) {
						setModalStatus('Debes dejar una nota breve antes de cerrar esta tarea.', 'error');
						return;
					}
					if (interactionModalState.mode === 'task' && requiresNext && !interactionModal.nextFollowup.value) {
						setModalStatus('Debes dejar la proxima fecha antes de completar esta tarea comercial.', 'error');
						return;
					}

					var body = new URLSearchParams();
					body.append('action', 'twob_crm_quick_action');
					body.append('nonce', '<?php echo esc_js($nonce); ?>');
					if (interactionModalState.mode === 'task') {
						body.append('quick_action', 'set_task_status');
						body.append('task_id', interactionModalState.taskId || '0');
						body.append('task_status', 'done');
						body.append('interaction_kind', interactionModal.kind.value);
						body.append('interaction_channel', interactionModal.channel.value);
						body.append('interaction_action', interactionModal.action.value);
						body.append('interaction_result', interactionModal.result.value);
						body.append('interaction_stage', interactionModal.stage.value);
						body.append('interaction_date', interactionModal.date.value);
						body.append('next_followup', interactionModal.nextFollowup.value);
						body.append('interaction_note', note);
					} else {
						body.append('quick_action', 'add_interaction_detailed');
						body.append('lead_id', interactionModalState.leadId || '0');
						body.append('task_id', interactionModalState.taskId || '0');
						body.append('kind', interactionModal.kind.value);
						body.append('channel', interactionModal.channel.value);
						body.append('interaction_action', interactionModal.action.value);
						body.append('result', interactionModal.result.value);
						body.append('stage', interactionModal.stage.value);
						body.append('interaction_date', interactionModal.date.value);
						body.append('next_followup', interactionModal.nextFollowup.value);
						body.append('note', note);
					}

					interactionModal.submit.disabled = true;
					setModalStatus('', '');
					sendQuick(body)
						.then(function(json){
							if (!json || !json.success) {
								setModalStatus(json && json.data && json.data.message ? json.data.message : 'No se pudo guardar la gestion.', 'error');
								interactionModal.submit.disabled = false;
								return;
							}
							setModalStatus(json.data && json.data.message ? json.data.message : 'Gestion guardada.', 'ok');
							window.setTimeout(function(){ window.location.reload(); }, 300);
						})
						.catch(function(){
							setModalStatus('No se pudo guardar la gestion.', 'error');
							interactionModal.submit.disabled = false;
						});
				}

				interactionModal.channel.addEventListener('change', function(){ syncModalAction(false, ''); });
				interactionModal.kind.addEventListener('change', function(){ syncModalAction(false, ''); });
				interactionModal.result.addEventListener('change', function(){ syncModalStageSuggestion(false); });
				interactionModal.cancel.addEventListener('click', closeInteractionModal);
				interactionModal.close.addEventListener('click', closeInteractionModal);
				interactionModal.submit.addEventListener('click', submitInteractionModal);
				backdrop.addEventListener('click', function(event){
					if (event.target === backdrop) {
						closeInteractionModal();
					}
				});

				interactionModal.syncAction = syncModalAction;
				interactionModal.syncStageSuggestion = syncModalStageSuggestion;
				interactionModal.setStatus = setModalStatus;
				interactionModal.closeModal = closeInteractionModal;
				return interactionModal;
			}

			function openInteractionModal(context){
				var modal = ensureInteractionModal();
				context = context || {};
				interactionModalState = {
					mode: context.mode || (context.guided ? 'task' : 'interaction'),
					taskId: context.taskId || context.task_id || '',
					leadId: context.leadId || context.lead_id || '',
					currentStage: context.currentStage || context.current_stage || '',
					taskTitle: context.taskTitle || context.task_title || '',
					leadTitle: context.leadTitle || context.lead_title || ''
				};
				modal.title.textContent = interactionModalState.mode === 'task' ? 'Registrar gestion y cerrar tarea' : 'Registrar interaccion';
				modal.subtitle.textContent = interactionModalState.mode === 'task'
					? ((interactionModalState.taskTitle || 'Tarea comercial') + (interactionModalState.leadTitle ? ' | ' + interactionModalState.leadTitle : ''))
					: (interactionModalState.leadTitle || 'Lead');
					modal.hint.textContent = interactionModalState.mode === 'task'
						? 'Este registro completara la tarea solo si la gestion realmente cuenta: contacto directo o una accion social valida con resultado claro. Revisar perfil sin gestion no la cierra.'
						: ((context.defaultResult || context.default_result)
							? 'Si el lead ya respondio, registra aqui la respuesta recibida y el siguiente paso que hara Dani.'
							: 'Registra la gestion real, directa o suave, el resultado y, si corresponde, la siguiente fecha de seguimiento.');
				modal.kind.value = context.defaultKind || context.default_kind || 'followup';
				modal.channel.value = context.defaultChannel || context.default_channel || 'linkedin';
				modal.result.value = context.defaultResult || context.default_result || 'other';
				modal.date.value = context.date || todayValue;
				modal.nextFollowup.value = context.nextFollowup || context.next_followup || '';
				modal.note.value = context.note || '';
				modal.stage.value = context.currentStage || context.current_stage || '';
				var cycleLabel = context.cycleLabel || context.cycle_label || '';
				var taskLabel = context.taskLabel || context.task_label || interactionModalState.taskTitle || 'Tarea comercial';
				var leadBits = [
					interactionModalState.leadTitle || context.leadTitle || context.lead_title || 'Lead',
					context.company || context.leadCompany || context.lead_company || ''
				].filter(Boolean);
				if (modal.context) {
					modal.context.hidden = false;
				}
				if (modal.taskMeta) {
					modal.taskMeta.textContent = [cycleLabel, taskLabel].filter(Boolean).join(' · ') || taskLabel;
				}
				if (modal.leadMeta) {
					modal.leadMeta.textContent = leadBits.join(' · ');
				}
				var recentInteractions = Array.isArray(context.recentInteractions) ? context.recentInteractions : (Array.isArray(context.recent_interactions) ? context.recent_interactions : []);
				if (modal.history) {
					if (recentInteractions.length) {
						modal.history.innerHTML = recentInteractions.map(function(item) {
							var summary = item && item.summary ? String(item.summary) : '';
							return '<div class="twob-modal-history-item">' + summary.replace(/</g, '&lt;').replace(/>/g, '&gt;') + '</div>';
						}).join('');
					} else {
						modal.history.innerHTML = '<div class="twob-modal-history-item is-empty">Aun no hay interacciones previas registradas para este lead.</div>';
					}
				}
				if (modal.historyWrap) {
					modal.historyWrap.hidden = false;
				}
				modal.syncAction(true, context.defaultAction || context.default_action || '');
				modal.syncStageSuggestion(true);
				modal.submit.textContent = interactionModalState.mode === 'task' ? 'Guardar gestion y completar tarea' : 'Guardar interaccion';
				modal.setStatus('', '');
				modal.submit.disabled = false;
				modal.backdrop.classList.add('is-open');
				window.setTimeout(function(){ modal.note.focus(); }, 30);
			}

				function interactionContextFromLeadButton(btn, leadCard, action, currentStage){
					return {
						mode: 'interaction',
						taskId: btn.getAttribute('data-task-id') || '0',
						leadId: btn.getAttribute('data-lead-id') || (leadCard ? leadCard.getAttribute('data-lead-id') : '0'),
						leadTitle: btn.getAttribute('data-lead-title') || (leadCard ? ((leadCard.querySelector('strong') || {}).textContent || '') : ''),
						currentStage: currentStage || '',
					defaultKind: action === 'log_contact' ? 'contact' : 'followup',
					defaultChannel: btn.getAttribute('data-default-channel') || 'linkedin',
					defaultAction: btn.getAttribute('data-default-action') || suggestedInteractionAction(action === 'log_contact' ? 'contact' : 'followup', btn.getAttribute('data-default-channel') || 'linkedin'),
					defaultResult: btn.getAttribute('data-default-result') || '',
					nextFollowup: btn.getAttribute('data-next-followup') || ''
				};
			}

			function interactionContextFromTaskButton(btn){
				return {
					mode: 'task',
					taskId: btn.getAttribute('data-task-id') || '0',
					taskTitle: btn.getAttribute('data-task-title') || '',
					leadId: btn.getAttribute('data-lead-id') || '0',
					leadTitle: btn.getAttribute('data-lead-title') || '',
					company: btn.getAttribute('data-task-company') || '',
					currentStage: btn.getAttribute('data-current-stage') || '',
					defaultKind: btn.getAttribute('data-default-kind') || 'followup',
					defaultChannel: btn.getAttribute('data-default-channel') || 'linkedin',
					defaultAction: btn.getAttribute('data-default-action') || '',
					nextFollowup: btn.getAttribute('data-next-followup') || ''
				};
			}

			function executeLeadCardAction(btn, forcedLostReason){
				var leadCard = btn.closest('[data-lead-id]');
				var leadId = btn.getAttribute('data-lead-id') || (leadCard ? leadCard.getAttribute('data-lead-id') : 0);
				var action = btn.getAttribute('data-action');
				var stage = '';
				var stageSelect = leadCard ? leadCard.querySelector('.twob-stage-select, .twob-lead-stage') : null;
				var lostReasonInput = leadCard ? leadCard.querySelector('.twob-lead-lost-reason') : null;
				var existingLostReason = lostReasonInput ? String(lostReasonInput.value || '').trim() : '';
				if (stageSelect) { stage = stageSelect.value; }
				if (typeof forcedLostReason === 'string' && lostReasonInput) {
					lostReasonInput.value = forcedLostReason;
					existingLostReason = forcedLostReason.trim();
					refreshLostReasonUI(leadCard);
				}

				if (stage === 'lost' && !existingLostReason && (action === 'update_lead_card' || action === 'set_stage')) {
					openLostReasonModal({
						leadCard: leadCard,
						leadTitle: leadCard && leadCard.querySelector('.twob-lead-name') ? leadCard.querySelector('.twob-lead-name').value : '',
						leadCompany: leadCard && leadCard.querySelector('.twob-lead-company') ? leadCard.querySelector('.twob-lead-company').value : '',
						initialReason: '',
						onConfirm: function(reason){
							executeLeadCardAction(btn, reason);
						}
					});
					return;
				}

				if (action === 'log_contact' || action === 'log_followup') {
					openInteractionModal(interactionContextFromLeadButton(btn, leadCard, action, stage));
					return;
				}

				var body = new URLSearchParams();
				body.append('action', 'twob_crm_quick_action');
				body.append('nonce', '<?php echo esc_js($nonce); ?>');
				body.append('quick_action', action);
				body.append('lead_id', leadId);
				body.append('stage', stage);
				if ('set_stage' === action && stage === 'lost') {
					body.append('lost_reason', existingLostReason);
				}
				if ('update_lead_card' === action && leadCard) {
					var nameInput = leadCard.querySelector('.twob-lead-name');
					var nextInput = leadCard.querySelector('.twob-lead-next');
					var companyInput = leadCard.querySelector('.twob-lead-company');
					var emailInput = leadCard.querySelector('.twob-lead-email');
					var phoneInput = leadCard.querySelector('.twob-lead-phone');
					var employeeCountInput = leadCard.querySelector('.twob-lead-employee-count');
					var budgetInput = leadCard.querySelector('.twob-lead-budget');
					var valueInput = leadCard.querySelector('.twob-lead-value');
					var websiteInput = leadCard.querySelector('.twob-lead-website-url');
					var linkedinPersonInput = leadCard.querySelector('.twob-lead-linkedin-person');
					var linkedinCompanyInput = leadCard.querySelector('.twob-lead-linkedin-company');
					var originInput = leadCard.querySelector('.twob-lead-origin-channel');
					var typeInput = leadCard.querySelector('.twob-lead-client-type');
					var serviceInput = leadCard.querySelector('.twob-lead-service-interest');
					var temperatureInput = leadCard.querySelector('.twob-lead-temperature');
					var technicalFindingInput = leadCard.querySelector('.twob-lead-technical-finding');
					var allianceSourceInput = leadCard.querySelector('.twob-lead-alliance-source');
					var observationsInput = leadCard.querySelector('.twob-lead-observations');
					body.append('lead_name', nameInput ? nameInput.value : '');
					body.append('next_followup', nextInput ? nextInput.value : '');
					body.append('company', companyInput ? companyInput.value : '');
					body.append('email', emailInput ? emailInput.value : '');
					body.append('phone', phoneInput ? phoneInput.value : '');
					body.append('employee_count', employeeCountInput ? employeeCountInput.value : '');
					body.append('budget', budgetInput ? budgetInput.value : '');
					body.append('value', valueInput ? valueInput.value : '');
					body.append('website_url', websiteInput ? websiteInput.value : '');
					body.append('linkedin_person', linkedinPersonInput ? linkedinPersonInput.value : '');
					body.append('linkedin_company', linkedinCompanyInput ? linkedinCompanyInput.value : '');
					body.append('origin_channel', originInput ? originInput.value : '');
					body.append('client_type', typeInput ? typeInput.value : '');
					body.append('service_interest', serviceInput ? serviceInput.value : '');
					body.append('temperature', temperatureInput ? temperatureInput.value : '');
					body.append('temperature_manual', temperatureInput && temperatureInput.dataset.userChanged === '1' ? '1' : '');
					body.append('technical_finding', technicalFindingInput ? technicalFindingInput.value : '');
					body.append('alliance_source', allianceSourceInput ? allianceSourceInput.value : '');
					body.append('observations', observationsInput ? observationsInput.value : '');
					body.append('lost_reason', existingLostReason);
				}
				if ('save_technical_finding' === action) {
					var findingInput = leadCard ? leadCard.querySelector('.twob-dashboard-finding-input, .twob-lead-technical-finding') : null;
					var findingValue = findingInput ? String(findingInput.value || '').trim() : '';
					var findingFlag = leadCard ? leadCard.querySelector('.twob-review-finding-flag') : null;
					if (!findingValue) {
						alert('Escribe un hallazgo antes de guardar.');
						return;
					}
					body.append('technical_finding', findingValue);
					btn.disabled = true;
					sendQuick(body)
						.then(function(json){
							if (!json || !json.success) {
								alert(json && json.data && json.data.message ? json.data.message : 'No se pudo guardar el hallazgo.');
								btn.disabled = false;
								return;
							}
							if (findingFlag) {
								findingFlag.classList.remove('is-warning', 'is-soft');
								findingFlag.classList.add('is-ready');
								findingFlag.textContent = 'Hallazgo listo';
							}
							btn.textContent = 'Hallazgo guardado';
							window.setTimeout(function(){
								btn.disabled = false;
								btn.textContent = 'Actualizar hallazgo';
							}, 800);
						})
						.catch(function(){
							alert('No se pudo guardar el hallazgo.');
							btn.disabled = false;
						});
					return;
				}
				if ('activate_precontact' === action) {
					var leadName = btn.getAttribute('data-lead-name') || (leadCard && leadCard.querySelector('.twob-lead-name') ? leadCard.querySelector('.twob-lead-name').value : '') || (leadCard && leadCard.querySelector('strong') ? leadCard.querySelector('strong').textContent : 'este lead');
					var leadCompany = btn.getAttribute('data-lead-company') || (leadCard && leadCard.querySelector('.twob-lead-company') ? leadCard.querySelector('.twob-lead-company').value : '') || 'esta empresa';
					var firstContactChannel = btn.getAttribute('data-first-contact-channel') || btn.getAttribute('data-default-channel') || (leadCard && leadCard.querySelector('.twob-lead-origin-channel') ? leadCard.querySelector('.twob-lead-origin-channel').value : '');
					if (!window.confirm('¿Confirmas que enviaste el primer mensaje a ' + leadName + ' de ' + leadCompany + '?')) {
						return;
					}
					body.append('first_contact_channel', firstContactChannel);
				}

				btn.disabled = true;
				sendQuick(body)
					.then(function(json){
						if (!json || !json.success) {
							alert(json && json.data && json.data.message ? json.data.message : 'No se pudo ejecutar la accion.');
							btn.disabled = false;
							return;
						}
						alert(json.data && json.data.message ? json.data.message : 'Accion ejecutada');
						window.location.reload();
					})
					.catch(function(){
						alert('No se pudo ejecutar la accion.');
						btn.disabled = false;
					});
			}

			document.querySelectorAll('.twob-btn').forEach(function(btn){
				btn.addEventListener('click', function(e){
					e.preventDefault();
					executeLeadCardAction(btn);
				});
			});

			document.querySelectorAll('.twob-task-done').forEach(function(cb){
				cb.addEventListener('change', function(){
					if (!cb.checked) { return; }
					var taskId = cb.getAttribute('data-task-id');
					if (!taskId) { return; }
					var body = new URLSearchParams();
					body.append('action', 'twob_crm_quick_action');
					body.append('nonce', '<?php echo esc_js($nonce); ?>');
					body.append('quick_action', 'set_task_status');
					body.append('task_id', taskId);
					body.append('task_status', 'done');
					sendQuick(body)
						.then(function(json){
							if (!json || !json.success) {
								if (json && json.data && json.data.require_task_completion) {
									openInteractionModal(json.data.task || interactionContextFromTaskButton(cb));
									return;
								}
								alert(json && json.data && json.data.message ? json.data.message : 'No se pudo marcar la tarea.');
								return;
							}
							alert(json.data && json.data.message ? json.data.message : 'Tarea actualizada');
							window.location.reload();
						})
						.catch(function(){ alert('No se pudo marcar la tarea.'); });
				});
			});

			var addLeadObsBtn = document.getElementById('twob_add_lead_observation');
			if (addLeadObsBtn) {
				addLeadObsBtn.addEventListener('click', function(){
					var wrap = document.getElementById('twob_lead_observations_wrap');
					if (!wrap) { return; }
					var area = document.createElement('textarea');
					area.className = 'twob-lead-observation';
					area.rows = 2;
					area.placeholder = 'Observacion adicional';
					wrap.appendChild(area);
				});
			}

				var createLeadBtn = document.getElementById('twob_create_lead');
				if (createLeadBtn) {
					createLeadBtn.addEventListener('click', function(){
						var creationMode = currentLeadCreationMode();
						var name = document.getElementById('twob_lead_name').value.trim();
						var company = document.getElementById('twob_lead_company') ? document.getElementById('twob_lead_company').value.trim() : '';
						var email = document.getElementById('twob_lead_email') ? document.getElementById('twob_lead_email').value : '';
						var phone = document.getElementById('twob_lead_phone') ? document.getElementById('twob_lead_phone').value : '';
						var employeeCount = document.getElementById('twob_lead_employee_count') ? document.getElementById('twob_lead_employee_count').value : '';
						var budget = document.getElementById('twob_lead_budget') ? document.getElementById('twob_lead_budget').value : '';
						var value = document.getElementById('twob_lead_value') ? document.getElementById('twob_lead_value').value : '';
						var websiteUrl = document.getElementById('twob_lead_website_url') ? document.getElementById('twob_lead_website_url').value.trim() : '';
						var linkedinPerson = document.getElementById('twob_lead_linkedin_person') ? document.getElementById('twob_lead_linkedin_person').value : '';
						var linkedinCompany = document.getElementById('twob_lead_linkedin_company') ? document.getElementById('twob_lead_linkedin_company').value : '';
						var originChannel = document.getElementById('twob_lead_origin_channel') ? document.getElementById('twob_lead_origin_channel').value : '';
						var next = document.getElementById('twob_lead_next_followup') ? document.getElementById('twob_lead_next_followup').value : '';
						var sequencePolicy = sequencePolicyForOrigin(originChannel);
						if (creationMode !== 'pre_contact' && !next && sequencePolicy !== 'manual') {
							next = defaultDay3Value();
						}
						var firstContactChannel = document.getElementById('twob_lead_first_contact_channel') ? document.getElementById('twob_lead_first_contact_channel').value : 'linkedin';
						var clientType = document.getElementById('twob_lead_client_type') ? document.getElementById('twob_lead_client_type').value : '';
						var serviceInterest = document.getElementById('twob_lead_service_interest') ? document.getElementById('twob_lead_service_interest').value : '';
					var technicalFinding = document.getElementById('twob_lead_technical_finding') ? document.getElementById('twob_lead_technical_finding').value : '';
						var allianceSource = document.getElementById('twob_lead_alliance_source') ? document.getElementById('twob_lead_alliance_source').value : '';
						var createTaskNow = document.getElementById('twob_lead_create_task_now') ? (document.getElementById('twob_lead_create_task_now').checked ? '1' : '') : '';
						var observations = Array.prototype.slice.call(document.querySelectorAll('#twob_lead_observations_wrap .twob-lead-observation')).map(function(el){ return (el.value || '').trim(); }).filter(function(v){ return v; }).join('\n\n');
						if (!name) { alert('Nombre requerido'); return; }
						if (creationMode === 'pre_contact') {
							if (!company || !websiteUrl || !originChannel) {
								alert('Para Pre-contacto completa Empresa, Sitio web y Canal origen.');
								return;
							}
							next = '';
						} else {
							if (!originChannel || !clientType || !serviceInterest) { alert('Completa canal de origen, tipo de cliente y servicio de interes.'); return; }
							if (!firstContactChannel) { alert('Selecciona el canal real del primer contacto.'); return; }
						}
						var body = new URLSearchParams();
						body.append('action', 'twob_crm_quick_action');
						body.append('nonce', '<?php echo esc_js($nonce); ?>');
						body.append('quick_action', 'add_lead');
						body.append('creation_mode', creationMode);
						body.append('lead_name', name);
						body.append('next_followup', next);
						body.append('company', company);
					body.append('email', email);
					body.append('phone', phone);
					body.append('employee_count', employeeCount);
					body.append('budget', budget);
					body.append('value', value);
					body.append('website_url', websiteUrl);
					body.append('linkedin_person', linkedinPerson);
