					var interactionLeadSelect = document.getElementById('twob_interaction_lead');
					var interactionLeadSearch = document.getElementById('twob_interaction_lead_search');
					var interactionKindSelect = document.getElementById('twob_interaction_kind');
					var interactionChannelSelect = document.getElementById('twob_interaction_channel');
					var interactionActionSelect = document.getElementById('twob_interaction_action');
					var interactionResultSelect = document.getElementById('twob_interaction_result');
					var interactionStageSelect = document.getElementById('twob_interaction_stage');
					var interactionTaskIdInput = document.getElementById('twob_interaction_task_id');
					var interactionLeadOptions = interactionLeadSelect ? Array.prototype.slice.call(interactionLeadSelect.options).map(function(opt){
						return {
							value: opt.value,
							text: opt.textContent,
							selected: opt.selected,
							dataset: Object.assign({}, opt.dataset || {})
						};
					}) : [];
					function rebuildInteractionLeadOptions(filterValue){
						if (!interactionLeadSelect || !interactionLeadOptions.length) { return; }
						var currentValue = interactionLeadSelect.value;
						var query = (filterValue || '').trim().toLowerCase();
						interactionLeadSelect.innerHTML = '';
						var visibleCount = 0;
						interactionLeadOptions.forEach(function(item){
							var searchText = ((item.dataset && item.dataset.search) ? item.dataset.search : item.text).toLowerCase();
							if (item.value !== '0' && query && searchText.indexOf(query) === -1) {
								return;
							}
							var opt = document.createElement('option');
							opt.value = item.value;
							opt.textContent = item.text;
							Object.keys(item.dataset || {}).forEach(function(key){
								opt.dataset[key] = item.dataset[key];
							});
							if (currentValue && currentValue === item.value) {
								opt.selected = true;
							} else if (!currentValue && item.selected) {
								opt.selected = true;
							}
							interactionLeadSelect.appendChild(opt);
							if (item.value !== '0') {
								visibleCount++;
							}
						});
						if (!interactionLeadSelect.options.length) {
							var emptyOpt = document.createElement('option');
							emptyOpt.value = '0';
							emptyOpt.textContent = 'Sin leads para esta busqueda';
							interactionLeadSelect.appendChild(emptyOpt);
						}
						if (!interactionLeadSelect.value && interactionLeadSelect.options.length) {
							interactionLeadSelect.selectedIndex = 0;
						}
						if (interactionLeadSearch) {
							interactionLeadSearch.setAttribute('data-visible-count', String(visibleCount));
						}
					}
					function syncInteractionStage(){
						if (!interactionLeadSelect || !interactionStageSelect) { return; }
						var opt = interactionLeadSelect.options[interactionLeadSelect.selectedIndex];
						if (!opt || !opt.dataset) { return; }
					var currentStage = opt.dataset.stage || '';
					if (isResponseFocusScreen && interactionResultSelect) {
						var suggestedStage = suggestedStageFromResult(interactionResultSelect.value, currentStage);
						interactionStageSelect.value = suggestedStage || currentStage || 'responded_interested';
						return;
					}
					if (currentStage) {
						interactionStageSelect.value = currentStage;
					}
				}
				function syncInteractionLeadDefaults(force){
					if (!interactionLeadSelect) { return; }
					var opt = interactionLeadSelect.options[interactionLeadSelect.selectedIndex];
					if (!opt || !opt.dataset) { return; }
					if (isResponseFocusScreen && interactionKindSelect) {
						interactionKindSelect.value = 'followup';
					}
					if (interactionTaskIdInput) {
						interactionTaskIdInput.value = opt.dataset.openTaskId || '0';
					}
					if (interactionChannelSelect) {
						interactionChannelSelect.value = opt.dataset.responseChannel || (isResponseFocusScreen ? 'whatsapp' : interactionChannelSelect.value);
					}
					if (interactionResultSelect) {
						interactionResultSelect.value = opt.dataset.responseResult || (isResponseFocusScreen ? 'interested' : interactionResultSelect.value);
					}
					if (opt.dataset.responseAction && interactionActionSelect && (force || !interactionActionSelect.value || interactionActionSelect.getAttribute('data-auto-value'))) {
						interactionActionSelect.value = opt.dataset.responseAction;
						interactionActionSelect.setAttribute('data-auto-value', opt.dataset.responseAction);
					}
				}
				function syncInteractionAction(force){
					if (!interactionActionSelect || !interactionChannelSelect || !interactionKindSelect) { return; }
					var suggested = suggestedInteractionAction(interactionKindSelect.value, interactionChannelSelect.value);
					if (interactionResultSelect && ['interested', 'need_time', 'meeting_booked'].indexOf(interactionResultSelect.value) >= 0 && interactionKindSelect.value === 'followup') {
						suggested = responseReceivedAction(interactionChannelSelect.value);
					}
					var lastAuto = interactionActionSelect.getAttribute('data-auto-value') || '';
					if (force || !interactionActionSelect.value || interactionActionSelect.value === lastAuto) {
					interactionActionSelect.value = suggested;
				}
				interactionActionSelect.setAttribute('data-auto-value', suggested);
				}
					if (interactionLeadSelect) {
						rebuildInteractionLeadOptions(interactionLeadSearch ? interactionLeadSearch.value : '');
						interactionLeadSelect.addEventListener('change', function(){
							syncInteractionLeadDefaults(true);
							syncInteractionAction(true);
							syncInteractionStage();
						});
					syncInteractionLeadDefaults(true);
						syncInteractionStage();
					}
					if (interactionLeadSearch) {
						interactionLeadSearch.addEventListener('input', function(){
							rebuildInteractionLeadOptions(interactionLeadSearch.value || '');
							syncInteractionLeadDefaults(true);
							syncInteractionAction(true);
							syncInteractionStage();
						});
					}
				if (interactionKindSelect) {
					interactionKindSelect.addEventListener('change', function(){ syncInteractionAction(false); });
				}
			if (interactionChannelSelect) {
				interactionChannelSelect.addEventListener('change', function(){ syncInteractionAction(false); });
			}
			if (interactionResultSelect) {
				interactionResultSelect.addEventListener('change', function(){
					syncInteractionAction(false);
					syncInteractionStage();
				});
			}
			syncInteractionAction(true);
			syncInteractionStage();
			if (addInteractionBtn) {
				addInteractionBtn.addEventListener('click', function(){
