			function rebuildTaskTypeOptions(){
				if (!taskTypeSelect) { return; }
				var category = taskCategorySelect ? taskCategorySelect.value : 'commercial';
				var options = taskTypeMap[category] || taskTypeMap.commercial || {};
				var prev = taskTypeSelect.value;
				taskTypeSelect.innerHTML = '';
				Object.keys(options).forEach(function(key){
					var opt = document.createElement('option');
					opt.value = key;
					opt.textContent = options[key];
					taskTypeSelect.appendChild(opt);
				});
				if (prev && Object.prototype.hasOwnProperty.call(options, prev)) {
					taskTypeSelect.value = prev;
				} else if (Object.prototype.hasOwnProperty.call(options, 'followup')) {
					taskTypeSelect.value = 'followup';
				} else if (taskTypeSelect.options.length) {
					taskTypeSelect.value = taskTypeSelect.options[0].value;
				}
				toggleMeetingFields();
			}
			function toggleMeetingFields(){
				if (!taskTypeSelect || !meetingOnlyFields.length) { return; }
				var isMeeting = taskTypeSelect.value === 'meeting';
				meetingOnlyFields.forEach(function(el){
					if (isMeeting) {
						el.classList.add('is-visible');
					} else {
						el.classList.remove('is-visible');
					}
				});
