			document.querySelectorAll('.twob-payment-status').forEach(function(btn){
				btn.addEventListener('click', function(){
					var body = new URLSearchParams();
					body.append('action', 'twob_crm_quick_action');
					body.append('nonce', '<?php echo esc_js($nonce); ?>');
					body.append('quick_action', 'set_payment_status');
					body.append('payment_id', btn.getAttribute('data-payment-id'));
					body.append('payment_status', btn.getAttribute('data-status'));
					sendQuick(body)
						.then(function(json){
							alert(json && json.data && json.data.message ? json.data.message : 'Estado actualizado');
							window.location.reload();
						})
						.catch(function(){ alert('No se pudo actualizar el estado del cobro.'); });
				});
			});

			document.querySelectorAll('.twob-set-funnel').forEach(function(btn){
				btn.addEventListener('click', function(){
					var leadId = btn.getAttribute('data-lead-id');
					var select = document.querySelector('.twob-funnel-stage[data-lead-id="' + leadId + '"]');
					if (!leadId || !select) { return; }
					var body = new URLSearchParams();
					body.append('action', 'twob_crm_quick_action');
					body.append('nonce', '<?php echo esc_js($nonce); ?>');
					body.append('quick_action', 'set_funnel_stage');
					body.append('lead_id', leadId);
					body.append('funnel_stage', select.value);
					sendQuick(body)
						.then(function(json){
							alert(json && json.data && json.data.message ? json.data.message : 'Embudo actualizado');
							window.location.reload();
						})
						.catch(function(){ alert('No se pudo actualizar el embudo.'); });
				});
			});

			// Drag & drop real para Kanban
			var dragLeadId = null;
			document.querySelectorAll('.twob-draggable').forEach(function(card){
				card.addEventListener('dragstart', function(e){
					dragLeadId = card.getAttribute('data-lead-id');
					card.classList.add('is-dragging');
					if (e.dataTransfer) {
						e.dataTransfer.effectAllowed = 'move';
						e.dataTransfer.setData('text/plain', dragLeadId || '');
					}
				});
				card.addEventListener('dragend', function(){
					card.classList.remove('is-dragging');
				});
			});
			document.querySelectorAll('.twob-dropzone').forEach(function(zone){
				zone.addEventListener('dragover', function(e){
					e.preventDefault();
					zone.classList.add('drag-over');
				});
				zone.addEventListener('dragleave', function(){
					zone.classList.remove('drag-over');
				});
				zone.addEventListener('drop', function(e){
					e.preventDefault();
					zone.classList.remove('drag-over');
					var leadId = dragLeadId || (e.dataTransfer ? e.dataTransfer.getData('text/plain') : '');
					var newStage = zone.getAttribute('data-stage');
					if (!leadId || !newStage) { return; }
					var body = new URLSearchParams();
					body.append('action', 'twob_crm_quick_action');
					body.append('nonce', '<?php echo esc_js($nonce); ?>');
					body.append('quick_action', 'set_stage');
					body.append('lead_id', leadId);
					body.append('stage', newStage);
					if ('lost' === newStage) {
						openLostReasonModal({
							leadTitle: 'Lead #' + leadId,
							leadCompany: 'Cambio desde Kanban',
							initialReason: '',
							onConfirm: function(reason){
								var retryBody = new URLSearchParams(body.toString());
								retryBody.append('lost_reason', reason);
								sendQuick(retryBody)
									.then(function(json){
										alert(json && json.data && json.data.message ? json.data.message : 'Etapa actualizada');
										window.location.reload();
									})
									.catch(function(){ alert('No se pudo mover el lead.'); });
							}
						});
						return;
					}
					sendQuick(body)
						.then(function(json){
							alert(json && json.data && json.data.message ? json.data.message : 'Etapa actualizada');
							window.location.reload();
						})
						.catch(function(){ alert('No se pudo mover el lead.'); });
				});
			});
		})();
		</script>
		<script src="https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js"></script>
		<?php self::render_site_reviewer_scripts($nonce); ?>
		<script>
			(function(){
				function sendReactivationQuick(body){
					return fetch(ajaxurl, {
						method: 'POST',
						headers: {'Content-Type':'application/x-www-form-urlencoded; charset=UTF-8'},
						body: body.toString()
					}).then(function(response){
						return response.json();
					});
				}

				function setStatus(node, message, tone){
					if (!node) { return; }
					node.classList.remove('is-error', 'is-ok', 'is-loading');
					if (tone) {
						node.classList.add('is-' + tone);
					}
					node.textContent = message || '';
				}

				function hasFindingForRoot(root){
					var leadCard = root ? root.closest('.twob-lead-accordion') : null;
					var findingField = leadCard ? leadCard.querySelector('.twob-lead-technical-finding') : null;
					return !!(findingField && String(findingField.value || '').trim());
				}

				function collectReactivationChannels(root){
					var channels = [];
					if (!root) { return channels; }
					root.querySelectorAll('.twob-react-field[data-react-field]').forEach(function(field){
						var key = field.getAttribute('data-react-field');
						if (key === 'twob_sector') { return; }
						if ((field.value || '').trim()) {
							channels.push(key);
						}
					});
					return channels;
				}

				function syncReactivationState(root){
					if (!root) { return; }
					var research = root.querySelector('[data-reactivation-research]');
					var status = root.querySelector('[data-react-save-status]');
					var generateButton = root.querySelector('[data-react-action="generate-sequence"]');
					var canUseResearch = hasFindingForRoot(root);
					var hasChannels = collectReactivationChannels(root).length > 0;
					if (research) {
						research.classList.toggle('is-locked', !canUseResearch);
					}
					root.querySelectorAll('.twob-react-field, .twob-react-verify-url').forEach(function(field){
						field.disabled = !canUseResearch;
					});
					if (generateButton) {
						generateButton.disabled = !canUseResearch || !hasChannels;
					}
					if (status && !canUseResearch) {
						setStatus(status, 'Primero guarda el hallazgo técnico para habilitar esta investigación.', '');
					} else if (status && canUseResearch && !hasChannels) {
						setStatus(status, 'Llena al menos un canal antes de generar la secuencia. Si el sitio no tiene ninguno, usa el formulario de contacto.', '');
					}
				}

				function saveReactivationField(root, field){
					if (!root || !field) { return; }
					var leadId = root.getAttribute('data-lead-id') || '0';
					var status = root.querySelector('[data-react-save-status]');
					var body = new URLSearchParams();
					body.append('action', 'twob_crm_quick_action');
					body.append('nonce', '<?php echo esc_js($nonce); ?>');
					body.append('quick_action', 'save_reactivation_field');
					body.append('lead_id', leadId);
					body.append('field', field.getAttribute('data-react-field') || '');
					body.append('value', field.value || '');
					setStatus(status, 'Guardando investigación...', 'loading');
					sendReactivationQuick(body).then(function(json){
						if (!json || !json.success) {
							setStatus(status, json && json.data && json.data.message ? json.data.message : 'No se pudo guardar el campo.', 'error');
							return;
						}
						setStatus(status, 'Investigación guardada automáticamente.', 'ok');
						syncReactivationState(root);
					}).catch(function(){
						setStatus(status, 'No se pudo guardar el campo.', 'error');
					});
				}

				function openVerifyUrl(root){
					if (!root) { return; }
					var field = root.querySelector('[data-react-field="twob_react_formulario_url"]');
					var value = field ? String(field.value || '').trim() : '';
					if (value && !/^https?:\/\//i.test(value)) {
						value = 'https://' + value.replace(/^\/+/, '');
					}
					if (!value) {
						window.alert('Ingresa primero la URL del formulario.');
						return;
					}
					window.open(value, '_blank', 'noopener');
				}

				function copyInline(button){
					if (!button || !navigator.clipboard) { return; }
					var value = button.getAttribute('data-copy-value') || '';
					if (!value) { return; }
					var original = button.getAttribute('data-label') || button.textContent;
					button.setAttribute('data-label', original);
					navigator.clipboard.writeText(value).then(function(){
						button.textContent = '✓ Copiado';
						button.classList.add('is-ok');
						window.setTimeout(function(){
							button.textContent = original;
							button.classList.remove('is-ok');
						}, 1600);
					});
				}

				var reactModal = null;
				var reactModalState = {};

				function ensureReactModal(){
					if (reactModal) { return reactModal; }
					var backdrop = document.createElement('div');
					backdrop.className = 'twob-react-modal-backdrop';
					backdrop.innerHTML = '' +
						'<div class="twob-react-modal" role="dialog" aria-modal="true" aria-labelledby="twobReactModalTitle">' +
							'<div class="twob-react-modal-head">' +
								'<div><h3 id="twobReactModalTitle">Resolver tarea de reactivación</h3><div class="twob-line-2" id="twobReactModalSubtitle"></div></div>' +
								'<button type="button" class="twob-react-modal-close" aria-label="Cerrar">×</button>' +
							'</div>' +
							'<div class="twob-react-modal-status" id="twobReactModalStatus"></div>' +
							'<div class="twob-form-row" id="twobReactModalInfo"></div>' +
							'<div class="twob-form-row" id="twobReactFieldEmail" hidden><label>Email del decisor</label><input type="email" id="twobReactEmailValue" placeholder="gerente@empresa.cl"></div>' +
							'<div class="twob-form-row" id="twobReactFieldPhone" hidden><label>Nuevo teléfono</label><input type="text" id="twobReactPhoneValue" placeholder="+56 9 XXXX XXXX"></div>' +
							'<div class="twob-form-row" id="twobReactFieldMeeting" hidden><label>¿Cuándo es la reunión?</label><input type="date" id="twobReactMeetingDate"></div>' +
							'<div class="twob-form-row" id="twobReactFieldReason" hidden><label>¿Por qué razón?</label><textarea id="twobReactReasonValue" rows="4" placeholder="Opcional"></textarea></div>' +
							'<div class="twob-form-row"><label>Nota breve (opcional)</label><textarea id="twobReactNoteValue" rows="3" placeholder="Resumen corto de lo que pasó"></textarea></div>' +
							'<div class="twob-react-modal-footer">' +
								'<button type="button" class="button" id="twobReactModalCancel">Cancelar</button>' +
								'<button type="button" class="button button-primary" id="twobReactModalSubmit">Guardar resultado</button>' +
							'</div>' +
						'</div>';
					document.body.appendChild(backdrop);

					reactModal = {
						backdrop: backdrop,
						title: backdrop.querySelector('#twobReactModalTitle'),
						subtitle: backdrop.querySelector('#twobReactModalSubtitle'),
						status: backdrop.querySelector('#twobReactModalStatus'),
						info: backdrop.querySelector('#twobReactModalInfo'),
						fieldEmail: backdrop.querySelector('#twobReactFieldEmail'),
						fieldPhone: backdrop.querySelector('#twobReactFieldPhone'),
						fieldMeeting: backdrop.querySelector('#twobReactFieldMeeting'),
						fieldReason: backdrop.querySelector('#twobReactFieldReason'),
						email: backdrop.querySelector('#twobReactEmailValue'),
						phone: backdrop.querySelector('#twobReactPhoneValue'),
						meeting: backdrop.querySelector('#twobReactMeetingDate'),
						reason: backdrop.querySelector('#twobReactReasonValue'),
						note: backdrop.querySelector('#twobReactNoteValue'),
						cancel: backdrop.querySelector('#twobReactModalCancel'),
						submit: backdrop.querySelector('#twobReactModalSubmit'),
						close: backdrop.querySelector('.twob-react-modal-close')
					};

					function setModalStatus(message, tone){
						setStatus(reactModal.status, message, tone);
					}

					function closeModal(){
						reactModal.backdrop.classList.remove('is-open');
						reactModal.submit.disabled = false;
						setModalStatus('', '');
						reactModalState = {};
					}

					function submitModal(){
						var body = new URLSearchParams();
						body.append('action', 'twob_crm_quick_action');
						body.append('nonce', '<?php echo esc_js($nonce); ?>');
						body.append('quick_action', 'resolve_reactivation_task');
						body.append('task_id', reactModalState.taskId || '0');
						body.append('outcome', reactModalState.outcome || '');
						body.append('email', reactModal.email.value || '');
						body.append('phone', reactModal.phone.value || '');
						body.append('meeting_date', reactModal.meeting.value || '');
						body.append('reason', reactModal.reason.value || '');
						body.append('note', reactModal.note.value || '');

						if (reactModal.fieldEmail.hidden === false && !(reactModal.email.value || '').trim()) {
							setModalStatus('Debes ingresar el email del decisor.', 'error');
							return;
						}
						if (reactModal.fieldPhone.hidden === false && !(reactModal.phone.value || '').trim()) {
							setModalStatus('Debes ingresar el nuevo teléfono.', 'error');
							return;
						}
						if (reactModal.fieldMeeting.hidden === false && !(reactModal.meeting.value || '').trim()) {
							setModalStatus('Debes indicar la fecha de la reunión.', 'error');
							return;
						}

						reactModal.submit.disabled = true;
						setModalStatus('Guardando resultado...', 'loading');
						sendReactivationQuick(body).then(function(json){
							if (!json || !json.success) {
								setModalStatus(json && json.data && json.data.message ? json.data.message : 'No se pudo guardar el resultado.', 'error');
								reactModal.submit.disabled = false;
								return;
							}
							setModalStatus(json.data && json.data.message ? json.data.message : 'Resultado guardado.', 'ok');
							window.setTimeout(function(){ window.location.reload(); }, 300);
						}).catch(function(){
							setModalStatus('No se pudo guardar el resultado.', 'error');
							reactModal.submit.disabled = false;
						});
					}

					reactModal.cancel.addEventListener('click', closeModal);
					reactModal.close.addEventListener('click', closeModal);
					reactModal.submit.addEventListener('click', submitModal);
					reactModal.backdrop.addEventListener('click', function(event){
						if (event.target === reactModal.backdrop) {
							closeModal();
						}
					});
					reactModal.closeModal = closeModal;
					reactModal.setModalStatus = setModalStatus;
					return reactModal;
				}

				function openReactOutcomeModal(button){
					var taskCard = button ? button.closest('.twob-react-task-card') : null;
					if (!taskCard) { return; }
					var outcome = button.getAttribute('data-react-outcome') || '';
					var channel = taskCard.getAttribute('data-react-channel') || '';
					var modal = ensureReactModal();
					var requiresEmail = outcome === 'got_email';
					var requiresPhone = outcome === 'got_phone';
					var requiresMeeting = outcome === 'meeting_booked';
					var allowsReason = outcome === 'rejected';
					modal.subtitle.textContent = taskCard.querySelector('strong') ? taskCard.querySelector('strong').textContent : 'Tarea de reactivación';
					modal.info.innerHTML = '<div class="twob-helper-box"><strong>Resultado seleccionado</strong><span>Canal: ' + channel + ' · Resultado: ' + outcome + '</span></div>';
					modal.fieldEmail.hidden = !requiresEmail;
					modal.fieldPhone.hidden = !requiresPhone;
					modal.fieldMeeting.hidden = !requiresMeeting;
					modal.fieldReason.hidden = !allowsReason;
					modal.email.value = '';
					modal.phone.value = '';
					modal.meeting.value = '';
					modal.reason.value = '';
					modal.note.value = '';
					modal.setModalStatus('', '');
					reactModalState = {
						taskId: taskCard.getAttribute('data-react-task-id') || '0',
						outcome: outcome
					};
					modal.backdrop.classList.add('is-open');
				}

				function initReactivationRoot(root){
					if (!root || root.getAttribute('data-reactivation-ready') === '1') { return; }
					root.setAttribute('data-reactivation-ready', '1');
					syncReactivationState(root);

					root.querySelectorAll('.twob-react-field[data-react-field]').forEach(function(field){
						var triggerSave = function(){
							if (field.disabled) { return; }
							saveReactivationField(root, field);
						};
						field.addEventListener('change', triggerSave);
						field.addEventListener('blur', triggerSave);
					});

					root.querySelectorAll('.twob-react-verify-url').forEach(function(button){
						button.addEventListener('click', function(){ openVerifyUrl(root); });
					});

					root.querySelectorAll('.twob-copy-inline').forEach(function(button){
						button.addEventListener('click', function(){ copyInline(button); });
					});

					root.querySelectorAll('.twob-react-result').forEach(function(button){
						button.addEventListener('click', function(){ openReactOutcomeModal(button); });
					});

					var generateButton = root.querySelector('[data-react-action="generate-sequence"]');
					if (generateButton) {
						generateButton.addEventListener('click', function(){
							var body = new URLSearchParams();
							body.append('action', 'twob_crm_quick_action');
							body.append('nonce', '<?php echo esc_js($nonce); ?>');
							body.append('quick_action', 'generate_reactivation_sequence');
							body.append('lead_id', root.getAttribute('data-lead-id') || '0');
							setStatus(root.querySelector('[data-react-save-status]'), 'Generando secuencia para Dani...', 'loading');
							generateButton.disabled = true;
							sendReactivationQuick(body).then(function(json){
								if (!json || !json.success) {
									setStatus(root.querySelector('[data-react-save-status]'), json && json.data && json.data.message ? json.data.message : 'No se pudo generar la secuencia.', 'error');
									generateButton.disabled = false;
									return;
								}
								setStatus(root.querySelector('[data-react-save-status]'), json.data && json.data.message ? json.data.message : 'Secuencia creada.', 'ok');
								window.setTimeout(function(){ window.location.reload(); }, 280);
							}).catch(function(){
								setStatus(root.querySelector('[data-react-save-status]'), 'No se pudo generar la secuencia.', 'error');
								generateButton.disabled = false;
							});
						});
					}

					root.addEventListener('twob:finding-saved', function(){
						syncReactivationState(root);
					});
				}

				document.querySelectorAll('[data-reactivation-root]').forEach(function(root){
					initReactivationRoot(root);
				});

				document.addEventListener('twob:reactivation-mount', function(event) {
					var scope = event.detail && event.detail.scope;
					if (!scope) { return; }
					scope.querySelectorAll('[data-reactivation-root]').forEach(function(root) {
						root.removeAttribute('data-reactivation-ready');
						initReactivationRoot(root);
					});
				});
			})();
		</script>
		<?php
	}
}

register_activation_hook(__FILE__, array('TwoB_CRM_Dani_Visual', 'activate'));
register_deactivation_hook(__FILE__, array('TwoB_CRM_Dani_Visual', 'deactivate'));
